Object.assign(ANNOTATIONS_RAW, {
  "Grapevine_Disposition": {
    "definition": "A Grapevine_Disposition is a disposition (<a href=\"https://www.ebi.ac.uk/ols4/ontologies/bfo/classes/http%253A%252F%252Fpurl.obolibrary.org%252Fobo%252FBFO_0000016\" target=\"_blank\">BFO_0000016</a>) that is an internally-grounded, realized entity inhering in a Vitis vinifera plant or plant part, representing a potentiality that may be realized under specific triggering conditions through characteristic processes.", 
    "alternative_term": "grapevine potentiality | vine disposition | Vitis disposition |+ Rebendisposition | Rebenpotential | Weinrebendisposition",
    "example_of_usage": "A Cabernet Sauvignon vine planted in the Médoc possesses multiple Grapevine_Dispositions that may or may not be realized depending on conditions encountered during each growing season. ||Its Downy_Mildew_Resistance_Disposition remains unrealized in dry years when Plasmopara viticola inoculum is absent, but becomes realized through defense responses when humid conditions promote infection pressure. ||Similarly, its Cold_Hardiness_Disposition exists as a potentiality throughout the year but is only realized when acclimation processes are triggered by shortening photoperiod and declining temperatures in autumn, ultimately determining whether primary buds survive winter minima of -15°C. ||The vine's Quality_Potential_Disposition for producing wines with characteristic blackcurrant aromatics and firm tannins requires appropriate terroir conditions, vine age, crop load management, and harvest timing to be fully realized in the resulting wine.",
    "editor_note": "This is the root class for all dispositional properties specific to Vitis vinifera in VVO. ||Dispositions are distinguished from Grapevine_Quality in that qualities are fully present whenever they exist, while dispositions exist as potentialities that require triggering conditions to be realized through processes. ||Dispositions are also distinguished from Grapevine_Role in that dispositions are internally grounded in the physical structure of the bearer, while roles are externally grounded in social or relational contexts.  As a realizable entity, a grapevine disposition exists as a genuine property of its bearer even when not being manifested, distinguishing it from qualities which are always fully present. ||Grapevine dispositions encompass the full spectrum of potentialities relevant to viticulture and oenology, including resistance and tolerance dispositions that may be realized upon encounter with biotic or abiotic stressors, developmental dispositions governing growth patterns and phenological timing, reproductive dispositions affecting flowering and fruit set, physiological dispositions relating to water relations and nutrient acquisition, and quality-determining dispositions that influence grape and wine characteristics. ||The realization of a grapevine disposition depends on the presence of appropriate triggers (such as pathogen contact for resistance dispositions or environmental stress for tolerance dispositions) and may be modulated by genetic background, developmental stage, environmental conditions, and viticultural management practices. ||Understanding grapevine dispositions is fundamental to cultivar selection, rootstock-scion matching, and vineyard site assessment.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Röhl J, Jansen L (2011) Why functions are not special dispositions, Monist 94(3):379-402|| Keller M (2020) The Science of Grapevines, 3rd Edition, Academic Press"
  },
  "Biotic_Stress_Resistance_Disposition": {
    "definition": "A Biotic_Stress_Resistance_Disposition is a Grapevine_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes when the bearer encounters living organisms that pose potential threats to plant health, including fungal, bacterial, and viral pathogens, as well as arthropod pests and parasitic nematodes.", 
    "alternative_term": "disease resistance disposition | pest resistance potential | biotic defense disposition |+ Biotische Stressresistenz-Disposition | Krankheitsresistenz-Disposition | Schädlingsresistenz-Potenzial",
    "example_of_usage": "The PIWI (Pilzwiderstandsfähige) cultivar 'Regent' possesses multiple Biotic_Stress_Resistance_Dispositions inherited from its complex pedigree including Vitis amurensis ancestry. ||Its Rpv3-mediated Downy_Mildew_Resistance_Disposition is realized upon contact with Plasmopara viticola zoospores through rapid hypersensitive cell death limiting pathogen colonization, reducing disease severity by 70-85% compared to susceptible Vitis vinifera cultivars under equivalent inoculum pressure. ||Simultaneously, its Ren3-associated Powdery_Mildew_Resistance_Disposition is realized through localized cell death and phytoalexin accumulation when Erysiphe necator attempts penetration, though this resistance may be partially overcome by adapted pathogen strains in regions with high selection pressure. ||These resistance dispositions enable 'Regent' cultivation with 50-70% reduction in fungicide applications compared to traditional cultivars, demonstrating how understanding biotic stress resistance dispositions guides sustainable viticulture strategies.",
    "editor_note": "Biotic_Stress_Resistance_Disposition is_a Grapevine_Disposition. ||This class encompasses all resistance dispositions against living organisms, distinguished from Abiotic_Stress_Tolerance_Disposition which covers responses to non-living environmental stressors. ||Child classes are organized by stressor type (Pathogen_Resistance_Disposition, Pest_Resistance_Disposition) and by defense mechanism (Defense_Mechanism_Disposition). ||The term \"resistance\" rather than \"tolerance\" is used following plant pathology conventions where resistance implies limiting pathogen development while tolerance implies maintaining yield despite pathogen presence.  This disposition encompasses the full spectrum of genetically-encoded resistance mechanisms, from major gene-mediated qualitative resistance providing near-complete protection against specific pathogen races, to polygenic quantitative resistance conferring partial but broad-spectrum protection. ||The molecular basis of biotic stress resistance dispositions includes pattern recognition receptors detecting conserved pathogen-associated molecular patterns (PAMPs), intracellular nucleotide-binding leucine-rich repeat (NLR) receptors recognizing specific effector proteins, and downstream signaling cascades activating defense gene expression. ||Realization of these dispositions manifests through diverse processes including hypersensitive response, phytoalexin biosynthesis, cell wall reinforcement, and systemic acquired resistance. ||Biotic stress resistance dispositions are of paramount importance in viticulture due to the susceptibility of Vitis vinifera cultivars to numerous pathogens and pests, driving breeding programs to introgress resistance loci from wild Vitis species and motivating rootstock selection based on resistance profiles.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jones JDG, Dangl JL (2006) The plant immune system, Nature 444:323-329|| Töpfer R et al. (2011) New horizons for grapevine breeding, Fruit, Vegetable and Cereal Science and Biotechnology 5:79-100|| Dry IB et al. (2010) Grapevine disease resistance genes, Genetics, Genomics and Breeding of Grapes, Science Publishers"
  },
  "Pathogen_Resistance_Disposition": {
    "definition": "A Pathogen_Resistance_Disposition is a Biotic_Stress_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with microbial organisms capable of causing disease, including fungi, oomycetes, bacteria, viruses, and phytoplasmas.", 
    "alternative_term": "disease resistance disposition | microbial resistance potential | pathogen defense capacity |+ Pathogenresistenz-Disposition | Krankheitserreger-Resistenz | Erregerabwehr-Potenzial",
    "example_of_usage": "The Vitis vinifera cultivar 'Chasselas' exhibits minimal Pathogen_Resistance_Disposition against most fungal and oomycete pathogens, requiring 12-16 fungicide applications per season in humid Central European climates to control Plasmopara viticola, Erysiphe necator, and Botrytis cinerea. ||In contrast, the interspecific hybrid 'Solaris' (Merzling × Gm 6493) possesses multiple Pathogen_Resistance_Dispositions inherited from its complex pedigree including V. amurensis and V. rupestris ancestry. ||These dispositions are realized through rapid defense activation upon pathogen contact, enabling cultivation with only 2-4 fungicide applications annually while maintaining infection levels below 5% leaf area affected for downy mildew and below 10% cluster infection for powdery mildew under moderate disease pressure. ||This 70-80% reduction in plant protection inputs demonstrates the practical significance of pathogen resistance dispositions for economically and environmentally sustainable grape production.",
    "editor_note": "Pathogen_Resistance_Disposition is_a Biotic_Stress_Resistance_Disposition. ||This class encompasses resistance to all disease-causing microorganisms, distinguished from Pest_Resistance_Disposition which covers resistance to arthropods and nematodes. ||Child classes are organized taxonomically by pathogen group: Fungal_Resistance_Disposition (including oomycetes by convention), Viral_Resistance_Disposition, Bacterial_Resistance_Disposition, and Phytoplasma_Resistance_Disposition. ||Note that oomycetes such as Plasmopara viticola are phylogenetically distinct from true fungi but are conventionally grouped under fungal diseases in viticultural practice.  This disposition represents the genetically-encoded capacity to limit pathogen ingress, colonization, reproduction, or spread through diverse molecular and cellular mechanisms operating at pre-invasive and post-invasive stages of infection. ||Pre-invasive resistance mechanisms include physical barriers such as cuticle thickness and stomatal morphology, as well as preformed antimicrobial compounds. ||Post-invasive mechanisms encompass pathogen recognition through pattern recognition receptors (PRRs) detecting pathogen-associated molecular patterns (PAMPs) and through nucleotide-binding leucine-rich repeat (NLR) receptors recognizing pathogen effectors, triggering downstream defense responses including reactive oxygen species production, cell wall reinforcement, phytoalexin biosynthesis, and programmed cell death. ||Pathogen resistance dispositions in grapevine vary from monogenic qualitative resistance conferring race-specific immunity to polygenic quantitative resistance providing partial but durable protection. ||The introgression of pathogen resistance dispositions from wild Vitis species into V. vinifera cultivars represents a primary breeding objective for sustainable viticulture, addressing the exceptional susceptibility of European grapevine cultivars to numerous pathogens introduced through global trade.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jones JDG, Dangl JL (2006) The plant immune system, Nature 444:323-329|| Gessler C et al. (2011) Vitis vinifera and grape diseases, Genetics, Genomics and Breeding of Grapes, Science Publishers|| Armijo G et al. (2016) Grapevine pathogenic microorganisms: understanding infection strategies and host response scenarios, Frontiers in Plant Science 7:382"
  },
  "Fungal_Resistance_Disposition": {
    "definition": "A Fungal_Resistance_Disposition is a Pathogen_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with fungal pathogens and oomycetes, the most economically significant group of grapevine disease-causing organisms.", 
    "alternative_term": "fungal disease resistance | mycotic resistance disposition | oomycete resistance potential |+ Pilzresistenz-Disposition | Pilzwiderstandsfähigkeit | Mykose-Resistenz",
    "example_of_usage": "The fungal resistance breeding program at the Julius Kühn-Institut (JKI) in Siebeldingen, Germany, systematically evaluates Fungal_Resistance_Disposition in segregating populations derived from crosses between Vitis vinifera and resistant wild species. ||Seedlings are screened for resistance to Plasmopara viticola using leaf disc assays with standardized sporangial suspensions (50,000 sporangia/mL), scoring sporulation intensity on a 1-9 OIV scale after 7 days incubation. ||Individuals rated OIV 1-3 (no to weak sporulation) possess strong Fungal_Resistance_Disposition against downy mildew, while those rated OIV 7-9 (strong sporulation covering >50% leaf area) lack effective resistance. ||Selected resistant genotypes undergo further evaluation for Erysiphe necator resistance in greenhouse trials and Botrytis cinerea resistance in field clusters, as pyramiding multiple Fungal_Resistance_Dispositions is essential for durable protection under diverse environmental conditions and evolving pathogen populations.",
    "editor_note": "Fungal_Resistance_Disposition is_a Pathogen_Resistance_Disposition. ||By convention in plant pathology and viticulture, this class includes resistance to oomycetes (e.g., Plasmopara viticola) despite their phylogenetic distinction from true fungi (Kingdom Stramenopila vs. ||Kingdom Fungi). ||Child classes are organized by specific pathogen: Downy_Mildew_Resistance_Disposition, Powdery_Mildew_Resistance_Disposition, Botrytis_Resistance_Disposition, Black_Rot_Resistance_Disposition, Anthracnose_Resistance_Disposition, and Trunk_Disease_Resistance_Disposition.  This disposition encompasses resistance mechanisms effective against obligate biotrophic pathogens such as Plasmopara viticola (downy mildew) and Erysiphe necator (powdery mildew), necrotrophic pathogens including Botrytis cinerea (grey mold), hemibiotrophic pathogens such as Guignardia bidwellii (black rot) and Elsinoë ampelina (anthracnose), and wood-inhabiting fungi causing trunk diseases including Phaeomoniella chlamydospora and various Botryosphaeriaceae species. ||The molecular basis of fungal resistance dispositions includes recognition of fungal cell wall components (chitin, β-glucans) by pattern recognition receptors, detection of fungal effector proteins by NLR receptors, and activation of defense responses including chitinase and glucanase production, phytoalexin biosynthesis (particularly stilbenes such as resveratrol and viniferins), lignification, and callose deposition. ||Fungal resistance dispositions may operate at multiple infection stages including spore germination inhibition, penetration resistance, haustorial encasement, and limitation of mycelial spread. ||Given that fungal and oomycete diseases account for over 80% of pesticide use in viticulture globally, enhancing fungal resistance dispositions through breeding represents a critical objective for sustainable grape production.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gadoury DM et al. (2012) Grapevine powdery mildew (Erysiphe necator): a fascinating system for the study of the biology, ecology and epidemiology of an obligate biotroph, Molecular Plant Pathology 13:1-16|| Kassemeyer HH (2017) Fungi of grapes, Biology of Microorganisms on Grapes, in Must and in Wine, Springer|| Töpfer R, Hausmann L (2010) Breeding for fungal disease resistant grapevines, Genetics, Genomics and Breeding of Grapes, Science Publishers"
  },
  "Downy_Mildew_Resistance_Disposition": {
    "definition": "A Downy_Mildew_Resistance_Disposition is a Fungal_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with the oomycete Plasmopara viticola, the causal agent of grapevine downy mildew.", 
    "alternative_term": "Plasmopara resistance disposition | peronospora resistance | DM resistance potential |+ Peronospora-Resistenz-Disposition | Falscher Mehltau-Resistenz | Rebenperonospora-Widerstandsfähigkeit",
    "example_of_usage": "Field evaluation of Downy_Mildew_Resistance_Disposition at INRAE Colmar, France, involves planting replicated plots of test genotypes alongside susceptible controls ('Müller-Thurgau', OIV resistance rating 1) and resistant references ('Regent', OIV rating 7) in a vineyard with naturally high P. viticola pressure. ||Disease severity is assessed at multiple timepoints using the OIV 452 descriptor, recording percentage leaf area with sporulating lesions and percentage of infected clusters. ||The resistant breeding selection Gf.Ga-52-42, carrying Rpv3-1 from 'Villard blanc' and Rpv10 from V. amurensis, demonstrates strong Downy_Mildew_Resistance_Disposition with mean leaf infection below 5% and cluster infection below 2% across five seasons, compared to 60-85% leaf infection in 'Müller-Thurgau' controls. ||This resistance is realized through rapid hypersensitive response visible as small necrotic flecks within 48 hours post-inoculation, preventing sporangiophore emergence and limiting secondary spread.",
    "editor_note": "Downy_Mildew_Resistance_Disposition is_a Fungal_Resistance_Disposition. ||Although Plasmopara viticola is an oomycete rather than a true fungus, resistance to this pathogen is classified under Fungal_Resistance_Disposition following viticultural convention. ||Child classes distinguish resistance mechanisms: Rpv_Mediated_Resistance_Disposition for major gene resistance, Quantitative_Downy_Mildew_Resistance_Disposition for polygenic resistance, Ontogenic_Downy_Mildew_Resistance_Disposition for age-related resistance, and Induced_Downy_Mildew_Resistance_Disposition for elicitor-triggered enhanced resistance.  This disposition represents the capacity to limit one or more stages of the P. viticola infection cycle, including zoospore encystment and germination on the leaf surface, stomatal penetration, intercellular hyphal growth, haustorial formation in mesophyll cells, and sporangiophore emergence through stomata. ||Downy mildew resistance dispositions in Vitis species operate through diverse mechanisms including pre-formed physical barriers (stomatal density and morphology, cuticle composition), constitutive chemical defenses, rapid recognition of pathogen-associated molecular patterns triggering PAMP-triggered immunity, and effector-triggered immunity mediated by resistance genes of the NLR family. ||The latter mechanism underlies the major resistance loci designated Rpv (Resistance to Plasmopara viticola), with over 30 loci identified to date in various wild Vitis species including V. rupestris, V. riparia, V. amurensis, V. cinerea, and Muscadinia rotundifolia. ||Downy mildew resistance is of paramount importance for viticulture in humid climates where P. viticola can cause complete crop loss in susceptible cultivars, driving intensive fungicide programs that represent significant economic and environmental costs.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gessler C, Pertot I, Perazzolli M (2011) Plasmopara viticola: a review of knowledge on downy mildew of grapevine and effective disease management, Phytopathologia Mediterranea 50:3-44|| Buonassisi D et al. (2017) Breeding for grapevine downy mildew resistance: a review of \"omics\" approaches, Euphytica 213:103|| VIVC (2024) Vitis International Variety Catalogue - Resistance loci database"
  },
  "Rpv_Mediated_Resistance_Disposition": {
    "definition": "An Rpv_Mediated_Resistance_Disposition is a Downy_Mildew_Resistance_Disposition that inheres in a Vitis plant and is realized through effector-triggered immunity (ETI) conferred by one or more Rpv (Resistance to Plasmopara viticola) loci encoding nucleotide-binding leucine-rich repeat (NLR) receptor proteins that recognize specific P.", 
    "alternative_term": "major gene downy mildew resistance | Rpv locus resistance | ETI-based Plasmopara resistance |+ Rpv-vermittelte Resistenz-Disposition | Rpv-Genresistenz | Majorgen-Peronospora-Resistenz",
    "example_of_usage": "Marker-assisted selection for Rpv_Mediated_Resistance_Disposition at Hochschule Geisenheim University employs SSR and SNP markers flanking characterized Rpv loci to identify resistant seedlings in segregating populations. ||A cross between 'Riesling' (susceptible, rpv/rpv) and the resistant breeding line Gf.Ga-47-42 (Rpv3-1/rpv3, Rpv12/rpv12) produces offspring segregating for both loci. ||DNA extracted from young leaf tissue is genotyped using the Rpv3-1-linked marker GF18-06 and the Rpv12-linked marker UDV-014, identifying approximately 25% of seedlings carrying both resistance alleles. ||These double-resistant individuals are confirmed through artificial inoculation with P. viticola sporangia, showing characteristic small necrotic lesions (diameter <2mm) without sporulation, contrasting with susceptible siblings exhibiting abundant sporangiophore production (>50 sporangiophores per lesion) visible as white downy growth on the abaxial leaf surface.",
    "editor_note": "Rpv_Mediated_Resistance_Disposition is_a Downy_Mildew_Resistance_Disposition. ||This class encompasses all major gene resistances conferred by characterized Rpv loci, distinguished from Quantitative_Downy_Mildew_Resistance_Disposition which involves polygenic inheritance. ||Child classes represent individual Rpv loci (Rpv1_Resistance_Disposition, Rpv3_Resistance_Disposition, etc.) and combinations thereof (Pyramided_Rpv_Resistance_Disposition). ||The \"Rpv\" nomenclature follows Vitis gene naming conventions established by the International Grape Genome Program (IGGP).  viticola effector molecules. ||This disposition represents qualitative, major gene-mediated resistance characterized by rapid and robust defense activation upon pathogen recognition, typically manifesting as hypersensitive response (HR) with localized programmed cell death at infection sites within 24-72 hours post-penetration. ||Over 30 Rpv loci have been genetically mapped across the Vitis genus, originating from diverse North American (V. rupestris, V. riparia, V. labrusca, V. cinerea), Asian (V. amurensis, V. piasezkii), and Muscadinia (M. rotundifolia) species. ||Each Rpv locus confers resistance to specific P. viticola isolates carrying corresponding avirulence effectors, creating potential for resistance breakdown when virulent pathogen races emerge through effector mutation or loss. ||Consequently, modern resistance breeding programs emphasize pyramiding multiple Rpv loci with distinct recognition specificities to achieve durable field resistance. ||Rpv-mediated resistance dispositions are readily introgressed into V. vinifera backgrounds through marker-assisted selection using linked molecular markers, enabling efficient breeding of disease-resistant cultivars retaining high wine quality.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fischer BM et al. (2004) Quantitative trait locus analysis of fungal disease resistance factors on a molecular map of grapevine, Theoretical and Applied Genetics 108:501-515|| Töpfer R et al. (2011) New horizons for grapevine breeding, Fruit, Vegetable and Cereal Science and Biotechnology 5:79-100|| Dry IB et al. (2019) Grapevine NLR immunity against downy and powdery mildew pathogens, Acta Horticulturae 1248:129-136"
  },
  "Rpv1_Resistance_Disposition": {
    "definition": "An Rpv1_Resistance_Disposition is an Rpv_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Rpv1 locus derived from Muscadinia rotundifolia and is realized through effector-triggered immunity upon recognition of corresponding Plasmopara viticola avirulence effectors.", 
    "alternative_term": "Rpv1 downy mildew resistance | Muscadinia-derived DM resistance | Run1/Rpv1 cluster resistance |+ Rpv1-Resistenz-Disposition | Rpv1-Peronospora-Resistenz | Muscadinia-Resistenz",
    "example_of_usage": "The breeding line Gf.2000-305-122 at Julius Kühn-Institut carries Rpv1_Resistance_Disposition introgressed from M. rotundifolia through multiple generations of pseudo-backcrossing initiated by Alain Bouquet at INRA Montpellier in the 1970s. ||When challenged with a diverse collection of 15 P. viticola isolates from European wine regions, this line exhibits complete resistance to all isolates, with no macroscopically visible sporulation on detached leaf discs maintained under optimal conditions for pathogen development (20°C, >95% RH, 16h photoperiod). ||Microscopic examination reveals attempted penetration through stomata followed by rapid cell death confined to 1-3 epidermal and mesophyll cells, effectively halting pathogen development. ||This exceptionally broad-spectrum resistance reflects the evolutionary distance between M. rotundifolia and European P. viticola populations, which lack the corresponding virulence effectors capable of suppressing Rpv1-mediated immunity.",
    "editor_note": "Rpv1_Resistance_Disposition is_a Rpv_Mediated_Resistance_Disposition. ||The Rpv1 locus is physically linked to Run1 (powdery mildew resistance) on chromosome 12, and both resistances are typically co-inherited. ||Rpv1 is distinguished by its origin in Muscadinia rotundifolia and its exceptionally strong, broad-spectrum resistance phenotype. ||Breeding with Rpv1 requires overcoming Muscadinia × Euvitis crossing barriers and managing extensive linkage drag from the large introgressed chromosomal segment.  ||The Rpv1 locus maps to chromosome 12 and is tightly linked to the powdery mildew resistance locus Run1, forming a resistance gene cluster that has been extensively utilized in breeding programs. ||Rpv1 originates from M. rotundifolia, a species native to the southeastern United States that co-evolved with endemic Plasmopara populations and possesses exceptionally strong downy mildew resistance. ||The resistance mechanism involves rapid hypersensitive response with complete arrest of pathogen development at the penetration stage, resulting in tiny necrotic flecks without any sporangiophore formation even under high inoculum pressure. ||Introgression of Rpv1 into V. vinifera backgrounds has been challenging due to the limited crossability between Muscadinia and Euvitis subgenera and the extensive linkage drag associated with the large introgressed segment, but pseudo-backcross breeding strategies have successfully incorporated this locus into wine grape breeding lines while progressively restoring V. vinifera genetic background and wine quality characteristics.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bouquet A (1986) Introduction dans l'espèce Vitis vinifera L. d'un caractère de résistance à l'oïdium (Uncinula necator) issu de l'espèce Muscadinia rotundifolia, Vignevini 12:141-146|| Merdinoglu D et al. (2003) Genetic analysis of downy mildew resistance derived from Muscadinia rotundifolia, Acta Horticulturae 603:451-456|| Feechan A et al. (2013) Genetic dissection of a TIR-NB-LRR locus from the wild North American grapevine species Muscadinia rotundifolia, Molecular Plant-Microbe Interactions 26:684-695"
  },
  "Rpv3_Resistance_Disposition": {
    "definition": "An Rpv3_Resistance_Disposition is an Rpv_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying one or more haplotypes of the Rpv3 locus on chromosome 18 and is realized through effector-triggered immunity upon recognition of corresponding Plasmopara viticola avirulence effectors.", 
    "alternative_term": "Rpv3 downy mildew resistance | Rpv3 haplotype resistance | Seibel-derived DM resistance |+ Rpv3-Resistenz-Disposition | Rpv3-Peronospora-Resistenz | Rpv3-Haplotyp-Resistenz",
    "example_of_usage": "The widely-planted PIWI cultivar 'Regent' carries Rpv3-1_Resistance_Disposition inherited from 'Chambourcin' in its pedigree. ||Under natural infection conditions in the Pfalz wine region of Germany, 'Regent' vines exhibit strong but incomplete Rpv3_Resistance_Disposition realization, with typical leaf infection severities of 5-15% compared to 70-90% in adjacent 'Müller-Thurgau' plots during conducive seasons. ||Microscopic observation reveals that P. viticola penetration and initial colonization proceed normally in 'Regent' leaves, but hypersensitive cell death is triggered 48-72 hours post-inoculation, limiting lesion expansion and reducing sporulation intensity by 70-85%. ||However, monitoring by the JKI has documented P. viticola isolates from 'Regent' vineyards with increased aggressiveness on Rpv3-1 genotypes, producing sporulation levels approaching those on susceptible controls, demonstrating the selective pressure exerted by widespread Rpv3-1 deployment and the consequent adaptation of pathogen populations.",
    "editor_note": "Rpv3_Resistance_Disposition is_a Rpv_Mediated_Resistance_Disposition. ||Multiple Rpv3 haplotypes exist (Rpv3-1, Rpv3-2, Rpv3-3) with different origins and recognition specificities. ||Rpv3-1 from 'Seibel 4614' lineage is most widely deployed but shows evidence of durability challenges in European vineyards with high PIWI adoption. ||Rpv3 resistance is typically partial rather than complete, and combining with other Rpv loci is recommended for durable field resistance.  The Rpv3 locus represents a complex resistance gene cluster with multiple distinct haplotypes (Rpv3-1, Rpv3-2, Rpv3-3) originating from different North American Vitis species and conferring varying levels and spectra of resistance. ||Rpv3-1, derived from the French-American hybrid 'Seibel 4614' (ancestor of 'Villard blanc' and 'Seyval blanc'), provides moderate to strong resistance that has been widely deployed in European PIWI breeding. ||Rpv3-2 and Rpv3-3 represent additional haplotypes with partially overlapping but distinct recognition specificities. ||The Rpv3-mediated resistance phenotype typically manifests as delayed and reduced sporulation rather than complete immunity, with small necrotic lesions that may support limited sporangiophore production under high disease pressure. ||This partial resistance phenotype has led to concerns about durability, with virulent P. viticola isolates capable of partially overcoming Rpv3-1 resistance already documented in European vineyards with high PIWI cultivar adoption, underscoring the importance of combining Rpv3 with additional resistance loci.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Welter LJ et al. (2007) Genetic mapping and localization of quantitative trait loci affecting fungal disease resistance and leaf morphology in grapevine, Molecular Breeding 20:359-374|| Bellin D et al. (2009) Resistance to Plasmopara viticola in grapevine 'Bianca' is controlled by a major dominant gene causing localised necrosis at the infection site, Theoretical and Applied Genetics 120:163-176|| Casagrande K et al. (2011) Defence responses in Rpv3-dependent resistance to grapevine downy mildew, Planta 234:1097-1109"
  },
  "Rpv10_Resistance_Disposition": {
    "definition": "An Rpv10_Resistance_Disposition is an Rpv_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Rpv10 locus derived from Vitis amurensis and is realized through effector-triggered immunity upon recognition of corresponding Plasmopara viticola avirulence effectors.", 
    "alternative_term": "Rpv10 downy mildew resistance | V. amurensis-derived DM resistance | Asian grape DM resistance |+ Rpv10-Resistenz-Disposition | Rpv10-Peronospora-Resistenz | Amurensis-Resistenz",
    "example_of_usage": "The breeding line 'Gf.Ga-52-42' at JKI Siebeldingen carries Rpv10_Resistance_Disposition derived from V. amurensis through the resistant parent 'Gf.Ga-47-42'. ||Phenotypic evaluation using detached leaf disc assays with P. viticola sporangial suspension (30,000 sporangia/mL) demonstrates that Rpv10 confers strong resistance characterized by small necrotic spots (mean diameter 0.8mm) visible 3-4 days post-inoculation with no subsequent sporangiophore development even after 10 days under optimal conditions for the pathogen. ||In contrast, susceptible 'Müller-Thurgau' discs develop extensive sporulation covering >80% of the leaf disc surface. ||Importantly, P. viticola isolates capable of partially overcoming Rpv3-1 resistance retain full avirulence on Rpv10 genotypes, demonstrating the distinct recognition specificities of these loci and validating the strategy of combining Rpv10 with Rpv3 for enhanced resistance durability.",
    "editor_note": "Rpv10_Resistance_Disposition is_a Rpv_Mediated_Resistance_Disposition. ||The Rpv10 locus originates from Vitis amurensis, the most cold-hardy Vitis species, providing additional breeding value beyond disease resistance. ||Rpv10 has a distinct recognition specificity from Rpv3 and is frequently combined with Rpv3 haplotypes in modern breeding programs. ||The locus on chromosome 9 is distinct from the Run1/Rpv1 cluster on chromosome 12 and the Rpv3 cluster on chromosome 18.  The Rpv10 locus maps to chromosome 9 and was identified in the Asian wild species V. amurensis, which evolved in regions of northeastern China, Korea, and the Russian Far East where endemic Plasmopara populations exerted selection pressure for resistance. ||V. amurensis additionally possesses exceptional cold hardiness, making it a valuable genetic resource for breeding cultivars adapted to continental climates. ||The Rpv10 resistance phenotype is characterized by rapid hypersensitive response with localized cell death arresting pathogen development at early post-penetration stages, resulting in small necrotic flecks (typically <1mm diameter) without macroscopically visible sporulation. ||Rpv10 provides a recognition specificity distinct from Rpv3, making it an excellent partner for pyramiding strategies. ||The resistance breeding line 'Solaris' and its derivatives carry Rpv10 combined with other resistance factors, contributing to the development of cold-hardy, disease-resistant cultivars suitable for northern European and continental climates.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schwander F et al. (2012) Rpv10: a new locus from the Asian Vitis gene pool for pyramiding downy mildew resistance loci in grapevine, Theoretical and Applied Genetics 124:163-176|| Venuti S et al. (2013) Historical introgression of the downy mildew resistance gene Rpv12 from the Asian species Vitis amurensis into grapevine varieties, PLoS ONE 8:e61228"
  },
  "Rpv12_Resistance_Disposition": {
    "definition": "An Rpv12_Resistance_Disposition is an Rpv_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Rpv12 locus derived from Vitis amurensis and is realized through effector-triggered immunity upon recognition of corresponding Plasmopara viticola avirulence effectors.", 
    "alternative_term": "Rpv12 downy mildew resistance | chromosome 14 DM resistance | Kunbarat-type resistance |+ Rpv12-Resistenz-Disposition | Rpv12-Peronospora-Resistenz | Rpv12-Amurensis-Resistenz",
    "example_of_usage": "The Hungarian cultivar 'Kunbarat', released in 1976 from a cross of 'Irsai Olivér' × V. amurensis, carries Rpv12_Resistance_Disposition that has provided stable field resistance for over four decades in Hungarian vineyards. ||Controlled inoculation experiments at the University of Pécs demonstrate that 'Kunbarat' exhibits the strongest resistance phenotype among tested cultivars, with hypersensitive response initiated within 18-24 hours post-inoculation and complete arrest of pathogen development by 48 hours. ||Sporulation is never observed even under extreme inoculum pressure (100,000 sporangia/mL) or extended incubation periods (14 days). ||Molecular marker analysis confirmed the presence of Rpv12 on chromosome 14, and genetic studies showed that this resistance segregates independently from Rpv10 on chromosome 9, despite both originating from V. amurensis, enabling their combination in breeding to achieve multiple-gene resistance.",
    "editor_note": "Rpv12_Resistance_Disposition is_a Rpv_Mediated_Resistance_Disposition. ||Although both Rpv10 and Rpv12 originate from Vitis amurensis, they map to different chromosomes (9 and 14 respectively) and can be independently selected and combined. ||Rpv12 confers particularly strong resistance with rapid hypersensitive response. ||The presence of Rpv12 in established Hungarian cultivars provides validated germplasm for breeding programs seeking to incorporate this resistance source.  The Rpv12 locus maps to chromosome 14 and represents a second major resistance gene from V. amurensis that is genetically independent from Rpv10. ||Rpv12 confers exceptionally strong resistance with a phenotype characterized by rapid and intense hypersensitive response resulting in complete arrest of P. viticola development at very early infection stages. ||Historical pedigree analysis has revealed that Rpv12 was inadvertently introgressed into European grapevine breeding material through early 20th century crosses involving V. amurensis, and is present in several established PIWI cultivars including 'Kunbarat' and 'Kunleány' from the Hungarian breeding program. ||The independent genetic position of Rpv12 relative to other major Rpv loci makes it highly valuable for resistance gene pyramiding, and its combination with Rpv3 and/or Rpv10 is expected to provide robust, durable field resistance against diverse P. viticola populations including isolates with evolved virulence against individual resistance genes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Venuti S et al. (2013) Historical introgression of the downy mildew resistance gene Rpv12 from the Asian species Vitis amurensis into grapevine varieties, PLoS ONE 8:e61228|| Kozma P et al. (2009) Resistance to downy mildew derived from interspecific hybrid Vitis rupestris × Vitis amurensis, Acta Horticulturae 827:507-512"
  },
  "Pyramided_Rpv_Resistance_Disposition": {
    "definition": "A Pyramided_Rpv_Resistance_Disposition is an Rpv_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying two or more distinct Rpv loci with different recognition specificities and is realized through multiple, independent effector-triggered immunity pathways upon encounter with Plasmopara viticola.", 
    "alternative_term": "stacked Rpv resistance | multi-locus DM resistance | combined Rpv resistance |+ Pyramidierte Rpv-Resistenz-Disposition | Rpv-Genpyramide | Kombinierte Rpv-Resistenz",
    "example_of_usage": "The breeding program at Hochschule Geisenheim University systematically develops Pyramided_Rpv_Resistance_Disposition genotypes through marker-assisted crossing and selection. ||A strategic cross between a Rpv1+Rpv3-1 carrier (from Muscadinia introgression line × 'Regent') and a Rpv10+Rpv12 carrier (from V. amurensis-derived material) produces a segregating population where approximately 6.25% (1/16) of offspring inherit all four resistance loci. ||These elite selections are identified through multiplex genotyping of linked markers and confirmed through phenotypic evaluation with diverse P. viticola isolates including characterized virulent races. ||Four-gene pyramid genotypes exhibit complete immunity across all tested isolates, with no visible symptoms or microscopic pathogen development even using isolates that partially overcome Rpv3-1 alone. ||Field trials over multiple seasons confirm that pyramided genotypes maintain less than 1% leaf infection under natural epidemic conditions where susceptible controls reach 80-95% infection and single-locus resistant cultivars show 5-20% infection, validating the durability advantage of the pyramiding approach.",
    "editor_note": "Pyramided_Rpv_Resistance_Disposition is_a Rpv_Mediated_Resistance_Disposition. ||This class represents combinations of two or more Rpv loci, distinguished from classes representing individual loci. ||The specific loci present in a pyramided genotype should be documented in associated quality or information entity classes. ||Pyramiding is the recommended breeding strategy for durable resistance given documented instances of Rpv3 resistance erosion in European vineyards with high PIWI cultivar adoption.  This disposition represents the strategic combination of complementary resistance genes to achieve broad-spectrum, durable field resistance that cannot be overcome through single-step pathogen adaptation. ||The underlying principle is that while a pathogen population may evolve virulence against any single resistance gene through effector mutation or deletion, the simultaneous evolution of virulence against multiple, mechanistically independent resistance genes is statistically improbable and would typically incur severe fitness costs. ||Common pyramiding combinations in grapevine breeding include Rpv1+Rpv3, Rpv3+Rpv10, Rpv3+Rpv12, Rpv10+Rpv12, and three-way combinations such as Rpv3+Rpv10+Rpv12. ||Marker-assisted selection enables efficient identification of individuals carrying multiple resistance alleles in early seedling stages, dramatically accelerating the development of pyramided cultivars. ||Pyramided genotypes typically display enhanced resistance phenotypes compared to single-locus carriers, with additive or synergistic effects resulting in more rapid, complete pathogen arrest and reduced probability of resistance breakdown under field conditions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Eibach R, Töpfer R (2015) Traditional grapevine breeding techniques, Grapevine Breeding Programs for the Wine Industry, Woodhead Publishing|| Zini E et al. (2019) Applying genomic information for grapevine downy and powdery mildew resistance, Acta Horticulturae 1248:1-8|| Schneider C et al. (2019) From resistance gene pyramiding to marker-assisted resistance breeding in grapevine, OENO One 53:649-656"
  },
  "Quantitative_Downy_Mildew_Resistance_Disposition": {
    "definition": "A Quantitative_Downy_Mildew_Resistance_Disposition is a Downy_Mildew_Resistance_Disposition that inheres in a Vitis plant and is realized through the cumulative action of multiple genes with small individual effects, collectively conferring partial but broadly effective resistance to Plasmopara viticola across diverse pathogen genotypes.", 
    "alternative_term": "polygenic downy mildew resistance | partial DM resistance | horizontal DM resistance | QTL-based Plasmopara resistance |+ Quantitative Peronospora-Resistenz-Disposition | Polygene Peronospora-Resistenz | Partielle Falscher-Mehltau-Resistenz",
    "example_of_usage": "The Vitis vinifera cultivar 'Kishmish vatkana' from Central Asia exhibits Quantitative_Downy_Mildew_Resistance_Disposition despite lacking characterized Rpv loci, demonstrating that partial resistance exists within the V. vinifera gene pool. ||QTL mapping studies using a 'Kishmish vatkana' × 'Cabernet Sauvignon' population identified five genomic regions on chromosomes 4, 7, 12, 17, and 18 collectively explaining 42% of phenotypic variance for sporulation density. ||Individual QTLs contributed between 6% and 12% of variance, with additive effects combining to reduce sporulation by 60-70% compared to fully susceptible genotypes. ||In field evaluations at INRAE Bordeaux, 'Kishmish vatkana' maintained leaf infection severity of 25-35% during epidemic years when susceptible controls reached 85-95%, demonstrating that quantitative resistance provides meaningful protection even without complete immunity. ||Breeding programs increasingly combine quantitative resistance backgrounds with major Rpv genes, hypothesizing that the polygenic component enhances durability by imposing additional selective constraints on pathogen adaptation.",
    "editor_note": "Quantitative_Downy_Mildew_Resistance_Disposition is_a Downy_Mildew_Resistance_Disposition. ||This class is distinguished from Rpv_Mediated_Resistance_Disposition by its polygenic inheritance and partial resistance phenotype. ||Quantitative resistance may co-occur with major gene resistance in the same genotype, and distinguishing their relative contributions requires genetic analysis. ||The term \"horizontal resistance\" is sometimes used synonymously but is deprecated due to ambiguity. ||QTLs for quantitative resistance may be distinct from or overlap with characterized Rpv loci.  Unlike monogenic Rpv-mediated resistance, quantitative resistance is inherited as a continuous trait controlled by numerous quantitative trait loci (QTLs) distributed across the genome, each contributing incrementally to the overall resistance phenotype. ||The molecular mechanisms underlying quantitative resistance are diverse and may include enhanced basal defense responses, more rapid or intense PAMP-triggered immunity, elevated constitutive levels of antimicrobial compounds, modified leaf surface properties affecting zoospore behavior, and subtle variations in cellular architecture impeding pathogen colonization. ||Quantitative resistance typically manifests as reduced infection frequency, smaller lesion size, decreased sporulation intensity, and extended latent period rather than complete immunity. ||While individual QTLs provide modest effects (typically explaining 5-15% of phenotypic variance), their combination can result in high levels of field resistance. ||A key advantage of quantitative resistance is its presumed durability, as overcoming multiple independent resistance mechanisms simultaneously presents a formidable evolutionary challenge for pathogen populations. ||However, the complex genetic architecture complicates breeding efforts, requiring genomic selection approaches or phenotypic selection under controlled disease pressure to effectively accumulate favorable alleles.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bellin D et al. (2009) Resistance to Plasmopara viticola in grapevine 'Bianca' is controlled by a major dominant gene causing localised necrosis at the infection site, Theoretical and Applied Genetics 120:163-176|| Buonassisi D et al. (2017) Breeding for grapevine downy mildew resistance: a review of \"omics\" approaches, Euphytica 213:103|| Poland JA et al. (2009) Shades of gray: the world of quantitative disease resistance, Trends in Plant Science 14:21-29"
  },
  "Ontogenic_Downy_Mildew_Resistance_Disposition": {
    "definition": "An Ontogenic_Downy_Mildew_Resistance_Disposition is a Downy_Mildew_Resistance_Disposition that inheres in a Vitis plant and is realized through developmental stage-dependent defense mechanisms, with resistance levels varying systematically across the plant's ontogeny and the phenological progression of individual organs.", 
    "alternative_term": "age-related downy mildew resistance | developmental DM resistance | tissue maturity resistance |+ Ontogenetische Peronospora-Resistenz-Disposition | Altersabhängige Peronospora-Resistenz | Entwicklungsbedingte Falscher-Mehltau-Resistenz",
    "example_of_usage": "Studies at Cornell University's Geneva Experiment Station characterized Ontogenic_Downy_Mildew_Resistance_Disposition in 'Chardonnay' grape clusters through systematic inoculation experiments across berry development stages. ||Clusters inoculated at 80% capfall (BBCH 68) exhibited 78% infection incidence with abundant sporulation on developing berries. ||Inoculation at pea-size stage (BBCH 73) resulted in 52% infection with moderate sporulation. ||By bunch closure (BBCH 77), infection dropped to 18% with sparse sporulation confined to pedicel attachment points. ||Post-véraison inoculation (BBCH 83) produced no successful infections regardless of inoculum concentration. ||Biochemical analysis revealed that berry skin total phenolics increased from 2.3 mg/g fresh weight at pea-size to 8.7 mg/g at véraison, while cuticle thickness doubled from 2.1 μm to 4.4 μm over the same period. ||These findings inform the standard recommendation for fungicide applications protecting the critical bloom-to-bunch-closure window, after which ontogenic resistance provides substantial natural protection.",
    "editor_note": "Ontogenic_Downy_Mildew_Resistance_Disposition is_a Downy_Mildew_Resistance_Disposition. ||This class captures developmentally programmed changes in susceptibility that occur in all Vitis genotypes, distinct from genetically variable resistance conferred by Rpv loci or quantitative factors. ||Ontogenic resistance operates independently of but additively with genetic resistance factors. ||The practical significance lies in identifying developmental windows of maximum vulnerability requiring intensive protection.  This disposition reflects the principle that susceptibility to Plasmopara viticola is not constant throughout plant development but changes predictably with tissue age, physiological status, and developmental programming. ||Young, actively expanding leaves are typically most susceptible, with resistance increasing as leaves mature and reach full photosynthetic capacity. ||This age-related resistance correlates with changes in leaf surface properties (cuticle thickness, stomatal density and morphology), cell wall composition (increased lignification and callose content), and accumulation of constitutive defense compounds (phenolics, stilbenes). ||Similarly, grape berries exhibit pronounced ontogenic resistance, with high susceptibility from flowering through several weeks post-bloom, followed by progressive resistance development that renders berries essentially immune by véraison. ||This berry resistance correlates with epidermal cell wall modifications, accumulation of antimicrobial compounds in the skin, and loss of functional stomata. ||Understanding ontogenic resistance is critical for disease management timing, as protection strategies must account for the transient windows of maximum susceptibility during canopy and cluster development.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kennelly MM et al. (2005) Seasonal development of ontogenic resistance to downy mildew in grape berries and rachises, Phytopathology 95:1445-1452|| Ficke A et al. (2002) Ontogenic resistance and plant disease management: a case study of grape powdery mildew, Phytopathology 92:671-675|| Gindro K et al. (2012) Stilbenes: biomarkers of grapevine resistance to disease of high relevance for agronomy, oenology and human health, Plant Defense: Biological Control, Springer"
  },
  "Induced_Downy_Mildew_Resistance_Disposition": {
    "definition": "An Induced_Downy_Mildew_Resistance_Disposition is a Downy_Mildew_Resistance_Disposition that inheres in a Vitis plant and is realized through enhanced defense capacity acquired following prior exposure to resistance-inducing stimuli, including pathogen challenge, beneficial microorganisms, or chemical elicitors.", 
    "alternative_term": "elicitor-induced DM resistance | primed Plasmopara resistance | SAR-mediated DM resistance |+ Induzierte Peronospora-Resistenz-Disposition | Elicitor-induzierte Peronospora-Resistenz | Systemisch erworbene Peronospora-Resistenz",
    "example_of_usage": "Field trials at Agroscope Changins, Switzerland, evaluated Induced_Downy_Mildew_Resistance_Disposition in 'Chasselas' vines treated with the elicitor product Bastid® (laminarin, a β-1,3-glucan from brown algae). ||Weekly applications beginning at BBCH 15 (5 leaves unfolded) primed vine defenses, as confirmed by elevated basal expression of PR-1 and STS (stilbene synthase) genes in treated versus control vines. ||Following natural P. viticola infection during a rainy June period, elicitor-treated vines exhibited 38% lower leaf infection severity (22% versus 35%) and 45% lower cluster infection (12% versus 22%) compared to water-treated controls. ||Microscopic examination of inoculated leaf discs revealed that sporangiophore emergence was delayed by 18-24 hours in elicitor-treated tissue, with 40% fewer sporangiophores per lesion. ||While insufficient as a standalone strategy, integrating elicitor applications with reduced fungicide programs achieved equivalent disease control to conventional programs with 30% fewer synthetic fungicide applications, demonstrating the practical value of induced resistance for sustainable viticulture.",
    "editor_note": "Induced_Downy_Mildew_Resistance_Disposition is_a Downy_Mildew_Resistance_Disposition. ||This class encompasses all forms of enhanced resistance acquired through prior stimulation, distinguished from constitutive genetic resistance (Rpv-mediated, quantitative) and developmental resistance (ontogenic). ||The induced state is transient and requires repeated elicitation to maintain protection throughout the growing season. ||Induced resistance provides complementary protection that can be integrated with genetic resistance and conventional disease management.  This disposition represents a primed state of the plant immune system characterized by faster, stronger, and more sustained activation of defense responses upon subsequent pathogen encounter. ||Induced resistance in grapevine against P. viticola can be triggered through multiple pathways, including systemic acquired resistance (SAR) following localized pathogen infection, induced systemic resistance (ISR) elicited by plant growth-promoting rhizobacteria or mycorrhizal fungi, and chemically induced resistance activated by synthetic or natural elicitor compounds. ||Molecular signatures of the induced resistant state include elevated expression of defense-related genes (PR proteins, stilbene synthases), accumulation of signaling molecules (salicylic acid, jasmonic acid), epigenetic modifications facilitating rapid transcriptional responses, and enhanced sensitivity of pattern recognition receptors. ||Practical applications of induced resistance in viticulture include phosphonate fungicides (which induce host defenses in addition to direct antimicrobial effects), commercial elicitor products based on β-glucans, chitosan, or plant extracts, and biological control agents that colonize roots or foliar surfaces and prime systemic defenses. ||While induced resistance alone rarely provides complete protection, it can significantly enhance the efficacy of other resistance mechanisms and reduce fungicide requirements.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Harm A et al. (2011) Evaluation of chemical and natural resistance inducers against downy mildew (Plasmopara viticola) in grapevine, American Journal of Enology and Viticulture 62:184-192|| Perazzolli M et al. (2011) Phosphate-solubilizing Pseudomonas rhizobacteria as potential inducers of systemic resistance against grapevine downy mildew, IOBC/WPRS Bulletin 67:245-251|| Walters DR et al. (2013) Controlling crop diseases using induced resistance: challenges for the future, Journal of Experimental Botany 64:1263-1280"
  },
  "Powdery_Mildew_Resistance_Disposition": {
    "definition": "A Powdery_Mildew_Resistance_Disposition is a Fungal_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with the obligate biotrophic ascomycete Erysiphe necator (syn.", 
    "alternative_term": "Erysiphe necator resistance | oidium resistance disposition | PM resistance potential |+ Echter Mehltau-Resistenz-Disposition | Oidium-Resistenz | Mehltauwiderstandsfähigkeit",
    "example_of_usage": "Comparative evaluation of Powdery_Mildew_Resistance_Disposition across Vitis germplasm at UC Davis Department of Viticulture and Enology employed standardized greenhouse screening with controlled E. necator inoculation (10,000 conidia/mL suspension). ||The V. vinifera cultivar 'Carignan' (susceptible control) developed extensive mycelial colonies covering >90% of inoculated leaf surface within 14 days, with abundant conidiophore production rated OIV 1 (fully susceptible). ||The resistant accession V. romanetii C166-043 carrying Ren4 showed no macroscopic colony development, with microscopic examination revealing 95% of penetration attempts arrested at the papilla formation stage and the remaining 5% triggering single-cell hypersensitive death, rated OIV 9 (highly resistant). ||Intermediate phenotypes in segregating populations displayed reduced colony density, smaller colony diameter, and decreased sporulation intensity, enabling quantification of resistance QTLs contributing to partial resistance phenotypes observed in many interspecific breeding lines.",
    "editor_note": "Powdery_Mildew_Resistance_Disposition is_a Fungal_Resistance_Disposition. ||This class is parallel to Downy_Mildew_Resistance_Disposition under Fungal_Resistance_Disposition. ||Child classes are organized by resistance locus type (Run_Mediated_Resistance_Disposition, Ren_Mediated_Resistance_Disposition) and by resistance mechanism (Quantitative_Powdery_Mildew_Resistance_Disposition, Ontogenic_Powdery_Mildew_Resistance_Disposition, Evasion_Based_Resistance_Disposition). ||The Run and Ren nomenclature follows Vitis gene naming conventions, with \"Run\" originally denoting resistance from Uncinula (former genus name) and \"Ren\" denoting resistance from other sources.  Uncinula necator), the causal agent of grapevine powdery mildew. ||This disposition represents the capacity to limit one or more stages of the E. necator infection cycle, including conidial germination, appressorium formation, penetration peg insertion through the cuticle, haustorial establishment in epidermal cells, and subsequent hyphal proliferation and sporulation on the plant surface. ||Unlike downy mildew where infection occurs through stomata, powdery mildew requires direct cuticular penetration, making cell wall properties and rapid cell wall reinforcement critical resistance components. ||Powdery mildew resistance dispositions in Vitis operate through mechanisms including pre-formed physical barriers (cuticle thickness and composition), rapid papilla formation blocking penetration attempts, hypersensitive response killing penetrated cells before haustorial maturation, and post-penetration resistance limiting colony expansion and reproduction. ||Major resistance loci designated Run (Resistance to Uncinula necator) and Ren (Resistance from Erysiphe necator) have been mapped in various wild Vitis species, with Run1 from Muscadinia rotundifolia and Ren1 from V. vinifera 'Kishmish vatkana' being most characterized. ||Powdery mildew resistance is essential for sustainable viticulture globally, as E. necator thrives in both humid and semi-arid climates and can cause severe crop losses through direct berry infection leading to cluster rots and off-flavors in wine.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gadoury DM et al. (2012) Grapevine powdery mildew (Erysiphe necator): a fascinating system for the study of the biology, ecology and epidemiology of an obligate biotroph, Molecular Plant Pathology 13:1-16|| Qiu W et al. (2015) Current understanding of grapevine defense mechanisms against the biotrophic fungus (Erysiphe necator), the causal agent of powdery mildew disease, Horticulture Research 2:15020|| Dry IB et al. (2010) Molecular strategies to enhance the genetic resistance of grapevines to powdery mildew, Australian Journal of Grape and Wine Research 16:94-105"
  },
  "Run_Mediated_Resistance_Disposition": {
    "definition": "A Run_Mediated_Resistance_Disposition is a Powdery_Mildew_Resistance_Disposition that inheres in a Vitis plant carrying one or more Run (Resistance to Uncinula necator) loci and is realized through effector-triggered immunity upon recognition of corresponding Erysiphe necator avirulence effectors.", 
    "alternative_term": "Run locus powdery mildew resistance | Muscadinia PM resistance | major gene oidium resistance |+ Run-vermittelte Resistenz-Disposition | Run-Mehltau-Resistenz | Majorgen-Oidium-Resistenz",
    "example_of_usage": "The breeding program at CSIRO Agriculture and Food, Australia, has developed advanced selections carrying Run_Mediated_Resistance_Disposition through marker-assisted introgression from M. rotundifolia. ||The selection 2000-30-19, a BC4 generation pseudo-backcross with >96% V. vinifera genetic background, carries the Run1 locus as confirmed by the tightly linked VVIM11 marker. ||Controlled inoculation with E. necator isolates at 5,000 conidia/mL resulted in complete resistance, with hypersensitive cell death visible as small necrotic spots (diameter <0.5mm) at inoculation sites within 36 hours and no subsequent mycelial growth or conidiation through 21 days observation. ||Histological examination revealed that germinating conidia formed appressoria normally but penetration was arrested at the cell wall, with attempted penetration sites marked by intense callose deposition and rapid browning of the attacked epidermal cell. ||This strong, pre-haustorial resistance phenotype demonstrates the exceptional efficacy of Run1-mediated defense against powdery mildew establishment.",
    "editor_note": "Run_Mediated_Resistance_Disposition is_a Powdery_Mildew_Resistance_Disposition. ||The \"Run\" nomenclature derives from the former genus name Uncinula for the powdery mildew pathogen, now correctly Erysiphe. ||Run loci are distinguished from Ren loci by their origin in Muscadinia rotundifolia specifically. ||Run1 and Run2 both originate from M. rotundifolia but map to different chromosomes (12 and 18 respectively) and have independent recognition specificities. ||Run1 is physically linked to Rpv1 on chromosome 12, enabling co-selection for both powdery and downy mildew resistance.  The Run loci encode nucleotide-binding leucine-rich repeat (NLR) receptor proteins that detect specific fungal effectors secreted during attempted colonization, triggering rapid and robust defense responses that arrest pathogen development. ||The Run1 locus from Muscadinia rotundifolia is the most extensively characterized, located on chromosome 12 in a resistance gene cluster that also includes Rpv1 for downy mildew resistance. ||Run1 encodes a TIR-NB-LRR protein (MrRUN1) that recognizes an as-yet-unidentified E. necator effector, triggering programmed cell death at the site of attempted penetration. ||The Run2 locus, also from M. rotundifolia, represents an independent resistance gene with distinct recognition specificity located on chromosome 18. ||Run-mediated resistance phenotypes are characterized by rapid hypersensitive response, typically visible as small brown necrotic flecks within 48-72 hours post-inoculation, with no subsequent colony development or sporulation. ||The co-inheritance of Run1 with Rpv1 provides exceptional breeding value, enabling simultaneous introgression of resistance to both major fungal diseases from a single donor source, though the Muscadinia origin necessitates extensive backcrossing to restore V. vinifera quality characteristics.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hoffmann S et al. (2008) Resistance to Erysiphe necator in the grapevine 'Kishmish vatkana' is controlled by a single locus through restriction of hyphal growth, Theoretical and Applied Genetics 116:427-438|| Feechan A et al. (2013) Genetic dissection of a TIR-NB-LRR locus from the wild North American grapevine species Muscadinia rotundifolia, Molecular Plant-Microbe Interactions 26:684-695|| Dry IB et al. (2019) Grapevine NLR immunity against downy and powdery mildew pathogens, Acta Horticulturae 1248:129-136"
  },
  "Run1_Resistance_Disposition": {
    "definition": "A Run1_Resistance_Disposition is a Run_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Run1 locus derived from Muscadinia rotundifolia and is realized through effector-triggered immunity mediated by the MrRUN1 TIR-NB-LRR receptor protein upon recognition of corresponding Erysiphe necator avirulence effectors.", 
    "alternative_term": "Run1 powdery mildew resistance | MrRUN1 resistance | chromosome 12 PM resistance |+ Run1-Resistenz-Disposition | Run1-Oidium-Resistenz | MrRUN1-vermittelte Resistenz",
    "example_of_usage": "Transgenic validation of Run1_Resistance_Disposition was achieved at CSIRO by transforming susceptible V. vinifera 'Shiraz' with the MrRUN1 gene under its native promoter. ||Transformed lines expressing MrRUN1 exhibited complete resistance to E. necator, with inoculated leaves showing hypersensitive cell death at penetration sites and no subsequent colony establishment, identical to the phenotype observed in M. rotundifolia. ||Non-transformed 'Shiraz' controls developed extensive powdery colonies covering >80% of leaf surface by 14 days post-inoculation. ||Further characterization revealed that Run1 resistance is effective against E. necator isolates from Australia (genetic group B predominant), California (mixed A and B), and Europe (group B), indicating broad-spectrum resistance across pathogen diversity. ||In BC3 pseudo-backcross breeding lines with 87.5% theoretical V. vinifera background, Run1 resistance remained fully effective while sensory evaluation of micro-vinifications showed wine quality approaching commercial V. vinifera standards, demonstrating successful combination of disease resistance with acceptable enological characteristics.",
    "editor_note": "Run1_Resistance_Disposition is_a Run_Mediated_Resistance_Disposition. ||Run1 is physically linked to Rpv1 on chromosome 12, and both loci are typically co-inherited in breeding programs. ||The MrRUN1 gene has been functionally validated through transgenic complementation. ||Run1 provides broad-spectrum resistance against diverse E. necator genetic groups. ||Breeding lines must be advanced through multiple backcross generations to recover V. vinifera quality characteristics while maintaining the resistance locus through marker-assisted selection.  The Run1 locus maps to a resistance gene cluster on chromosome 12 that includes the linked Rpv1 locus for downy mildew resistance, enabling co-inheritance of both resistances through a single introgression event. ||The MrRUN1 gene was the first powdery mildew resistance gene functionally characterized in grapevine through transgenic complementation experiments demonstrating that its expression alone is sufficient to confer the resistance phenotype in susceptible V. vinifera backgrounds. ||Run1-mediated resistance operates primarily through pre-penetration and penetration-stage arrest, with hypersensitive cell death triggered rapidly upon pathogen recognition. ||The resistance is highly effective against diverse E. necator genetic groups including the A (Flag Shoot) and B (ascospore) populations present in different viticultural regions. ||Run1 represents a cornerstone of powdery mildew resistance breeding, with extensive deployment in European, American, and Australian breeding programs, though its Muscadinia origin requires extensive pseudo-backcrossing to restore V. vinifera genetic background and wine quality characteristics while maintaining resistance through marker-assisted selection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Feechan A et al. (2013) Genetic dissection of a TIR-NB-LRR locus from the wild North American grapevine species Muscadinia rotundifolia, Molecular Plant-Microbe Interactions 26:684-695|| Dry IB et al. (2010) Molecular strategies to enhance the genetic resistance of grapevines to powdery mildew, Australian Journal of Grape and Wine Research 16:94-105|| Bouquet A (1986) Introduction dans l'espèce Vitis vinifera L. d'un caractère de résistance à l'oïdium (Uncinula necator) issu de l'espèce Muscadinia rotundifolia, Vignevini 12:141-146"
  },
  "Run2_Resistance_Disposition": {
    "definition": "A Run2_Resistance_Disposition is a Run_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Run2 locus derived from Muscadinia rotundifolia and is realized through effector-triggered immunity upon recognition of Erysiphe necator avirulence effectors distinct from those recognized by Run1.", 
    "alternative_term": "Run2 powdery mildew resistance | chromosome 18 PM resistance | second Muscadinia PM resistance |+ Run2-Resistenz-Disposition | Run2-Oidium-Resistenz | Chromosom-18-Mehltau-Resistenz",
    "example_of_usage": "Genetic mapping of Run2_Resistance_Disposition utilized a segregating population derived from the M. rotundifolia accession 'Magnolia', which exhibits strong powdery mildew resistance but lacks markers linked to the Run1 locus. ||Linkage analysis using SSR and SNP markers localized Run2 to a 3.2 cM interval on chromosome 18, distinct from the chromosome 12 location of Run1. ||Phenotypic evaluation using detached leaf assays with E. necator conidia (8,000/mL) demonstrated that Run2 confers complete resistance characterized by hypersensitive cell death at inoculation sites without subsequent mycelial development or sporulation, qualitatively similar to Run1. ||Critically, when a breeding line combining both Run1 and Run2 was challenged with E. necator isolates showing partial adaptation to Run1 (reduced but not eliminated sporulation on Run1-only genotypes), the pyramided Run1+Run2 line maintained complete resistance, validating the complementary recognition specificities of these loci. ||This finding supports the breeding strategy of combining multiple Run loci to enhance resistance durability in the face of pathogen evolution.",
    "editor_note": "Run2_Resistance_Disposition is_a Run_Mediated_Resistance_Disposition. ||Run2 is located on chromosome 18, genetically independent from the Run1/Rpv1 cluster on chromosome 12. ||Run2 originates from different M. rotundifolia accessions than Run1, requiring separate introgression programs. ||The combination of Run1 and Run2 provides enhanced durability through redundant recognition of pathogen effectors. ||The Run2 resistance gene has not yet been molecularly cloned, unlike MrRUN1.  The Run2 locus maps to chromosome 18, genetically independent from the Run1/Rpv1 cluster on chromosome 12, and was identified in specific M. rotundifolia accessions that lack Run1. ||The independent chromosomal location and distinct recognition specificity of Run2 make it valuable for resistance gene pyramiding strategies, as combining Run1 and Run2 in a single genotype provides redundant recognition capacity that enhances durability against potential resistance-breaking pathogen variants. ||Run2-mediated resistance operates through similar mechanisms to Run1, with rapid hypersensitive response arresting pathogen development at early penetration stages. ||However, the molecular identity of the Run2 gene and its cognate effector remain to be fully characterized. ||Because Run2 originates from M. rotundifolia accessions distinct from those carrying Run1, introgression requires separate crosses and backcross programs, though marker-assisted selection enables efficient identification of carriers in segregating populations. ||The combination of Run1, Run2, and Ren loci from other Vitis species represents a comprehensive strategy for durable powdery mildew resistance in cultivated grapevines.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Riaz S et al. (2011) Identification of mildew resistance in wild and cultivated Central Asian grape germplasm, BMC Plant Biology 11:149|| Blanc S et al. (2012) Identification and mapping of powdery mildew resistance locus MrRun2 in grapevine, Acta Horticulturae 948:175-181|| Dry IB et al. (2019) Grapevine NLR immunity against downy and powdery mildew pathogens, Acta Horticulturae 1248:129-136"
  },
  "Ren_Mediated_Resistance_Disposition": {
    "definition": "A Ren_Mediated_Resistance_Disposition is a Powdery_Mildew_Resistance_Disposition that inheres in a Vitis plant carrying one or more Ren (Resistance from Erysiphe necator) loci and is realized through effector-triggered immunity upon recognition of corresponding Erysiphe necator avirulence effectors.", 
    "alternative_term": "Ren locus powdery mildew resistance | Vitis-derived PM resistance | non-Muscadinia PM resistance |+ Ren-vermittelte Resistenz-Disposition | Ren-Mehltau-Resistenz | Ren-Lokus-Oidium-Resistenz",
    "example_of_usage": "The grapevine breeding consortium VitisGen evaluated Ren_Mediated_Resistance_Disposition across a diversity panel of 380 Vitis accessions using standardized greenhouse screening with E. necator isolate NY19 (genetic group B). ||Genotypes were scored 21 days post-inoculation using a 0-5 visual scale for colony coverage and sporulation intensity. ||Accessions carrying characterized Ren loci exhibited dramatically reduced infection compared to susceptible V. vinifera controls (mean score 4.7). ||Ren1 carriers ('Kishmish vatkana' derivatives) scored 0.3-0.8 with sparse hypersensitive flecking. ||Ren4 carriers (V. romanetii accessions) scored 0.0-0.2 with no visible colony development. ||Ren3 carriers ('Regent', 'Villard blanc') scored 1.2-1.8 with small, weakly sporulating colonies. ||The phenotypic variation among Ren loci reflects differences in recognition timing and downstream response intensity. ||Marker-assisted selection using locus-specific SSR markers enabled efficient identification of resistance alleles in segregating populations, with pyramided Ren1+Ren4 individuals displaying enhanced resistance (score 0.0) compared to single-locus carriers, supporting the strategy of combining multiple Ren sources for comprehensive protection.",
    "editor_note": "Ren_Mediated_Resistance_Disposition is_a Powdery_Mildew_Resistance_Disposition. ||Ren loci are distinguished from Run loci by their non-Muscadinia origins, though both confer major gene resistance to Erysiphe necator. ||The Ren nomenclature follows the convention established when the first locus outside Muscadinia was characterized. ||Child classes represent individual Ren loci numbered sequentially by discovery order. ||Some Ren loci (e.g., Ren5, Ren7) are omitted from VVO pending validation or due to limited breeding utility.  The Ren designation encompasses major resistance genes identified in various Vitis species outside of Muscadinia rotundifolia, distinguishing them from Run loci which specifically derive from Muscadinia. ||Over ten Ren loci have been mapped across the Vitis genus, originating from diverse species including V. vinifera (Ren1 from 'Kishmish vatkana'), V. cinerea (Ren2), interspecific hybrids (Ren3 from 'Regent'), V. romanetii (Ren4), V. piasezkii (Ren6), and others. ||Each Ren locus encodes NLR receptor proteins recognizing specific E. necator effectors, triggering defense responses that arrest pathogen development at various infection stages. ||The resistance phenotypes conferred by different Ren loci range from complete immunity with rapid hypersensitive response to partial resistance with reduced colony size and sporulation. ||The diversity of Ren loci origins provides extensive opportunities for resistance gene pyramiding, combining loci with distinct recognition specificities to achieve durable field resistance. ||Notably, Ren1 represents the only major powdery mildew resistance gene identified within V. vinifera itself, offering the unique advantage of introgression without the quality penalties associated with wild species ancestry, though its single-source origin raises durability concerns that favor combination with additional Ren or Run loci.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hoffmann S et al. (2008) Resistance to Erysiphe necator in the grapevine 'Kishmish vatkana' is controlled by a single locus through restriction of hyphal growth, Theoretical and Applied Genetics 116:427-438|| Qiu W et al. (2015) Current understanding of grapevine defense mechanisms against the biotrophic fungus (Erysiphe necator), Horticulture Research 2:15020|| Dry IB et al. (2019) Grapevine NLR immunity against downy and powdery mildew pathogens, Acta Horticulturae 1248:129-136"
  },
  "Ren1_Resistance_Disposition": {
    "definition": "A Ren1_Resistance_Disposition is a Ren_Mediated_Resistance_Disposition that inheres in a Vitis vinifera plant carrying the Ren1 locus derived from the Central Asian cultivar 'Kishmish vatkana' and is realized through effector-triggered immunity upon recognition of corresponding Erysiphe necator avirulence effectors.", 
    "alternative_term": "Ren1 powdery mildew resistance | Kishmish vatkana resistance | V. vinifera PM resistance |+ Ren1-Resistenz-Disposition | Ren1-Oidium-Resistenz | Kishmish-vatkana-Resistenz",
    "example_of_usage": "The breeding program at University of California, Davis, systematically evaluated Ren1_Resistance_Disposition inheritance using populations derived from 'Kishmish vatkana' crossed to elite V. vinifera wine grape cultivars. ||A 'Kishmish vatkana' × 'Cabernet Sauvignon' F1 population segregated 1:1 for resistance, confirming single dominant gene inheritance. ||Resistant individuals showed characteristic Ren1 phenotype upon E. necator inoculation: germinating conidia formed appressoria and penetrated epidermal cells normally, establishing primary haustoria visible microscopically at 24 hours post-inoculation. ||However, by 48-72 hours, penetrated cells and 2-4 adjacent cells underwent hypersensitive death, arresting further colonization. ||Macroscopically, small necrotic flecks (1-2mm diameter) developed without subsequent mycelial proliferation or sporulation. ||In contrast, susceptible siblings supported extensive colony development with abundant conidiophore production. ||Marker-assisted backcrossing using the Ren1-linked marker SC8-0071-014 enabled selection of BC2 individuals retaining Ren1 with 87.5% 'Cabernet Sauvignon' genetic background, demonstrating the feasibility of introgressing Ren1 while maintaining varietal character for high-quality wine production.",
    "editor_note": "Ren1_Resistance_Disposition is_a Ren_Mediated_Resistance_Disposition. ||Ren1 is uniquely derived from V. vinifera rather than wild Vitis species, located on chromosome 13. ||The post-penetration resistance mechanism distinguishes Ren1 from Run1 which operates pre-penetration. ||The V. vinifera origin eliminates interspecific hybridization quality penalties but limits genetic diversity of resistance sources. ||Combining Ren1 with Run or other Ren loci is recommended for enhanced durability.  Ren1 holds unique significance as the only major powdery mildew resistance gene identified within the V. vinifera species itself, discovered in traditional table grape cultivars from Uzbekistan and adjacent regions where endemic E. necator populations likely exerted long-term selection pressure. ||The Ren1 locus maps to chromosome 13 and encodes an NLR receptor that triggers post-penetration resistance, allowing initial fungal penetration and haustorial formation but restricting subsequent hyphal growth through programmed cell death of colonized cells. ||This post-haustorial resistance mechanism contrasts with the pre-penetration resistance conferred by Run1. ||The V. vinifera origin of Ren1 provides a critical breeding advantage, as introgression does not introduce the undesirable flavor compounds, color instability, or other quality deficits associated with interspecific hybridization. ||However, the single germplasm source and post-penetration mechanism raise concerns about durability under high disease pressure, motivating strategies to combine Ren1 with additional resistance loci. ||Ren1 has been successfully deployed in breeding programs worldwide, contributing to cultivars that combine high wine quality with reduced fungicide requirements.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hoffmann S et al. (2008) Resistance to Erysiphe necator in the grapevine 'Kishmish vatkana' is controlled by a single locus through restriction of hyphal growth, Theoretical and Applied Genetics 116:427-438|| Coleman C et al. (2009) The powdery mildew resistance gene REN1 co-segregates with an NBS-LRR gene cluster in two Central Asian grapevines, BMC Genetics 10:89|| Riaz S et al. (2013) Genetic mapping of Ren1 and development of markers for marker-assisted selection of powdery mildew resistance in grapevine, Theoretical and Applied Genetics 126:1355-1363"
  },
  "Ren2_Resistance_Disposition": {
    "definition": "A Ren2_Resistance_Disposition is a Ren_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Ren2 locus derived from Vitis cinerea and is realized through effector-triggered immunity upon recognition of corresponding Erysiphe necator avirulence effectors.", 
    "alternative_term": "Ren2 powdery mildew resistance | V. cinerea PM resistance | chromosome 14 PM resistance |+ Ren2-Resistenz-Disposition | Ren2-Oidium-Resistenz | Cinerea-Mehltau-Resistenz",
    "example_of_usage": "Genetic characterization of Ren2_Resistance_Disposition at the University of Missouri utilized mapping populations derived from the resistant V. cinerea accession B9. ||QTL analysis identified a major resistance locus on chromosome 14 explaining 72% of phenotypic variance for powdery mildew severity, subsequently designated Ren2. ||Resistant individuals carrying the Ren2 allele displayed hypersensitive response within 24-36 hours of E. necator penetration attempts, with microscopic examination revealing intense hydrogen peroxide accumulation (visualized by DAB staining) in cells contacted by fungal appressoria. ||Macroscopically, Ren2 carriers developed small brown flecks (<1mm diameter) at inoculation sites without subsequent mycelial growth, contrasting with susceptible V. vinifera 'Norton' controls showing extensive white powdery colonies. ||The Ren2-linked SSR marker VMC7f2 enables marker-assisted selection in breeding populations. ||Advanced selections combining Ren2 with other resistance sources showed complete immunity in field trials at Mountain Grove, Missouri, under natural disease pressure that caused 60-80% leaf coverage on susceptible controls, demonstrating effective pyramiding of Ren2 with complementary resistance genes.",
    "editor_note": "Ren2_Resistance_Disposition is_a Ren_Mediated_Resistance_Disposition. ||Ren2 originates from V. cinerea, a North American species distinct from the Muscadinia source of Run loci. ||The chromosome 14 location is independent from other major PM resistance loci. ||V. cinerea ancestry introduces quality challenges (herbaceous flavors) requiring extensive backcrossing. ||Ren2 has contributed to resistance in some French-American hybrids, though its molecular identity remains to be fully characterized.  The Ren2 locus maps to chromosome 14 and originates from V. cinerea, a North American wild species distributed across the southeastern and central United States that evolved in sympatry with endemic Erysiphe populations. ||V. cinerea exhibits exceptional powdery mildew resistance and has contributed resistance factors to several French-American hybrid cultivars developed in the 19th and early 20th centuries. ||The Ren2 resistance phenotype is characterized by rapid hypersensitive response with localized cell death arresting fungal development at early post-penetration stages, resulting in small necrotic lesions without macroscopic colony establishment or sporulation. ||The chromosomal location of Ren2 on chromosome 14 is independent from other major resistance loci, making it valuable for pyramiding strategies. ||However, V. cinerea introgression is associated with characteristic herbaceous and foxy flavor compounds that require extensive backcrossing to eliminate while retaining the resistance locus. ||Despite these quality challenges, Ren2 provides a robust resistance source with recognition specificity complementary to other Ren and Run loci, contributing to comprehensive resistance breeding strategies that combine multiple genes for durable protection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dalbó MA et al. (2001) A gene controlling sex in grapevines placed on a molecular marker-based genetic map, Genome 44:75-82|| Qiu W et al. (2015) Current understanding of grapevine defense mechanisms against the biotrophic fungus (Erysiphe necator), Horticulture Research 2:15020"
  },
  "Ren3_Resistance_Disposition": {
    "definition": "A Ren3_Resistance_Disposition is a Ren_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Ren3 locus and is realized through effector-triggered immunity conferring partial resistance to Erysiphe necator.", 
    "alternative_term": "Ren3 powdery mildew resistance | Regent PM resistance | chromosome 15 PM resistance |+ Ren3-Resistenz-Disposition | Ren3-Oidium-Resistenz | Regent-Mehltau-Resistenz",
    "example_of_usage": "Field evaluation of Ren3_Resistance_Disposition at the Geilweilerhof research station, Germany, compared powdery mildew development on 'Regent' (Ren3 carrier) versus susceptible 'Müller-Thurgau' over five consecutive seasons under reduced spray programs (3-4 applications versus standard 8-10). 'Regent' exhibited consistent partial resistance with mean leaf infection severity of 12-18% (OIV 452 rating 5-6) compared to 65-85% in untreated 'Müller-Thurgau' controls. ||Microscopic examination revealed that E. necator successfully established colonies on 'Regent' leaves, but colony expansion was restricted to approximately 40% of the diameter observed on susceptible tissue, and sporulation intensity was reduced by 60-70%. ||Importantly, monitoring studies detected E. necator isolates with increased aggressiveness on Ren3 backgrounds in vineyards with high 'Regent' adoption, emphasizing the partial nature of this resistance and the importance of combining Ren3 with additional loci. ||Breeding selections pyramiding Ren3 with Ren9 or Run1 displayed enhanced resistance (leaf infection <5%) compared to Ren3 alone, validating complementation strategies.",
    "editor_note": "Ren3_Resistance_Disposition is_a Ren_Mediated_Resistance_Disposition. ||Ren3 confers partial rather than complete resistance, distinguishing it from Run1, Ren1, and Ren4 which provide near-immunity. ||The locus on chromosome 15 may represent a complex of linked resistance factors. ||Ren3 is widely deployed in European PIWI cultivars but shows evidence of durability challenges similar to Rpv3 for downy mildew. ||Pyramiding with other Ren or Run loci is strongly recommended.  The Ren3 locus maps to chromosome 15 and was identified in the PIWI cultivar 'Regent' and related breeding material derived from complex interspecific pedigrees involving French-American hybrids. ||Unlike Run1 or Ren1 which confer near-complete resistance, Ren3 provides quantitative resistance characterized by reduced colony size, decreased sporulation intensity, and extended latent period rather than complete immunity. ||This partial resistance phenotype allows limited fungal colonization and reproduction, raising concerns about selection pressure on pathogen populations and potential resistance erosion under intensive deployment. ||The genetic architecture of Ren3 resistance may involve multiple linked genes within a resistance gene cluster on chromosome 15, with the major QTL explaining 50-70% of phenotypic variance in segregating populations. ||Despite its partial nature, Ren3 has been widely deployed in European PIWI cultivars including 'Regent', 'Johanniter', 'Cabernet Cortis', and others, providing meaningful field protection that reduces fungicide requirements by 50-70% compared to fully susceptible V. vinifera cultivars. ||Combining Ren3 with additional resistance loci is recommended to enhance protection level and durability.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Welter LJ et al. (2007) Genetic mapping and localization of quantitative trait loci affecting fungal disease resistance and leaf morphology in grapevine, Molecular Breeding 20:359-374|| Zendler D et al. (2017) Fine mapping of Ren3 reveals two loci mediating hypersensitive response against Erysiphe necator in grapevine, Euphytica 213:68|| Töpfer R, Hausmann L (2010) Breeding for fungal disease resistant grapevines, Genetics, Genomics and Breeding of Grapes, Science Publishers"
  },
  "Ren4_Resistance_Disposition": {
    "definition": "A Ren4_Resistance_Disposition is a Ren_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Ren4 locus derived from Vitis romanetii and is realized through effector-triggered immunity conferring exceptionally strong, broad-spectrum resistance to Erysiphe necator.", 
    "alternative_term": "Ren4 powdery mildew resistance | V. romanetii PM resistance | Chinese grape PM resistance |+ Ren4-Resistenz-Disposition | Ren4-Oidium-Resistenz | Romanetii-Mehltau-Resistenz",
    "example_of_usage": "Comprehensive phenotypic characterization of Ren4_Resistance_Disposition at Cornell University's Geneva Experiment Station employed controlled inoculation experiments with E. necator isolates representing genetic groups A (flag shoot), B (ascosporic), and multiple genotypes within each group. ||The V. romanetii accession C166-043 carrying Ren4 exhibited complete immunity against all 23 tested isolates, with no visible symptoms or microscopic evidence of successful penetration events through 28 days post-inoculation at inoculum densities up to 50,000 conidia/mL. ||Histological examination using calcoflour white staining revealed that 98% of germinated conidia formed appressoria normally but failed at the penetration stage, with intense papilla formation visible beneath attempted penetration sites. ||The remaining 2% of penetration attempts triggered immediate single-cell hypersensitive death. ||In F1 populations from Ren4 × V. vinifera crosses, resistance segregated 1:1 confirming dominant single-gene inheritance. ||BC1 and BC2 selections combining Ren4 with 75-87.5% V. vinifera background retained complete resistance while showing progressive improvement in fruit quality parameters including increased berry size, reduced titratable acidity, and more neutral flavor profile.",
    "editor_note": "Ren4_Resistance_Disposition is_a Ren_Mediated_Resistance_Disposition. ||Ren4 originates from V. romanetii, a Chinese species, and maps to chromosome 18. ||The exceptionally strong, pre-penetration resistance mechanism distinguishes Ren4 from Ren1 (post-penetration) and Ren3 (partial). ||Broad-spectrum efficacy across E. necator genetic groups makes Ren4 particularly valuable. ||V. romanetii ancestry introduces significant quality challenges requiring extensive backcrossing.  The Ren4 locus maps to chromosome 18 and originates from V. romanetii, a Chinese wild species closely related to V. piasezkii and V. davidii that evolved in regions with endemic powdery mildew pressure. ||Ren4 confers one of the strongest powdery mildew resistance phenotypes observed in Vitis, characterized by rapid pre-penetration arrest with intense papilla formation blocking fungal entry at the cell wall, complemented by hypersensitive response in the rare cells where penetration succeeds. ||This multi-layered defense results in complete immunity across diverse E. necator genetic groups and isolates, with no macroscopic or microscopic evidence of fungal colonization even under extreme inoculum pressure. ||The broad-spectrum efficacy and pre-penetration mechanism make Ren4 exceptionally valuable for resistance breeding, though V. romanetii introgression introduces quality challenges including small berry size, high acidity, and distinctive flavor compounds requiring extensive backcrossing to recover commercial quality characteristics. ||Marker-assisted selection enables efficient introgression of Ren4 while progressively restoring V. vinifera background through marker-assisted backcrossing programs.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ramming DW et al. (2011) A single dominant locus, Ren4, confers rapid non-race-specific resistance to grapevine powdery mildew, Phytopathology 101:502-508|| Riaz S et al. (2011) Identification of mildew resistance in wild and cultivated Central Asian grape germplasm, BMC Plant Biology 11:149|| Qiu W et al. (2015) Current understanding of grapevine defense mechanisms against the biotrophic fungus (Erysiphe necator), Horticulture Research 2:15020"
  },
  "Ren6_Resistance_Disposition": {
    "definition": "A Ren6_Resistance_Disposition is a Ren_Mediated_Resistance_Disposition that inheres in a Vitis plant carrying the Ren6 locus derived from Vitis piasezkii and is realized through effector-triggered immunity conferring strong resistance to Erysiphe necator.", 
    "alternative_term": "Ren6 powdery mildew resistance | V. piasezkii PM resistance | chromosome 9 PM resistance |+ Ren6-Resistenz-Disposition | Ren6-Oidium-Resistenz | Piasezkii-Mehltau-Resistenz",
    "example_of_usage": "Genetic mapping of Ren6_Resistance_Disposition utilized a population derived from the resistant V. piasezkii accession DVIT2027 crossed to susceptible V. vinifera 'Malaga Rosada'. ||QTL analysis identified a major resistance locus on chromosome 9 explaining 67% of phenotypic variance, designated Ren6. ||Phenotypic evaluation using detached leaf disc assays with E. necator conidia demonstrated that Ren6 carriers exhibited hypersensitive response within 36-48 hours post-inoculation, with small necrotic lesions (diameter <1mm) and no subsequent mycelial growth or sporulation. ||Interestingly, a second linked QTL (Ren7) was detected 8 cM from Ren6, contributing an additional 15% of phenotypic variance. ||Individuals carrying both Ren6 and Ren7 showed enhanced resistance compared to Ren6-only carriers, with more rapid hypersensitive response and smaller necrotic lesions. ||The V. piasezkii resistance gene cluster on chromosome 9 provides breeding programs with a valuable new source for powdery mildew resistance, particularly attractive because the same species carries Rpv5 downy mildew resistance, enabling potential dual-disease resistance introgression from a single donor.",
    "editor_note": "Ren6_Resistance_Disposition is_a Ren_Mediated_Resistance_Disposition. ||Ren6 originates from V. piasezkii and maps to chromosome 9, where it is closely linked to Ren7 forming a resistance gene cluster. ||The co-inheritance of Ren6 and Ren7 provides enhanced resistance compared to either locus alone. ||V. piasezkii additionally carries Rpv5 for downy mildew resistance, offering potential for combined introgression of both disease resistances from this single wild species source.  The Ren6 locus maps to chromosome 9 and originates from V. piasezkii, a Chinese wild species native to central and western China that exhibits exceptional resistance to both powdery and downy mildew diseases. ||Ren6 was identified as genetically distinct from other characterized resistance loci through allelism tests and molecular mapping, providing an additional independent resistance source for pyramiding strategies. ||The Ren6 resistance phenotype is characterized by rapid hypersensitive response arresting fungal development shortly after penetration, resulting in small necrotic flecks without subsequent colony expansion or sporulation. ||Importantly, Ren6 is closely linked to Ren7, another powdery mildew resistance locus identified in the same V. piasezkii accessions, and both loci are typically co-inherited as a resistance gene cluster. ||The combination of Ren6/Ren7 provides robust protection that has proven effective against diverse E. necator populations in multi-environment trials. ||V. piasezkii also carries the Rpv5 locus for downy mildew resistance, potentially enabling simultaneous introgression of resistance to both major fungal diseases from this single wild species source, analogous to the Run1/Rpv1 cluster from Muscadinia.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pap D et al. (2016) Identification of two novel powdery mildew resistance loci, Ren6 and Ren7, from the wild Chinese grape species Vitis piasezkii, BMC Plant Biology 16:170|| Riaz S et al. (2020) Genetic analysis of powdery mildew resistance in Chinese wild Vitis species through association mapping, Molecular Breeding 40:89"
  },
  "Quantitative_Powdery_Mildew_Resistance_Disposition": {
    "definition": "A Quantitative_Powdery_Mildew_Resistance_Disposition is a Powdery_Mildew_Resistance_Disposition that inheres in a Vitis plant and is realized through the cumulative action of multiple genes with individually small effects, collectively conferring partial but durable resistance to Erysiphe necator across diverse pathogen genotypes and environmental conditions.", 
    "alternative_term": "polygenic powdery mildew resistance | partial PM resistance | horizontal oidium resistance | QTL-based PM resistance |+ Quantitative Mehltau-Resistenz-Disposition | Polygene Oidium-Resistenz | Partielle Echter-Mehltau-Resistenz",
    "example_of_usage": "QTL mapping studies for Quantitative_Powdery_Mildew_Resistance_Disposition in a 'Cabernet Sauvignon' × 'Norton' population at the University of Missouri identified seven genomic regions contributing to powdery mildew resistance, none co-localizing with known major Ren or Run loci. ||Individual QTLs on chromosomes 2, 5, 9, 11, 13, 15, and 18 each explained 4-11% of phenotypic variance for colony density and sporulation intensity. ||Individuals accumulating favorable alleles at five or more QTLs showed 55-70% reduction in sporulation compared to those inheriting unfavorable alleles at most loci. ||Field evaluation over four seasons demonstrated that high-QTL selections maintained leaf infection severity of 20-30% under natural epidemic conditions while susceptible segregants reached 70-85%. ||Importantly, the quantitative resistance remained stable across years and locations with different E. necator population structures, supporting the durability hypothesis. ||Genomic selection models incorporating all mapped QTLs achieved prediction accuracies of 0.65-0.72 for powdery mildew severity, enabling efficient selection for quantitative resistance in breeding populations without phenotypic evaluation of individual progeny.",
    "editor_note": "Quantitative_Powdery_Mildew_Resistance_Disposition is_a Powdery_Mildew_Resistance_Disposition. ||This class is distinguished from Ren_Mediated_Resistance_Disposition and Run_Mediated_Resistance_Disposition by its polygenic inheritance and partial resistance phenotype. ||Quantitative resistance may co-occur with major gene resistance, and genomic selection approaches can efficiently accumulate favorable alleles. ||The presumed durability advantage requires validation through long-term deployment studies tracking pathogen population adaptation.  Unlike monogenic Ren- or Run-mediated resistance, quantitative powdery mildew resistance follows continuous inheritance patterns controlled by numerous quantitative trait loci (QTLs) distributed across the genome, each contributing incrementally to the overall resistance phenotype. ||The molecular mechanisms underlying quantitative resistance are diverse and may include enhanced basal defense activation, more effective PAMP-triggered immunity, elevated constitutive levels of antimicrobial compounds in the cuticle and epidermis, modified cell wall architecture impeding fungal penetration, and subtle variations in leaf surface properties affecting conidial germination and appressorium formation. ||Quantitative resistance typically manifests as reduced infection frequency, smaller colony size, decreased sporulation intensity, and extended latent period rather than complete immunity. ||While individual QTLs typically explain only 5-20% of phenotypic variance, their combination can provide commercially meaningful levels of field resistance. ||The presumed durability advantage of quantitative resistance stems from the evolutionary challenge facing pathogen populations in simultaneously overcoming multiple independent resistance mechanisms, each imposing incremental fitness costs on adapted genotypes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Cadle-Davidson L et al. (2016) Lessons from a phenotyping center revealed by the genome-guided mapping of powdery mildew resistance loci, Phytopathology 106:1159-1169|| Poland JA et al. (2009) Shades of gray: the world of quantitative disease resistance, Trends in Plant Science 14:21-29|| Blanc S et al. (2012) Quantitative trait loci for resistance to powdery mildew in two segregating populations of grapevine, BMC Genetics 13:100"
  },
  "Ontogenic_Powdery_Mildew_Resistance_Disposition": {
    "definition": "An Ontogenic_Powdery_Mildew_Resistance_Disposition is a Powdery_Mildew_Resistance_Disposition that inheres in a Vitis plant and is realized through developmental stage-dependent changes in susceptibility, with resistance levels varying systematically across organ ontogeny and the seasonal progression of plant development.", 
    "alternative_term": "age-related powdery mildew resistance | developmental PM resistance | tissue maturity oidium resistance |+ Ontogenetische Mehltau-Resistenz-Disposition | Altersabhängige Oidium-Resistenz | Entwicklungsbedingte Echter-Mehltau-Resistenz",
    "example_of_usage": "Systematic characterization of Ontogenic_Powdery_Mildew_Resistance_Disposition in 'Chardonnay' grape berries at Cornell University quantified the transition from susceptibility to resistance across developmental stages. ||Cluster inoculations with E. necator conidia (20,000/mL) at weekly intervals from bloom through véraison demonstrated dramatic changes in susceptibility. ||Inoculation at bloom (BBCH 65) resulted in 82% berry infection with dense mycelial coverage. ||At 2 weeks post-bloom (6°Brix), infection remained high at 71%. ||By 4 weeks post-bloom (10°Brix), infection dropped to 34%, and by 6 weeks (16°Brix approaching véraison), only 8% of berries became infected with restricted colony development. ||Post-véraison inoculation produced no successful infections. ||Biochemical analysis revealed that berry skin phenolic concentration increased from 1.8 to 7.2 mg/g fresh weight between bloom and véraison, while cuticle proper thickness increased from 0.4 to 1.2 μm. ||These findings establish the \"window of susceptibility\" concept guiding fungicide timing, with applications critical from pre-bloom through 4-6 weeks post-bloom, after which ontogenic resistance provides substantial natural protection.",
    "editor_note": "Ontogenic_Powdery_Mildew_Resistance_Disposition is_a Powdery_Mildew_Resistance_Disposition. ||This class captures developmentally programmed changes in susceptibility occurring in all Vitis genotypes, distinct from genetically variable resistance conferred by Ren or Run loci. ||Ontogenic resistance operates independently of but additively with genetic resistance factors. ||The practical significance lies in identifying developmental windows requiring intensive protection, with the bloom-to-early-ripening period being most critical for berry infection management.  This disposition reflects the well-documented phenomenon that grapevine tissues exhibit profoundly different susceptibility to Erysiphe necator depending on their developmental age and physiological status. ||Young, actively expanding leaves are highly susceptible, with resistance increasing progressively as leaves mature, reaching near-immunity approximately 14-21 days after full expansion. ||This leaf ontogenic resistance correlates with changes in cuticle composition and thickness, epidermal cell wall architecture, accumulation of phenolic compounds, and declining metabolic activity favorable for biotrophic pathogen nutrition. ||Berry ontogenic resistance is particularly pronounced and economically significant, with berries highly susceptible from bloom through approximately 4 weeks post-bloom (until approximately 8°Brix), after which susceptibility declines rapidly. ||By véraison, berries are essentially immune to new infections regardless of inoculum pressure. ||This berry resistance transition involves changes in epidermal cell wall composition, cuticle restructuring during ripening, and accumulation of antimicrobial compounds. ||Understanding ontogenic resistance informs disease management strategies, identifying critical windows when protection is essential and periods when natural resistance provides adequate protection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ficke A et al. (2002) Ontogenic resistance and plant disease management: a case study of grape powdery mildew, Phytopathology 92:671-675|| Gadoury DM et al. (2003) Effects of diffuse colonization of grape berries by Uncinula necator on bunch rots, berry microflora, and juice and wine quality, Phytopathology 93:925-932|| Gindro K et al. (2012) Stilbenes: biomarkers of grapevine resistance to disease, Plant Defense: Biological Control, Springer"
  },
  "Evasion_Based_Resistance_Disposition": {
    "definition": "An Evasion_Based_Resistance_Disposition is a Powdery_Mildew_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through architectural, phenological, or morphological characteristics that reduce pathogen encounter, establishment, or epidemic development without direct physiological or genetic resistance mechanisms.", 
    "alternative_term": "disease escape disposition | architectural PM avoidance | phenological disease evasion |+ Ausweich-basierte Resistenz-Disposition | Krankheitsvermeidungs-Disposition | Architektonische Mehltau-Resistenz",
    "example_of_usage": "Evaluation of Evasion_Based_Resistance_Disposition at INRAE Bordeaux compared powdery mildew development on 'Sauvignon Blanc' (compact clusters, dense canopy) versus 'Merlot' (looser clusters, more open canopy) under identical management and natural disease pressure. ||Despite similar genetic susceptibility to E. necator in controlled inoculation tests (OIV rating 3 for both), field disease severity differed significantly. 'Merlot' clusters exhibited 40% lower berry infection severity (mean 18% versus 30% in 'Sauvignon Blanc') correlated with its looser cluster architecture (OIV 204 rating 5 versus 7) promoting faster drying after rainfall and dew events. ||Microclimate monitoring revealed that cluster-zone relative humidity exceeded 80% for 2.3 fewer hours per day in 'Merlot' canopy compared to 'Sauvignon Blanc'. ||Similarly, training system comparisons showed that VSP (Vertical Shoot Positioning) trained 'Chardonnay' with optimal leaf removal exhibited 35% lower cluster infection than minimally pruned 'Chardonnay', demonstrating how viticultural management can enhance evasion-based resistance through canopy architecture modification even in genetically identical material.",
    "editor_note": "Evasion_Based_Resistance_Disposition is_a Powdery_Mildew_Resistance_Disposition. ||This class represents disease avoidance through architectural, phenological, or morphological traits rather than physiological resistance mechanisms. ||Evasion operates independently of true resistance genes and can be enhanced through viticultural management practices. ||The distinction from true resistance is important: evasion reduces disease through avoiding favorable conditions for the pathogen rather than limiting pathogen development after contact. ||Traits contributing to evasion are often quantitatively inherited and amenable to selection.  This disposition encompasses traits that enable plants to \"escape\" disease through spatial or temporal avoidance of optimal infection conditions rather than through active defense responses. ||Architectural evasion mechanisms include open canopy structure promoting air circulation and rapid tissue drying, upright shoot growth reducing humidity in the fruiting zone, and loose cluster architecture minimizing berry-to-berry contact surfaces favorable for fungal spread. ||Phenological evasion involves flowering and fruit development timing that positions susceptible stages outside periods of peak inoculum availability or environmental conditions favorable for infection. ||Morphological evasion includes traits such as reduced leaf hair density that may impede conidial adhesion, glossy cuticle surfaces that affect spore germination microenvironments, and sparse cluster compactness reducing microhabitat humidity. ||While not providing true resistance, evasion-based mechanisms can substantially reduce disease severity in field conditions, contributing to integrated disease management strategies and reducing reliance on chemical control. ||These traits are often under quantitative genetic control and can be selected in breeding programs alongside true resistance genes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Austin CN, Wilcox WF (2011) Effects of fruit-zone leaf removal, training systems, and irrigation on the development of grapevine powdery mildew, American Journal of Enology and Viticulture 62:193-198|| Molitor D et al. (2012) Impact of grape cluster division on cluster morphology and bunch rot epidemic, American Journal of Enology and Viticulture 63:508-514|| Dry IB et al. (2010) Molecular strategies to enhance the genetic resistance of grapevines to powdery mildew, Australian Journal of Grape and Wine Research 16:94-105"
  },
  "Botrytis_Resistance_Disposition": {
    "definition": "A Botrytis_Resistance_Disposition is a Fungal_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with the necrotrophic ascomycete Botrytis cinerea, the causal agent of grey mold (bunch rot) and, under specific conditions, noble rot.", 
    "alternative_term": "grey mold resistance disposition | bunch rot resistance | Botrytis cinerea resistance |+ Botrytis-Resistenz-Disposition | Grauschimmel-Resistenz | Traubenfäule-Resistenz",
    "example_of_usage": "Comparative field evaluation of Botrytis_Resistance_Disposition at Geisenheim University assessed grey mold incidence across 47 cultivars over five harvest seasons with varying autumn precipitation. ||The susceptible cultivar 'Gewürztraminer' (compact clusters, thin skin, high sugar) exhibited mean cluster infection of 45-65% in wet years, with individual berries showing characteristic grey sporulation and entire clusters collapsing to \"slip-skin\" consistency. ||In contrast, 'Regent' demonstrated strong Botrytis_Resistance_Disposition with mean infection of 8-15% under identical conditions, attributable to its loose cluster architecture (OIV 204 rating 3), thick berry skin (mean 285 μm versus 180 μm in 'Gewürztraminer'), and elevated constitutive stilbene content. ||Intermediate cultivars such as 'Riesling' (mean infection 25-35%) showed characteristic partial resistance with infection concentrated at berry contact points and wound sites. ||No cultivar achieved complete immunity, reflecting the absence of major gene resistance and the pathogen's capacity to exploit any compromised tissue, but the 4-5 fold difference in infection severity between resistant and susceptible cultivars demonstrates the practical significance of selecting for enhanced Botrytis resistance dispositions.",
    "editor_note": "Botrytis_Resistance_Disposition is_a Fungal_Resistance_Disposition. ||Unlike downy and powdery mildew resistances which involve major gene (R gene) mediated immunity, Botrytis resistance is exclusively quantitative with no identified major resistance loci. ||Child classes are organized by mechanism: Cluster_Architecture_Based_Resistance_Disposition (structural), Cuticle_Based_Resistance_Disposition (physical barrier), and Phytoalexin_Based_Botrytis_Resistance_Disposition (chemical defense). ||Noble_Rot_Susceptibility_Disposition represents the special case where controlled B. cinerea infection is desirable for certain wine styles.  This disposition represents the capacity to limit B. cinerea infection, colonization, and spread through diverse mechanisms operating at pre-penetration, penetration, and post-penetration stages. ||Unlike biotrophic pathogens such as powdery and downy mildew that require living host tissue, B. cinerea kills host cells and feeds on dead tissue, fundamentally altering the host-pathogen interaction dynamics. ||Botrytis resistance dispositions encompass both constitutive and induced mechanisms, including physical barriers (cuticle thickness and composition, berry skin toughness), preformed and induced antimicrobial compounds (particularly stilbene phytoalexins such as resveratrol and pterostilbene), cluster architectural traits that reduce humidity and berry contact, and active defense responses including oxidative burst and cell wall reinforcement at wound sites. ||The complex, quantitative nature of Botrytis resistance reflects the pathogen's opportunistic infection strategy exploiting wounds, natural openings, and senescing tissue rather than specific recognition-based immunity. ||No major gene resistance to B. cinerea has been identified in Vitis, making breeding for Botrytis resistance dependent on accumulating multiple partial resistance factors. ||Botrytis resistance is economically critical as grey mold causes significant crop losses in humid climates and produces off-flavors that severely compromise wine quality.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Elmer PAG, Michailides TJ (2007) Epidemiology of Botrytis cinerea in orchard and vine crops, Botrytis: Biology, Pathology and Control, Springer|| Deytieux-Belleau C et al. (2009) Berry skin development in Vitis vinifera: morphological and biochemical events linked to Botrytis resistance, Journal of Experimental Botany 60:3919-3930|| Bézier A et al. (2002) Carbon source-dependent expression of a resveratrol synthase gene of grapevine, Physiological and Molecular Plant Pathology 61:179-186"
  },
  "Cluster_Architecture_Based_Resistance_Disposition": {
    "definition": "A Cluster_Architecture_Based_Resistance_Disposition is a Botrytis_Resistance_Disposition that inheres in a Vitis vinifera cluster and is realized through morphological and structural characteristics that create unfavorable microclimatic conditions for Botrytis cinerea infection and spread, independent of direct physiological or biochemical defense mechanisms.", 
    "alternative_term": "structural bunch rot resistance | cluster morphology resistance | architectural Botrytis avoidance |+ Traubenarchitektur-basierte Resistenz-Disposition | Strukturelle Botrytis-Resistenz | Traubenmorphologie-Resistenz",
    "example_of_usage": "Quantitative analysis of Cluster_Architecture_Based_Resistance_Disposition at INRAE Bordeaux employed 3D imaging to characterize cluster compactness across 120 cultivars and correlate architectural parameters with grey mold susceptibility. ||Cluster compactness was quantified using the CI-12 index (berries per cm rachis) and OIV descriptor 204. ||The compact cultivar 'Pinot Noir' (CI-12 = 8.2, OIV 204 rating 7-9) exhibited mean porosity of only 12% (air space within cluster volume) and berry contact index of 4.3 (mean contact points per berry), creating a persistent humid microenvironment where relative humidity exceeded 90% for 14 hours following a 10mm rainfall event. ||In contrast, the loose cultivar 'Gewürztraminer clone 643' (CI-12 = 4.1, OIV 204 rating 3) showed porosity of 38% and contact index of 1.8, with cluster humidity returning to ambient within 4 hours post-rainfall. ||Under natural Botrytis pressure, 'Pinot Noir' developed 52% cluster infection while 'Gewürztraminer clone 643' showed only 18% infection despite 'Gewürztraminer' being generally considered susceptible, demonstrating how cluster architecture can override other susceptibility factors.",
    "editor_note": "Cluster_Architecture_Based_Resistance_Disposition is_a Botrytis_Resistance_Disposition. ||This class encompasses structural traits that reduce disease through environmental modification rather than direct host-pathogen interaction. ||Child classes include Loose_Cluster_Disposition (low compactness) and Thick_Skin_Disposition (mechanical barrier). ||Cluster architecture is distinct from but may interact with Cuticle_Based_Resistance_Disposition and Phytoalexin_Based_Botrytis_Resistance_Disposition which represent physiological rather than structural mechanisms.  This disposition encompasses the genetically determined cluster structural traits that influence humidity retention, air circulation, berry contact surface area, and wound susceptibility within the cluster microenvironment. ||Key architectural parameters include cluster compactness (density of berry packing), cluster length and shape (cylindrical, conical, winged), berry size relative to rachis dimensions, pedicel length and flexibility, and rachis branching patterns. ||Compact clusters with tightly packed berries create persistent high humidity microenvironments following rain or dew events, maintain berry-to-berry contact surfaces that facilitate pathogen spread, and are prone to berry cracking when expanding berries compress against neighbors. ||In contrast, loose clusters with well-spaced berries dry rapidly after wetting, minimize contact-mediated pathogen transfer, and reduce mechanical stress on berry skins. ||Cluster architecture is under strong genetic control with moderate to high heritability, enabling effective selection in breeding programs. ||These structural traits represent constitutive, passive resistance mechanisms that function independently of active defense responses, providing baseline protection that complements inducible biochemical defenses.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Vail ME, Marois JJ (1991) Grape cluster architecture and the susceptibility of berries to Botrytis cinerea, Phytopathology 81:188-191|| Molitor D et al. (2012) Impact of grape cluster division on cluster morphology and bunch rot epidemic, American Journal of Enology and Viticulture 63:508-514|| Tello J, Ibáñez J (2018) What do we know about grapevine bunch compactness? A state-of-the-art review, Australian Journal of Grape and Wine Research 24:6-23"
  },
  "Thick_Skin_Disposition": {
    "definition": "A Thick_Skin_Disposition is a Cluster_Architecture_Based_Resistance_Disposition that inheres in a Vitis vinifera berry and is realized through the development of a mechanically robust exocarp (skin) that provides enhanced physical resistance to Botrytis cinerea penetration and reduces susceptibility to berry cracking, wound formation, and cuticle microfissures that serve as pathogen entry points.", 
    "alternative_term": "thick berry skin trait | tough skin disposition | mechanical skin resistance |+ Dickschaligkeit-Disposition | Dicke-Beerenhaut-Disposition | Mechanische-Hautresistenz",
    "example_of_usage": "Comparative analysis of Thick_Skin_Disposition at the University of Adelaide assessed berry mechanical properties across 28 wine grape cultivars using texture analyzer measurements of puncture force and skin thickness determinations via histological sectioning. 'Cabernet Sauvignon' exhibited pronounced Thick_Skin_Disposition with mean skin thickness of 312 μm, puncture force of 0.89 N, and tensile strength of 1.42 MPa. ||In contrast, thin-skinned 'Pinot Noir' showed values of 178 μm, 0.41 N, and 0.68 MPa respectively. ||Under controlled inoculation with B. cinerea conidia (10⁵/mL) applied to unwounded berries, 'Cabernet Sauvignon' developed infection in only 8% of inoculated berries versus 34% in 'Pinot Noir' after 7 days incubation at 20°C and 95% RH. ||When berries were pre-wounded with a sterile needle, infection rates equalized at 85-92% for both cultivars, confirming that Thick_Skin_Disposition operates primarily through mechanical barrier function preventing initial penetration rather than post-infection resistance. ||Field observations corroborated laboratory findings, with 'Cabernet Sauvignon' showing 3-4 fold lower grey mold incidence than 'Pinot Noir' under equivalent disease pressure in Coonawarra vineyards.",
    "editor_note": "Thick_Skin_Disposition is_a Cluster_Architecture_Based_Resistance_Disposition. ||This class represents mechanical barrier resistance through berry skin properties, classified under structural rather than physiological resistance mechanisms. ||Thick skin correlates with but is distinct from Cuticle_Based_Resistance_Disposition which specifically addresses the outermost waxy layer. ||Skin thickness influences wine style through phenolic extraction, creating potential trade-offs with enological objectives. ||The disposition provides protection primarily against unwounded berry infection|| wounded berries remain susceptible regardless of skin thickness.  This disposition represents the genetically determined capacity to produce berries with thick, tough skins characterized by multiple cell layers in the hypodermis, thick-walled epidermal cells, high content of structural polysaccharides (cellulose, hemicellulose, pectin), and dense phenolic accumulation providing mechanical reinforcement. ||Berry skin thickness in Vitis vinifera varies substantially among cultivars, ranging from approximately 150 μm in thin-skinned table grapes to over 350 μm in thick-skinned wine grapes, with corresponding differences in puncture resistance and tensile strength. ||Thick-skinned genotypes resist mechanical damage during berry expansion, rain events, and cluster compression, maintaining skin integrity that prevents opportunistic B. cinerea entry. ||Additionally, thick skins often correlate with elevated phenolic content (anthocyanins, tannins) that may contribute antimicrobial activity. ||The genetic control of berry skin thickness involves multiple QTLs and shows high heritability, enabling effective selection. ||However, thick skin disposition may influence wine style through increased phenolic extraction and potential for skin-derived bitter or astringent compounds, requiring balance with enological objectives.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Deytieux-Belleau C et al. (2009) Berry skin development in Vitis vinifera: morphological and biochemical events linked to Botrytis resistance, Journal of Experimental Botany 60:3919-3930|| Gabler FM et al. (2003) Correlations of morphological, anatomical, and chemical features of grape berries with resistance to Botrytis cinerea, Phytopathology 93:1263-1273|| Rosenquist JK, Morrison JC (1989) Some factors affecting cuticle and wax accumulation on grape berries, American Journal of Enology and Viticulture 40:241-244"
  },
  "Cuticle_Based_Resistance_Disposition": {
    "definition": "A Cuticle_Based_Resistance_Disposition is a Botrytis_Resistance_Disposition that inheres in a Vitis vinifera berry and is realized through characteristics of the cuticular membrane that impede Botrytis cinerea conidial germination, germ tube penetration, and appressorium formation on the berry surface.", 
    "alternative_term": "cuticle barrier resistance | wax layer resistance | epicuticular defense |+ Kutikula-basierte Resistenz-Disposition | Wachsschicht-Resistenz | Kutikuläre-Botrytis-Resistenz",
    "example_of_usage": "Detailed characterization of Cuticle_Based_Resistance_Disposition at INRA Montpellier examined cuticular properties across 12 cultivars using scanning electron microscopy of epicuticular wax morphology, gas chromatography-mass spectrometry of wax composition, and atomic force microscopy of surface nanomechanics. 'Grenache' exhibited dense epicuticular wax coverage (42 μg/cm²) with elaborate platelet crystals creating a rough, hydrophobic surface (water contact angle 142°) on which B. cinerea conidia showed 62% germination rate with delayed germ tube emergence (mean 18 hours). 'Chasselas' displayed sparse, amorphous wax (18 μg/cm²), smooth surface topography, and lower hydrophobicity (contact angle 98°), supporting 89% germination with rapid germ tube emergence (mean 8 hours). ||Controlled inoculation of surface-sterilized berries demonstrated that 'Grenache' developed infection in 24% of berries versus 58% in 'Chasselas' when inoculated with equivalent conidial suspensions onto intact surfaces. ||However, when cuticle was enzymatically removed with cutinase pre-treatment, infection rates equalized at 82-88%, confirming that differences in susceptibility were attributable to Cuticle_Based_Resistance_Disposition rather than post-penetration defense mechanisms.",
    "editor_note": "Cuticle_Based_Resistance_Disposition is_a Botrytis_Resistance_Disposition. ||This class specifically addresses the outermost cuticular layer including epicuticular and intracuticular waxes, distinct from Thick_Skin_Disposition which encompasses overall exocarp mechanical properties. ||Cuticle properties affect the earliest infection stages including conidial adhesion, germination, and initial penetration. ||Cuticle integrity often declines during ripening as berry expansion outpaces cuticle deposition, explaining the increased susceptibility of mature berries to Botrytis infection.  The cuticle, comprising a cutin polymer matrix embedded with intracuticular waxes and covered by epicuticular wax deposits, serves as the outermost barrier between the berry and its environment, and its properties profoundly influence susceptibility to B. cinerea infection of intact fruit. ||Cuticle-based resistance mechanisms include cuticle thickness providing a physical barrier to direct penetration, wax crystal morphology and density affecting water retention and conidial adhesion, wax chemical composition influencing surface hydrophobicity and germination cue availability, and cuticle integrity (absence of microcracks and fissures) preventing pathogen access to underlying tissues. ||Epicuticular wax crystal structure varies among cultivars from amorphous films to elaborate crystalline plates, needles, or tubules, with potential effects on spore adhesion and germination microenvironment. ||Cuticle properties change during berry development, with cuticle deposition active during early development but often failing to keep pace with berry expansion during ripening, leading to cuticle thinning and microcracking that increases susceptibility. ||Cuticular characteristics are under genetic control with moderate heritability and represent selectable traits for breeding, though their contributions to field resistance are difficult to isolate from other resistance mechanisms.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Comménil P et al. (1997) Surface waxes of grapevine grape berries and their role in pathogenicity of Botrytis cinerea, Journal of Experimental Botany 48:1599-1607|| Gabler FM et al. (2003) Correlations of morphological, anatomical, and chemical features of grape berries with resistance to Botrytis cinerea, Phytopathology 93:1263-1273|| Becker T, Knoche M (2012) Water movement through the surfaces of the grape berry and its stem, American Journal of Enology and Viticulture 63:100-108"
  },
  "Phytoalexin_Based_Botrytis_Resistance_Disposition": {
    "definition": "A Phytoalexin_Based_Botrytis_Resistance_Disposition is a Botrytis_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through the production of antimicrobial secondary metabolites, particularly stilbene phytoalexins, that inhibit Botrytis cinerea growth, sporulation, and tissue colonization.", 
    "alternative_term": "stilbene-based Botrytis resistance | resveratrol-mediated resistance | induced chemical defense |+ Phytoalexin-basierte Botrytis-Resistenz-Disposition | Stilben-Resistenz | Resveratrol-vermittelte Resistenz",
    "example_of_usage": "Investigation of Phytoalexin_Based_Botrytis_Resistance_Disposition at the University of Bordeaux compared stilbene production dynamics in resistant 'Marselan' versus susceptible 'Semillon' following controlled B. cinerea inoculation of véraison-stage berries. ||Prior to inoculation, 'Marselan' berries contained constitutive resveratrol at 12.4 μg/g fresh weight versus 3.8 μg/g in 'Semillon'. ||Within 24 hours post-inoculation, 'Marselan' showed 8-fold induction of STS gene expression and rapid accumulation of ε-viniferin (the most fungitoxic stilbene, reaching 45 μg/g by 48 hours), while 'Semillon' exhibited only 2-fold STS induction and minimal viniferin production (8 μg/g). ||In vitro bioassays confirmed that stilbene extracts from inoculated 'Marselan' berries inhibited B. cinerea conidial germination by 78% and germ tube elongation by 85%, compared to 23% and 31% inhibition by 'Semillon' extracts. ||Infection severity at 7 days post-inoculation was 18% in 'Marselan' versus 62% in 'Semillon', demonstrating the functional significance of enhanced phytoalexin production capacity for Botrytis resistance under conditions where physical barrier mechanisms were bypassed through artificial inoculation.",
    "editor_note": "Phytoalexin_Based_Botrytis_Resistance_Disposition is_a Botrytis_Resistance_Disposition. ||This class represents active biochemical defense through antimicrobial compound production, distinct from structural resistance mechanisms (Cluster_Architecture_Based_Resistance_Disposition) and passive barrier functions (Cuticle_Based_Resistance_Disposition). ||Stilbene phytoalexins are the primary antimicrobial class in Vitis, with viniferins being more fungitoxic than their resveratrol precursor. ||B. cinerea can partially detoxify stilbenes via laccase enzymes, limiting the efficacy of phytoalexin-based resistance as a sole defense mechanism.  This disposition encompasses both constitutive accumulation of preformed antimicrobial compounds and the induced biosynthesis of phytoalexins in response to pathogen detection or tissue damage. ||Stilbenes, derived from the phenylpropanoid pathway via stilbene synthase (STS) enzymes, represent the primary phytoalexin class in Vitis, with resveratrol (3,5,4'-trihydroxystilbene) being the central compound from which more fungitoxic derivatives including pterostilbene, viniferins (oxidative dimers and oligomers), and piceid (resveratrol glucoside) are produced. ||The antifungal activity of stilbenes against B. cinerea involves disruption of membrane integrity, inhibition of conidial germination and germ tube elongation, and interference with enzyme secretion required for tissue maceration. ||Cultivars with enhanced Phytoalexin_Based_Botrytis_Resistance_Disposition show elevated constitutive stilbene content, more rapid and intense STS gene induction following infection or wounding, and greater capacity to produce highly fungitoxic oxidized stilbenes (viniferins). ||The disposition is influenced by berry developmental stage, with maximum inducibility typically occurring at véraison, and by environmental factors including UV light exposure that stimulates stilbene accumulation. ||While phytoalexin-based resistance provides meaningful protection, B. cinerea possesses laccase enzymes capable of stilbene detoxification, enabling virulent isolates to partially overcome this defense mechanism.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Langcake P, Pryce RJ (1977) The production of resveratrol and the viniferins by grapevines in response to ultraviolet irradiation, Phytochemistry 16:1193-1196|| Jeandet P et al. (2002) Phytoalexins from the Vitaceae: biosynthesis, phytoalexin gene expression in transgenic plants, antifungal activity, and metabolism, Journal of Agricultural and Food Chemistry 50:2731-2741|| Pezet R et al. (2004) Glycosylation and oxidative dimerization of resveratrol are respectively associated to sensitivity and resistance of grapevine cultivars to downy mildew, Physiological and Molecular Plant Pathology 65:297-303"
  },
  "Noble_Rot_Susceptibility_Disposition": {
    "definition": "A Noble_Rot_Susceptibility_Disposition is a Botrytis_Resistance_Disposition that, paradoxically, represents the capacity of a Vitis vinifera berry to support the specialized \"noble rot\" (pourriture noble, Edelfäule) infection by Botrytis cinerea under specific environmental conditions, enabling the production of distinctive botrytized sweet wines including Sauternes, Tokaji Aszú, Trockenbeerenauslese, and Sélection de Grains Nobles.", 
    "alternative_term": "noble rot capacity | botrytized wine potential | Edelfäule susceptibility |+ Edelfäule-Anfälligkeits-Disposition | Botrytis-Süßwein-Eignung | Pourriture-noble-Disposition",
    "example_of_usage": "The Noble_Rot_Susceptibility_Disposition of 'Sémillon' underlies its dominance in Sauternes production, where it typically comprises 75-80% of plantings in classified growths such as Château d'Yquem. 'Sémillon' possesses the ideal combination of traits for noble rot development: thin skin (mean 165 μm) permitting B. cinerea penetration and subsequent water loss, moderate initial sugar (22-24°Brix) providing substrate for fungal metabolism, low acidity maintaining palatability after acid reduction, and neutral aromatic profile transformed by fungal activity into complex honeyed, apricot, and saffron notes. ||In contrast, thick-skinned 'Cabernet Sauvignon' planted adjacently for red wine production rarely develops noble rot, instead either resisting infection or progressing directly to destructive grey rot when infected. ||Environmental monitoring at Château d'Yquem documented ideal noble rot conditions: morning fog raising humidity above 90% for 4-6 hours, followed by afternoon sunshine and temperatures of 18-24°C with humidity dropping below 60%. ||Under these conditions, 'Sémillon' berries reached harvest sugar concentrations of 35-42°Brix through 40-60% water loss over 3-4 weeks of progressive noble rot development, with multiple selective harvest passes (tries) recovering only optimally botrytized berries.",
    "editor_note": "Noble_Rot_Susceptibility_Disposition is_a Botrytis_Resistance_Disposition, though it represents susceptibility to a specific, desirable form of Botrytis infection rather than resistance. ||This ontological positioning reflects that noble rot capacity is a specialized disposition within the broader Botrytis response spectrum, distinguished from destructive grey rot by environmental conditions and cultivar characteristics. ||The class captures the disposition for controlled, beneficial B. cinerea interaction rather than the destructive infection represented by general Botrytis susceptibility. ||Required traits include thin skin, appropriate sugar and acid balance, and aromatic precursor content enabling desirable transformation.  This disposition inheres in cultivars whose berries, when infected by B. cinerea under conditions of alternating humidity and dryness, undergo controlled desiccation and profound biochemical transformation rather than destructive grey rot decay. ||The noble rot process requires thin-skinned berries permitting fungal penetration and water loss, sufficient sugar content to support fungal metabolism while preventing complete berry collapse, and specific aromatic precursor compounds that undergo fungal transformation into desirable volatile compounds. ||During noble rot development, B. cinerea consumes organic acids (particularly tartaric acid) and metabolizes grape constituents to produce glycerol, gluconic acid, and distinctive aromatic compounds (sotolon, furaneol), while water evaporates through the perforated cuticle, concentrating sugars to 30-40°Brix or higher. ||The disposition is expressed only when humid mornings (promoting infection and fungal activity) alternate with dry, sunny afternoons (preventing grey rot progression and enabling desiccation), conditions typical of specific terroirs including Sauternes, Tokaj, and Rhine-Mosel valleys. ||Cultivars lacking Noble_Rot_Susceptibility_Disposition either resist B. cinerea infection entirely or develop destructive grey rot rather than the controlled noble rot transformation.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ribéreau-Gayon P et al. (2006) Handbook of Enology Volume 1: The Microbiology of Wine and Vinifications, 2nd Edition, John Wiley & Sons|| Fournier E et al. (2013) Botrytis cinerea epidemiology and noble rot, Botrytis - the Fungus, the Pathogen and its Management in Agricultural Systems, Springer|| Magyar I (2011) Botrytized wines, Advances in Food and Nutrition Research 63:147-206"
  },
  "Black_Rot_Resistance_Disposition": {
    "definition": "A Black_Rot_Resistance_Disposition is a Fungal_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with the hemibiotrophic ascomycete Guignardia bidwellii (anamorph Phyllosticta ampelicida), the causal agent of grape black rot.", 
    "alternative_term": "Guignardia resistance disposition | black rot immunity | Phyllosticta resistance |+ Schwarzfäule-Resistenz-Disposition | Black-Rot-Resistenz | Guignardia-Resistenz",
    "example_of_usage": "Field evaluation of Black_Rot_Resistance_Disposition at the University of Georgia Tifton campus compared disease development across a diverse Vitis germplasm collection under natural epidemic conditions in the humid southeastern United States. ||The V. vinifera cultivar 'Chardonnay' (susceptible control) exhibited severe black rot with 85-95% of clusters showing mummified berries by véraison in unsprayed plots, and leaf lesions covering 40-60% of canopy area. ||The V. aestivalis-derived cultivar 'Norton' ('Cynthiana') demonstrated strong Black_Rot_Resistance_Disposition with only 5-12% cluster infection and scattered small leaf lesions (<5% canopy area) under identical conditions. ||Controlled inoculation experiments revealed that 'Norton' restricts G. bidwellii development during the biotrophic phase, with microscopic observation showing hyphal growth confined to 2-3 cell layers beneath the penetration site compared to extensive intercellular colonization in susceptible 'Chardonnay'. ||The interspecific hybrid 'Chambourcin' exhibited intermediate resistance (25-35% cluster infection), reflecting its mixed parentage combining susceptible V. vinifera with resistant North American species ancestry.",
    "editor_note": "Black_Rot_Resistance_Disposition is_a Fungal_Resistance_Disposition. ||Black rot caused by Guignardia bidwellii is a true fungus (Ascomycota), distinct from the oomycete causing downy mildew. ||Child classes include Rgr_Mediated_Resistance_Disposition for major gene resistance and Quantitative_Black_Rot_Resistance_Disposition for polygenic resistance. ||The disease is endemic to eastern North America, where wild Vitis species have evolved resistance, but can be devastating on susceptible V. vinifera cultivars introduced to these regions.  This disposition represents the capacity to limit G. bidwellii infection, colonization, and reproduction across the pathogen's complex disease cycle affecting leaves, shoots, tendrils, and most critically, developing berries. ||Black rot is characterized by an initial biotrophic phase where the fungus colonizes living tissue asymptomatically, followed by a necrotrophic phase producing the characteristic tan lesions with dark borders on leaves and the devastating black, shriveled \"mummified\" berries that can destroy entire clusters. ||Resistance mechanisms operate at multiple infection stages including inhibition of conidial germination on plant surfaces, restriction of appressorial penetration, limitation of intercellular hyphal growth during the biotrophic phase, and containment of necrosis during the transition to necrotrophy. ||Unlike downy and powdery mildew, black rot resistance in Vitis involves both major gene effects (Rgr loci) and substantial quantitative variation. ||The disease is particularly destructive in humid continental climates of eastern North America, where G. bidwellii is endemic, making black rot resistance a primary breeding objective for cultivars adapted to these regions. ||European V. vinifera cultivars are generally highly susceptible, while North American species including V. rupestris, V. cinerea, and V. aestivalis exhibit varying levels of resistance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hoffman LE et al. (2002) Factors influencing the susceptibility of grapevine berries to black rot caused by Guignardia bidwellii, Phytopathology 92:1090-1098|| Rex F et al. (2014) QTL mapping of black rot (Guignardia bidwellii) resistance in the grapevine rootstock 'Börner', Theoretical and Applied Genetics 127:1667-1677|| Molitor D, Beyer M (2014) Epidemiology, identification and disease management of grape black rot and potentially useful metabolites of black rot pathogens for industrial applications, Annals of Applied Biology 165:305-317"
  },
  "Rgr_Mediated_Resistance_Disposition": {
    "definition": "An Rgr_Mediated_Resistance_Disposition is a Black_Rot_Resistance_Disposition that inheres in a Vitis plant carrying one or more Rgr (Resistance to Guignardia) loci and is realized through major gene-mediated defense responses upon encounter with Guignardia bidwellii.", 
    "alternative_term": "Rgr locus black rot resistance | major gene black rot resistance | Börner-derived resistance |+ Rgr-vermittelte Resistenz-Disposition | Rgr-Schwarzfäule-Resistenz | Majorgen-Black-Rot-Resistenz",
    "example_of_usage": "Genetic mapping of Rgr_Mediated_Resistance_Disposition at the Julius Kühn-Institut utilized a segregating population from the cross 'Börner' (resistant) × V. vinifera 'Lemberger' (susceptible). ||Phenotypic evaluation employed detached leaf assays with G. bidwellii conidial suspension (10⁵ conidia/mL), scoring lesion development on a 1-9 scale at 14 days post-inoculation. ||Resistance segregated in a 1:1 ratio consistent with single dominant gene inheritance. ||QTL analysis identified a major locus on chromosome 14 explaining 76% of phenotypic variance, designated Rgr1. ||Resistant individuals carrying the Rgr1 allele exhibited small necrotic flecks (OIV rating 7-9) without subsequent pycnidia formation, while susceptible siblings developed expanding tan lesions with abundant pycnidial sporulation (OIV rating 1-3). ||The Rgr1-linked SSR marker GF14-67 enables marker-assisted selection with 98% accuracy in predicting phenotype. ||Advanced breeding selections combining Rgr1 with Rpv and Ren loci from 'Börner' represent multiple-disease-resistant germplasm suitable for humid climate viticulture, demonstrating the value of this rootstock cultivar as a source of combined fungal disease resistances.",
    "editor_note": "Rgr_Mediated_Resistance_Disposition is_a Black_Rot_Resistance_Disposition. ||Rgr1 was identified in 'Börner', a V. riparia × V. cinerea hybrid rootstock that also carries downy mildew resistance, with both resistances mapping to chromosome 14. ||The Rgr nomenclature follows the established Vitis resistance gene naming convention. ||Additional Rgr loci from other resistant germplasm sources await characterization. ||Rgr-mediated resistance operates through rapid hypersensitive response during the biotrophic infection phase, preventing transition to destructive necrotrophy.  The Rgr loci encode resistance factors that confer qualitative, race-specific or broad-spectrum resistance to black rot, analogous to the Rpv and Ren/Run loci for downy and powdery mildew respectively. ||Rgr1, the first characterized black rot resistance locus, was identified in the rootstock cultivar 'Börner' (V. riparia × V. cinerea) and maps to chromosome 14, where it co-localizes with a resistance gene cluster also containing downy mildew resistance factors. ||The Rgr1-mediated resistance phenotype is characterized by rapid hypersensitive response following G. bidwellii penetration, resulting in small necrotic flecks that arrest fungal colonization before the pathogen completes its biotrophic phase and transitions to tissue-destructive necrotrophy. ||Additional Rgr loci have been identified in other resistant germplasm sources including V. rupestris and Muscadinia rotundifolia, providing multiple independent resistance genes for potential pyramiding strategies. ||Marker-assisted selection using Rgr-linked molecular markers enables efficient introgression of black rot resistance into V. vinifera breeding populations, addressing a critical disease pressure for grape production in humid continental climates. ||The identification and deployment of Rgr loci represents an important advance for sustainable viticulture in regions where black rot has historically limited cultivation of high-quality wine grape cultivars.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Rex F et al. (2014) QTL mapping of black rot (Guignardia bidwellii) resistance in the grapevine rootstock 'Börner', Theoretical and Applied Genetics 127:1667-1677|| Zyprian E et al. (2016) Quantitative trait loci affecting pathogen resistance and ripening of grapevines, Molecular Genetics and Genomics 291:1573-1594"
  },
  "Quantitative_Black_Rot_Resistance_Disposition": {
    "definition": "A Quantitative_Black_Rot_Resistance_Disposition is a Black_Rot_Resistance_Disposition that inheres in a Vitis plant and is realized through the cumulative action of multiple genes with individually moderate effects, collectively conferring partial but durable resistance to Guignardia bidwellii across diverse environmental conditions and pathogen populations.", 
    "alternative_term": "polygenic black rot resistance | partial Guignardia resistance | QTL-based black rot resistance |+ Quantitative Schwarzfäule-Resistenz-Disposition | Polygene Black-Rot-Resistenz | Partielle Guignardia-Resistenz",
    "example_of_usage": "QTL mapping for Quantitative_Black_Rot_Resistance_Disposition in an 'Horizon' × Illinois 547-1 population at Cornell University identified five genomic regions contributing to black rot resistance independent of the Rgr1 locus. ||Phenotypic evaluation across three seasons with varying disease pressure employed both detached leaf assays and field cluster assessments, scoring lesion severity, sporulation intensity, and berry infection percentage. ||QTLs on chromosomes 5, 7, 10, 14 (distinct from Rgr1), and 17 each explained 8-18% of phenotypic variance, with additive effects combining to produce a 40-65% reduction in disease severity when favorable alleles were accumulated. ||Progeny inheriting favorable alleles at four or more QTLs exhibited mean berry infection of 15-25% compared to 55-70% in individuals with predominantly unfavorable alleles, under natural epidemic conditions where susceptible V. vinifera controls reached 90%+ infection. ||Importantly, the quantitative resistance remained effective across years with different environmental conditions and presumed pathogen population variation, supporting the durability hypothesis. ||Genomic selection models incorporating all mapped QTLs achieved prediction accuracies of 0.58-0.67 for black rot severity, enabling efficient breeding progress without phenotyping individual progeny.",
    "editor_note": "Quantitative_Black_Rot_Resistance_Disposition is_a Black_Rot_Resistance_Disposition. ||This class is distinguished from Rgr_Mediated_Resistance_Disposition by its polygenic inheritance and partial resistance phenotype. ||Quantitative and major gene resistances may co-occur in the same genotype, with quantitative factors potentially enhancing durability of Rgr-mediated resistance. ||Multiple North American Vitis species contribute quantitative resistance factors that can be combined in breeding to achieve commercially meaningful protection levels.  Unlike monogenic Rgr-mediated resistance, quantitative black rot resistance follows continuous inheritance patterns controlled by multiple quantitative trait loci (QTLs) distributed across the genome, each contributing incrementally to the overall resistance phenotype. ||The molecular and physiological mechanisms underlying quantitative resistance likely include enhanced constitutive defense compound levels, more rapid or intense activation of induced defenses following pathogen recognition, modified tissue properties affecting penetration success, and variation in the duration of the biotrophic window before necrotrophy onset. ||Quantitative resistance typically manifests as reduced infection frequency, smaller lesion size, decreased pycnidial density within lesions, extended latent period, and lower berry susceptibility rather than complete immunity. ||The presumed durability advantage of quantitative resistance derives from the evolutionary difficulty of pathogen adaptation to multiple independent resistance mechanisms simultaneously. ||Quantitative black rot resistance is particularly relevant for breeding programs targeting humid continental climates, where combining partial resistances from multiple sources can achieve commercially acceptable disease control levels with reduced fungicide inputs, even in the absence of complete immunity.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Rex F et al. (2014) QTL mapping of black rot (Guignardia bidwellii) resistance in the grapevine rootstock 'Börner', Theoretical and Applied Genetics 127:1667-1677|| Cadle-Davidson L (2008) Variation within and between Vitis spp. for foliar resistance to the downy mildew pathogen Plasmopara viticola, Plant Disease 92:1577-1584"
  },
  "Anthracnose_Resistance_Disposition": {
    "definition": "An Anthracnose_Resistance_Disposition is a Fungal_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with the hemibiotrophic ascomycete Elsinoë ampelina (anamorph Sphaceloma ampelinum), the causal agent of grape anthracnose, also known as bird's eye rot.", 
    "alternative_term": "Elsinoë resistance disposition | bird's eye rot resistance | Sphaceloma resistance |+ Anthraknose-Resistenz-Disposition | Brenner-Resistenz | Elsinoë-Resistenz",
    "example_of_usage": "Evaluation of Anthracnose_Resistance_Disposition at the Grape Genetic Resources Repository of the Brazilian Agricultural Research Corporation (Embrapa Uva e Vinho) screened 185 Vitis accessions under high natural disease pressure in the humid subtropical climate of Rio Grande do Sul. ||Susceptible V. vinifera cultivar 'Italia' exhibited severe anthracnose with 75-90% of young shoots showing girdling cankers, 60-80% defoliation from leaf lesions, and 45-65% of berries displaying bird's eye lesions by véraison. ||The V. labrusca cultivar 'Isabella' demonstrated strong Anthracnose_Resistance_Disposition with only 5-10% of shoots showing minor cankers, minimal leaf damage (<10%), and berry infection below 5%. ||Interspecific hybrids showed variable resistance correlated with their proportion of North American species ancestry, with 'BRS Vitória' (complex hybrid) exhibiting intermediate resistance (20-30% shoot infection, 15% berry infection). ||Anatomical studies revealed that resistant genotypes possess thicker cuticles on young shoots and more rapid wound periderm formation following penetration, limiting lesion expansion and secondary sporulation. ||No major resistance genes have been identified, with inheritance studies suggesting polygenic control with moderate heritability (h² = 0.45-0.55).",
    "editor_note": "Anthracnose_Resistance_Disposition is_a Fungal_Resistance_Disposition. ||Anthracnose caused by Elsinoë ampelina is a distinct disease from the \"anthracnose\" of other crops, with grape-specific symptomatology and epidemiology. ||Unlike downy mildew, powdery mildew, and black rot, no major resistance genes (R genes) have been characterized for anthracnose in Vitis. ||Resistance appears quantitative and is found primarily in North American species adapted to humid climates where E. ampelina is endemic. ||The disease is particularly important in tropical and subtropical viticulture where environmental conditions favor repeated infection cycles.  This disposition represents the capacity to limit E. ampelina infection, colonization, and sporulation on susceptible tissues including young leaves, shoots, tendrils, petioles, and developing berries. ||Anthracnose produces characteristic symptoms including circular leaf spots with grey centers and dark margins (\"bird's eye\" lesions), sunken cankers on green shoots that may girdle and kill young growth, and circular berry lesions with raised dark borders that crack and serve as entry points for secondary pathogens. ||The disease is favored by warm, wet spring conditions and is particularly severe in tropical and subtropical viticulture regions and in humid continental climates during rainy growing seasons. ||Resistance mechanisms include physical barriers limiting conidial penetration, rapid activation of defense responses during the biotrophic infection phase, and limitation of lesion expansion during the necrotrophic phase. ||Unlike downy and powdery mildew, anthracnose resistance genetics remain poorly characterized, with resistance appearing largely quantitative and derived primarily from North American Vitis species including V. rupestris, V. labrusca, and V. cinerea. ||European V. vinifera cultivars display a range of susceptibility, with some traditional cultivars from humid regions showing moderate field tolerance likely reflecting historical selection pressure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Poolsawat O et al. (2012) Identification and quantification of resistance to anthracnose (Elsinoë ampelina) in wild and cultivated grapes, Vitis 51:95-100|| Santos RF et al. (2018) Grape anthracnose resistance: screening and inheritance studies, Plant Pathology 67:1535-1543|| Thind TS (2015) Anthracnose of gapes, Diseases of Fruits and Vegetables and Their Management, Indian Phytopathological Society"
  },
  "Trunk_Disease_Resistance_Disposition": {
    "definition": "A Trunk_Disease_Resistance_Disposition is a Fungal_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through defense processes that limit infection, colonization, and pathogenesis by the complex of wood-inhabiting fungi causing grapevine trunk diseases, including esca, Eutypa dieback, Botryosphaeria dieback, Phomopsis dieback, and related syndromes.", 
    "alternative_term": "wood disease resistance | GTD resistance | vascular pathogen resistance |+ Rebholzkrankheit-Resistenz-Disposition | Esca-Komplex-Resistenz | Holzpilz-Resistenz",
    "example_of_usage": "Long-term evaluation of Trunk_Disease_Resistance_Disposition at INRAE Bordeaux monitored trunk disease development across 24 cultivars in a replicated trial established in 1990 and assessed annually for esca foliar symptoms and vine mortality through 2020. ||After 30 years, cumulative vine mortality attributed to trunk diseases ranged from 8% in resistant 'Merlot' to 62% in highly susceptible 'Sauvignon Blanc', with 'Cabernet Sauvignon' intermediate at 28%. ||Annual esca foliar symptom expression (tiger-stripe patterns, apoplexy) averaged 2.4% of 'Merlot' vines versus 18.6% of 'Sauvignon Blanc' vines during epidemic years. ||Wood anatomical studies revealed that 'Merlot' exhibits more rapid and extensive tylosis formation in xylem vessels adjacent to infection sites, compartmentalizing pathogens and maintaining functional vascular capacity. ||Phytotoxin tolerance assays demonstrated that 'Merlot' leaf tissue exhibited 40% less necrosis than 'Sauvignon Blanc' when exposed to equivalent concentrations of Phaeomoniella chlamydospora culture filtrates, suggesting both structural and physiological components contribute to its enhanced Trunk_Disease_Resistance_Disposition. ||These findings inform replanting decisions and cultivar selection for vineyard longevity.",
    "editor_note": "Trunk_Disease_Resistance_Disposition is_a Fungal_Resistance_Disposition. ||This class encompasses resistance to the entire complex of wood-inhabiting fungi causing grapevine trunk diseases (GTDs), recognizing that vineyards typically face multiple pathogens simultaneously. ||Child classes include Esca_Resistance_Disposition, Eutypa_Resistance_Disposition, and Botryosphaeria_Resistance_Disposition for resistance to specific pathogen groups. ||Resistance mechanisms differ fundamentally from foliar disease resistance, emphasizing wound responses, compartmentalization, and phytotoxin tolerance rather than pathogen recognition and hypersensitive response.  This disposition represents the capacity to resist or tolerate chronic fungal infection of perennial woody tissues including the trunk, cordons, and spurs, where pathogens cause progressive vascular dysfunction, wood necrosis, and eventual vine decline or death. ||Trunk diseases are caused by diverse fungal taxa that share the common features of wound-mediated infection, slow progression over multiple years, colonization of xylem and associated tissues, and production of phytotoxins that disrupt vascular function and cause foliar symptoms distal to infection sites. ||Resistance mechanisms operating against trunk diseases fundamentally differ from those effective against foliar pathogens, emphasizing wound healing efficiency, compartmentalization of infected tissues through tylosis formation and barrier zone development, tolerance to fungal phytotoxins, and maintenance of functional vascular capacity despite partial colonization. ||No complete resistance to trunk diseases exists in cultivated Vitis, but substantial variation in susceptibility among cultivars and rootstocks enables selection for enhanced tolerance. ||Trunk diseases have emerged as the most significant threat to vineyard longevity globally, causing estimated annual losses exceeding €1.5 billion in Europe alone, making resistance breeding a critical priority despite the challenges posed by long evaluation periods and complex, multi-pathogen etiology.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gramaje D et al. (2018) Managing grapevine trunk diseases with respect to etiology and epidemiology: current strategies and future prospects, Plant Disease 102:12-39|| Bertsch C et al. (2013) Grapevine trunk diseases: complex and still poorly understood, Plant Pathology 62:243-265|| Mugnai L et al. (1999) Esca (black measles) and brown wood-streaking: two old and elusive diseases of grapevines, Plant Disease 83:404-418"
  },
  "Esca_Resistance_Disposition": {
    "definition": "An Esca_Resistance_Disposition is a Trunk_Disease_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through defense processes that limit infection, colonization, and pathogenesis by the fungal complex causing esca disease, primarily Phaeomoniella chlamydospora (Pch), Phaeoacremonium minimum (Pm), and the basidiomycete Fomitiporia mediterranea (Fmed).", 
    "alternative_term": "esca complex tolerance | Phaeomoniella resistance | black measles resistance |+ Esca-Resistenz-Disposition | Esca-Toleranz | Phaeomoniella-Resistenz",
    "example_of_usage": "Comparative analysis of Esca_Resistance_Disposition at the University of Florence employed controlled trunk inoculation of 15 cultivars with Phaeomoniella chlamydospora to characterize early resistance responses. ||Six months post-inoculation, wood cores were extracted and analyzed for extent of vascular discoloration, pathogen DNA quantity (qPCR), and host defense gene expression. 'Sangiovese' (tolerant) exhibited 65% shorter wood streaking (mean 4.2 cm versus 12.1 cm in susceptible 'Trebbiano'), 78% lower Pch DNA concentration, and 3.5-fold higher expression of genes encoding stilbene synthase, phenylalanine ammonia-lyase, and chitinase in tissues adjacent to inoculation sites. ||Histological examination revealed that 'Sangiovese' produced tyloses in 45% of vessels within 5mm of infection versus only 12% in 'Trebbiano', and accumulated dense phenolic deposits visible as dark reaction zones compartmentalizing the infection. ||Phytotoxin sensitivity assays showed that 'Sangiovese' callus tissue maintained 70% viability when exposed to 50 μg/mL scytalone, while 'Trebbiano' callus viability dropped to 30% at equivalent concentrations, demonstrating both structural and biochemical components of enhanced Esca_Resistance_Disposition.",
    "editor_note": "Esca_Resistance_Disposition is_a Trunk_Disease_Resistance_Disposition. ||Esca is a disease complex involving multiple fungal species acting in succession: Phaeomoniella chlamydospora and Phaeoacremonium species cause vascular symptoms, while Fomitiporia mediterranea causes white rot of mature wood. ||Child classes include Wound_Compartmentalization_Disposition and Tylosis_Formation_Disposition representing specific resistance mechanisms. ||Esca resistance evaluation requires long-term studies due to the chronic disease progression, with controlled inoculation studies providing early indicators of potential field tolerance.  This disposition represents the capacity to resist the progressive wood degradation and vascular dysfunction caused by these pathogens acting in succession or combination, manifesting as various syndromes including brown wood streaking (young vine decline), Petri disease, and classical esca with its characteristic white rot and tiger-stripe foliar symptoms. ||Esca resistance mechanisms include efficient wound healing limiting initial Pch colonization, compartmentalization of vascular infections through tylosis formation and accumulation of phenolic compounds in vessel-occluding gels, tolerance to the naphthoquinone phytotoxins (scytalone, isosclerone) produced by Pch and Pm, and resistance to the lignin-degrading enzymes of Fmed that cause white rot of heartwood. ||The chronic nature of esca, with symptoms often appearing years or decades after initial infection, complicates resistance evaluation. ||No cultivar is immune, but substantial variation exists, with 'Cabernet Sauvignon' and 'Merlot' generally showing better tolerance than 'Sauvignon Blanc', 'Ugni Blanc', and 'Grenache'. ||Understanding esca resistance dispositions is critical for cultivar and rootstock selection to maximize productive vineyard lifespan, as esca has become the most economically significant trunk disease in European viticulture.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gramaje D et al. (2018) Managing grapevine trunk diseases with respect to etiology and epidemiology, Plant Disease 102:12-39|| Magnin-Robert M et al. (2011) Changes in plant metabolism and accumulation of fungal metabolites in response to esca proper and apoplexy expression in the whole grapevine, Phytopathology 101:424-436|| Murolo S, Romanazzi G (2014) Effects of grapevine cultivar, rootstock and clone on esca disease, Australasian Plant Pathology 43:215-221"
  },
  "Wound_Compartmentalization_Disposition": {
    "definition": "A Wound_Compartmentalization_Disposition is an Esca_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through the formation of anatomical and chemical barriers that restrict the spread of wood-inhabiting pathogens from initial wound infection sites into healthy surrounding tissues.", 
    "alternative_term": "wound barrier formation | CODIT response disposition | decay compartmentalization |+ Wundkompartimentierungs-Disposition | Wundabschottung | Barrierezone-Bildung",
    "example_of_usage": "Quantitative characterization of Wound_Compartmentalization_Disposition at Hochschule Geisenheim compared barrier zone formation in 8 cultivars following standardized pruning wound inoculation with Phaeomoniella chlamydospora. ||At 6 and 12 months post-inoculation, wood sections were harvested and analyzed for compartmentalization zone dimensions, histochemistry, and pathogen extent. 'Riesling' exhibited strong Wound_Compartmentalization_Disposition with barrier zone width of 2.8 mm (versus 0.9 mm in susceptible 'Müller-Thurgau'), barrier zone completeness of 94% (continuous arc around wound), and intense phloroglucinol-HCl staining indicating lignin deposition throughout the barrier. ||Pathogen colonization was restricted to 15 mm from the wound in 'Riesling' versus 48 mm in 'Müller-Thurgau' at 12 months. ||Biochemical analysis revealed 4.2-fold higher accumulation of trans-resveratrol and ε-viniferin in 'Riesling' barrier zone tissues. ||Importantly, barrier zone formation was most effective when wounds were made during vine dormancy (December-February), with spring pruning wounds showing 40% reduction in compartmentalization completeness across all cultivars, demonstrating the interaction between genetic disposition and cultural practices in determining wound compartmentalization efficacy.",
    "editor_note": "Wound_Compartmentalization_Disposition is_a Esca_Resistance_Disposition. ||This class represents the anatomical barrier formation component of esca resistance, mechanistically related to but distinct from Tylosis_Formation_Disposition which specifically addresses vessel occlusion. ||CODIT (Compartmentalization of Decay in Trees) principles apply to grapevines though the specific anatomical responses differ from forest trees. ||Compartmentalization effectiveness is strongly influenced by pruning timing, wound size, and vine physiological status, creating important interactions between genetic disposition and viticultural management.  This disposition represents the grapevine's capacity to implement the CODIT (Compartmentalization of Decay in Trees) response, forming boundary zones that limit pathogen movement in radial, tangential, and axial directions within woody tissues. ||Effective wound compartmentalization involves multiple coordinated processes including rapid formation of wound periderm sealing the wound surface, deposition of suberin and lignin in cell walls of the barrier zone, accumulation of phenolic compounds (particularly stilbenes and flavonoids) with antimicrobial activity, and formation of dense tyloses occluding vessels to prevent longitudinal pathogen spread. ||The strength of compartmentalization responses varies substantially among grapevine cultivars and is influenced by wound timing, vine age and vigor, and environmental conditions. ||Cultivars with strong Wound_Compartmentalization_Disposition form narrow, dense barrier zones that effectively contain infections, while susceptible cultivars produce diffuse, incomplete barriers allowing pathogen escape and progressive colonization of functional xylem. ||This disposition is particularly important following pruning wounds, the primary infection courts for esca-associated fungi, and its enhancement through cultivar selection or cultural practices represents a key strategy for trunk disease management.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Shigo AL (1984) Compartmentalization: a conceptual framework for understanding how trees grow and defend themselves, Annual Review of Phytopathology 22:189-214|| Pouzoulet J et al. (2014) Xylem vessel diameter affects the compartmentalization of the vascular pathogen Phaeomoniella chlamydospora in grapevine, Frontiers in Plant Science 5:253|| Pierron RJG et al. (2016) Cork formation and anatomical responses of grapevine xylem to Phaeomoniella chlamydospora infection, FEMS Microbiology Letters 363:fnw025"
  },
  "Tylosis_Formation_Disposition": {
    "definition": "A Tylosis_Formation_Disposition is an Esca_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through the production of tyloses — balloon-like outgrowths of xylem parenchyma cells that protrude through pit membranes into adjacent vessel lumens, occluding the vessel and preventing longitudinal movement of pathogens and their phytotoxins through the vascular system.", 
    "alternative_term": "vessel occlusion capacity | tylosis defense disposition | vascular occlusion response |+ Thyllenbildungs-Disposition | Gefäßverschluss-Kapazität | Thylle-Verteidigung",
    "example_of_usage": "Detailed anatomical analysis of Tylosis_Formation_Disposition at UC Davis compared tylosis production in response to Phaeomoniella chlamydospora trunk inoculation across 10 scion cultivars and 5 rootstocks. ||Vascular casts and scanning electron microscopy quantified tylosis density, coverage, and wall thickness in vessels at 5, 10, and 20 mm from inoculation sites at 4 months post-inoculation. 'Petit Verdot' exhibited the strongest Tylosis_Formation_Disposition with tylosis density of 12.4 per mm vessel length, 85% vessel lumen occlusion, and tylosis wall thickness of 1.8 μm (heavily lignified). ||In contrast, susceptible 'Thompson Seedless' showed density of 3.2 per mm, only 25% occlusion, and thin walls of 0.6 μm. ||Pathogen colonization extent inversely correlated with tylosis parameters (r = -0.78 for density, -0.82 for occlusion percentage). ||Importantly, rootstock genotype significantly influenced scion tylosis formation, with 'Petit Verdot' on '110 Richter' producing 35% more tyloses than on '101-14 Mgt', indicating that rootstock-mediated signals modulate this defense response. ||Hydraulic conductivity measurements confirmed that heavily tylosed 'Petit Verdot' vines maintained adequate water transport (85% of healthy controls) despite partial vessel occlusion, demonstrating effective partitioning between infected and functional vascular sectors.",
    "editor_note": "Tylosis_Formation_Disposition is_a Esca_Resistance_Disposition. ||Tyloses are formed by xylem parenchyma cells (specifically, contact cells adjacent to vessels) and represent a specialized vascular defense distinct from general wound compartmentalization. ||Tylosis production is triggered by both pathogen infection and abiotic stresses (drought, wounding), requiring careful experimental controls to assess pathogen-specific responses. ||Rootstock genotype influences scion tylosis formation, adding complexity to resistance phenotyping. ||Excessive tylosis can impair water transport, particularly under drought, necessitating balance between defense and hydraulic function.  This disposition represents a specialized vascular defense mechanism critical for restricting the spread of esca-associated fungi (Phaeomoniella chlamydospora, Phaeoacremonium species) that colonize and move through functional xylem vessels. ||Effective tylosis formation involves the perception of pathogen presence or vascular dysfunction, activation of parenchyma cell expansion, targeted deposition of tylosis walls containing suberin, lignin, and phenolic compounds, and coordination of tylosis production to create continuous vessel blockages without excessive compromise of water transport capacity. ||The speed, extent, and chemical fortification of tylosis responses vary substantially among grapevine cultivars, correlating with differential susceptibility to trunk diseases. ||Cultivars with strong Tylosis_Formation_Disposition rapidly produce dense, lignified tyloses in vessels adjacent to infection sites, creating effective barriers against pathogen spread, while susceptible cultivars produce sparse, thin-walled tyloses that pathogens readily breach. ||However, excessive tylosis formation can impair vine water relations, particularly under drought stress, requiring balance between pathogen containment and maintenance of hydraulic function. ||Understanding tylosis formation dispositions informs both cultivar selection and development of elicitor treatments that could enhance this natural defense response.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pouzoulet J et al. (2014) Xylem vessel diameter affects the compartmentalization of the vascular pathogen Phaeomoniella chlamydospora in grapevine, Frontiers in Plant Science 5:253|| De Micco V et al. (2016) Xylem anatomical traits reveal different strategies of two Mediterranean oaks to cope with drought and warming, Environmental and Experimental Botany 133:128-138|| Sun Q et al. (2013) Xylem occlusion in grapevine to limit the systemic spread of Pierce's disease, American Journal of Enology and Viticulture 64:153-159"
  },
  "Eutypa_Resistance_Disposition": {
    "definition": "A Eutypa_Resistance_Disposition is a Trunk_Disease_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through defense processes that limit infection, colonization, and pathogenesis by Eutypa lata and related diatrypaceous fungi causing Eutypa dieback (also known as dying arm disease).", 
    "alternative_term": "Eutypa dieback tolerance | dying arm resistance | Eutypa lata resistance |+ Eutypa-Resistenz-Disposition | Eutypiose-Resistenz | Eutypa-lata-Toleranz",
    "example_of_usage": "Controlled inoculation studies of Eutypa_Resistance_Disposition at CSIRO Adelaide compared host responses across 18 cultivars following E. lata trunk inoculation. ||Vines were inoculated with mycelial plugs inserted into drill wounds on the trunk, and disease development was assessed at 12 and 24 months through destructive sampling of inoculated trunks. ||Canker dimensions (length, width, depth) and pathogen extent (visualized by wood discoloration and confirmed by re-isolation) varied dramatically among cultivars. 'Grenache' exhibited strong Eutypa_Resistance_Disposition with mean canker length of 28 mm and pathogen reisolation limited to 35 mm from inoculation point at 24 months. ||Susceptible 'Shiraz' developed cankers averaging 95 mm length with pathogen recovery to 120 mm. 'Grenache' also showed enhanced tolerance to eutypine in detached leaf bioassays, with 50% less necrosis than 'Shiraz' at equivalent toxin concentrations (50 μg/mL), suggesting both structural resistance (compartmentalization) and biochemical tolerance contribute to its Eutypa_Resistance_Disposition. ||Field surveys in South Australian vineyards corroborated experimental findings, with 'Grenache' blocks showing 60% lower incidence of Eutypa symptoms than adjacent 'Shiraz' of equivalent age.",
    "editor_note": "Eutypa_Resistance_Disposition is_a Trunk_Disease_Resistance_Disposition. ||Eutypa dieback is distinct from esca in etiology (Eutypa lata versus Phaeomoniella/Phaeoacremonium/Fomitiporia complex) and symptomatology (stunted shoots with small leaves versus tiger-stripe foliar symptoms), though both diseases may co-occur in the same vine. ||Eutypa resistance involves both wound healing/compartmentalization and tolerance to the phytotoxin eutypine. ||Disease evaluation requires multi-year studies due to slow pathogen progression, though controlled inoculation accelerates screening compared to natural infection studies.  This disposition represents the capacity to resist the progressive wood necrosis, canker formation, and stunted shoot growth caused by E. lata colonization of pruning wounds and subsequent spread through vascular and structural wood tissues. ||Eutypa dieback symptoms include wedge-shaped cankers visible in trunk cross-sections, stunted spring shoots with small, chlorotic, cup-shaped leaves, and eventual death of affected cordons or entire vines. ||Resistance mechanisms operating against E. lata include efficient wound healing that limits the infection window (ascospore germination and penetration primarily occur within 2-4 weeks of pruning), compartmentalization restricting mycelial spread from initial infection sites, and tolerance to eutypine and other phytotoxic secondary metabolites produced by the fungus that cause the characteristic stunted growth symptoms. ||Substantial variation in Eutypa susceptibility exists among cultivars, with 'Cabernet Sauvignon', 'Shiraz', and 'Chenin Blanc' considered highly susceptible, while 'Merlot', 'Semillon', and 'Clairette' show greater tolerance. ||No cultivar is immune, but selection for enhanced Eutypa_Resistance_Disposition can significantly extend productive vineyard life in regions where this disease is prevalent, particularly in Mediterranean and warm-temperate wine regions with winter rainfall patterns.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sosnowski MR et al. (2007) Influence of grapevine cultivar and isolate of Eutypa lata on wood and foliar symptoms, Plant Disease 91:924-931|| Peros JP, Berger G (1994) A rapid method to assess the aggressiveness of Eutypa lata isolates and the susceptibility of grapevine cultivars to Eutypa dieback, Agronomie 14:515-523|| Trouillas FP et al. (2010) Taxonomy and DNA phylogeny of Diatrypaceae associated with Vitis vinifera and other woody plants in California, Mycologia 102:319-336"
  },
  "Botryosphaeria_Resistance_Disposition": {
    "definition": "A Botryosphaeria_Resistance_Disposition is a Trunk_Disease_Resistance_Disposition that inheres in a Vitis vinifera plant and is realized through defense processes that limit infection, colonization, and pathogenesis by fungi in the family Botryosphaeriaceae, a diverse group causing Botryosphaeria dieback and related canker diseases of grapevine.", 
    "alternative_term": "Botryosphaeria dieback tolerance | black dead arm resistance | Botryosphaeriaceae resistance |+ Botryosphaeria-Resistenz-Disposition | Botryosphaeria-Toleranz | Diplodia-Resistenz",
    "example_of_usage": "Multi-species evaluation of Botryosphaeria_Resistance_Disposition at Stellenbosch University, South Africa, compared host responses to four Botryosphaeriaceae species (Neofusicoccum australe, N. parvum, Diplodia seriata, Lasiodiplodia theobromae) across 12 cultivars using standardized green shoot inoculation assays. ||At 8 weeks post-inoculation, lesion lengths were measured and pathogens re-isolated to confirm Koch's postulates. ||Substantial cultivar × pathogen interactions were observed. 'Pinotage' showed broad Botryosphaeria_Resistance_Disposition with mean lesion lengths of 18-25 mm across all four species. 'Sauvignon Blanc' was broadly susceptible (lesions 65-95 mm). ||Interestingly, 'Cabernet Sauvignon' exhibited species-specific responses, showing strong resistance to D. seriata (22 mm) but high susceptibility to N. parvum (78 mm), demonstrating that Botryosphaeria_Resistance_Disposition is not uniform across the pathogen family. ||Field validation in a 15-year-old cultivar trial confirmed experimental rankings, with 'Pinotage' vines showing 70% lower incidence of black dead arm symptoms than 'Sauvignon Blanc'. ||Histological examination revealed that 'Pinotage' produces denser wound-associated tyloses and accumulates higher concentrations of antimicrobial phenolics in response to Botryosphaeriaceae colonization.",
    "editor_note": "Botryosphaeria_Resistance_Disposition is_a Trunk_Disease_Resistance_Disposition. ||The Botryosphaeriaceae family includes numerous species pathogenic on grapevine, with regional variation in predominant species and cultivar × species interactions creating complexity for resistance evaluation. ||Many Botryosphaeriaceae exist as latent endophytes, with disease expression triggered by host stress, complicating the distinction between resistance (preventing infection/colonization) and tolerance (limiting disease expression despite colonization). ||Shared resistance mechanisms with esca-associated fungi suggest common trunk disease resistance factors, but species-specific components also contribute to overall Botryosphaeria_Resistance_Disposition.  This disposition represents the capacity to resist infection by multiple Botryosphaeriaceae species including Diplodia seriata, Lasiodiplodia theobromae, Neofusicoccum parvum, Botryosphaeria dothidea, and related taxa that cause wood necrosis, canker formation, graft union failure, and cordon dieback. ||Botryosphaeriaceae fungi are ubiquitous in vineyard environments, existing as endophytes in healthy tissue and transitioning to pathogenic behavior when host stress compromises defense responses. ||These opportunistic pathogens infect through pruning wounds and other injuries, producing wedge-shaped or sectorial necrosis in wood, black or brown vascular streaking, and occasionally shoot dieback and bud necrosis. ||Resistance mechanisms include efficient wound closure limiting infection opportunities, recognition and containment of endophytic populations before pathogenic transition, compartmentalization of necrotic tissues, and tolerance to botryosphaeriaceae phytotoxins (mellein, botryodiplodin). ||Botryosphaeriaceae diversity creates challenges for resistance breeding, as cultivars may differ in susceptibility to individual species. ||Generally, cultivars susceptible to esca also show heightened Botryosphaeria susceptibility, suggesting shared resistance mechanisms against trunk-colonizing fungi, but species-specific resistance components also exist.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Úrbez-Torres JR (2011) The status of Botryosphaeriaceae species infecting grapevines, Phytopathologia Mediterranea 50:S5-S45|| Pitt WM et al. (2013) Evaluation of fungicides for the management of Botryosphaeria canker of grapevines, Plant Disease 97:1473-1482|| Billones-Baaijens R, Savocchia S (2019) A review of Botryosphaeriaceae species associated with grapevine trunk diseases in Australia and New Zealand, Australasian Plant Pathology 48:3-18"
  },
  "Viral_Resistance_Disposition": {
    "definition": "A Viral_Resistance_Disposition is a Pathogen_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes that limit infection, replication, systemic movement, or symptom expression by plant viruses affecting grapevine.", 
    "alternative_term": "virus resistance disposition | viral disease tolerance | grapevine virus immunity |+ Virusresistenz-Disposition | Virale-Krankheitsresistenz | Virustoleranz",
    "example_of_usage": "Screening for Viral_Resistance_Disposition at INRAE Colmar evaluated responses of 45 Vitis accessions to Grapevine fanleaf virus (GFLV) through controlled graft inoculation using infected rootstock material. ||Virus presence and titer were monitored by DAS-ELISA at 6, 12, and 24 months post-grafting. ||Susceptible V. vinifera 'Gewürztraminer' showed systemic infection in 100% of grafted plants within 6 months, with high viral titers (OD₄₀₅ > 2.0) and severe symptoms including leaf deformation, yellow mosaic, and 40-60% yield reduction. ||The V. rupestris × V. riparia hybrid 'Börner' exhibited strong Viral_Resistance_Disposition with only 15% of grafted plants testing positive at 24 months, low viral titers when detected (OD₄₀₅ < 0.3), and no observable symptoms or yield impact. ||Muscadinia rotundifolia accessions showed apparent immunity with 0% transmission despite extended graft union contact. ||Interestingly, some V. vinifera cultivars ('Chasselas', 'Savagnin') displayed tolerance phenotypes — 100% infection rates but maintained near-normal productivity (>85% of healthy controls), demonstrating that Viral_Resistance_Disposition encompasses both resistance (limiting infection) and tolerance (limiting disease impact despite infection).",
    "editor_note": "Viral_Resistance_Disposition is_a Pathogen_Resistance_Disposition. ||This class encompasses resistance to all viral pathogens of grapevine, distinct from Fungal_Resistance_Disposition and Bacterial_Resistance_Disposition which address other pathogen kingdoms. ||Child classes are organized by viral disease complex: Fanleaf_Resistance_Disposition, Leafroll_Resistance_Disposition, Red_Blotch_Resistance_Disposition, and Fleck_Tolerance_Disposition. ||Viral resistance may operate directly against the virus or indirectly through vector resistance. ||The distinction between resistance (limiting infection) and tolerance (limiting impact despite infection) is particularly important for viral diseases where true immunity is rare.  This disposition represents the capacity to resist or tolerate the diverse viral pathogens that persistently infect grapevine, including nepoviruses (Grapevine fanleaf virus), ampeloviruses (Grapevine leafroll-associated viruses), vitiviruses, marafiviruses, and the recently characterized geminivirids (Grapevine red blotch virus). ||Unlike fungal and bacterial pathogens that can be controlled through chemical applications, viral infections are incurable once established, making resistance dispositions the primary long-term management strategy alongside use of certified virus-free planting material. ||Viral resistance mechanisms in plants include restriction of viral entry and initial replication, RNA silencing pathways degrading viral genomes, translation inhibition of viral proteins, impaired cell-to-cell movement through plasmodesmata, blocked systemic transport via phloem, and hypersensitive response eliminating infected cells. ||Additionally, resistance to viral vectors (nematodes for nepoviruses, mealybugs and soft scales for leafroll viruses) provides indirect protection by preventing virus acquisition and transmission. ||True genetic resistance to grapevine viruses is rare in Vitis vinifera, with most cultivars susceptible to infection but varying in tolerance (ability to maintain productivity despite infection). ||Wild Vitis species, particularly North American species co-evolved with endemic nepoviruses, provide sources of both direct viral resistance and vector resistance that can be introgressed into cultivated backgrounds through breeding.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Martelli GP (2017) An overview on grapevine viruses, viroids, and the diseases they cause, Grapevine Viruses: Molecular Biology, Diagnostics and Management, Springer|| Oliver JE, Fuchs M (2011) Tolerance and resistance to viruses and their vectors in Vitis sp.: a virologist's perspective of the literature, American Journal of Enology and Viticulture 62:438-451|| Maree HJ et al. (2013) Grapevine leafroll-associated virus 3, Frontiers in Microbiology 4:82"
  },
  "Fanleaf_Resistance_Disposition": {
    "definition": "A Fanleaf_Resistance_Disposition is a Viral_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, replication, systemic spread, or symptom expression by Grapevine fanleaf virus (GFLV) and the closely related Arabis mosaic virus (ArMV), nepoviruses causing fanleaf degeneration disease.", 
    "alternative_term": "GFLV resistance disposition | fanleaf degeneration resistance | nepovirus resistance |+ Reisigkrankheit-Resistenz-Disposition | GFLV-Resistenz | Fanleaf-Resistenz",
    "example_of_usage": "Long-term evaluation of Fanleaf_Resistance_Disposition at the University of California, Davis, compared disease development in 'Cabernet Sauvignon' grafted onto susceptible ('AxR#1', V. vinifera × V. rupestris) versus resistant ('O39-16', V. vinifera × M. rotundifolia) rootstocks planted in a vineyard naturally infested with GFLV-viruliferous Xiphinema index. ||After 12 years, 95% of vines on 'AxR#1' tested GFLV-positive by ELISA, exhibiting severe fanleaf symptoms with mean yield of 4.2 kg/vine compared to 11.8 kg/vine for healthy controls (64% reduction). ||In contrast, only 8% of vines on 'O39-16' tested positive, with infected individuals showing low viral titers and minimal symptoms, and plot mean yield of 10.5 kg/vine (89% of healthy controls). ||Nematode population monitoring revealed X. index densities of 850 individuals per 250g soil around 'AxR#1' roots versus only 45 per 250g soil around 'O39-16', demonstrating that Fanleaf_Resistance_Disposition of the rootstock operated primarily through suppression of vector populations rather than direct viral resistance, effectively interrupting the transmission cycle and protecting the susceptible scion.",
    "editor_note": "Fanleaf_Resistance_Disposition is_a Viral_Resistance_Disposition. ||Fanleaf disease is caused by GFLV and related nepoviruses transmitted by Xiphinema dagger nematodes. ||Child classes distinguish GFLV_Resistance_Disposition (direct resistance to virus replication/movement) from Xiphinema_Transmission_Resistance_Disposition (resistance to nematode vector). ||Practical fanleaf management relies primarily on X. index-resistant rootstocks, as true resistance to GFLV itself is limited in available germplasm. ||The disease has been present in European viticulture for centuries, likely since Roman times.  This disposition represents the capacity to resist one of the most ancient and economically important viral diseases of grapevine, endemic to European and Mediterranean viticulture for centuries and now distributed worldwide. ||GFLV causes characteristic symptoms including fan-shaped leaves with abnormally acute sinuses, yellow mosaic or vein-banding patterns, shortened internodes, abnormal branching, poor fruit set (millerandage), and progressive vine decline with yield losses of 50-80% in severely affected vines. ||The virus is transmitted persistently by ectoparasitic dagger nematodes of the genus Xiphinema, primarily X. index and X. italiae, which acquire virus particles during root feeding and retain infectivity for months to years. ||Fanleaf resistance dispositions can operate at multiple levels including resistance to nematode feeding preventing virus acquisition from soil inoculum, resistance to virus replication and systemic movement following nematode-mediated inoculation, and tolerance enabling maintenance of productivity despite infection. ||True resistance to GFLV itself is rare in Vitis, but strong resistance to X. index exists in certain North American species and Muscadinia rotundifolia, providing the basis for resistant rootstock breeding that represents the most effective long-term management strategy for fanleaf-affected vineyards.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Andret-Link P et al. (2004) Grapevine fanleaf virus: still a major threat to the grapevine industry, Journal of Plant Pathology 86:183-195|| Walker MA et al. (1994) Resistance to Xiphinema index in Vitis and its hybrids, Vitis 33:21-26|| Fuchs M (2017) Grapevine fanleaf virus, Grapevine Viruses: Molecular Biology, Diagnostics and Management, Springer"
  },
  "GFLV_Resistance_Disposition": {
    "definition": "A GFLV_Resistance_Disposition is a Fanleaf_Resistance_Disposition that inheres in a Vitis plant and is realized through host defense processes that directly limit Grapevine fanleaf virus replication, cell-to-cell movement, or systemic spread within plant tissues, independent of resistance to the Xiphinema nematode vector.", 
    "alternative_term": "direct GFLV resistance | viral replication resistance | nepovirus multiplication resistance |+ Direkte GFLV-Resistenz-Disposition | Virusreplikations-Resistenz | GFLV-Vermehrungs-Resistenz",
    "example_of_usage": "Systematic evaluation of GFLV_Resistance_Disposition at INRAE Colmar utilized mechanical inoculation to bypass vector-mediated transmission and directly assess host responses to viral infection. ||Carborundum-assisted rub inoculation of young leaves with purified GFLV particles was performed on 60 Vitis accessions, with systemic infection assessed by ELISA and qRT-PCR at 6 weeks post-inoculation. ||V. vinifera cultivars showed uniformly high susceptibility, with 95-100% infection rates and high viral titers (10⁶-10⁸ RNA copies per μg total RNA). ||V. rupestris and V. riparia accessions exhibited variable responses, with infection rates of 60-90% but generally lower viral titers (10⁴-10⁶ copies). ||Remarkably, Muscadinia rotundifolia accession 'Carlos' showed apparent immunity with 0% systemic infection across 40 inoculated plants, and localized necrosis at inoculation sites suggesting hypersensitive response. ||When 'Carlos' was used as rootstock with V. vinifera 'Chardonnay' scion, 100% of scions became infected following scion inoculation, demonstrating that M. rotundifolia GFLV_Resistance_Disposition is cell-autonomous and does not confer systemic protection to grafted susceptible scions.",
    "editor_note": "GFLV_Resistance_Disposition is_a Fanleaf_Resistance_Disposition. ||This class represents direct antiviral resistance operating after inoculation, distinguished from Xiphinema_Transmission_Resistance_Disposition which prevents initial virus delivery. ||True resistance to GFLV replication is rare, with M. rotundifolia providing the strongest known source. ||The cell-autonomous nature of M. rotundifolia resistance limits its utility in rootstock applications for protecting V. vinifera scions, though resistant rootstocks still provide benefit through vector resistance. ||Mechanical inoculation studies bypass vector complications but may not fully reflect natural infection dynamics.  This disposition represents true antiviral resistance mechanisms operating after the virus has entered the plant, in contrast to vector resistance that prevents initial inoculation. ||GFLV, a member of the genus Nepovirus (family Secoviridae), has a bipartite positive-sense RNA genome encoding replication proteins on RNA1 and movement and coat proteins on RNA2. ||Host resistance mechanisms targeting GFLV may include RNA silencing (RNAi) pathways that recognize and degrade viral RNA, translation inhibition preventing viral polyprotein synthesis, interference with viral replicase complex assembly, restriction of cell-to-cell movement through modification of plasmodesmatal transport, and limitation of systemic spread through the vascular system. ||True genetic resistance to GFLV replication is rare in the Vitis genus, with most accessions supporting viral multiplication following mechanical or nematode-mediated inoculation. ||Muscadinia rotundifolia exhibits the strongest GFLV resistance phenotype, with some accessions apparently immune to infection. ||Introgression of M. rotundifolia resistance into V. vinifera backgrounds has proven challenging due to crossing barriers and extensive linkage drag, but represents a long-term breeding objective for comprehensive fanleaf resistance combining both viral and vector resistance components.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Spielmann A et al. (2000) Analysis of transgenic grapevine (Vitis rupestris) and Nicotiana benthamiana plants expressing an Arabis mosaic virus coat protein gene, Plant Science 156:235-244|| Vigne E et al. (2004) Evaluation of transgenic Vitis vinifera expressing the coat protein or movement protein genes of Grapevine fanleaf virus, Vitis 43:79-89|| Oliver JE, Fuchs M (2011) Tolerance and resistance to viruses and their vectors in Vitis sp., American Journal of Enology and Viticulture 62:438-451"
  },
  "Xiphinema_Transmission_Resistance_Disposition": {
    "definition": "A Xiphinema_Transmission_Resistance_Disposition is a Fanleaf_Resistance_Disposition that inheres in a Vitis plant and is realized through host characteristics that prevent or limit Grapevine fanleaf virus transmission by Xiphinema dagger nematodes, primarily through resistance to nematode feeding on roots.", 
    "alternative_term": "Xiphinema index resistance | nematode transmission resistance | vector-mediated GFLV resistance |+ Xiphinema-Übertragungs-Resistenz-Disposition | Nematoden-Vektor-Resistenz | Xiphinema-index-Resistenz",
    "example_of_usage": "Greenhouse evaluation of Xiphinema_Transmission_Resistance_Disposition at UC Davis quantified nematode feeding preference and population development on 20 rootstock genotypes in controlled pot assays. ||Vines were planted in soil inoculated with 500 X. index individuals per pot, and nematode populations were assessed after 6 months. ||Susceptible 'Freedom' (V. champinii derivative) supported vigorous nematode reproduction with final populations averaging 2,850 per pot (470% increase). ||The resistant selection 'O39-16' (V. vinifera × M. rotundifolia BC₃) showed strong Xiphinema_Transmission_Resistance_Disposition with final populations of only 85 per pot (83% decline from initial inoculum), indicating that nematodes failed to reproduce and gradually died. ||Microscopic examination of roots revealed that X. index probing attempts on 'O39-16' triggered rapid browning of contacted cells, with 78% of observed feeding attempts abandoned within 10 minutes compared to sustained feeding lasting >60 minutes on 'Freedom'. ||In field trials with GFLV-viruliferous X. index, 'O39-16' rootstocks remained 95% virus-free after 8 years while adjacent 'Freedom' rootstocks reached 100% infection within 4 years, demonstrating effective translation of nematode resistance into field-level fanleaf disease control.",
    "editor_note": "Xiphinema_Transmission_Resistance_Disposition is_a Fanleaf_Resistance_Disposition. ||This class represents resistance to the nematode vector rather than to GFLV itself, providing indirect but highly effective viral disease control. ||X. index resistance is the primary mechanism through which resistant rootstocks protect grafted V. vinifera scions from fanleaf infection. ||The resistance is distinct from general nematode resistance, as X. index has specific host preferences and resistance mechanisms may not transfer to other nematode species. ||Resistance sources include M. rotundifolia and several North American Vitis species.  This disposition represents indirect viral resistance operating by interrupting the vector-mediated transmission cycle rather than through direct antiviral mechanisms. ||Xiphinema index, the primary GFLV vector, is an ectoparasitic nematode that feeds on root tips using a long odontostyle (feeding stylet) to penetrate epidermal cells and extract cell contents. ||The nematode acquires GFLV particles during feeding on infected roots and retains virus in association with its foregut lining, transmitting to healthy plants during subsequent feeding over periods of months to years. ||Resistance to X. index feeding in certain Vitis genotypes involves multiple mechanisms including root tip anatomical features impeding stylet penetration, biochemical factors deterring feeding initiation or continuation, hypersensitive response killing cells at feeding sites, and root regeneration capacity compensating for feeding damage. ||Muscadinia rotundifolia and certain North American Vitis species (V. arizonica, V. rufotomentosa, V. candicans) exhibit strong X. index resistance that dramatically reduces nematode populations and consequently limits virus spread. ||This resistance has been successfully introgressed into rootstock breeding lines, providing the most effective practical strategy for managing fanleaf disease in infested vineyards through disruption of the virus-vector relationship.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Walker MA et al. (1994) Resistance to Xiphinema index in Vitis and its hybrids, Vitis 33:21-26|| Hwang CF et al. (2010) Fine mapping and characterization of XiR1, a locus for Xiphinema index resistance in grape, Theoretical and Applied Genetics 121:1749-1762|| Esmenjaud D, Bouquet A (2009) Selection and application of resistant germplasm for grapevine nematodes management, Integrated Management of Fruit Crops and Forest Nematodes, Springer"
  },
  "Leafroll_Resistance_Disposition": {
    "definition": "A Leafroll_Resistance_Disposition is a Viral_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, replication, systemic spread, or symptom expression by Grapevine leafroll-associated viruses (GLRaVs), a complex of phloem-limited ampeloviruses and closteroviruses causing grapevine leafroll disease.", 
    "alternative_term": "GLRaV resistance disposition | leafroll tolerance | ampelovirus resistance |+ Blattroll-Resistenz-Disposition | Blattrollkrankheit-Resistenz | GLRaV-Resistenz",
    "example_of_usage": "Field evaluation of Leafroll_Resistance_Disposition in a naturally infected Napa Valley vineyard compared disease progression and economic impact across 12 cultivars over 8 growing seasons. ||Virus status was monitored annually by ELISA, with yield and fruit quality parameters measured at harvest. ||The susceptible cultivar 'Merlot' showed rapid disease progression with 85% infection by year 5, exhibiting severe symptoms (OIV 467 rating 7-9), mean yield reduction of 32% (6.2 vs 9.1 tonnes/ha in healthy vines), Brix reduction of 2.8°, and anthocyanin decline of 45%. 'Cabernet Sauvignon' demonstrated enhanced Leafroll_Resistance_Disposition (tolerance phenotype) with equivalent infection rate but markedly reduced impact: 18% yield reduction, 1.4° Brix reduction, and 22% anthocyanin decline. ||Symptom expression was less severe (OIV rating 3-5) despite similar viral titers as measured by qRT-PCR. ||The white cultivar 'Chardonnay' showed the highest tolerance with only 8% yield impact and minimal quality degradation, though symptoms were also inherently less visible. ||Vector monitoring revealed no cultivar differences in mealybug population densities, indicating that differential Leafroll_Resistance_Disposition reflected host tolerance to viral infection rather than vector resistance.",
    "editor_note": "Leafroll_Resistance_Disposition is_a Viral_Resistance_Disposition. ||Leafroll disease involves multiple viral species (GLRaV-1 through GLRaV-9, with GLRaV-3 most prevalent and damaging), complicating resistance evaluation. ||Child classes include GLRaV_Replication_Resistance_Disposition for direct antiviral resistance and Vector_Transmission_Resistance_Disposition for insect vector resistance. ||Unlike fanleaf, leafroll transmission by aerial insect vectors cannot be controlled through rootstock selection alone. ||Tolerance (maintaining productivity despite infection) is currently more relevant than true resistance for practical viticulture, as no strong resistance sources have been identified in V. vinifera.  This disposition represents the capacity to resist one of the most economically significant and widespread viral disease complexes affecting viticulture globally, present in virtually all wine-producing regions. ||Leafroll disease causes characteristic symptoms in red cultivars including downward rolling of leaf margins, interveinal reddening with green veins, and leaf thickening, while white cultivars show more subtle chlorosis and rolling. ||Physiological impacts include delayed and uneven ripening, reduced sugar accumulation (1-5°Brix reduction), elevated acidity, diminished anthocyanin and flavor compound synthesis, and yield losses of 15-40%. ||The GLRaV complex includes multiple species (GLRaV-1, -2, -3, -4, and variants) transmitted by mealybugs (Pseudococcus, Planococcus) and soft scale insects (Parthenolecanium, Pulvinaria) in a semi-persistent manner. ||Leafroll resistance dispositions can operate through resistance to viral replication and phloem loading, resistance or tolerance to insect vector feeding, and tolerance mechanisms maintaining productivity despite infection. ||Unlike fanleaf disease where resistant rootstocks effectively control transmission, leafroll is transmitted to aerial plant parts by mobile insect vectors, making scion resistance more critical. ||No strong genetic resistance to GLRaVs has been identified in V. vinifera, though significant tolerance variation exists among cultivars.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Naidu RA et al. (2014) Grapevine leafroll disease and associated viruses: a unique pathosystem, Annual Review of Phytopathology 52:61-83|| Maree HJ et al. (2013) Grapevine leafroll-associated virus 3, Frontiers in Microbiology 4:82|| Almeida RPP et al. (2013) Ecology and management of grapevine leafroll disease, Frontiers in Microbiology 4:94"
  },
  "GLRaV_Replication_Resistance_Disposition": {
    "definition": "A GLRaV_Replication_Resistance_Disposition is a Leafroll_Resistance_Disposition that inheres in a Vitis plant and is realized through host defense processes that directly limit Grapevine leafroll-associated virus replication, phloem cell colonization, or systemic spread within the plant vascular system, independent of resistance to mealybug or soft scale vectors.", 
    "alternative_term": "direct GLRaV resistance | leafroll replication resistance | ampelovirus multiplication resistance |+ Direkte GLRaV-Resistenz-Disposition | GLRaV-Replikations-Resistenz | Ampelovirus-Vermehrungs-Resistenz",
    "example_of_usage": "Comprehensive screening for GLRaV_Replication_Resistance_Disposition at Cornell University evaluated 180 Vitis accessions including wild species, interspecific hybrids, and V. vinifera cultivars using chip-bud graft inoculation with GLRaV-3-infected buds. ||Systemic infection was assessed by ELISA and RT-PCR at 6 and 12 months post-grafting. ||Results revealed universal susceptibility with no accession showing immunity or high-level resistance. ||V. vinifera cultivars exhibited 95-100% transmission rates with high viral titers (Ct values 18-22 in RT-qPCR). ||North American species (V. riparia, V. rupestris, V. labrusca) showed equivalent susceptibility (90-100% transmission) despite evolutionary separation from GLRaV-endemic regions. ||Even M. rotundifolia, which provides strong resistance to GFLV and many fungal pathogens, supported GLRaV-3 replication with 85% transmission rates. ||The only statistically significant variation detected was in symptom expression and yield impact, with 'Chambourcin' and 'Norton' showing tolerance phenotypes maintaining 90% of healthy vine productivity despite infection, compared to 65% productivity retention in symptomatic 'Cabernet Franc'. ||These findings confirm that breeding for GLRaV_Replication_Resistance_Disposition faces fundamental limitations in available germplasm diversity.",
    "editor_note": "GLRaV_Replication_Resistance_Disposition is_a Leafroll_Resistance_Disposition. ||This class represents direct antiviral resistance operating after inoculation, distinguished from Vector_Transmission_Resistance_Disposition which prevents initial virus delivery. ||Despite extensive germplasm screening, no strong natural resistance to GLRaV replication has been identified in Vitis or Muscadinia. ||This absence of resistance sources distinguishes leafroll from fanleaf disease, where M. rotundifolia provides strong GFLV resistance. ||Current management relies on clean planting material and vector control rather than genetic resistance. ||Tolerance variation among cultivars provides the only genetic tool currently available.  This disposition represents true antiviral resistance mechanisms operating after viral particles have been introduced into phloem tissues by vector feeding. ||GLRaVs are phloem-limited, positive-sense RNA viruses belonging to the families Closteroviridae (GLRaV-1, -3) and Botourmiaviridae (GLRaV-2), with complex genomes encoding replicases, movement proteins, and multiple coat protein variants. ||Host resistance mechanisms potentially targeting GLRaVs include RNA silencing pathways operative in phloem companion cells, restriction factors limiting viral replicase function, impaired viral movement through plasmodesmata connecting sieve elements and companion cells, and phloem-specific defense responses. ||True genetic resistance to GLRaV replication has proven extremely difficult to identify in Vitis germplasm, with screening of hundreds of accessions failing to reveal immune or highly resistant genotypes. ||All tested V. vinifera cultivars support GLRaV replication when graft-inoculated, though viral titers and symptom severity vary. ||Wild Vitis species show similarly broad susceptibility, with no strong resistance source identified for breeding programs. ||This absence of natural resistance has motivated research into transgenic approaches expressing viral coat proteins or RNA interference constructs, though these remain experimental.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Oliver JE, Fuchs M (2011) Tolerance and resistance to viruses and their vectors in Vitis sp., American Journal of Enology and Viticulture 62:438-451|| Maree HJ et al. (2013) Grapevine leafroll-associated virus 3, Frontiers in Microbiology 4:82|| Burger JT et al. (2017) Grapevine leafroll-associated viruses, Grapevine Viruses: Molecular Biology, Diagnostics and Management, Springer"
  },
  "Vector_Transmission_Resistance_Disposition": {
    "definition": "A Vector_Transmission_Resistance_Disposition is a Leafroll_Resistance_Disposition that inheres in a Vitis plant and is realized through host characteristics that prevent or limit Grapevine leafroll-associated virus transmission by mealybug (Pseudococcidae) and soft scale (Coccidae) insect vectors, primarily through resistance or non-preference affecting vector feeding behavior on aerial plant parts.", 
    "alternative_term": "mealybug resistance disposition | leafroll vector resistance | scale insect transmission resistance |+ Vektor-Übertragungs-Resistenz-Disposition | Schmierläuse-Resistenz | Blattroll-Vektor-Resistenz",
    "example_of_usage": "Investigation of Vector_Transmission_Resistance_Disposition at UC Davis compared vine mealybug (Planococcus ficus) population development and GLRaV-3 transmission efficiency across 8 cultivars in controlled greenhouse assays. ||Viruliferous mealybugs (10 per plant) were caged on healthy test vines, and vector populations were assessed weekly for 8 weeks while transmission was evaluated by RT-PCR at 12 weeks post-infestation. ||Significant cultivar variation in mealybug reproduction was observed, with 'Cabernet Sauvignon' supporting mean populations of 245 individuals per plant versus only 82 on 'Thompson Seedless' (67% reduction), suggesting differential Vector_Transmission_Resistance_Disposition. ||However, GLRaV-3 transmission rates did not differ significantly (75-90% across all cultivars), indicating that population suppression was insufficient to substantially reduce transmission probability. ||Analysis of leaf surface characteristics revealed that 'Thompson Seedless' possessed higher trichome density (32 vs 18 per mm²) and thicker epicuticular wax, potentially deterring mealybug settlement. ||Field trials showed similar trends but confirmed that natural vector pressure and transmission rates did not differ practically among cultivars under commercial conditions, limiting the current utility of vector-based resistance for leafroll management.",
    "editor_note": "Vector_Transmission_Resistance_Disposition is_a Leafroll_Resistance_Disposition. ||This class represents resistance to mealybug and soft scale insect vectors rather than to GLRaVs themselves. ||Unlike Xiphinema_Transmission_Resistance_Disposition for fanleaf where strong nematode resistance effectively controls disease, no strong resistance to leafroll vectors has been identified that provides practical disease control. ||The aerial feeding habit of leafroll vectors (versus soil-dwelling nematodes for fanleaf) means rootstock-based resistance is not applicable, making scion resistance the relevant target. ||Current leafroll vector management relies on cultural and chemical approaches rather than host resistance.  This disposition represents indirect viral resistance operating by interrupting the vector-mediated transmission cycle rather than through direct antiviral mechanisms. ||GLRaV transmission occurs when viruliferous vectors feed on phloem tissues, introducing viral particles that colonize sieve elements. ||Unlike the soil-dwelling nematode vectors of GFLV that can be excluded through resistant rootstocks, leafroll vectors are mobile insects that feed on above-ground tissues including leaves, shoots, and clusters, necessitating scion-based resistance. ||Vector transmission resistance mechanisms may include leaf surface characteristics (trichome density, wax composition) affecting vector settling and probing behavior, phloem chemistry deterring sustained feeding, induced defenses triggered by vector feeding that reduce transmission efficiency, and antibiosis factors reducing vector survival or reproduction. ||Variation in mealybug population development among grapevine cultivars has been documented, with some cultivars supporting lower populations that could theoretically reduce transmission pressure. ||However, strong genetic resistance to leafroll vectors has not been clearly demonstrated in Vitis germplasm, and practical vector management relies primarily on insecticides, mating disruption, and biological control rather than host plant resistance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Daane KM et al. (2012) Biology and management of mealybugs in vineyards, Arthropod Management in Vineyards, Springer|| Almeida RPP et al. (2013) Ecology and management of grapevine leafroll disease, Frontiers in Microbiology 4:94|| Bertin S et al. (2016) Transmission of Grapevine leafroll-associated virus-1 and -3 by soft scale and mealybug vectors, Proceedings of the International Council for the Study of Virus and Virus-like Diseases of the Grapevine (ICVG) 18:96-97"
  },
  "Red_Blotch_Resistance_Disposition": {
    "definition": "A Red_Blotch_Resistance_Disposition is a Viral_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, replication, systemic spread, or symptom expression by Grapevine red blotch virus (GRBV), a recently characterized DNA virus causing red blotch disease in North American and other vineyards.", 
    "alternative_term": "GRBV resistance disposition | red blotch tolerance | geminivirus resistance |+ Roter-Fleck-Resistenz-Disposition | GRBV-Resistenz | Red-Blotch-Resistenz",
    "example_of_usage": "Initial screening for Red_Blotch_Resistance_Disposition at UC Davis evaluated GRBV infection outcomes across 35 accessions following graft inoculation with infected budwood. ||Infection was assessed by qPCR targeting GRBV coat protein gene at 6, 12, and 24 months post-grafting. ||All tested V. vinifera cultivars (n=20) showed systemic infection within 12 months, with viral titers ranging from 10⁴ to 10⁶ genome copies per ng DNA. ||Symptom expression varied among cultivars, with 'Cabernet Sauvignon' and 'Merlot' displaying pronounced red blotches covering 40-60% of leaf area by véraison, while 'Chardonnay' and other white cultivars showed subtle interveinal chlorosis. ||North American species showed variable responses: V. riparia accessions exhibited delayed systemic infection (50% positive at 12 months versus 100% for V. vinifera) and lower viral titers, suggesting potential partial Red_Blotch_Resistance_Disposition worthy of further investigation. ||V. labrusca-derived 'Concord' supported infection but maintained yields within 90% of healthy controls, demonstrating tolerance. ||These preliminary findings provide direction for expanded germplasm screening, though no immunity or high-level resistance has been identified to date.",
    "editor_note": "Red_Blotch_Resistance_Disposition is_a Viral_Resistance_Disposition. ||Red blotch is caused by a geminivirus (DNA virus) distinct from the RNA viruses causing leafroll and fanleaf, potentially enabling different resistance mechanisms. ||The disease was only characterized in 2012, so resistance research is at early stages compared to long-studied viral diseases. ||Current management relies on clean planting material and removal of infected vines, as vector control options are limited and no resistant cultivars are available. ||Screening of diverse Vitis germplasm for resistance sources is ongoing.  This disposition represents the capacity to resist a newly emerged threat first described in 2012 in California vineyards, where it was initially confused with leafroll disease due to similar foliar reddening symptoms. ||GRBV is a member of the family Geminiviridae, genus Grablovirus, distinguished from the RNA viruses (GLRaVs) causing leafroll by its circular single-stranded DNA genome that replicates in the nucleus through rolling circle amplification. ||Red blotch symptoms in red cultivars include irregular red blotches on leaf blades that expand and coalesce during the season, without the leaf rolling typical of GLRaV infection. ||Physiological impacts include reduced sugar accumulation (2-5°Brix), elevated titratable acidity, diminished anthocyanin synthesis, and altered flavor compound profiles that compromise wine quality. ||Transmission occurs through the three-cornered alfalfa treehopper (Spissistilus festinus) and possibly other vectors, as well as through infected propagation material. ||Red blotch resistance research is in early stages given the recent virus characterization, but screening of Vitis germplasm has begun to identify potential resistance or tolerance sources. ||No strong resistance has been reported to date in V. vinifera, though systematic evaluation of wild species and breeding populations continues.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Al Rwahnih M et al. (2013) Grapevine red blotch-associated virus is a DNA virus causing red blotch disease, Phytopathology 103:1069-1076|| Sudarshana MR et al. (2015) Grapevine red blotch-associated virus, an emerging threat to the grapevine industry, Phytopathology 105:1026-1032|| Bahder BW et al. (2016) Grapevine red blotch disease and its vector, Wine Business Monthly 23:80-86"
  },
  "Fleck_Tolerance_Disposition": {
    "definition": "A Fleck_Tolerance_Disposition is a Viral_Resistance_Disposition that inheres in a Vitis plant and is realized through the capacity to maintain normal growth, productivity, and vine health despite infection by Grapevine fleck virus (GFkV), a maculavirus that is symptomless in most V.", 
    "alternative_term": "GFkV tolerance | fleck virus asymptomatic carriage | maculavirus tolerance |+ Marmorierungs-Toleranz-Disposition | GFkV-Toleranz | Fleck-Virus-Toleranz",
    "example_of_usage": "Evaluation of Fleck_Tolerance_Disposition at ENTAV-INRA Grau du Roi compared responses to GFkV across V. vinifera cultivars and Vitis rootstock genotypes following graft inoculation. ||V. vinifera cultivars (n=30) uniformly demonstrated Fleck_Tolerance_Disposition, with 100% infection rates as confirmed by RT-PCR but complete absence of symptoms and no detectable impacts on growth rate, yield, or fruit quality parameters over 5-year evaluation. ||The sensitive indicator V. rupestris 'St. ||George' developed characteristic symptoms within 60 days of graft inoculation: chlorotic flecking on third-fourth leaves expanding basipetally, translucent vein appearance, and 25% reduction in shoot elongation. ||Rootstock genotypes with V. rupestris parentage showed variable responses, with 'SO4' (V. berlandieri × V. riparia) remaining asymptomatic while 'Schwarzmann' (V. riparia × V. rupestris) exhibited mild transient flecking. ||Importantly, when GFkV-infected vines were co-infected with GLRaV-3, leafroll symptom severity increased 40% compared to GLRaV-3 single infection, demonstrating synergistic interactions that justify pursuing virus-free status even for generally tolerated pathogens. ||These findings confirm that V. vinifera cultivars inherently possess Fleck_Tolerance_Disposition but that rootstock sensitivity and mixed infection dynamics complicate management decisions.",
    "editor_note": "Fleck_Tolerance_Disposition is_a Viral_Resistance_Disposition. ||Fleck disease is unusual among grapevine viral diseases in that commercial V. vinifera cultivars are inherently tolerant, with sensitivity restricted to certain wild species (V. rupestris) and some rootstock hybrids. ||The term \"tolerance\" rather than \"resistance\" is used because V. vinifera supports viral replication without symptoms rather than restricting infection. ||GFkV has no known vector for field transmission, spreading only through propagation. ||Despite its generally benign nature, GFkV-free status is preferred for mother plant material due to potential synergistic interactions in mixed viral infections.  vinifera cultivars but causes disease in sensitive Vitis species and rootstock hybrids. ||This disposition represents tolerance to a virus that is nearly ubiquitous in grapevine germplasm worldwide, with infection rates exceeding 80% in many surveyed populations, yet causes no apparent harm in the vast majority of commercial V. vinifera cultivars. ||GFkV, a member of the family Tymoviridae, has isometric particles containing a positive-sense RNA genome and is transmitted through vegetative propagation but has no known insect vector for field spread. ||The virus induces characteristic symptoms only in sensitive indicator hosts including V. rupestris (particularly clone 'St. ||George'), where it causes chlorotic flecking, leaf distortion, and vein clearing, hence its use in biological indexing. ||The near-universal tolerance of V. vinifera to GFkV represents an unusual case where most cultivated material inherently possesses the Fleck_Tolerance_Disposition, in contrast to diseases like leafroll where tolerance is the exception. ||However, certain rootstock hybrids with V. rupestris parentage may exhibit sensitivity, and GFkV presence can exacerbate symptoms of other viral infections in mixed infections, making virus-free status still desirable for high-quality planting material even for this generally benign pathogen.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sabanadzovic S et al. (2017) Grapevine fleck virus, Grapevine Viruses: Molecular Biology, Diagnostics and Management, Springer|| Martelli GP (2017) An overview on grapevine viruses, viroids, and the diseases they cause, Grapevine Viruses: Molecular Biology, Diagnostics and Management, Springer|| Fuchs M et al. (2007) Serological and molecular characterization of Grapevine fleck virus isolates from different grapevine-growing regions, Archives of Virology 152:1191-1197"
  },
  "Bacterial_Resistance_Disposition": {
    "definition": "A Bacterial_Resistance_Disposition is a Pathogen_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes that limit infection, colonization, multiplication, or pathogenesis by bacterial pathogens affecting grapevine.", 
    "alternative_term": "bacterial disease resistance | prokaryotic pathogen resistance | bacterial infection immunity |+ Bakterienresistenz-Disposition | Bakterielle-Krankheitsresistenz | Prokaryoten-Pathogen-Resistenz",
    "example_of_usage": "Comparative evaluation of Bacterial_Resistance_Disposition at UC Davis assessed responses to both Agrobacterium vitis and Xylella fastidiosa across 30 Vitis accessions to characterize the independence of resistance mechanisms against these distinct bacterial pathogens. ||For crown gall, wound inoculation with tumorigenic A. vitis strain K306 resulted in gall formation on 100% of V. vinifera cultivars tested, with gall volumes of 8-25 cm³ at 12 weeks. ||Wild species V. amurensis and V. riparia showed similarly high susceptibility, indicating no differential Bacterial_Resistance_Disposition against Agrobacterium across tested germplasm. ||In contrast, Pierce's disease challenge through mechanical inoculation of X. fastidiosa strain Temecula1 revealed dramatic variation in Bacterial_Resistance_Disposition. ||V. vinifera 'Chardonnay' developed severe symptoms with bacterial titers of 10⁸ CFU/g petiole and 100% mortality by 16 weeks. ||V. arizonica b43-17 showed strong resistance with titers below detection limits and no symptoms. ||Critically, crown gall susceptible V. arizonica exhibited Pierce's disease resistance, while Pierce's disease susceptible V. vinifera showed equivalent crown gall susceptibility, demonstrating that Bacterial_Resistance_Disposition is pathogen-specific rather than reflecting general antibacterial capacity.",
    "editor_note": "Bacterial_Resistance_Disposition is_a Pathogen_Resistance_Disposition. ||This class encompasses resistance to all bacterial pathogens of grapevine, parallel to Fungal_Resistance_Disposition and Viral_Resistance_Disposition. ||Child classes include Crown_Gall_Resistance_Disposition (Agrobacterium) and Pierces_Disease_Resistance_Disposition (Xylella fastidiosa). ||Resistance mechanisms differ fundamentally between these pathogens due to their distinct infection biology: wound-mediated transformation for Agrobacterium versus insect-vectored xylem colonization for Xylella. ||No resistance to bacterial blight (Xanthomonas ampelina) is currently modeled in VVO due to limited breeding relevance.  This disposition represents the capacity to resist the relatively limited but economically significant bacterial diseases of grapevine, which differ fundamentally from fungal and viral pathogens in their biology, infection mechanisms, and host-pathogen interactions. ||Major bacterial pathogens of grapevine include Agrobacterium vitis (syn. ||Allorhizobium vitis) causing crown gall, Xylella fastidiosa causing Pierce's disease and related leaf scorch syndromes, and Xanthomonas ampelina causing bacterial blight. ||Bacterial resistance mechanisms in plants encompass recognition of pathogen-associated molecular patterns (PAMPs) such as flagellin and lipopolysaccharides triggering PAMP-triggered immunity (PTI), effector-triggered immunity (ETI) mediated by resistance proteins recognizing bacterial type III secretion effectors, physical barriers preventing bacterial entry or spread, antimicrobial compound production, and restriction of bacterial multiplication in host tissues. ||For grapevine specifically, bacterial resistance dispositions vary dramatically by pathogen system, with no effective resistance available against crown gall in V. vinifera, while strong resistance to Pierce's disease exists in wild North American Vitis species that co-evolved with X. fastidiosa. ||The distinct epidemiology and tissue tropism of bacterial pathogens (wound-mediated infection for Agrobacterium, xylem-limited colonization for Xylella, foliar infection for Xanthomonas) require different resistance mechanisms, making bacterial resistance a heterogeneous category encompassing diverse host defense strategies.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Burr TJ, Otten L (1999) Crown gall of grape: biology and disease management, Annual Review of Phytopathology 37:53-80|| Hopkins DL, Purcell AH (2002) Xylella fastidiosa: cause of Pierce's disease of grapevine and other emergent diseases, Plant Disease 86:1056-1066|| Jones JDG, Dangl JL (2006) The plant immune system, Nature 444:323-329"
  },
  "Crown_Gall_Resistance_Disposition": {
    "definition": "A Crown_Gall_Resistance_Disposition is a Bacterial_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, transformation, or tumor development following exposure to Agrobacterium vitis (syn.", 
    "alternative_term": "Agrobacterium resistance disposition | gall formation resistance | crown gall tolerance |+ Mauke-Resistenz-Disposition | Agrobakterien-Resistenz | Wurzelhalsgallen-Resistenz",
    "example_of_usage": "Systematic screening for Crown_Gall_Resistance_Disposition at Cornell University evaluated 120 Vitis accessions using standardized wound inoculation with tumorigenic Agrobacterium vitis strain CG49 on greenhouse-grown potted vines. ||Wounded stems were inoculated with bacterial suspension (10⁸ CFU/mL), and gall development was scored at 6, 12, and 20 weeks post-inoculation using a 0-5 scale based on gall size and coverage of the wound site. ||V. vinifera cultivars showed uniformly high susceptibility with mean scores of 4.2-4.8 across 40 tested cultivars. ||Wild species V. riparia (score 3.8), V. rupestris (4.1), and V. amurensis (4.5) showed equivalent susceptibility. ||Interspecific rootstock hybrids ranged from 3.5 to 4.6 with no commercially relevant resistance identified. ||The only accessions showing potentially useful Crown_Gall_Resistance_Disposition were certain V. labrusca × V. vinifera hybrids ('Niagara', score 2.1|| 'Catawba', score 2.4), though these remain susceptible and are unsuitable as wine grapes due to labrusca flavor characteristics. ||These findings confirm that breeding for crown gall resistance faces severe germplasm limitations, with no immunity and only moderate tolerance available in non-vinifera backgrounds with quality compromises.",
    "editor_note": "Crown_Gall_Resistance_Disposition is_a Bacterial_Resistance_Disposition. ||Crown gall is caused by Agrobacterium vitis (grapevine-specific) rather than the broad-host-range A. tumefaciens. ||Child classes include Agrobacterium_Transformation_Resistance_Disposition (resistance to T-DNA transfer/integration) and Wound_Healing_Efficiency_Disposition (rapid wound closure preventing infection). ||The absence of effective resistance in V. vinifera and most breeding-relevant germplasm distinguishes crown gall from Pierce's disease where strong resistance sources exist. ||Cold climate viticulture faces greatest crown gall pressure due to winter injury creating infection sites.  Allorhizobium vitis), the tumorigenic bacterium causing crown gall disease of grapevine. ||This disposition represents the capacity to resist the transformation of plant cells by bacterial T-DNA and/or the subsequent proliferation of transformed cells into characteristic galls at wound sites on trunks, cordons, and graft unions. ||Crown gall disease develops when wounded plant tissues are colonized by tumorigenic Agrobacterium strains carrying Ti (tumor-inducing) plasmids. ||The bacteria transfer T-DNA into plant cell nuclei, where it integrates into chromosomes and directs synthesis of auxins and cytokinins that cause uncontrolled cell proliferation (tumor formation) and opines that provide nutrients for bacterial growth. ||Crown gall resistance mechanisms potentially include interference with bacterial attachment to wound surfaces, inhibition of T-DNA transfer across plant cell membranes, prevention of T-DNA nuclear import or chromosomal integration, resistance to hormone-mediated transformation, and active elimination of transformed cells. ||Despite extensive screening, no commercially useful level of crown gall resistance has been identified in V. vinifera or most Vitis species. ||Crown gall is particularly damaging in cold climate viticulture where winter injury creates wound sites susceptible to infection, and in nurseries where grafting wounds provide entry points. ||Management relies primarily on prevention through use of non-infested planting material and protection of wound sites rather than genetic resistance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Burr TJ, Otten L (1999) Crown gall of grape: biology and disease management, Annual Review of Phytopathology 37:53-80|| Szegedi E, Civerolo EL (2011) Bacterial diseases of grapevine, International Journal of Horticultural Science 17:45-49|| Pulawska J (2010) Crown gall of stone fruits and nuts, economic significance and diversity of its causal agents: tumorigenic Agrobacterium spp., Journal of Plant Pathology 92:S1.87-S1.98"
  },
  "Agrobacterium_Transformation_Resistance_Disposition": {
    "definition": "An Agrobacterium_Transformation_Resistance_Disposition is a Crown_Gall_Resistance_Disposition that inheres in a Vitis plant and is realized through cellular mechanisms that specifically interfere with Agrobacterium-mediated genetic transformation, preventing T-DNA transfer from the bacterial Ti plasmid into plant cell nuclei or blocking T-DNA integration into plant chromosomal DNA.", 
    "alternative_term": "T-DNA transfer resistance | transformation immunity | Agrobacterium recalcitrance |+ Agrobakterien-Transformations-Resistenz-Disposition | T-DNA-Transfer-Resistenz | Transformations-Immunität",
    "example_of_usage": "Investigation of Agrobacterium_Transformation_Resistance_Disposition in Vitis was conducted indirectly through transgenic transformation efficiency studies at INRA Colmar, which revealed significant genotypic variation potentially reflecting natural resistance mechanisms. ||Embryogenic callus cultures from 15 cultivars were co-cultivated with A. tumefaciens strain EHA105 carrying a GUS reporter construct under standardized conditions (48h co-cultivation, 100 μM acetosyringone). ||Transformation efficiency, measured as GUS-positive regenerants per gram callus, varied 12-fold among cultivars. 'Chardonnay' showed high transformability (45 transformants/g), while '41B' rootstock showed very low efficiency (3.8 transformants/g) despite equivalent callus quality and regeneration capacity. ||Molecular analysis revealed that '41B' exhibited 70% lower transient GUS expression at 5 days post-co-cultivation, suggesting resistance at the T-DNA transfer or early expression stage rather than regeneration. ||Unfortunately, this apparent Agrobacterium_Transformation_Resistance_Disposition in '41B' did not correlate with crown gall resistance in planta, with '41B' developing equivalent galls to highly transformable 'Chardonnay' following A. vitis wound inoculation. ||This disconnect indicates that in vitro transformation resistance may involve different mechanisms than whole-plant crown gall resistance, or that tumorigenic A. vitis strains overcome barriers that limit laboratory A. tumefaciens strains.",
    "editor_note": "Agrobacterium_Transformation_Resistance_Disposition is_a Crown_Gall_Resistance_Disposition. ||This class represents molecular-level resistance to T-DNA transfer and integration, distinct from Wound_Healing_Efficiency_Disposition which operates at the tissue level. ||Natural transformation resistance has not been conclusively demonstrated to provide crown gall protection in Vitis, though genotypic variation in transformation efficiency suggests underlying resistance factors. ||Research into transformation resistance is complicated by the use of different Agrobacterium species/strains in biotechnology (typically A. tumefaciens) versus natural crown gall disease (A. vitis). ||Transformation resistance would also impede beneficial transgenic applications.  This disposition represents the molecular level of crown gall resistance operating after bacterial colonization of wound sites has occurred, targeting the unique biological process by which Agrobacterium reprograms host cells. ||The T-DNA transfer process involves bacterial attachment to plant cells, induction of virulence genes by wound-released phenolic compounds, processing and export of T-DNA through a type IV secretion system, T-DNA transit across plant cell membranes and cytoplasm, nuclear import, and chromosomal integration. ||Potential resistance mechanisms disrupting this cascade include modification of VirA/VirG two-component sensing to prevent virulence gene induction, interference with bacterial attachment or secretion system function, degradation of T-DNA or associated proteins in the cytoplasm, blockage of nuclear import machinery recognition of VirD2/VirE2 nuclear localization signals, and inhibition of T-DNA integration by host DNA repair or chromatin factors. ||While natural Agrobacterium_Transformation_Resistance_Disposition has not been clearly demonstrated in Vitis, variation in transformation efficiency among genotypes during transgenic research suggests that such resistance may exist at low levels. ||Paradoxically, the same mechanisms that might confer crown gall resistance would also impede beneficial transgenic applications in grapevine improvement.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gelvin SB (2003) Agrobacterium-mediated plant transformation: the biology behind the \"gene-jockeying\" tool, Microbiology and Molecular Biology Reviews 67:16-37|| Ziemienowicz A (2014) Agrobacterium-mediated plant transformation: factors, applications and recent advances, Biocatalysis and Agricultural Biotechnology 3:95-102|| Pitzschke A, Hirt H (2010) New insights into an old story: Agrobacterium-induced tumour formation in plants by plant transformation, EMBO Journal 29:1021-1032"
  },
  "Wound_Healing_Efficiency_Disposition": {
    "definition": "A Wound_Healing_Efficiency_Disposition is a Crown_Gall_Resistance_Disposition that inheres in a Vitis plant and is realized through rapid and effective wound closure processes that minimize the temporal window for Agrobacterium colonization of susceptible wound tissues and reduce the availability of wound-released phenolic compounds that induce bacterial virulence genes.", 
    "alternative_term": "wound closure efficiency | rapid wound healing | wound sealing capacity |+ Wundheilungs-Effizienz-Disposition | Schnelle-Wundschließung | Wundversiegelungs-Kapazität",
    "example_of_usage": "Evaluation of Wound_Healing_Efficiency_Disposition at the University of Minnesota compared wound closure dynamics among 10 cultivars and rootstocks with varying crown gall susceptibility under controlled conditions. ||Standardized wounds (5mm diameter, 3mm depth) were created on green shoots, and healing progression was monitored by measuring wound exudate volume, callus coverage percentage, and periderm formation at 3, 7, 14, and 21 days post-wounding. ||The cold-hardy hybrid 'Marquette' exhibited superior Wound_Healing_Efficiency_Disposition with 50% callus coverage by day 7 (versus 20% in 'Chardonnay'), complete wound sealing by day 14 (versus day 28 in 'Chardonnay'), and 65% lower cumulative wound exudate volume. ||When parallel wounds were inoculated with Agrobacterium vitis at 0, 3, 7, or 14 days post-wounding, 'Marquette' showed significantly reduced gall formation on wounds inoculated at 7 days (35% incidence versus 90% in 'Chardonnay') and no galls on wounds inoculated at 14 days (versus 45% in 'Chardonnay'), demonstrating that rapid wound healing effectively shortens the infection window. ||However, immediate post-wounding inoculation (day 0) resulted in equivalent gall formation (95%) across all genotypes, confirming that Wound_Healing_Efficiency_Disposition operates by reducing infection opportunity rather than through direct antibacterial mechanisms.",
    "editor_note": "Wound_Healing_Efficiency_Disposition is_a Crown_Gall_Resistance_Disposition. ||This class represents tissue-level wound response affecting infection opportunity, distinct from Agrobacterium_Transformation_Resistance_Disposition which operates at the cellular/molecular level. ||Rapid wound healing provides broad protection against wound-invading pathogens including both Agrobacterium and trunk disease fungi, making this a potentially valuable multi-purpose resistance trait. ||Cold-hardy cultivars bred for winter survival may have been indirectly selected for enhanced wound healing due to recurrent winter injury pressure. ||The disposition operates by shortening the infection window rather than eliminating susceptibility.  This disposition represents a tissue-level resistance mechanism operating before bacterial transformation occurs, based on the principle that Agrobacterium requires access to actively dividing cells at fresh wound surfaces and that wound-released signals trigger bacterial attachment and T-DNA transfer. ||Effective wound healing involves rapid formation of wound periderm sealing the exposed surface, deposition of suberin and lignin in wound-adjacent cell walls, callus proliferation covering and protecting the wound, and reduced exudation of phenolic compounds (acetosyringone and related molecules) that activate Agrobacterium vir genes. ||Genotypes with enhanced Wound_Healing_Efficiency_Disposition would be expected to show faster wound closure, reduced wound exudate accumulation, and consequently shorter infection windows and lower transformation success rates. ||This resistance mechanism is particularly relevant for crown gall management during nursery propagation (graft union protection), mechanical harvesting (trunk wound protection), and winter injury recovery in cold climates. ||While variation in wound healing among grapevine genotypes has been observed, its specific contribution to crown gall resistance versus other wound-associated pathogens (trunk disease fungi) requires further research.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Stover EW et al. (1997) Crown gall in grape: biology and control, Viticulture and Enology Research Center, Fresno State University|| Pierron RJG et al. (2016) Cork formation and anatomical responses of grapevine xylem to Phaeomoniella chlamydospora infection, FEMS Microbiology Letters 363:fnw025|| Burr TJ, Otten L (1999) Crown gall of grape: biology and disease management, Annual Review of Phytopathology 37:53-80"
  },
  "Pierces_Disease_Resistance_Disposition": {
    "definition": "A Pierces_Disease_Resistance_Disposition is a Bacterial_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, multiplication, systemic spread, or symptom development following inoculation with Xylella fastidiosa subsp.", 
    "alternative_term": "Xylella resistance disposition | PD resistance | sharpshooter-transmitted disease resistance |+ Pierce-Krankheit-Resistenz-Disposition | Xylella-fastidiosa-Resistenz | Pierce-Resistenz",
    "example_of_usage": "Long-term field evaluation of Pierces_Disease_Resistance_Disposition at the UC Davis Oakville experimental vineyard compared disease development across resistant breeding selections and susceptible controls under natural glassy-winged sharpshooter (Homalodisca vitripennis) transmission pressure. ||Over 10 years, susceptible V. vinifera 'Chardonnay' experienced 92% mortality with survivors showing severe chronic symptoms, bacterial titers of 10⁷-10⁸ CFU/g petiole, and near-zero productivity. ||The PdR1-carrying breeding selection 94-27-008 (V. arizonica × 'Chardonnay' BC₁) demonstrated strong Pierces_Disease_Resistance_Disposition with 0% mortality, no visible symptoms, bacterial titers below 10⁴ CFU/g (often below detection), and yields equivalent to disease-free controls (8.2 tonnes/ha). ||The resistant selection 'U0505-01' exhibited intermediate response with occasional mild leaf scorch, titers of 10⁴-10⁵ CFU/g, but maintained commercially viable productivity (6.8 tonnes/ha). ||Importantly, even asymptomatic resistant selections tested positive for X. fastidiosa by PCR in 15-30% of samples, indicating that Pierces_Disease_Resistance_Disposition operates primarily through limitation of bacterial multiplication and spread rather than complete immunity to infection. ||This resistance mechanism enables sustainable viticulture in Pierce's disease-endemic regions of California, Texas, and the southeastern United States where susceptible V. vinifera cultivation is otherwise impossible.",
    "editor_note": "Pierces_Disease_Resistance_Disposition is_a Bacterial_Resistance_Disposition. ||Pierce's disease is caused by Xylella fastidiosa subsp. fastidiosa, a xylem-limited bacterium transmitted by sharpshooter leafhoppers. ||Child classes include PdR1_Mediated_Resistance_Disposition (major gene resistance), Xylella_Multiplication_Resistance_Disposition (limiting bacterial population), and Xylem_Occlusion_Tolerance_Disposition (maintaining hydraulic function despite infection). ||Strong resistance exists in native North American Vitis species co-evolved with X. fastidiosa, in marked contrast to crown gall where no effective resistance has been identified. ||The disease limits V. vinifera cultivation throughout the southeastern United States and increasingly in California.  fastidiosa, the xylem-limited bacterium causing Pierce's disease of grapevine. ||This disposition represents the capacity to resist one of the most devastating bacterial diseases of grapevine, endemic to the Americas where X. fastidiosa co-evolved with native Vitis species and is transmitted by xylem-feeding sharpshooter leafhoppers (Cicadellidae: Cicadellini) and spittlebugs (Cercopidae). ||Pierce's disease causes progressive vine decline characterized by irregular leaf scorch beginning at margins, \"matchstick\" petioles with abscised leaf blades, irregular cane maturation with green islands surrounded by mature bark, and vine death typically within 1-5 years of infection in susceptible V. vinifera cultivars. ||The disease mechanism involves bacterial multiplication in xylem vessels, biofilm formation, and progressive vessel occlusion blocking water transport, with symptom severity correlating with bacterial population levels. ||Pierce's disease resistance dispositions in Vitis operate through multiple mechanisms including restriction of bacterial multiplication, limitation of systemic spread through xylem, tolerance to vessel occlusion maintaining hydraulic function, and potentially vector-mediated resistance affecting transmission efficiency. ||Wild North American Vitis species native to regions with endemic X. fastidiosa exhibit strong resistance, with V. arizonica, V. aestivalis, V. shuttleworthii, and V. smalliana providing sources for resistance breeding. ||The PdR1 locus from V. arizonica represents the most advanced breeding achievement, enabling development of Pierce's disease resistant wine grape cultivars.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hopkins DL, Purcell AH (2002) Xylella fastidiosa: cause of Pierce's disease of grapevine and other emergent diseases, Plant Disease 86:1056-1066|| Krivanek AF et al. (2006) Resistance to Xylella fastidiosa in North American Vitis species, Plant Disease 90:1503-1508|| Walker MA, Tenscher A (2017) Breeding Pierce's disease resistant winegrapes, Acta Horticulturae 1157:191-196"
  },
  "PdR1_Mediated_Resistance_Disposition": {
    "definition": "A PdR1_Mediated_Resistance_Disposition is a Pierces_Disease_Resistance_Disposition that inheres in a Vitis plant carrying the PdR1 (Pierce's disease Resistance 1) locus derived from Vitis arizonica and is realized through major gene-mediated defense responses that strongly limit Xylella fastidiosa multiplication and systemic spread in xylem tissues.", 
    "alternative_term": "PdR1 Pierce's disease resistance | V. arizonica-derived PD resistance | major gene Xylella resistance |+ PdR1-vermittelte Resistenz-Disposition | PdR1-Pierce-Resistenz | V.-arizonica-Resistenz",
    "example_of_usage": "Marker-assisted breeding for PdR1_Mediated_Resistance_Disposition at UC Davis has produced advanced wine grape selections through systematic backcrossing of V. arizonica b43-17 resistance into V. vinifera backgrounds. ||The breeding strategy involved initial F1 crosses to 'Chardonnay' and 'Cabernet Sauvignon', followed by four generations of backcrossing to elite V. vinifera cultivars with PdR1 selection at each generation using flanking SSR markers. ||The resulting BC₄ selections contain approximately 97% V. vinifera genetic background while retaining the PdR1 resistance locus. ||Phenotypic validation through greenhouse needle inoculation with X. fastidiosa strain Temecula1 (10⁸ CFU/mL) demonstrated that PdR1-positive selections maintained bacterial populations of 10²-10⁴ CFU/g petiole at 12 weeks post-inoculation, compared to 10⁷-10⁸ CFU/g in PdR1-negative siblings and susceptible 'Chardonnay' controls. ||Symptom expression in PdR1-positive plants ranged from none to minimal marginal necrosis, while susceptible controls exhibited severe leaf scorch with 80-100% defoliation. ||The released cultivar 'Camminare Noir' (PdR1/pdr1 heterozygous, 97% V. vinifera) has demonstrated stable field resistance in Temecula, California trials over 8 years, producing commercially acceptable red wines described as having \"Pinot Noir-like characteristics\" in sensory evaluations, validating that PdR1_Mediated_Resistance_Disposition can be combined with high wine quality.",
    "editor_note": "PdR1_Mediated_Resistance_Disposition is_a Pierces_Disease_Resistance_Disposition. ||PdR1 from V. arizonica b43-17 represents the most advanced and validated Pierce's disease resistance locus, located on chromosome 14 in an NLR gene cluster. ||The resistance is dominant, enabling heterozygous deployment in commercial cultivars. ||Marker-assisted selection has been critical for efficient introgression through multiple backcross generations. ||Additional PD resistance loci have been mapped in other Vitis species (PdR2, PdR3), providing opportunities for future gene pyramiding to enhance durability. ||The UC Davis PdR1 breeding program represents a model for grapevine disease resistance deployment.  The PdR1 locus maps to chromosome 14 and was identified in the V. arizonica accession b43-17 collected from canyons near Monterrey, Mexico, representing a co-evolved resistance from a region with endemic X. fastidiosa pressure. ||PdR1 confers dominant resistance characterized by dramatic restriction of bacterial populations, with resistant genotypes maintaining titers 1,000-10,000 fold lower than susceptible V. vinifera under equivalent inoculum pressure. ||The PdR1 resistance mechanism appears to involve rapid host recognition of X. fastidiosa followed by local defense responses that limit bacterial multiplication and prevent systemic colonization of the vine. ||Fine mapping has resolved PdR1 to a cluster of putative nucleotide-binding leucine-rich repeat (NLR) genes, suggesting effector-triggered immunity analogous to resistance mechanisms against other pathogens. ||Marker-assisted selection using tightly linked molecular markers (VVIP26, VVIN64) enables efficient introgression of PdR1 into V. vinifera backgrounds through backcrossing. ||The UC Davis breeding program has successfully developed PdR1-carrying wine grape cultivars including 'Camminare Noir', 'Paseante Noir', and 'Errante Noir' that combine Pierce's disease resistance with acceptable wine quality, representing a major achievement in grapevine disease resistance breeding.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Krivanek AF et al. (2005) Vitis resistance to Pierce's disease is characterized by differential Xylella fastidiosa populations in stems and leaves, Phytopathology 95:44-52|| Riaz S et al. (2008) Genetic and physical mapping of the Pierce's disease resistance locus PdR1, Theoretical and Applied Genetics 117:1067-1078|| Walker MA, Tenscher A (2017) Breeding Pierce's disease resistant winegrapes, Acta Horticulturae 1157:191-196"
  },
  "Xylella_Multiplication_Resistance_Disposition": {
    "definition": "A Xylella_Multiplication_Resistance_Disposition is a Pierces_Disease_Resistance_Disposition that inheres in a Vitis plant and is realized through host factors that specifically limit Xylella fastidiosa population growth within xylem vessels, resulting in bacterial titers orders of magnitude below those achieved in susceptible genotypes under equivalent inoculation conditions.", 
    "alternative_term": "Xylella population limitation | bacterial titer restriction | multiplication rate resistance |+ Xylella-Vermehrungs-Resistenz-Disposition | Bakterien-Titer-Beschränkung | Xylella-Populationskontrolle",
    "example_of_usage": "Quantitative characterization of Xylella_Multiplication_Resistance_Disposition at the USDA-ARS San Joaquin Valley Agricultural Sciences Center employed time-course bacterial population measurements following standardized needle inoculation with X. fastidiosa strain Temecula1 (10⁴ CFU delivered per inoculation point). ||Petiole samples were collected at 4, 8, 12, and 16 weeks post-inoculation from susceptible 'Chardonnay', resistant V. arizonica b43-17, and 20 interspecific breeding selections. 'Chardonnay' exhibited rapid bacterial multiplication with populations increasing from initial inoculum to 10⁵ CFU/g by week 4, 10⁷ CFU/g by week 8, and plateau at 10⁸ CFU/g by week 12, accompanied by progressive symptom development. ||V. arizonica b43-17 demonstrated exceptional Xylella_Multiplication_Resistance_Disposition with populations remaining below 10³ CFU/g through week 16, representing 100,000-fold suppression relative to 'Chardonnay'. ||Breeding selections showed continuous variation in multiplication resistance, with PdR1-positive selections maintaining populations of 10³-10⁵ CFU/g while PdR1-negative selections reached 10⁶-10⁸ CFU/g. ||Critically, a symptom severity threshold was identified at approximately 10⁶ CFU/g, below which vines remained asymptomatic regardless of genotype, demonstrating that Xylella_Multiplication_Resistance_Disposition sufficient to maintain subthreshold populations provides functional disease resistance.",
    "editor_note": "Xylella_Multiplication_Resistance_Disposition is_a Pierces_Disease_Resistance_Disposition. ||This class represents the quantitative phenotype of limiting bacterial populations, which can be conferred by major genes (PdR1) or potentially by accumulation of minor factors. ||Multiplication resistance is distinct from tolerance (Xylem_Occlusion_Tolerance_Disposition), which enables productivity maintenance despite higher bacterial populations. ||The 10⁶ CFU/g symptom threshold provides a practical resistance target for breeding programs. ||Multiplication resistance is measured by culture plating (CFU/g) or qPCR (genome copies/g), with strong correlation between methods.  This disposition represents the quantitative aspect of Pierce's disease resistance most directly correlated with disease outcomes, as symptom severity and vine mortality are strongly associated with bacterial population levels in planta. ||Mechanisms contributing to Xylella multiplication resistance may include unfavorable xylem sap composition (pH, ion concentrations, organic nutrient availability) limiting bacterial growth, antimicrobial compounds present in xylem fluid or vessel walls, rapid host recognition triggering localized defense responses, and restriction of bacterial spread between vessels limiting systemic colonization. ||The distinction between multiplication resistance and systemic spread resistance is experimentally important, as some host genotypes may allow local bacterial growth but prevent systemic colonization, while others may permit slow spread but maintain low populations throughout. ||Xylella_Multiplication_Resistance_Disposition is the primary measurable phenotype in Pierce's disease resistance screening programs, assessed through quantitative culture plating or qPCR of petiole or stem tissues at standardized times post-inoculation. ||Strong multiplication resistance is characteristic of PdR1-mediated resistance, but quantitative variation in multiplication rates exists even among genotypes lacking major resistance genes, providing potential for accumulating minor factors through breeding.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Krivanek AF, Walker MA (2005) Vitis resistance to Pierce's disease is characterized by differential Xylella fastidiosa populations in stems and leaves, Phytopathology 95:44-52|| Roper MC et al. (2007) Xylella fastidiosa requires polygalacturonase for colonization and pathogenicity in Vitis vinifera grapevines, Molecular Plant-Microbe Interactions 20:411-419|| Lindow S (2019) Secrets of success: biological control of Pierce's disease by Paraburkholderia phytofirmans and Xylella fastidiosa, Phytopathology 109:5"
  },
  "Xylem_Occlusion_Tolerance_Disposition": {
    "definition": "A Xylem_Occlusion_Tolerance_Disposition is a Pierces_Disease_Resistance_Disposition that inheres in a Vitis plant and is realized through the capacity to maintain adequate hydraulic conductivity and water transport despite partial occlusion of xylem vessels by Xylella fastidiosa biofilms, bacterial aggregates, and host-produced tyloses, thereby minimizing water stress symptoms and productivity losses even when bacterial infection is established.", 
    "alternative_term": "hydraulic dysfunction tolerance | vessel occlusion tolerance | vascular blockage tolerance |+ Xylem-Okklusions-Toleranz-Disposition | Hydraulik-Dysfunktion-Toleranz | Gefäßblockade-Toleranz",
    "example_of_usage": "Investigation of Xylem_Occlusion_Tolerance_Disposition at Texas A&M University compared hydraulic responses to X. fastidiosa infection across 6 cultivars with varying disease phenotypes. ||Vines were mechanically inoculated and assessed at 16 weeks post-inoculation for bacterial population (qPCR), percent loss of hydraulic conductivity (PLC) measured by flow meter, and whole-vine transpiration in controlled environment chambers. ||Susceptible 'Chardonnay' (bacterial titer 10⁸ CFU/g) exhibited 78% PLC and transpiration reduced to 25% of healthy controls, with severe leaf scorch on all leaves. ||The interspecific hybrid 'Blanc du Bois' showed equivalent bacterial titer (10⁸ CFU/g) but demonstrated enhanced Xylem_Occlusion_Tolerance_Disposition with only 52% PLC and transpiration maintained at 55% of controls, with scorch limited to older leaves. ||Anatomical examination revealed that 'Blanc du Bois' possessed 40% higher native vessel density (185 vs 132 vessels/mm²) and smaller mean vessel diameter (38 vs 52 μm), providing greater hydraulic redundancy. ||When both cultivars were subjected to equivalent artificial flow restriction (mimicking 60% PLC), 'Blanc du Bois' maintained 70% of control transpiration versus 40% in 'Chardonnay', confirming intrinsic tolerance differences independent of bacterial effects. ||These findings suggest that Xylem_Occlusion_Tolerance_Disposition provides an additional resistance strategy complementing direct antibacterial mechanisms.",
    "editor_note": "Xylem_Occlusion_Tolerance_Disposition is_a Pierces_Disease_Resistance_Disposition. ||This class represents tolerance to vascular dysfunction rather than resistance to bacterial infection, providing a complementary strategy to Xylella_Multiplication_Resistance_Disposition. ||Occlusion tolerance may enable functional viticulture even where infection cannot be completely prevented. ||The disposition overlaps conceptually with general drought tolerance, as both involve maintaining hydraulic function under water stress. ||Tylosis formation, while contributing to bacterial containment, paradoxically exacerbates occlusion|| thus, optimal defense may involve balanced tylosis response sufficient to limit spread without catastrophic conductivity loss.  This disposition represents a tolerance mechanism distinct from resistance mechanisms that limit bacterial multiplication or spread, enabling functional compensation for partial vascular blockage. ||Pierce's disease symptoms including leaf scorch, premature defoliation, and vine decline result substantially from hydraulic failure as progressive vessel occlusion reduces water transport capacity below levels required to meet transpirational demand. ||Xylem_Occlusion_Tolerance_Disposition may involve anatomical features including high native vessel density providing hydraulic redundancy, smaller vessel diameters reducing individual vessel contribution to total conductivity, efficient inter-vessel connectivity enabling bypass of occluded elements, and enhanced root hydraulic conductance compensating for reduced stem conductivity. ||Additionally, tolerance may involve physiological adjustments including osmotic adjustment maintaining cell turgor at reduced water potentials, stomatal regulation balancing transpiration with reduced supply, and modified growth allocation prioritizing hydraulic function. ||The distinction between multiplication resistance and occlusion tolerance is experimentally important, as some cultivars maintain productivity despite substantial infection (tolerance), while others decline rapidly once infection thresholds are exceeded (low tolerance). ||Breeding for occlusion tolerance could complement multiplication resistance strategies, particularly for conditions where resistance is incomplete.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "McElrone AJ et al. (2003) Variation in xylem structure and function in stems and roots of trees to 20 m of depth, New Phytologist 163:507-517|| Sun Q et al. (2013) Xylem occlusion in grapevine to limit the systemic spread of Pierce's disease, American Journal of Enology and Viticulture 64:153-159|| Choat B et al. (2010) Vascular function in grape berries across development and its relevance to apparent hydraulic isolation, Plant Physiology 154:1546-1555"
  },
  "Phytoplasma_Resistance_Disposition": {
    "definition": "A Phytoplasma_Resistance_Disposition is a Pathogen_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes that limit infection, multiplication, systemic spread, or symptom expression by phytoplasmas, wall-less prokaryotes of the class Mollicutes that cause grapevine yellows diseases.", 
    "alternative_term": "grapevine yellows resistance | Mollicute resistance | phytoplasma tolerance |+ Phytoplasmen-Resistenz-Disposition | Vergilbungskrankheit-Resistenz | Mollicuten-Resistenz",
    "example_of_usage": "Comparative evaluation of Phytoplasma_Resistance_Disposition at the University of Udine, Italy, monitored Flavescence dorée and Bois noir incidence and symptom expression across 25 cultivars in a naturally infected vineyard over 8 seasons. ||Infection status was confirmed annually by nested PCR targeting phytoplasma 16S rRNA genes, while symptom severity was scored using a 0-5 scale. ||Substantial cultivar variation in Phytoplasma_Resistance_Disposition was observed for both diseases. ||For Flavescence dorée, 'Chardonnay' showed high susceptibility with 45% cumulative infection, severe symptoms (mean score 4.2), and 15% vine mortality. 'Merlot' demonstrated enhanced tolerance with equivalent infection rate (42%) but markedly reduced symptom severity (score 2.1) and spontaneous recovery in 35% of infected vines. ||For Bois noir, 'Sangiovese' exhibited extreme susceptibility (55% infection, score 4.5, 22% mortality) while 'Cabernet Sauvignon' showed relative tolerance (38% infection, score 1.8, 5% mortality). ||Critically, cultivar rankings differed between diseases, with 'Merlot' tolerant to FD but susceptible to BN (score 3.8), indicating that Phytoplasma_Resistance_Disposition involves pathogen-specific components rather than general anti-phytoplasma mechanisms. ||No cultivar showed immunity to either phytoplasma.",
    "editor_note": "Phytoplasma_Resistance_Disposition is_a Pathogen_Resistance_Disposition. ||Phytoplasmas occupy a unique position as prokaryotes (bacteria-like) that are obligate intracellular parasites with characteristics (wall-less, phloem-limited, insect-transmitted) distinct from both bacteria and viruses. ||Child classes include Flavescence_Doree_Resistance_Disposition and Bois_Noir_Resistance_Disposition for the two major grapevine yellows diseases in Europe. ||The distinction between \"resistance\" (limiting infection/multiplication) and \"tolerance\" (limiting symptoms despite infection) and \"recovery\" (symptom remission with pathogen persistence) is particularly important for phytoplasma diseases where true resistance is rare.  This disposition represents the capacity to resist a unique class of pathogens that are obligate parasites of plant phloem tissues and insect vectors, unculturable in artificial media, and transmitted by phloem-feeding leafhoppers in a persistent-propagative manner. ||Major grapevine yellows diseases include Flavescence dorée (FD) caused by 'Candidatus Phytoplasma vitis' and Bois noir (BN) caused by 'Candidatus Phytoplasma solani', which produce similar symptoms including leaf rolling and discoloration (yellowing in white cultivars, reddening in red cultivars), incomplete lignification of canes, shriveled berries, and progressive vine decline. ||Phytoplasma resistance mechanisms in plants potentially include interference with phytoplasma multiplication in phloem sieve elements, limitation of systemic spread through the sieve tube network, tolerance to phytoplasma-induced phloem dysfunction, and resistance to leafhopper vector feeding preventing pathogen acquisition or inoculation. ||True resistance to phytoplasmas is poorly characterized in Vitis, though substantial variation in symptom expression and recovery capacity exists among cultivars. ||Vector resistance represents an important complementary strategy, as interrupting the phytoplasma-vector relationship can effectively reduce disease incidence even in phytoplasma-susceptible cultivars. ||Phytoplasma diseases have emerged as major threats to European viticulture, with Flavescence dorée subject to mandatory control measures in EU member states due to its epidemic potential.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bertaccini A et al. (2014) Phytoplasmas and phytoplasma diseases: a severe threat to agriculture, American Journal of Plant Sciences 5:1763-1788|| Constable FE (2010) Phytoplasma epidemiology: grapevines as a model, Phytoplasmas: Genomes, Plant Hosts and Vectors, CAB International|| Romanazzi G, Murolo S (2008) Grapevine yellows in Italy: past, present, and future, Journal of Plant Pathology 90:S2.303"
  },
  "Flavescence_Doree_Resistance_Disposition": {
    "definition": "A Flavescence_Doree_Resistance_Disposition is a Phytoplasma_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, multiplication, systemic spread, symptom development, or vector transmission of 'Candidatus Phytoplasma vitis', the causal agent of Flavescence dorée (FD), the most severe and regulated grapevine yellows disease in Europe.", 
    "alternative_term": "FD resistance disposition | Candidatus Phytoplasma vitis resistance | golden flavescence resistance |+ Goldgelbe-Vergilbung-Resistenz-Disposition | Flavescence-dorée-Resistenz | FD-Resistenz",
    "example_of_usage": "Systematic screening for Flavescence_Doree_Resistance_Disposition at INRAE Bordeaux evaluated FD responses across 120 V. vinifera cultivars and 30 interspecific genotypes using controlled transmission via infectious Scaphoideus titanus collected from FD-infected vineyards. ||Test plants were exposed to viruliferous leafhoppers (5 per plant) for a 3-week acquisition access period, then maintained in insect-proof conditions for 24 months with periodic PCR testing and symptom assessment. ||Among V. vinifera cultivars, infection rates ranged from 35% ('Cabernet Sauvignon') to 95% ('Baco Blanc'), with symptom severity scores of 1.5 to 4.8 on a 0-5 scale. ||Recovery rates (symptom remission while remaining PCR-positive) ranged from 0% ('Chardonnay') to 45% ('Ugni Blanc'). ||The most resistant V. vinifera cultivar identified was 'Cabernet Sauvignon' with low infection rate, mild symptoms (score 1.5), and 25% recovery. ||Among interspecific genotypes, several rootstock varieties including '3309 Couderc' (V. riparia × V. rupestris) showed reduced infection rates (15-25%) and minimal symptom expression, suggesting enhanced Flavescence_Doree_Resistance_Disposition in non-vinifera germplasm. ||Importantly, cultivar differences in vector feeding preference did not correlate with infection rates, indicating that resistance operates primarily at the plant-phytoplasma interaction rather than plant-vector level.",
    "editor_note": "Flavescence_Doree_Resistance_Disposition is_a Phytoplasma_Resistance_Disposition. ||Flavescence dorée is a quarantine disease in the EU (EPPO A2 list) with mandatory control measures including vector treatment and infected vine removal. ||The child class Scaphoideus_Titanus_Resistance_Disposition addresses vector resistance as an indirect protection mechanism. ||True immunity to FD has not been identified in Vitis, making tolerance (reduced symptoms despite infection) and recovery (symptom remission) the relevant resistance phenotypes. ||Cultivar selection can meaningfully reduce disease impact but cannot eliminate the need for vector control in endemic areas.  This disposition represents the capacity to resist a quarantine pathogen that has caused devastating epidemics across European wine regions since its emergence in southwestern France in the 1950s, necessitating mandatory control measures including insecticide treatments against the vector Scaphoideus titanus and removal of infected vines. ||Flavescence dorée produces characteristic symptoms including downward leaf rolling with golden yellowing (white cultivars) or reddening (red cultivars) beginning from basal leaves and progressing acropetally, rubber-like flexibility of incompletely lignified canes, flower abortion or berry shriveling, and rapid vine decline often leading to death within 2-3 years. ||Resistance mechanisms may include restriction of phytoplasma multiplication in phloem, limitation of systemic colonization, resistance to phytoplasma-induced metabolic reprogramming, and recovery capacity enabling symptom remission. ||Additionally, resistance to the leafhopper vector S. titanus can provide indirect protection by reducing transmission. ||No V. vinifera cultivar shows immunity to FD, but substantial variation in susceptibility, symptom severity, and recovery rates provides opportunities for cultivar selection in endemic regions. ||Some interspecific hybrids and rootstocks show enhanced tolerance or resistance, potentially contributing to reduced disease pressure in mixed plantings.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Chuche J, Thiéry D (2014) Biology and ecology of the Flavescence dorée vector Scaphoideus titanus, Journal of Pest Science 87:381-393|| Eveillard S et al. (2016) Contrasting susceptibilities to Flavescence dorée in Vitis vinifera, rootstocks and wild Vitis species, Frontiers in Plant Science 7:1762|| EFSA Panel on Plant Health (2014) Scientific opinion on pest categorisation of Grapevine flavescence dorée, EFSA Journal 12:3851"
  },
  "Scaphoideus_Titanus_Resistance_Disposition": {
    "definition": "A Scaphoideus_Titanus_Resistance_Disposition is a Flavescence_Doree_Resistance_Disposition that inheres in a Vitis plant and is realized through host characteristics that prevent or limit Flavescence dorée transmission by the leafhopper Scaphoideus titanus (Hemiptera: Cicadellidae), the specific and obligate vector of 'Candidatus Phytoplasma vitis' in European vineyards.", 
    "alternative_term": "leafhopper vector resistance | Scaphoideus feeding resistance | FD vector resistance |+ Scaphoideus-titanus-Resistenz-Disposition | Zikaden-Vektor-Resistenz | Kleinzikaden-Resistenz",
    "example_of_usage": "Investigation of Scaphoideus_Titanus_Resistance_Disposition at the Edmund Mach Foundation, San Michele all'Adige, Italy, compared leafhopper performance and feeding behavior across 15 cultivars using choice and no-choice bioassays. ||In choice tests offering simultaneous access to leaf discs from different cultivars, S. titanus adults showed significant settling preferences, with 3.2-fold more individuals on preferred 'Chardonnay' compared to less-preferred 'Teroldego' after 24 hours. ||In no-choice development assays, nymphal survival from first instar to adult ranged from 78% on 'Chardonnay' to 45% on 'Cabernet Sauvignon', with development time extended by 4-6 days on less-suitable hosts. ||Electrical penetration graph (EPG) analysis of feeding behavior revealed that S. titanus achieved sustained phloem ingestion (E2 waveform >30 minutes) on 85% of 'Chardonnay' plants but only 52% of 'Teroldego' plants, with significantly shorter phloem access phases on resistant genotypes. ||Despite these differences in Scaphoideus_Titanus_Resistance_Disposition, field FD infection rates did not differ significantly between cultivars in mixed plantings with equivalent vector pressure, suggesting that observed resistance levels are insufficient to prevent transmission under epidemic conditions. ||This finding emphasizes that S. titanus resistance may contribute to but cannot replace chemical vector control for FD management.",
    "editor_note": "Scaphoideus_Titanus_Resistance_Disposition is_a Flavescence_Doree_Resistance_Disposition. ||This class represents resistance to the insect vector rather than to the phytoplasma itself, providing potential indirect disease protection. ||S. titanus is monophagous on Vitis and the sole significant FD vector in Europe, making vector resistance a relevant target. ||However, no strong resistance providing practical field protection has been identified, and mandatory insecticide treatments remain required regardless of cultivar. ||Vector resistance research is complicated by the regulated status of FD requiring contained facilities for transmission experiments with viruliferous insects.  This disposition represents indirect phytoplasma resistance operating by interrupting the vector-mediated transmission cycle rather than through direct anti-phytoplasma mechanisms. ||S. titanus is a Nearctic species accidentally introduced to Europe in the mid-20th century, where it has become the sole epidemiologically significant FD vector due to its monophagous feeding on Vitis, efficient phytoplasma acquisition and transmission, and high reproductive potential in vineyard ecosystems. ||Resistance mechanisms affecting S. titanus may include leaf surface properties (trichome density, wax composition) deterring settling and probing behavior, phloem sap composition unfavorable for sustained feeding, antibiosis factors reducing leafhopper survival or fecundity, and induced defenses triggered by feeding that reduce transmission efficiency. ||Variation in S. titanus population development and feeding preferences among Vitis genotypes has been documented, with some cultivars and rootstocks supporting lower populations or less sustained feeding than others. ||Vector resistance could complement chemical control strategies, potentially reducing insecticide requirements in integrated management programs. ||However, no strong S. titanus resistance has been identified that provides practical FD protection, and mandatory insecticide applications remain required in FD-regulated areas regardless of cultivar.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Chuche J, Thiéry D (2014) Biology and ecology of the Flavescence dorée vector Scaphoideus titanus, Journal of Pest Science 87:381-393|| Bressan A et al. (2005) Feeding behavior of Scaphoideus titanus Ball on different host plants, Bulletin of Insectology 58:115-122|| Galetto L et al. (2018) Acquisition of Flavescence dorée phytoplasma by Scaphoideus titanus Ball from different grapevine varieties, Bulletin of Insectology 71:5-12"
  },
  "Bois_Noir_Resistance_Disposition": {
    "definition": "A Bois_Noir_Resistance_Disposition is a Phytoplasma_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit infection, multiplication, systemic spread, symptom development, or recovery following infection by 'Candidatus Phytoplasma solani', the causal agent of Bois noir (BN), a widespread grapevine yellows disease with distinct epidemiology from Flavescence dorée.", 
    "alternative_term": "BN resistance disposition | Candidatus Phytoplasma solani resistance | black wood tolerance |+ Schwarzholzkrankheit-Resistenz-Disposition | Bois-noir-Resistenz | BN-Toleranz",
    "example_of_usage": "Long-term monitoring of Bois_Noir_Resistance_Disposition at the Julius Kühn-Institut, Siebeldingen, Germany, tracked BN incidence, symptom development, and recovery in a 20-cultivar trial block over 12 consecutive seasons in a region with endemic H. obsoletus populations and established phytoplasma reservoirs in adjacent ruderal vegetation. ||Cumulative infection rates (at least one positive PCR test during monitoring period) ranged from 15% ('Riesling') to 68% ('Dornfelder'). ||However, infection rate poorly predicted disease impact due to dramatic cultivar differences in symptom expression and recovery. 'Dornfelder' exhibited high susceptibility with severe symptoms (mean score 4.1), 8% spontaneous recovery, and 12% cumulative mortality. ||In contrast, 'Portugieser' showed equivalent infection rate (62%) but demonstrated strong Bois_Noir_Resistance_Disposition with mild symptoms (score 1.6), 65% spontaneous recovery within 2-3 years of symptom onset, and only 2% mortality. ||Recovery was associated with reduced but not eliminated phytoplasma titers, suggesting tolerance and host-mediated suppression rather than pathogen clearance. 'Riesling' represented a third phenotype with apparent infection resistance (low infection rate despite equivalent vector exposure) combined with moderate tolerance when infected (score 2.4, 40% recovery). ||These distinct Bois_Noir_Resistance_Disposition patterns enable cultivar-specific management recommendations, with tolerant cultivars like 'Portugieser' requiring less aggressive roguing of infected vines than susceptible cultivars like 'Dornfelder'.",
    "editor_note": "Bois_Noir_Resistance_Disposition is_a Phytoplasma_Resistance_Disposition. ||BN differs epidemiologically from FD in that the vector H. obsoletus does not complete its life cycle on grapevine and feeds only incidentally on vines, with herbaceous reservoir hosts essential for disease maintenance. ||This epidemiology means that vector resistance in grapevine is less relevant than for FD, and host tolerance/recovery capacity becomes the primary resistance mechanism of breeding interest. ||BN is not subject to mandatory control regulations equivalent to FD quarantine status in most regions, though monitoring and management are recommended. ||Spontaneous recovery rates are generally higher for BN than FD, making recovery capacity an important component of Bois_Noir_Resistance_Disposition.  This disposition represents the capacity to resist or tolerate infection by a phytoplasma that, unlike FD, is not grapevine-specific and is transmitted by the polyphagous planthopper Hyalesthes obsoletus (Hemiptera: Cixiidae) from herbaceous reservoir hosts including bindweed (Convolvulus arvensis), nettle (Urtica dioica), and other plants where the vector completes its life cycle. ||Bois noir symptoms are indistinguishable from FD, including leaf rolling with discoloration, incomplete cane lignification, and berry shriveling, but BN typically shows lower incidence, slower epidemic development, and higher spontaneous recovery rates than FD. ||Because H. obsoletus feeds on grapevine only occasionally as an adult seeking shelter, and because phytoplasma reservoir hosts are essential for the disease cycle, Bois_Noir_Resistance_Disposition operates in a different epidemiological context than FD resistance. ||Resistance mechanisms include limitation of phytoplasma multiplication in phloem following incidental vector feeding, tolerance to phytoplasma-induced phloem dysfunction, and recovery capacity enabling symptom remission and restoration of productivity. ||Substantial cultivar variation exists, with some V. vinifera cultivars showing tolerance or high recovery rates that enable economically viable production despite endemic BN presence.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Quaglino F et al. (2013) 'Candidatus Phytoplasma solani', a novel taxon associated with stolbur and Bois noir related diseases of plants, International Journal of Systematic and Evolutionary Microbiology 63:2879-2894|| Maixner M (2011) Recent advances in Bois noir research, Petria 21:95-108|| Langer M, Maixner M (2004) Molecular characterisation of grapevine yellows associated phytoplasmas of the stolbur-group based on RFLP-analysis of non-ribosomal DNA, Vitis 43:191-199"
  },
  "Pest_Resistance_Disposition": {
    "definition": "A Pest_Resistance_Disposition is a Biotic_Stress_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes upon encounter with arthropod pests and parasitic nematodes that feed on, damage, or vector pathogens to grapevine tissues.", 
    "alternative_term": "arthropod resistance disposition | herbivore resistance | pest tolerance |+ Schädlingsresistenz-Disposition | Arthropoden-Resistenz | Herbivoren-Abwehr",
    "example_of_usage": "Comprehensive screening for Pest_Resistance_Disposition at the USDA-ARS Grape Genetics Research Unit, Geneva, New York, evaluated responses to multiple pest species across 85 Vitis accessions representing cultivated and wild germplasm. ||Standardized bioassays assessed phylloxera root galling, Meloidogyne incognita root-knot formation, Japanese beetle (Popillia japonica) leaf consumption, and grape berry moth (Paralobesia viteana) larval development. ||V. vinifera 'Chardonnay' showed broad pest susceptibility with severe phylloxera nodosities (rating 5), high nematode galling index (7.2), complete defoliation by Japanese beetles in choice tests, and 85% berry moth larval survival. ||In contrast, V. cinerea accessions demonstrated multiple Pest_Resistance_Dispositions with minimal phylloxera damage (rating 1-2), nematode resistance (galling index 1.5), 70% less beetle feeding than 'Chardonnay', and reduced berry moth survival (45%). ||Interestingly, pest resistance profiles were not uniformly correlated across pest types, with some accessions showing phylloxera resistance but nematode susceptibility, indicating that Pest_Resistance_Disposition comprises multiple independent genetic systems rather than a single generalized defense capacity. ||These findings inform rootstock breeding targeting specific pest complexes prevalent in different viticultural regions.",
    "editor_note": "Pest_Resistance_Disposition is_a Biotic_Stress_Resistance_Disposition. ||This class encompasses resistance to all animal pests of grapevine, parallel to Pathogen_Resistance_Disposition which addresses microbial threats. ||Child classes include Phylloxera_Resistance_Disposition (the historically most significant), Nematode_Resistance_Disposition (important for rootstock breeding and virus vector management), Insect_Resistance_Disposition (diverse foliar and fruit pests), and Mite_Resistance_Disposition (eriophyid and spider mites). ||The economic and historical importance of different pests varies by region and era, with phylloxera having fundamentally transformed global viticulture in the 19th century.  This disposition represents the capacity to resist the diverse animal organisms that exploit grapevine as a food source, habitat, or reproductive substrate, distinct from pathogen resistance which addresses microbial threats. ||Major grapevine pests encompass the historically devastating grape phylloxera (Daktulosphaira vitifoliae), plant-parasitic nematodes (Xiphinema, Meloidogyne, Pratylenchus species), phloem-feeding insects (mealybugs, leafhoppers, scales), foliage-feeding insects (Japanese beetles, grape berry moth larvae), and eriophyid mites causing erineum and bud damage. ||Pest resistance mechanisms in plants include constitutive physical barriers (trichomes, tough tissues, latex), preformed chemical defenses (alkaloids, terpenoids, phenolics), induced defenses triggered by herbivore feeding (proteinase inhibitors, volatile emissions, phytoalexins), and tolerance mechanisms enabling productivity maintenance despite pest damage. ||Additionally, indirect defenses attracting natural enemies of pests through volatile signals or extrafloral resources contribute to pest suppression. ||For grapevine specifically, the profound susceptibility of V. vinifera roots to phylloxera historically reshaped global viticulture through the universal adoption of resistant rootstocks, while resistance to other pests varies among cultivars and provides opportunities for integrated pest management. ||Understanding pest resistance dispositions informs cultivar and rootstock selection, breeding program priorities, and development of sustainable pest management strategies reducing reliance on synthetic pesticides.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Granett J et al. (2001) Biology and management of grape phylloxera, Annual Review of Entomology 46:387-412|| Walling LL (2000) The myriad plant responses to herbivores, Journal of Plant Growth Regulation 19:195-216|| Howe GA, Jander G (2008) Plant immunity to insect herbivores, Annual Review of Plant Biology 59:41-66"
  },
  "Phylloxera_Resistance_Disposition": {
    "definition": "A Phylloxera_Resistance_Disposition is a Pest_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit feeding, gall formation, population development, or damage by grape phylloxera (Daktulosphaira vitifoliae), the aphid-like insect that caused the catastrophic destruction of European vineyards in the late 19th century and permanently transformed global viticulture through the universal adoption of resistant rootstocks.", 
    "alternative_term": "Daktulosphaira resistance | grape phylloxera immunity | radicicole/gallicole resistance |+ Reblaus-Resistenz-Disposition | Phylloxera-Resistenz | Daktulosphaira-Abwehr",
    "example_of_usage": "The historical devastation demonstrating the absence of Phylloxera_Resistance_Disposition in V. vinifera began in the 1860s when phylloxera, inadvertently introduced from North America on botanical specimens, spread through French vineyards with catastrophic consequences. ||By 1900, over 2.5 million hectares of European vineyards had been destroyed, representing 40% of French production capacity and causing economic losses equivalent to twice the costs of the Franco-Prussian War. ||The solution—grafting V. vinifera scions onto resistant American rootstocks—was proposed by Jules-Émile Planchon and validated through systematic trials demonstrating that V. riparia, V. rupestris, and V. berlandieri roots support phylloxera populations 100-1000 fold lower than V. vinifera while maintaining vine productivity. ||Modern rootstock breeding continues to optimize Phylloxera_Resistance_Disposition, with genotypes like 'SO4' (V. berlandieri × V. riparia) supporting minimal root galling (OIV rating 8-9) while providing excellent graft compatibility and adaptation to diverse soil conditions. ||The universal adoption of resistant rootstocks represents the most successful application of host plant resistance in agricultural history, enabling V. vinifera cultivation to continue in all traditional wine regions despite permanent phylloxera establishment.",
    "editor_note": "Phylloxera_Resistance_Disposition is_a Pest_Resistance_Disposition. ||This class addresses resistance to Daktulosphaira vitifoliae, historically the most devastating grapevine pest. ||Child classes distinguish Root_Phylloxera_Resistance_Disposition (economically critical, addressed through rootstocks) from Foliar_Phylloxera_Resistance_Disposition (less damaging, primarily affecting American species and hybrids). ||The phylloxera crisis of the 1860s-1900s permanently transformed viticulture, making grafted vines the global standard. ||Resistance is found in North American Vitis species co-evolved with phylloxera|| V. vinifera lacks meaningful resistance due to absence of evolutionary exposure.  This disposition represents the capacity to resist a uniquely devastating grapevine pest native to eastern North America, where it co-evolved with indigenous Vitis species that developed effective resistance mechanisms. ||Phylloxera has a complex life cycle with both root-feeding (radicicole) and leaf-feeding (gallicole) forms, though the root-feeding form causes the economically significant damage to susceptible V. vinifera. ||On susceptible roots, phylloxera feeding induces characteristic galls (nodosities on young roots, tuberosities on older lignified roots) that disrupt root function and provide entry points for secondary pathogens, leading to progressive vine decline and death. ||Resistance mechanisms include hypersensitive response killing cells at feeding sites, production of wound periderm isolating feeding damage, antibiosis factors reducing insect survival or fecundity, and antixenosis reducing feeding preference. ||North American Vitis species including V. riparia, V. rupestris, V. berlandieri, and V. cinerea exhibit varying levels of root phylloxera resistance that has been exploited through rootstock breeding, while V. vinifera remains essentially defenseless against root infestation, necessitating grafting for sustainable production in phylloxera-infested soils worldwide.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Granett J et al. (2001) Biology and management of grape phylloxera, Annual Review of Entomology 46:387-412|| Ordish G (1987) The Great Wine Blight, 2nd Edition, Sidgwick & Jackson|| Powell KS (2012) A holistic approach to future management of grapevine phylloxera, Root Feeders: An Ecosystem Perspective, CAB International"
  },
  "Root_Phylloxera_Resistance_Disposition": {
    "definition": "A Root_Phylloxera_Resistance_Disposition is a Phylloxera_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that limit feeding damage, gall development, population establishment, or vine decline caused by the radicicole (root-feeding) form of grape phylloxera (Daktulosphaira vitifoliae).", 
    "alternative_term": "radicicole resistance | root gall resistance | rootstock phylloxera resistance |+ Wurzelreblaus-Resistenz-Disposition | Radizikolenresistenz | Wurzelgallen-Resistenz",
    "example_of_usage": "Systematic quantification of Root_Phylloxera_Resistance_Disposition at INRAE Bordeaux employed standardized pot assays comparing root damage across 45 rootstock genotypes and V. vinifera controls following controlled phylloxera infestation. ||Potted vines were inoculated with 500 phylloxera crawlers and assessed at 16 weeks for nodosity count per gram root, tuberosity severity (0-5 scale), root system damage (0-9 OIV scale), and vine growth parameters. ||V. vinifera 'Cabernet Sauvignon' (own-rooted) showed severe susceptibility with 42 nodosities/g root, tuberosity rating 4.5, OIV damage score 2 (very susceptible), and 65% growth reduction. ||The highly resistant 'Börner' (V. riparia × V. cinerea) demonstrated exceptional Root_Phylloxera_Resistance_Disposition with 0.3 nodosities/g (99% reduction), no tuberosities, OIV score 9, and no growth impact. ||Commercial rootstock '110 Richter' (V. berlandieri × V. rupestris) showed intermediate resistance with 3.2 nodosities/g, tuberosity rating 1.2, OIV score 7, and 8% growth reduction—sufficient for practical vineyard use. ||Importantly, phylloxera populations recovered from resistant rootstocks showed no enhanced virulence when re-inoculated onto susceptible vines, indicating that resistance operates through host defense rather than supporting adapted phylloxera biotypes under these experimental conditions.",
    "editor_note": "Root_Phylloxera_Resistance_Disposition is_a Phylloxera_Resistance_Disposition. ||This class addresses resistance in root tissues to the radicicole form, which is the economically significant phase causing vine decline and death in susceptible V. vinifera. ||Child classes include Nodosity_Limitation_Disposition (resistance to young root galls), Tuberosity_Resistance_Disposition (resistance to lignified root damage), and Root_Regeneration_Disposition (compensatory root growth maintaining function). ||The combination of these mechanisms determines overall rootstock performance. ||Concern exists regarding phylloxera biotypes potentially overcoming resistance in some rootstocks, particularly in Australian and Californian vineyards.  This disposition represents the economically critical resistance that has enabled continued V. vinifera cultivation worldwide through grafting onto resistant rootstocks. ||Root phylloxera infestation begins when crawlers or eggs deposited on roots initiate feeding on root tip meristems and cortical tissues. ||On susceptible V. vinifera roots, phylloxera feeding induces characteristic gall structures—nodosities (hook-shaped swellings on young white roots) and tuberosities (warty proliferations on lignified structural roots)—that progressively destroy root function. ||Resistant roots respond to phylloxera attack through multiple mechanisms including rapid hypersensitive cell death at feeding sites preventing sustained nutrition, formation of wound periderm isolating damage, production of toxic or deterrent secondary metabolites, and maintenance of functional root capacity despite limited feeding. ||The distinction between immunity (no feeding, no galls), resistance (limited feeding with minimal damage), and tolerance (feeding occurs but vine productivity maintained) is important, as most commercial rootstocks exhibit resistance or tolerance rather than true immunity. ||Root_Phylloxera_Resistance_Disposition is the foundation of modern viticulture, with over 80% of global vineyard area planted on resistant rootstocks, and understanding its mechanisms remains essential for addressing emerging phylloxera biotypes that may overcome existing resistance sources.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Granett J et al. (2001) Biology and management of grape phylloxera, Annual Review of Entomology 46:387-412|| Kellow AV et al. (2004) Interaction between Vitis vinifera and grape phylloxera: changes in root tissue during nodosity formation, Annals of Botany 93:581-590|| Powell KS et al. (2013) Tolerance and resistance to root damage are not correlated during phylloxera host-plant interactions, Plant Pathology 62:1251-1261"
  },
  "Nodosity_Limitation_Disposition": {
    "definition": "A Nodosity_Limitation_Disposition is a Root_Phylloxera_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that prevent or limit formation of nodosities—the characteristic hook-shaped galls induced by grape phylloxera feeding on young, unsuberized root tips.", 
    "alternative_term": "root tip gall resistance | nodosity suppression | young root resistance |+ Nodositäts-Begrenzungs-Disposition | Wurzelspitzen-Gallen-Resistenz | Nodositäts-Unterdrückung",
    "example_of_usage": "Detailed histological analysis of Nodosity_Limitation_Disposition at the University of Melbourne compared cellular responses to phylloxera feeding in resistant V. riparia 'Gloire de Montpellier' versus susceptible V. vinifera 'Shiraz' using microscopy of excised root tips inoculated with individual phylloxera crawlers. ||On 'Shiraz' roots, feeding induced rapid cell division in the pericycle and cortex within 48 hours, with recognizable nodosity structures forming by day 7 and reaching full development (2-3mm swelling with characteristic hook shape) by day 14. ||Phylloxera within nodosities showed active feeding and reproduction, with mean offspring production of 8.5 crawlers per adult over 21 days. ||On 'Gloire de Montpellier' roots demonstrating Nodosity_Limitation_Disposition, initial cellular response to feeding was detectable at 48 hours but accompanied by rapid browning of cells adjacent to the feeding site characteristic of hypersensitive response. ||By day 7, necrotic tissue surrounded the feeding site, preventing the coordinated cell proliferation necessary for nodosity formation. ||Rudimentary swellings occasionally formed but remained small (<0.5mm) and non-functional, with phylloxera showing 85% mortality and mean offspring production of only 0.3 crawlers per surviving adult. ||These observations confirm that Nodosity_Limitation_Disposition operates through rapid recognition and localized cell death that sacrifices infected cells to prevent establishment of functional feeding galls.",
    "editor_note": "Nodosity_Limitation_Disposition is_a Root_Phylloxera_Resistance_Disposition. ||Nodosities form on young unsuberized root tips and represent the initial colonization site for root phylloxera. ||This class is distinguished from Tuberosity_Resistance_Disposition which addresses galls on older lignified roots. ||Hypersensitive response appears to be a key mechanism, analogous to pathogen resistance. ||Nodosity limitation is typically stronger in V. riparia-derived rootstocks than in V. berlandieri-derived rootstocks, which may tolerate some nodosity formation while still providing adequate field resistance.  This disposition represents resistance at the primary infection site where first-instar crawlers or eggs initiate root colonization, determining whether phylloxera can establish feeding sites and begin population development on the root system. ||Nodosities form when phylloxera feeding induces abnormal cell division and expansion in the root tip meristem and cortex, creating hooked swellings that house the insect and provide continuous access to nutritious phloem and cortical cells. ||On susceptible V. vinifera, nodosities develop within 7-10 days of feeding initiation and support rapid phylloxera reproduction. ||Resistance mechanisms limiting nodosity formation include hypersensitive response killing cells at feeding sites before gall development can proceed, failure of root tissues to undergo phylloxera-induced cell proliferation, production of toxic secondary metabolites in root tips, and physical properties of root tissues preventing stylet penetration or sustained feeding. ||Nodosity_Limitation_Disposition varies among resistant Vitis species, with some (V. riparia) showing near-complete suppression of nodosity formation while others (V. berlandieri) permit limited nodosity development but prevent progression to vine-damaging tuberosities. ||Evaluating nodosity formation is a primary screening method for root phylloxera resistance in rootstock breeding programs.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kellow AV et al. (2004) Interaction between Vitis vinifera and grape phylloxera: changes in root tissue during nodosity formation, Annals of Botany 93:581-590|| Forneck A et al. (2002) Histochemistry and anatomy of phylloxera (Daktulosphaira vitifoliae) nodosities on young roots of grapevine (Vitis spp.), Vitis 41:93-97|| Lawo NC et al. (2011) Grapevine phylloxera's performance on phylloxera resistant rootstock and their physiological response to root damage, Plant Physiology and Biochemistry 49:426-431"
  },
  "Tuberosity_Resistance_Disposition": {
    "definition": "A Tuberosity_Resistance_Disposition is a Root_Phylloxera_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that prevent or limit formation of tuberosities—the warty, necrotic galls induced by grape phylloxera feeding on older, lignified structural roots.", 
    "alternative_term": "structural root resistance | tuberosity suppression | lignified root defense |+ Tuberosität-Resistenz-Disposition | Strukturwurzel-Resistenz | Tuberositäts-Abwehr",
    "example_of_usage": "Field evaluation of Tuberosity_Resistance_Disposition at CSIRO Adelaide compared long-term root health across 12 rootstock genotypes in a vineyard with documented aggressive phylloxera biotype pressure over 15 years. ||Root systems were excavated at years 5, 10, and 15 for assessment of tuberosity severity (0-5 scale), structural root integrity, and secondary pathogen colonization. ||Own-rooted V. vinifera 'Shiraz' controls showed catastrophic decline with tuberosity scores of 4.8 by year 5, complete structural root deterioration, 100% Fusarium colonization, and vine death by year 8. ||The V. berlandieri × V. rupestris rootstock '140 Ruggeri' demonstrated strong Tuberosity_Resistance_Disposition despite moderate nodosity presence on young roots (nodosity score 3.2). ||Tuberosity formation remained minimal (score 0.8 at year 15), structural roots maintained integrity, Fusarium colonization was only 12%, and vines sustained commercial productivity throughout the trial. ||Histological examination revealed that '140 Ruggeri' roots responded to phylloxera probing of lignified tissues with intense suberization and phenolic deposition creating impenetrable barriers, while successful feeding attempts triggered rapid cork cambium activation isolating small tuberosities before pathogen entry. ||This field performance demonstrates that Tuberosity_Resistance_Disposition can provide durable vine protection even where nodosity limitation is incomplete.",
    "editor_note": "Tuberosity_Resistance_Disposition is_a Root_Phylloxera_Resistance_Disposition. ||Tuberosities on lignified structural roots cause more serious vine damage than nodosities on young roots, as they affect the permanent root framework and facilitate pathogen entry. ||Some rootstocks (especially V. berlandieri derivatives) show stronger tuberosity resistance than nodosity limitation, representing an alternative resistance strategy. ||The combination of tuberosity formation and secondary pathogen invasion is typically responsible for vine death in susceptible genotypes, making tuberosity resistance the critical determinant of long-term rootstock performance.  This disposition represents resistance to the most destructive phase of root phylloxera infestation, as tuberosities disrupt the permanent root framework, provide entry points for secondary soil pathogens (particularly Fusarium and other root rot fungi), and cause progressive structural deterioration leading to vine decline and death. ||Tuberosities develop when phylloxera colonize suberized roots through lenticels or wounds, inducing localized hyperplasia and subsequent necrosis that creates characteristic rough, corky proliferations. ||Unlike nodosities which may be tolerated without significant vine impact, extensive tuberosity formation inevitably leads to vine decline through combined effects of reduced water and nutrient uptake, pathogen invasion, and structural root loss. ||Resistance mechanisms include lignin and suberin barriers preventing phylloxera access to feeding-competent tissues, rapid wound periderm formation isolating feeding sites, production of phenolic compounds toxic to phylloxera in lignified tissues, and anatomical features limiting phylloxera penetration. ||Tuberosity_Resistance_Disposition is often mechanistically distinct from nodosity limitation, with some rootstocks (particularly V. berlandieri derivatives) permitting nodosity formation while effectively preventing tuberosity development, providing adequate field protection through this alternative resistance strategy.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Granett J et al. (2001) Biology and management of grape phylloxera, Annual Review of Entomology 46:387-412|| Powell KS et al. (2013) Tolerance and resistance to root damage are not correlated during phylloxera host-plant interactions, Plant Pathology 62:1251-1261|| Kellow AV et al. (2004) Interaction between Vitis vinifera and grape phylloxera, Annals of Botany 93:581-590"
  },
  "Root_Regeneration_Disposition": {
    "definition": "A Root_Regeneration_Disposition is a Root_Phylloxera_Resistance_Disposition that inheres in a Vitis plant and is realized through the capacity to produce new root growth rapidly and extensively, compensating for phylloxera-induced damage and maintaining adequate root function despite ongoing infestation pressure.", 
    "alternative_term": "root system recovery | compensatory root growth | root turnover capacity |+ Wurzelregenerations-Disposition | Wurzelsystem-Erholung | Kompensatorisches-Wurzelwachstum",
    "example_of_usage": "Experimental quantification of Root_Regeneration_Disposition at Agriculture Victoria, Australia, employed rhizotron observation of root dynamics in phylloxera-infested and control vines across 8 rootstock genotypes over two growing seasons. ||Minirhizotron cameras recorded root appearance, growth, and disappearance at weekly intervals, enabling calculation of root production, mortality, and turnover rates. ||Under phylloxera infestation, V. vinifera 'Sultana' (own-rooted) showed root production rates of 0.8 roots/cm²/week but mortality of 1.2 roots/cm²/week, resulting in progressive net root loss and 45% reduction in total root length by season end. ||The regeneration-tolerant rootstock '1103 Paulsen' (V. berlandieri × V. rupestris) demonstrated strong Root_Regeneration_Disposition with production rates increasing from 1.1 roots/cm²/week (control) to 2.3 roots/cm²/week under infestation—a compensatory response doubling root production. ||Despite elevated mortality (1.8 roots/cm²/week), '1103 Paulsen' maintained net positive root growth and equivalent total root length to uninfested controls. ||Carbohydrate analysis revealed that '1103 Paulsen' mobilized 35% more starch reserves from permanent roots under infestation compared to 'Sultana', fueling the enhanced regeneration response. ||This tolerance-based Root_Regeneration_Disposition explains the excellent field performance of '1103 Paulsen' in phylloxera-infested Australian vineyards despite its moderate nodosity scores in pot bioassays.",
    "editor_note": "Root_Regeneration_Disposition is_a Root_Phylloxera_Resistance_Disposition. ||This class represents tolerance through damage compensation rather than resistance through damage prevention, providing an alternative or complementary strategy to Nodosity_Limitation_Disposition and Tuberosity_Resistance_Disposition. ||Root regeneration capacity varies among rootstocks and is influenced by vine carbohydrate status, making management practices affecting vine reserves (crop load, timing of irrigation) relevant to expression of this tolerance mechanism. ||The distinction between \"resistance\" (limiting pest damage) and \"tolerance\" (compensating for damage) is particularly clear in this context.  This disposition represents a tolerance mechanism distinct from resistance mechanisms that prevent or limit phylloxera feeding, enabling vines to sustain productivity through continual replacement of damaged roots rather than through exclusion or elimination of the pest. ||Phylloxera feeding destroys root tips and progressively degrades the root system|| genotypes with strong Root_Regeneration_Disposition respond by initiating new root growth from undamaged tissues faster than phylloxera can colonize, maintaining a functional root population adequate for water and nutrient uptake. ||Root regeneration capacity depends on the availability of stored carbohydrate reserves, hormonal signaling promoting adventitious root initiation, meristematic activity in root pericycle and cambium tissues, and environmental conditions (soil moisture, temperature, aeration) permitting rapid root growth. ||This tolerance strategy is particularly relevant for rootstocks in the V. berlandieri background, which may permit moderate phylloxera feeding but compensate through vigorous root system restoration. ||Root_Regeneration_Disposition provides practical field resistance even in the absence of strong antibiosis or antixenosis, though it may be insufficient under extreme phylloxera pressure or in conditions (drought, nutrient stress) limiting regeneration capacity. ||The concept parallels wound tolerance in other plant-pest interactions where damage compensation rather than damage avoidance provides functional protection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Powell KS et al. (2013) Tolerance and resistance to root damage are not correlated during phylloxera host-plant interactions, Plant Pathology 62:1251-1261|| Clingeleffer PR, Krake LR (2002) Responses of Cabernet Sauvignon grapevines to minimal pruning and phylloxera infestation, Australian Journal of Grape and Wine Research 8:73-83|| Keller M (2020) The Science of Grapevines, 3rd Edition, Academic Press"
  },
  "Foliar_Phylloxera_Resistance_Disposition": {
    "definition": "A Foliar_Phylloxera_Resistance_Disposition is a Phylloxera_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that prevent or limit feeding, gall formation, and population development by the gallicole (leaf-feeding) form of grape phylloxera (Daktulosphaira vitifoliae) on foliage.", 
    "alternative_term": "gallicole resistance | leaf gall resistance | foliar galling immunity |+ Blattreblaus-Resistenz-Disposition | Gallikolenresistenz | Blattgallen-Resistenz",
    "example_of_usage": "Comparative analysis of Foliar_Phylloxera_Resistance_Disposition at Cornell University evaluated leaf galling responses across 35 Vitis accessions following controlled exposure to phylloxera crawlers applied to expanding leaves. ||Gall density (galls per 100 cm² leaf area), gall size, and phylloxera reproduction within galls were assessed at 21 days post-infestation. ||V. vinifera cultivars ('Chardonnay', 'Cabernet Sauvignon', 'Riesling') demonstrated strong Foliar_Phylloxera_Resistance_Disposition with gall densities of 0-0.8 galls/100cm², minimal successful gall formation, and no sustained phylloxera reproduction. ||In contrast, V. riparia accessions—though highly resistant to root phylloxera—showed extreme leaf susceptibility with gall densities of 45-120 galls/100cm², large functional galls, and active reproduction averaging 35 offspring per gall. ||V. labrusca and V. labrusca hybrids ('Concord', 'Catawba') showed intermediate responses (8-25 galls/100cm²). ||Histological examination revealed that phylloxera probing on V. vinifera leaves triggered localized cell death within 24 hours, preventing the coordinated cell proliferation required for gall formation. ||On susceptible V. riparia, no cell death response occurred, and gall development proceeded normally. ||This inverse pattern of foliar versus root resistance demonstrates that Foliar_Phylloxera_Resistance_Disposition is genetically and mechanistically distinct from Root_Phylloxera_Resistance_Disposition.",
    "editor_note": "Foliar_Phylloxera_Resistance_Disposition is_a Phylloxera_Resistance_Disposition. ||This class addresses resistance to the gallicole (leaf-feeding) form, which is economically less important than root resistance but biologically fascinating due to the inverse susceptibility pattern between V. vinifera (leaf resistant, root susceptible) and American species (leaf susceptible, root resistant). ||The child class Gall_Formation_Resistance_Disposition specifically addresses the cellular mechanisms preventing leaf gall development. ||Foliar phylloxera populations can serve as inoculum source for root colonization, making leaf resistance potentially relevant for integrated phylloxera management even where root resistance is provided by rootstocks.  This disposition represents resistance to a different phase of the phylloxera life cycle than root resistance, addressing the aerial galls that form on leaf undersides when winged or crawling phylloxera colonize leaves. ||Foliar phylloxera galls are pouch-like structures opening on the lower leaf surface, each containing a fundatrix female that reproduces parthenogenetically, with subsequent generations either remaining on leaves or migrating to roots. ||While foliar phylloxera infestation is less economically damaging than root infestation—rarely causing significant vine decline—heavy galling can reduce photosynthetic area, stress young vines, and serves as a population reservoir for root colonization. ||Interestingly, susceptibility patterns to foliar versus root phylloxera are often inversely related among Vitis species: American species (V. riparia, V. rupestris) that show strong root resistance often support extensive leaf galling, while V. vinifera with catastrophic root susceptibility shows resistance to leaf gall formation. ||This inverse relationship suggests different genetic control of resistance in different tissues. ||Mechanisms of foliar resistance include leaf anatomical features preventing gall initiation, hypersensitive response killing cells at probing sites, and failure of leaves to undergo the cell proliferation required for gall formation.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Granett J et al. (2001) Biology and management of grape phylloxera, Annual Review of Entomology 46:387-412|| Forneck A, Huber L (2009) (A)sexual reproduction - a review of life cycles of grape phylloxera, Daktulosphaira vitifoliae, Entomologia Experimentalis et Applicata 131:1-10|| Sterling C (1952) Ontogeny of the phylloxera gall of grape leaf, American Journal of Botany 39:6-15"
  },
  "Gall_Formation_Resistance_Disposition": {
    "definition": "A Gall_Formation_Resistance_Disposition is a Foliar_Phylloxera_Resistance_Disposition that inheres in a Vitis plant leaf and is realized through cellular mechanisms that prevent the coordinated cell proliferation and tissue reorganization required for functional phylloxera gall development following insect probing and feeding attempts.", 
    "alternative_term": "gall initiation resistance | leaf gall suppression | gall morphogenesis block |+ Gallenbildungs-Resistenz-Disposition | Galleninitiations-Resistenz | Gallenmorphogenese-Blockade",
    "example_of_usage": "Mechanistic investigation of Gall_Formation_Resistance_Disposition at the University of Natural Resources and Life Sciences, Vienna, employed time-course microscopy comparing cellular responses to phylloxera probing in resistant V. vinifera 'Grüner Veltliner' versus susceptible V. riparia 'Gloire de Montpellier'. ||Detached leaves were infested with synchronized first-instar crawlers, and feeding sites were sectioned at 6, 12, 24, 48, and 96 hours for histological analysis and cell death visualization (trypan blue staining). ||On susceptible V. riparia, phylloxera stylet insertion at 6 hours was followed by localized cell division visible at 24 hours, coordinated tissue bulging at 48 hours, and recognizable gall primordia at 96 hours, with no cell death in adjacent tissues. ||On resistant 'Grüner Veltliner', equivalent stylet insertion occurred at 6 hours, but by 12 hours, cells within 200μm of the feeding site showed intense trypan blue staining indicating cell death. ||By 24 hours, a zone of collapsed, dead cells surrounded the probing site, and no cell division was observed. ||Attempted gall formation was aborted, and phylloxera either died or abandoned the leaf. ||Gene expression analysis revealed that 'Grüner Veltliner' showed rapid (6-12 hour) upregulation of defense genes including PR-1, chitinase, and phenylalanine ammonia-lyase at feeding sites, while V. riparia showed no defense gene induction. ||These findings demonstrate that Gall_Formation_Resistance_Disposition in V. vinifera involves active recognition and hypersensitive response rather than passive incompatibility.",
    "editor_note": "Gall_Formation_Resistance_Disposition is_a Foliar_Phylloxera_Resistance_Disposition. ||This class addresses the specific cellular mechanism preventing leaf gall development, mechanistically analogous to hypersensitive response against pathogens. ||The presence of strong gall formation resistance in V. vinifera, which lacks root resistance, demonstrates that phylloxera defense is controlled by tissue-specific genetic systems. ||Understanding these mechanisms could potentially inform strategies for enhancing root resistance, though the distinct biology of root versus leaf tissues may limit direct translation.  This disposition represents the specific mechanism underlying foliar phylloxera resistance, focusing on the host tissue response that determines whether phylloxera feeding can induce the characteristic pouch galls or is aborted before gall formation proceeds. ||Successful phylloxera leaf gall formation requires a precise sequence of host responses including localized suppression of cell death, induction of cell division in adaxial mesophyll, coordinated cell expansion creating the gall chamber, differentiation of nutritive tissue lining the gall, and maintenance of a favorable environment for the enclosed insect. ||Gall_Formation_Resistance_Disposition disrupts this sequence through alternative host responses including hypersensitive cell death at feeding sites sacrificing potential gall tissues, failure of cells to respond to phylloxera-secreted growth regulators, production of toxic or deterrent compounds at probing sites, and anatomical features (thick cuticle, dense trichomes) preventing initial feeding establishment. ||V. vinifera exhibits strong Gall_Formation_Resistance_Disposition characterized by rapid cell death in response to phylloxera probing, explaining the near-absence of functional leaf galls on European cultivars despite their catastrophic root susceptibility. ||This tissue-specific resistance provides insight into the distinct genetic control of phylloxera defense in different plant organs.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sterling C (1952) Ontogeny of the phylloxera gall of grape leaf, American Journal of Botany 39:6-15|| Forneck A et al. (2002) Histochemistry and anatomy of phylloxera galls on Vitis spp., Vitis 41:93-97|| Nabity PD et al. (2013) Leaf-galling phylloxera on grapes reprograms host metabolism and morphology, Proceedings of the National Academy of Sciences 110:16663-16668"
  },
  "Nematode_Resistance_Disposition": {
    "definition": "A Nematode_Resistance_Disposition is a Pest_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that limit feeding, reproduction, or damage by plant-parasitic nematodes, microscopic roundworms that attack grapevine roots causing direct injury and, in the case of certain species, transmitting economically important viruses.", 
    "alternative_term": "plant-parasitic nematode resistance | root nematode immunity | nematode feeding resistance |+ Nematodenresistenz-Disposition | Pflanzenparasitäre-Nematoden-Resistenz | Wurzelnematoden-Abwehr",
    "example_of_usage": "Comprehensive evaluation of Nematode_Resistance_Disposition at UC Davis Foundation Plant Services assessed responses to three economically important nematode genera across 40 rootstock genotypes using standardized greenhouse pot assays. ||Vines were planted in soil inoculated with Xiphinema index (500 individuals), Meloidogyne incognita (5,000 eggs), or Pratylenchus vulnus (2,000 mixed stages) per pot, with nematode populations and root damage assessed at 6 months. ||Susceptible V. vinifera 'Cabernet Sauvignon' (own-rooted) supported high populations of all three genera: X. index 2,450/pot, M. incognita galling index 8.2/10, P. vulnus 18,500/pot with severe root lesioning. ||The Muscadinia-derived rootstock 'O39-16' demonstrated broad Nematode_Resistance_Disposition with X. index suppressed to 45/pot (98% reduction), M. incognita galling index 1.2, and P. vulnus limited to 1,200/pot. ||Importantly, nematode resistance profiles varied among rootstocks, with '1103 Paulsen' showing strong Meloidogyne resistance (galling index 0.8) but moderate Xiphinema susceptibility (890/pot), while 'Freedom' showed inverse pattern (X. index 180/pot but galling index 6.5). ||These differential resistance profiles guide rootstock selection based on site-specific nematode pressure, with molecular markers enabling targeted breeding for multiple nematode resistances.",
    "editor_note": "Nematode_Resistance_Disposition is_a Pest_Resistance_Disposition. ||This class encompasses resistance to all plant-parasitic nematodes affecting grapevine roots, with child classes organized by nematode genus: Xiphinema_Index_Resistance_Disposition (dagger nematodes, virus vectors), Meloidogyne_Resistance_Disposition (root-knot nematodes), and Pratylenchus_Resistance_Disposition (lesion nematodes). ||Nematode resistance is primarily relevant for rootstock breeding rather than scion improvement, as roots are the target tissue. ||The dual importance of Xiphinema resistance for both direct damage prevention and fanleaf virus management distinguishes it from other nematode resistances.  This disposition represents the capacity to resist a diverse group of soil-dwelling obligate parasites belonging to multiple genera with distinct feeding strategies, host interactions, and economic impacts on viticulture. ||Major nematode pests of grapevine include ectoparasitic dagger nematodes (Xiphinema species) that feed externally on root tips and transmit nepoviruses including Grapevine fanleaf virus, endoparasitic root-knot nematodes (Meloidogyne species) that induce characteristic galls and disrupt vascular function, and migratory endoparasitic lesion nematodes (Pratylenchus species) that cause cortical necrosis. ||Nematode resistance mechanisms include pre-infectional barriers preventing nematode penetration or feeding establishment, hypersensitive response killing cells at feeding sites, production of nematicidal or nematostatic compounds, and incompatibility preventing completion of nematode life cycles in host tissues. ||For grapevine rootstock breeding, nematode resistance serves dual purposes: protecting root system health from direct nematode damage and, critically for Xiphinema, preventing virus acquisition and transmission that would otherwise doom grafted V. vinifera scions to fanleaf decline. ||Resistance sources have been identified in various Vitis species and Muscadinia rotundifolia, enabling development of nematode-resistant rootstocks for infested vineyard sites.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Nicol JM et al. (1999) Current nematode threats to world viticulture, Nematology Monographs and Perspectives 2:269-282|| Anwar SA, McKenry MV (2002) Developmental response of a resistance-breaking population of Meloidogyne arenaria on Vitis spp., Journal of Nematology 34:28-33|| Zasada IA et al. (2010) Managing nematodes without methyl bromide, Annual Review of Phytopathology 48:311-328"
  },
  "Xiphinema_Index_Resistance_Disposition": {
    "definition": "A Xiphinema_Index_Resistance_Disposition is a Nematode_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that limit feeding, reproduction, and population development of the dagger nematode Xiphinema index, an ectoparasitic nematode of paramount importance in viticulture as the primary vector of Grapevine fanleaf virus (GFLV).", 
    "alternative_term": "dagger nematode resistance | X. index resistance | fanleaf vector resistance |+ Xiphinema-index-Resistenz-Disposition | Dolchnematoden-Resistenz | GFLV-Vektor-Resistenz",
    "example_of_usage": "Long-term field validation of Xiphinema_Index_Resistance_Disposition at the USDA-ARS research vineyard in Parlier, California, compared X. index population dynamics and GFLV transmission over 12 years across rootstocks planted in soil naturally infested with viruliferous nematodes. ||The susceptible rootstock '5C Teleki' (V. berlandieri × V. riparia) supported X. index populations averaging 1,250 per 250g soil, with 95% of grafted 'Thompson Seedless' scions becoming GFLV-positive within 4 years and exhibiting severe fanleaf symptoms. ||The resistant '039-16' (V. vinifera × M. rotundifolia BC₃) demonstrated exceptional Xiphinema_Index_Resistance_Disposition, suppressing X. index to 35 per 250g soil (97% reduction), with only 8% of scions becoming infected after 12 years and those showing low viral titers and minimal symptoms. ||Importantly, '039-16' resistance remained stable throughout the trial with no evidence of resistance-breaking nematode biotypes emerging. ||Root excavation revealed that '039-16' roots triggered rapid browning and cell death at X. index feeding sites, preventing sustained feeding and reproduction. ||This field performance validates that Xiphinema_Index_Resistance_Disposition provides durable, effective fanleaf management superior to any other available strategy in heavily infested sites.",
    "editor_note": "Xiphinema_Index_Resistance_Disposition is_a Nematode_Resistance_Disposition. ||This class specifically addresses resistance to X. index, the primary GFLV vector, distinct from general nematode resistance. ||The dual importance of X. index resistance for both direct root protection and fanleaf virus management makes it the highest priority nematode resistance trait for rootstock breeding in GFLV-endemic regions. ||The resistance mechanism appears similar to Root_Phylloxera_Resistance_Disposition, involving hypersensitive-like cell death at feeding sites. ||Resistance sources include M. rotundifolia and several North American Vitis species, with the XiR1 locus from M. rotundifolia being the best-characterized resistance gene.  This disposition represents resistance to a large (3-4mm) nematode that feeds externally on root tips using a long odontostyle (feeding stylet) to penetrate cells and extract contents, causing direct root damage through feeding site destruction and, critically, transmitting GFLV between infected and healthy vines. ||X. index acquires GFLV particles during feeding on infected roots and retains virus in association with its foregut cuticle, remaining viruliferous for months to years and transmitting to healthy vines during subsequent feeding. ||Resistance mechanisms include root tip anatomical features impeding stylet penetration, rapid cell death at feeding sites preventing sustained nutrition, chemical factors in root tissues deterring feeding initiation or causing nematode mortality, and overall poor host suitability reducing nematode reproduction and population buildup. ||Xiphinema_Index_Resistance_Disposition serves dual functions:protecting root system integrity from feeding damage and, more importantly, interrupting fanleaf virus transmission by eliminating or dramatically reducing vector populations. ||Muscadinia rotundifolia and certain North American Vitis species (V. arizonica, V. candicans, V. rufotomentosa) provide strong X. index resistance that has been introgressed into rootstock breeding lines, offering the most effective long-term strategy for managing fanleaf disease in infested vineyards.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Walker MA et al. (1994) Resistance to Xiphinema index in Vitis and its hybrids, Vitis 33:21-26|| Hwang CF et al. (2010) Fine mapping and characterization of XiR1, a locus for Xiphinema index resistance in grape, Theoretical and Applied Genetics 121:1749-1762|| Esmenjaud D, Bouquet A (2009) Selection and application of resistant germplasm for grapevine nematodes management, Integrated Management of Fruit Crops and Forest Nematodes, Springer"
  },
  "Meloidogyne_Resistance_Disposition": {
    "definition": "A Meloidogyne_Resistance_Disposition is a Nematode_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that limit infection, giant cell formation, gall development, or reproduction by root-knot nematodes of the genus Meloidogyne, sedentary endoparasites that induce characteristic root galls and cause significant damage to grapevine root systems worldwide.", 
    "alternative_term": "root-knot nematode resistance | Meloidogyne immunity | RKN resistance |+ Wurzelgallennematoden-Resistenz-Disposition | Meloidogyne-Resistenz | Wurzelknoten-Nematoden-Abwehr",
    "example_of_usage": "Systematic screening for Meloidogyne_Resistance_Disposition at the University of California Kearney Agricultural Research and Extension Center evaluated 55 rootstock genotypes against a mixed Meloidogyne population (predominantly M. incognita with M. javanica) using replicated pot assays. ||Vines were grown in inoculated soil (10,000 eggs per pot) for 4 months, then assessed for galling severity (0-10 scale), eggs per gram root, and root system health. ||Susceptible 'AXR#1' (V. vinifera × V. rupestris) exhibited severe galling (index 8.5), high reproduction (45,000 eggs/g root), and stunted, dysfunctional root systems. ||The resistant 'Freedom' (1613C × Dog Ridge) demonstrated strong Meloidogyne_Resistance_Disposition with minimal galling (index 0.8), low reproduction (850 eggs/g root, 98% reduction), and healthy root development. ||Histological examination revealed that J2 penetration occurred equally on resistant and susceptible roots, but on 'Freedom', attempted giant cell induction triggered hypersensitive cell death visible as localized browning within 48 hours, preventing establishment of functional feeding sites. ||Nematodes on resistant roots either died or developed into small, non-reproductive males rather than egg-producing females. ||This resistance mechanism demonstrates that Meloidogyne_Resistance_Disposition operates through post-penetration incompatibility disrupting the intimate host-parasite interaction required for nematode reproduction.",
    "editor_note": "Meloidogyne_Resistance_Disposition is_a Nematode_Resistance_Disposition. ||Root-knot nematodes require induction of giant cells for feeding and reproduction, making disruption of this process the primary resistance mechanism. ||Child classes address resistance to specific Meloidogyne species (M_Incognita_Resistance_Disposition, M_Javanica_Resistance_Disposition, M_Arenaria_Resistance_Disposition) as different genetic factors may confer species-specific resistance. ||Resistance-breaking Meloidogyne populations have been documented, particularly for M. arenaria, highlighting the importance of deploying multiple resistance sources and monitoring nematode population responses.  This disposition represents resistance to nematodes with a complex host-parasite interaction involving invasion of root tips by infective second-stage juveniles (J2), migration to the vascular cylinder, induction of specialized feeding sites (giant cells) through secretion of effector proteins, and completion of the life cycle within galled root tissue. ||On susceptible roots, Meloidogyne feeding induces formation of multinucleate giant cells that function as metabolic sinks providing nutrition to the developing female, accompanied by surrounding cell hyperplasia creating the visible root galls (knots). ||Heavy infestation disrupts root function, reduces water and nutrient uptake, and predisposes roots to secondary pathogen infection. ||Resistance mechanisms preventing or limiting root-knot nematode damage include hypersensitive response killing cells at initial J2 penetration sites, incompatibility preventing giant cell induction or maintenance, and failure to support nematode development to reproductive maturity. ||Three Meloidogyne species are particularly important in viticulture: M. incognita (southern root-knot nematode), M. javanica (Javanese root-knot nematode), and M. arenaria (peanut root-knot nematode), with resistance to each species potentially involving different genetic factors. ||Rootstock breeding has successfully incorporated Meloidogyne resistance from various Vitis species, with resistant rootstocks essential for productive viticulture in warm-climate regions with endemic root-knot nematode populations.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ferris H et al. (2012) Reflections on plant and soil nematode ecology: past, present and future, Journal of Nematology 44:115-126|| Anwar SA, McKenry MV (2002) Incidence and population density of plant-parasitic nematodes infecting vegetable crops and associated yield losses in Punjab, Pakistan, Pakistan Journal of Zoology 44:327-333|| Williamson VM, Kumar A (2006) Nematode resistance in plants: the battle underground, Trends in Genetics 22:396-403"
  },
  "M_Incognita_Resistance_Disposition": {
    "definition": "An M_Incognita_Resistance_Disposition is a Meloidogyne_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that specifically limit infection, giant cell formation, gall development, or reproduction by Meloidogyne incognita (southern root-knot nematode), the most widespread and economically important root-knot nematode species affecting viticulture in warm-climate regions worldwide.", 
    "alternative_term": "southern root-knot nematode resistance | M. incognita immunity | Mi-RKN resistance |+ M.-incognita-Resistenz-Disposition | Südlicher-Wurzelgallennematoden-Resistenz | M.-incognita-Abwehr",
    "example_of_usage": "Genetic mapping of M_Incognita_Resistance_Disposition at UC Davis utilized segregating populations from crosses involving the resistant rootstock 'Harmony' (1613C × 'Dog Ridge') to identify QTLs conditioning resistance. ||Phenotyping employed controlled inoculation with M. incognita race 3 (5,000 eggs per pot), with galling index and egg production assessed at 90 days. ||Resistance segregated as a dominant trait, with QTL analysis identifying a major locus on chromosome 9 explaining 65% of phenotypic variance for galling and 72% for reproduction, designated MiR1. ||Resistant individuals (MiR1/MiR1 or MiR1/mir1) exhibited galling indices of 0.5-2.0 and egg production below 1,000 per gram root, while susceptible individuals (mir1/mir1) showed galling of 7-9 and reproduction exceeding 30,000 eggs/g. ||Histopathological comparison revealed that J2 penetration occurred equally across genotypes, but resistant roots showed massive cell death surrounding attempted feeding sites by 72 hours post-penetration, with complete failure of giant cell establishment. ||The MiR1-linked marker VMC5g7 enables marker-assisted selection with 94% accuracy, accelerating introgression of M_Incognita_Resistance_Disposition into adapted rootstock backgrounds. ||Field trials confirmed that MiR1-positive selections maintained resistance over 8 years with no evidence of resistance-breaking nematode adaptation.",
    "editor_note": "M_Incognita_Resistance_Disposition is_a Meloidogyne_Resistance_Disposition. ||M. incognita is the most widespread root-knot nematode in viticulture, with four races differing in virulence. ||Resistance may be race-specific, with some rootstocks resistant to races 1 and 3 but susceptible to race 2. ||The MiR1 locus from V. champinii derivatives provides strong resistance to common races. ||M. incognita resistance is often correlated with but not identical to M. javanica resistance, as different recognition systems may be involved.  This disposition represents resistance to a polyphagous, highly adaptable nematode that reproduces parthenogenetically, enabling rapid population buildup on susceptible hosts, with four recognized races (races 1-4) differing in host range and virulence. ||M. incognita thrives in sandy, warm soils characteristic of many premium wine regions including California, Australia, South Africa, and Mediterranean countries, making resistance essential for sustainable production in these areas. ||Resistance mechanisms preventing M. incognita damage include hypersensitive response at penetration and migration sites, incompatibility preventing giant cell induction or maintenance specifically in response to M. incognita effector proteins, and root architectural or biochemical features limiting J2 establishment. ||The genetics of M. incognita resistance in Vitis involves multiple loci, with resistance sources identified in several species including V. champinii, V. rufotomentosa, and interspecific hybrids. ||The N gene from V. champinii confers resistance to M. incognita races 1 and 3, while additional factors provide broader coverage. ||Given the prevalence of M. incognita in global viticulture, M_Incognita_Resistance_Disposition is the primary root-knot nematode resistance objective in rootstock breeding programs, with multiple resistant commercial rootstocks available.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Cousins P, Walker MA (2002) Genetics of resistance to Meloidogyne incognita in crosses of grape rootstocks, Theoretical and Applied Genetics 105:802-807|| Ferris H et al. (2012) Reflections on plant and soil nematode ecology, Journal of Nematology 44:115-126|| Anwar SA, McKenry MV (2002) Developmental response of a resistance-breaking population of Meloidogyne arenaria on Vitis spp., Journal of Nematology 34:28-33"
  },
  "M_Javanica_Resistance_Disposition": {
    "definition": "An M_Javanica_Resistance_Disposition is a Meloidogyne_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that specifically limit infection, giant cell formation, gall development, or reproduction by Meloidogyne javanica (Javanese root-knot nematode), a thermophilic species with worldwide distribution in tropical and subtropical viticultural regions.", 
    "alternative_term": "Javanese root-knot nematode resistance | M. javanica immunity | Mj-RKN resistance |+ M.-javanica-Resistenz-Disposition | Javanischer-Wurzelgallennematoden-Resistenz | M.-javanica-Abwehr",
    "example_of_usage": "Comparative evaluation of M_Javanica_Resistance_Disposition versus M. incognita resistance at the Agricultural Research Organization, Volcani Center, Israel, tested 25 rootstock genotypes against both species in parallel pot assays to characterize resistance specificity. ||Roots were inoculated with 5,000 J2 of either M. javanica (local isolate from Negev vineyards) or M. incognita race 1, with galling and reproduction assessed at 90 days. ||Most rootstocks showed correlated responses, with 'Freedom', '1103 Paulsen', and 'Dog Ridge' exhibiting broad Meloidogyne resistance (galling index <2.0 for both species). ||However, differential responses occurred in some genotypes: '140 Ruggeri' showed strong M. incognita resistance (galling 1.5, reproduction factor RF 0.3) but moderate M. javanica susceptibility (galling 5.8, RF 8.2). ||Conversely, 'Ramsey' exhibited M_Javanica_Resistance_Disposition (galling 2.2, RF 1.5) but M. incognita susceptibility (galling 6.5, RF 15.3). ||These differential responses demonstrate that M_Javanica_Resistance_Disposition can be genetically distinct from M_Incognita_Resistance_Disposition, requiring species-specific screening when selecting rootstocks for regions where M. javanica predominates. ||For Israeli viticulture conditions, 'Freedom' and '1103 Paulsen' were recommended as providing reliable protection against the local M. javanica-dominated nematode complex.",
    "editor_note": "M_Javanica_Resistance_Disposition is_a Meloidogyne_Resistance_Disposition. ||M. javanica is the second most important root-knot nematode species in global viticulture, with particular prevalence in Australia, South Africa, and the Middle East. ||Resistance may overlap with M. incognita resistance through shared recognition mechanisms, but species-specific resistance also exists. ||Rootstock selection should be based on the predominant Meloidogyne species at the planting site, as differential resistance can result in resistance failure if species composition is not correctly identified.  This disposition represents resistance to a nematode that, like M. incognita, reproduces by obligate mitotic parthenogenesis and attacks a broad host range, but shows somewhat distinct distribution patterns, with M. javanica often predominating in warmer climates and heavier soils than typically favored by M. incognita. ||M. javanica is particularly prevalent in Australian, South African, Israeli, and Mediterranean basin viticulture, where it can cause severe damage to ungrafted V. vinifera and susceptible rootstocks. ||Resistance mechanisms may partially overlap with M. incognita resistance, as both species induce similar giant cell feeding sites and may be recognized by common plant surveillance systems. ||However, species-specific resistance also exists, with some rootstocks showing differential responses to M. javanica versus M. incognita, necessitating specific screening and selection for M. javanica resistance where this species predominates. ||The genetics of M. javanica resistance involves loci that may be distinct from or allelic to M. incognita resistance factors, with some resistant rootstocks effective against both species while others show species specificity. ||Field documentation of resistance stability over time is critical, as Meloidogyne populations can adapt to resistance under continuous selection pressure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "McKenry MV, Anwar SA (2006) Nematode and grape rootstock interactions including an improved understanding of tolerance, Journal of Nematology 38:312-318|| Walker GE (1997) Effects of Meloidogyne javanica and organic amendments on grapevine root systems, Australian Journal of Grape and Wine Research 3:33-42|| Ferris H et al. (2012) Reflections on plant and soil nematode ecology, Journal of Nematology 44:115-126"
  },
  "M_Arenaria_Resistance_Disposition": {
    "definition": "An M_Arenaria_Resistance_Disposition is a Meloidogyne_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that specifically limit infection, giant cell formation, gall development, or reproduction by Meloidogyne arenaria (peanut root-knot nematode), a species of particular concern in viticulture due to documented occurrences of resistance-breaking populations that overcome resistance effective against other Meloidogyne species.", 
    "alternative_term": "peanut root-knot nematode resistance | M. arenaria immunity | resistance-breaking RKN resistance |+ M.-arenaria-Resistenz-Disposition | Erdnuss-Wurzelgallennematoden-Resistenz | M.-arenaria-Abwehr",
    "example_of_usage": "Investigation of resistance-breaking M_Arenaria populations threatening M_Arenaria_Resistance_Disposition at UC Davis documented emergence of virulent nematodes in California vineyards planted continuously to resistant rootstocks. ||A population recovered from declining 'Freedom' vines in Fresno County (designated MA-FR) was compared with a standard laboratory M. arenaria isolate (MA-Lab) in inoculation assays on a rootstock panel. ||On the normally resistant 'Freedom', MA-Lab induced minimal galling (index 1.2) and reproduction (RF 0.8), confirming resistance. ||However, MA-FR overcame resistance, producing severe galling (index 7.5) and high reproduction (RF 22.5), demonstrating loss of effective M_Arenaria_Resistance_Disposition against this adapted population. ||Crucially, the alternative rootstock 'RS-3' (V. champinii × V. rupestris selection) maintained resistance against both populations (galling <1.5, RF <0.5), indicating that virulence to 'Freedom' did not confer broad resistance-breaking capacity. ||Molecular analysis suggested that MA-FR represented selection of pre-existing virulent genotypes within the original population rather than true resistance breakdown. ||These findings emphasize that M_Arenaria_Resistance_Disposition requires ongoing monitoring and management, with recommendations including rotation among rootstocks with different resistance backgrounds and integration of non-host cover crops to suppress nematode populations between vineyard cycles.",
    "editor_note": "M_Arenaria_Resistance_Disposition is_a Meloidogyne_Resistance_Disposition. ||M. arenaria presents unique challenges due to documented resistance-breaking populations, distinguishing it from M. incognita and M. javanica where resistance has generally proven more durable. ||The emergence of virulent populations highlights the evolutionary potential of nematode populations under continuous selection by resistant rootstocks. ||Management recommendations include avoiding monoculture of single resistance sources, monitoring nematode populations for virulence shifts, and maintaining integrated management approaches rather than relying solely on host resistance.  This disposition represents resistance to a nematode that, while generally less prevalent than M. incognita in vineyards, poses unique challenges through its demonstrated capacity to adapt to host resistance. ||M. arenaria populations virulent on previously resistant rootstocks have been identified in California and other regions, raising concerns about resistance durability and necessitating integrated management strategies beyond sole reliance on host resistance. ||The species includes two races with distinct host ranges, and additional pathotypes may exist with specific virulence patterns. ||Resistance mechanisms against M. arenaria parallel those effective against other Meloidogyne species, involving recognition and hypersensitive response to attempted giant cell induction, but the genetic basis may differ, and resistance effective against M. incognita does not guarantee M. arenaria resistance. ||The emergence of resistance-breaking M. arenaria populations highlights the importance of resistance gene stewardship, including rotation among rootstock resistance sources, avoiding planting resistant rootstocks continuously on infested sites, and combining host resistance with cultural and biological control tactics. ||Breeding for durable M_Arenaria_Resistance_Disposition requires screening against aggressive field-derived populations rather than laboratory-maintained isolates that may have lost virulence.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Anwar SA, McKenry MV (2002) Developmental response of a resistance-breaking population of Meloidogyne arenaria on Vitis spp., Journal of Nematology 34:28-33|| McKenry MV, Anwar SA (2006) Nematode and grape rootstock interactions including an improved understanding of tolerance, Journal of Nematology 38:312-318|| Ferris H et al. (2012) Reflections on plant and soil nematode ecology, Journal of Nematology 44:115-126"
  },
  "Pratylenchus_Resistance_Disposition": {
    "definition": "A Pratylenchus_Resistance_Disposition is a Nematode_Resistance_Disposition that inheres in a Vitis plant root system and is realized through defense processes that limit penetration, migration, feeding, or reproduction by lesion nematodes of the genus Pratylenchus, migratory endoparasites that cause extensive cortical necrosis as they feed and move through root tissues.", 
    "alternative_term": "lesion nematode resistance | Pratylenchus immunity | root lesion resistance |+ Pratylenchus-Resistenz-Disposition | Läsionsnematoden-Resistenz | Wandernematoden-Abwehr",
    "example_of_usage": "Evaluation of Pratylenchus_Resistance_Disposition at Agriculture and Agri-Food Canada, Summerland Research Station, assessed responses of 30 rootstock genotypes to Pratylenchus penetrans, the predominant lesion nematode in British Columbia and Pacific Northwest vineyards. ||Potted vines were inoculated with 3,000 mixed-stage P. penetrans per pot and assessed at 6 months for nematode reproduction (final population/initial inoculum = reproduction factor RF), root lesion severity (0-5 scale), and vine growth impact. ||Susceptible V. vinifera 'Chardonnay' (own-rooted) showed high reproduction (RF 18.5), severe lesioning (score 4.2), and 35% growth reduction. ||Several rootstocks demonstrated Pratylenchus_Resistance_Disposition, though resistance levels were generally more moderate than observed for Meloidogyne. '3309 Couderc' (V. riparia × V. rupestris) exhibited good resistance with RF 2.8, lesion score 1.5, and minimal growth impact (8% reduction). 'Schwarzmann' showed similar performance (RF 3.2, lesion score 1.8). ||Notably, some rootstocks highly resistant to Meloidogyne showed Pratylenchus susceptibility: 'Freedom' exhibited RF 12.5 and lesion score 3.5 for P. penetrans despite excellent Meloidogyne resistance, demonstrating that these resistance systems are genetically independent. ||For cool-climate sites with Pratylenchus pressure, '3309 Couderc' and related V. riparia hybrids provide the best available Pratylenchus_Resistance_Disposition.",
    "editor_note": "Pratylenchus_Resistance_Disposition is_a Nematode_Resistance_Disposition. ||Lesion nematodes (Pratylenchus spp.) have a migratory endoparasitic lifestyle distinct from sedentary Meloidogyne or ectoparasitic Xiphinema, requiring different resistance mechanisms. ||P. vulnus is most important in warm climates while P. penetrans predominates in cool regions. ||Resistance to Pratylenchus is genetically independent from Meloidogyne resistance, necessitating specific screening when both nematode groups are present. ||Fewer highly resistant rootstock options exist compared to Meloidogyne resistance, representing an area for continued breeding improvement.  This disposition represents resistance to nematodes with a fundamentally different parasitic strategy than either sedentary root-knot nematodes (Meloidogyne) or ectoparasitic dagger nematodes (Xiphinema), requiring distinct resistance mechanisms. ||Pratylenchus species, particularly P. vulnus (walnut lesion nematode) and P. penetrans (northern root-lesion nematode), damage grapevine roots through mechanical destruction and enzymatic degradation of cortical cells during feeding and migration, creating characteristic brown necrotic lesions that coalesce and can girdle roots. ||Unlike Meloidogyne, Pratylenchus does not induce specialized feeding structures, instead moving continuously through tissues and feeding on sequential cells, making hypersensitive response less effective as a resistance mechanism. ||Resistance mechanisms against Pratylenchus may include physical barriers (thick-walled cells, suberized layers) impeding migration, chemical factors (terpenes, phenolics) toxic to nematodes or inhibiting their digestive enzymes, and rapid wound healing limiting damage expansion. ||Pratylenchus resistance has received less breeding attention than Meloidogyne or Xiphinema resistance, but is important in cool-climate viticulture where P. penetrans predominates and in replant situations where P. vulnus can build to damaging levels. ||Resistance sources exist in various Vitis species, though fewer highly resistant rootstocks are commercially available compared to Meloidogyne-resistant options.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pinkerton JN et al. (1999) Responses of some grape rootstocks to ring nematode and root lesion nematode, American Journal of Enology and Viticulture 50:275-282|| Howland AD et al. (2014) Evaluation of grapevine rootstocks for resistance to the northern root-knot nematode and lesion nematode, American Journal of Enology and Viticulture 65:173-177|| McKenry MV (1992) Nematodes, Grape Pest Management, 2nd Edition, University of California Division of Agriculture and Natural Resources"
  },
  "Insect_Resistance_Disposition": {
    "definition": "An Insect_Resistance_Disposition is a Pest_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes that limit feeding, oviposition, development, or damage by phytophagous insects attacking grapevine foliage, shoots, flowers, or fruit.", 
    "alternative_term": "insect herbivore resistance | arthropod feeding resistance | entomological defense |+ Insektenresistenz-Disposition | Schadinsekten-Abwehr | Herbivoren-Insekten-Resistenz",
    "example_of_usage": "Integrated evaluation of Insect_Resistance_Disposition at the USDA-ARS San Joaquin Valley Agricultural Sciences Center assessed multiple insect pest responses across 30 cultivars and rootstocks using standardized bioassays and field monitoring. ||Choice and no-choice feeding tests quantified responses to glassy-winged sharpshooter (Homalodisca vitripennis), grape mealybug (Pseudococcus maritimus), variegated leafhopper (Erythroneura variabilis), and western grapeleaf skeletonizer (Harrisina brillians). ||V. vinifera 'Thompson Seedless' showed broad insect susceptibility with high sharpshooter feeding rates (4.2 probes/hour), mealybug population buildup (285 crawlers/vine at 60 days), leafhopper stippling covering 45% of leaf area, and complete defoliation by skeletonizer larvae. ||In contrast, V. arizonica accessions demonstrated multiple Insect_Resistance_Dispositions with 65% reduction in sharpshooter probing, 80% lower mealybug populations, leafhopper damage limited to 12% leaf area, and skeletonizer larvae showing 40% mortality on resistant foliage. ||Notably, insect resistance profiles were not uniformly correlated, with some genotypes showing strong leafhopper resistance but mealybug susceptibility, indicating independent genetic control of different Insect_Resistance_Dispositions. ||These findings inform both rootstock selection (for root-feeding insects) and scion breeding (for foliar and fruit insects), with particular emphasis on vector insects affecting disease transmission.",
    "editor_note": "Insect_Resistance_Disposition is_a Pest_Resistance_Disposition. ||This class encompasses resistance to all phytophagous insects affecting grapevine, parallel to Nematode_Resistance_Disposition and Phylloxera_Resistance_Disposition under Pest_Resistance_Disposition. ||Child classes include Leafhopper_Resistance_Disposition (including Pierce's disease vectors), Mealybug_Resistance_Disposition (leafroll virus vectors), Grape_Berry_Moth_Resistance_Disposition (fruit feeders), and Japanese_Beetle_Resistance_Disposition (foliage feeders). ||The vector relationships of leafhoppers and mealybugs with major viral and bacterial pathogens create important linkages between Insect_Resistance_Disposition and Pathogen_Resistance_Disposition hierarchies.  This disposition represents the capacity to resist the diverse insect herbivores that exploit grapevine as a food source or reproductive substrate, encompassing both direct feeders causing tissue damage and insect vectors transmitting plant pathogens. ||Major insect pests of grapevine include xylem-feeding sharpshooter leafhoppers (Cicadellidae: Cicadellini) that vector Xylella fastidiosa causing Pierce's disease, phloem-feeding leafhoppers (Cicadellidae: Typhlocybinae) causing stippling damage and reducing photosynthetic capacity, phloem-feeding mealybugs (Pseudococcidae) and soft scales (Coccidae) that vector Grapevine leafroll-associated viruses, lepidopteran berry and cluster feeders including grape berry moths (Tortricidae) that damage fruit and facilitate secondary infections, and foliage-feeding beetles (Scarabaeidae, Chrysomelidae) causing defoliation. ||Insect resistance mechanisms in plants include constitutive physical defenses (trichomes, tough tissues, surface waxes), preformed chemical defenses (phenolics, alkaloids, terpenoids), induced defenses triggered by herbivore feeding (proteinase inhibitors, volatile emissions attracting natural enemies), and tolerance mechanisms maintaining productivity despite insect damage. ||For grapevine specifically, the vector relationships of certain insects with devastating viral and bacterial pathogens elevate the importance of insect resistance beyond direct damage prevention, making leafhopper and mealybug resistance critical components of integrated disease management strategies.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Howe GA, Jander G (2008) Plant immunity to insect herbivores, Annual Review of Plant Biology 59:41-66|| Walling LL (2000) The myriad plant responses to herbivores, Journal of Plant Growth Regulation 19:195-216|| Daane KM et al. (2018) Ecology and management of grapevine insects, Integrated Pest Management in Viticulture, Burleigh Dodds Science Publishing"
  },
  "Leafhopper_Resistance_Disposition": {
    "definition": "A Leafhopper_Resistance_Disposition is an Insect_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit feeding, reproduction, or damage by leafhoppers (Hemiptera: Cicadellidae), a diverse family of phloem- and xylem-feeding insects including both direct pests causing stippling damage and critically important vectors of plant pathogens.", 
    "alternative_term": "Cicadellidae resistance | hopper resistance | leafhopper feeding deterrence |+ Zikaden-Resistenz-Disposition | Kleinzikaden-Resistenz | Blattzikaden-Abwehr",
    "example_of_usage": "Comparative assessment of Leafhopper_Resistance_Disposition at Texas A&M AgriLife Research evaluated responses to both xylem-feeding glassy-winged sharpshooter (Homalodisca vitripennis) and phloem-feeding grape leafhopper (Erythroneura elegantula) across 25 Vitis accessions using electrical penetration graph (EPG) monitoring and population development assays. ||EPG analysis revealed that H. vitripennis achieved sustained xylem ingestion (>30 minute continuous feeding bouts) on 92% of V. vinifera 'Chardonnay' test sessions but only 35% of sessions on V. arizonica b43-17, with resistant plants eliciting frequent stylet withdrawal and non-feeding probing behavior. ||For E. elegantula, oviposition choice tests showed 4.2-fold higher egg deposition on 'Chardonnay' (28 eggs/leaf) versus the resistant V. cinerea accession C166-026 (6.7 eggs/leaf), with subsequent nymphal survival of 78% versus 32% respectively. ||Importantly, Leafhopper_Resistance_Disposition against the two feeding guilds showed weak correlation (r = 0.34), with some genotypes resistant to sharpshooters but susceptible to grape leafhoppers and vice versa, indicating distinct resistance mechanisms targeting xylem- versus phloem-feeders. ||These findings support breeding strategies combining resistance sources effective against both leafhopper types for comprehensive protection in regions facing both Pierce's disease pressure and direct leafhopper damage.",
    "editor_note": "Leafhopper_Resistance_Disposition is_a Insect_Resistance_Disposition. ||Leafhoppers comprise two functionally distinct groups affecting grapevine: xylem-feeding sharpshooters (Pierce's disease vectors) and phloem-feeding grape leafhoppers (direct pests). ||Child classes include Glassy_Winged_Sharpshooter_Resistance_Disposition and Empoasca_Resistance_Disposition addressing these distinct pest groups. ||The vector importance of sharpshooters for Xylella fastidiosa creates critical linkage between Leafhopper_Resistance_Disposition and Pierces_Disease_Resistance_Disposition. ||Resistance mechanisms differ between xylem and phloem feeders due to their distinct target tissues and feeding behaviors.  This disposition represents resistance to insects that attack grapevine through piercing-sucking mouthparts, extracting plant fluids and potentially transmitting bacterial or phytoplasma pathogens during the feeding process. ||Leafhoppers affecting grapevine fall into two functional groups with distinct impacts: xylem-feeding sharpshooters (subfamily Cicadellinae, tribe Cicadellini and Proconiini) that vector Xylella fastidiosa causing Pierce's disease, and phloem-feeding leafhoppers (subfamily Typhlocybinae, particularly genera Erythroneura and Empoasca) that cause direct feeding damage through chlorophyll destruction and cell emptying, producing characteristic stippling and bronzing of leaves. ||Resistance mechanisms against leafhoppers include leaf surface properties (trichome density, epicuticular wax composition) affecting settling and probing behavior, vascular tissue characteristics influencing feeding efficiency, chemical factors in xylem or phloem sap deterring sustained feeding, and induced defenses reducing leafhopper performance. ||Given the devastating impact of Pierce's disease vectored by sharpshooters, Leafhopper_Resistance_Disposition has dual importance for direct damage reduction and pathogen transmission interruption, making it a priority trait for breeding in Pierce's disease-endemic regions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Backus EA et al. (2005) Sensory systems and behaviours which mediate hemipteran plant-feeding: a taxonomic overview, Journal of Insect Physiology 51:791-803|| Daane KM, Williams LE (2003) Manipulating vineyard irrigation amounts to reduce insect pest damage, Ecological Applications 13:1650-1666|| Brodbeck BV et al. (2011) Physiological and behavioral adaptations of three species of leafhoppers in response to the dilute nutrient content of xylem fluid, Journal of Insect Physiology 39:73-81"
  },
  "Glassy_Winged_Sharpshooter_Resistance_Disposition": {
    "definition": "A Glassy_Winged_Sharpshooter_Resistance_Disposition is a Leafhopper_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit feeding, reproduction, or Xylella fastidiosa transmission by the glassy-winged sharpshooter (Homalodisca vitripennis), a large xylem-feeding leafhopper that has emerged as the most important Pierce's disease vector in California and poses ongoing invasion threats to other viticultural regions.", 
    "alternative_term": "GWSS resistance | Homalodisca resistance | sharpshooter vector resistance |+ Glasflügelzikaden-Resistenz-Disposition | GWSS-Resistenz | Homalodisca-vitripennis-Abwehr",
    "example_of_usage": "Investigation of Glassy_Winged_Sharpshooter_Resistance_Disposition at UC Riverside employed video tracking and electrical penetration graph (EPG) analysis to characterize H. vitripennis feeding behavior on resistant versus susceptible Vitis genotypes. ||Adult sharpshooters were confined on test plants for 24-hour sessions with continuous EPG monitoring of feeding waveforms. ||On susceptible V. vinifera 'Chardonnay', sharpshooters achieved sustained xylem ingestion (X-wave) for mean cumulative duration of 14.2 hours per 24-hour session, with ingestion bouts averaging 85 minutes. ||On the PdR1-carrying resistant selection 94-27-008 (V. arizonica × V. vinifera), xylem ingestion duration was reduced to 8.5 hours with significantly more frequent stylet withdrawal events, though sustained feeding still occurred. ||Notably, 'Chardonnay' and 94-27-008 showed equivalent X. fastidiosa transmission rates when sharpshooters fed first on infected source plants and then on test plants (75% vs 72% transmission), indicating that the Glassy_Winged_Sharpshooter_Resistance_Disposition of 94-27-008 was insufficient to prevent inoculation. ||This finding confirms that PdR1-mediated Pierce's disease resistance operates through bacterial resistance mechanisms (limiting X. fastidiosa multiplication) rather than through vector deterrence, and that GWSS-specific resistance remains an unmet breeding objective that could enhance durability of existing bacterial resistance.",
    "editor_note": "Glassy_Winged_Sharpshooter_Resistance_Disposition is_a Leafhopper_Resistance_Disposition. ||H. vitripennis is the primary Pierce's disease vector in California, with vector efficiency and ecological characteristics that have transformed disease epidemiology since its 1990s invasion. ||This class addresses resistance to the insect vector, distinct from Pierces_Disease_Resistance_Disposition which addresses resistance to X. fastidiosa itself. ||Current Pierce's disease resistant cultivars rely on bacterial resistance (PdR1) rather than vector resistance. ||True GWSS-specific resistance could complement bacterial resistance for enhanced durability but has not been a primary breeding target due to the vector's polyphagous nature limiting impact of grapevine resistance alone.  This disposition represents resistance to an insect whose primary economic impact derives not from direct feeding damage—which is minimal despite prodigious xylem consumption rates of up to 100× body weight per day—but from its exceptional efficiency as a Xylella vector, capable of transmitting the bacterium within minutes of feeding on infected plants and retaining infectivity through adult molts. ||H. vitripennis is native to the southeastern United States but invaded California in the 1990s, where it has dramatically altered Pierce's disease epidemiology due to its large size enabling long-distance dispersal, broad host range supporting populations on numerous ornamental and crop plants, and overwintering adults that transmit X. fastidiosa in early spring when native vectors are inactive. ||Resistance mechanisms affecting H. vitripennis may include xylem sap composition deterring sustained feeding, physical properties of xylem vessels impeding stylet penetration, induced defenses triggered by probing that cause stylet withdrawal, and antixenosis reducing settling preference. ||While direct resistance to H. vitripennis feeding would complement Xylella resistance for comprehensive Pierce's disease protection, research has focused primarily on bacterial resistance (PdR1 locus) rather than vector resistance, as the vector's broad host range limits the impact of grapevine-specific deterrence.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Almeida RPP, Purcell AH (2003) Homalodisca vitripennis (Germar) (Hemiptera, Cicadellidae) transmission of Xylella fastidiosa to almond, Plant Disease 87:1255-1259|| Backus EA et al. (2012) EPG comparisons of feeding behavior and X. fastidiosa transmission rates by glassy-winged sharpshooter on Vitis vinifera and Nicotiana tabacum, Journal of Economic Entomology 105:629-637|| Blua MJ et al. (2001) The Glassy-winged Sharpshooter in California, Proceedings of the Pierce's Disease Research Symposium, California Department of Food and Agriculture"
  },
  "Empoasca_Resistance_Disposition": {
    "definition": "An Empoasca_Resistance_Disposition is a Leafhopper_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit feeding, oviposition, nymphal development, or damage by grape leafhoppers of the genus Empoasca and related typhlocybine leafhoppers (Erythroneura, Arboridia) that cause direct feeding injury through extraction of mesophyll and phloem cell contents.", 
    "alternative_term": "grape leafhopper resistance | Erythroneura resistance | typhlocybine leafhopper resistance |+ Empoasca-Resistenz-Disposition | Rebzikaden-Resistenz | Kleinzikaden-Abwehr",
    "example_of_usage": "Field evaluation of Empoasca_Resistance_Disposition at the Edmund Mach Foundation, San Michele all'Adige, Italy, monitored Empoasca vitis population development and damage across 18 cultivars in replicated vineyard plots under natural infestation over three seasons without insecticide application. ||Nymphal counts (per 25 leaves) and adult sticky trap catches provided population metrics, while damage was assessed using a 0-5 visual scale for stippling severity and chlorophyll content measurements (SPAD readings) as physiological indicators. ||The susceptible cultivar 'Müller-Thurgau' supported high populations (mean 85 nymphs per 25 leaves at peak), severe stippling (score 4.2), and 35% reduction in chlorophyll content. 'Riesling' demonstrated enhanced Empoasca_Resistance_Disposition with 60% lower nymph counts (34 per 25 leaves), moderate stippling (score 1.8), and only 12% chlorophyll reduction. ||Laboratory choice tests confirmed that E. vitis adults showed reduced settling (45% fewer) and oviposition (62% fewer eggs) on 'Riesling' versus 'Müller-Thurgau' leaf discs. ||Microscopic examination revealed that 'Riesling' possessed 2.3-fold higher trichome density on abaxial leaf surfaces, potentially impeding leafhopper movement and feeding. ||The correlation between trichome density and Empoasca_Resistance_Disposition across all cultivars was significant (r = -0.68), suggesting that this morphological trait contributes substantially to leafhopper deterrence and could be targeted in breeding programs.",
    "editor_note": "Empoasca_Resistance_Disposition is_a Leafhopper_Resistance_Disposition. ||This class addresses resistance to phloem-feeding grape leafhoppers (Empoasca, Erythroneura, and related typhlocybine genera) that cause direct stippling damage, distinct from Glassy_Winged_Sharpshooter_Resistance_Disposition addressing xylem-feeding Pierce's disease vectors. ||Multiple Empoasca and Erythroneura species affect grapevine in different regions with similar damage symptoms. ||These leafhoppers are not known vectors of major grapevine pathogens, making their importance purely economic through direct damage. ||Resistance mechanisms often involve leaf surface properties, particularly trichome density, which can be readily assessed and selected in breeding programs.  This disposition represents resistance to small (3-4mm) phloem-feeding leafhoppers that produce characteristic stippling damage visible as white to yellow speckling on leaves from emptied cells, progressing to leaf bronzing, marginal necrosis, and premature defoliation under heavy infestation. ||Unlike xylem-feeding sharpshooters, Empoasca and related genera are not known vectors of major grapevine pathogens, making their impact purely through direct feeding damage affecting photosynthetic capacity and, in severe cases, fruit ripening and vine vigor. ||Multiple Empoasca species affect grapevine in different regions: E. vitis (European grape leafhopper) in Europe, E. fabae (potato leafhopper) and Erythroneura elegantula (western grape leafhopper) in North America. ||Resistance mechanisms include leaf physical properties (trichome density, thickness, toughness) impeding settling and feeding, constitutive or induced chemical factors reducing palatability or nymphal survival, and rapid wound responses limiting damage from individual feeding events. ||Variation in leafhopper susceptibility among V. vinifera cultivars has been documented, with some traditional cultivars showing enhanced tolerance potentially reflecting historical selection in leafhopper-prone environments. ||Breeding for Empoasca_Resistance_Disposition could reduce insecticide requirements in regions with chronic leafhopper pressure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pavan F et al. (2000) Evaluation of damage caused by Empoasca vitis on grapevine, Integrated Control in Viticulture, IOBC/WPRS Bulletin 23:67-71|| Daane KM, Williams LE (2003) Manipulating vineyard irrigation amounts to reduce insect pest damage, Ecological Applications 13:1650-1666|| Fornasiero D et al. (2012) Empoasca vitis management in organic and integrated vineyards, IOBC/WPRS Bulletin 79:213-219"
  },
  "Mealybug_Resistance_Disposition": {
    "definition": "A Mealybug_Resistance_Disposition is an Insect_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit feeding, reproduction, population development, or Grapevine leafroll-associated virus transmission by mealybugs (Hemiptera: Pseudococcidae), phloem-feeding insects that have emerged as the most important vectors of grapevine leafroll disease in many viticultural regions.", 
    "alternative_term": "Pseudococcidae resistance | vine mealybug resistance | leafroll vector resistance |+ Schmierlaus-Resistenz-Disposition | Wollläuse-Resistenz | Pseudococciden-Abwehr",
    "example_of_usage": "Screening for Mealybug_Resistance_Disposition at Stellenbosch University, South Africa, evaluated vine mealybug (Planococcus ficus) population development and GLRaV-3 transmission across 20 cultivars using controlled infestation assays. ||Potted vines were infested with 50 adult female mealybugs, with population counts and honeydew production measured at 8 weeks. ||GLRaV-3 transmission was assessed using viruliferous mealybugs in separate assays with RT-PCR confirmation at 12 weeks post-exposure. ||Population development varied 3.5-fold among cultivars, from 420 individuals on highly susceptible 'Chenin Blanc' to 120 on less-susceptible 'Pinotage', with honeydew production correlated (r = 0.89) with population size. 'Pinotage' demonstrated moderate Mealybug_Resistance_Disposition with 35% lower adult female weight (0.82 mg versus 1.26 mg on 'Chenin Blanc'), suggesting reduced feeding quality, and 40% lower fecundity (185 versus 310 eggs per female). ||However, GLRaV-3 transmission rates did not differ significantly among cultivars (62-78%), indicating that even partial mealybug resistance was insufficient to prevent virus transmission under assay conditions. ||Analysis of phloem sap amino acid composition revealed no consistent differences between relatively resistant and susceptible cultivars. ||These findings suggest that meaningful Mealybug_Resistance_Disposition for leafroll management may require resistance levels beyond those naturally present in V. vinifera, potentially necessitating introgression from wild Vitis species.",
    "editor_note": "Mealybug_Resistance_Disposition is_a Insect_Resistance_Disposition. ||Mealybugs are the primary vectors of Grapevine leafroll-associated viruses, creating critical linkage between this class and Leafroll_Resistance_Disposition. ||Unlike Xiphinema resistance where strong sources exist in wild Vitis, no strong mealybug resistance has been identified in available germplasm. ||The cryptic feeding behavior of mealybugs (under bark, in clusters) complicates both management and resistance evaluation. ||Current leafroll management relies on clean planting material, roguing, and vector control rather than host resistance. ||Identifying or developing mealybug resistance remains an important but unfulfilled breeding objective.  This disposition represents resistance to soft-bodied, waxy-coated insects that colonize protected sites on vines including under bark, on roots, within leaf axils, and inside clusters, making them difficult to detect and control. ||Multiple mealybug species affect grapevine: the vine mealybug (Planococcus ficus) and grape mealybug (Pseudococcus maritimus) being most significant globally, with obscure mealybug (P. viburni), longtailed mealybug (P. longispinus), and citrus mealybug (Planococcus citri) regionally important. ||Beyond direct damage from sap extraction and honeydew contamination promoting sooty mold, mealybugs transmit Grapevine leafroll-associated viruses (GLRaVs) in a semi-persistent manner, acquiring and transmitting virus during feeding periods of minutes to hours. ||Resistance mechanisms may include bark physical properties limiting colonization of protected sites, phloem sap characteristics reducing feeding quality and reproductive success, induced defenses affecting mealybug performance, and volatile emissions recruiting natural enemies. ||Given the near-universal susceptibility of V. vinifera to GLRaVs and the absence of direct viral resistance, mealybug resistance represents a critical indirect pathway for leafroll disease management. ||However, strong genetic resistance to mealybugs has not been clearly identified in Vitis germplasm, and management currently relies on cultural practices, biological control, and insecticides.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Daane KM et al. (2012) Biology and management of mealybugs in vineyards, Arthropod Management in Vineyards, Springer|| Walton VM, Pringle KL (2004) Vine mealybug, Planococcus ficus (Signoret), a key pest in South African vineyards, South African Journal of Enology and Viticulture 25:57-62|| Almeida RPP et al. (2013) Ecology and management of grapevine leafroll disease, Frontiers in Microbiology 4:94"
  },
  "Grape_Berry_Moth_Resistance_Disposition": {
    "definition": "A Grape_Berry_Moth_Resistance_Disposition is an Insect_Resistance_Disposition that inheres in a Vitis plant cluster and is realized through defense processes that limit oviposition, larval establishment, feeding damage, or successful development by grape berry moths (Lepidoptera: Tortricidae), economically important pests whose larvae feed within developing flowers and ripening berries, causing direct crop loss and facilitating secondary infections.", 
    "alternative_term": "Lobesia resistance | grape berry moth tolerance | tortricid berry pest resistance |+ Traubenwickler-Resistenz-Disposition | Beeren-Motten-Resistenz | Lobesia-botrana-Abwehr",
    "example_of_usage": "Field evaluation of Grape_Berry_Moth_Resistance_Disposition at INRAE Bordeaux monitored Lobesia botrana infestation and damage across 25 cultivars in replicated plots without insecticide application over four seasons. ||Oviposition density (eggs per 50 clusters), larval penetration success (percent of eggs producing feeding larvae), and berry damage (percent of berries with entry holes or frass) were assessed at first and second generation peaks. 'Merlot' showed high susceptibility with 28 eggs per 50 clusters, 72% penetration success, and 18% berry damage at second generation. 'Cabernet Sauvignon' demonstrated enhanced Grape_Berry_Moth_Resistance_Disposition with equivalent oviposition (25 eggs per 50 clusters) but significantly lower penetration success (41%) and berry damage (8%). ||Laboratory bioassays revealed that neonate larvae offered 'Cabernet Sauvignon' berries showed 35% mortality during the critical first 24 hours of establishment versus 12% on 'Merlot', with surviving larvae exhibiting 25% longer development time. ||Berry skin puncture force was significantly higher for 'Cabernet Sauvignon' (0.85 N) than 'Merlot' (0.52 N), and correlation analysis across all cultivars showed significant relationship between skin mechanical resistance and larval establishment failure (r = 0.72). ||These findings indicate that Grape_Berry_Moth_Resistance_Disposition in 'Cabernet Sauvignon' operates primarily through berry physical properties impeding larval penetration, a trait potentially amenable to selection in breeding programs.",
    "editor_note": "Grape_Berry_Moth_Resistance_Disposition is_a Insect_Resistance_Disposition. ||Grape berry moths comprise multiple tortricid species in different regions (L. botrana in Europe, P. viteana in eastern North America), with similar biology and damage. ||Berry moth damage creates entry points for bunch rot fungi, linking this class to Botrytis_Resistance_Disposition through pest-disease interactions. ||Resistance mechanisms involving berry skin properties overlap with Thick_Skin_Disposition for Botrytis resistance, suggesting potential for combined selection. ||L. botrana is a quarantine pest in some regions including the United States following eradication of a 2009 California introduction.  This disposition represents resistance to a complex of tortricid moths affecting grapevine globally, including the European grapevine moth (Lobesia botrana) dominant in European, Middle Eastern, and recently South American viticulture, and the grape berry moth (Paralobesia viteana) important in eastern North American viticulture. ||Female moths oviposit on flower clusters or developing berries, with emerging larvae burrowing into reproductive tissues, destroying florets before bloom, hollowing developing berries, and creating wounds that serve as entry points for bunch rot pathogens including Botrytis cinerea, Aspergillus, and sour rot complexes. ||Resistance mechanisms may include cluster and berry physical properties (tough skin, compact cuticle) limiting larval penetration, chemical factors deterring oviposition or reducing larval survival, volatile profiles affecting host location by ovipositing females, and cluster architecture (loose clusters with exposed berries) reducing favorable oviposition sites and larval microhabitats. ||The intimate relationship between berry moth damage and secondary fungal infection means that Grape_Berry_Moth_Resistance_Disposition contributes to bunch rot management beyond direct pest control. ||Variation in berry moth susceptibility among cultivars has been documented, providing opportunities for breeding and cultivar selection in regions with chronic berry moth pressure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ioriatti C et al. (2011) Lobesia botrana (Lepidoptera: Tortricidae), a new pest of grapevine in the Americas, Journal of Economic Entomology 104:1037-1044|| Thiéry D, Moreau J (2005) Relative performance of European grapevine moth (Lobesia botrana) on grapes and other hosts, Oecologia 143:548-557|| Roehrich R, Boller E (1991) Tortricids in vineyards, Tortricid Pests: Their Biology, Natural Enemies and Control, Elsevier"
  },
  "Japanese_Beetle_Resistance_Disposition": {
    "definition": "A Japanese_Beetle_Resistance_Disposition is an Insect_Resistance_Disposition that inheres in a Vitis plant foliage and is realized through defense processes that limit feeding, aggregation, or damage by the Japanese beetle (Popillia japonica), an invasive scarabaeid beetle that has become a significant defoliating pest of grapevine in eastern North America and poses ongoing invasion threats to other regions including Europe.", 
    "alternative_term": "Popillia resistance | Japanese beetle tolerance | scarab beetle resistance |+ Japankäfer-Resistenz-Disposition | Popillia-japonica-Abwehr | Japankäfer-Fraßresistenz",
    "example_of_usage": "Systematic evaluation of Japanese_Beetle_Resistance_Disposition at Cornell University's New York State Agricultural Experiment Station compared feeding damage across 45 Vitis accessions under natural Japanese beetle pressure over five seasons in Geneva, NY. ||Defoliation was assessed weekly during the July-August beetle flight period using a 0-100% visual scale, with cumulative feeding expressed as beetle-days calculated from trap catches × defoliation integration. ||V. vinifera 'Concord' and V. labrusca hybrids showed high susceptibility with 65-80% defoliation at season peak and cumulative damage equivalent to 850-1,100 beetle-days. ||In contrast, V. vinifera 'Cayuga White' demonstrated strong Japanese_Beetle_Resistance_Disposition with only 15-25% peak defoliation and cumulative damage of 180-280 beetle-days despite equivalent beetle pressure. ||Laboratory choice tests confirmed field rankings: beetles offered paired leaf discs consistently consumed 3.8× more 'Concord' than 'Cayuga White' tissue over 24-hour trials. ||Phytochemical analysis revealed that 'Cayuga White' leaves contained 2.4-fold higher concentrations of quercetin glycosides, compounds with documented beetle-deterrent activity. ||Foliar application of quercetin extract to susceptible 'Concord' reduced beetle feeding by 45% in subsequent choice tests, providing proof-of-concept that the resistance mechanism involves feeding deterrent chemistry that could potentially be enhanced through breeding or management practices.",
    "editor_note": "Japanese_Beetle_Resistance_Disposition is_a Insect_Resistance_Disposition. ||P. japonica is an invasive pest from Asia established in eastern North America since 1916, with recent spread to Europe (first detections in Italy 2014, Switzerland 2017). ||Adult beetles cause damage through foliage skeletonization|| larvae feed on grass roots and do not affect grapevine directly. ||Variation in susceptibility among Vitis species and cultivars provides opportunities for cultivar selection in affected regions. ||The beetle's invasive spread trajectory suggests increasing importance for European viticulture in coming decades, making resistance research a proactive priority.  This disposition represents resistance to an insect whose adult stage causes the economically important damage through voracious feeding on leaf tissue between veins, producing characteristic \"skeletonized\" leaves with only the vascular network remaining. ||Japanese beetles are gregarious feeders, with initial feeding damage releasing aggregation pheromones that attract additional beetles, potentially resulting in rapid, severe defoliation of preferred host plants including grapevine. ||Heavy defoliation reduces photosynthetic capacity, delays fruit ripening, increases sunburn on exposed clusters, and weakens vines entering dormancy. ||Resistance mechanisms may include leaf chemical composition deterring feeding initiation or continuation, leaf physical properties (thickness, toughness, trichome density) reducing palatability, volatile profiles less attractive to host-seeking beetles, and induced defenses reducing nutritional quality or producing deterrent compounds following initial damage. ||Substantial variation in Japanese beetle feeding preference among Vitis species and V. vinifera cultivars has been documented, with some cultivars consistently showing reduced damage providing opportunities for cultivar selection and breeding. ||Japanese_Beetle_Resistance_Disposition is particularly relevant for eastern North American viticulture where the pest is established and expanding, and for European regions preparing for potential invasion.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hammons DL et al. (2009) Attraction of Japanese beetles to host plants and conspecific females, Journal of Economic Entomology 102:585-593|| Loughrin JH et al. (1996) Volatile compounds induced by Japanese beetle feeding on susceptible plants, Journal of Chemical Ecology 22:639-658|| Potter DA, Held DW (2002) Biology and management of the Japanese beetle, Annual Review of Entomology 47:175-205"
  },
  "Mite_Resistance_Disposition": {
    "definition": "A Mite_Resistance_Disposition is a Pest_Resistance_Disposition that inheres in a Vitis vinifera plant or plant part and is realized through defense processes that limit feeding, colonization, reproduction, or damage by phytophagous mites, microscopic arachnids that attack grapevine foliage, buds, and other tissues.", 
    "alternative_term": "phytophagous mite resistance | acarid resistance | mite feeding resistance |+ Milbenresistenz-Disposition | Phytophage-Milben-Resistenz | Spinnmilben-Abwehr",
    "example_of_usage": "Comprehensive evaluation of Mite_Resistance_Disposition at Oregon State University assessed responses to both eriophyid (Colomerus vitis) and tetranychid (Eotetranychus willamettei) mites across 35 cultivars in Willamette Valley vineyard trials. ||Erineum development was scored visually (0-5 scale for leaf coverage), while spider mite populations were monitored by leaf brushing counts (mites per leaf) at biweekly intervals through the growing season. ||Substantial cultivar variation in Mite_Resistance_Disposition was detected for both mite groups. ||V. vinifera 'Pinot Noir' showed high susceptibility to both pests, with erineum scores of 3.8 and peak spider mite densities of 45 per leaf requiring acaricide intervention. 'Müller-Thurgau' exhibited differential resistance, with low erineum formation (score 0.8) but high spider mite susceptibility (52 per leaf). ||Conversely, 'Gewürztraminer' supported extensive erineum (score 4.2) but maintained low spider mite populations (8 per leaf), potentially due to dense leaf trichomes harboring predatory Typhlodromus mites. ||The hybrid 'Maréchal Foch' demonstrated broad Mite_Resistance_Disposition with minimal erineum (score 0.5) and low spider mite populations (6 per leaf). ||These uncorrelated resistance patterns confirm that Mite_Resistance_Disposition comprises independent mechanisms targeting different mite groups, requiring separate evaluation and breeding approaches.",
    "editor_note": "Mite_Resistance_Disposition is_a Pest_Resistance_Disposition. ||This class encompasses resistance to all phytophagous mites affecting grapevine, organized into child classes by mite family: Eriophyid_Mite_Resistance_Disposition (gall-forming and bud-infesting eriophyoid mites) and Spider_Mite_Resistance_Disposition (tetranychid mites causing stippling). ||Resistance mechanisms and cultivar rankings differ between these mite groups, requiring separate consideration. ||Mites are arachnids, not insects, justifying their placement in a separate resistance class parallel to Insect_Resistance_Disposition.  This disposition represents the capacity to resist two ecologically and morphologically distinct groups of plant-feeding mites: eriophyid mites (Eriophyoidea) including the grape erineum mite (Colomerus vitis) and grape bud mite (C. vitis and Calepitrimerus vitis), and tetranychid spider mites (Tetranychidae) including the Pacific spider mite (Tetranychus pacificus), Willamette spider mite (Eotetranychus willamettei), and European red mite (Panonychus ulmi). ||These mite groups differ fundamentally in biology, feeding behavior, and damage symptoms: eriophyid mites are vermiform, highly host-specific, and induce characteristic gall structures (erinea) or bud abnormalities, while spider mites are oval-bodied, often polyphagous, and cause stippling damage through cell puncturing and chlorophyll extraction. ||Mite resistance mechanisms in plants include leaf surface properties (trichome density and morphology, epicuticular wax) affecting mite movement and feeding access, constitutive or induced chemical defenses (terpenoids, phenolics) toxic or deterrent to mites, rapid wound responses limiting feeding success, and domatia or other structures harboring predatory mites that provide biological control. ||For grapevine, mite management has traditionally relied on acaricides and conservation of natural enemies, but cultivar differences in mite susceptibility provide opportunities for host plant resistance as a component of integrated mite management.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duso C et al. (2010) Biological control of mites in European vineyards, Arthropod Management in Vineyards, Springer|| Walton VM et al. (2007) Relationship between rust mites Calepitrimerus vitis (Nalepa) and bud damage on selected grape cultivars, Vitis 46:66-70|| Helle W, Sabelis MW (1985) Spider Mites: Their Biology, Natural Enemies and Control, Elsevier"
  },
  "Eriophyid_Mite_Resistance_Disposition": {
    "definition": "An Eriophyid_Mite_Resistance_Disposition is a Mite_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit colonization, feeding, gall induction, or population development by eriophyid mites (Eriophyoidea), microscopic, worm-shaped mites that are highly specialized parasites of grapevine causing distinctive erineum galls on leaves and damaging buds.", 
    "alternative_term": "Eriophyoidea resistance | gall mite resistance | rust mite resistance |+ Gallmilben-Resistenz-Disposition | Eriophyiden-Resistenz | Pockenmilben-Abwehr",
    "example_of_usage": "Systematic screening for Eriophyid_Mite_Resistance_Disposition at Hochschule Geisenheim University evaluated Colomerus vitis erineum strain colonization across 50 cultivars using controlled mite transfer and natural field infestation. ||Detached leaf assays involved placing mite-infested leaf pieces on test cultivar leaves and scoring erineum development at 14 and 28 days post-transfer on a 0-5 scale based on gall coverage. ||Field assessment scored natural erineum development at mid-season. ||V. vinifera 'Silvaner' showed extreme susceptibility with rapid erineum development (score 4.5 at 14 days, 5.0 at 28 days in detached leaves|| 4.2 field score) covering over 60% of adaxial leaf surface with corresponding felt-like galls on abaxial surfaces. 'Riesling' demonstrated moderate Eriophyid_Mite_Resistance_Disposition (detached: 2.2 at 14 days, 2.8 at 28 days|| field: 1.8), with erineum development delayed and limited in extent. ||Remarkably, certain V. amurensis accessions exhibited apparent immunity with no erineum development (scores 0.0) despite successful mite transfer, suggesting complete resistance to gall induction. ||Microscopic examination revealed that attempted feeding on resistant V. amurensis leaves triggered rapid browning of contacted cells within 24 hours, preventing the coordinated epidermal proliferation required for erineum formation. ||This hypersensitive-like response parallels mechanisms observed in pathogen resistance, suggesting that Eriophyid_Mite_Resistance_Disposition may involve active recognition and defense rather than passive incompatibility.",
    "editor_note": "Eriophyid_Mite_Resistance_Disposition is_a Mite_Resistance_Disposition. ||Eriophyid mites include both gall-inducing (erineum strain of C. vitis) and non-gall-inducing (bud mite strain of C. vitis, rust mite C. vitis) forms, with different damage symptoms requiring separate assessment. ||Child classes include Erineum_Formation_Resistance_Disposition (resistance to leaf galling) and Bud_Mite_Resistance_Disposition (resistance to bud damage). ||Eriophyid mites are highly host-specific, with C. vitis found only on Vitis, limiting their ecological impact but ensuring consistent pest pressure in vineyards.  This disposition represents resistance to the grape erineum mite (Colomerus vitis), which in its erineum strain induces characteristic felt-like galls (erinea) on leaf undersides, and in its bud mite strain causes stunted, distorted shoot growth, as well as the grape rust mite (Calepitrimerus vitis), which damages buds and young foliage. ||Eriophyid mites are among the smallest arthropods (100-300 μm), possess only two pairs of legs, and feed by penetrating individual epidermal cells with their stylet-like mouthparts, either triggering abnormal cell proliferation forming galls or causing cell death and tissue scarring. ||Resistance mechanisms may include leaf anatomical features (stomatal density, trichome presence, epidermal cell properties) affecting mite access and feeding success, biochemical factors preventing or limiting gall induction, rapid cell death responses sacrificing attacked cells before gall development proceeds, and overall plant vigor enabling tolerance to mite damage. ||Eriophyid mite damage is generally considered of limited economic importance in commercial viticulture except where severe bud mite infestation reduces fruitfulness, but can be cosmetically problematic in direct-market operations and may serve as reservoirs for virus transmission in some systems.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duso C, de Lillo E (1996) Grape, Eriophyoid Mites: Their Biology, Natural Enemies and Control, Elsevier|| Smith LM, Stafford EM (1948) The bud mite and the erineum mite of grapes, Hilgardia 18:317-334|| Walton VM et al. (2007) Relationship between rust mites Calepitrimerus vitis and bud damage on selected grape cultivars, Vitis 46:66-70"
  },
  "Erineum_Formation_Resistance_Disposition": {
    "definition": "An Erineum_Formation_Resistance_Disposition is an Eriophyid_Mite_Resistance_Disposition that inheres in a Vitis plant leaf and is realized through defense processes that prevent or limit the induction and development of erinea—the characteristic felt-like galls formed on leaf surfaces in response to feeding by the erineum strain of the grape erineum mite (Colomerus vitis).", 
    "alternative_term": "erineum resistance | leaf gall mite resistance | Colomerus vitis gall resistance |+ Erineum-Bildungs-Resistenz-Disposition | Pockenmilben-Gallen-Resistenz | Filzgallen-Resistenz",
    "example_of_usage": "Mechanistic investigation of Erineum_Formation_Resistance_Disposition at INRAE Montpellier compared cellular responses to Colomerus vitis feeding in susceptible V. vinifera 'Carignan' versus resistant V. rupestris accessions using microscopy and gene expression analysis. ||Leaf pieces were infested with standardized mite numbers, and cellular responses were monitored at 24, 48, 72, and 168 hours post-infestation. ||On susceptible 'Carignan', mite feeding induced visible trichome proliferation at 48 hours, with recognizable erineum structures by 72 hours and fully developed felt-like galls by 168 hours. ||Trichome length increased 8-fold (from 50μm to 400μm) within developing erinea, and expression of trichome-associated genes (MYB transcription factors, structural genes) was strongly upregulated. ||On resistant V. rupestris, initial mite probing occurred normally, but by 24 hours, cells at and adjacent to feeding sites showed browning and collapse characteristic of hypersensitive response. ||No trichome proliferation was induced, and by 72 hours, mites had died or emigrated from the necrotic areas. ||Gene expression analysis revealed rapid upregulation of defense-associated genes (PR-1, chitinase, phenylalanine ammonia-lyase) in V. rupestris but not in 'Carignan' following mite feeding. ||These findings demonstrate that Erineum_Formation_Resistance_Disposition in V. rupestris involves active recognition of mite feeding and deployment of defense responses that sacrifice attacked cells rather than supporting gall development, mechanistically parallel to effector-triggered immunity against pathogens.",
    "editor_note": "Erineum_Formation_Resistance_Disposition is_a Eriophyid_Mite_Resistance_Disposition. ||Erinea are leaf galls specifically induced by the erineum strain of Colomerus vitis through manipulation of plant trichome development. ||Resistance operates by preventing the coordinated plant response required for gall formation, analogous to Gall_Formation_Resistance_Disposition against foliar phylloxera. ||Erineum damage is primarily cosmetic in commercial viticulture but may be problematic for fresh grape sales or vineyard tourism. ||Wild Vitis species, particularly V. rupestris and V. amurensis, provide potential resistance sources.  This disposition represents resistance to a specific host-parasite interaction in which mite feeding on the abaxial (lower) leaf epidermis triggers abnormal proliferation of epidermal trichomes, creating convex blisters visible on the adaxial (upper) surface with corresponding concave, felt-lined pockets on the lower surface where mites feed and reproduce within the protective trichome mass. ||Erineum development requires coordinated plant responses to mite feeding including localized suppression of normal developmental programs, induction of trichome initiation and hyper-elongation, and maintenance of the modified tissue as a favorable mite habitat. ||Erineum_Formation_Resistance_Disposition disrupts this sequence through alternative host responses including hypersensitive cell death at feeding sites preventing the coordinated tissue response, failure of epidermal cells to respond to mite-secreted effectors or growth regulators, constitutive trichome density that may physically impede mite access to preferred feeding sites, or rapid wound healing responses that abort incipient gall development. ||Substantial variation in erineum susceptibility exists among V. vinifera cultivars and wild Vitis species, with some genotypes essentially immune to erineum formation, providing genetic resources for understanding resistance mechanisms and potential breeding applications where erineum is economically or aesthetically problematic.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duso C, de Lillo E (1996) Grape, Eriophyoid Mites: Their Biology, Natural Enemies and Control, Elsevier|| Westphal E et al. (1990) Histological observations on grapevine leaves showing the erineum strain of Colomerus vitis (Acari: Eriophyidae), Entomologia Generalis 15:261-270|| Smith LM, Stafford EM (1948) The bud mite and the erineum mite of grapes, Hilgardia 18:317-334"
  },
  "Bud_Mite_Resistance_Disposition": {
    "definition": "A Bud_Mite_Resistance_Disposition is an Eriophyid_Mite_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that prevent or limit colonization, feeding, and damage within dormant and developing buds by bud-infesting eriophyid mites, particularly the bud mite strain of Colomerus vitis and the grape rust mite Calepitrimerus vitis.", 
    "alternative_term": "grape bud mite resistance | Colomerus bud strain resistance | bud eriophyid resistance |+ Knospenmilben-Resistenz-Disposition | Colomerus-Knospen-Resistenz | Knospengallmilben-Abwehr",
    "example_of_usage": "Long-term evaluation of Bud_Mite_Resistance_Disposition at the Viticulture Research Center Haro, Spain, monitored bud mite damage across 25 cultivars over 8 seasons in replicated vineyard blocks without acaricide application. ||Spring shoot damage was scored on a 0-5 scale assessing internode shortening, leaf distortion, and scar tissue presence, while fruitfulness was measured as clusters per shoot. ||The susceptible cultivar 'Garnacha Tinta' exhibited chronic bud mite damage with mean spring scores of 3.2, shortened first internodes (4.2 cm vs 8.5 cm in healthy vines), and 25% fruitfulness reduction (0.9 vs 1.2 clusters/shoot in protected controls). ||Damage severity varied substantially among seasons (scores 1.8-4.5) correlating with winter minimum temperatures affecting mite survival. 'Tempranillo' demonstrated strong Bud_Mite_Resistance_Disposition with consistently low damage scores (mean 0.6, range 0.2-1.1 across seasons), normal internode development, and no detectable fruitfulness impact despite equivalent mite populations detected in dormant bud dissections. ||Anatomical examination revealed that 'Tempranillo' buds possessed tighter scale overlap and denser scale trichomes than 'Garnacha', potentially limiting mite access to meristematic tissues. ||Additionally, 'Tempranillo' showed more rapid spring bud development, reducing the duration of susceptibility to mite feeding on undifferentiated tissues. ||These combined structural and phenological factors likely contribute to its Bud_Mite_Resistance_Disposition.",
    "editor_note": "Bud_Mite_Resistance_Disposition is_a Eriophyid_Mite_Resistance_Disposition. ||Bud mites include the bud strain of Colomerus vitis and Calepitrimerus vitis (grape rust mite), both of which overwinter in buds and damage developing shoots. ||Bud mite damage is more economically significant than erineum but more difficult to evaluate due to high environmental variability. ||Resistance appears to involve both structural (bud architecture) and phenological (rapid development) components. ||Bud mite biology differs sufficiently from the erineum strain that resistance may be independently controlled.  This disposition represents resistance to mites that overwinter within bud scales and feed on meristematic tissues during bud development, causing a spectrum of damage ranging from mild scarring and reduced leaf size to severe shoot stunting, shortened internodes, distorted leaves, and drastically reduced fruitfulness. ||Bud mite damage is often more economically significant than erineum damage, as severe infestations can reduce crop yields by 30-50% through destruction of developing inflorescences within buds. ||Resistance mechanisms potentially include bud architectural features limiting mite access to feeding sites, chemical factors within bud tissues toxic or deterrent to mites, rapid tissue differentiation reducing the window of susceptibility, and overall bud vigor enabling compensation for moderate mite damage. ||Bud mite damage is notoriously variable among vines and seasons, complicating resistance evaluation, as factors including vine stress, winter temperatures affecting mite survival, and spring weather affecting bud development interact with host genotype to determine damage severity. ||Nevertheless, consistent cultivar differences have been documented, with some cultivars showing chronic susceptibility while others rarely exhibit damage despite equivalent mite pressure, providing evidence for genetic variation in Bud_Mite_Resistance_Disposition amenable to selection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Walton VM et al. (2007) Relationship between rust mites Calepitrimerus vitis (Nalepa) and bud damage on selected grape cultivars, Vitis 46:66-70|| Bernard MB et al. (2005) Eriophyoid mite damage in Vitis vinifera (grapevine) in Australia: Calepitrimerus vitis and Colomerus vitis (Acari: Eriophyidae) as the causes of the damage, Experimental and Applied Acarology 35:207-223|| Smith LM, Stafford EM (1948) The bud mite and the erineum mite of grapes, Hilgardia 18:317-334"
  },
  "Spider_Mite_Resistance_Disposition": {
    "definition": "A Spider_Mite_Resistance_Disposition is a Mite_Resistance_Disposition that inheres in a Vitis plant and is realized through defense processes that limit colonization, feeding, reproduction, or population buildup of tetranychid spider mites (Tetranychidae), web-spinning mites that damage grapevine foliage through cell puncturing and chlorophyll extraction causing characteristic stippling and bronzing.", 
    "alternative_term": "Tetranychidae resistance | web-spinning mite resistance | red spider mite resistance |+ Spinnmilben-Resistenz-Disposition | Tetranychiden-Resistenz | Rote-Spinne-Abwehr",
    "example_of_usage": "Investigation of Spider_Mite_Resistance_Disposition at UC Davis examined both direct resistance factors and predator-mediated resistance across 30 cultivars, comparing Tetranychus pacificus population development in the presence and absence of the predatory mite Galendromus occidentalis. ||In predator-exclusion assays on detached leaves, T. pacificus reproduction varied 2.5-fold among cultivars, from 28 eggs per female over 5 days on susceptible 'Thompson Seedless' to 11 eggs on relatively resistant 'Cabernet Sauvignon'. ||This direct resistance correlated moderately with leaf toughness (r = -0.52) but not with trichome density. ||In field trials with natural predator populations, cultivar rankings shifted substantially: 'Chardonnay', with moderate direct resistance (18 eggs in lab assays), supported the lowest field populations (3.2 mites/leaf at season peak) due to exceptionally well-developed leaf domatia at vein axils harboring high G. occidentalis densities (0.85 predators/leaf). ||Conversely, 'Carignane' with equivalent direct resistance supported 4-fold higher field populations (12.8 mites/leaf) associated with poorly developed domatia (0.12 predators/leaf). ||When predators were experimentally supplemented on 'Carignane', spider mite populations declined to 'Chardonnay' levels, confirming that Spider_Mite_Resistance_Disposition operates substantially through tritrophic interactions. ||These findings emphasize that breeding for spider mite resistance should consider domatia development as a key trait influencing biological control potential alongside direct resistance factors.",
    "editor_note": "Spider_Mite_Resistance_Disposition is_a Mite_Resistance_Disposition. ||Spider mites (Tetranychidae) differ fundamentally from eriophyid mites in biology, morphology, and host specificity. ||Resistance mechanisms include both direct effects on mite performance and indirect effects mediated by predatory mite populations influenced by leaf domatia. ||The tritrophic nature of spider mite resistance, involving cultivar effects on predator abundance and efficacy, distinguishes it from most other pest resistances and has important implications for integrated mite management emphasizing predator conservation.  This disposition represents resistance to a functionally distinct mite group from eriophyids, with spider mites being larger (300-600 μm), oval-bodied, possessing four pairs of legs as adults, and often polyphagous rather than host-specialized. ||Major spider mite pests of grapevine include the Pacific spider mite (Tetranychus pacificus), two-spotted spider mite (T. urticae), Willamette spider mite (Eotetranychus willamettei), and European red mite (Panonychus ulmi), with species prevalence varying by region. ||Spider mites feed by inserting their cheliceral stylets into leaf mesophyll cells and extracting contents, causing chlorotic stippling that progresses to bronzing, leaf necrosis, and premature defoliation under heavy infestation, reducing photosynthetic capacity and delaying fruit ripening. ||Resistance mechanisms include leaf physical properties (trichome density and morphology, leaf toughness) affecting mite movement and feeding efficiency, constitutive or induced chemical defenses (terpenoids, phenolics) reducing mite survival or fecundity, and importantly, leaf domatia—small structures at vein axils that harbor predatory phytoseiid mites providing biological control. ||Spider mite resistance in grapevine is often mediated through tritrophic interactions involving predatory mites rather than direct antibiosis, making domatia-mediated resistance particularly significant.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Karban R et al. (1995) Induced resistance in wild tobacco with clipped sagebrush neighbors, Ecology 76:2165-2169|| English-Loeb GM et al. (2002) Tritrophic interactions and defense induction in grapevines, Induced Plant Resistance to Herbivory, Springer|| Duso C et al. (2010) Biological control of mites in European vineyards, Arthropod Management in Vineyards, Springer"
  },
  "Defense_Mechanism_Disposition": {
    "definition": "A Defense_Mechanism_Disposition is a Biotic_Stress_Resistance_Disposition that inheres in a Vitis vinifera plant and represents the underlying capacity to deploy specific defensive structures, compounds, or processes that protect against herbivores and pathogens, abstracted from the particular pest or pathogen being resisted.", 
    "alternative_term": "plant defense capacity | defense trait disposition | resistance mechanism |+ Verteidigungsmechanismus-Disposition | Abwehrmechanismus-Kapazität | Pflanzenabwehr-Disposition",
    "example_of_usage": "Comprehensive characterization of Defense_Mechanism_Disposition at the University of Udine assessed multiple constitutive and induced defense parameters across 20 cultivars to evaluate the breadth and coordination of defense capacity. ||Constitutive measures included cuticle thickness, trichome density, constitutive phenolic content, and preformed PR protein levels. ||Induced responses were assessed following Plasmopara viticola inoculation, measuring stilbene accumulation, PR gene expression, and callose deposition at 24, 48, and 72 hours post-inoculation. ||Principal component analysis revealed that Defense_Mechanism_Disposition varied substantially among cultivars and comprised largely independent components. 'Cabernet Sauvignon' exhibited strong constitutive physical defenses (thick cuticle 4.2 μm, high trichome density 28/mm²) but moderate chemical and induced responses. ||Conversely, 'Regent' (PIWI cultivar) showed modest constitutive barriers but exceptionally strong induced stilbene production (45 μg/g fresh weight at 48h versus 8 μg/g in 'Cabernet Sauvignon'). 'Muscadinia rotundifolia' demonstrated uniformly high Defense_Mechanism_Disposition across all measured parameters, consistent with its broad-spectrum disease resistance. ||These findings demonstrate that overall resistance phenotypes emerge from combinations of defense mechanisms varying independently among genotypes, with implications for breeding strategies targeting multiple defense components.",
    "editor_note": "Defense_Mechanism_Disposition is_a Biotic_Stress_Resistance_Disposition. ||This class provides a mechanistic perspective on resistance, complementing the pathogen/pest-specific resistance classes elsewhere in VVO. ||Child classes include Constitutive_Defense_Disposition (preformed defenses) and Induced_Defense_Disposition (activated upon attack). ||Defense mechanisms may contribute to resistance against multiple pathogens and pests sharing susceptibility to particular barriers or compounds, enabling prediction of resistance breadth from mechanistic knowledge.  This disposition captures the mechanistic basis of biotic stress resistance, complementing the pathogen-specific and pest-specific resistance classes that describe resistance outcomes against particular organisms. ||Defense mechanisms in plants are traditionally categorized as constitutive (preformed, always present) versus induced (activated upon attack), and as direct (affecting the attacker directly) versus indirect (recruiting natural enemies or signaling to neighboring plants). ||For grapevine, constitutive defenses include physical barriers such as cuticle, trichomes, and tough tissues, as well as preformed chemical defenses including phenolic compounds, antimicrobial proteins, and structural polymers. ||Induced defenses encompass the hypersensitive response, systemic acquired resistance, production of phytoalexins (particularly stilbenes in Vitis), pathogenesis-related proteins, and volatile emissions. ||Understanding defense mechanism dispositions enables prediction of resistance breadth across multiple attackers sharing susceptibility to particular mechanisms, identification of defense trade-offs and synergies, and targeted breeding for enhanced defense capacity rather than resistance to individual threats. ||The Defense_Mechanism_Disposition hierarchy provides a mechanistic framework complementing the taxonomically organized Pathogen_Resistance_Disposition and Pest_Resistance_Disposition hierarchies.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pieterse CMJ et al. (2012) Hormonal modulation of plant immunity, Annual Review of Cell and Developmental Biology 28:489-521|| Dicke M, Baldwin IT (2010) The evolutionary context for herbivore-induced plant volatiles: beyond the \"cry for help\", Trends in Plant Science 15:167-175|| Hammerschmidt R (1999) Phytoalexins: what have we learned after 60 years?, Annual Review of Phytopathology 37:285-306"
  },
  "Constitutive_Defense_Disposition": {
    "definition": "A Constitutive_Defense_Disposition is a Defense_Mechanism_Disposition that inheres in a Vitis vinifera plant and is realized through preformed defensive structures, compounds, or properties that are present regardless of pathogen or pest attack, providing a first line of defense without requiring recognition of specific threats or activation of induced responses.", 
    "alternative_term": "preformed defense | constitutive resistance | basal defense capacity |+ Konstitutive-Verteidigungs-Disposition | Präformierte-Abwehr | Basale-Abwehr-Kapazität",
    "example_of_usage": "Systematic quantification of Constitutive_Defense_Disposition at INRAE Colmar compared basal defense parameters in healthy, unchallenged leaves across 30 cultivars representing diverse genetic backgrounds. ||Physical parameters measured included cuticle thickness (transmission electron microscopy), adaxial and abaxial trichome density (light microscopy), stomatal density and aperture dimensions (SEM), and leaf toughness (penetrometer). ||Chemical parameters included total phenolics (Folin-Ciocalteu), flavonoid content (spectrophotometric), proanthocyanidin concentration (DMACA assay), and basal PR protein activity (chitinase, glucanase enzyme assays). ||V. vinifera cultivars showed wide variation in Constitutive_Defense_Disposition, with 'Gewürztraminer' exhibiting high physical investment (cuticle 4.8 μm, trichome density 42/mm²) but low chemical defense (total phenolics 18 mg/g), while 'Tannat' showed the inverse pattern (cuticle 2.1 μm, trichomes 8/mm², but phenolics 52 mg/g). ||The PIWI cultivar 'Solaris' demonstrated high constitutive chemical defense (phenolics 48 mg/g, proanthocyanidins 12 mg/g) combined with moderate physical barriers. ||Wild species V. riparia exhibited the highest overall Constitutive_Defense_Disposition with thick cuticle (5.2 μm), dense trichomes (65/mm²), and high phenolics (58 mg/g). ||Correlation analysis revealed that physical and chemical constitutive defenses were largely independent (r = 0.18), suggesting separate genetic control and potential for combining both defense modes through breeding.",
    "editor_note": "Constitutive_Defense_Disposition is_a Defense_Mechanism_Disposition. ||This class encompasses all preformed defenses present without pathogen/pest challenge, contrasting with Induced_Defense_Disposition requiring activation. ||Child classes include Physical_Barrier_Disposition (structural defenses) and Chemical_Defense_Disposition (preformed compounds). ||Constitutive and induced defenses may act synergistically, with constitutive barriers slowing initial infection while induced responses mount, or may represent alternative defense strategies varying among genotypes.  This disposition represents the baseline defensive capacity present in healthy, unchallenged plants, encompassing both physical barriers that impede attacker access or establishment and chemical defenses that are toxic, deterrent, or antimicrobial without requiring de novo synthesis upon attack. ||Constitutive defenses in grapevine include structural features such as cuticle thickness and composition, trichome density and morphology, stomatal characteristics, cell wall composition and lignification, and tissue toughness, as well as preformed chemical defenses including phenolic compounds (flavonoids, hydroxycinnamic acids, tannins), antimicrobial proteins (chitinases, glucanases, thaumatin-like proteins at basal levels), and secondary metabolites with deterrent or toxic properties. ||The relative investment in constitutive versus induced defenses represents a fundamental trade-off in plant defense strategy, with constitutive defenses providing immediate protection but incurring ongoing metabolic costs, while induced defenses are metabolically economical but require time for deployment. ||Grapevine cultivars vary substantially in constitutive defense investment, with some relying primarily on preformed barriers while others emphasize rapid, strong induced responses, and the most resistant genotypes often combining both strategies effectively.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Wittstock U, Gershenzon J (2002) Constitutive plant toxins and their role as defenses against herbivores and pathogens, Current Opinion in Plant Biology 5:300-307|| Underwood W (2012) The plant cell wall: a dynamic barrier against pathogen invasion, Frontiers in Plant Science 3:85|| Lattanzio V et al. (2006) Role of phenolics in the resistance mechanisms of plants against fungal pathogens and insects, Phytochemistry: Advances in Research, Research Signpost"
  },
  "Physical_Barrier_Disposition": {
    "definition": "A Physical_Barrier_Disposition is a Constitutive_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through structural features of plant surfaces and tissues that physically impede pathogen penetration, pest feeding, or attacker establishment independent of chemical toxicity or induced responses.", 
    "alternative_term": "structural defense | anatomical barrier | physical resistance mechanism |+ Physikalische-Barriere-Disposition | Strukturelle-Abwehr | Anatomische-Barriere",
    "example_of_usage": "Integrated analysis of Physical_Barrier_Disposition at Hochschule Geisenheim University characterized structural defense parameters across 25 cultivars and correlated them with resistance phenotypes against multiple pathogens. ||Cuticle properties (thickness, wax load, contact angle as hydrophobicity measure), trichome characteristics (density on adaxial and abaxial surfaces, trichome type distribution), stomatal parameters (density, guard cell dimensions), and leaf toughness (specific leaf area, punch resistance) were quantified on fully expanded leaves. ||Multiple regression analysis related Physical_Barrier_Disposition parameters to infection severity by Plasmopara viticola (penetrating via stomata), Erysiphe necator (penetrating cuticle directly), and Botrytis cinerea (requiring wound or senescent tissue entry). ||Stomatal density on abaxial surfaces (range 120-285 stomata/mm²) was the strongest predictor of downy mildew severity (r = 0.71), with low-stomatal cultivars including 'Riesling' (135/mm²) showing 45% less infection than high-stomatal 'Silvaner' (268/mm²). ||Cuticle thickness (range 1.8-5.2 μm) predicted powdery mildew establishment (r = -0.58), while trichome density showed no relationship with foliar pathogens but correlated significantly with leafhopper resistance (r = -0.65). ||These findings demonstrate that different Physical_Barrier_Disposition components provide protection against specific attacker guilds based on their infection biology, enabling targeted selection for particular threat profiles.",
    "editor_note": "Physical_Barrier_Disposition is_a Constitutive_Defense_Disposition. ||This class encompasses structural defenses functioning through physical properties rather than chemical toxicity. ||Child classes include Cuticle_Thickness_Disposition, Trichome_Density_Disposition, and Stomatal_Density_Disposition addressing specific barrier types. ||The effectiveness of particular barriers depends on attacker biology, with stomatal density most relevant for stomatal-penetrating pathogens (downy mildew), cuticle properties for direct-penetrating pathogens (powdery mildew), and trichomes for arthropod pests.  This disposition represents the anatomical and morphological component of constitutive defense, encompassing structures that function as passive barriers by virtue of their physical properties including thickness, toughness, hydrophobicity, or architecture. ||Major physical barriers in grapevine include the cuticle (cuticular membrane with embedded and epicuticular waxes covering all aerial surfaces), trichomes (epidermal appendages varying in density, morphology, and distribution), stomatal characteristics (density, size, and regulation affecting pathogen entry), cell wall properties (thickness, composition, lignification), and tissue architecture (compactness, air spaces, vascular arrangement). ||Physical barriers provide non-specific defense effective against diverse attackers sharing requirements for surface attachment, penetration, or tissue access. ||The effectiveness of physical barriers depends on both quantitative parameters (cuticle thickness, trichome density) and qualitative features (wax crystal morphology, trichome type), with substantial genetic variation among grapevine cultivars and species providing material for breeding enhancement. ||Physical barriers often interact with chemical defenses, as cuticle and cell walls may contain embedded antimicrobial compounds, and trichomes may produce or store defensive metabolites.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Underwood W (2012) The plant cell wall: a dynamic barrier against pathogen invasion, Frontiers in Plant Science 3:85|| Yeats TH, Rose JKC (2013) The formation and function of plant cuticles, Plant Physiology 163:5-20|| Hanley ME et al. (2007) Plant structural traits and their role in anti-herbivore defence, Perspectives in Plant Ecology, Evolution and Systematics 8:157-178"
  },
  "Cuticle_Thickness_Disposition": {
    "definition": "A Cuticle_Thickness_Disposition is a Physical_Barrier_Disposition that inheres in a Vitis vinifera plant and is realized through the development of a thick cuticular membrane covering aerial plant surfaces, providing enhanced resistance to pathogen penetration, reduced water loss, and protection against environmental stresses.", 
    "alternative_term": "cuticular membrane thickness | cuticle development | epicuticular barrier |+ Kutikuladicke-Disposition | Kutikula-Entwicklung | Wachsschicht-Stärke",
    "example_of_usage": "Quantitative analysis of Cuticle_Thickness_Disposition at the University of Adelaide characterized cuticular properties across 18 wine grape cultivars on both leaves and berries using transmission electron microscopy and chemical extraction methods. ||Leaf cuticle thickness (measured on mature, fully expanded leaves at véraison) ranged from 1.9 μm ('Pinot Noir') to 4.8 μm ('Cabernet Sauvignon'), while berry cuticle thickness at harvest ranged from 2.4 μm ('Pinot Noir') to 6.2 μm ('Grenache'). ||Cuticle thickness was moderately heritable (h² = 0.52 for leaves, 0.61 for berries) and showed strong organ correlation (r = 0.78 between leaf and berry thickness within cultivars). ||Controlled inoculation experiments demonstrated that Cuticle_Thickness_Disposition significantly affected powdery mildew establishment, with infection success (appressorial penetration rate) negatively correlated with leaf cuticle thickness (r = -0.68). ||Cultivars with thick cuticles including 'Cabernet Sauvignon' (4.8 μm) showed 55% lower penetration success than thin-cuticle 'Pinot Noir' (1.9 μm) at equivalent inoculum loads. ||For Botrytis, berry cuticle thickness was inversely correlated with unwounded infection severity (r = -0.72), with 'Grenache' (6.2 μm) showing 75% lower infection than 'Pinot Noir' (2.4 μm) under controlled humidity chamber conditions. ||These findings validate Cuticle_Thickness_Disposition as a selectable trait contributing to disease resistance.",
    "editor_note": "Cuticle_Thickness_Disposition is_a Physical_Barrier_Disposition. ||Cuticle thickness affects resistance to direct-penetrating pathogens (powdery mildew, Botrytis) but not stomatal-penetrating pathogens (downy mildew). ||Thickness is one aspect of cuticular defense alongside wax composition, crystal morphology, and hydrophobicity. ||Berry cuticle thickness is particularly important for bunch rot resistance, relating to Cuticle_Based_Resistance_Disposition under Botrytis_Resistance_Disposition, though the present class addresses the mechanistic trait rather than resistance to a specific pathogen.  This disposition represents the quantitative aspect of cuticle development, with thicker cuticles generally providing greater barrier function against direct-penetrating pathogens and environmental challenges. ||The plant cuticle is a continuous hydrophobic layer covering all aerial organs, composed of a cutin polyester matrix embedded with waxes (intracuticular) and overlaid by epicuticular wax crystals, together forming the primary interface between the plant and its environment. ||In grapevine, cuticle thickness varies substantially among organs (berries typically thicker than leaves), developmental stages (increasing during maturation), and genotypes (2-6 μm range among cultivars on mature leaves). ||Thick cuticles impede direct penetration by pathogens such as Erysiphe necator (powdery mildew), which must breach the cuticle to access epidermal cells, and Botrytis cinerea, which secretes cutinases to degrade the cuticle during infection. ||Additionally, thick cuticles reduce pathogen adhesion, limit diffusion of pathogen enzymes and toxins, and decrease the effectiveness of cutinase-mediated penetration. ||Cuticle_Thickness_Disposition is particularly relevant for berry resistance to bunch rots, where thick berry cuticles represent a primary defense against post-véraison infection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Yeats TH, Rose JKC (2013) The formation and function of plant cuticles, Plant Physiology 163:5-20|| Comménil P et al. (1997) Host-pathogen interactions during infection of grape berries by Botrytis cinerea, VITIS Journal of Grapevine Research 36:193-198|| Dry IB, Thomas MR (2015) Molecular genetics of grape berry ripening, Advances in Botanical Research 74:325-361"
  },
  "Trichome_Density_Disposition": {
    "definition": "A Trichome_Density_Disposition is a Physical_Barrier_Disposition that inheres in a Vitis vinifera plant and is realized through the development of dense epidermal trichomes (plant hairs) on leaf surfaces and other organs, providing physical impediment to arthropod pest movement and feeding, modification of leaf surface microclimate, and in some cases, chemical defense through glandular secretions.", 
    "alternative_term": "leaf pubescence | trichome development | epidermal hair density |+ Trichom-Dichte-Disposition | Blattbehaarung | Epidermale-Haardichte",
    "example_of_usage": "Evaluation of Trichome_Density_Disposition effects on arthropod resistance at Cornell University characterized trichome parameters and pest responses across 28 cultivars spanning the pubescence range in cultivated Vitis. ||Trichome density was quantified by microscopy on abaxial leaf surfaces at two positions (near midrib, near margin), with counts expressed as trichomes per mm². ||Cultivars ranged from essentially glabrous ('Chardonnay', 4 trichomes/mm²) to densely tomentose ('Concord', 85 trichomes/mm²), with intermediate types including 'Cabernet Sauvignon' (22/mm²) and 'Gewürztraminer' (48/mm²). ||Potato leafhopper (Empoasca fabae) colonization showed strong negative correlation with Trichome_Density_Disposition (r = -0.82), with choice tests confirming active avoidance of pubescent surfaces. ||Hopperburn damage severity correlated similarly (r = -0.78), with tomentose 'Concord' (85/mm²) showing no detectable damage while glabrous 'Chardonnay' (4/mm²) sustained 65% leaf area affected. ||For grape leafhopper (Erythroneura comes), the relationship was weaker (r = -0.45), suggesting partial but incomplete deterrence. ||Importantly, trichome density showed positive correlation with Typhlodromus pyri predatory mite abundance (r = 0.58), indicating that pubescent cultivars support enhanced biological control of spider mites. ||These findings demonstrate that Trichome_Density_Disposition provides broad protection against multiple pest groups while enhancing natural enemy habitat.",
    "editor_note": "Trichome_Density_Disposition is_a Physical_Barrier_Disposition. ||Trichomes primarily affect arthropod pests rather than pathogens, with density being the most important parameter for small insect and mite resistance. ||The effect varies among pest species and may be positive (physical barrier, predator habitat) or negative (microhabitat for certain pests) depending on context. ||Grapevine trichomes are predominantly non-glandular, distinguishing their function from glandular trichomes in other plant families that produce toxic or sticky secretions.  This disposition represents the quantitative development of trichomes, with higher densities generally providing greater protection against small arthropod pests including leafhoppers, spider mites, and thrips that must navigate the trichome forest to access feeding sites. ||Grapevine trichomes are predominantly non-glandular, consisting of simple unicellular or multicellular hairs varying in length, density, and distribution among organs, surfaces (adaxial versus abaxial), and genotypes. ||Trichome density on abaxial (lower) leaf surfaces shows particularly wide genetic variation in Vitis, from nearly glabrous cultivars to densely tomentose types with felt-like pubescence. ||Dense trichomes impede pest movement by creating physical obstacles, interfere with stylet insertion by small piercing-sucking insects, modify boundary layer humidity affecting pest development and pathogen germination, and provide refugia for predatory mites contributing to biological control. ||Conversely, dense trichomes may create favorable microhabitats for certain pests and pathogens, and the relationship between trichome density and defense varies with the specific attacker. ||Trichome_Density_Disposition is readily observable and highly heritable, making it amenable to selection in breeding programs targeting arthropod resistance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Hanley ME et al. (2007) Plant structural traits and their role in anti-herbivore defence, Perspectives in Plant Ecology, Evolution and Systematics 8:157-178|| Dalin P et al. (2008) Leaf trichome formation and plant resistance to herbivory, Induced Plant Resistance to Herbivory, Springer|| Karban R et al. (1995) Induced resistance in wild tobacco with clipped sagebrush neighbors, Ecology 76:2165-2169"
  },
  "Stomatal_Density_Disposition": {
    "definition": "A Stomatal_Density_Disposition is a Physical_Barrier_Disposition that inheres in a Vitis vinifera plant leaf and is realized through the developmental specification of stomatal frequency per unit leaf area, affecting the number of potential entry points for stomatal-penetrating pathogens and influencing leaf gas exchange characteristics.", 
    "alternative_term": "stomatal frequency | stomatal patterning | guard cell density |+ Spaltöffnungsdichte-Disposition | Stomatäre-Frequenz | Stomata-Dichte",
    "example_of_usage": "Investigation of Stomatal_Density_Disposition effects on downy mildew susceptibility at INRAE Bordeaux quantified stomatal parameters and P. viticola infection across 22 cultivars under controlled inoculation conditions. ||Stomatal density was determined by microscopy on cleared abaxial leaf surfaces, with parallel measurements of stomatal aperture dimensions and calculated stomatal conductance index. ||Density ranged from 118 stomata/mm² ('Riesling') to 312/mm² ('Merlot'), representing a 2.6-fold variation among commercial cultivars. ||Controlled inoculation with P. viticola sporangia suspension revealed significant correlation between Stomatal_Density_Disposition and infection establishment (r = 0.71), with low-density 'Riesling' (118/mm²) showing 52% fewer infection sites per unit leaf area than high-density 'Merlot' (312/mm²) at equivalent inoculum concentration. ||When infection was expressed per stomata (site-specific infection probability), cultivar differences diminished substantially (range 0.12-0.18 infections/stomata), confirming that stomatal density rather than stomatal-specific resistance explained much of the cultivar variation. ||Microscopic observation confirmed that zoospores encysted preferentially near stomata regardless of cultivar, with penetration success per stomatal encounter similar across genotypes. ||These findings demonstrate that Stomatal_Density_Disposition contributes meaningfully to quantitative downy mildew resistance through a simple geometric mechanism of reduced entry point availability.",
    "editor_note": "Stomatal_Density_Disposition is_a Physical_Barrier_Disposition. ||Stomatal density specifically affects pathogens using stomatal penetration, primarily Plasmopara viticola among major grapevine diseases. ||Density is genetically controlled and environmentally stable, making it a reliable selection target. ||Trade-offs with gas exchange capacity and potential effects on water use efficiency must be considered in breeding applications. ||The disposition addresses stomatal number rather than stomatal function or regulation, which involve different genetic and physiological systems.  This disposition represents the quantitative aspect of stomatal patterning, with density varying substantially among grapevine cultivars (typically 100-350 stomata/mm² on abaxial surfaces) due to genetic differences in stomatal initiation and spacing during leaf development. ||Stomata, the pores formed by paired guard cells that regulate gas exchange, serve as primary infection courts for several important grapevine pathogens, most notably Plasmopara viticola (downy mildew), which releases zoospores that swim to stomata, encyst, and penetrate through the stomatal pore to initiate infection. ||Higher stomatal density provides more potential entry points per unit leaf area, increasing the probability of successful pathogen establishment following inoculation. ||Beyond direct entry point considerations, stomatal density influences leaf transpiration rate, boundary layer humidity, and water status under stress, creating complex interactions between Stomatal_Density_Disposition and disease susceptibility. ||Breeding for reduced stomatal density could theoretically enhance downy mildew resistance, though trade-offs with photosynthetic capacity and water use efficiency must be considered, and the magnitude of density effects relative to other resistance factors determines practical breeding value.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Díez-Navajas AM et al. (2008) Comparative study of the role of stomata in susceptibility of wild grapevine (Vitis vinifera subsp. sylvestris) to downy mildew, VITIS Journal of Grapevine Research 47:21-26|| Hetherington AM, Woodward FI (2003) The role of stomata in sensing and driving environmental change, Nature 424:901-908|| Gindro K et al. (2003) Cellular and molecular changes in grapevine (Vitis vinifera) leaves in response to infection by Plasmopara viticola, VITIS Journal of Grapevine Research 42:225-234"
  },
  "Chemical_Defense_Disposition": {
    "definition": "A Chemical_Defense_Disposition is a Constitutive_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through the preformed presence of secondary metabolites and proteins with antimicrobial, antifungal, insecticidal, or feeding-deterrent properties in plant tissues, providing chemical protection against pathogens and pests without requiring induced synthesis upon attack.", 
    "alternative_term": "preformed chemical defense | constitutive phytochemical defense | basal antimicrobial capacity |+ Chemische-Verteidigungs-Disposition | Präformierte-chemische-Abwehr | Konstitutive-Phytochemische-Verteidigung",
    "example_of_usage": "Comprehensive metabolomic analysis of Chemical_Defense_Disposition at the Edmund Mach Foundation characterized constitutive secondary metabolite profiles in healthy leaves of 35 cultivars using LC-MS-based untargeted metabolomics. ||Total phenolic content ranged from 12 mg gallic acid equivalents/g fresh weight ('Müller-Thurgau') to 58 mg/g ('Tannat'), with specific compound classes showing even wider variation. ||Constitutive flavonol content (quercetin and kaempferol glycosides) varied 8-fold (2.1-16.8 mg/g), hydroxycinnamic acids (caftaric, coutaric acids) 4-fold (3.2-12.8 mg/g), and proanthocyanidins 12-fold (0.8-9.6 mg/g) among cultivars. ||Correlation with pathogen resistance phenotypes revealed compound class-specific relationships. ||Constitutive stilbene levels (primarily piceid) correlated with downy mildew resistance (r = -0.52 with infection severity), while proanthocyanidin content predicted Botrytis resistance (r = -0.61 with berry infection). ||Flavonol content showed strongest association with powdery mildew resistance (r = -0.48). ||In vitro bioassays confirmed that purified grapevine phenolics inhibited pathogen growth in a dose-dependent manner, with 50% inhibition concentrations ranging from 25-150 μg/mL depending on compound and pathogen. ||These findings demonstrate that Chemical_Defense_Disposition comprises multiple semi-independent compound classes with differential effects on specific pathogens, enabling targeted breeding for enhanced chemical defense against particular disease threats.",
    "editor_note": "Chemical_Defense_Disposition is_a Constitutive_Defense_Disposition. ||This class encompasses preformed chemical defenses present before attack, complementing Physical_Barrier_Disposition and contrasting with induced chemical defenses under Induced_Defense_Disposition. ||Child classes include Constitutive_Phenolic_Disposition and Preformed_Antimicrobial_Disposition addressing major compound categories. ||Chemical defenses interact with physical barriers, as phenolics may be incorporated into cuticle and cell walls, and with induced defenses, as basal compound pools may be augmented upon attack.  This disposition represents the biochemical component of constitutive defense, encompassing the diverse array of specialized metabolites and defensive proteins that accumulate in healthy plant tissues and contribute to basal resistance. ||Grapevine chemical defenses include phenolic compounds (flavonoids, hydroxycinnamic acids, stilbenes at basal levels, proanthocyanidins/tannins), terpenoids (monoterpenes, sesquiterpenes), antimicrobial proteins (chitinases, glucanases, thaumatin-like proteins, defensins at constitutive levels), and cell wall-associated compounds (lignin, suberin precursors). ||The concentration, composition, and tissue distribution of constitutive chemical defenses vary substantially among grapevine cultivars and species, contributing to differences in basal resistance even before induced defenses are activated. ||Chemical defenses may function through direct toxicity to attackers, inhibition of pathogen enzymes (protease inhibitors, chitinase inhibitors), membrane disruption (saponins, certain phenolics), or feeding deterrence (tannins, bitter compounds). ||The relationship between Chemical_Defense_Disposition and resistance depends on the specific attacker and defense compounds involved, as pathogens and pests vary in their sensitivity to particular chemical classes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lattanzio V et al. (2006) Role of phenolics in the resistance mechanisms of plants against fungal pathogens and insects, Phytochemistry: Advances in Research, Research Signpost|| Wittstock U, Gershenzon J (2002) Constitutive plant toxins and their role as defenses against herbivores and pathogens, Current Opinion in Plant Biology 5:300-307|| Dixon RA (2001) Natural products and plant disease resistance, Nature 411:843-847"
  },
  "Constitutive_Phenolic_Disposition": {
    "definition": "A Constitutive_Phenolic_Disposition is a Chemical_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through high basal accumulation of phenolic compounds—secondary metabolites derived from the phenylpropanoid pathway—providing broad-spectrum antimicrobial, antioxidant, and anti-herbivore defense properties.", 
    "alternative_term": "basal phenolic content | constitutive polyphenol defense | preformed phenylpropanoid defense |+ Konstitutive-Phenol-Disposition | Basaler-Phenolgehalt | Präformierte-Phenylpropanoid-Abwehr",
    "example_of_usage": "Evaluation of Constitutive_Phenolic_Disposition effects on multiple pathogen resistance at UC Davis characterized phenolic profiles and disease susceptibility across 25 cultivars representing the phenolic content range in cultivated grapevine. ||Total phenolics, measured by Folin-Ciocalteu assay on healthy leaf tissue, ranged from 14 mg GAE/g ('Chasselas') to 62 mg/g ('Petit Verdot'). ||HPLC profiling quantified major compound classes including hydroxycinnamic acids, flavonols, flavan-3-ols, and stilbenes at basal levels. ||Controlled inoculation experiments tested resistance to P. viticola, E. necator, and B. cinerea. ||Multiple regression revealed that Constitutive_Phenolic_Disposition parameters explained 35-55% of resistance variation depending on pathogen. ||Flavan-3-ol content (catechin, epicatechin) was the strongest predictor of E. necator resistance (partial r² = 0.28), consistent with in vitro inhibition of conidial germination by these compounds. ||Hydroxycinnamic acid content predicted P. viticola resistance (partial r² = 0.21), while proanthocyanidin levels correlated most strongly with B. cinerea resistance (partial r² = 0.32), reflecting the importance of tannins in restricting necrotrophic pathogen colonization. ||The high-phenolic cultivar 'Petit Verdot' (62 mg/g total phenolics) showed 40-60% less infection across all three pathogens compared to low-phenolic 'Chasselas' (14 mg/g), demonstrating that strong Constitutive_Phenolic_Disposition provides broad-spectrum, though partial, resistance enhancement.",
    "editor_note": "Constitutive_Phenolic_Disposition is_a Chemical_Defense_Disposition. ||Phenolics are the most abundant and diverse class of grapevine secondary metabolites, with established roles in defense. ||This class addresses basal phenolic content in healthy tissues, complementing induced stilbene synthesis (under Induced_Defense_Disposition) and specific phenolic subclasses addressed elsewhere. ||Phenolic content affects both disease resistance and wine quality, creating potential synergies or trade-offs requiring consideration in breeding applications.  This disposition represents one of the most important chemical defense systems in grapevine, as Vitis is notably rich in diverse phenolic compounds including flavonoids (flavonols, flavan-3-ols, anthocyanins), non-flavonoid phenolics (hydroxycinnamic acids, hydroxybenzoic acids, stilbenes), and polymeric phenolics (proanthocyanidins/condensed tannins, lignin). ||Constitutive phenolic defense operates through multiple mechanisms including direct antimicrobial activity (membrane disruption, enzyme inhibition), antioxidant scavenging of pathogen-generated reactive oxygen species, protein precipitation (tannin-protein complexes reducing digestibility), feeding deterrence through astringency and bitterness, and precursor availability for rapid induced defense responses. ||Phenolic content and composition vary dramatically among grapevine cultivars, tissues, and developmental stages, with red-fruited cultivars typically accumulating higher levels than white, and young tissues often showing higher concentrations than mature organs. ||The relationship between Constitutive_Phenolic_Disposition and resistance is generally positive but compound class-specific, as different phenolic subgroups show varying potency against particular pathogens and pests. ||Breeding for enhanced Constitutive_Phenolic_Disposition could improve broad-spectrum resistance while potentially affecting wine quality parameters that are strongly influenced by grape phenolic composition.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lattanzio V et al. (2006) Role of phenolics in the resistance mechanisms of plants against fungal pathogens and insects, Phytochemistry: Advances in Research, Research Signpost|| Cheynier V et al. (2013) Plant phenolics: recent advances on their biosynthesis, genetics, and ecophysiology, Plant Physiology and Biochemistry 72:1-20|| Dixon RA (2001) Natural products and plant disease resistance, Nature 411:843-847"
  },
  "Preformed_Antimicrobial_Disposition": {
    "definition": "A Preformed_Antimicrobial_Disposition is a Chemical_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through constitutive accumulation of proteins and small molecules with direct antimicrobial activity against bacteria, fungi, and oomycetes, providing immediate defense upon pathogen contact without requiring induced synthesis.", 
    "alternative_term": "basal antimicrobial activity | constitutive PR proteins | preformed antifungal compounds |+ Präformierte-antimikrobielle-Disposition | Basale-antimikrobielle-Aktivität | Konstitutive-PR-Proteine",
    "example_of_usage": "Characterization of Preformed_Antimicrobial_Disposition at the Julius Kühn-Institut quantified basal antimicrobial protein activity and correlated it with disease resistance across 20 cultivars. ||Healthy leaf protein extracts were analyzed for chitinase activity (colorimetric assay with colloidal chitin), β-1,3-glucanase activity (reducing sugar release from laminarin), and total antifungal activity (radial diffusion assay against Botrytis cinerea). ||Basal chitinase activity ranged from 12 nkat/mg protein ('Müller-Thurgau') to 48 nkat/mg ('Regent'), while glucanase activity ranged from 8 to 35 nkat/mg across the same cultivars. ||Direct antifungal activity in diffusion assays showed 2.5-fold variation, with PIWI cultivars ('Regent', 'Solaris') exhibiting the highest inhibition zones. ||Cultivars with strong Preformed_Antimicrobial_Disposition showed significantly faster containment of pathogen spread following inoculation with P. viticola and B. cinerea, with 'Regent' (high basal PR activity) limiting lesion expansion to 3.2 mm at 72 hours post-inoculation compared to 8.5 mm in low-activity 'Müller-Thurgau'. ||Proteomic analysis revealed that 'Regent' maintained 3-fold higher constitutive levels of PR-2, PR-3, and PR-5 proteins compared to susceptible cultivars, potentially reflecting its interspecific hybrid background combining defense gene complements from multiple Vitis species. ||These findings demonstrate that Preformed_Antimicrobial_Disposition contributes to rapid pathogen containment independent of induced response kinetics.",
    "editor_note": "Preformed_Antimicrobial_Disposition is_a Chemical_Defense_Disposition. ||This class addresses direct antimicrobial compounds and proteins at constitutive (pre-attack) levels, complementing induced antimicrobial responses (phytoalexin production, PR protein induction) under Induced_Defense_Disposition. ||Basal PR protein levels vary among genotypes and may explain differences in early infection containment before induced defenses reach full activity. ||PIWI cultivars often show elevated basal antimicrobial activity reflecting their interspecific hybrid backgrounds.  This disposition represents the protein and specialized metabolite components of chemical defense that directly attack or inhibit microbial pathogens through mechanisms distinct from the general antioxidant and protein-precipitating activities of bulk phenolics. ||Preformed antimicrobials in grapevine include pathogenesis-related proteins at basal expression levels (PR-2 β-1,3-glucanases, PR-3 chitinases, PR-4 chitin-binding proteins, PR-5 thaumatin-like proteins, PR-14 lipid transfer proteins), defensins and other antimicrobial peptides, and specialized metabolites with direct antifungal activity (certain stilbenes, pterostilbene at basal levels). ||These compounds function by degrading pathogen cell wall components (glucanases, chitinases), disrupting pathogen membranes (defensins, lipid transfer proteins), inhibiting pathogen enzymes, or directly killing pathogen cells. ||The constitutive levels of antimicrobial proteins vary among grapevine genotypes, with some cultivars and wild species maintaining higher basal expression providing enhanced first-line defense before induced responses are fully activated. ||Preformed_Antimicrobial_Disposition complements physical barriers by providing chemical attack on pathogens that successfully breach surface defenses, and serves as a foundation that can be rapidly augmented through induced defense pathways upon pathogen recognition.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "van Loon LC et al. (2006) Significance of inducible defense-related proteins in infected plants, Annual Review of Phytopathology 44:135-162|| Monteiro S et al. (2003) Structural and functional aspects of PR-10 proteins, FEBS Letters 541:1-7|| Ferreira RB et al. (2007) The wine proteins, Trends in Food Science and Technology 18:293-306"
  },
  "Induced_Defense_Disposition": {
    "definition": "An Induced_Defense_Disposition is a Defense_Mechanism_Disposition that inheres in a Vitis vinifera plant and is realized through defense responses that are activated upon recognition of pathogen or pest attack, involving de novo synthesis of defensive compounds, activation of defense-related genes, and deployment of cellular defense mechanisms not present or active in unchallenged plants.", 
    "alternative_term": "inducible defense capacity | activated defense response | dynamic defense disposition |+ Induzierte-Verteidigungs-Disposition | Aktivierbare-Abwehr | Dynamische-Abwehr-Kapazität",
    "example_of_usage": "Systematic characterization of Induced_Defense_Disposition at INRAE Colmar compared defense induction kinetics across 25 cultivars following Plasmopara viticola inoculation. ||Leaf discs were inoculated with sporangia suspension and harvested at 0, 6, 12, 24, 48, and 72 hours post-inoculation for gene expression analysis (qRT-PCR of defense marker genes), metabolite profiling (stilbenes by HPLC), and histochemical staining (callose, H₂O₂, cell death). ||Cultivars varied dramatically in Induced_Defense_Disposition parameters. ||The PIWI cultivar 'Regent' exhibited rapid, strong induction with stilbene synthase (STS) expression increasing 85-fold by 12 hours, resveratrol accumulating to 45 μg/g by 24 hours, and visible hypersensitive response (HR) cell death by 48 hours limiting pathogen spread. ||Susceptible 'Müller-Thurgau' showed delayed, weak induction with STS expression only 8-fold elevated at 24 hours, resveratrol reaching 6 μg/g at 48 hours, and no detectable HR. ||Intermediate cultivar 'Riesling' displayed moderate induction kinetics (25-fold STS at 18 hours, 18 μg/g resveratrol at 36 hours). ||Principal component analysis revealed that induction speed (time to 50% maximum response) and magnitude (maximum fold-change) were partially independent, with some cultivars showing fast but weak responses and others slow but ultimately strong accumulation. ||These findings demonstrate that Induced_Defense_Disposition comprises multiple parameters amenable to independent selection.",
    "editor_note": "Induced_Defense_Disposition is_a Defense_Mechanism_Disposition. ||This class encompasses all defense responses activated upon pathogen/pest attack, contrasting with Constitutive_Defense_Disposition representing preformed defenses. ||Child classes include Hypersensitive_Response_Disposition (cell death-based defense), Phytoalexin_Production_Disposition (induced antimicrobial metabolites), and Pathogenesis_Related_Protein_Disposition (induced defense proteins). ||Induced and constitutive defenses typically act synergistically, with constitutive barriers slowing initial infection while induced responses mount.  This disposition represents the dynamic, responsive component of plant defense, complementing constitutive defenses by enabling targeted, amplified responses to specific threats while avoiding the metabolic costs of maintaining high defense levels continuously. ||Induced defenses in grapevine encompass the hypersensitive response (rapid programmed cell death at infection sites), phytoalexin production (particularly stilbenes including resveratrol and viniferins), pathogenesis-related protein accumulation (chitinases, glucanases, thaumatin-like proteins, and others), cell wall reinforcement (callose deposition, lignification, cross-linking), systemic acquired resistance (SAR) providing whole-plant protection following local infection, and volatile emission signaling to neighboring plants and recruiting natural enemies. ||The speed, magnitude, and specificity of induced responses vary substantially among grapevine genotypes, with resistant cultivars typically showing faster, stronger, and more sustained induction compared to susceptible cultivars challenged with the same pathogen. ||Understanding Induced_Defense_Disposition provides mechanistic insight into resistance differences among cultivars and enables breeding strategies targeting enhanced inducibility rather than elevated constitutive defense, potentially avoiding fitness costs associated with continuous high defense investment.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pieterse CMJ et al. (2012) Hormonal modulation of plant immunity, Annual Review of Cell and Developmental Biology 28:489-521|| Jones JDG, Dangl JL (2006) The plant immune system, Nature 444:323-329|| Hammerschmidt R (1999) Phytoalexins: what have we learned after 60 years?, Annual Review of Phytopathology 37:285-306"
  },
  "Hypersensitive_Response_Disposition": {
    "definition": "A Hypersensitive_Response_Disposition is an Induced_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to execute rapid, localized programmed cell death at sites of pathogen recognition, sacrificing infected and immediately adjacent cells to create a hostile environment that limits pathogen growth, reproduction, and spread to surrounding healthy tissue.", 
    "alternative_term": "HR capacity | programmed cell death defense | localized cell death response |+ Hypersensitive-Reaktions-Disposition | Programmierter-Zelltod-Abwehr | HR-Kapazität",
    "example_of_usage": "Detailed characterization of Hypersensitive_Response_Disposition at the University of Udine compared HR kinetics and pathogen containment across grapevine genotypes with and without the Rpv3 downy mildew resistance locus. ||Leaf discs were inoculated with P. viticola sporangia and assessed at 12-hour intervals for HR markers including trypan blue staining (cell death), DAB staining (H₂O₂ accumulation), and autofluorescence (phenolic accumulation at death sites). ||Resistant 'Bianca' (Rpv3-positive) exhibited strong Hypersensitive_Response_Disposition with H₂O₂ accumulation detectable at infection sites within 12 hours post-inoculation (hpi), cell death visible by 24 hpi, and complete HR lesion formation by 48 hpi. ||HR lesions were tightly confined (mean diameter 0.3 mm), with pathogen sporulation completely suppressed. ||Susceptible 'Chasselas' (Rpv3-negative) showed no HR, with diffuse pathogen colonization and abundant sporulation by 96 hpi covering 60% of disc area. ||The partial resistance cultivar 'Solaris' (Rpv3/Rpv10 combination) displayed enhanced Hypersensitive_Response_Disposition with faster HR initiation (H₂O₂ at 8 hpi) and smaller lesions (0.15 mm), correlating with stronger resistance. ||Importantly, HR-negative 'Chasselas' inoculated with the necrotroph Botrytis cinerea showed equivalent infection to HR-positive genotypes, confirming that Hypersensitive_Response_Disposition provides specific benefit against biotrophs rather than broad-spectrum resistance.",
    "editor_note": "Hypersensitive_Response_Disposition is_a Induced_Defense_Disposition. ||HR is typically associated with effector-triggered immunity (ETI) mediated by R gene recognition of pathogen effectors. ||In grapevine, HR is central to Rpv-mediated downy mildew resistance and Run/Ren-mediated powdery mildew resistance. ||HR effectiveness depends on speed and spatial containment—too slow or too extensive HR may fail to provide protection. ||HR is ineffective against necrotrophs like Botrytis that benefit from host cell death, representing a fundamental trade-off in defense strategy.  This disposition represents one of the most effective plant defense mechanisms against biotrophic pathogens that require living host cells for nutrition and reproduction, effectively starving the pathogen by eliminating its food source. ||The hypersensitive response (HR) is typically triggered by recognition of pathogen effector proteins by plant resistance (R) proteins, initiating a signaling cascade involving reactive oxygen species (ROS) burst, nitric oxide production, calcium influx, MAPK activation, and ultimately activation of cell death programs. ||In grapevine, HR is observed in resistant responses to multiple pathogens including Plasmopara viticola (in Rpv-mediated resistance), Erysiphe necator (in Run/Ren-mediated resistance), and phylloxera (in root and foliar resistance). ||The speed, intensity, and spatial containment of HR vary among genotypes, with effective resistance requiring HR rapid enough to confine pathogens before significant colonization occurs and spatially restricted enough to minimize self-damage. ||Hypersensitive_Response_Disposition is particularly relevant for resistance to obligate biotrophic pathogens but may be ineffective or counterproductive against necrotrophs like Botrytis cinerea that thrive on dead tissue.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mur LAJ et al. (2008) The hypersensitive response|| the centenary is upon us but how much do we know?, Journal of Experimental Botany 59:501-520|| Künstler A et al. (2016) Staying alive—is cell death dispensable for plant disease resistance during the hypersensitive response?, Physiological and Molecular Plant Pathology 93:75-84|| Allegre M et al. (2009) Stomatal deregulation in Plasmopara viticola-infected grapevine leaves, New Phytologist 173:832-840"
  },
  "Phytoalexin_Production_Disposition": {
    "definition": "A Phytoalexin_Production_Disposition is an Induced_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to synthesize and accumulate phytoalexins—low molecular weight antimicrobial compounds produced de novo or dramatically upregulated in response to pathogen attack, stress, or elicitor treatment.", 
    "alternative_term": "inducible phytoalexin capacity | stilbene phytoalexin production | antimicrobial compound induction |+ Phytoalexin-Produktions-Disposition | Induzierbare-Stilben-Kapazität | Antimikrobielle-Verbindungs-Induktion",
    "example_of_usage": "Comprehensive analysis of Phytoalexin_Production_Disposition at the University of Bordeaux characterized stilbene induction across 30 cultivars using standardized UV-C elicitation and Plasmopara viticola challenge. ||Leaf discs were exposed to UV-C (254 nm, 15 minutes) or inoculated with P. viticola sporangia, then harvested at 24, 48, and 72 hours for stilbene profiling by HPLC-MS. ||Total stilbene accumulation at 48 hours post-UV ranged from 8 μg/g fresh weight ('Chasselas', low inducer) to 125 μg/g ('Regent', high inducer), representing 15-fold variation in Phytoalexin_Production_Disposition. ||Profile analysis revealed cultivar-specific patterns: 'Regent' produced predominantly trans-resveratrol (45%) and ε-viniferin (35%), while 'Merzling' accumulated higher proportions of pterostilbene (25%) and δ-viniferin (20%). ||Following P. viticola inoculation, high-inducing cultivars showed strong negative correlation between stilbene accumulation and sporulation intensity (r = -0.78), confirming biological relevance of Phytoalexin_Production_Disposition for disease resistance. ||Time-course analysis revealed that induction speed varied independently from maximum accumulation, with 'Solaris' reaching 50% maximum earlier (18 hours) than 'Regent' (28 hours) despite lower final concentrations, suggesting that both kinetic and quantitative parameters contribute to effective phytoalexin-based defense.",
    "editor_note": "Phytoalexin_Production_Disposition is_a Induced_Defense_Disposition. ||Grapevine phytoalexins are predominantly stilbenes, synthesized via the phenylpropanoid pathway through the action of stilbene synthase (STS). ||Child classes address specific aspects of stilbene phytoalexin production including Stilbene_Synthase_Induction_Disposition (enzyme induction), Resveratrol_Production_Disposition (primary stilbene product), and Viniferin_Production_Disposition (oligomeric stilbenes). ||The large STS gene family in Vitis (unique among plants) enables exceptional stilbene production capacity, making phytoalexins particularly important in grapevine defense.  This disposition represents one of the most important inducible chemical defenses in grapevine, which is notable for producing stilbene-type phytoalexins including resveratrol, pterostilbene, and various viniferins that exhibit potent antifungal and antimicrobial activities. ||Phytoalexin production in Vitis is triggered by pathogen recognition, elicitor perception (including oligosaccharides, lipids, and proteins), UV irradiation, wounding, and abiotic stresses, with the magnitude and kinetics of response varying substantially among genotypes. ||The biosynthesis of stilbene phytoalexins involves induction of stilbene synthase (STS) genes, of which grapevine possesses an unusually large family (approximately 40 members), enabling rapid and massive stilbene accumulation upon challenge. ||Phytoalexins function through multiple mechanisms including direct antimicrobial activity via membrane disruption and enzyme inhibition, antioxidant activity protecting plant cells from pathogen-induced oxidative damage, and potential signaling roles in systemic defense activation. ||The strength of Phytoalexin_Production_Disposition correlates with disease resistance in many grapevine pathosystems, with resistant cultivars typically showing faster induction, higher accumulation, and more diverse phytoalexin profiles compared to susceptible genotypes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jeandet P et al. (2002) The production of resveratrol (3,5,4′-trihydroxystilbene) by grape berries in different developmental stages, American Journal of Enology and Viticulture 42:41-46|| Langcake P, Pryce RJ (1977) The production of resveratrol and the viniferins by grapevines in response to infection or injury, Physiological Plant Pathology 9:77-86|| Chong J et al. (2009) The stilbene synthase gene family in grapevine: genome-wide identification and expression analyses during development and stress responses, BMC Plant Biology 9:54"
  },
  "Stilbene_Synthase_Induction_Disposition": {
    "definition": "A Stilbene_Synthase_Induction_Disposition is a Phytoalexin_Production_Disposition that inheres in a Vitis vinifera plant and is realized through rapid and strong transcriptional activation of stilbene synthase (STS) genes in response to pathogen attack, elicitor treatment, or abiotic stress, providing the enzymatic capacity for de novo stilbene phytoalexin biosynthesis.", 
    "alternative_term": "STS gene induction | stilbene synthase activation | STS transcriptional response |+ Stilbensynthase-Induktions-Disposition | STS-Gen-Aktivierung | Stilbensynthase-Transkriptions-Antwort",
    "example_of_usage": "Molecular characterization of Stilbene_Synthase_Induction_Disposition at INRAE Colmar employed qRT-PCR analysis of multiple STS gene family members across 15 cultivars following Plasmopara viticola inoculation. ||Expression of five representative STS genes (VvSTS6, VvSTS16, VvSTS27, VvSTS36, VvSTS41) was monitored at 0, 6, 12, 24, 48, and 72 hours post-inoculation using gene-specific primers. ||Total STS induction (sum of all five genes) showed dramatic cultivar variation in both kinetics and magnitude. ||Resistant 'Regent' exhibited rapid Stilbene_Synthase_Induction_Disposition with detectable upregulation by 6 hpi, peak expression at 18 hpi (125-fold above basal for VvSTS27, the most responsive gene), and sustained elevation through 72 hpi. ||Susceptible 'Chasselas' showed delayed, weak induction with peak at 48 hpi reaching only 12-fold for VvSTS27. ||Interestingly, individual STS genes showed cultivar-specific induction patterns: VvSTS41 was the dominant induced gene in 'Solaris' (85-fold) but only moderately induced in 'Regent' (25-fold), suggesting genotype-specific regulatory variation within the STS family. ||Correlation analysis revealed that STS induction magnitude at 24 hpi was the strongest predictor of final stilbene accumulation (r = 0.89) and resistance phenotype (r = -0.72 with sporulation severity), confirming that Stilbene_Synthase_Induction_Disposition is a key determinant of effective stilbene-based defense.",
    "editor_note": "Stilbene_Synthase_Induction_Disposition is_a Phytoalexin_Production_Disposition. ||STS induction represents the regulatory control point for stilbene phytoalexin production, determining the enzymatic capacity available for resveratrol synthesis. ||The large STS gene family in grapevine (~40 genes) provides redundancy and flexibility in induction responses. ||Different STS genes respond to different stimuli and show cultivar-specific expression patterns, creating complex genotype × environment interactions in stilbene production. ||STS induction kinetics (speed) and magnitude (fold-change) are partially independent parameters both contributing to effective defense.  This disposition represents the regulatory component of stilbene-based defense, as STS enzyme levels are typically low in unchallenged tissues and must be induced to enable substantial phytoalexin accumulation. ||Stilbene synthase catalyzes the condensation of one molecule of p-coumaroyl-CoA with three molecules of malonyl-CoA to produce resveratrol, the foundational stilbene from which more complex phytoalexins (viniferins, pterostilbene) are derived. ||Grapevine possesses an exceptionally large STS gene family comprising approximately 40 functional genes organized in clusters on chromosomes 10 and 16, reflecting ancient gene duplication events that have expanded stilbene biosynthetic capacity in this genus. ||Different STS genes show distinct expression patterns, with some induced by pathogens, others by UV light, and some showing tissue-specific expression, together providing flexible and robust stilbene production capacity across diverse challenge conditions. ||The speed and magnitude of STS induction vary among cultivars, with resistant genotypes typically showing earlier peak expression (12-24 hours post-challenge) and higher fold-induction (50-200 fold) compared to susceptible cultivars (peak at 36-48 hours, 5-20 fold induction).",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Chong J et al. (2009) The stilbene synthase gene family in grapevine: genome-wide identification and expression analyses during development and stress responses, BMC Plant Biology 9:54|| Vannozzi A et al. (2012) Genome-wide analysis of the grapevine stilbene synthase multigenic family: genomic organization and expression profiles upon biotic and abiotic stresses, BMC Plant Biology 12:130|| Höll J et al. (2013) The R2R3-MYB transcription factors MYB14 and MYB15 regulate stilbene biosynthesis in Vitis vinifera, Plant Cell 25:4135-4149"
  },
  "Resveratrol_Production_Disposition": {
    "definition": "A Resveratrol_Production_Disposition is a Phytoalexin_Production_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to accumulate trans-resveratrol (3,5,4′-trihydroxystilbene), the foundational stilbene phytoalexin from which more complex antimicrobial stilbenoids are derived, in response to pathogen challenge or stress.", 
    "alternative_term": "trans-resveratrol accumulation | resveratrol synthesis capacity | trihydroxystilbene production |+ Resveratrol-Produktions-Disposition | Trans-Resveratrol-Akkumulation | Trihydroxystilben-Produktion",
    "example_of_usage": "Quantitative evaluation of Resveratrol_Production_Disposition at the University of Milan characterized resveratrol accumulation dynamics across 22 cultivars following controlled Botrytis cinerea inoculation of berries at véraison. ||Berry samples were harvested at 0, 24, 48, 72, and 96 hours post-inoculation for HPLC quantification of trans-resveratrol and its glycoside piceid. ||Basal resveratrol levels in uninoculated berries ranged from 0.2 μg/g ('Pinot Noir') to 2.8 μg/g ('Primitivo'), representing constitutive variation. ||Following B. cinerea challenge, Resveratrol_Production_Disposition varied dramatically among cultivars. 'Primitivo' showed the strongest response, reaching peak resveratrol of 85 μg/g at 48 hpi (30-fold induction), while 'Pinot Noir' accumulated only 8 μg/g at peak (40-fold induction but from very low baseline). ||Infection severity at 96 hpi correlated negatively with resveratrol accumulation (r = -0.65), confirming defensive function. ||Interestingly, cultivars differed in resveratrol-to-piceid ratios, with some accumulating predominantly free resveratrol (70-80% of total, 'Nebbiolo') and others primarily glycosylated piceid (60-70%, 'Sangiovese'). ||Free resveratrol showed stronger correlation with resistance (r = -0.71) than total stilbenes (r = -0.58), suggesting that the aglycone form is the active defensive compound and that glycosylation may represent a storage or detoxification mechanism rather than direct defense.",
    "editor_note": "Resveratrol_Production_Disposition is_a Phytoalexin_Production_Disposition. ||Resveratrol is the direct product of STS enzyme activity and serves as precursor for more complex stilbenoids. ||This class addresses the capacity to accumulate the compound itself, complementing Stilbene_Synthase_Induction_Disposition which addresses the enzymatic capacity. ||Resveratrol exists in both free and glycosylated (piceid) forms, with the free aglycone typically considered the active antimicrobial form. ||The compound's human health benefits create additional interest beyond plant defense applications.  This disposition represents the production of the primary stilbene product of stilbene synthase activity, which serves both as a direct antimicrobial compound and as the precursor for biosynthesis of more potent derivatives including pterostilbene (methylated resveratrol) and various viniferins (resveratrol oligomers). ||Resveratrol accumulation following pathogen challenge typically reaches maximum concentrations at 24-72 hours post-inoculation, depending on genotype and pathogen, with concentrations ranging from barely detectable in highly susceptible cultivars to over 100 μg/g fresh weight in strongly responding genotypes. ||The antimicrobial activity of resveratrol includes inhibition of conidial germination, disruption of hyphal membrane integrity, and interference with pathogen metabolism, with minimum inhibitory concentrations against major grapevine pathogens typically in the range of 50-200 μg/mL. ||Beyond direct antimicrobial effects, resveratrol serves as a substrate for peroxidases that generate the more potent antimicrobial viniferins, and its accumulation kinetics influence the subsequent profile of stilbene derivatives produced. ||Resveratrol_Production_Disposition has attracted particular interest due to the compound's human health benefits (antioxidant, cardioprotective, potential anticancer properties), creating dual incentives for enhancing this trait through breeding.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jeandet P et al. (2002) The production of resveratrol by grape berries in different developmental stages, American Journal of Enology and Viticulture 42:41-46|| Adrian M et al. (2000) Stilbene content of mature Vitis vinifera berries in response to UV-C elicitation, Journal of Agricultural and Food Chemistry 48:6103-6105|| Langcake P, Pryce RJ (1976) The production of resveratrol by Vitis vinifera and other members of the Vitaceae as a response to infection or injury, Physiological Plant Pathology 9:77-86"
  },
  "Viniferin_Production_Disposition": {
    "definition": "A Viniferin_Production_Disposition is a Phytoalexin_Production_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to synthesize and accumulate viniferins—oligomeric stilbenes formed by oxidative coupling of resveratrol units—which exhibit substantially higher antifungal activity than their monomeric precursor resveratrol.", 
    "alternative_term": "viniferin synthesis capacity | oligomeric stilbene production | resveratrol oligomerization |+ Viniferin-Produktions-Disposition | Oligomere-Stilben-Produktion | Resveratrol-Oligomerisierung",
    "example_of_usage": "Detailed profiling of Viniferin_Production_Disposition at the Julius Kühn-Institut characterized stilbene oligomerization dynamics across 18 cultivars following Plasmopara viticola inoculation. ||Leaf samples were analyzed by LC-MS at 24, 48, 72, and 96 hpi for resveratrol, piceid, ε-viniferin, δ-viniferin, and pterostilbene to track both phytoalexin production and metabolic conversion. ||Cultivars showed distinct profiles reflecting differential Viniferin_Production_Disposition. ||Resistant 'Regent' exhibited rapid conversion with ε-viniferin exceeding resveratrol by 48 hpi (32 μg/g versus 18 μg/g), reaching final ε-viniferin concentration of 58 μg/g by 72 hpi representing 65% of total stilbenes. ||Susceptible 'Müller-Thurgau' showed delayed, limited oligomerization with resveratrol remaining dominant through 96 hpi and ε-viniferin never exceeding 4 μg/g (22% of total stilbenes). ||The PIWI cultivar 'Solaris' displayed the strongest Viniferin_Production_Disposition with early resveratrol peak at 24 hpi followed by rapid conversion, achieving ε-viniferin-to-resveratrol ratio of 4.5 by 72 hpi. ||Correlation analysis revealed that ε-viniferin concentration at 48 hpi was a better predictor of resistance (r = -0.85 with sporulation) than total stilbenes (r = -0.68) or resveratrol alone (r = -0.55), confirming the superior defensive value of oligomeric stilbenes. ||Peroxidase activity assays showed that 'Solaris' leaf extracts converted exogenous resveratrol to ε-viniferin 3-fold faster than 'Müller-Thurgau' extracts, indicating that enhanced peroxidase activity contributes to strong Viniferin_Production_Disposition.",
    "editor_note": "Viniferin_Production_Disposition is_a Phytoalexin_Production_Disposition. ||Viniferins are formed by oxidative coupling of resveratrol, making their accumulation dependent on prior resveratrol synthesis but also requiring peroxidase activity for oligomerization. ε-Viniferin is typically the dominant and most studied viniferin form, with 5-10 fold higher antifungal activity than resveratrol. ||The ratio of viniferins to resveratrol may be as important as total stilbene concentration for effective defense. ||Some fungal pathogens produce laccases that can detoxify stilbenes, creating potential for pathogen counter-adaptation to phytoalexin-based resistance.  This disposition represents the production of the most potent antimicrobial stilbenes in grapevine defense, including ε-viniferin (resveratrol dimer), δ-viniferin (another dimeric form), α-viniferin (cyclic trimer), and higher oligomers, which together constitute the active phytoalexin arsenal in resistant responses to fungal pathogens. ||Viniferin formation occurs through the action of peroxidases that catalyze oxidative coupling of resveratrol, a process that can occur both enzymatically within plant tissues and chemically through pathogen-derived oxidases, creating a dynamic interplay between host and pathogen during infection. ||The antifungal activity of ε-viniferin exceeds that of resveratrol by 5-10 fold against major grapevine pathogens, with minimum inhibitory concentrations of 10-50 μg/mL, making viniferin accumulation particularly important for effective stilbene-based defense. ||Genotypes with strong Viniferin_Production_Disposition not only produce resveratrol rapidly but also efficiently convert it to viniferins, resulting in phytoalexin profiles dominated by the more potent oligomeric forms. ||The kinetics of viniferin production typically lag behind resveratrol accumulation by 12-24 hours, as viniferin formation depends on prior resveratrol synthesis.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pezet R et al. (2004) δ-Viniferin, a resveratrol dehydrodimer: one of the major stilbenes synthesized by grapevine leaves, Journal of Agricultural and Food Chemistry 51:5488-5492|| Langcake P, Pryce RJ (1977) A new class of phytoalexins from grapevines, Experientia 33:151-152|| Schnee S et al. (2013) Vitis vinifera canes, a source of stilbenoids against downy mildew, OENO One 47:259-268"
  },
  "Pathogenesis_Related_Protein_Disposition": {
    "definition": "A Pathogenesis_Related_Protein_Disposition is an Induced_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through rapid and strong induction of pathogenesis-related (PR) proteins—families of defense-related proteins whose expression is dramatically upregulated in response to pathogen attack, elicitor treatment, or activation of systemic acquired resistance.", 
    "alternative_term": "PR protein induction | defense protein accumulation | pathogenesis-related gene expression |+ Pathogenese-bezogene-Protein-Disposition | PR-Protein-Induktion | Abwehrprotein-Akkumulation",
    "example_of_usage": "Systematic analysis of Pathogenesis_Related_Protein_Disposition at Agroscope Changins-Wädenswil compared PR protein induction across 20 cultivars following Erysiphe necator inoculation. ||Leaf samples collected at 0, 24, 48, 72, and 120 hpi were analyzed for PR-2 (glucanase), PR-3 (chitinase), and PR-5 (thaumatin-like protein) by Western blot densitometry and enzyme activity assays. ||Resistant 'Regent' exhibited strong Pathogenesis_Related_Protein_Disposition with rapid induction kinetics. ||PR-3 chitinase activity increased 12-fold by 24 hpi, reaching peak at 48 hpi (28-fold above basal), while PR-2 glucanase showed 8-fold induction by 48 hpi. ||PR-5 accumulation was slower but sustained, reaching 15-fold at 120 hpi. ||Susceptible 'Chasselas' showed delayed, weak induction with PR-3 reaching only 3-fold at 72 hpi and PR-2 showing minimal response (1.5-fold). ||The combined PR protein index (sum of standardized fold-changes) correlated strongly with powdery mildew resistance (r = -0.78 with colony density at 120 hpi). ||Notably, constitutive PR levels also varied, with 'Regent' showing 2.5-fold higher basal PR-3 than 'Chasselas', suggesting that both basal and induced components of Pathogenesis_Related_Protein_Disposition contribute to resistance. ||When purified PR protein preparations were tested in vitro, grapevine chitinase inhibited E. necator conidial germination by 65% at 50 μg/mL, confirming direct antifungal function.",
    "editor_note": "Pathogenesis_Related_Protein_Disposition is_a Induced_Defense_Disposition. ||PR proteins comprise multiple families with distinct antimicrobial mechanisms, addressed through child classes Chitinase_Induction_Disposition and Glucanase_Induction_Disposition for the most prominent families in antifungal defense. ||PR proteins contribute to both local defense and systemic acquired resistance (SAR). ||Some PR proteins are expressed at basal levels in healthy tissue (addressed under Preformed_Antimicrobial_Disposition), with the present class focusing on inducible accumulation upon challenge.  This disposition represents the protein component of induced defense, complementing phytoalexin production through direct antimicrobial activities including cell wall degradation, membrane permeabilization, and pathogen enzyme inhibition. ||Grapevine expresses representatives of most characterized PR protein families, with PR-2 (β-1,3-glucanases), PR-3 (chitinases), PR-4 (chitin-binding proteins), PR-5 (thaumatin-like proteins), PR-10 (ribonuclease-like proteins), and PR-14 (lipid transfer proteins) being most prominent in defense responses. ||PR proteins function through diverse mechanisms targeting pathogen structures and processes. ||Glucanases degrade fungal cell wall β-glucans, chitinases hydrolyze chitin (a major component of fungal cell walls and insect exoskeletons), and thaumatin-like proteins disrupt pathogen membranes. ||The magnitude and speed of PR protein induction vary substantially among grapevine genotypes, with resistant cultivars typically showing stronger basal expression and more rapid, sustained induction compared to susceptible genotypes. ||Importantly, PR protein activity contributes to both local resistance at infection sites and systemic acquired resistance providing whole-plant protection.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "van Loon LC et al. (2006) Significance of inducible defense-related proteins in infected plants, Annual Review of Phytopathology 44:135-162|| Ferreira RB et al. (2007) The wine proteins, Trends in Food Science and Technology 18:293-306|| Monteiro S et al. (2003) Structural and functional aspects of PR-10 proteins, FEBS Letters 541:1-7"
  },
  "Chitinase_Induction_Disposition": {
    "definition": "A Chitinase_Induction_Disposition is a Pathogenesis_Related_Protein_Disposition that inheres in a Vitis vinifera plant and is realized through rapid and strong transcriptional activation and accumulation of chitinase enzymes (PR-3 family) in response to pathogen attack, providing enhanced capacity to degrade chitin, a major structural component of fungal cell walls and insect exoskeletons.", 
    "alternative_term": "PR-3 induction | chitinase gene activation | antifungal chitinase response |+ Chitinase-Induktions-Disposition | PR-3-Induktion | Antifungale-Chitinase-Antwort",
    "example_of_usage": "Molecular characterization of Chitinase_Induction_Disposition at the University of Florence compared chitinase gene expression and enzyme activity across 15 cultivars following Botrytis cinerea berry inoculation. ||Expression of four chitinase genes (VvChit1b class I, VvChit4a class III, VvChit4c class IV, VvChi1 class I) was monitored by qRT-PCR at 0, 12, 24, 48, and 72 hpi, with parallel measurement of total chitinase enzyme activity using colloidal chitin substrate. ||Resistant 'Nebbiolo' exhibited strong Chitinase_Induction_Disposition with VvChit4c (class IV) showing 45-fold induction by 24 hpi, VvChit1b (class I) reaching 28-fold at 48 hpi, and total chitinase activity increasing 8-fold by 48 hpi. ||Susceptible 'Moscato Bianco' showed delayed, weak induction with VvChit4c only 6-fold at 48 hpi and enzyme activity increasing just 2-fold. ||Class IV chitinase (VvChit4c) showed the strongest correlation with resistance (r = -0.82 between expression and infection severity), suggesting this class is most important for B. cinerea defense. ||In vitro assays demonstrated that purified grapevine class IV chitinase inhibited B. cinerea hyphal growth by 70% at 25 μg/mL and reduced conidial germination by 55%, confirming direct antifungal function. ||Transgenic tobacco overexpressing VvChit4c showed enhanced B. cinerea resistance, providing functional validation of this gene's defensive role.",
    "editor_note": "Chitinase_Induction_Disposition is_a Pathogenesis_Related_Protein_Disposition. ||Chitinases target chitin in fungal cell walls and insect exoskeletons, making them specifically effective against true fungi (Ascomycetes, Basidiomycetes) but not oomycetes (e.g., Plasmopara viticola) whose cell walls contain cellulose rather than chitin. ||Multiple chitinase classes exist with distinct properties and expression patterns. ||Chitinase activity releases chitin oligomers that can trigger additional defense responses, creating positive feedback amplification of defense signaling.  This disposition represents the induction of one of the most important PR protein families for antifungal defense, as chitinase activity directly attacks fungal hyphal integrity and can inhibit spore germination. ||Plant chitinases are classified into classes I-V based on structure, with grapevine expressing representatives of classes I, II, III, and IV, each with distinct biochemical properties and expression patterns. ||Chitinases function by hydrolyzing the β-1,4-glycosidic bonds between N-acetylglucosamine residues in chitin, releasing oligomers that themselves can act as elicitors triggering further defense responses in a positive feedback loop. ||The speed and magnitude of chitinase induction vary among genotypes, with resistant cultivars typically showing earlier induction onset (detectable within 6-12 hours post-inoculation), higher peak expression (20-50 fold above basal), and more sustained elevation compared to susceptible cultivars. ||Chitinase_Induction_Disposition is particularly relevant for resistance to fungal pathogens with chitin-containing cell walls, including Erysiphe necator (powdery mildew), Botrytis cinerea (grey mold), and various trunk disease fungi, but not for oomycetes like Plasmopara viticola whose cell walls lack chitin.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Collinge DB et al. (1993) Plant chitinases, Plant Journal 3:31-40|| Robert N et al. (2002) Molecular characterization of the incompatible interaction of Vitis vinifera leaves with Pseudomonas syringae pv. pisi: expression of genes coding for stilbene synthase and class 10 PR protein, European Journal of Plant Pathology 108:837-847|| Derckel JP et al. (1998) Differential expression of grapevine (Vitis vinifera L.) chitinase genes following challenge with fungal and bacterial pathogens, Vitis 37:165-170"
  },
  "Glucanase_Induction_Disposition": {
    "definition": "A Glucanase_Induction_Disposition is a Pathogenesis_Related_Protein_Disposition that inheres in a Vitis vinifera plant and is realized through rapid and strong transcriptional activation and accumulation of β-1,3-glucanase enzymes (PR-2 family) in response to pathogen attack, providing enhanced capacity to degrade β-1,3-glucans, major structural polysaccharides in the cell walls of fungi and oomycetes.", 
    "alternative_term": "PR-2 induction | β-1,3-glucanase activation | glucan hydrolase response |+ Glucanase-Induktions-Disposition | PR-2-Induktion | β-1,3-Glucanase-Aktivierung",
    "example_of_usage": "Comparative analysis of Glucanase_Induction_Disposition at INRAE Bordeaux examined β-1,3-glucanase gene expression and activity across 18 cultivars following Plasmopara viticola inoculation, specifically targeting the oomycete-relevant glucanase response. ||Expression of three glucanase genes (VvGluc1 class I, VvGluc2 class II, VvGluc3 class II) was monitored at 0, 12, 24, 48, and 72 hpi alongside enzyme activity assays using laminarin substrate. ||Resistant 'Regent' (Rpv3-positive) showed strong Glucanase_Induction_Disposition with VvGluc3 reaching 35-fold induction by 18 hpi and total glucanase activity increasing 6-fold by 24 hpi. ||Susceptible 'Chasselas' exhibited delayed, weak induction with VvGluc3 only 5-fold at 48 hpi and activity increasing 1.8-fold. ||Importantly, class II extracellular glucanase (VvGluc3) showed strongest correlation with resistance (r = -0.79 with sporulation intensity), suggesting that apoplastic deployment is critical for defense against the intercellularly colonizing P. viticola. ||Combined glucanase-chitinase activity assays demonstrated synergistic effects, with the enzyme combination inhibiting in vitro germination of Botrytis cinerea conidia by 85% compared to 45% (glucanase alone) and 55% (chitinase alone) at equivalent concentrations. ||For P. viticola zoospores lacking chitin, glucanase alone provided 60% germination inhibition, confirming the importance of Glucanase_Induction_Disposition specifically for oomycete resistance where chitinase has no direct target.",
    "editor_note": "Glucanase_Induction_Disposition is_a Pathogenesis_Related_Protein_Disposition. β-1,3-Glucanases target β-glucans present in both fungal and oomycete cell walls, providing broader pathogen coverage than chitinases which are ineffective against chitin-lacking oomycetes. ||Class II (extracellular) glucanases may be particularly important for defense against pathogens like P. viticola that colonize apoplastic spaces. ||Glucanase and chitinase typically show coordinated induction and synergistic antifungal effects, representing a coherent defense module targeting pathogen cell wall integrity.  This disposition represents the induction of another critical PR protein family for antimicrobial defense, as β-1,3-glucanase activity directly compromises pathogen cell wall integrity and can synergize with chitinases for enhanced antifungal effect. ||Unlike chitinases, β-1,3-glucanases are effective against both true fungi (which contain chitin and β-glucans) and oomycetes like Plasmopara viticola (which lack chitin but contain abundant β-1,3-glucans), making Glucanase_Induction_Disposition particularly important for downy mildew resistance. ||Grapevine β-1,3-glucanases are classified into class I (vacuolar, with N-terminal extension) and class II (extracellular, without extension) based on structure and localization, with both classes contributing to defense through complementary spatial deployment. ||The hydrolysis products of glucanase activity (β-glucan oligosaccharides) can function as elicitors triggering additional defense responses, similar to chitin oligomers released by chitinases. ||Glucanase and chitinase induction typically occur coordinately, with the combined activity providing synergistic antifungal effects exceeding either enzyme alone through simultaneous attack on multiple cell wall components.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mauch F et al. (1988) Antifungal hydrolases in pea tissue I. Purification and characterization of two chitinases and two β-1,3-glucanases differentially regulated during development and in response to fungal infection, Plant Physiology 87:325-333|| Renault AS et al. (1996) β-1,3-Glucanase gene expression in grapevine leaves as a response to infection with Botrytis cinerea, American Journal of Enology and Viticulture 47:57-62|| van Loon LC et al. (2006) Significance of inducible defense-related proteins in infected plants, Annual Review of Phytopathology 44:135-162"
  },
  "Systemic_Acquired_Resistance_Disposition": {
    "definition": "A Systemic_Acquired_Resistance_Disposition is an Induced_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to establish whole-plant enhanced resistance following localized pathogen infection, providing broad-spectrum protection against subsequent attacks by diverse pathogens in tissues distant from the initial infection site.", 
    "alternative_term": "SAR capacity | systemic priming | salicylic acid-dependent resistance |+ Systemisch-erworbene-Resistenz-Disposition | SAR-Kapazität | Salicylsäure-abhängige-Systemresistenz",
    "example_of_usage": "Investigation of Systemic_Acquired_Resistance_Disposition at INRAE Bordeaux employed a spatially separated inoculation system to assess SAR induction and efficacy across 15 cultivars. ||Primary leaves were inoculated with Plasmopara viticola to trigger local defense and potential SAR, while challenge inoculation was applied to distal leaves 5 days later. ||SAR establishment was quantified as percent reduction in P. viticola sporulation on challenge leaves relative to non-primed controls. ||Cultivars varied dramatically in Systemic_Acquired_Resistance_Disposition. ||The PIWI cultivar 'Regent' showed strong SAR with 72% reduction in sporulation on systemically primed leaves, accompanied by 4-fold higher basal PR-1 expression in distal tissues and accelerated stilbene accumulation upon challenge (peak at 18 hpi versus 36 hpi in non-primed). ||Susceptible 'Chasselas' exhibited weak SAR (18% sporulation reduction) with minimal PR gene priming in systemic tissues. ||Salicylic acid measurements confirmed the SA-dependence of the response, with 'Regent' showing 3.5-fold SA elevation in systemic leaves following primary infection compared to 1.4-fold in 'Chasselas'. ||Exogenous SA application (1 mM foliar spray) induced SAR-like protection even in 'Chasselas' (55% sporulation reduction), suggesting that weak Systemic_Acquired_Resistance_Disposition in susceptible cultivars reflects deficient SA signaling rather than inability to respond to the signal. ||Duration experiments revealed that 'Regent' maintained significant SAR protection for 14 days post-primary infection, while 'Chasselas' SAR decayed within 7 days.",
    "editor_note": "Systemic_Acquired_Resistance_Disposition is_a Induced_Defense_Disposition. ||SAR is triggered by pathogen infection and mediated by salicylic acid signaling, distinct from Induced_Systemic_Resistance_Disposition which is triggered by beneficial microbes and mediated by jasmonate/ethylene signaling. ||SAR provides broad-spectrum resistance effective against biotrophic and hemibiotrophic pathogens but may be less effective against necrotrophs. ||The primed state established by SAR represents a form of plant \"immune memory\" that can persist for extended periods. ||SAR can be artificially induced by SA analogs (e.g., BTH/Acibenzolar-S-methyl), providing a crop protection strategy that exploits this natural defense pathway.  This disposition represents one of the most important systemic defense mechanisms in plants, enabling a single infection event to prime the entire plant for enhanced defense responses lasting days to weeks. ||Systemic acquired resistance (SAR) is triggered by local pathogen recognition and hypersensitive response, generating mobile signals—primarily salicylic acid (SA) and the methylated derivative methyl salicylate, along with lipid-derived signals including azelaic acid and glycerol-3-phosphate—that travel through phloem to distal tissues. ||In systemic tissues, these signals activate the NPR1 (Nonexpressor of PR genes 1) regulatory pathway, leading to chromatin remodeling, transcription factor activation, and expression of pathogenesis-related (PR) genes including PR-1, PR-2, and PR-5. ||The resulting \"primed\" state enables faster and stronger defense responses upon subsequent pathogen challenge, with primed tissues showing earlier PR gene induction, more rapid phytoalexin accumulation, and enhanced hypersensitive response compared to naive tissues. ||Systemic_Acquired_Resistance_Disposition varies among grapevine genotypes in both the strength of SAR establishment following primary infection and the duration of the primed state, with resistant cultivars often showing more robust and persistent SAR than susceptible cultivars.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Durrant WE, Dong X (2004) Systemic acquired resistance, Annual Review of Phytopathology 42:185-209|| Fu ZQ, Dong X (2013) Systemic acquired resistance: turning local infection into global defense, Annual Review of Plant Biology 64:839-863|| Harm A et al. (2011) Evaluation of chemical and natural resistance inducers against downy mildew (Plasmopara viticola) in grapevine, American Journal of Enology and Viticulture 62:184-192"
  },
  "Induced_Systemic_Resistance_Disposition": {
    "definition": "An Induced_Systemic_Resistance_Disposition is an Induced_Defense_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to establish whole-plant enhanced resistance following colonization by beneficial root-associated microorganisms, particularly plant growth-promoting rhizobacteria (PGPR) and certain mycorrhizal fungi, providing protection against foliar and root pathogens through jasmonate/ethylene-mediated defense priming.", 
    "alternative_term": "ISR capacity | rhizobacteria-induced resistance | jasmonate-mediated systemic resistance |+ Induzierte-systemische-Resistenz-Disposition | ISR-Kapazität | Rhizobakterien-induzierte-Resistenz",
    "example_of_usage": "Evaluation of Induced_Systemic_Resistance_Disposition at the University of Reims Champagne-Ardenne assessed grapevine responsiveness to beneficial rhizobacteria across 12 cultivars using controlled rhizosphere inoculation and subsequent foliar pathogen challenge. ||Rooted cuttings were inoculated with Pseudomonas fluorescens CHA0 or Bacillus subtilis GB03 at planting, allowed 4 weeks for root colonization, then challenge-inoculated on leaves with either Plasmopara viticola or Botrytis cinerea. ||Cultivars showed differential Induced_Systemic_Resistance_Disposition to bacterial priming. 'Chardonnay' roots colonized by P. fluorescens showed strong ISR against both pathogens, with 58% reduction in P. viticola sporulation and 45% reduction in B. cinerea lesion size relative to non-colonized controls. ||Molecular analysis confirmed JA pathway activation, with 6-fold elevated expression of the JA marker gene VvLOX9 in roots and 3-fold elevation in leaves of colonized plants. 'Cabernet Sauvignon' showed weaker Induced_Systemic_Resistance_Disposition (32% and 22% reductions respectively) despite equivalent root colonization levels, suggesting genotypic variation in ISR signaling responsiveness. ||Interestingly, ISR and SAR showed additive effects when combined, with plants receiving both rhizobacterial priming and localized P. viticola infection exhibiting 78% protection against challenge inoculation, exceeding either treatment alone. ||AMF colonization (Rhizophagus irregularis) similarly induced ISR, with 'Pinot Noir' showing 52% P. viticola reduction in mycorrhizal versus non-mycorrhizal plants. ||These findings demonstrate that Induced_Systemic_Resistance_Disposition provides a distinct, complementary defense layer exploitable through beneficial microbiome management.",
    "editor_note": "Induced_Systemic_Resistance_Disposition is_a Induced_Defense_Disposition. ||ISR is triggered by beneficial root microbes (PGPR, mycorrhizae) and mediated by JA/ET signaling, contrasting with SAR triggered by pathogens and mediated by SA. ||ISR is particularly effective against necrotrophic pathogens and herbivores (JA-responsive defenses) while SAR favors protection against biotrophs (SA-responsive). ||The two pathways can act additively or synergistically when both are activated. ||ISR provides a foundation for biocontrol approaches using beneficial microorganisms as plant protection agents, with cultivar responsiveness to ISR-triggering microbes representing a selectable trait for integrated management systems.  This disposition represents a distinct systemic defense pathway from SAR, triggered not by pathogen attack but by mutualistic microbial interactions in the rhizosphere, and mediated primarily by jasmonic acid (JA) and ethylene (ET) signaling rather than salicylic acid. ||Induced systemic resistance (ISR) primes plants for enhanced expression of JA/ET-responsive defense genes upon pathogen challenge, without constitutively activating defenses in the absence of attack, thereby providing protection without the metabolic costs of continuous defense expression. ||Beneficial microbes triggering ISR in grapevine include Pseudomonas fluorescens, Bacillus subtilis, Trichoderma species, and arbuscular mycorrhizal fungi (AMF), which colonize roots and produce elicitors including lipopolysaccharides, flagellin, siderophores, and volatile organic compounds that are perceived by plant receptors and initiate systemic signaling. ||The resulting primed state enhances callose deposition, phytoalexin accumulation, and oxidative burst responses upon subsequent pathogen challenge in both root and shoot tissues. ||Induced_Systemic_Resistance_Disposition is particularly relevant for integrated pest management approaches that leverage beneficial soil microbiomes, and varies among grapevine genotypes in responsiveness to ISR-triggering microbes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pieterse CMJ et al. (2014) Induced systemic resistance by beneficial microbes, Annual Review of Phytopathology 52:347-375|| Verhagen BWM et al. (2004) The transcriptome of rhizobacteria-induced systemic resistance in Arabidopsis, Molecular Plant-Microbe Interactions 17:895-908|| Compant S et al. (2005) Use of plant growth-promoting bacteria for biocontrol of plant diseases: principles, mechanisms of action, and future prospects, Applied and Environmental Microbiology 71:4951-4959"
  },
  "Abiotic_Stress_Tolerance_Disposition": {
    "definition": "An Abiotic_Stress_Tolerance_Disposition is a Grapevine_Disposition that inheres in a Vitis vinifera plant and is realized through physiological, biochemical, and structural mechanisms that enable maintenance of cellular function, growth, and productivity under environmental conditions that would otherwise cause damage, growth inhibition, or death.", 
    "alternative_term": "environmental stress tolerance | abiotic stress resistance | climate adaptation capacity |+ Abiotische-Stresstoleranz-Disposition | Umweltstress-Toleranz | Klimaanpassungs-Kapazität",
    "example_of_usage": "Comprehensive characterization of Abiotic_Stress_Tolerance_Disposition at Cornell University evaluated multiple stress tolerances across 40 cultivars and rootstocks to develop regional adaptation profiles for New York viticulture. ||Cold tolerance was assessed by differential thermal analysis of bud LT50 values, drought tolerance by leaf water potential maintenance and gas exchange under controlled water deficit, and heat tolerance by photosynthetic recovery following 40°C exposure. ||V. vinifera 'Riesling' showed moderate cold tolerance (LT50 -22°C) but high heat sensitivity (35% photosynthesis reduction post-heat), while 'Cabernet Sauvignon' displayed lower cold tolerance (LT50 -18°C) but superior heat tolerance (12% reduction). ||The cold-hardy hybrid 'Marquette' exhibited exceptional cold tolerance (LT50 -34°C) combined with moderate heat and drought tolerance, representing broad Abiotic_Stress_Tolerance_Disposition suitable for continental climates with temperature extremes. ||Rootstock '3309C' showed the best drought tolerance among evaluated genotypes (maintained 85% stomatal conductance at -1.5 MPa soil water potential) but only moderate cold hardiness. ||These multidimensional profiles revealed that Abiotic_Stress_Tolerance_Disposition comprises largely independent components, with few genotypes excelling across all stress types, necessitating careful matching of cultivar tolerance profiles to site-specific stress challenges.",
    "editor_note": "Abiotic_Stress_Tolerance_Disposition is_a Grapevine_Disposition. ||This class encompasses tolerance to all non-living environmental stresses, parallel to Biotic_Stress_Resistance_Disposition addressing living attackers. ||Child classes include Cold_Tolerance_Disposition, Heat_Tolerance_Disposition, Drought_Tolerance_Disposition, Salt_Tolerance_Disposition, and Lime_Tolerance_Disposition addressing major abiotic stress categories. ||Abiotic stress tolerances are often partially independent, requiring multidimensional characterization for comprehensive adaptation assessment. ||Rootstock and scion may contribute differently to whole-vine abiotic stress tolerance.  This disposition represents the capacity to tolerate physical and chemical stresses originating from the non-living environment, complementing biotic stress resistance that addresses living attackers. ||Major abiotic stresses affecting grapevine include temperature extremes (winter cold, spring frost, summer heat), water stress (drought, waterlogging), soil chemical challenges (salinity, lime-induced chlorosis, heavy metals), light stress (excessive radiation, UV damage), and nutrient imbalances. ||Abiotic stress tolerance mechanisms encompass osmoprotectant accumulation (proline, glycine betaine, sugars), antioxidant systems (enzymatic and non-enzymatic scavengers of reactive oxygen species), membrane stabilization (lipid desaturation, protective proteins), modified growth patterns (dormancy, reduced transpiration, altered root architecture), and ion homeostasis maintenance under saline or mineral-stress conditions. ||The relative importance of different abiotic stress tolerances varies dramatically by viticultural region, with cold tolerance paramount in continental climates, drought tolerance critical in Mediterranean and semi-arid regions, and lime tolerance essential on calcareous soils. ||Understanding Abiotic_Stress_Tolerance_Disposition informs site-cultivar matching, rootstock selection, and breeding priorities for climate adaptation as environmental conditions shift.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Cramer GR et al. (2011) Effects of abiotic stress on plants: a systems biology perspective, BMC Plant Biology 11:163|| Chaves MM et al. (2010) Grapevine under deficit irrigation: hints from physiological and molecular data, Annals of Botany 105:661-676|| Flexas J et al. (2010) Photosynthesis limitations during water stress acclimation and recovery in the drought-adapted Vitis hybrid Richter-110, Journal of Experimental Botany 60:2361-2377"
  },
  "Cold_Tolerance_Disposition": {
    "definition": "A Cold_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological and biochemical mechanisms enabling survival of freezing temperatures that would otherwise cause lethal ice formation within tissues, membrane damage, and cell death.", 
    "alternative_term": "freeze tolerance | winter hardiness | low temperature tolerance |+ Kältetoleranz-Disposition | Frosttoleranz | Winterhärte-Kapazität",
    "example_of_usage": "Long-term monitoring of Cold_Tolerance_Disposition at the University of Minnesota characterized seasonal cold hardiness dynamics across 25 cultivars over 8 winters using differential thermal analysis (DTA) to determine bud LT50 values (temperature killing 50% of buds). ||Measurements at monthly intervals from November through March revealed dramatic cultivar differences in both maximum hardiness and seasonal patterns. ||V. vinifera 'Pinot Noir' showed marginal Cold_Tolerance_Disposition with maximum hardiness of -21°C reached in mid-January, rapid deacclimation beginning in late February, and frequent economic crop losses (5 of 8 winters with >50% primary bud mortality). ||The Minnesota-bred hybrid 'Frontenac' exhibited exceptional Cold_Tolerance_Disposition with maximum hardiness of -35°C, extended hardiness maintenance through February, and slower spring deacclimation, sustaining zero bud mortality across all 8 winters despite exposure to -32°C ambient temperature in the most severe winter. 'Marquette' showed intermediate but commercially adequate cold tolerance (LT50 -34°C) with an additional advantage of rapid reacclimation following midwinter thaws, recovering 4°C of hardiness within 72 hours after a January warming event that caused permanent hardiness loss in less adaptive cultivars. ||These findings demonstrate that Cold_Tolerance_Disposition encompasses not only absolute minimum survival temperature but also acclimation kinetics, hardiness maintenance, and reacclimation capacity.",
    "editor_note": "Cold_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||This class encompasses all aspects of cold/freeze tolerance, with child classes addressing specific components including Midwinter_Hardiness_Disposition (deep dormancy cold tolerance), Spring_Frost_Tolerance_Disposition (post-budbreak frost survival), and Fall_Frost_Tolerance_Disposition (pre-dormancy cold events). ||Cold tolerance is the primary factor limiting V. vinifera cultivation in continental climates and drives extensive cold-hardy cultivar breeding programs. ||The dynamic nature of cold tolerance through the dormant season distinguishes it from static traits, requiring assessment of acclimation, maintenance, and deacclimation phases.  This disposition represents one of the most critical abiotic stress tolerances for grapevine, determining the geographic limits of cultivation and the economic sustainability of viticulture in continental and cold-climate regions. ||Cold tolerance in woody perennials involves a dynamic process of cold acclimation in autumn (triggered by shortening photoperiod and declining temperatures), maximum hardiness during midwinter dormancy, and deacclimation in spring as temperatures rise and growth resumes. ||The mechanisms underlying cold tolerance include controlled extracellular ice formation that draws water from cells (freeze tolerance), deep supercooling that avoids ice formation in critical tissues like xylem ray parenchyma and bud primordia, accumulation of cryoprotective compounds (sugars, proline, dehydrins, antifreeze proteins), membrane lipid remodeling increasing fluidity at low temperatures, and dormancy regulation preventing premature deacclimation. ||Cold tolerance varies dramatically among Vitis species, with V. vinifera generally least hardy (midwinter LT50 typically -15°C to -25°C), while V. riparia, V. amurensis, and cold-adapted hybrids tolerate -30°C to -40°C. ||Cold damage remains the primary limitation to V. vinifera cultivation in regions with severe winters, driving both rootstock selection and extensive breeding programs for cold-hardy cultivars.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Mills LJ et al. (2006) Timing of low temperature exposure affects cold hardiness and budbreak in Vitis vinifera, American Journal of Enology and Viticulture 57:528-535|| Keller M (2020) The Science of Grapevines, 3rd Edition, Academic Press"
  },
  "Midwinter_Hardiness_Disposition": {
    "definition": "A Midwinter_Hardiness_Disposition is a Cold_Tolerance_Disposition that inheres in a Vitis plant during the period of maximum cold acclimation (typically December through February in the Northern Hemisphere) and is realized through the capacity to survive the most extreme low temperatures encountered during deep dormancy when tissues have achieved full cold hardening.", 
    "alternative_term": "maximum cold hardiness | deep dormancy freeze tolerance | peak winter hardiness |+ Mittwinter-Härte-Disposition | Maximale-Frosthärte | Tiefwinter-Toleranz",
    "example_of_usage": "Systematic quantification of Midwinter_Hardiness_Disposition at South Dakota State University employed differential thermal analysis (DTA) to determine LT50 values for buds, canes, and trunks across 35 cultivars at maximum hardiness in mid-January. ||Primary bud LT50 ranged from -15.2°C ('Grenache', least hardy V. vinifera) to -38.4°C ('Valiant', V. riparia hybrid), representing 23°C variation in Midwinter_Hardiness_Disposition across cultivated grapevine diversity. ||Cane LT50 values were consistently 3-5°C colder than corresponding bud values within cultivars, while trunk tissues showed variable relationships depending on wood age and acclimation status. ||Among V. vinifera cultivars, 'Riesling' (-24.8°C) and 'Cabernet Franc' (-23.5°C) showed superior Midwinter_Hardiness_Disposition compared to 'Merlot' (-19.2°C) and 'Syrah' (-17.8°C). ||The PIWI cultivar 'Solaris' achieved -27.3°C, intermediate between V. vinifera and cold-hardy hybrids. ||Strong correlation was observed between bud and cane hardiness within cultivars (r = 0.94), suggesting common genetic control, while correlation with trunk hardiness was lower (r = 0.72), indicating partially independent regulation. ||These LT50 values directly inform cultivar recommendations, with -25°C considered the minimum threshold for reliable production in upper Midwestern U.S. climates where ambient temperatures routinely reach -30°C.",
    "editor_note": "Midwinter_Hardiness_Disposition is_a Cold_Tolerance_Disposition. ||This class specifically addresses cold tolerance during deep dormancy when acclimation is complete, distinct from spring frost tolerance (growing tissue damage) or fall frost tolerance (pre-dormancy damage). ||The child class Bud_Cold_Hardiness_Disposition addresses the economically critical bud tissues determining next season's crop. ||LT50 values are the standard metric, measured by controlled freezing or differential thermal analysis. ||Midwinter hardiness represents the genetic potential for cold tolerance, while actual winter survival depends also on environmental factors including minimum temperature duration, wind exposure, and snow cover.  This disposition represents the peak cold tolerance capacity of grapevine, reflecting the maximum protection achieved through complete cold acclimation processes including dormancy establishment, cryoprotectant accumulation, membrane stabilization, and water redistribution. ||Midwinter hardiness is typically quantified as the LT50 value—the temperature at which 50% of a given tissue type is killed—determined through controlled freezing tests or differential thermal analysis detecting ice nucleation events in supercooled tissues. ||The midwinter hardiness of different vine tissues varies substantially, with canes and trunks generally more hardy than buds, and among bud components, primary buds less hardy than secondary and tertiary buds. ||V. vinifera cultivars achieve midwinter bud LT50 values typically ranging from -15°C (tender cultivars like 'Grenache') to -25°C (hardier cultivars like 'Riesling'), while V. riparia and V. amurensis can reach -40°C, and cold-hardy hybrids bred from these species achieve -30°C to -38°C. ||Midwinter_Hardiness_Disposition is the primary determinant of cultivar survival in continental climates with severe winters, though spring frost tolerance (post-budbreak) and deacclimation stability also contribute to overall winter survival success.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mills LJ et al. (2006) Foliar temperature and VvCBF gene expression during the early stages of cold acclimation in Vitis, Functional Plant Biology 33:593-605|| Wolf TK, Cook MK (1994) Cold hardiness of dormant buds of grape cultivars: comparison of thermal analysis and field survival, HortScience 29:1453-1455|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235"
  },
  "Bud_Cold_Hardiness_Disposition": {
    "definition": "A Bud_Cold_Hardiness_Disposition is a Midwinter_Hardiness_Disposition that inheres specifically in dormant grapevine buds and is realized through the capacity of bud tissues to survive freezing temperatures through deep supercooling of bud primordia and/or tolerance to ice formation in bud scales and adjacent tissues.", 
    "alternative_term": "bud freeze tolerance | dormant bud hardiness | bud LT50 |+ Knospen-Frosthärte-Disposition | Schlafende-Knospen-Härte | Knospen-Kältetoleranz",
    "example_of_usage": "Detailed characterization of Bud_Cold_Hardiness_Disposition at the Cool Climate Oenology and Viticulture Institute, Brock University, employed differential thermal analysis to separately determine LT50 values for primary, secondary, and tertiary bud components across 20 cultivars through the dormant season. ||At maximum hardiness in January, primary bud LT50 ranged from -17.8°C ('Merlot') to -36.2°C ('Frontenac'), while secondary buds were consistently 2.5-4.0°C more hardy and tertiary buds 4.5-6.5°C more hardy than primary buds within each cultivar. ||For 'Riesling' (primary LT50 -23.5°C, secondary -26.8°C, tertiary -28.9°C), a -26°C midwinter event would kill approximately 50% of primary buds while leaving secondary and tertiary buds largely intact, enabling 70-80% yield recovery through secondary shoot growth. ||Field validation over 6 winters confirmed that DTA-predicted Bud_Cold_Hardiness_Disposition accurately matched observed field survival (r = 0.91 between predicted and actual mortality). ||Economic modeling demonstrated that cultivars with primary bud LT50 below -25°C showed positive net returns in the Niagara Peninsula climate, while cultivars above -22°C required supplemental winter protection (hilling, geotextile covers) costing $800-1,200/ha annually. ||These findings establish Bud_Cold_Hardiness_Disposition thresholds for economically sustainable cold-climate viticulture.",
    "editor_note": "Bud_Cold_Hardiness_Disposition is_a Midwinter_Hardiness_Disposition. ||Bud cold hardiness is economically the most critical tissue-specific hardiness because bud survival determines next season's crop. ||Child classes address the three bud components within the compound bud structure: Primary_Bud_Hardiness_Disposition, Secondary_Bud_Hardiness_Disposition, and Tertiary_Bud_Hardiness_Disposition. ||Grapevine buds survive freezing primarily through supercooling rather than freeze tolerance, with low-temperature exotherms (LTEs) in differential thermal analysis marking lethal ice nucleation events. ||The differential hardiness among bud components enables partial crop recovery following intermediate freeze events.  This disposition represents the most economically critical component of grapevine cold hardiness, as bud survival determines the following season's shoot number, cluster number, and ultimately crop yield. ||Grapevine buds survive freezing primarily through supercooling—the maintenance of water in liquid state below its equilibrium freezing point—rather than through freeze tolerance, with bud primordia remaining ice-free while surrounding tissues freeze. ||The supercooling capacity of grapevine buds is limited by ice nucleation events that trigger rapid freezing, detectable as low-temperature exotherms (LTEs) in differential thermal analysis, with the LTE temperature correlating with bud lethal temperature. ||The compound bud structure of grapevine, containing primary, secondary, and tertiary bud primordia within a common bud scale envelope, creates a hierarchy of cold hardiness with important implications for crop recovery following winter injury. ||Primary buds are typically least hardy but most fruitful, secondary buds more hardy but less fruitful, and tertiary buds most hardy but minimally fruitful, enabling partial crop recovery when primary buds are killed but secondary or tertiary buds survive. ||Bud_Cold_Hardiness_Disposition is the primary selection target in cold-climate grape breeding and the key parameter for cultivar recommendations in regions with severe winters.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Andrews PK, Sandidge CR, Toyama TK (1984) Deep supercooling of dormant and deacclimating Vitis buds, American Journal of Enology and Viticulture 35:175-177|| Quamme HA (1986) Use of thermal analysis to measure freezing resistance of grape buds, Canadian Journal of Plant Science 66:945-952|| Ferguson JC et al. (2011) Dynamic thermal profiles of grapevine cold hardiness, American Journal of Enology and Viticulture 62:407-413"
  },
  "Primary_Bud_Hardiness_Disposition": {
    "definition": "A Primary_Bud_Hardiness_Disposition is a Bud_Cold_Hardiness_Disposition that inheres specifically in the primary (central) bud primordium within the compound grapevine bud and is realized through the supercooling capacity and freeze avoidance mechanisms of this most developmentally advanced and fruitful bud component.", 
    "alternative_term": "primary bud freeze tolerance | central bud hardiness | main bud LT50 |+ Primärknospen-Härte-Disposition | Hauptknospen-Frosthärte | Zentralknospen-Kältetoleranz",
    "example_of_usage": "Precision assessment of Primary_Bud_Hardiness_Disposition at Iowa State University employed high-resolution differential thermal analysis to distinguish low-temperature exotherms (LTEs) from primary, secondary, and tertiary bud components across 15 cultivars at biweekly intervals from November through March. ||Primary bud LTEs occurred at consistently warmer temperatures than secondary and tertiary LTEs, confirming the hierarchy of bud component hardiness. ||At maximum hardiness in mid-January, 'Frontenac' exhibited exceptional Primary_Bud_Hardiness_Disposition with LT50 of -34.2°C, while V. vinifera 'Pinot Noir' showed marginal hardiness at -19.8°C. ||The difference between primary and secondary bud LT50 (hardiness differential) varied among cultivars from 2.1°C ('Brianna') to 5.8°C ('Chambourcin'), with implications for crop recovery potential following intermediate freeze events. ||Field trials validated the predictive value of Primary_Bud_Hardiness_Disposition, with significant correlation between laboratory LT50 and field survival at individual node positions following natural freeze events (r = 0.88). ||Economic analysis demonstrated that each 1°C improvement in Primary_Bud_Hardiness_Disposition reduced average annual winter damage costs by approximately $120/ha in central Iowa conditions, providing quantitative justification for the strong breeding emphasis on this trait in cold-climate cultivar development programs.",
    "editor_note": "Primary_Bud_Hardiness_Disposition is_a Bud_Cold_Hardiness_Disposition. ||The primary bud produces the main, most fruitful shoot and is typically least hardy among the three bud components within the compound bud. ||Primary bud survival is the primary determinant of full crop potential, with primary bud kill requiring reliance on less fruitful secondary shoots for crop recovery. ||The differential between primary and secondary bud hardiness varies among cultivars and influences crop recovery potential. ||Primary bud LT50 is the most commonly reported bud hardiness parameter and the primary selection criterion in cold-hardy cultivar breeding.  This disposition represents the cold tolerance of the bud structure that produces the primary shoot bearing the majority of the crop under normal circumstances, making Primary_Bud_Hardiness_Disposition the most economically significant component of bud cold hardiness. ||The primary bud is the first-formed and largest primordium within the compound bud, containing well-developed cluster primordia (typically 1-3 depending on cultivar) and representing the dominant growth point that will produce the main shoot the following spring. ||Due to its larger size and more advanced development, the primary bud typically exhibits lower cold hardiness than the smaller, less differentiated secondary and tertiary buds, with LT50 values generally 2-6°C warmer than secondary buds within the same compound bud structure. ||This differential hardiness has been attributed to differences in tissue hydration, supercooling capacity related to primordium size, and developmental stage effects on cryoprotective compound accumulation. ||Primary_Bud_Hardiness_Disposition directly determines the temperature threshold for significant crop loss, as primary bud kill eliminates the most fruitful shoots and requires reliance on less productive secondary growth for crop recovery.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pool RM et al. (1990) Environmental factors controlling cold hardiness and dormancy in grapevines, VITIS Journal of Grapevine Research 29:129-144|| Wolf TK, Cook MK (1994) Cold hardiness of dormant buds of grape cultivars: comparison of thermal analysis and field survival, HortScience 29:1453-1455|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235"
  },
  "Secondary_Bud_Hardiness_Disposition": {
    "definition": "A Secondary_Bud_Hardiness_Disposition is a Bud_Cold_Hardiness_Disposition that inheres specifically in the secondary (lateral) bud primordium within the compound grapevine bud and is realized through the supercooling capacity and freeze avoidance mechanisms of this smaller, less differentiated bud component that serves as a backup growth point when the primary bud is killed.", 
    "alternative_term": "secondary bud freeze tolerance | lateral bud hardiness | backup bud LT50 |+ Sekundärknospen-Härte-Disposition | Seitenknospen-Frosthärte | Lateralknospen-Kältetoleranz",
    "example_of_usage": "Investigation of Secondary_Bud_Hardiness_Disposition and its interaction with secondary shoot fruitfulness at the University of Minnesota evaluated both hardiness parameters and crop recovery potential across 20 cultivars following controlled winter injury treatments. ||Secondary bud LT50 at maximum hardiness ranged from -22.4°C ('Merlot') to -39.5°C ('Frontenac'), with the secondary-primary hardiness differential (SPHD) ranging from 2.2°C to 5.3°C among cultivars. ||Following experimental exposure to temperatures killing >90% of primary buds, secondary shoot fruitfulness varied from 0.15 clusters/shoot ('Foch', minimal recovery) to 1.45 clusters/shoot ('Frontenac', excellent recovery). ||The product of secondary bud survival probability and secondary shoot fruitfulness defined a \"crop recovery index\" that varied 8-fold among cultivars. 'Marquette' exhibited an optimal combination of strong Secondary_Bud_Hardiness_Disposition (LT50 -37.8°C, SPHD 3.8°C) and good secondary fruitfulness (1.1 clusters/shoot), achieving 65% crop recovery following simulated severe winter injury. ||Conversely, 'St. ||Croix' showed excellent secondary hardiness (LT50 -38.2°C) but poor secondary fruitfulness (0.35 clusters/shoot), limiting effective recovery to 25% of potential crop. ||These findings demonstrate that Secondary_Bud_Hardiness_Disposition must be evaluated alongside secondary shoot fruitfulness to assess true crop security in cold climates.",
    "editor_note": "Secondary_Bud_Hardiness_Disposition is_a Bud_Cold_Hardiness_Disposition. ||Secondary buds are more cold hardy than primary buds but produce less fruitful shoots, serving as backup for crop recovery following primary bud damage. ||The economic value of secondary bud survival depends on secondary shoot fruitfulness, which varies among cultivars. ||The secondary-primary hardiness differential (typically 2-4°C) defines a temperature window where primary buds are killed but secondary buds survive, enabling partial crop recovery. ||Breeding for cold-climate adaptation should consider both secondary bud hardiness and secondary shoot fruitfulness.  This disposition represents the cold tolerance of the bud structure that produces secondary shoots following primary bud damage, typically bearing 30-70% of the cluster number and reduced cluster weight compared to primary shoots but providing meaningful crop recovery capacity. ||The secondary bud develops in the axil of the first leaf primordium of the primary bud, remaining smaller and less differentiated than the primary bud throughout dormancy, characteristics that contribute to its enhanced cold hardiness. ||Secondary buds typically achieve LT50 values 2-4°C colder than primary buds within the same cultivar, representing a significant survival advantage during intermediate freeze events that kill primary but spare secondary buds. ||The fruitfulness of secondary shoots varies substantially among cultivars, with some cultivars producing reasonably fruitful secondary growth (0.8-1.5 clusters per shoot) while others produce primarily vegetative secondary shoots (0-0.3 clusters per shoot). ||Cultivars combining enhanced Secondary_Bud_Hardiness_Disposition with high secondary shoot fruitfulness provide superior crop recovery potential following winter damage, an important trait combination for cold-climate viticulture.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Howell GS (2001) Sustainable grape productivity and the growth-yield relationship: a review, American Journal of Enology and Viticulture 52:165-174|| Dami IE et al. (2012) Evaluation of winter injury and subsequent performance of grapevine cultivars in Ohio, Acta Horticulturae 932:235-241|| Pool RM et al. (1990) Environmental factors controlling cold hardiness and dormancy in grapevines, VITIS Journal of Grapevine Research 29:129-144"
  },
  "Tertiary_Bud_Hardiness_Disposition": {
    "definition": "A Tertiary_Bud_Hardiness_Disposition is a Bud_Cold_Hardiness_Disposition that inheres specifically in the tertiary bud primordium within the compound grapevine bud and is realized through the supercooling capacity and freeze avoidance mechanisms of this smallest, least differentiated bud component that serves as a last-resort growth point when both primary and secondary buds are killed.", 
    "alternative_term": "tertiary bud freeze tolerance | third bud hardiness | last-resort bud LT50 |+ Tertiärknospen-Härte-Disposition | Drittknospen-Frosthärte | Reserveknospen-Kältetoleranz",
    "example_of_usage": "Assessment of Tertiary_Bud_Hardiness_Disposition following the polar vortex event of January 2014 in eastern North America provided field validation of laboratory hardiness measurements across vineyards experiencing temperatures from -25°C to -35°C. ||Post-winter evaluation of 12 cultivars across 8 sites documented the hierarchy of bud component survival and subsequent shoot development. ||At sites experiencing -30°C minimum temperature, V. vinifera cultivars ('Riesling', 'Cabernet Franc') suffered 100% primary and secondary bud mortality, with only tertiary buds surviving (15-40% survival) and producing exclusively vegetative growth—no crop was harvested. ||Cold-hardy hybrids ('Frontenac', 'Marquette') at the same sites retained substantial secondary bud survival (45-70%) enabling 40-55% crop recovery. ||At the most severely affected site (-35°C minimum), even 'Frontenac' lost all primary and secondary buds, but Tertiary_Bud_Hardiness_Disposition enabled 60% tertiary bud survival and vine persistence. ||Vines relying on tertiary growth required 2-3 seasons to fully recover canopy architecture and return to normal production. ||These observations confirm that Tertiary_Bud_Hardiness_Disposition provides vineyard survival insurance against extreme cold events but cannot substitute for primary and secondary hardiness for crop production, defining its role as a last-resort persistence mechanism rather than a production trait.",
    "editor_note": "Tertiary_Bud_Hardiness_Disposition is_a Bud_Cold_Hardiness_Disposition. ||Tertiary buds are the most cold hardy but least fruitful bud component, serving as a survival mechanism for vine persistence following catastrophic winter damage. ||Tertiary shoots are typically vegetative or minimally fruitful, providing no commercial crop but enabling canopy regeneration and vineyard persistence. ||The tertiary-primary hardiness differential (typically 4-7°C) defines the margin of vine survival capacity beyond crop production thresholds. ||Tertiary bud hardiness is most relevant for assessing vineyard survival risk in extreme continental climates where temperatures may exceed both primary and secondary bud hardiness thresholds.  This disposition represents the cold tolerance of the most rudimentary bud structure, which produces tertiary shoots that are typically vegetative or minimally fruitful (0-0.5 clusters per shoot in most cultivars), providing vine survival and canopy recovery but essentially no commercial crop following severe winter damage. ||The tertiary bud develops in the axil of the second leaf primordium of the primary bud and remains the smallest and least differentiated of the three bud components, characteristics that confer maximum cold hardiness. ||Tertiary buds typically achieve LT50 values 4-7°C colder than primary buds, representing the extreme low-temperature survival capacity of the dormant bud complex. ||While tertiary bud survival rarely contributes meaningfully to crop production, it enables vine survival and canopy regeneration following catastrophic winter events, maintaining vineyard infrastructure for recovery in subsequent seasons. ||Tertiary_Bud_Hardiness_Disposition thus represents vine survival capacity rather than crop production potential, with its primary value being vineyard persistence following extreme cold events that exceed the hardiness of both primary and secondary buds.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sabbatini P, Howell GS (2013) Freezing temperature responses of primary, secondary, and tertiary grape buds during natural cold acclimation, Acta Horticulturae 978:307-313|| Dami IE et al. (2012) Evaluation of winter injury and subsequent performance of grapevine cultivars in Ohio, Acta Horticulturae 932:235-241|| Zabadal TJ et al. (2007) Winter Injury to Grapevines and Methods of Protection, Michigan State University Extension Bulletin E-2930"
  },
  "Cane_Cold_Hardiness_Disposition": {
    "definition": "A Cane_Cold_Hardiness_Disposition is a Midwinter_Hardiness_Disposition that inheres in the dormant canes (one-year-old wood) of a Vitis vinifera plant and is realized through the freezing tolerance of cane tissues including bark, phloem, cambium, xylem, and pith, determining the survival of shoot framework that supports bud positioning and vascular connectivity to the vine's permanent structure.", 
    "alternative_term": "shoot cold hardiness | one-year wood freezing tolerance | cane winter hardiness |+ Trieb-Kältehärte-Disposition | Rutenholz-Frosthärte | Einjähriges-Holz-Winterhärte",
    "example_of_usage": "Systematic characterization of Cane_Cold_Hardiness_Disposition at Michigan State University employed controlled freezing of dormant cane sections with subsequent assessment of tissue-specific damage across 20 cultivars. ||Cane segments were frozen to temperatures from -20°C to -40°C in 2.5°C increments, held for 4 hours, then slowly thawed and evaluated for browning in phloem, cambium, xylem rays, and pith at 48 hours post-treatment. ||Additionally, electrical conductivity of freeze-thaw leachate provided integrated damage assessment. ||Cane_Cold_Hardiness_Disposition showed substantial cultivar variation, with V. vinifera 'Riesling' exhibiting phloem LT50 = -26°C, cambium LT50 = -27°C, and xylem LT50 = -29°C, while the cold-hardy hybrid 'Frontenac' achieved phloem LT50 = -35°C, cambium LT50 = -36°C, and xylem LT50 = -38°C. ||The differential between primary bud and cane phloem LT50 (the \"bud-cane gap\") ranged from 3°C ('La Crescent') to 8°C ('Marquette'), with larger gaps indicating greater likelihood that buds would be killed while canes remain functional. ||Field validation following the 2014 polar vortex (minimum -34°C) confirmed that cultivars with cane phloem LT50 above -34°C showed vascular dysfunction symptoms including delayed and weak budbreak, shoot dieback, and reduced vigor even from surviving buds, demonstrating that Cane_Cold_Hardiness_Disposition assessment is essential for predicting vine recovery capacity beyond simple bud survival.",
    "editor_note": "Cane_Cold_Hardiness_Disposition is_a Midwinter_Hardiness_Disposition. ||Cane hardiness encompasses multiple tissues with different freezing behaviors and damage thresholds, addressed through child classes Phloem_Hardiness_Disposition, Xylem_Hardiness_Disposition, and Cambium_Hardiness_Disposition. ||Cane damage can compromise shoot development even when buds survive, making cane hardiness assessment important for complete winter injury prediction. ||Canes are generally hardier than buds, so cane damage indicates severe cold events exceeding normal bud protection thresholds.  This disposition represents the cold hardiness of the current season's mature shoots that will bear the following year's fruiting wood, with cane survival essential for maintaining trained vine architecture, providing vascular supply to retained buds, and avoiding the need for retraining from trunk or cordon tissues following winter damage. ||Cane tissues generally achieve greater cold hardiness than primary buds within the same cultivar, with the hardiness hierarchy typically being primary bud < secondary bud < tertiary bud < phloem < cambium ≤ xylem, creating a damage progression where buds are killed before cane function is compromised. ||However, severe cold events can damage cane tissues, disrupting vascular continuity even when some buds survive, and resulting in weak, poorly supplied shoots or complete failure of bud break despite apparent bud viability. ||Cane_Cold_Hardiness_Disposition encompasses multiple tissue types with distinct freezing behaviors, with phloem showing freeze tolerance through controlled extracellular ice formation, xylem exhibiting deep supercooling in ray parenchyma cells, and cambium requiring protection of the meristematic zone for spring growth resumption. ||Assessment of cane hardiness through controlled freezing with subsequent tissue browning evaluation or electrical conductivity measurements provides important complement to bud hardiness data for comprehensive winter damage prediction.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Wolpert JA, Howell GS (1985) Cold acclimation of Concord grapevines II. Natural acclimation pattern and tissue moisture decline in canes and primary buds of bearing vines, American Journal of Enology and Viticulture 36:189-194|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Zabadal TJ et al. (2007) Winter injury to grapevines and methods of protection, Michigan State University Extension Bulletin E-2930"
  },
  "Phloem_Hardiness_Disposition": {
    "definition": "A Phloem_Hardiness_Disposition is a Cane_Cold_Hardiness_Disposition that inheres specifically in the phloem tissue of dormant grapevine canes and is realized through the freezing tolerance of sieve elements, companion cells, and phloem parenchyma, determining the capacity for carbohydrate transport to support spring growth initiation and early shoot development.", 
    "alternative_term": "phloem freezing tolerance | inner bark hardiness | assimilate transport tissue cold resistance |+ Phloem-Härte-Disposition | Basthärte | Siebelement-Kältetoleranz",
    "example_of_usage": "Detailed investigation of Phloem_Hardiness_Disposition at Cornell University examined phloem freezing injury patterns and functional consequences across 15 cultivars using controlled freezing, histological assessment, and spring growth monitoring. ||Dormant cane sections were frozen to target temperatures, sectioned longitudinally through the bark, and scored for phloem browning on a 0-5 scale (0 = no browning, 5 = complete necrosis). ||LT50 values were determined by probit analysis. ||Phloem_Hardiness_Disposition ranged from LT50 = -24°C ('Merlot') to LT50 = -37°C ('Frontenac'). ||Histological examination revealed that initial freezing damage appeared as discrete brown zones in phloem parenchyma at temperatures 2-3°C above lethal threshold, progressing to complete phloem necrosis at and below LT50. ||Functional assessment tracked carbohydrate mobilization in spring by measuring starch depletion in xylem rays and sugar accumulation in developing buds. ||Canes with partial phloem damage (browning score 2-3) showed 40% slower starch mobilization and 25% lower bud sugar content at budbreak compared to undamaged controls, correlating with reduced shoot vigor (35% shorter shoots at 30 days post-budbreak). ||Complete phloem kill (score 5) resulted in bud failure despite apparent bud viability, as carbohydrate supply was severed. ||These findings demonstrate that Phloem_Hardiness_Disposition determines not only tissue survival but functional capacity for supporting spring growth, with partial damage causing quantitative growth reduction before complete failure threshold.",
    "editor_note": "Phloem_Hardiness_Disposition is_a Cane_Cold_Hardiness_Disposition. ||Phloem is typically the most cold-sensitive vascular tissue in canes, setting the functional limit for carbohydrate transport even when xylem water conduction remains intact. ||Phloem survives freezing through freeze tolerance (controlled extracellular ice formation) rather than supercooling. ||Partial phloem damage causes growth reduction proportional to damage severity, while complete damage severs carbohydrate supply to distal tissues. ||Phloem damage is assessed by browning of inner bark in cross-sections.  This disposition represents the cold hardiness of the primary assimilate transport tissue, with phloem survival essential for mobilizing stored carbohydrates from roots and trunk to developing buds and shoots in spring. ||Phloem tissue survives freezing through a freeze-tolerance mechanism involving controlled ice formation in extracellular spaces, cellular dehydration as water moves to growing ice crystals, and membrane/protein stabilization through accumulated cryoprotectants (sugars, proline, dehydrins). ||The relatively thin-walled, metabolically active cells of phloem are generally more cold-sensitive than the thick-walled, largely non-living cells of xylem, establishing phloem as the limiting vascular tissue for cold hardiness in most cultivars. ||Phloem damage from freezing is visible as browning of the inner bark when canes are cross-sectioned, progressing from scattered brown flecks (minor damage) to complete browning (lethal damage). ||Even partial phloem damage can restrict carbohydrate supply to developing shoots, causing weak growth, poor fruit set, and delayed canopy development. ||Phloem_Hardiness_Disposition is typically 3-8°C greater than primary bud hardiness within the same cultivar, providing a buffer that usually protects vascular function when buds are killed, but severe cold events can damage phloem and compromise vine recovery.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ashworth EN (1984) Xylem development in Prunus flower buds and the relationship to deep supercooling, Plant Physiology 74:862-865|| Wolpert JA, Howell GS (1985) Cold acclimation of Concord grapevines II. Natural acclimation pattern and tissue moisture decline, American Journal of Enology and Viticulture 36:189-194|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235"
  },
  "Xylem_Hardiness_Disposition": {
    "definition": "A Xylem_Hardiness_Disposition is a Cane_Cold_Hardiness_Disposition that inheres specifically in the xylem tissue of dormant grapevine canes and is realized through the freezing tolerance of xylem parenchyma cells (ray and axial parenchyma) and the structural integrity of vessel elements and fibers, determining the capacity for water transport and structural support of spring growth.", 
    "alternative_term": "xylem freezing tolerance | wood parenchyma hardiness | ray parenchyma cold resistance |+ Xylem-Härte-Disposition | Holzhärte | Xylemparenchym-Kältetoleranz",
    "example_of_usage": "Investigation of Xylem_Hardiness_Disposition at Washington State University employed differential thermal analysis (DTA) to detect low-temperature exotherms corresponding to intracellular freezing in xylem ray parenchyma across 18 cultivars at maximum midwinter hardiness. ||DTA of cane sections revealed distinct exotherm profiles, with high-temperature exotherms (HTEs) representing extracellular ice formation in apoplast and vessel lumens (non-lethal), and low-temperature exotherms (LTEs) representing lethal intracellular freezing in supercooled parenchyma. ||Xylem_Hardiness_Disposition, defined by LTE temperature, ranged from -27°C ('Merlot') to -42°C ('Valiant'), with xylem consistently the hardiest cane tissue. ||The xylem-phloem hardiness differential ranged from 2°C ('Frontenac') to 5°C ('Cabernet Franc'), indicating cultivar-specific vulnerability hierarchies. ||Anatomical analysis revealed that ray parenchyma cell size correlated with supercooling capacity, with smaller cells (mean diameter 12 μm in 'Frontenac') supercooling to lower temperatures than larger cells (22 μm in 'Merlot'), consistent with homogeneous ice nucleation theory predicting greater supercooling in smaller volumes. ||Following extreme cold exposure (-38°C) in field conditions, cultivars with Xylem_Hardiness_Disposition below this threshold showed spring symptoms including delayed budbreak, reduced xylem sap flow (measured by bleeding after pruning cuts), and impaired starch mobilization from ray parenchyma. ||These findings establish xylem ray parenchyma supercooling limits as the ultimate cold tolerance boundary in grapevine canes.",
    "editor_note": "Xylem_Hardiness_Disposition is_a Cane_Cold_Hardiness_Disposition. ||Xylem parenchyma survives freezing through deep supercooling, distinct from the freeze-tolerance mechanism of phloem. ||LTEs detected by DTA represent lethal intracellular freezing when supercooling limits are exceeded. ||Xylem is typically the hardiest cane tissue, so xylem damage indicates extreme cold events. ||Ray parenchyma stores starch critical for spring growth initiation, so xylem damage affects both water transport and carbohydrate mobilization.  This disposition represents the cold hardiness of the water-conducting and mechanical support tissue, with xylem function essential for supplying water to developing buds and shoots and maintaining cane structural integrity. ||Xylem exhibits a complex freezing response, with the non-living vessel elements and fibers tolerating ice formation in their lumens (indeed, winter embolism is common and resolved by spring root pressure), while living xylem parenchyma cells—particularly ray parenchyma containing stored starch—survive through deep supercooling, maintaining liquid water within cells to temperatures far below the equilibrium freezing point. ||Deep supercooling capacity in grapevine xylem parenchyma is limited by ice nucleation events, with lethal intracellular freezing occurring when supercooling limits are exceeded, detectable as low-temperature exotherms (LTEs) in differential thermal analysis. ||The supercooling limit of xylem ray parenchyma represents the absolute cold tolerance boundary for xylem function, typically the hardiest tissue in canes and exceeded only in the most extreme cold events. ||Xylem damage manifests as browning of ray parenchyma visible in cross-sections and can disrupt spring water transport and carbohydrate storage/mobilization functions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pierquet P, Stushnoff C (1980) Relationship of low temperature exotherms to cold injury in Vitis riparia Michx., American Journal of Enology and Viticulture 31:1-6|| George MF et al. (1974) Low temperature exotherms and woody plant distribution, HortScience 9:519-522|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235"
  },
  "Cambium_Hardiness_Disposition": {
    "definition": "A Cambium_Hardiness_Disposition is a Cane_Cold_Hardiness_Disposition that inheres specifically in the vascular cambium of dormant grapevine canes and is realized through the freezing tolerance of this meristematic tissue layer, determining the capacity for spring resumption of secondary growth and regeneration of functional vascular tissues.", 
    "alternative_term": "cambium freezing tolerance | meristem cold hardiness | vascular cambium winter resistance |+ Kambium-Härte-Disposition | Kambiumfrosthärte | Meristem-Kältetoleranz",
    "example_of_usage": "Assessment of Cambium_Hardiness_Disposition at the Finger Lakes Grape Program examined cambium survival patterns and regeneration capacity across 12 cultivars following natural and controlled cold exposure. ||Controlled freezing of cane sections to temperatures from -25°C to -40°C was followed by histological examination of the cambial zone, scoring cambium viability on a 0-5 scale (0 = fully viable, 5 = completely dead) based on cell browning and structural integrity. ||Cambium_Hardiness_Disposition ranged from LT50 = -25°C ('Cabernet Franc') to LT50 = -38°C ('Frontenac'), with cambium hardiness intermediate between phloem and xylem within each cultivar. ||Histological detail revealed that cambium death initiated in localized patches at temperatures 2-3°C above LT50, progressing to coalescent and then circumferential death at and below LT50. ||Recovery experiments tracked cambial regeneration following partial damage. ||Canes with 30-50% cambium kill (score 2) showed successful regeneration from surviving sectors, producing continuous cambial ring within 6 weeks of spring growth initiation. ||Canes with 70-90% cambium kill (score 4) showed incomplete regeneration with persistent gaps, resulting in sectored growth and reduced cane diameter increment. ||Complete cambium death (score 5) eliminated secondary growth capacity entirely. ||These findings demonstrate that Cambium_Hardiness_Disposition determines not only immediate tissue survival but long-term regenerative capacity, with partial damage recoverable through cambial proliferation while complete circumferential loss is permanent.",
    "editor_note": "Cambium_Hardiness_Disposition is_a Cane_Cold_Hardiness_Disposition. ||The vascular cambium is the lateral meristem responsible for secondary growth, positioned as a single-cell layer between phloem and xylem. ||Cambium hardiness is typically intermediate between the more sensitive phloem and hardier xylem. ||Cambium damage appears as browning at the phloem-xylem interface. ||Partial cambium damage can recover through proliferation from surviving sectors, but complete circumferential death eliminates growth capacity permanently. ||Cambium survival is critical for long-term vine recovery and wound healing.  This disposition represents the cold hardiness of the single-cell-layer lateral meristem positioned between phloem and xylem, with cambium survival essential for producing new xylem and phloem to replace winter-damaged or aging vascular tissues and for wound healing following pruning cuts or mechanical injury. ||The vascular cambium, composed of fusiform initials (producing axial vascular elements) and ray initials (producing vascular rays), is a thin but critically important tissue whose loss eliminates the vine's capacity for radial growth and vascular regeneration. ||Cambium cells survive freezing through mechanisms similar to phloem (freeze tolerance with controlled extracellular ice formation), with hardiness typically intermediate between phloem and xylem. ||Cambium damage manifests as a dark brown or black line at the phloem-xylem interface when canes are cross-sectioned, and can occur as isolated patches or complete circumferential death depending on cold severity and cultivar hardiness. ||Partial cambium kill allows recovery through proliferation of surviving cambial sectors, while complete circumferential cambium death results in permanent loss of growth capacity in affected tissues. ||Cambium_Hardiness_Disposition is particularly important for vine longevity and recovery from severe winter damage, as cambial regeneration underlies all wound healing and structural repair processes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ashworth EN, Wisniewski ME (1991) Response of fruit tree tissues to freezing temperatures, HortScience 26:501-504|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Zabadal TJ et al. (2007) Winter injury to grapevines and methods of protection, Michigan State University Extension Bulletin E-2930"
  },
  "Trunk_Cold_Hardiness_Disposition": {
    "definition": "A Trunk_Cold_Hardiness_Disposition is a Midwinter_Hardiness_Disposition that inheres in the trunk (permanent woody structure) of a Vitis vinifera vine and is realized through the freezing tolerance of trunk tissues including bark, phloem, cambium, xylem, and pith, determining survival of the vine's permanent framework and the graft union in grafted vines.", 
    "alternative_term": "trunk freezing tolerance | permanent wood hardiness | vine framework cold resistance |+ Stammkältehärte-Disposition | Stammfrosthärte | Rebstamm-Winterhärte",
    "example_of_usage": "Long-term evaluation of Trunk_Cold_Hardiness_Disposition at the University of Minnesota documented trunk survival and damage patterns across 30 cultivars through 20 winters including multiple severe events with minima below -35°C. ||Trunk damage was assessed annually by visual inspection for bark splitting, canker development, and crown injury, with destructive sampling of damaged vines to evaluate internal tissue condition. ||Cultivar differences in Trunk_Cold_Hardiness_Disposition were substantial and consistent across events. ||V. vinifera cultivars including 'Riesling' and 'Pinot Noir' showed chronic trunk damage with 15-40% of vines exhibiting bark splitting or crown injury following winters with minima below -28°C, and cumulative vine mortality of 35-60% over the 20-year period. ||Cold-hardy hybrids including 'Frontenac' and 'Marquette' showed minimal trunk damage (< 5% of vines affected) even following -35°C events, with cumulative mortality below 10%. ||The graft union proved critical in grafted plantings, with scion-rootstock combinations showing graft union failure when rootstock hardiness substantially exceeded scion hardiness, creating mechanical stress from differential tissue survival. ||Own-rooted 'Frontenac' showed 100% trunk survival, while 'Frontenac' grafted to the less-hardy '3309C' rootstock showed 12% graft union failure following -34°C exposure. ||These findings establish Trunk_Cold_Hardiness_Disposition as the foundation of long-term vineyard sustainability in cold climates, with graft union compatibility an additional consideration in grafted systems.",
    "editor_note": "Trunk_Cold_Hardiness_Disposition is_a Midwinter_Hardiness_Disposition. ||Trunk hardiness determines vine survival independent of annual crop production, representing the highest-stakes cold tolerance parameter. ||Trunk damage includes bark splitting, southwest injury, crown injury, and graft union failure, each with distinct mechanisms and patterns. ||Graft union hardiness depends on both scion and rootstock tissue hardiness and their compatibility under freeze stress. ||Trunk death requires vine replacement (multi-year loss), while cane and bud damage affect only current-season production.  This disposition represents the cold hardiness of the perennial structure that represents years to decades of vineyard investment, with trunk survival essential for maintaining trained vine architecture, supporting cordon and cane renewal, and preserving the scion-rootstock connection in grafted vines. ||Trunk tissues generally achieve similar or greater cold hardiness than corresponding cane tissues, benefiting from larger thermal mass (slower cooling rates), greater insulation from bark accumulation, and in some cases, protection from snow cover at lower trunk positions. ||However, the trunk contains critical vulnerable zones including the graft union (often the least hardy point in grafted vines), the crown region at soil level (subject to temperature extremes), and any previous wound sites where bark protection is compromised. ||Trunk damage patterns include localized bark splitting (rapid cooling creating differential contraction), southwest injury (freeze-thaw cycles on sun-exposed bark), crown injury (extreme cold at poorly insulated soil surface), and graft union failure (differential hardiness between scion and rootstock tissues). ||Trunk_Cold_Hardiness_Disposition is the ultimate determinant of vine survival, as trunk death necessitates vine replacement regardless of bud or cane condition, representing multi-year production loss and substantial replanting costs.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Howell GS (2000) Grapevine cold hardiness: mechanisms of cold acclimation, mid-winter hardiness maintenance, and spring deacclimation, Proceedings of the ASEV 50th Anniversary Annual Meeting|| Zabadal TJ et al. (2007) Winter injury to grapevines and methods of protection, Michigan State University Extension Bulletin E-2930"
  },
  "Root_Cold_Hardiness_Disposition": {
    "definition": "A Root_Cold_Hardiness_Disposition is a Midwinter_Hardiness_Disposition that inheres in the root system of a Vitis plant and is realized through the freezing tolerance of root tissues, determining survival of the below-ground vine structure that anchors the plant, absorbs water and nutrients, stores carbohydrates, and in grafted vines, defines the rootstock genotype contribution to vine performance.", 
    "alternative_term": "root freezing tolerance | below-ground cold hardiness | root system winter hardiness |+ Wurzel-Kältehärte-Disposition | Wurzelfrosthärte | Wurzelsystem-Winterhärte",
    "example_of_usage": "Systematic evaluation of Root_Cold_Hardiness_Disposition at South Dakota State University assessed root freezing tolerance across 20 rootstock genotypes and own-rooted cultivars using controlled freezing of excavated root samples. ||Root segments (5-10 mm diameter) were frozen to temperatures from -5°C to -20°C in 2.5°C increments, with viability assessed by electrolyte leakage and vital staining (TTC reduction). ||Root_Cold_Hardiness_Disposition showed strong genotypic variation correlated with species background. ||V. vinifera roots ('Riesling' own-rooted) exhibited LT50 = -6.5°C, substantially less hardy than the same cultivar's cane phloem (LT50 = -26°C), demonstrating the characteristic 15-20°C hardiness deficit of roots versus shoots. ||American species rootstocks showed enhanced Root_Cold_Hardiness_Disposition, with V. riparia 'Gloire' at LT50 = -14°C, '3309C' (V. riparia × V. rupestris) at LT50 = -12°C, and cold-selected 'Minnesota 1211' at LT50 = -18°C. ||Soil temperature monitoring across 5 winters revealed that root zone temperatures (30 cm depth) remained above -8°C even when air temperatures reached -35°C under adequate snow cover, but dropped to -14°C during a snow-free January period, causing 40% root mortality in V. vinifera own-rooted vines while V. riparia-based rootstocks showed less than 10% damage. ||These findings demonstrate that Root_Cold_Hardiness_Disposition is normally non-limiting due to soil thermal buffering, but becomes critical under inadequate insulation conditions, favoring cold-hardy rootstock selection in continental climates.",
    "editor_note": "Root_Cold_Hardiness_Disposition is_a Midwinter_Hardiness_Disposition. ||Roots are substantially less cold hardy than above-ground tissues (8-15°C differential) because they do not experience acclimating conditions and are normally protected by soil thermal buffering. ||Root hardiness becomes limiting only when soil freezing exceeds thermal buffering capacity (snow-free periods, exposed sandy soils). ||Rootstock genotype determines root hardiness in grafted vines independent of scion. ||Root death eliminates the entire vine regardless of scion tissue condition, making root hardiness the ultimate survival threshold under extreme soil freezing conditions.  This disposition represents a distinct and generally lower cold hardiness compared to above-ground tissues, as roots do not experience the same acclimating conditions (short photoperiods, gradual temperature decline) that induce maximum hardiness in shoots and buds, and are normally protected by soil thermal buffering. ||Root cold hardiness in grapevine is typically 8-15°C less than corresponding shoot tissue hardiness within the same genotype, with root LT50 values ranging from approximately -5°C to -12°C for V. vinifera roots to -12°C to -20°C for cold-hardy American species roots. ||Under normal soil conditions, thermal buffering, snow cover, and soil moisture maintain root zone temperatures well above lethal thresholds even when air temperatures are extreme. ||However, root cold damage can occur when soil freezes deeply during snow-free periods, in exposed sandy soils with poor thermal buffering, or in container-grown nursery stock. ||Root_Cold_Hardiness_Disposition is particularly important in rootstock selection for cold climates, as rootstock root hardiness determines the below-ground survival threshold independent of scion hardiness, and root death eliminates the entire vine regardless of above-ground tissue condition.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Howell GS, Shaulis NJ (1980) Factors influencing within-vine variation in the cold resistance of cane and primary bud tissues, American Journal of Enology and Viticulture 31:158-161|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Goffinet MC (2004) Anatomy of grapevine winter injury and recovery, Grape Research News 15:1-7"
  },
  "Acclimation_Disposition": {
    "definition": "An Acclimation_Disposition is a Cold_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the physiological processes by which freezing tolerance is acquired during autumn in response to environmental cues including shortening photoperiod and declining temperatures, transforming cold-sensitive growing tissues into cold-hardy dormant tissues capable of surviving winter freezing.", 
    "alternative_term": "cold acclimation capacity | hardening disposition | freezing tolerance acquisition |+ Akklimatisierungs-Disposition | Kälteabhärtungs-Kapazität | Frosthärte-Entwicklung",
    "example_of_usage": "Systematic characterization of Acclimation_Disposition at Cornell University tracked cold hardiness development through autumn across 20 cultivars using biweekly differential thermal analysis from September through January. ||Acclimation onset, rate, and completion were quantified by fitting logistic curves to hardiness trajectories. ||Cultivars showed striking variation in Acclimation_Disposition parameters. 'Concord' (V. labrusca) initiated acclimation earliest (September 15, at 14.2 hours daylength), showed rapid hardiness gain (1.8°C per week during October), and completed acclimation by December 1, achieving maximum hardiness of -28°C. ||V. vinifera 'Riesling' initiated later (October 1), acclimated more slowly (1.2°C per week), and did not complete acclimation until December 20, reaching maximum -22°C. ||The cold-hardy hybrid 'Frontenac' combined early initiation (September 20) with rapid rate (2.1°C per week) and high maximum (-33°C), representing optimal Acclimation_Disposition for continental climates. ||Critically, a November 15 freeze event (-18°C) during the acclimation period caused 60% bud mortality in incompletely acclimated 'Riesling' (hardiness only -15°C at that date) while fully acclimated 'Concord' (already at -24°C) showed no damage. ||These findings demonstrate that Acclimation_Disposition—encompassing timing, rate, and completeness—determines vulnerability to early winter cold events as much as maximum midwinter hardiness.",
    "editor_note": "Acclimation_Disposition is_a Cold_Tolerance_Disposition. ||This class addresses the process of acquiring cold hardiness, distinct from Midwinter_Hardiness_Disposition which addresses the hardiness state achieved. ||Child classes include Acclimation_Rate_Disposition (speed of hardiness acquisition), Maximum_Hardiness_Disposition (ultimate hardiness achieved), and Hardiness_Retention_Disposition (maintenance of hardiness through winter). ||Acclimation is triggered by photoperiod (first stage) and low temperature (second stage), with both stages required for complete hardiness development.  This disposition represents the dynamic capacity to develop cold hardiness, encompassing the rate at which hardiness increases, the timing of acclimation initiation and completion, and the maximum hardiness level ultimately achieved. ||Cold acclimation in grapevine involves coordinated changes across multiple levels including growth cessation and dormancy induction, periderm development and cane maturation, accumulation of cryoprotective compounds (soluble sugars, proline, raffinose family oligosaccharides, dehydrins), membrane lipid remodeling (increased unsaturation maintaining fluidity at low temperatures), gene expression reprogramming (CBF/DREB transcription factors activating cold-responsive genes), and water redistribution reducing cellular freezing vulnerability. ||The acclimation process occurs in two stages, with the first stage triggered primarily by short photoperiod and the second stage requiring exposure to low non-freezing temperatures, together producing the sequential development of freezing tolerance through autumn and early winter. ||Acclimation_Disposition varies among grapevine genotypes in acclimation rate, timing, and completeness, with inadequate acclimation representing a significant source of winter damage when early cold events precede full hardiness development.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Wake CMF, Fennell A (2000) Morphological, physiological and dormancy responses of three Vitis genotypes to short photoperiod, Physiologia Plantarum 109:203-210|| Thomashow MF (1999) Plant cold acclimation: freezing tolerance genes and regulatory mechanisms, Annual Review of Plant Physiology and Plant Molecular Biology 50:571-599"
  },
  "Acclimation_Rate_Disposition": {
    "definition": "An Acclimation_Rate_Disposition is an Acclimation_Disposition that inheres in a Vitis vinifera plant and is realized through the speed at which freezing tolerance increases during autumn cold acclimation, determining how rapidly the vine transitions from cold-sensitive to cold-hardy status following exposure to acclimation-inducing environmental signals.", 
    "alternative_term": "hardening rate | acclimation speed | cold hardiness acquisition rate |+ Akklimatisierungsrate-Disposition | Abhärtungsgeschwindigkeit | Frosthärte-Entwicklungsrate",
    "example_of_usage": "Detailed kinetic analysis of Acclimation_Rate_Disposition at the University of Minnesota monitored hardiness development at 5-day intervals from September 1 through December 15 across 25 cultivars to characterize acclimation dynamics with high temporal resolution. ||Primary bud LT50 was determined by differential thermal analysis at each timepoint, and acclimation rate was calculated as the slope of hardiness gain during the most rapid acclimation phase (typically October-November). ||Acclimation_Rate_Disposition varied 4-fold among cultivars, from 0.6°C per week ('Cabernet Franc') to 2.4°C per week ('Frontenac'). ||Notably, acclimation rate showed only moderate correlation with maximum hardiness (r = 0.52), indicating partial independence of these traits. 'La Crescent' exemplified rapid acclimation (2.2°C per week) achieving moderate maximum hardiness (-29°C), while 'Marquette' showed moderate rate (1.6°C per week) but superior maximum (-33°C). ||The practical significance of Acclimation_Rate_Disposition was demonstrated by an October 28 freeze event (-12°C) during a test year. ||At this date, rapid-acclimating 'Frontenac' had already reached -22°C hardiness (no damage), while slow-acclimating 'Cabernet Franc' had achieved only -8°C (severe damage despite similar starting points in September). ||Regression analysis identified Acclimation_Rate_Disposition as the primary predictor of damage from early-season cold events (r² = 0.71), exceeding the predictive value of maximum hardiness (r² = 0.35) for this damage type.",
    "editor_note": "Acclimation_Rate_Disposition is_a Acclimation_Disposition. ||Acclimation rate determines vulnerability to early-season cold events before full hardiness is achieved. ||Rate is partially independent of maximum hardiness, representing a distinct component of cold adaptation. ||Rapid acclimation is most advantageous in continental climates with abrupt autumn temperature drops. ||Rate is typically quantified as °C change in LT50 per week during active acclimation.  This disposition represents the kinetic component of cold acclimation, with faster acclimation rates providing earlier attainment of protective hardiness levels and reduced vulnerability to early-season cold events. ||Acclimation rate is typically quantified as the change in LT50 per unit time (°C per day or week) during the active hardening period, with rates in grapevine ranging from approximately 0.5°C per week in slow-acclimating genotypes to over 2.5°C per week in rapid acclimators. ||The rate of hardiness acquisition depends on both genotypic factors (responsiveness to photoperiod and temperature signals, efficiency of cryoprotectant biosynthesis, gene regulatory dynamics) and environmental conditions (temperature regime, photoperiod progression, moisture status). ||Rapid acclimation is advantageous in continental climates where autumn temperature can drop precipitously, but may be less critical in maritime climates with gradual seasonal transitions. ||Acclimation_Rate_Disposition is partially independent of maximum hardiness potential, as some genotypes acclimate rapidly to moderate hardiness levels while others acclimate slowly but achieve greater ultimate hardiness, creating distinct adaptation strategies for different climate patterns.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mills LJ et al. (2006) Timing of low temperature exposure affects cold hardiness and budbreak in Vitis vinifera, American Journal of Enology and Viticulture 57:528-535|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Kalberer SR et al. (2006) Deacclimation and reacclimation of cold-hardy plants: current understanding and emerging concepts, Plant Science 171:3-16"
  },
  "Maximum_Hardiness_Disposition": {
    "definition": "A Maximum_Hardiness_Disposition is an Acclimation_Disposition that inheres in a Vitis vinifera plant and is realized through the ultimate level of freezing tolerance achieved when cold acclimation is complete, representing the genetic ceiling for cold hardiness expression under optimal acclimation conditions.", 
    "alternative_term": "peak cold hardiness | maximum freezing tolerance | hardiness ceiling |+ Maximale-Härte-Disposition | Maximale-Frosthärte | Härtepotential",
    "example_of_usage": "Comprehensive cataloging of Maximum_Hardiness_Disposition at South Dakota State University compiled midwinter LT50 data for 150 cultivars and breeding selections spanning the diversity of cultivated grapevine, establishing a reference database for cold-climate cultivar selection. ||Primary bud LT50 was determined by differential thermal analysis at maximum hardiness (mid-January) over 3-5 winters per genotype to account for year-to-year variation. ||Maximum_Hardiness_Disposition ranged from -14°C ('Grenache', least hardy V. vinifera tested) to -42°C ('Valiant', V. riparia × V. amurensis derivative), encompassing 28°C variation across the germplasm base. ||V. vinifera cultivars clustered between -15°C and -25°C, with 'Riesling' (-23°C) and 'Cabernet Franc' (-22°C) among the hardiest vinifera. ||Interspecific hybrids showed a continuum reflecting their species composition, with 'Frontenac' (-33°C), 'Marquette' (-32°C), and 'La Crescent' (-29°C) achieving commercially viable hardiness for the Upper Midwest. ||Year-to-year variation within genotypes averaged ±1.5°C, with rankings highly consistent across years (r = 0.94 between year pairs). ||The strong heritability of Maximum_Hardiness_Disposition (h² = 0.82) confirms its genetic basis and supports selection for this trait in breeding programs. ||Regional analysis established -25°C as the minimum Maximum_Hardiness_Disposition threshold for reliable production in USDA Zone 4 climates where temperatures routinely reach -30°C.",
    "editor_note": "Maximum_Hardiness_Disposition is_a Acclimation_Disposition. ||Maximum hardiness represents the genetic potential for cold tolerance, achieved under optimal acclimation conditions. ||This is the most commonly reported cold hardiness parameter in cultivar characterizations. ||Maximum hardiness shows high heritability and strong genetic control, varying from approximately -15°C (tender V. vinifera) to below -40°C (hardiest V. amurensis). ||Environmental factors can prevent achievement of genetic maximum if acclimation is incomplete.  This disposition represents the peak hardiness capacity that defines a genotype's potential to survive extreme midwinter cold, distinct from the rate or timing of hardiness acquisition. ||Maximum hardiness is typically achieved in mid-January in the Northern Hemisphere after completion of both photoperiod-induced and low-temperature-induced acclimation stages, and is quantified as the minimum LT50 value observed during the dormant season. ||The maximum hardiness potential of a genotype reflects the cumulative effectiveness of all cryoprotective mechanisms including membrane stabilization, cryoprotectant accumulation, dehydration tolerance, and deep supercooling capacity in xylem tissues. ||Maximum_Hardiness_Disposition shows strong genetic control with high heritability, ranging from approximately -15°C for the least hardy V. vinifera cultivars to below -40°C for the hardiest V. amurensis and V. riparia genotypes. ||Achievement of genetic maximum hardiness potential depends on adequate acclimation conditions, as truncated photoperiod exposure, insufficient chilling, or premature warm periods can prevent full hardiness expression. ||Maximum_Hardiness_Disposition is the primary trait reported in cultivar cold hardiness characterizations and the benchmark for cultivar suitability assessment in cold-climate regions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Mills LJ et al. (2006) Cold hardiness of Vitis vinifera and interspecific hybrid grapevine cultivars, American Journal of Enology and Viticulture 57:238-245|| Luby JJ (1991) Breeding cold-hardy fruit crops in Minnesota, HortScience 26:507-512"
  },
  "Hardiness_Retention_Disposition": {
    "definition": "A Hardiness_Retention_Disposition is an Acclimation_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to maintain acquired freezing tolerance at or near maximum levels throughout the midwinter period despite fluctuating temperatures, preventing premature loss of hardiness during transient warm periods before spring.", 
    "alternative_term": "hardiness stability | midwinter hardiness maintenance | cold tolerance persistence |+ Härte-Beibehaltungs-Disposition | Härtestabilität | Winterhärte-Aufrechterhaltung",
    "example_of_usage": "Investigation of Hardiness_Retention_Disposition at Michigan State University exposed dormant canes to controlled warming treatments (15°C for 3, 7, or 14 days) at monthly intervals from December through February, then assessed residual hardiness by differential thermal analysis. ||Cultivar differences in Hardiness_Retention_Disposition were substantial. 'Frontenac' demonstrated exceptional hardiness retention, losing only 2°C after 7 days at 15°C in January (from -33°C to -31°C) and fully recovering this loss within 5 days of return to cold conditions. 'Riesling' showed moderate retention, losing 5°C after equivalent treatment (from -23°C to -18°C) with incomplete recovery. 'Pinot Noir' exhibited poor Hardiness_Retention_Disposition, losing 8°C after 7 days warming (from -20°C to -12°C) with only 3°C recovery. ||The timing of warm exposure affected all cultivars, with February warming causing greater hardiness loss than December warming, reflecting decreasing dormancy depth through winter. ||Field relevance was demonstrated following a January thaw (7 days above 10°C) in year 3 of the study. ||Post-thaw hardiness measurements showed 'Frontenac' at -30°C (3°C loss), 'Riesling' at -16°C (7°C loss), and 'Pinot Noir' at -11°C (9°C loss). ||When temperatures subsequently dropped to -22°C, 'Pinot Noir' suffered 85% primary bud mortality while 'Frontenac' was undamaged. ||These findings establish Hardiness_Retention_Disposition as critical for winter survival in fluctuating climates.",
    "editor_note": "Hardiness_Retention_Disposition is_a Acclimation_Disposition. ||Hardiness retention determines vulnerability to cold events following midwinter thaws, a common damage scenario in variable continental climates. ||Retention is linked to dormancy depth, with deeper dormancy conferring greater hardiness stability. ||Cultivars differ substantially in retention capacity, partially independent of maximum hardiness. ||Poor hardiness retention combined with variable winter weather creates conditions for severe damage even when maximum hardiness would be adequate for static cold exposure.  This disposition represents the stability of the cold-hardy state once achieved, distinct from the initial acquisition of hardiness (acclimation rate) or the ultimate level achieved (maximum hardiness). ||Hardiness retention depends on dormancy depth and stability, with deeply dormant buds maintaining hardiness despite warm exposure while shallow-dormant buds may respond to warmth by initiating deacclimation. ||Genotypes differ substantially in their sensitivity to midwinter warming, with some cultivars showing rapid hardiness loss (2-4°C per day of warm exposure) while others maintain hardiness tenaciously (< 0.5°C loss per day). ||Strong Hardiness_Retention_Disposition is particularly valuable in climates with variable winter weather including midwinter thaws followed by return to severe cold, as hardiness lost during warm periods may not be fully recovered before subsequent cold events. ||The physiological basis of hardiness retention involves maintenance of cryoprotectant levels, continued suppression of growth-related gene expression, and stability of dormancy-regulating hormone balances (high ABA, low GA/cytokinin) despite temperature fluctuations.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kalberer SR et al. (2006) Deacclimation and reacclimation of cold-hardy plants: current understanding and emerging concepts, Plant Science 171:3-16|| Wolf TK, Cook MK (1992) Seasonal deacclimation patterns of three grape cultivars at constant warm temperature, American Journal of Enology and Viticulture 43:171-179|| Ferguson JC et al. (2011) Dynamic thermal profiles of grapevine cold hardiness, American Journal of Enology and Viticulture 62:407-413"
  },
  "Deacclimation_Disposition": {
    "definition": "A Deacclimation_Disposition is a Cold_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the physiological processes by which acquired freezing tolerance is lost in response to warming temperatures and increasing photoperiod, transitioning tissues from the cold-hardy dormant state toward active growth and renewed cold sensitivity.", 
    "alternative_term": "dehardening capacity | cold hardiness loss | deacclimation response |+ Deakklimatisierungs-Disposition | Enthärtungs-Kapazität | Frosthärte-Verlust",
    "example_of_usage": "Comprehensive analysis of Deacclimation_Disposition at Washington State University characterized hardiness loss kinetics across 22 cultivars by exposing dormant canes to forcing conditions (20°C, 16-hour photoperiod) at intervals from January through March and monitoring hardiness decline. ||Deacclimation rate (°C hardiness loss per day), lag time before deacclimation initiation, and final hardiness after 21 days forcing were quantified for each cultivar and date combination. ||Deacclimation_Disposition showed strong cultivar and timing effects. ||In January (deep endodormancy), all cultivars showed minimal deacclimation (< 2°C loss in 21 days) regardless of genetic background. ||By February 15 (post-chilling), dramatic cultivar differences emerged. 'Pinot Noir' exhibited rapid Deacclimation_Disposition with 2.1°C loss per day after 3-day lag, reaching -8°C (from -20°C initial) by day 21. 'Riesling' showed moderate deacclimation (1.4°C per day, 5-day lag, final -12°C from -23°C initial). 'Frontenac' demonstrated slow deacclimation (0.8°C per day, 8-day lag, final -22°C from -33°C initial). ||By March 1, even resistant cultivars showed increased deacclimation responsiveness. ||Field observations confirmed laboratory patterns, with rapid-deacclimating 'Pinot Noir' suffering 70% bud damage from a late February freeze following 10 days of warm weather, while slow-deacclimating 'Frontenac' showed 5% damage from the same event. ||These findings demonstrate that Deacclimation_Disposition critically determines late-winter and spring cold damage vulnerability.",
    "editor_note": "Deacclimation_Disposition is_a Cold_Tolerance_Disposition. ||This class addresses the process of losing cold hardiness, complementing Acclimation_Disposition which addresses hardiness acquisition. ||Child classes include Deacclimation_Resistance_Disposition (capacity to resist hardiness loss) and Reacclimation_Capacity_Disposition (capacity to regain lost hardiness). ||Deacclimation timing is regulated by dormancy status, with endodormant tissues resistant to deacclimation until chilling requirement is satisfied. ||Premature deacclimation creates vulnerability to late-winter and spring cold events.  This disposition represents the dynamic capacity for hardiness loss, encompassing the rate of deacclimation, the temperature threshold triggering deacclimation, and the responsiveness to warming cues. ||Deacclimation in grapevine involves reversal of many acclimation changes including catabolism of cryoprotective compounds, membrane lipid remodeling toward greater saturation, reactivation of growth-related gene expression, and hormonal shifts (declining ABA, increasing GA and cytokinins) preparing tissues for spring growth. ||The timing and rate of deacclimation reflect the release from endodormancy into ecodormancy and subsequently into active growth, with chilling requirement satisfaction determining the transition to deacclimation-competent state. ||Premature or excessively rapid deacclimation represents a significant source of winter and spring cold damage, as partially deacclimated tissues are vulnerable to temperature fluctuations that fully acclimated tissues would survive. ||Deacclimation_Disposition varies among genotypes in both the temperature sensitivity of hardiness loss and the rate of deacclimation once triggered, with some cultivars showing dangerous responsiveness to brief warm periods while others maintain hardiness tenaciously until sustained warming occurs.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kalberer SR et al. (2006) Deacclimation and reacclimation of cold-hardy plants: current understanding and emerging concepts, Plant Science 171:3-16|| Ferguson JC et al. (2014) Modeling dormant bud cold hardiness and budbreak in twenty-three Vitis genotypes reveals variation by region of origin, American Journal of Enology and Viticulture 65:59-71|| Pagter M, Arora R (2013) Winter survival and deacclimation of perennials under warming climate: physiological perspectives, Physiologia Plantarum 147:75-87"
  },
  "Deacclimation_Resistance_Disposition": {
    "definition": "A Deacclimation_Resistance_Disposition is a Deacclimation_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to resist or delay loss of acquired freezing tolerance in response to warming temperatures, maintaining protective hardiness levels despite exposure to deacclimation-inducing conditions.", 
    "alternative_term": "deacclimation stability | dehardening resistance | hardiness loss resistance |+ Deakklimatisierungs-Resistenz-Disposition | Enthärtungs-Resistenz | Härteverlust-Widerstand",
    "example_of_usage": "Quantitative assessment of Deacclimation_Resistance_Disposition at Cornell University employed controlled warming experiments to characterize resistance parameters across 18 cultivars following endodormancy release. ||Canes collected in late February (post-chilling) were exposed to 18°C forcing conditions, with hardiness assessed by differential thermal analysis at 2-day intervals for 20 days. ||Deacclimation_Resistance_Disposition was quantified by three parameters: threshold warmth accumulation to initiate deacclimation (degree-days above 0°C before first measurable hardiness loss), deacclimation lag (days at forcing temperature before deacclimation onset), and half-life (days to lose 50% of initial cold hardiness). 'Frontenac' exhibited exceptional Deacclimation_Resistance_Disposition with threshold of 180 degree-days, 9-day lag, and 18-day half-life. 'Riesling' showed intermediate resistance (threshold 95 degree-days, 5-day lag, 11-day half-life). 'Pinot Noir' demonstrated low resistance (threshold 45 degree-days, 2-day lag, 6-day half-life). ||Plotting hardiness trajectories revealed that after 14 days at 18°C, 'Frontenac' retained 75% of initial hardiness while 'Pinot Noir' retained only 25%. ||Field validation during a variable March with alternating warm (15°C) and cold (-15°C) periods showed that 'Pinot Noir' lost hardiness during each warm phase and sustained cumulative damage, while 'Frontenac' maintained sufficient hardiness throughout. ||Strong Deacclimation_Resistance_Disposition thus provides resilience against the repeated warm-cold cycles characteristic of continental spring weather.",
    "editor_note": "Deacclimation_Resistance_Disposition is_a Deacclimation_Disposition. ||Deacclimation resistance determines vulnerability to late-winter and spring cold events following warm periods. ||Resistance is quantified by threshold warmth to trigger deacclimation, lag time, and rate of hardiness loss once initiated. ||Resistance is partially independent of maximum hardiness, representing a distinct adaptive trait. ||High deacclimation resistance is particularly valuable in climates with variable spring weather, providing extended protection during the dormancy-to-growth transition.  This disposition represents resistance to premature hardiness loss, with high deacclimation resistance conferring extended protection during late-winter warm periods and variable spring weather. ||Deacclimation resistance reflects both dormancy depth (deeply dormant tissues are inherently resistant to warming responses) and intrinsic resistance of cellular cold tolerance mechanisms to disruption by warming. ||Genotypes with strong Deacclimation_Resistance_Disposition show minimal hardiness loss during brief warm periods, require extended or more intense warming to initiate deacclimation, and maintain protective hardiness later into spring, providing extended protection against late-season cold events. ||The temperature threshold for deacclimation initiation, the lag period before measurable hardiness loss begins, and the rate of hardiness decline once initiated all contribute to overall deacclimation resistance. ||Strong Deacclimation_Resistance_Disposition is particularly valuable in climates with highly variable late-winter and spring weather, where cycling between warm and cold conditions can repeatedly challenge deacclimation-susceptible cultivars while deacclimation-resistant cultivars maintain protective hardiness throughout the transition period.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ferguson JC et al. (2011) Dynamic thermal profiles of grapevine cold hardiness, American Journal of Enology and Viticulture 62:407-413|| Kalberer SR et al. (2006) Deacclimation and reacclimation of cold-hardy plants: current understanding and emerging concepts, Plant Science 171:3-16|| Wolf TK, Cook MK (1992) Seasonal deacclimation patterns of three grape cultivars at constant warm temperature, American Journal of Enology and Viticulture 43:171-179"
  },
  "Reacclimation_Capacity_Disposition": {
    "definition": "A Reacclimation_Capacity_Disposition is a Deacclimation_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to regain freezing tolerance following partial deacclimation when cold conditions return, recovering hardiness lost during warm periods to restore protective levels before subsequent cold events.", 
    "alternative_term": "rehardening capacity | hardiness recovery | cold tolerance restoration |+ Reakklimatisierungs-Kapazität-Disposition | Wiederhärtungs-Kapazität | Kältehärte-Wiederherstellung",
    "example_of_usage": "Investigation of Reacclimation_Capacity_Disposition at the University of Minnesota employed deacclimation-reacclimation cycling experiments to characterize recovery potential across 15 cultivars. ||Dormant canes were subjected to 7 days at 15°C (deacclimation), then returned to -3°C for 3, 7, or 14 days (reacclimation), with hardiness assessed by differential thermal analysis at each transition. ||The experiment was conducted in mid-February (soon after endodormancy release) and repeated in mid-March (advanced ecodormancy). ||In February, 'Frontenac' exhibited strong Reacclimation_Capacity_Disposition, losing 5°C during deacclimation (from -33°C to -28°C) but recovering 4°C within 7 days of cold return (to -32°C), representing 80% recovery of lost hardiness. 'Marquette' showed similar capacity (6°C loss, 5°C recovery, 83% restoration). 'Riesling' demonstrated moderate reacclimation (5°C loss, 3°C recovery, 60% restoration). 'Pinot Noir' showed poor Reacclimation_Capacity_Disposition (8°C loss, 2°C recovery, 25% restoration). ||In March, all cultivars showed diminished reacclimation capacity, with 'Frontenac' recovering only 50% of lost hardiness and 'Pinot Noir' showing essentially no recovery. ||Field observations following a March warm-cold cycle (10 days at 12°C followed by -18°C freeze) confirmed laboratory predictions, with high-reacclimation cultivars suffering minimal damage while low-reacclimation cultivars showed severe bud mortality. ||These findings establish Reacclimation_Capacity_Disposition as critical for spring cold damage avoidance in variable climates.",
    "editor_note": "Reacclimation_Capacity_Disposition is_a Deacclimation_Disposition. ||Reacclimation represents the capacity to reverse hardiness loss, providing resilience against warm-cold cycling in late winter and spring. ||Reacclimation capacity diminishes as the season progresses, with tissues eventually losing the ability to recover hardiness as growth approaches. ||Both magnitude (degrees recovered) and rate (speed of recovery) contribute to effective reacclimation. ||Reacclimation capacity combined with deacclimation resistance provides comprehensive protection against variable transitional-season weather.  This disposition represents the reversibility of deacclimation, with high reacclimation capacity enabling recovery from premature hardiness loss and providing resilience against the alternating warm and cold periods characteristic of transitional seasons. ||Reacclimation is possible only within limits, as tissues that have deacclimated beyond a certain threshold lose the capacity for hardiness recovery, and the reacclimation potential diminishes as the season progresses toward active growth. ||Reacclimation_Capacity_Disposition encompasses both the magnitude of hardiness recovery achievable (degrees of hardiness regained) and the rate of reacclimation (hardiness gain per day of cold exposure). ||Genotypes differ in reacclimation capacity, with some cultivars able to recover substantial hardiness rapidly (3-5°C within 72 hours of cold return) while others show limited or slow recovery. ||Strong reacclimation capacity combined with deacclimation resistance provides optimal protection against variable late-winter weather, as resistant genotypes experience less initial hardiness loss while high reacclimation capacity enables recovery of whatever hardiness is lost during unavoidable warm exposure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kalberer SR et al. (2006) Deacclimation and reacclimation of cold-hardy plants: current understanding and emerging concepts, Plant Science 171:3-16|| Pagter M, Arora R (2013) Winter survival and deacclimation of perennials under warming climate: physiological perspectives, Physiologia Plantarum 147:75-87|| Ferguson JC et al. (2011) Dynamic thermal profiles of grapevine cold hardiness, American Journal of Enology and Viticulture 62:407-413"
  },
  "Spring_Frost_Tolerance_Disposition": {
    "definition": "A Spring_Frost_Tolerance_Disposition is a Cold_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through mechanisms that enable survival of freezing temperatures occurring after budbreak when actively growing tissues have lost the cold hardiness characteristic of dormant tissues.", 
    "alternative_term": "post-budbreak frost tolerance | spring freeze resistance | late frost tolerance |+ Frühjahrsfrost-Toleranz-Disposition | Spätfrost-Resistenz | Austriebsfrost-Toleranz",
    "example_of_usage": "Comprehensive evaluation of Spring_Frost_Tolerance_Disposition at INRAE Bordeaux combined phenological monitoring, controlled frost exposure, and recovery assessment across 25 cultivars over 5 seasons to characterize the multiple components of spring frost adaptation. ||Budbreak date (50% buds at green tip stage) was recorded annually, young shoots at matched developmental stages were exposed to controlled frost (-3°C for 2 hours), and survival and regrowth were assessed at 14 days post-exposure. ||Spring_Frost_Tolerance_Disposition showed cultivar variation through multiple mechanisms. 'Riesling' exhibited frost avoidance through late budbreak (April 15 mean, 12 days after 'Chasselas'), escaping 3 of 5 recorded frost events entirely. ||When exposed to frost, 'Riesling' young shoots showed moderate tissue tolerance with 45% primary shoot survival at -3°C. 'Merlot' broke bud early (April 5) but demonstrated strong recovery capacity, with secondary buds activating within 8 days of primary shoot frost kill and producing 0.7 clusters per secondary shoot. 'Chardonnay' combined early budbreak with poor recovery (secondary shoot fruitfulness only 0.2 clusters), representing low overall Spring_Frost_Tolerance_Disposition. ||Field records confirmed that cultivar damage patterns matched expectations from component traits, with late-breaking 'Riesling' showing lowest cumulative frost damage over the 5-year period despite only moderate tissue tolerance.",
    "editor_note": "Spring_Frost_Tolerance_Disposition is_a Cold_Tolerance_Disposition. ||Spring frost tolerance is fundamentally different from midwinter hardiness because actively growing tissues cannot achieve comparable cold tolerance to dormant tissues. ||Protection depends on avoidance (late budbreak), limited tissue tolerance, and recovery capacity. ||Child classes include Late_Budbreak_Frost_Avoidance_Disposition (phenological escape) and Shoot_Frost_Recovery_Disposition (regeneration after damage). ||Spring frost tolerance is partially independent of midwinter hardiness, representing a distinct component of overall cold adaptation.  This disposition represents cold tolerance during the vulnerable post-dormancy growth period, fundamentally distinct from midwinter hardiness in that actively growing tissues possess inherently limited freezing tolerance regardless of genotype, and protection depends primarily on frost avoidance through phenological timing or rapid recovery rather than tissue-level freeze tolerance. ||Spring frost damage is a major cause of crop loss in viticulture, with developing shoots and inflorescences killed at temperatures between -2°C and -4°C depending on growth stage, tissue hydration, and freezing duration. ||Spring_Frost_Tolerance_Disposition encompasses both avoidance mechanisms (late budbreak timing that reduces frost encounter probability) and tolerance/recovery mechanisms (tissue-level cold tolerance of young shoots, capacity to regenerate from secondary buds or basal shoots following frost damage). ||The relative importance of avoidance versus recovery depends on regional frost patterns, with late budbreak favored in climates with reliable late spring frosts and recovery capacity more relevant where frost timing is unpredictable. ||Spring_Frost_Tolerance_Disposition is partially independent of midwinter hardiness, as cultivars with excellent dormant cold tolerance may break bud early and suffer spring frost damage, while less winter-hardy cultivars with late budbreak may escape spring frost entirely.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Friend AP et al. (2011) Delayed winter pruning and spring frost damage to grapevine buds, Australian Journal of Grape and Wine Research 17:214-218|| Trought MCT et al. (1999) Vineyard variability in Marlborough, New Zealand, American Journal of Enology and Viticulture 50:484-489"
  },
  "Late_Budbreak_Frost_Avoidance_Disposition": {
    "definition": "A Late_Budbreak_Frost_Avoidance_Disposition is a Spring_Frost_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through genetically determined late timing of spring budbreak, reducing the probability that vulnerable developing shoots will be present during frost events.", 
    "alternative_term": "late phenology frost escape | delayed budbreak | late bud development |+ Späte-Austriebs-Frostvermeidungs-Disposition | Verzögerter-Austrieb | Phänologische-Frostvermeidung",
    "example_of_usage": "Quantitative assessment of Late_Budbreak_Frost_Avoidance_Disposition at the University of British Columbia analyzed budbreak timing across 35 cultivars over 10 seasons, correlating phenology with spring frost damage records and characterizing the heat unit requirements underlying budbreak timing differences. ||Budbreak date (50% green tip) ranged from April 2 ('Chasselas', earliest) to April 22 ('Mourvèdre', latest), representing 20-day spread among commercial cultivars. ||Heat unit accumulation (base 10°C) from January 1 to budbreak showed strong cultivar differentiation, ranging from 85 degree-days ('Chasselas') to 165 degree-days ('Mourvèdre'). ||Late_Budbreak_Frost_Avoidance_Disposition effectiveness was validated by frost damage records. ||Over the 10-season study period, the site experienced frost events (< -2°C) after April 1 in 7 seasons, with last frost date ranging from April 5 to April 25. ||Early-budbreaking 'Chasselas' (April 2 mean budbreak) experienced damaging frost exposure in 6 of 7 frost years, while late-budbreaking 'Mourvèdre' (April 22) experienced exposure in only 2 of 7 years. ||Cumulative frost damage index (sum of damage severity across years) showed strong correlation with budbreak timing (r = -0.78). ||However, the trade-off with season length was evident, as 'Mourvèdre' failed to achieve adequate fruit maturity (< 20° Brix) in 3 of 10 seasons due to insufficient heat accumulation, while early-budbreaking cultivars consistently ripened. ||These findings demonstrate that Late_Budbreak_Frost_Avoidance_Disposition provides effective frost protection but requires balancing against season length constraints.",
    "editor_note": "Late_Budbreak_Frost_Avoidance_Disposition is_a Spring_Frost_Tolerance_Disposition. ||Late budbreak represents phenological escape from frost rather than enhanced tissue tolerance. ||Budbreak timing is determined by heat unit requirements after chilling satisfaction, with late cultivars requiring more accumulated warmth. ||Late budbreak provides statistical frost avoidance proportional to the phenological delay. ||Trade-offs exist with season length utilization, as late budbreak compresses the growing season and may delay maturity.  This disposition represents a phenological avoidance strategy, with late-budbreaking cultivars escaping spring frost damage by maintaining dormant, cold-hardy buds through the period of highest frost risk rather than through enhanced tolerance of actively growing tissues. ||Late budbreak timing is controlled by the interaction of chilling requirement satisfaction (release from endodormancy), heat unit accumulation requirement for budbreak (ecodormancy release and growth initiation), and base temperature thresholds for development, with late cultivars typically requiring higher accumulated heat units before visible budbreak. ||The effectiveness of late budbreak as a frost avoidance strategy depends on regional frost climatology, with greatest benefit in climates where the frost-free date is predictable and late budbreak reliably positions growth initiation after this date. ||In regions with erratic spring frost patterns, late budbreak provides statistical but not absolute protection, reducing frost encounter frequency rather than eliminating risk. ||Late_Budbreak_Frost_Avoidance_Disposition may involve trade-offs with season length utilization, as late budbreak compresses the growing season and may delay harvest, potentially conflicting with autumn frost avoidance or optimal fruit maturity in short-season climates.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duchêne E, Schneider C (2005) Grapevine and climatic changes: a glance at the situation in Alsace, Agronomy for Sustainable Development 25:93-99|| Jones GV, Davis RE (2000) Climate influences on grapevine phenology, grape composition, and wine production and quality for Bordeaux, France, American Journal of Enology and Viticulture 51:249-261|| Zapata C et al. (2017) Predicting key phenological stages for 17 grapevine cultivars, American Journal of Enology and Viticulture 68:60-72"
  },
  "Shoot_Frost_Recovery_Disposition": {
    "definition": "A Shoot_Frost_Recovery_Disposition is a Spring_Frost_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to regenerate productive shoots following frost damage to primary growing points, restoring canopy function and at least partial crop production through activation of secondary buds, latent buds, or basal shoots.", 
    "alternative_term": "frost recovery capacity | post-frost regeneration | shoot regrowth potential |+ Trieb-Frost-Erholungs-Disposition | Frostschadens-Regeneration | Trieb-Wiederaustrieb",
    "example_of_usage": "Detailed characterization of Shoot_Frost_Recovery_Disposition at Virginia Tech employed controlled spring frost simulations to assess recovery parameters across 20 cultivars. ||Primary shoots at the 3-5 leaf stage were exposed to -3.5°C for 90 minutes (conditions causing > 90% primary shoot mortality), and recovery was tracked over 30 days, recording secondary bud activation timing, secondary shoot vigor, and cluster count on replacement shoots. ||Shoot_Frost_Recovery_Disposition varied substantially among cultivars. 'Merlot' demonstrated exceptional recovery with secondary bud activation visible within 6 days, secondary shoot elongation rate of 3.2 cm/day (exceeding typical primary shoot rate), and 0.85 clusters per secondary shoot, enabling 60% crop recovery. 'Cabernet Franc' showed similar rapid activation (7 days) but lower secondary fruitfulness (0.55 clusters/shoot), yielding 40% recovery. 'Chardonnay' exhibited poor Shoot_Frost_Recovery_Disposition with delayed activation (12 days), slow secondary shoot growth (1.8 cm/day), and minimal fruitfulness (0.25 clusters/shoot), achieving only 18% crop recovery. ||Notably, secondary shoot cluster size was 20-35% smaller than primary shoot clusters across all cultivars, indicating that even with high secondary fruitfulness, full crop recovery is not achievable. ||Field validation following a natural April frost confirmed laboratory rankings, with 'Merlot' blocks recovering 55% of typical yield versus 22% for 'Chardonnay' under equivalent damage conditions.",
    "editor_note": "Shoot_Frost_Recovery_Disposition is_a Spring_Frost_Tolerance_Disposition. ||Recovery capacity determines outcomes after frost damage occurs, complementing avoidance and tolerance mechanisms. ||Key parameters include secondary bud activation speed, secondary shoot vigor, and secondary bud fruitfulness. ||Recovery is rarely complete, as secondary shoots typically produce smaller clusters than primary shoots. ||Strong recovery capacity is particularly valuable when frost timing is unpredictable, as avoidance through late budbreak cannot be relied upon.  This disposition represents the recovery component of spring frost adaptation, determining outcomes after frost damage has occurred rather than preventing initial damage. ||Recovery capacity depends on the availability and fruitfulness of backup growing points (secondary and tertiary buds if present, latent buds on older wood), the speed of their activation following primary shoot death, and the fertility of replacement shoots. ||Cultivars differ substantially in recovery capacity based on secondary bud fruitfulness (ranging from 0 to 1.5 clusters per shoot among cultivars), the proportion of secondary buds surviving frost events (often higher than primary shoots due to delayed development), and the vigor of replacement shoot growth. ||Effective Shoot_Frost_Recovery_Disposition enables economically meaningful crop production even in years with significant frost damage, reducing the year-to-year production variability that threatens vineyard sustainability in frost-prone regions. ||Recovery capacity is particularly valuable when combined with partial tissue tolerance, allowing damaged primary shoots to potentially recover through lateral growth while secondary buds provide insurance against complete shoot loss.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Friend AP et al. (2011) Delayed winter pruning and spring frost damage to grapevine buds, Australian Journal of Grape and Wine Research 17:214-218|| Dry PR (2000) Canopy management for fruitfulness, Australian Journal of Grape and Wine Research 6:109-115|| Trought MCT et al. (1999) Vineyard variability in Marlborough, New Zealand, American Journal of Enology and Viticulture 50:484-489"
  },
  "Cold_Recovery_Disposition": {
    "definition": "A Cold_Recovery_Disposition is a Cold_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to regenerate functional tissues, restore vine architecture, and resume productive growth following winter cold damage to buds, canes, trunks, or roots.", 
    "alternative_term": "winter injury recovery | cold damage restoration | freeze injury resilience |+ Kälteschadens-Erholungs-Disposition | Winterschadens-Regeneration | Frostschadens-Wiederherstellung",
    "example_of_usage": "Long-term assessment of Cold_Recovery_Disposition at the University of Minnesota tracked vineyard recovery following the severe 2013-14 polar vortex winter (minimum -34°C) that caused extensive damage across cultivars. ||Annual measurements over 5 post-damage seasons documented bud survival, trunk condition, yield recovery, vine vigor, and mortality across 18 cultivars in replicated trials. ||Cold_Recovery_Disposition showed strong cultivar differentiation. 'Frontenac' exhibited exceptional recovery despite 85% primary bud kill, activating secondary buds to produce 45% of typical yield in year 1, achieving 90% yield recovery by year 2, and showing no detectable long-term vigor reduction or elevated mortality. 'La Crescent' showed slower recovery with 25% yield in year 1 (reflecting lower secondary bud fruitfulness), 70% by year 2, and 95% by year 3, with no trunk damage requiring structural recovery. ||V. vinifera 'Marquette' (grafted) suffered both bud and partial trunk damage (40% of vines with crown injury), requiring more complex recovery. ||Vines with crown injury produced only 15% yield in year 1 from basal buds, required trunk retraining from suckers, and did not achieve full yield recovery until year 4. ||Mortality over 5 years was 2% ('Frontenac'), 5% ('La Crescent'), and 18% ('Marquette', concentrated in crown-damaged vines). ||These findings demonstrate that Cold_Recovery_Disposition determines both short-term economic impact and long-term vineyard sustainability following severe winter events.",
    "editor_note": "Cold_Recovery_Disposition is_a Cold_Tolerance_Disposition. ||Recovery capacity determines long-term consequences of cold damage events, complementing hardiness traits that prevent initial damage. ||Child classes include Secondary_Bud_Activation_Disposition (backup bud mobilization) and Trunk_Regeneration_Disposition (structural recovery). ||Recovery timeframe ranges from single season (bud damage only) to multiple years (trunk/structural damage). ||Strong recovery capacity reduces cumulative impact of repeated cold events that individually cause incomplete damage.  This disposition represents the restorative component of cold adaptation, determining how rapidly and completely vines recover from cold injury events rather than preventing initial damage. ||Cold recovery encompasses multiple processes including activation of surviving backup buds (secondary, tertiary, latent, or basal buds) to replace killed shoots, regeneration of vascular tissues through cambial activity to repair damaged canes and trunks, wound compartmentalization to limit secondary infection of cold-damaged tissues, and restoration of carbohydrate reserves depleted by regrowth demands. ||The timeframe for recovery varies with damage severity, ranging from single-season crop recovery through secondary bud growth (moderate damage) to multi-year structural rebuilding when trunks are killed (severe damage). ||Cold_Recovery_Disposition varies among genotypes based on the abundance and fruitfulness of backup buds, the vigor of regenerative growth, the efficiency of wound healing, and the capacity to partition resources between regrowth and reserve replenishment. ||Strong recovery capacity reduces the long-term economic impact of winter damage events, enabling faster return to full production and avoiding cumulative decline from repeated partial damage.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235|| Dami IE et al. (2012) Evaluation of winter injury and subsequent performance of grapevine cultivars in Ohio, Acta Horticulturae 932:235-241|| Zabadal TJ et al. (2007) Winter injury to grapevines and methods of protection, Michigan State University Extension Bulletin E-2930"
  },
  "Secondary_Bud_Activation_Disposition": {
    "definition": "A Secondary_Bud_Activation_Disposition is a Cold_Recovery_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to rapidly activate secondary (and tertiary) buds within compound buds following death of primary buds from winter cold or spring frost, enabling shoot production and partial crop recovery from backup meristems.", 
    "alternative_term": "backup bud mobilization | secondary bud response | compound bud redundancy utilization |+ Sekundärknospen-Aktivierungs-Disposition | Ersatzknospen-Mobilisierung | Reserveknospen-Aktivierung",
    "example_of_usage": "Mechanistic investigation of Secondary_Bud_Activation_Disposition at Michigan State University employed controlled primary bud removal and hormonal analysis to characterize activation dynamics across 15 cultivars. ||Dormant buds were surgically removed to simulate primary bud kill at the delayed dormant stage, and secondary bud development was tracked at 2-day intervals. ||Parallel hormone analysis (auxin, cytokinin, ABA) in secondary bud tissues characterized the hormonal signals controlling activation. ||Secondary_Bud_Activation_Disposition varied substantially among cultivars. 'Merlot' showed rapid activation with secondary buds visibly swelling within 4 days of primary bud removal, green tissue emergence by day 8, and full shoot development by day 14. ||Hormonal analysis revealed rapid cytokinin increase (3.5-fold by day 4) and auxin decline in 'Merlot' secondary buds, consistent with release from correlative inhibition imposed by the dominant primary bud. 'Riesling' displayed slower Secondary_Bud_Activation_Disposition with swelling at day 8, emergence at day 14, and full development at day 22, accompanied by more gradual hormonal shifts. 'Chardonnay' showed the slowest activation (emergence at day 18) combined with low secondary shoot vigor (40% of 'Merlot' shoot length at 30 days). ||Field trials following natural primary bud kill confirmed laboratory rankings, with rapid-activating cultivars establishing functional canopy 10-14 days earlier than slow activators, translating to improved fruit maturity at harvest (1.5-2.5° Brix advantage) despite equivalent primary bud damage levels.",
    "editor_note": "Secondary_Bud_Activation_Disposition is_a Cold_Recovery_Disposition. ||Secondary bud activation exploits the compound bud's developmental redundancy for damage recovery. ||Activation speed and secondary shoot quality both contribute to effective recovery. ||Activation is controlled by hormonal signals (cytokinin/auxin balance) released from correlative inhibition when primary bud is killed. ||Secondary shoot fruitfulness (determined by cluster primordia in secondary bud at dormancy) is a separate trait from activation speed, with both contributing to recovery effectiveness.  This disposition represents the first line of cold damage recovery, utilizing the developmental redundancy built into the compound bud structure to replace killed primary growing points with surviving backup buds. ||Secondary_Bud_Activation_Disposition encompasses both the speed of secondary bud activation following primary bud death (days from damage to visible growth) and the subsequent performance of secondary shoots (vigor, fruitfulness, maturation timing). ||Rapid activation minimizes the delay in canopy establishment and season compression that follow primary bud loss, while secondary shoot fruitfulness determines the proportion of crop recoverable through this pathway. ||Cultivars differ substantially in secondary bud activation dynamics and secondary shoot performance, with some producing vigorous, relatively fruitful secondary growth within days of primary shoot death while others show delayed activation and minimal fruitfulness. ||Strong Secondary_Bud_Activation_Disposition is particularly valuable when primary bud damage is extensive but cane vascular tissues remain functional, as the surviving vascular system can support rapid secondary bud development if activation capacity is present.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dry PR (2000) Canopy management for fruitfulness, Australian Journal of Grape and Wine Research 6:109-115|| Howell GS (2001) Sustainable grape productivity and the growth-yield relationship, American Journal of Enology and Viticulture 52:165-174|| Fennell A (2004) Freezing tolerance and injury in grapevines, Journal of Crop Improvement 10:201-235"
  },
  "Trunk_Regeneration_Disposition": {
    "definition": "A Trunk_Regeneration_Disposition is a Cold_Recovery_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to regenerate functional trunk tissue following winter damage to the permanent woody structure, either through wound healing of partially damaged trunks or complete trunk replacement from basal suckers or graft union regrowth.", 
    "alternative_term": "trunk recovery | structural regeneration | permanent wood restoration |+ Stamm-Regenerations-Disposition | Stammwiederherstellung | Permanentholz-Erholung",
    "example_of_usage": "Long-term documentation of Trunk_Regeneration_Disposition at North Dakota State University tracked recovery outcomes following severe trunk damage across cultivars and training systems over 8 years in a replicated trial subjected to -38°C exposure in year 1. ||Trunk damage was categorized as partial (crown injury or bark splitting with some surviving cambium) or complete (circumferential cambium death requiring trunk replacement). ||Regeneration success, time to full production, and secondary complications were recorded. ||Trunk_Regeneration_Disposition varied among cultivars. 'Frontenac' with partial trunk damage showed excellent wound compartmentalization, with cold-damaged sectors walling off within one season, no crown gall development, and full yield restoration by year 2. 'Frontenac' with complete trunk death produced vigorous basal suckers (2.8 suckers per vine by June, strongest reaching 2.1 m by season end), enabling trunk replacement with return to 50% yield by year 2 and full yield by year 3. 'Marquette' showed similar sucker vigor but higher crown gall incidence (35% of damaged vines) at wound sites, requiring removal of infected tissue and extending recovery to year 4 for affected vines. ||V. vinifera cultivars on susceptible rootstocks showed poor Trunk_Regeneration_Disposition, with weak sucker production (0.8 per vine), high crown gall incidence (55%), and 28% vine mortality over the recovery period. ||These findings demonstrate that Trunk_Regeneration_Disposition determines vineyard survival and recovery economics following catastrophic winter events.",
    "editor_note": "Trunk_Regeneration_Disposition is_a Cold_Recovery_Disposition. ||Trunk regeneration addresses the most severe cold damage category requiring structural rebuilding. ||Recovery pathways include wound healing (partial damage) and trunk replacement from suckers (complete damage). ||Timeframe is multi-year, with full production recovery requiring 2-4 years depending on damage extent. ||Secondary infection (especially crown gall) is a major complication affecting regeneration success. ||Both scion and rootstock genotype influence trunk regeneration capacity in grafted vines.  This disposition represents recovery from the most severe category of cold damage, where the vine's permanent framework is compromised and structural rebuilding is required beyond simple shoot replacement. ||Trunk damage from freezing includes bark splitting (from rapid cooling and ice crystal expansion), crown gall development in cold-injured tissues (Agrobacterium infection of freeze-damaged cells), cambium kill (eliminating radial growth capacity), and complete trunk death requiring regeneration from surviving basal tissues. ||Trunk_Regeneration_Disposition encompasses wound compartmentalization capacity (limiting secondary pathogen invasion of damaged tissues), cambial regeneration from surviving sectors (restoring circumferential vascular connectivity), and sucker production capacity (providing replacement trunk candidates when existing trunk is unsalvageable). ||The timeframe for trunk recovery is multi-year, with complete trunk replacement requiring 2-4 years to establish new structural framework and return to full production. ||Cultivars and rootstocks differ in trunk regeneration capacity based on wound healing efficiency, susceptibility to secondary infections, vigor of basal growth, and tolerance of the training disruption required for trunk replacement.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Goffinet MC (2004) Anatomy of grapevine winter injury and recovery, Grape Research News 15:1-7|| Zabadal TJ et al. (2007) Winter injury to grapevines and methods of protection, Michigan State University Extension Bulletin E-2930|| Burr TJ, Otten L (1999) Crown gall of grape: biology and disease management, Annual Review of Phytopathology 37:53-80"
  },
  "Heat_Tolerance_Disposition": {
    "definition": "A Heat_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through physiological, biochemical, and morphological mechanisms that enable maintenance of cellular function, photosynthetic activity, and reproductive success under high temperature conditions that would otherwise cause metabolic disruption, tissue damage, or crop loss.", 
    "alternative_term": "high temperature tolerance | thermal tolerance | heat stress resistance |+ Hitzetoleranz-Disposition | Hochtemperatur-Toleranz | Thermotoleranz-Kapazität",
    "example_of_usage": "Comprehensive characterization of Heat_Tolerance_Disposition at CSIRO Agriculture, Adelaide, assessed multiple heat tolerance parameters across 30 cultivars under controlled heat stress (40°C for 4 hours) and recovery conditions. ||Measurements included chlorophyll fluorescence (Fv/Fm as PSII efficiency indicator), membrane stability (electrolyte leakage), leaf gas exchange (photosynthesis, stomatal conductance), and visual damage scoring. ||Cultivars showed substantial variation in Heat_Tolerance_Disposition. 'Grenache' (Mediterranean origin) exhibited strong heat tolerance with Fv/Fm declining only 12% during stress (from 0.82 to 0.72) and recovering fully within 24 hours, electrolyte leakage increasing just 15%, and photosynthesis maintaining 65% of pre-stress rate during heat exposure. 'Pinot Noir' (cool-climate origin) showed poor Heat_Tolerance_Disposition with Fv/Fm declining 35% (to 0.53), incomplete recovery (reaching 0.71 at 48 hours), electrolyte leakage increasing 45%, and photosynthesis reduced to 25% of pre-stress rate. ||The Australian-bred 'Tarrango' (heat-adapted background) demonstrated exceptional tolerance with only 8% Fv/Fm decline, 10% leakage increase, and 75% photosynthesis maintenance. ||Principal component analysis revealed that membrane thermostability and PSII heat tolerance were the strongest contributors to overall Heat_Tolerance_Disposition, suggesting these mechanisms as priority breeding targets for heat-resilient cultivars.",
    "editor_note": "Heat_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||Heat tolerance is increasingly important under climate change and encompasses multiple mechanisms addressed through child classes including Photosynthesis_Heat_Stability_Disposition, Membrane_Thermostability_Disposition, Heat_Shock_Protein_Disposition, Evaporative_Cooling_Disposition, and Berry_Heat_Tolerance_Disposition. ||Heat tolerance is partially independent of drought tolerance, though both stresses often co-occur and share some adaptive mechanisms. ||Mediterranean and hot-climate cultivars provide genetic resources for heat tolerance improvement.  This disposition represents the capacity to tolerate supraoptimal temperatures, with grapevine showing reduced photosynthesis above 30-35°C and potential for heat damage above 40°C depending on duration, humidity, and genotype. ||Heat stress in viticulture is increasingly important under climate change scenarios, with documented impacts including photosynthetic inhibition (stomatal closure, Rubisco deactivation, thylakoid damage), membrane destabilization (increased fluidity, ion leakage), protein denaturation, accelerated respiration depleting carbohydrate reserves, disrupted phenolic and aromatic compound biosynthesis affecting wine quality, and reproductive failure (pollen sterility, fruit abscission, sunburn). ||Heat tolerance mechanisms encompass maintenance of photosynthetic function at elevated temperatures (Rubisco activase thermostability, PSII heat tolerance), membrane stabilization (lipid saturation, protective proteins), heat shock protein accumulation (molecular chaperones preventing protein aggregation), evaporative cooling capacity (transpirational heat dissipation), and tissue-specific heat protection (berry sunburn resistance, flower heat tolerance). ||Heat_Tolerance_Disposition varies among Vitis species and cultivars, with Mediterranean and hot-climate cultivars generally showing enhanced heat adaptation compared to cool-climate genotypes, providing genetic resources for breeding heat-resilient cultivars.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Wahid A et al. (2007) Heat tolerance in plants: an overview, Environmental and Experimental Botany 61:199-223|| Greer DH, Weston C (2010) Heat stress affects flowering, berry growth, sugar accumulation and photosynthesis of Vitis vinifera cv. Semillon grapevines grown in a controlled environment, Functional Plant Biology 37:206-214|| Carvalho LC et al. (2015) Heat stress in grapevine: the pros and cons of acclimation, Plant, Cell and Environment 38:777-789"
  },
  "Photosynthesis_Heat_Stability_Disposition": {
    "definition": "A Photosynthesis_Heat_Stability_Disposition is a Heat_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to maintain photosynthetic function at elevated temperatures, preserving carbon assimilation and energy production under heat stress conditions that would otherwise cause stomatal closure, enzyme inactivation, and photosystem damage.", 
    "alternative_term": "photosynthetic thermotolerance | carbon assimilation heat stability | photosynthetic heat resistance |+ Photosynthese-Hitzestabilität-Disposition | Photosynthetische-Thermotoleranz | Kohlenstoffassimilations-Hitzestabilität",
    "example_of_usage": "Detailed investigation of Photosynthesis_Heat_Stability_Disposition at the University of California Davis employed temperature-response curves and recovery kinetics to characterize photosynthetic heat tolerance across 20 cultivars. ||Leaf gas exchange was measured at temperatures from 25°C to 45°C in 5°C increments, with parallel chlorophyll fluorescence monitoring of PSII function. ||The temperature causing 50% photosynthesis inhibition (T50) and the critical temperature for PSII damage (Tc, defined by rapid Fv/Fm decline) were determined for each cultivar. ||Photosynthesis_Heat_Stability_Disposition showed significant cultivar variation. 'Grenache' exhibited high T50 of 41.2°C and Tc of 46.5°C, maintaining 70% of maximum photosynthesis at 40°C. 'Riesling' showed lower Photosynthesis_Heat_Stability_Disposition with T50 of 36.8°C and Tc of 43.2°C, retaining only 35% of maximum photosynthesis at 40°C. ||Analysis of component limitations revealed cultivar-specific patterns. ||In 'Grenache', stomatal and biochemical limitations contributed equally to high-temperature decline, while in 'Riesling', biochemical limitation (Rubisco deactivation) dominated above 35°C, suggesting less thermostable Rubisco activase. ||Recovery experiments showed that 'Grenache' restored 95% of pre-stress photosynthesis within 4 hours of return to 25°C, while 'Riesling' recovered only 70% at equivalent timepoint, indicating some irreversible damage. ||These findings identify Photosynthesis_Heat_Stability_Disposition as a key differentiator among cultivars for performance in hot climates.",
    "editor_note": "Photosynthesis_Heat_Stability_Disposition is_a Heat_Tolerance_Disposition. ||Photosynthetic heat tolerance involves multiple components including stomatal, biochemical (Rubisco activase thermostability), and photochemical (PSII, thylakoid membrane) factors. ||T50 (temperature for 50% inhibition) and Tc (critical temperature for PSII damage) are useful quantitative parameters. ||Heat-induced photosynthetic limitation affects both immediate carbon gain and long-term vine productivity through reduced assimilate supply for fruit and reserve accumulation.  This disposition represents the thermostability of the photosynthetic apparatus, with photosynthesis in grapevine showing temperature optima between 25-30°C and progressive inhibition at higher temperatures through multiple mechanisms. ||Heat-induced photosynthetic decline involves stomatal limitations (reduced CO₂ supply due to stomatal closure), biochemical limitations (Rubisco activase denaturation reducing Rubisco activation state, impaired Calvin cycle enzyme function), and photochemical limitations (PSII damage, thylakoid membrane destabilization, reduced electron transport capacity). ||Cultivars differ in the temperature threshold for photosynthetic decline, the rate of decline above threshold, and the capacity for recovery following heat exposure. ||Photosynthesis_Heat_Stability_Disposition depends on thermostable forms of key enzymes (particularly Rubisco activase), heat-tolerant thylakoid membranes, effective photoprotective mechanisms (xanthophyll cycle, antioxidants), and coordinated stomatal behavior balancing CO₂ access against water loss. ||Strong Photosynthesis_Heat_Stability_Disposition enables continued carbon gain during heat events, supporting fruit ripening and reserve accumulation even under challenging thermal conditions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Berry J, Bjorkman O (1980) Photosynthetic response and adaptation to temperature in higher plants, Annual Review of Plant Physiology 31:491-543|| Crafts-Brandner SJ, Salvucci ME (2000) Rubisco activase constrains the photosynthetic potential of leaves at high temperature and CO2, Proceedings of the National Academy of Sciences 97:13430-13435|| Greer DH, Weedon MM (2012) Modelling photosynthetic responses to temperature of grapevine leaves on vines grown in a hot climate, Plant, Cell and Environment 35:1050-1064"
  },
  "Membrane_Thermostability_Disposition": {
    "definition": "A Membrane_Thermostability_Disposition is a Heat_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to maintain cellular membrane integrity and function at elevated temperatures, preventing the increased membrane fluidity, phase transitions, and ion leakage that characterize heat-induced membrane damage.", 
    "alternative_term": "membrane heat stability | cellular membrane integrity | lipid bilayer thermotolerance |+ Membran-Thermostabilität-Disposition | Membran-Hitzestabilität | Zellmembran-Integrität",
    "example_of_usage": "Systematic assessment of Membrane_Thermostability_Disposition at Stellenbosch University employed electrolyte leakage assays and lipid profiling across 25 cultivars to characterize membrane heat tolerance and its biochemical basis. ||Leaf discs were exposed to temperatures from 30°C to 55°C for 30 minutes, then incubated in deionized water with conductivity measured at 2 hours (initial leakage) and after autoclaving (total electrolytes). ||The temperature causing 50% relative electrolyte leakage (T50-EL) defined membrane thermostability threshold. ||Membrane_Thermostability_Disposition ranged from T50-EL of 46.2°C ('Pinot Noir', least stable) to 52.8°C ('Cinsaut', most stable), representing 6.6°C variation among commercial cultivars. ||Lipid analysis revealed that membrane fatty acid saturation correlated significantly with T50-EL (r = 0.72), with heat-tolerant 'Cinsaut' showing 42% saturated fatty acids versus 31% in heat-sensitive 'Pinot Noir'. ||The ratio of linolenic (18:3) to linoleic (18:2) acid was inversely correlated with thermostability (r = -0.68), consistent with the destabilizing effect of highly unsaturated lipids at elevated temperatures. ||Heat acclimation (pre-treatment at 38°C for 24 hours) improved Membrane_Thermostability_Disposition by 2-4°C across cultivars through increased lipid saturation, demonstrating phenotypic plasticity in this trait. ||These findings establish membrane lipid composition as a key determinant of Membrane_Thermostability_Disposition and identify lipid desaturase genes as potential breeding targets.",
    "editor_note": "Membrane_Thermostability_Disposition is_a Heat_Tolerance_Disposition. ||Membrane stability is a primary determinant of cellular heat tolerance, as membranes are highly temperature-sensitive structures. ||Electrolyte leakage is the standard assay, with T50-EL providing a quantitative stability threshold. ||Membrane composition (lipid saturation) is the primary biochemical determinant, with more saturated membranes showing greater thermostability. ||Heat acclimation can increase membrane thermostability through lipid remodeling, representing an inducible component of heat tolerance.  This disposition represents the thermal stability of biological membranes, which are primary sites of heat injury due to temperature-dependent changes in lipid bilayer properties. ||Heat stress increases membrane fluidity beyond optimal ranges, disrupting the precise lipid environment required for membrane protein function, increasing passive ion permeability leading to loss of cellular ion gradients, and potentially causing membrane phase transitions and irreversible damage. ||Membrane_Thermostability_Disposition depends on membrane lipid composition (higher lipid saturation increases thermostability), membrane protein content and type (some proteins stabilize membranes), accumulation of compatible solutes (trehalose, proline) that interact with membrane surfaces, and heat shock proteins that associate with membranes during stress. ||Membrane thermostability is commonly assessed by measuring electrolyte leakage from heat-treated tissue, with lower leakage indicating greater membrane integrity. ||Cultivars with strong Membrane_Thermostability_Disposition maintain lower electrolyte leakage, preserve cellular compartmentalization, and protect membrane-localized processes (photosynthetic electron transport, respiratory function, signaling) during heat exposure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Blum A, Ebercon A (1981) Cell membrane stability as a measure of drought and heat tolerance in wheat, Crop Science 21:43-47|| Sung DY et al. (2003) Acquired tolerance to temperature extremes, Trends in Plant Science 8:179-187|| Falcone DL et al. (2004) Regulation of membrane fatty acid composition by temperature in mutants of Arabidopsis with alterations in membrane lipid composition, BMC Plant Biology 4:17"
  },
  "Heat_Shock_Protein_Disposition": {
    "definition": "A Heat_Shock_Protein_Disposition is a Heat_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to rapidly synthesize and accumulate heat shock proteins (HSPs) in response to elevated temperatures, providing molecular chaperone protection against heat-induced protein denaturation and aggregation.", 
    "alternative_term": "HSP accumulation capacity | heat shock response | molecular chaperone induction |+ Hitzeschockprotein-Disposition | HSP-Akkumulations-Kapazität | Molekulare-Chaperon-Induktion",
    "example_of_usage": "Molecular characterization of Heat_Shock_Protein_Disposition at INRAE Montpellier examined HSP gene expression and protein accumulation across 15 cultivars following controlled heat shock (42°C for 2 hours) and recovery. ||Expression of representative genes from major HSP families (VvHSP101, VvHSP90, VvHSP70, VvHSP17.9) was quantified by qRT-PCR at 0, 0.5, 1, 2, 4, and 8 hours post-heat onset, while HSP protein levels were assessed by immunoblot. ||Heat_Shock_Protein_Disposition showed substantial cultivar variation in both induction kinetics and magnitude. 'Grenache' exhibited rapid, strong HSP induction with VvHSP17.9 (small HSP) expression increasing 85-fold within 1 hour, peaking at 150-fold by 2 hours, and VvHSP70 reaching 25-fold induction. ||Protein accumulation paralleled transcript patterns, with small HSP protein detectable by 2 hours and abundant by 4 hours. 'Chardonnay' showed delayed, weaker Heat_Shock_Protein_Disposition with VvHSP17.9 reaching only 45-fold peak induction at 4 hours (2-hour delay versus 'Grenache'). ||Correlation analysis revealed that HSP induction magnitude correlated with membrane thermostability (r = 0.68) and photosynthetic recovery (r = 0.72), confirming the protective function of HSP accumulation. ||Pre-conditioning (mild heat exposure at 38°C) enhanced subsequent Heat_Shock_Protein_Disposition in all cultivars, with 'Grenache' showing 40% faster induction and 25% higher peak expression following pre-conditioning, demonstrating the role of acquired thermotolerance in HSP-mediated protection.",
    "editor_note": "Heat_Shock_Protein_Disposition is_a Heat_Tolerance_Disposition. ||HSPs are molecular chaperones protecting proteins from heat-induced denaturation and aggregation. ||Multiple HSP families exist with distinct functions and localizations. ||The heat shock response is transcriptionally regulated by HSF transcription factors. ||Both constitutive HSP levels and induced accumulation contribute to heat tolerance. ||Small HSPs (sHSPs) are particularly important for protecting photosynthetic apparatus. ||Heat acclimation enhances subsequent HSP response (acquired thermotolerance).  This disposition represents the protein quality control component of heat tolerance, with HSPs functioning as molecular chaperones that bind to partially denatured proteins, prevent their irreversible aggregation, assist in proper refolding during recovery, and target damaged proteins for degradation when repair is not possible. ||Heat shock proteins in plants are classified by molecular weight into HSP100, HSP90, HSP70, HSP60, and small HSP (sHSP) families, each with distinct cellular localizations and functions. ||The heat shock response is orchestrated by heat shock transcription factors (HSFs) that activate HSP gene expression within minutes of temperature elevation, enabling rapid accumulation of protective proteins. ||Cultivars differ in both basal HSP levels (constitutive protection) and the speed, magnitude, and persistence of induced HSP accumulation following heat exposure. ||Strong Heat_Shock_Protein_Disposition provides enhanced protection against acute heat stress through rapid chaperone accumulation and improved recovery through efficient protein repair, with particular importance of small HSPs for protecting photosynthetic proteins and membranes in chloroplasts.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Wang W et al. (2004) Role of plant heat-shock proteins and molecular chaperones in the abiotic stress response, Trends in Plant Science 9:244-252|| Vierling E (1991) The roles of heat shock proteins in plants, Annual Review of Plant Physiology and Plant Molecular Biology 42:579-620|| Liu GT et al. (2012) Differential proteomic analysis of grapevine leaves by iTRAQ reveals responses to heat stress and subsequent recovery, BMC Plant Biology 12:174"
  },
  "Evaporative_Cooling_Disposition": {
    "definition": "An Evaporative_Cooling_Disposition is a Heat_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to dissipate heat through transpirational water loss, maintaining leaf and canopy temperatures below ambient air temperature during hot conditions through the latent heat of evaporation.", 
    "alternative_term": "transpirational cooling | evaporative heat dissipation | hydraulic thermoregulation |+ Verdunstungskühlungs-Disposition | Transpirative-Kühlung | Hydraulische-Thermoregulation",
    "example_of_usage": "Field investigation of Evaporative_Cooling_Disposition at UC Davis Oakville Research Station compared canopy temperature dynamics across 12 cultivars under hot conditions (> 38°C air temperature) using infrared thermography and concurrent gas exchange measurements. ||Canopy-to-air temperature differential (Tc-Ta), stomatal conductance, and vine water status (stem water potential) were monitored hourly from 10:00 to 16:00 on heat event days. ||Cultivars displayed contrasting Evaporative_Cooling_Disposition reflecting their stomatal regulation strategies. ||Anisohydric 'Syrah' maintained high stomatal conductance (0.25 mol m⁻² s⁻¹ at midday) and strong evaporative cooling (Tc-Ta = -8.5°C at 14:00), keeping canopy temperature at 32°C when air reached 40.5°C. ||Isohydric 'Grenache' showed progressive stomatal closure (conductance declining to 0.08 mol m⁻² s⁻¹ by 14:00), reduced cooling (Tc-Ta = -3.2°C), and canopy temperature reaching 37.3°C. ||Leaf damage (marginal necrosis) was observed on 'Grenache' following consecutive heat days, while 'Syrah' showed no visible damage despite identical air temperature exposure, demonstrating the protective value of Evaporative_Cooling_Disposition. ||However, stem water potential measurements revealed that 'Syrah' reached -1.5 MPa by late afternoon versus -1.0 MPa for 'Grenache', highlighting the water cost of aggressive cooling. ||Under limited irrigation, 'Grenache' maintained better water status and avoided late-season water stress, illustrating the environment-dependent value of different Evaporative_Cooling_Disposition strategies.",
    "editor_note": "Evaporative_Cooling_Disposition is_a Heat_Tolerance_Disposition. ||Evaporative cooling links heat and water relations, as transpiration provides cooling but consumes water. ||Isohydric versus anisohydric stomatal behavior determines the heat/water stress trade-off strategy. ||Cooling capacity depends on water availability, hydraulic conductance, stomatal behavior, and boundary layer conditions. ||In well-watered conditions, high cooling capacity protects against heat|| in water-limited conditions, conservative stomatal behavior may be preferable. ||Canopy temperature monitoring (thermal imaging) directly assesses evaporative cooling effectiveness.  This disposition represents the hydraulic component of heat tolerance, with transpirational cooling potentially reducing leaf temperatures by 5-15°C below air temperature depending on evaporative demand and water availability. ||Effective evaporative cooling requires adequate soil water supply, hydraulic conductance sufficient to replace transpired water, stomatal aperture maintained despite high evaporative demand, and canopy architecture facilitating air movement and heat dissipation. ||Cultivars differ in evaporative cooling capacity based on stomatal behavior (isohydric cultivars close stomata conserving water but sacrificing cooling, anisohydric cultivars maintain stomatal opening and cooling under moderate stress), hydraulic conductance (root and shoot xylem properties), and canopy characteristics affecting boundary layer conductance. ||Evaporative_Cooling_Disposition represents a trade-off between heat stress avoidance through cooling and drought stress risk through water expenditure, with optimal strategy depending on the relative severity and timing of heat versus water stress in specific environments. ||In irrigated viticulture with adequate water supply, high evaporative cooling capacity provides significant heat stress mitigation, while in rainfed or deficit irrigation systems, conservative stomatal behavior may be preferable despite reduced cooling.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jones HG (1999) Use of infrared thermometry for estimation of stomatal conductance as a possible aid to irrigation scheduling, Agricultural and Forest Meteorology 95:139-149|| Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant, Cell and Environment 26:1393-1405|| Chaves MM et al. (2010) Grapevine under deficit irrigation: hints from physiological and molecular data, Annals of Botany 105:661-676"
  },
  "Berry_Heat_Tolerance_Disposition": {
    "definition": "A Berry_Heat_Tolerance_Disposition is a Heat_Tolerance_Disposition that inheres in Vitis vinifera grape berries and is realized through mechanisms that protect berry tissues from high temperature damage during ripening, preserving berry integrity, preventing premature abscission, and maintaining the biochemical composition essential for wine quality.", 
    "alternative_term": "fruit heat tolerance | berry thermotolerance | grape heat stress resistance |+ Beeren-Hitzetoleranz-Disposition | Frucht-Thermotoleranz | Trauben-Hitzestress-Resistenz",
    "example_of_usage": "Comprehensive assessment of Berry_Heat_Tolerance_Disposition at the Australian Wine Research Institute compared berry responses to controlled heating (berry surface temperature maintained at 45°C for 4 hours using infrared heaters) across 18 cultivars at véraison. ||Damage was assessed by visual scoring (sunburn symptoms), electrolyte leakage from berry skin, anthocyanin retention (red cultivars), and sugar-acid balance at harvest. ||Berry_Heat_Tolerance_Disposition varied substantially among cultivars. 'Grenache' demonstrated exceptional tolerance with minimal visible damage (score 0.5/5), low electrolyte leakage (18% relative increase), and anthocyanin retention of 85% following heat treatment. 'Pinot Noir' showed high sensitivity with severe sunburn (score 3.5/5), high leakage (52% increase), and anthocyanin loss to 45% of control, with affected berries failing to complete normal ripening. ||Among white cultivars, 'Verdelho' (tropical origin) exhibited strong Berry_Heat_Tolerance_Disposition while 'Chardonnay' was sensitive. ||Interestingly, berry heat tolerance did not correlate strongly with leaf heat tolerance (r = 0.38), suggesting partially independent mechanisms. ||Cluster architecture analysis revealed that cultivars with loose clusters and pendant orientation showed less heat damage under field conditions due to improved air circulation and reduced radiation interception, indicating that both intrinsic tissue tolerance and avoidance through architecture contribute to field-level Berry_Heat_Tolerance_Disposition.",
    "editor_note": "Berry_Heat_Tolerance_Disposition is_a Heat_Tolerance_Disposition. ||Berry heat tolerance is distinct from vegetative tissue heat tolerance, with different damage mechanisms and consequences. ||Berry temperature can greatly exceed air temperature due to radiative heating. ||Child classes include Sunburn_Resistance_Disposition (combined heat/light damage) and Heat_Induced_Abscission_Resistance_Disposition (berry drop). ||Heat damage affects both yield (abscission, sunburn) and quality (anthocyanin degradation, decoupled ripening). ||Cluster architecture contributes to field heat exposure independently of intrinsic tissue tolerance.  This disposition represents heat tolerance of the economically critical fruit tissue, with berry heat damage manifested as sunburn (tissue necrosis from combined heat and light stress), heat-induced abscission (berry drop from pedicel failure), accelerated sugar accumulation with insufficient phenolic and aromatic development (decoupled ripening), anthocyanin degradation in red varieties, and altered acid metabolism (malate respiration). ||Berry temperature during hot periods can substantially exceed air temperature due to direct solar radiation absorption, with exposed berries reaching 45-50°C under full sun when air temperature is 35-40°C. ||Berry_Heat_Tolerance_Disposition encompasses both avoidance mechanisms (canopy architecture providing berry shading, berry skin properties reflecting radiation) and tolerance mechanisms (heat shock protein accumulation in berry tissues, antioxidant systems, cell wall stability). ||Cultivars differ in berry heat tolerance based on skin pigmentation (darker berries absorb more radiation), skin thickness and composition, cluster architecture affecting berry exposure, and biochemical heat protection capacity, with substantial breeding relevance as hot-climate viticulture expands.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Greer DH, Weston C (2010) Heat stress affects flowering, berry growth, sugar accumulation and photosynthesis of Vitis vinifera, Functional Plant Biology 37:206-214|| Spayd SE et al. (2002) Separation of sunlight and temperature effects on the composition of Vitis vinifera cv. Merlot berries, American Journal of Enology and Viticulture 53:171-182|| Mori K et al. (2007) Loss of anthocyanins in red-wine grape under high temperature, Journal of Experimental Botany 58:1935-1945"
  },
  "Sunburn_Resistance_Disposition": {
    "definition": "A Sunburn_Resistance_Disposition is a Berry_Heat_Tolerance_Disposition that inheres in Vitis vinifera grape berries and is realized through mechanisms that prevent or limit tissue necrosis caused by the combined effects of high temperature and intense solar radiation on exposed berry surfaces during ripening.", 
    "alternative_term": "berry sunburn tolerance | sun damage resistance | solar injury tolerance |+ Sonnenbrand-Resistenz-Disposition | Beeren-Sonnenbrand-Toleranz | Solarschadens-Resistenz",
    "example_of_usage": "Field evaluation of Sunburn_Resistance_Disposition at UC Davis Oakville station monitored sunburn incidence and severity across 20 cultivars in a trial where half of clusters received artificial shade (70% reduction) while matched clusters remained exposed over two seasons with multiple heat events (> 40°C). ||Sunburn was scored on exposed clusters using a 0-5 scale based on affected berry surface area. ||Sunburn_Resistance_Disposition ranged from highly resistant (mean score < 0.5) to highly susceptible (mean score > 3.5). 'Grenache' exhibited exceptional Sunburn_Resistance_Disposition with mean score of 0.3 on exposed clusters despite berry surface temperatures exceeding 48°C during peak heat events, attributable to its thick, waxy berry skin (cuticle 8.2 μm versus 4.5 μm average) and high skin flavonoid content. 'Pinot Noir' showed extreme susceptibility (score 3.8) with visible necrosis appearing within 48 hours of severe heat events|| its thin skin (3.2 μm cuticle), low reflectance, and limited antioxidant capacity provided minimal protection. ||White cultivars showed generally higher Sunburn_Resistance_Disposition than red cultivars when skin thickness was equivalent, reflecting lower radiation absorption. ||Shaded clusters showed negligible sunburn across all cultivars (scores < 0.3), confirming that Sunburn_Resistance_Disposition operates against the specific combination of heat plus light, not heat alone. ||Berry skin carotenoid concentration correlated negatively with sunburn severity (r = -0.65), supporting the photoprotective role of these compounds.",
    "editor_note": "Sunburn_Resistance_Disposition is_a Berry_Heat_Tolerance_Disposition. ||Sunburn requires the combination of high temperature and intense light, distinguishing it from purely thermal damage. ||Skin properties (thickness, reflectance, pigmentation) and antioxidant content (carotenoids, flavonoids) are primary determinants. ||Red berries are generally more susceptible than white due to higher radiation absorption by anthocyanins. ||Canopy management interacts strongly with intrinsic resistance, as shading eliminates sunburn regardless of cultivar susceptibility.  This disposition represents resistance to sunburn, a common disorder in hot-climate viticulture manifested as browning, tissue collapse, and desiccation of sun-exposed berry surfaces, rendering affected berries unsuitable for premium wine production. ||Sunburn results from the interaction of excessive berry heating (from absorbed solar radiation) and photochemical damage (from UV and visible light), with the combination causing oxidative stress, membrane damage, chlorophyll destruction (in pre-véraison berries), anthocyanin degradation (in ripening red berries), and eventually cell death. ||Sunburn_Resistance_Disposition depends on berry skin properties (thickness, pigmentation, wax content affecting radiation absorption and reflection), antioxidant capacity (carotenoids, flavonoids, ascorbate reducing oxidative damage), heat shock protein accumulation, and repair mechanisms enabling recovery from moderate stress. ||Cultivars with thicker, more reflective skins, higher antioxidant content, and greater heat-induced protective responses show enhanced Sunburn_Resistance_Disposition. ||Additionally, cluster positioning and canopy management interact with intrinsic berry resistance to determine field sunburn incidence, with exposed clusters at higher risk regardless of cultivar.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Spayd SE et al. (2002) Separation of sunlight and temperature effects on the composition of Vitis vinifera cv. Merlot berries, American Journal of Enology and Viticulture 53:171-182|| Greer DH, La Borde D (2006) Sunburn of grapes affects wine quality, Australian and New Zealand Grapegrower and Winemaker 506:21-23|| Reshef N et al. (2017) Sunlight modulates fruit metabolic profile and shapes the spatial pattern of compound accumulation in grape berries, Frontiers in Plant Science 8:70"
  },
  "Heat_Induced_Abscission_Resistance_Disposition": {
    "definition": "A Heat_Induced_Abscission_Resistance_Disposition is a Berry_Heat_Tolerance_Disposition that inheres in Vitis vinifera grape berries and pedicels and is realized through mechanisms that prevent premature berry detachment during heat stress events, preserving cluster integrity and yield by maintaining pedicel attachment even when berry tissues experience potentially damaging temperatures.", 
    "alternative_term": "berry drop resistance | heat shatter resistance | thermal abscission tolerance |+ Hitzeinduzierte-Abszissions-Resistenz-Disposition | Beerenfall-Resistenz | Thermische-Abszissions-Toleranz",
    "example_of_usage": "Controlled environment investigation of Heat_Induced_Abscission_Resistance_Disposition at CSIRO Adelaide exposed fruiting cuttings of 15 cultivars to heat treatments (40°C for 6 hours daily for 5 consecutive days) during the lag phase of berry development and quantified berry drop at 7 and 14 days post-treatment. ||Additionally, pedicel abscission zone tissues were analyzed for cell wall-degrading enzyme activity and ethylene evolution. ||Heat_Induced_Abscission_Resistance_Disposition varied dramatically among cultivars. 'Grenache' demonstrated exceptional resistance with only 3% berry drop following heat treatment (versus 2% in untreated controls), showing minimal increase in abscission zone polygalacturonase activity (1.4-fold) and low ethylene production (12 nL g⁻¹ h⁻¹). 'Merlot' showed intermediate susceptibility (18% drop, 3.2-fold enzyme induction, 28 nL g⁻¹ h⁻¹ ethylene). 'Pinot Noir' exhibited severe heat-induced abscission (42% berry drop, 6.5-fold enzyme induction, 55 nL g⁻¹ h⁻¹ ethylene), with abscission continuing for 10 days post-treatment. ||Application of the ethylene perception inhibitor 1-MCP prior to heat treatment reduced berry drop by 60-70% across susceptible cultivars, confirming ethylene involvement in heat-induced abscission. ||Correlation analysis revealed that cultivar differences in Heat_Induced_Abscission_Resistance_Disposition were strongly predicted by the magnitude of heat-induced ethylene production (r = 0.85), suggesting that ethylene biosynthesis regulation under heat stress is a key target for improving this trait.",
    "editor_note": "Heat_Induced_Abscission_Resistance_Disposition is_a Berry_Heat_Tolerance_Disposition. ||Abscission involves enzymatic weakening of the pedicel-berry junction, mediated by ethylene signaling. ||Resistance depends on limited activation of abscission zone enzymes and controlled ethylene production under heat stress. ||Berry drop timing (lag phase, véraison, ripening) affects susceptibility, with lag phase often most sensitive. ||Ethylene inhibitors (1-MCP, AVG) can reduce heat-induced abscission, suggesting potential management interventions.  This disposition represents resistance to heat-triggered abscission, a significant cause of yield loss in hot viticultural regions where extreme temperatures can induce berry drop ranging from scattered individual berries to substantial cluster portions. ||Heat-induced abscission involves activation of the abscission zone at the pedicel-berry junction, where cell wall-degrading enzymes (cellulases, pectinases, polygalacturonases) are induced by stress, weakening the attachment until mechanical separation occurs. ||The process is mediated by hormonal signals, with ethylene promoting abscission and auxin suppressing it, and heat stress can disrupt the hormonal balance favoring detachment. ||Heat_Induced_Abscission_Resistance_Disposition depends on the sensitivity of the abscission zone to heat-induced enzymatic activation, the hormonal response of pedicel tissues to heat stress, and potentially the mechanical strength of the pedicel-berry connection independent of enzymatic weakening. ||Cultivars with strong resistance maintain berry attachment through heat events that cause significant abscission in susceptible cultivars, preserving yield potential despite thermal stress.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Greer DH, Weston C (2010) Heat stress affects flowering, berry growth, sugar accumulation and photosynthesis of Vitis vinifera, Functional Plant Biology 37:206-214|| Roberts JA et al. (2002) Abscission, dehiscence, and other cell separation processes, Annual Review of Plant Biology 53:131-158|| Else MA et al. (2004) Stomatal closure in flooded tomato plants involves abscisic acid and a chemically unidentified anti-transpirant in xylem sap, Plant Physiology 135:2215-2224"
  },
  "Drought_Tolerance_Disposition": {
    "definition": "A Drought_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through physiological, biochemical, and morphological mechanisms that enable maintenance of cellular function, growth, and productivity under soil water deficit conditions that would otherwise cause wilting, metabolic disruption, and yield loss.", 
    "alternative_term": "water deficit tolerance | drought resistance | water stress tolerance |+ Trockentoleranz-Disposition | Wassermangel-Toleranz | Dürreresistenz",
    "example_of_usage": "Comprehensive characterization of Drought_Tolerance_Disposition at INRAE Montpellier compared physiological responses to progressive soil drying across 25 cultivars in a lysimeter experiment with precise water deficit control. ||Measurements included predawn and midday leaf water potential, stomatal conductance, photosynthesis, and osmotic potential at full turgor across a range of soil water availability from well-watered to severe stress (predawn water potential -0.2 to -1.2 MPa). ||Cultivars showed distinct Drought_Tolerance_Disposition strategies. 'Grenache' exhibited isohydric drought tolerance with early stomatal closure (conductance reduced 50% at predawn potential of -0.4 MPa), strict midday water potential regulation (maintained above -1.4 MPa), and minimal osmotic adjustment (0.15 MPa). 'Syrah' displayed anisohydric behavior with sustained stomatal opening (50% reduction only at -0.8 MPa predawn), progressive midday water potential decline to -1.9 MPa under severe stress, and moderate osmotic adjustment (0.35 MPa). 'Sangiovese' showed intermediate characteristics. ||Under severe stress, 'Grenache' maintained higher leaf relative water content (78% versus 62%) but accumulated less carbon (30% photosynthesis reduction versus 15% in 'Syrah' at moderate stress). ||Recovery following rewatering was faster in 'Grenache' (full stomatal recovery within 24 hours) compared to 'Syrah' (72 hours to full recovery, with some persistent embolism). ||These findings demonstrate that Drought_Tolerance_Disposition involves trade-offs between water conservation and carbon gain, with optimal strategy depending on drought severity and duration.",
    "editor_note": "Drought_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||Drought tolerance encompasses multiple mechanisms with different costs and benefits, addressed through child classes including Stomatal_Regulation_Disposition and Osmotic_Adjustment_Disposition. ||The isohydric-anisohydric spectrum represents a fundamental strategic axis in drought response, with neither extreme optimal for all conditions. ||Drought tolerance interacts with heat tolerance through shared mechanisms (stomatal behavior, membrane stability) and co-occurrence of stresses. ||Rootstock genotype strongly influences scion drought tolerance through root system properties and hydraulic conductance.  This disposition represents the capacity to tolerate water stress, critically important for viticulture as grapevines are cultivated across diverse climates ranging from humid to semi-arid, and increasingly relevant under climate change scenarios projecting reduced precipitation and increased drought frequency in many wine regions. ||Drought tolerance in grapevine involves multiple mechanisms including drought avoidance (deep rooting accessing subsoil water, early phenology escaping late-season drought), dehydration postponement (stomatal regulation conserving water, osmotic adjustment maintaining turgor), and dehydration tolerance (cellular protection mechanisms enabling function at low water potential). ||The strategic balance between water conservation and carbon gain varies among cultivars, with isohydric types prioritizing water conservation through early stomatal closure while anisohydric types maintain gas exchange longer under stress at the cost of greater dehydration risk. ||Drought_Tolerance_Disposition encompasses both constitutive traits (root architecture, stomatal density, cuticular properties) and inducible responses (stomatal closure, osmotic adjustment, protective protein accumulation). ||Understanding genotypic variation in drought tolerance informs cultivar selection for dry climates, rootstock choice for water-limited sites, and irrigation management strategies balancing vine stress with fruit quality optimization.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Chaves MM et al. (2010) Grapevine under deficit irrigation: hints from physiological and molecular data, Annals of Botany 105:661-676|| Lovisolo C et al. (2010) Drought-induced changes in development and function of grapevine (Vitis spp.) organs and in their hydraulic and non-hydraulic interactions at the whole-plant level: a physiological and molecular update, Functional Plant Biology 37:98-116|| Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405"
  },
  "Stomatal_Regulation_Disposition": {
    "definition": "A Stomatal_Regulation_Disposition is a Drought_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the pattern of stomatal aperture control in response to declining soil water availability and increasing atmospheric evaporative demand, determining the balance between water conservation through reduced transpiration and continued carbon assimilation through maintained gas exchange.", 
    "alternative_term": "stomatal drought response | stomatal conductance regulation | water-saving stomatal behavior |+ Stomataregulations-Disposition | Stomata-Trockenheitsantwort | Stomatäre-Leitfähigkeits-Regulation",
    "example_of_usage": "Detailed characterization of Stomatal_Regulation_Disposition at the University of California Davis employed diurnal gas exchange measurements across progressive drought in 20 cultivars to quantify stomatal sensitivity and response patterns. ||Stomatal conductance (gs) was measured hourly from 06:00 to 18:00 at soil water contents ranging from field capacity to severe deficit, with concurrent measurement of leaf water potential (Ψleaf) and xylem sap ABA concentration. ||Cultivars showed striking variation in Stomatal_Regulation_Disposition parameters. ||The response threshold (soil water potential causing initial stomatal closure) ranged from -0.3 MPa ('Grenache', sensitive) to -0.8 MPa ('Syrah', insensitive). ||The slope of gs versus Ψleaf relationship (stomatal sensitivity) varied 3-fold, from 85 mmol m⁻² s⁻¹ MPa⁻¹ ('Grenache') to 28 mmol m⁻² s⁻¹ MPa⁻¹ ('Syrah'). ||ABA sensitivity (gs reduction per unit xylem ABA increase) also differed, with 'Grenache' showing 50% gs reduction at 500 ng L⁻¹ ABA versus 1200 ng L⁻¹ for equivalent reduction in 'Syrah'. ||Stomatal_Regulation_Disposition had direct consequences for water use and productivity. ||Under moderate drought, 'Grenache' used 35% less water than 'Syrah' but also assimilated 25% less carbon. ||Mathematical modeling identified stomatal sensitivity parameters as key determinants of cultivar performance across climate scenarios, with high-sensitivity cultivars favored in severe drought environments and low-sensitivity cultivars advantageous where moderate stress is typical and irrigation is available.",
    "editor_note": "Stomatal_Regulation_Disposition is_a Drought_Tolerance_Disposition. ||Stomatal regulation represents the primary short-term response to drought, determining the water conservation versus carbon gain trade-off. ||Child classes address the major stomatal behavior strategies along the isohydric-anisohydric continuum. ||Stomatal regulation involves integration of hydraulic, chemical (ABA), and atmospheric signals, with genotypic variation in sensitivity to each. ||Stomatal behavior interacts with evaporative cooling capacity, as closed stomata reduce both water loss and transpirational cooling.  This disposition represents the stomatal component of drought response, fundamental to plant water relations as stomata control the primary pathway for both water loss (transpiration) and CO₂ uptake (photosynthesis). ||Stomatal regulation under drought involves complex integration of hydraulic signals (leaf water potential, xylem tension), chemical signals (abscisic acid from roots and leaves, pH changes in xylem sap), and atmospheric signals (vapor pressure deficit), with the relative weighting of these signals varying among genotypes to produce distinct stomatal behavior patterns. ||The stomatal response strategy profoundly influences whole-plant water use, carbon gain, and survival under drought, with early-closing stomata conserving water but sacrificing photosynthesis while late-closing stomata maximize carbon gain but risk severe dehydration and hydraulic failure. ||Stomatal_Regulation_Disposition in grapevine spans a continuum from strongly isohydric (tight stomatal control maintaining leaf water potential) to anisohydric (loose control allowing water potential to decline), with most cultivars falling between these extremes. ||This variation represents evolved adaptation to different moisture regimes and provides genetic diversity for breeding and cultivar selection targeting specific environments.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405|| Tardieu F, Simonneau T (1998) Variability among species of stomatal control under fluctuating soil water status and evaporative demand: modelling isohydric and anisohydric behaviours, Journal of Experimental Botany 49:419-432|| Tombesi S et al. (2015) Stomatal closure is induced by hydraulic signals and maintained by ABA in drought-stressed grapevine, Scientific Reports 5:12449"
  },
  "Isohydric_Behavior_Disposition": {
    "definition": "An Isohydric_Behavior_Disposition is a Stomatal_Regulation_Disposition that inheres in a Vitis vinifera plant and is realized through tight stomatal control that maintains relatively constant midday leaf water potential regardless of soil water availability, prioritizing hydraulic safety and tissue hydration over carbon assimilation during drought.", 
    "alternative_term": "isohydric stomatal behavior | water potential homeostasis | conservative water use |+ Isohydrisches-Verhalten-Disposition | Wasserpotential-Homöostase | Konservative-Wassernutzung",
    "example_of_usage": "Mechanistic investigation of Isohydric_Behavior_Disposition at INRAE Bordeaux compared the archetypal isohydric cultivar 'Grenache' with anisohydric 'Syrah' under controlled drought progression, examining the physiological basis of water potential homeostasis. ||Potted vines were subjected to soil drying over 21 days with daily measurements of predawn water potential (Ψpd, indicator of soil water status), midday water potential (Ψmd), stomatal conductance, and xylem sap ABA. 'Grenache' exhibited classic Isohydric_Behavior_Disposition with Ψmd maintained between -1.2 and -1.4 MPa throughout drought despite Ψpd declining from -0.2 to -0.9 MPa. ||This homeostasis was achieved through progressive stomatal closure, with conductance declining from 280 to 35 mmol m⁻² s⁻¹ (87% reduction) as drought intensified. ||ABA analysis revealed that 'Grenache' accumulated xylem ABA earlier (detectable increase at Ψpd = -0.3 MPa) and more strongly (peak 2800 ng L⁻¹) than 'Syrah' (increase at -0.6 MPa, peak 1400 ng L⁻¹). ||Guard cell sensitivity assays confirmed that 'Grenache' stomata were 2.3-fold more responsive to ABA than 'Syrah' stomata. ||Hydraulic vulnerability curves showed that 'Grenache' maintained Ψmd above its P50 (water potential causing 50% loss of hydraulic conductivity = -1.8 MPa) throughout drought, whereas 'Syrah' Ψmd approached and briefly exceeded its P50 (-2.1 MPa). ||The Isohydric_Behavior_Disposition of 'Grenache' thus reflects combined early ABA accumulation and high stomatal ABA sensitivity, prioritizing hydraulic safety through strict Ψmd regulation.",
    "editor_note": "Isohydric_Behavior_Disposition is_a Stomatal_Regulation_Disposition. ||Isohydric behavior maintains stable leaf water potential through sensitive stomatal closure, prioritizing hydraulic safety over carbon gain. ||The mechanism involves early ABA accumulation and high guard cell ABA sensitivity. ||Isohydric cultivars are well-suited to severe drought environments where hydraulic failure is a significant risk. ||Trade-offs include reduced photosynthesis and growth under moderate drought where stomata close preemptively. 'Grenache' and 'Tempranillo' are classic isohydric cultivars.  This disposition represents the water-conserving end of the stomatal regulation spectrum, with isohydric cultivars responding to early drought signals by closing stomata to prevent the decline in leaf water potential that would otherwise occur as soil water becomes limiting. ||The term \"isohydric\" (Greek: equal water) refers to the maintenance of stable leaf water status across varying soil moisture conditions, achieved through sensitive stomatal responses to hydraulic and chemical signals. ||Isohydric behavior involves high sensitivity to abscisic acid (ABA), rapid stomatal closure in response to declining xylem water potential, and possibly root-to-shoot chemical signaling that triggers stomatal closure before leaf water potential declines significantly. ||The adaptive value of Isohydric_Behavior_Disposition lies in protection against hydraulic failure (xylem cavitation and embolism) and maintenance of leaf tissue integrity during drought, enabling rapid recovery when water becomes available. ||However, this conservative strategy incurs costs in reduced photosynthesis and growth during drought periods, potentially limiting productivity in environments where moderate drought is common but not severe. ||Classic isohydric grapevine cultivars include 'Grenache' and 'Tempranillo'.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405|| Tardieu F, Simonneau T (1998) Variability among species of stomatal control under fluctuating soil water status and evaporative demand, Journal of Experimental Botany 49:419-432|| Soar CJ et al. (2006) Grape vine varieties Shiraz and Grenache differ in their stomatal response to VPD: apparent links with ABA physiology and gene expression in leaf tissue, Australian Journal of Grape and Wine Research 12:2-12"
  },
  "Anisohydric_Behavior_Disposition": {
    "definition": "An Anisohydric_Behavior_Disposition is a Stomatal_Regulation_Disposition that inheres in a Vitis vinifera plant and is realized through loose stomatal control that allows midday leaf water potential to decline progressively with decreasing soil water availability, prioritizing continued carbon assimilation over strict maintenance of tissue hydration during drought.", 
    "alternative_term": "anisohydric stomatal behavior | opportunistic water use | risk-taking water strategy |+ Anisohydrisches-Verhalten-Disposition | Variable-Wasserpotential-Strategie | Opportunistische-Wassernutzung",
    "example_of_usage": "Field investigation of Anisohydric_Behavior_Disposition in the Barossa Valley compared 'Syrah' (anisohydric) and 'Grenache' (isohydric) under natural drought conditions across two contrasting seasons (average and severe drought). ||Midday measurements of leaf water potential, stomatal conductance, and photosynthesis were conducted at 2-week intervals throughout the growing season, with concurrent soil moisture monitoring. 'Syrah' displayed pronounced Anisohydric_Behavior_Disposition with Ψmd declining from -1.0 MPa in well-watered conditions to -2.2 MPa during peak drought in the severe year, while 'Grenache' maintained Ψmd between -1.2 and -1.5 MPa regardless of conditions. ||At equivalent soil water content (15% volumetric), 'Syrah' sustained stomatal conductance of 120 mmol m⁻² s⁻¹ and photosynthesis of 8.5 μmol CO₂ m⁻² s⁻¹, while 'Grenache' had reduced to 45 mmol m⁻² s⁻¹ and 3.2 μmol CO₂ m⁻² s⁻¹. ||Cumulative seasonal carbon assimilation was 40% higher in 'Syrah' during the average drought year. ||However, the severe drought year revealed the risks of Anisohydric_Behavior_Disposition, with 'Syrah' showing 35% loss of hydraulic conductivity from cavitation (measured by percentage loss of conductivity, PLC), visible leaf desiccation affecting 15% of canopy, and incomplete recovery the following season. 'Grenache' showed only 8% PLC and full recovery. ||Interestingly, fruit quality parameters diverged, with 'Syrah' berries showing higher anthocyanin concentration (likely stress-induced) but also elevated alcohol potential from accelerated sugar accumulation. ||These observations illustrate how Anisohydric_Behavior_Disposition maximizes productivity in moderate drought but incurs greater risk under severe conditions.",
    "editor_note": "Anisohydric_Behavior_Disposition is_a Stomatal_Regulation_Disposition. ||Anisohydric behavior allows leaf water potential to decline with soil drying, maintaining gas exchange at the cost of tissue hydration. ||The mechanism involves reduced ABA sensitivity and/or delayed ABA accumulation compared to isohydric cultivars. ||Anisohydric cultivars are favored in environments with moderate, predictable drought and available irrigation. ||Risks include hydraulic failure and tissue damage under severe drought. 'Syrah/Shiraz' and 'Semillon' are classic anisohydric cultivars.  This disposition represents the productivity-oriented end of the stomatal regulation spectrum, with anisohydric cultivars maintaining substantial stomatal opening and gas exchange as drought develops, accepting lower leaf water potential as a consequence of continued transpiration against increasing soil-to-leaf water potential gradient. ||The term \"anisohydric\" (Greek: unequal water) refers to the variable leaf water status that results from this strategy, with midday water potential tracking soil water potential rather than being defended at a stable set-point. ||Anisohydric behavior involves reduced sensitivity to ABA, higher stomatal conductance at equivalent water potential, and potentially greater reliance on hydraulic signals versus chemical signals in stomatal regulation. ||The adaptive value of Anisohydric_Behavior_Disposition lies in maximizing carbon gain during periods of moderate water deficit, supporting growth and fruit development when isohydric cultivars would severely curtail photosynthesis. ||However, this aggressive strategy incurs risks of hydraulic failure (cavitation) and tissue damage under severe or prolonged drought when water potential declines below critical thresholds. ||Classic anisohydric grapevine cultivars include 'Syrah' (Shiraz) and 'Semillon'.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405|| Hochberg U et al. (2013) Stomatal regulation of anisohydric grapevine (Vitis vinifera cv. Syrah) during drought stress, Annals of Botany 112:1595-1606|| Chaves MM et al. (2010) Grapevine under deficit irrigation: hints from physiological and molecular data, Annals of Botany 105:661-676"
  },
  "Near_Isohydric_Behavior_Disposition": {
    "definition": "A Near_Isohydric_Behavior_Disposition is a Stomatal_Regulation_Disposition that inheres in a Vitis vinifera plant and is realized through intermediate stomatal control that partially regulates midday leaf water potential, allowing moderate decline under drought while preventing the extreme water potential reductions characteristic of anisohydric behavior.", 
    "alternative_term": "intermediate stomatal behavior | partial water potential regulation | moderate water conservation |+ Nah-isohydrisches-Verhalten-Disposition | Intermediäre-Stomataregulation | Partielle-Wasserpotential-Regulation",
    "example_of_usage": "Comparative analysis of Near_Isohydric_Behavior_Disposition at Bordeaux Sciences Agro positioned 30 cultivars along the isohydric-anisohydric continuum using standardized drought stress protocols and quantitative stomatal behavior parameters. ||The isohydricity index (σ, slope of midday versus predawn water potential regression) was calculated for each cultivar, with σ = 0 indicating perfect isohydric behavior and σ = 1 indicating fully anisohydric behavior. ||Near-isohydric cultivars were defined as σ between 0.3 and 0.7. ||Of the 30 cultivars evaluated, 18 (60%) showed Near_Isohydric_Behavior_Disposition with σ ranging from 0.32 ('Merlot') to 0.68 ('Cabernet Sauvignon'). ||Near-isohydric 'Merlot' allowed Ψmd to decline from -1.1 MPa (well-watered) to -1.6 MPa (moderate drought) before stabilizing through stomatal closure, showing intermediate response between isohydric 'Grenache' (σ = 0.15, Ψmd stable at -1.3 MPa) and anisohydric 'Syrah' (σ = 0.85, Ψmd declining to -2.0 MPa). ||Productivity analysis revealed that near-isohydric cultivars achieved intermediate seasonal carbon gain, capturing 75-85% of anisohydric productivity while maintaining hydraulic safety margins (PLC below 20% under moderate drought). ||Notably, some cultivars showed environmentally plastic Near_Isohydric_Behavior_Disposition, with 'Cabernet Sauvignon' (σ = 0.68 in maritime climate) behaving more isohydric (σ = 0.42) when grown in continental climate with greater diurnal temperature variation, suggesting acclimation of stomatal regulation strategy. ||These findings indicate that Near_Isohydric_Behavior_Disposition represents both a genetic trait and an adaptive response, providing flexibility across diverse growing conditions.",
    "editor_note": "Near_Isohydric_Behavior_Disposition is_a Stomatal_Regulation_Disposition. ||Near-isohydric behavior represents the middle of the stomatal regulation continuum, with partial water potential regulation. ||Many commercial cultivars show near-isohydric behavior, balancing productivity and safety. ||The isohydricity index (σ) provides quantitative positioning along the continuum. ||Some cultivars show plasticity in stomatal behavior depending on environment or stress history. ||Near-isohydric cultivars may be broadly adapted across diverse environments.  This disposition represents the middle ground of the stomatal regulation spectrum, where cultivars show partial water potential homeostasis that balances hydraulic safety against continued productivity. ||Near-isohydric behavior involves moderate stomatal sensitivity that permits continued gas exchange during early drought phases while triggering progressive closure as stress intensifies, resulting in leaf water potential that declines but stabilizes at a regulated minimum rather than tracking soil water potential indefinitely. ||The physiological basis of Near_Isohydric_Behavior_Disposition likely involves intermediate ABA sensitivity and/or hydraulic signal integration that produces graded rather than all-or-nothing stomatal responses. ||The adaptive value of this intermediate strategy lies in balancing the competing demands of water conservation and carbon gain, avoiding both the productivity costs of strict isohydric regulation and the hydraulic risks of anisohydric behavior. ||Many commercially important cultivars display near-isohydric characteristics, enabling reasonable productivity across varied environments while maintaining adequate hydraulic safety margins. ||This intermediate behavior also shows greater plasticity, with some cultivars adjusting their position on the isohydric-anisohydric spectrum based on environmental conditions or stress history.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Martínez-Vilalta J et al. (2014) A new look at water transport regulation in plants, New Phytologist 204:105-115|| Hochberg U et al. (2018) Iso/anisohydry: a plant-environment interaction rather than a simple hydraulic trait, Trends in Plant Science 23:112-120|| Lavoie-Lamoureux A et al. (2017) Factors influencing stomatal conductance in response to water availability in grapevine: a meta-analysis, Physiologia Plantarum 159:468-482"
  },
  "Osmotic_Adjustment_Disposition": {
    "definition": "An Osmotic_Adjustment_Disposition is a Drought_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through the active accumulation of compatible solutes in cells during water stress, lowering osmotic potential and enabling water uptake and turgor maintenance at soil and leaf water potentials that would otherwise cause wilting and loss of cell function.", 
    "alternative_term": "osmotic regulation | active solute accumulation | turgor-maintaining solute adjustment |+ Osmotische-Anpassungs-Disposition | Osmoregulation | Aktive-Solut-Akkumulation",
    "example_of_usage": "Systematic quantification of Osmotic_Adjustment_Disposition at the University of Adelaide measured osmotic potential at full turgor (Ψπ100) in leaves of 25 cultivars under well-watered and drought-stressed (predawn Ψ = -0.8 MPa for 14 days) conditions. ||Osmotic adjustment was calculated as the difference between stressed and control Ψπ100 values. ||Additionally, tissue extracts were analyzed for major compatible solutes (proline, total soluble sugars, potassium) to identify the biochemical basis of adjustment. ||Osmotic_Adjustment_Disposition varied substantially among cultivars, ranging from 0.12 MPa ('Pinot Noir', minimal adjustment) to 0.72 MPa ('Sultana', strong adjustment). ||Intermediate values characterized most wine grape cultivars, with 'Cabernet Sauvignon' at 0.38 MPa and 'Chardonnay' at 0.45 MPa. ||Solute analysis revealed cultivar-specific adjustment strategies. 'Sultana' achieved its strong adjustment primarily through sugar accumulation (contributing 55% of osmotic change) with moderate proline contribution (25%). 'Shiraz' (0.52 MPa adjustment) relied more heavily on proline (45% contribution) with lower sugar involvement (30%). ||Potassium contributed 15-25% of adjustment across all cultivars. ||Turgor maintenance directly reflected Osmotic_Adjustment_Disposition, with high-adjusting 'Sultana' maintaining leaf turgor of 0.65 MPa at leaf water potential of -2.0 MPa, while low-adjusting 'Pinot Noir' showed turgor loss (zero turgor) at -1.6 MPa. ||Growth analysis confirmed functional significance, with high-adjusting cultivars maintaining 70% of control shoot elongation rate at moderate drought versus 35% in low-adjusting cultivars, demonstrating that Osmotic_Adjustment_Disposition enables continued growth under water deficit.",
    "editor_note": "Osmotic_Adjustment_Disposition is_a Drought_Tolerance_Disposition. ||Osmotic adjustment provides cellular-level drought tolerance through solute accumulation, enabling turgor maintenance at low water potential. ||Child classes address specific aspects including Solute_Accumulation_Disposition (biochemical mechanisms) and Turgor_Maintenance_Disposition (functional outcome). ||The magnitude and solute composition of adjustment vary among genotypes. ||Osmotic adjustment is metabolically costly but enables continued growth and function during drought. ||Table grape cultivars often show stronger adjustment than wine grapes.  This disposition represents the biochemical component of drought tolerance operating at the cellular level, complementing stomatal regulation that operates at the whole-plant level. ||Osmotic adjustment enables cells to maintain positive turgor pressure and associated turgor-dependent processes (cell expansion, stomatal function, phloem transport) under water deficit conditions by increasing the concentration of osmotically active solutes including inorganic ions (potassium), amino acids (proline, glycine betaine), sugars (glucose, fructose, sucrose), sugar alcohols (mannitol, sorbitol), and organic acids (malate). ||The magnitude of osmotic adjustment varies among grapevine genotypes from minimal (< 0.2 MPa) to substantial (> 0.8 MPa), with high-adjusting cultivars able to maintain turgor and function at water potentials that cause wilting in low-adjusting cultivars. ||Osmotic_Adjustment_Disposition is quantified by comparing osmotic potential at full turgor in stressed versus well-watered plants, with the difference representing active solute accumulation. ||This capacity is metabolically costly (requiring carbon skeletons and energy for solute synthesis) but enables continued growth and function during drought when non-adjusting plants would be severely impaired.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Morgan JM (1984) Osmoregulation and water stress in higher plants, Annual Review of Plant Physiology 35:299-319|| Patakas A et al. (2002) Leaf age effects on solute accumulation in water-stressed grapevines, Journal of Plant Physiology 159:969-976|| Rodrigues ML et al. (1993) Osmotic adjustment in water stressed grapevine leaves in relation to carbon assimilation, Australian Journal of Plant Physiology 20:309-321"
  },
  "Solute_Accumulation_Disposition": {
    "definition": "A Solute_Accumulation_Disposition is an Osmotic_Adjustment_Disposition that inheres in a Vitis vinifera plant and is realized through the biochemical capacity to synthesize and accumulate specific compatible solutes in response to water stress, providing the osmotically active compounds that lower cellular osmotic potential.", 
    "alternative_term": "compatible solute synthesis | osmolyte accumulation | stress metabolite production |+ Solut-Akkumulations-Disposition | Kompatible-Solut-Synthese | Osmolyt-Akkumulation",
    "example_of_usage": "Biochemical and molecular characterization of Solute_Accumulation_Disposition at INRAE Montpellier examined compatible solute profiles and biosynthetic gene expression across 18 cultivars during controlled drought stress. ||Leaf proline, total soluble sugars, and potassium were quantified at well-watered and stressed (Ψpd = -0.8 MPa) conditions, with parallel qRT-PCR analysis of VvP5CS (proline synthesis), VvSPS (sucrose phosphate synthase), and VvHKT1 (potassium transport). ||Solute_Accumulation_Disposition showed substantial cultivar variation in both magnitude and composition. ||Total solute increase (expressed as osmotic contribution) ranged from 0.15 MPa ('Pinot Noir') to 0.68 MPa ('Sultana'). ||Proline accumulation ranged from 2.5 μmol g⁻¹ FW ('Chasselas') to 28 μmol g⁻¹ FW ('Shiraz'), with VvP5CS expression correlating strongly with proline level (r = 0.89). ||Sugar accumulation ranged from 15 mg g⁻¹ FW ('Grenache') to 85 mg g⁻¹ FW ('Sultana'), largely derived from starch hydrolysis rather than continued photosynthesis as evidenced by declining starch reserves. ||Cultivars showed distinct Solute_Accumulation_Disposition strategies, with 'Shiraz' representing a \"proline-dominated\" pattern (proline contributing 45% of osmotic adjustment) and 'Sultana' showing a \"sugar-dominated\" pattern (sugars contributing 55%). 'Cabernet Sauvignon' exhibited balanced accumulation (proline 30%, sugars 35%, K⁺ 20%). ||Metabolic cost analysis estimated that proline-dominated adjustment required 15% more nitrogen investment than sugar-dominated adjustment, potentially relevant for nitrogen-limited vineyard conditions. ||These findings demonstrate that Solute_Accumulation_Disposition encompasses both quantitative capacity and qualitative strategy with implications for resource allocation.",
    "editor_note": "Solute_Accumulation_Disposition is_a Osmotic_Adjustment_Disposition. ||This class addresses the biochemical basis of osmotic adjustment through compatible solute production. ||Major solutes include proline, sugars, and potassium, with cultivar-specific profiles. ||Biosynthetic gene expression (P5CS, SPS) underlies solute accumulation capacity. ||Different solutes have different metabolic costs and resource requirements (carbon, nitrogen). ||Solute composition may affect drought tolerance quality beyond osmotic contribution through additional protective functions (proline as antioxidant, sugars stabilizing membranes).  This disposition represents the biosynthetic foundation of osmotic adjustment, determining both the magnitude of adjustment possible and the metabolic costs incurred through solute production. ||Major compatible solutes accumulated during drought in grapevine include proline (synthesized via the glutamate pathway, catalyzed by pyrroline-5-carboxylate synthetase), soluble sugars (derived from starch hydrolysis and continued photosynthesis), sugar alcohols, glycine betaine (in species with active betaine aldehyde dehydrogenase), and inorganic ions (primarily potassium, accumulated via membrane transporters). ||These compounds are termed \"compatible\" because they can accumulate to high concentrations without disrupting enzyme function or cellular metabolism, unlike inorganic salts that would cause ionic toxicity at equivalent osmotic contribution. ||Solute_Accumulation_Disposition involves induction of biosynthetic enzyme genes under stress, metabolic flux toward compatible solutes, and cellular compartmentalization protecting sensitive enzymes from solute interference. ||Cultivars differ in both the total magnitude of solute accumulation and the specific solute profile produced, with some relying primarily on proline, others on sugars, and most on a combination. ||The relative metabolic cost varies among solutes, with sugar accumulation potentially conflicting with carbon allocation to growth while proline synthesis requires both carbon and nitrogen investment.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Delauney AJ, Verma DPS (1993) Proline biosynthesis and osmoregulation in plants, Plant Journal 4:215-223|| Patakas A et al. (2002) Leaf age effects on solute accumulation in water-stressed grapevines, Journal of Plant Physiology 159:969-976|| Cramer GR et al. (2007) Water and salinity stress in grapevines: early and late changes in transcript and metabolite profiles, Functional and Integrative Genomics 7:111-134"
  },
  "Turgor_Maintenance_Disposition": {
    "definition": "A Turgor_Maintenance_Disposition is an Osmotic_Adjustment_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to maintain positive cell turgor pressure under declining water potential, preserving turgor-dependent processes including cell expansion, stomatal function, and phloem transport during water stress.", 
    "alternative_term": "turgor pressure maintenance | cell turgor stability | wilting resistance |+ Turgor-Aufrechterhaltungs-Disposition | Zellturgor-Stabilität | Welke-Resistenz",
    "example_of_usage": "Detailed pressure-volume analysis of Turgor_Maintenance_Disposition at the University of Western Australia determined turgor loss point (Ψtlp) and associated parameters across 22 cultivars under well-watered and drought-acclimated conditions. ||Pressure-volume curves were constructed from sequential measurements of leaf water potential and relative water content during controlled dehydration, enabling calculation of Ψtlp, osmotic potential at full turgor (Ψπ100), and bulk modulus of elasticity (ε). ||Turgor_Maintenance_Disposition showed substantial cultivar variation. ||Under well-watered conditions, Ψtlp ranged from -1.45 MPa ('Pinot Noir', early turgor loss) to -2.15 MPa ('Sultana', late turgor loss), representing 0.7 MPa variation in drought tolerance threshold. ||Following drought acclimation (3 weeks at Ψpd = -0.6 MPa), Ψtlp shifted to more negative values in all cultivars, with the adjustment magnitude ranging from 0.1 MPa ('Pinot Noir') to 0.55 MPa ('Sultana'). ||The resulting acclimated Ψtlp ranged from -1.55 MPa ('Pinot Noir') to -2.70 MPa ('Sultana'). ||Functional significance was demonstrated by growth analysis during moderate drought (Ψleaf = -1.8 MPa). ||At this water potential, high-Turgor_Maintenance_Disposition 'Sultana' (Ψtlp = -2.70 MPa when acclimated) maintained positive turgor and 65% of control shoot elongation rate. ||Low-Turgor_Maintenance_Disposition 'Pinot Noir' (Ψtlp = -1.55 MPa) experienced turgor loss at -1.8 MPa, showing zero elongation and visible wilting. ||Correlation analysis across cultivars revealed strong relationship between Ψtlp and drought yield stability (r = 0.78), confirming that Turgor_Maintenance_Disposition directly supports productivity under water-limited conditions.",
    "editor_note": "Turgor_Maintenance_Disposition is_a Osmotic_Adjustment_Disposition. ||This class addresses the functional outcome of osmotic adjustment in maintaining cell turgor. ||The turgor loss point (Ψtlp) is the key parameter, with lower (more negative) values indicating greater drought tolerance. Ψtlp can be lowered through osmotic adjustment (solute accumulation) and/or decreased cell wall elasticity. ||Turgor maintenance enables continued growth, stomatal function, and phloem transport during drought. Ψtlp is both a constitutive trait (genetic variation) and an acclimated response (adjustment during drought exposure).  This disposition represents the functional outcome of osmotic adjustment, translating biochemical solute accumulation into physiological capacity for continued growth and function under drought. ||Turgor pressure (the pressure of cell contents against the cell wall) drives cell expansion underlying growth, maintains stomatal aperture enabling gas exchange, powers phloem transport of assimilates, and maintains cell structural integrity. ||Under water stress, declining water potential would normally reduce turgor toward zero (the turgor loss point, Ψtlp), causing wilting and cessation of turgor-dependent processes. ||Cultivars with strong Turgor_Maintenance_Disposition lower their turgor loss point through osmotic adjustment, enabling positive turgor at water potentials that would cause wilting in non-adjusting genotypes. ||The turgor loss point is a key physiological parameter, typically ranging from -1.5 MPa to -2.5 MPa among grapevine cultivars, with lower (more negative) values indicating greater drought tolerance. ||Turgor_Maintenance_Disposition enables continued shoot growth, functional stomatal regulation, and maintained source-sink relations during drought, directly supporting productivity under water-limited conditions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bartlett MK et al. (2012) The correlations and sequence of plant stomatal, hydraulic, and wilting responses to drought, Proceedings of the National Academy of Sciences 109:13928-13933|| Rodrigues ML et al. (1993) Osmotic adjustment in water stressed grapevine leaves in relation to carbon assimilation, Australian Journal of Plant Physiology 20:309-321|| Sancho-Knapik D et al. (2016) The reflectance spectrum of plant leaves and changes caused by drought stress, Functional Plant Biology 43:320-327"
  },
  "Root_System_Drought_Adaptation_Disposition": {
    "definition": "A Root_System_Drought_Adaptation_Disposition is a Drought_Tolerance_Disposition that inheres in the root system of a Vitis plant and is realized through root architectural, morphological, and physiological traits that enhance water acquisition from soil under drought conditions.", 
    "alternative_term": "root drought adaptation | below-ground water acquisition | root water uptake capacity |+ Wurzelsystem-Trockenanpassungs-Disposition | Unterirdische-Wasseraufnahme | Wurzel-Wasserakquisition",
    "example_of_usage": "Comprehensive characterization of Root_System_Drought_Adaptation_Disposition at UC Davis compared root system properties and drought performance across 15 commercial rootstocks grown in deep soil columns (2 m depth) with controlled water deficit. ||Root distribution was assessed by minirhizotron imaging, total root length and depth by excavation at trial completion, and functional water acquisition by deuterium-labeled water injection at different depths. ||Rootstocks showed substantial variation in Root_System_Drought_Adaptation_Disposition. '110 Richter' (V. berlandieri × V. rupestris) exhibited deep-rooting adaptation with 45% of root length below 1 m depth, maximum rooting depth of 1.85 m, and efficient deep water acquisition (deuterium from 1.5 m depth detected in leaves within 48 hours). '101-14 Mgt' (V. riparia × V. rupestris) showed shallow root concentration with only 15% below 1 m and maximum depth of 1.2 m, relying on dense surface rooting (root length density 2.8 cm cm⁻³ in upper 30 cm versus 1.4 cm cm⁻³ for '110 Richter'). ||Under progressive drought, '110 Richter'-grafted vines maintained higher predawn water potential (-0.35 versus -0.65 MPa for '101-14 Mgt' at equivalent surface soil moisture), demonstrating how Root_System_Drought_Adaptation_Disposition through deep rooting provides access to water unavailable to shallow-rooted systems. ||Scion variety ('Cabernet Sauvignon') was constant, confirming that observed differences reflected rootstock root properties.",
    "editor_note": "Root_System_Drought_Adaptation_Disposition is_a Drought_Tolerance_Disposition. ||Root system properties are primarily determined by rootstock genotype in grafted vines. ||Child classes address specific root adaptations including Deep_Rooting_Disposition, Root_Density_Disposition, and Root_Hydraulic_Conductance_Disposition. ||Root adaptation interacts with scion stomatal behavior to determine whole-vine drought response. ||Root system traits show strong genotype × soil type interactions, requiring site-specific rootstock selection.  This disposition represents the below-ground component of drought adaptation, complementing above-ground stomatal regulation and osmotic adjustment by determining the vine's capacity to access and transport soil water to transpiring shoots. ||Root system properties critical for drought adaptation include rooting depth (access to deep soil water reserves), root density and distribution (exploitation of soil volume), root hydraulic conductance (water transport efficiency), and root-to-shoot signaling (coordination of whole-plant drought responses through ABA and other signals). ||In grafted grapevines, Root_System_Drought_Adaptation_Disposition is primarily determined by the rootstock genotype, making rootstock selection a primary management tool for drought adaptation. ||Rootstocks vary substantially in root system architecture and function, ranging from shallow, dense root systems suited to soils with reliable surface moisture to deep, extensive systems adapted to access water in deep soil layers during prolonged drought. ||The interaction between rootstock root properties and scion stomatal behavior determines whole-vine drought response, with combinations of drought-adapted rootstock and water-conserving scion potentially providing synergistic drought tolerance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart DR et al. (2006) Grapevine rooting patterns: a comprehensive analysis and review, American Journal of Enology and Viticulture 57:89-104|| Alsina MM et al. (2011) Seasonal changes of whole root system conductance by a drought-tolerant grape root system, Journal of Experimental Botany 62:99-109|| Tramontini S et al. (2013) Rootstock control of scion response to water stress in grapevine, Environmental and Experimental Botany 93:20-26"
  },
  "Deep_Rooting_Disposition": {
    "definition": "A Deep_Rooting_Disposition is a Root_System_Drought_Adaptation_Disposition that inheres in a Vitis plant root system and is realized through the capacity to extend roots to substantial soil depths, accessing water reserves in subsoil layers that remain available when surface soils are depleted during drought.", 
    "alternative_term": "deep root penetration | subsoil rooting capacity | vertical root extension |+ Tiefwurzelungs-Disposition | Unterboden-Durchwurzelung | Vertikale-Wurzelausdehnung",
    "example_of_usage": "Field investigation of Deep_Rooting_Disposition at INRAE Montpellier employed soil coring and root excavation across 12 rootstocks in a 15-year-old vineyard on deep alluvial soil to characterize maximum rooting depth and vertical root distribution. ||Root presence was assessed in 20 cm depth increments to 4 m depth, with root length density quantified in each layer. ||Deep_Rooting_Disposition varied dramatically among rootstocks. '140 Ruggeri' (V. berlandieri × V. rupestris) showed exceptional deep rooting with live roots detected to 3.8 m depth and 35% of total root length below 1.5 m, reflecting its breeding origin from drought-adapted parents on limestone soils of southern France. 'Riparia Gloire' (V. riparia selection) exhibited minimal Deep_Rooting_Disposition with maximum depth of 1.1 m and only 8% of roots below 0.5 m, consistent with its origin in riparian habitats with reliable surface water. ||Hybrid rootstocks showed intermediate patterns, with '110 Richter' reaching 2.6 m and 'SO4' limited to 1.6 m. ||Soil water extraction monitoring using neutron probe revealed that deep-rooting '140 Ruggeri' extracted water from 2-3 m depth during late-season drought while shallow '3309C' extraction was confined to the upper meter. ||This deep water access enabled '140 Ruggeri'-grafted vines to maintain 25% higher midday water potential during August drought (-1.2 versus -1.6 MPa), demonstrating the functional significance of Deep_Rooting_Disposition for drought adaptation.",
    "editor_note": "Deep_Rooting_Disposition is_a Root_System_Drought_Adaptation_Disposition. ||Deep rooting provides drought avoidance through access to subsoil water reserves. ||V. berlandieri and V. rupestris parentage generally confers deeper rooting than V. riparia. ||Deep rooting value depends on soil conditions permitting root penetration and presence of subsoil water. ||Maximum rooting depth under field conditions ranges from ~1 m to >6 m depending on rootstock and soil. ||Deep rooting is particularly valuable in Mediterranean climates with winter-recharged deep soil water.  This disposition represents a drought avoidance mechanism operating through spatial exploitation of soil water resources, with deep-rooted vines able to maintain water uptake by shifting extraction to progressively deeper soil layers as surface moisture is exhausted. ||Deep rooting capacity depends on inherent root growth vigor, gravitropic response directing root extension downward, ability to penetrate compact subsoil layers, and tolerance of subsoil conditions (lower oxygen, higher bulk density, potentially different pH and mineral content). ||Grapevine rootstocks vary substantially in Deep_Rooting_Disposition, with maximum rooting depths ranging from less than 1 m in shallow-rooting genotypes to over 6 m in deep-rooting types under favorable soil conditions. ||Deep_Rooting_Disposition is particularly valuable in climates with winter rainfall recharging deep soil layers that are then progressively depleted during dry growing seasons, as deep roots access this stored water unavailable to shallow-rooted vines. ||However, deep rooting is only beneficial where soil conditions permit root penetration and where subsoil water is actually present, making site-soil characteristics critical determinants of deep rooting value.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart DR et al. (2006) Grapevine rooting patterns: a comprehensive analysis and review, American Journal of Enology and Viticulture 57:89-104|| Southey JM, Archer E (1988) The effect of rootstock cultivar on grapevine root distribution and density, in The Grapevine Root and its Environment, Department of Agriculture and Water Supply Technical Communication 215, Pretoria|| Bauerle TL et al. (2008) Root foraging in response to heterogeneous soil moisture in two grapevines that differ in potential growth rate, New Phytologist 179:857-866"
  },
  "Root_Density_Disposition": {
    "definition": "A Root_Density_Disposition is a Root_System_Drought_Adaptation_Disposition that inheres in a Vitis plant root system and is realized through the production of high root length density (root length per unit soil volume), enhancing the capacity to extract water from exploited soil zones through intensive exploitation rather than extensive exploration.", 
    "alternative_term": "root length density | root proliferation capacity | soil volume exploitation |+ Wurzeldichte-Disposition | Wurzellängendichte | Bodenvolumen-Erschließung",
    "example_of_usage": "Quantitative assessment of Root_Density_Disposition at Washington State University compared root length density profiles across 10 rootstocks using soil coring with image analysis to quantify root length in undisturbed samples. ||Cores were collected at 10 cm depth intervals to 1.5 m at distances of 30, 60, and 90 cm from the vine trunk, enabling three-dimensional mapping of root distribution. ||Root_Density_Disposition showed marked rootstock variation. '101-14 Mgt' exhibited high root density with peak values of 3.8 cm cm⁻³ in the 10-30 cm depth zone at 30 cm from trunk, and mean density of 2.1 cm cm⁻³ across the upper 50 cm. '110 Richter' showed lower density (peak 1.8 cm cm⁻³, mean 1.2 cm cm⁻³ in upper 50 cm) but greater depth distribution. ||Fine root fraction (< 1 mm diameter) analysis revealed that high-density '101-14 Mgt' invested 65% of root length in fine roots versus 48% for '110 Richter', explaining density differences through proliferation strategy. ||Soil water depletion monitoring during a controlled drought showed that high-density '101-14 Mgt' depleted upper soil water more rapidly (reaching -1.5 MPa soil water potential in 12 days versus 18 days for '110 Richter'), but then experienced sharper stress increase as this zone was exhausted while '110 Richter' transitioned to deeper extraction. ||These findings illustrate how Root_Density_Disposition creates distinct water extraction patterns with different implications for drought timing and severity.",
    "editor_note": "Root_Density_Disposition is_a Root_System_Drought_Adaptation_Disposition. ||Root density determines water extraction intensity within rooted volume, complementing deep rooting which extends accessible volume. ||High density favors rapid exploitation of available water but may accelerate local depletion. ||V. riparia parentage tends toward higher density, shallow systems while V. berlandieri tends toward lower density, deeper systems. ||Root density is expressed as length per volume (cm cm⁻³) or mass per volume (g cm⁻³). ||Fine root proliferation capacity is a major component of root density.  This disposition represents a drought adaptation strategy based on thorough extraction of available water within the rooted soil volume, complementary to deep rooting which extends the accessible volume. ||High root density reduces the distance water must travel through soil to reach root surfaces, increases total absorptive surface area, and enables more complete extraction of soil water including water held at higher matric potential in smaller pores. ||Root density varies among rootstocks from less than 1 cm root length per cm³ soil to over 4 cm cm⁻³ in the most densely rooted zones, with substantial implications for soil water depletion patterns and drought response. ||Root_Density_Disposition may involve different balances between fine roots (high surface area for absorption but short-lived and metabolically costly) and coarser roots (lower absorption efficiency but greater longevity), affecting both water uptake capacity and carbon costs of root system maintenance. ||High root density can be advantageous for exploiting brief rainfall events that wet only surface soils, but may exhaust local soil water rapidly during extended drought if not combined with deep rooting accessing additional water reserves.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mapfumo E et al. (1994) Grapevine root distribution and water relations in a clay loam soil, Australian Journal of Grape and Wine Research 1:77-83|| Morlat R, Jacquet A (2003) Grapevine root system and soil characteristics in a vineyard maintained long-term with or without interrow sward, American Journal of Enology and Viticulture 54:1-7|| Bauerle TL et al. (2008) Root foraging in response to heterogeneous soil moisture in two grapevines that differ in potential growth rate, New Phytologist 179:857-866"
  },
  "Root_Hydraulic_Conductance_Disposition": {
    "definition": "A Root_Hydraulic_Conductance_Disposition is a Root_System_Drought_Adaptation_Disposition that inheres in a Vitis plant root system and is realized through high efficiency of water transport from soil through roots to the shoot system, minimizing the hydraulic resistance that limits water flow from soil to leaves.", 
    "alternative_term": "root water transport efficiency | root hydraulic capacity | root conductivity |+ Wurzel-Hydraulik-Leitfähigkeits-Disposition | Wurzel-Wassertransport-Effizienz | Wurzel-Leitfähigkeit",
    "example_of_usage": "Detailed hydraulic characterization of Root_Hydraulic_Conductance_Disposition at the University of Bordeaux measured whole-root-system hydraulic conductance (Lpr) across 12 rootstocks using high-pressure flow meter (HPFM) techniques on excavated root systems and pressurized root exudation methods in potted vines. ||Measurements were conducted under well-watered conditions and after 10 days of soil drying to assess conductance plasticity. ||Root_Hydraulic_Conductance_Disposition varied 3-fold among rootstocks under well-watered conditions. '1103 Paulsen' (V. berlandieri × V. rupestris) exhibited highest Lpr at 4.2 × 10⁻⁷ m³ s⁻¹ MPa⁻¹ per unit root surface area, while 'Riparia Gloire' showed lowest conductance at 1.4 × 10⁻⁷ m³ s⁻¹ MPa⁻¹. ||Following soil drying, conductance declined in all rootstocks, but the magnitude of decline differed. ||High-conductance '1103 Paulsen' showed 55% conductance reduction, while low-conductance 'Riparia Gloire' declined only 25%. ||Analysis of aquaporin gene expression (VvPIP1 and VvPIP2 families) revealed that '1103 Paulsen' down-regulated aquaporins more strongly under drought (3.5-fold reduction versus 1.8-fold in 'Riparia Gloire'), suggesting active conductance modulation. ||The functional significance was demonstrated by scion water status, with high-Lpr '1103 Paulsen'-grafted 'Cabernet Sauvignon' showing higher midday water potential under well-watered conditions (-0.9 versus -1.1 MPa for 'Riparia Gloire') but similar or lower potential under drought due to conductance plasticity. ||These findings reveal that Root_Hydraulic_Conductance_Disposition encompasses both maximum capacity and drought-induced modulation.",
    "editor_note": "Root_Hydraulic_Conductance_Disposition is_a Root_System_Drought_Adaptation_Disposition. ||Root hydraulic conductance determines water delivery efficiency to shoots. ||Conductance has radial (cortex pathway) and axial (xylem) components. ||Aquaporins are major regulators of radial conductance. ||Conductance declines under drought through aquaporin down-regulation and embolism, potentially contributing to drought signaling. ||High conductance is beneficial under adequate water supply but conductance plasticity may be adaptive under drought.  This disposition represents the transport efficiency component of root function, determining how effectively acquired soil water is delivered to above-ground tissues to support transpiration, growth, and stress responses. ||Root hydraulic conductance reflects the combined conductance of the radial pathway (soil to xylem across root cortex, endodermis, and stele) and the axial pathway (longitudinal flow through xylem vessels to the shoot). ||Radial conductance is influenced by aquaporin (water channel protein) expression and activity, suberization and Casparian strip development, and root anatomical features. ||Axial conductance depends on xylem vessel diameter, frequency, and connectivity. ||Root_Hydraulic_Conductance_Disposition is dynamic, with conductance declining under severe drought through aquaporin down-regulation (potentially an adaptive response reducing water loss to dry soil) and root embolism. ||High hydraulic conductance enables the root system to supply water to meet transpirational demand under well-watered conditions and moderate stress, while conductance modulation may contribute to whole-plant drought signaling by allowing root water potential to decline and trigger shoot responses.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Alsina MM et al. (2011) Seasonal changes of whole root system conductance by a drought-tolerant grape root system, Journal of Experimental Botany 62:99-109|| Vandeleur RK et al. (2009) The role of plasma membrane intrinsic protein aquaporins in water transport through roots: diurnal and drought stress responses reveal different strategies between isohydric and anisohydric cultivars of grapevine, Plant Physiology 149:445-460|| Lovisolo C et al. (2008) Whole-plant hydraulic conductance and root-to-shoot flow of abscisic acid are independently affected by water stress in grapevines, Functional Plant Biology 35:922-930"
  },
  "Hydraulic_Architecture_Disposition": {
    "definition": "A Hydraulic_Architecture_Disposition is a Drought_Tolerance_Disposition that inheres in the vascular system of a Vitis vinifera plant and is realized through the structural and functional properties of the water transport pathway that determine the efficiency of water movement from soil to leaves and the vulnerability of this pathway to drought-induced failure.", 
    "alternative_term": "xylem hydraulic properties | vascular water transport | hydraulic conductance architecture |+ Hydraulische-Architektur-Disposition | Xylem-Hydraulik | Vaskulärer-Wassertransport",
    "example_of_usage": "Comprehensive characterization of Hydraulic_Architecture_Disposition at INRAE Bordeaux quantified hydraulic parameters across 20 cultivars using bench dehydration vulnerability curves, native embolism assessment, and xylem anatomical analysis. ||Stem segments were dehydrated to a range of water potentials, then measured for percentage loss of hydraulic conductivity (PLC) to construct vulnerability curves, with P50 (water potential at 50% PLC) as the key safety parameter. ||Cultivar variation in Hydraulic_Architecture_Disposition was substantial. 'Grenache' exhibited a conservative hydraulic architecture with relatively low maximum conductivity (Kmax = 3.8 kg m⁻¹ MPa⁻¹ s⁻¹) but high cavitation resistance (P50 = -2.8 MPa), reflecting narrow mean vessel diameter (145 μm) and thick inter-vessel pit membranes. 'Syrah' showed contrasting properties with high Kmax (6.2 kg m⁻¹ MPa⁻¹ s⁻¹) but lower safety (P50 = -1.9 MPa), associated with larger vessels (185 μm mean diameter). ||The hydraulic safety margin (difference between minimum operating water potential and P50) was 1.4 MPa for 'Grenache' (Ψmin = -1.4 MPa, P50 = -2.8 MPa) versus only 0.3 MPa for 'Syrah' (Ψmin = -1.6 MPa, P50 = -1.9 MPa), explaining 'Syrah's vulnerability to hydraulic failure during severe drought. ||These Hydraulic_Architecture_Disposition differences directly related to isohydric-anisohydric classification, with conservative 'Grenache' maintaining larger safety margins through stomatal closure while 'Syrah' operated near its hydraulic limits to maintain gas exchange.",
    "editor_note": "Hydraulic_Architecture_Disposition is_a Drought_Tolerance_Disposition. ||Hydraulic architecture determines the efficiency-safety trade-off in xylem function. ||Child classes include Cavitation_Resistance_Disposition (P50, resistance to embolism), Embolism_Repair_Disposition (recovery capacity), and Vessel_Diameter_Disposition (anatomical basis of conductivity). ||Hydraulic safety margin (Ψmin - P50) determines vulnerability to drought-induced hydraulic failure. ||Hydraulic architecture underlies and helps explain isohydric versus anisohydric stomatal behavior strategies.  This disposition represents the xylem-centered component of drought tolerance, encompassing vessel dimensions and connectivity, resistance to cavitation (embolism formation under tension), and capacity to repair embolized vessels following stress relief. ||Hydraulic architecture reflects the fundamental trade-off in xylem design between transport efficiency (maximized by large, frequent vessels) and safety (enhanced by small vessels with strong pit membranes resistant to air-seeding). ||Grapevine is among the most efficient water conductors in the plant kingdom due to large vessel diameters (often exceeding 200 μm), but this efficiency creates vulnerability to cavitation under drought stress when xylem tensions exceed air-seeding thresholds. ||Hydraulic_Architecture_Disposition varies among cultivars and rootstocks in vessel dimensions, cavitation resistance (P50, the pressure causing 50% loss of conductivity), and embolism repair capacity, collectively determining the hydraulic safety margins that allow continued function versus the efficiency that supports high productivity. ||Understanding Hydraulic_Architecture_Disposition informs the matching of cultivar hydraulic properties to site water availability and the interpretation of isohydric versus anisohydric stomatal behavior as strategies maintaining hydraulic safety margins.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tyree MT, Ewers FW (1991) The hydraulic architecture of trees and other woody plants, New Phytologist 119:345-360|| Choat B et al. (2010) Measurement of vulnerability to water stress-induced cavitation in grapevine: a comparison of four techniques applied to a long-vesseled species, Plant Cell and Environment 33:1502-1512|| Brodribb TJ, Cochard H (2009) Hydraulic failure defines the recovery and point of death in water-stressed conifers, Plant Physiology 149:575-584"
  },
  "Cavitation_Resistance_Disposition": {
    "definition": "A Cavitation_Resistance_Disposition is a Hydraulic_Architecture_Disposition that inheres in the xylem of a Vitis vinifera plant and is realized through structural properties that resist the formation and spread of embolism (air bubbles blocking water transport) under the tension developed in xylem during drought.", 
    "alternative_term": "embolism resistance | xylem cavitation resistance | hydraulic safety |+ Kavitations-Resistenz-Disposition | Embolie-Resistenz | Hydraulische-Sicherheit",
    "example_of_usage": "Systematic determination of Cavitation_Resistance_Disposition at the University of Bordeaux employed the Cavitron centrifuge technique to generate vulnerability curves for 25 cultivars, providing high-throughput, standardized assessment of P50 values. ||Stem segments were subjected to increasing centrifugal tension while conductivity was monitored, enabling rapid construction of complete vulnerability curves. ||Cavitation_Resistance_Disposition showed significant cultivar variation spanning 1.3 MPa. ||Most resistant cultivars included 'Grenache' (P50 = -2.85 MPa), 'Mourvèdre' (P50 = -2.72 MPa), and 'Carignan' (P50 = -2.65 MPa), all Mediterranean cultivars presumably selected under drought pressure. ||Most vulnerable cultivars included 'Merlot' (P50 = -1.58 MPa), 'Pinot Noir' (P50 = -1.65 MPa), and 'Gamay' (P50 = -1.72 MPa), originating from cooler, more humid climates. ||Anatomical analysis revealed that P50 correlated strongly with pit membrane thickness (r = -0.78) and weakly with vessel diameter (r = 0.35), confirming pit membrane properties as the primary determinant of Cavitation_Resistance_Disposition. ||Field observations during the severe 2003 European drought validated laboratory rankings, with vulnerable 'Merlot' vines showing 45-60% PLC and visible canopy dieback while resistant 'Grenache' maintained PLC below 20% despite similar exposure. ||The relationship between Cavitation_Resistance_Disposition and stomatal behavior was confirmed, with cavitation-resistant cultivars operating closer to their P50 (narrower safety margins) enabled by tight stomatal control, while vulnerable cultivars maintained wider margins through earlier stomatal closure.",
    "editor_note": "Cavitation_Resistance_Disposition is_a Hydraulic_Architecture_Disposition. ||Cavitation resistance determines the water potential threshold for hydraulic failure. ||P50 (water potential at 50% conductivity loss) is the standard metric. ||Pit membrane properties (thickness, porosity) are primary determinants. ||Vessel diameter has secondary influence. ||Mediterranean-origin cultivars generally show greater resistance than cool-climate cultivars. ||Cavitation resistance interacts with stomatal behavior to determine hydraulic safety margins.  This disposition represents the safety component of xylem hydraulic function, determining the water potential threshold at which catastrophic loss of hydraulic conductivity occurs. ||Cavitation (the phase change from liquid water to water vapor) occurs when xylem tension exceeds the capacity of water columns to withstand negative pressure, typically initiated by air-seeding through porous pit membranes connecting adjacent vessels. ||Resistance to cavitation depends primarily on pit membrane properties (thickness, porosity, flexibility) that determine the air-seeding pressure threshold, with thicker, less porous membranes providing greater resistance. ||Secondary factors include vessel diameter (larger vessels contain more water under tension and may have more vulnerable pit connections), vessel length (longer vessels have more pit area for potential air entry), and inter-vessel connectivity. ||Cavitation_Resistance_Disposition is quantified by vulnerability curves relating xylem water potential to percentage loss of conductivity (PLC), with P50 (water potential at 50% PLC) as the standard metric. ||Grapevine P50 values typically range from -1.5 to -3.0 MPa depending on genotype, with more negative values indicating greater cavitation resistance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Choat B et al. (2010) Measurement of vulnerability to water stress-induced cavitation in grapevine: a comparison of four techniques applied to a long-vesseled species, Plant Cell and Environment 33:1502-1512|| Tyree MT, Sperry JS (1989) Vulnerability of xylem to cavitation and embolism, Annual Review of Plant Physiology and Plant Molecular Biology 40:19-38|| Brodersen CR et al. (2010) The dynamics of embolism repair in xylem: in vivo visualizations using high-resolution computed tomography, Plant Physiology 154:1088-1095"
  },
  "Embolism_Repair_Disposition": {
    "definition": "An Embolism_Repair_Disposition is a Hydraulic_Architecture_Disposition that inheres in a Vitis vinifera plant and is realized through physiological mechanisms that restore hydraulic conductivity in embolized xylem vessels, either by refilling cavitated vessels with water or by growing new functional xylem to bypass blocked conduits.", 
    "alternative_term": "xylem recovery | embolism reversal | hydraulic restoration |+ Embolie-Reparatur-Disposition | Xylem-Wiederherstellung | Hydraulische-Erholung",
    "example_of_usage": "Investigation of Embolism_Repair_Disposition at UC Davis employed X-ray computed microtomography (microCT) to visualize embolism formation and potential refilling in living grapevine stems across 8 cultivars. ||Potted vines were droughted to induce 50-70% PLC, then rewatered, with microCT imaging at daily intervals tracking the status of individual vessels (water-filled versus air-filled). ||Embolism_Repair_Disposition showed substantial variation among cultivars. 'Chardonnay' exhibited rapid repair with 75% of embolized vessels refilling within 7 days of rewatering, coinciding with sustained positive xylem pressure (up to +0.08 MPa) measured at night, suggesting root pressure-driven refilling. 'Cabernet Sauvignon' showed slower, less complete repair (45% refilling at 7 days) with weaker root pressure development (+0.02 MPa). ||Interestingly, repair was vessel-size dependent, with narrow vessels (< 100 μm diameter) refilling preferentially over wide vessels (> 200 μm), consistent with the physics of dissolving air bubbles under positive pressure. ||Season also affected Embolism_Repair_Disposition, with spring drought events showing more complete recovery (85% vessel refilling) than late-season drought (55% refilling), potentially reflecting root starch reserves available for osmotic work and/or active vessel development in spring. ||Cumulative effects were documented over 3 seasons of repeated drought cycles, with vines experiencing chronic stress showing progressive decline in maximum conductivity (15% reduction from year 1 to year 3), indicating that Embolism_Repair_Disposition has limits and severe repeated stress causes lasting hydraulic damage.",
    "editor_note": "Embolism_Repair_Disposition is_a Hydraulic_Architecture_Disposition. ||Embolism repair restores conductivity after cavitation through vessel refilling and/or new xylem growth. ||Root pressure is implicated in refilling, operating at night or after rewetting. ||Narrow vessels refill more readily than wide vessels. ||Repair capacity varies among genotypes and with season. ||Repeated severe cavitation can exceed repair capacity, causing cumulative hydraulic damage. ||The mechanisms and extent of embolism repair remain active research areas.  This disposition represents the recovery component of hydraulic function, determining how effectively vines can restore water transport capacity following drought-induced cavitation and whether hydraulic damage has persistent effects on vine function. ||Embolism repair mechanisms remain debated but may include root pressure-driven refilling (positive xylem pressure generated in roots dissolving gas and forcing water into embolized vessels, typically occurring at night or following rewetting), osmotic refilling (localized solute secretion lowering water potential and drawing water into embolized vessels from adjacent living cells), and new xylem production (vessel formation bypassing irreparably blocked conduits). ||The relative importance of these mechanisms likely varies with species, timing, and drought severity, with root pressure potentially effective for moderate embolism while severe damage may require new vessel development. ||Embolism_Repair_Disposition in grapevine appears substantial, as vines commonly recover from significant conductivity loss following rewetting, but repair capacity has limits and repeated severe cavitation may cause cumulative hydraulic damage reducing vine productivity over time.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Brodersen CR et al. (2010) The dynamics of embolism repair in xylem: in vivo visualizations using high-resolution computed tomography, Plant Physiology 154:1088-1095|| Sperry JS et al. (1987) Spring filling of xylem vessels in wild grapevine, Plant Physiology 83:414-417|| Zwieniecki MA, Holbrook NM (2009) Confronting Maxwell's demon: biophysics of xylem embolism repair, Trends in Plant Science 14:530-534"
  },
  "Vessel_Diameter_Disposition": {
    "definition": "A Vessel_Diameter_Disposition is a Hydraulic_Architecture_Disposition that inheres in the xylem of a Vitis vinifera plant and is realized through the anatomical dimensions of xylem vessels, determining the trade-off between hydraulic conductance efficiency (favored by large vessels) and hydraulic safety (enhanced by small vessels).", 
    "alternative_term": "vessel size | xylem conduit diameter | vascular anatomy |+ Gefäßdurchmesser-Disposition | Xylem-Gefäßgröße | Vaskuläre-Anatomie",
    "example_of_usage": "Anatomical characterization of Vessel_Diameter_Disposition at Stellenbosch University employed microscopic analysis of transverse stem sections across 15 cultivars to quantify vessel diameter distributions and relate anatomy to hydraulic function. ||Sections from standardized positions on current-year shoots were stained and imaged, with vessel diameters measured for 200+ vessels per cultivar. ||Additionally, theoretical conductivity (Kth) was calculated from vessel dimensions assuming Hagen-Poiseuille flow. ||Vessel_Diameter_Disposition showed significant cultivar variation. 'Shiraz' produced the widest vessels with mean diameter of 165 μm, maximum 285 μm, and high calculated Kth of 45 kg m⁻¹ MPa⁻¹ s⁻¹. 'Pinot Noir' showed intermediate dimensions (mean 138 μm, max 225 μm, Kth 28). 'Grenache' exhibited the narrowest vessels (mean 118 μm, max 195 μm, Kth 18) among major cultivars. ||Vessel frequency showed inverse pattern, with narrow-vesseled 'Grenache' compensating somewhat through higher vessel density (125 vessels mm⁻² versus 85 for 'Shiraz'). ||The efficiency-safety trade-off was confirmed by correlation between mean vessel diameter and P50 (r = 0.62), with large-vesseled cultivars showing lower cavitation resistance. ||Environmental plasticity was demonstrated by comparing irrigated versus deficit-irrigated vines of 'Cabernet Sauvignon', with water deficit during shoot development reducing mean vessel diameter by 18% (142 versus 173 μm) and improving P50 by 0.4 MPa, representing acclimatory adjustment of Vessel_Diameter_Disposition enhancing hydraulic safety at the cost of transport efficiency.",
    "editor_note": "Vessel_Diameter_Disposition is_a Hydraulic_Architecture_Disposition. ||Vessel diameter is the primary anatomical determinant of xylem conductance (scales with radius⁴). ||Grapevine produces exceptionally large vessels enabling high transport capacity but creating cavitation vulnerability. ||Vessel diameter varies among genotypes and shows environmental plasticity. ||Narrow vessels provide safety but reduce conductance|| plants often compensate through vessel frequency. ||The efficiency-safety trade-off in vessel dimensions underlies the broader Hydraulic_Architecture_Disposition.  This disposition represents the anatomical foundation of xylem hydraulic properties, as vessel diameter has powerful effects on both water transport capacity (conductance scales with the fourth power of radius according to the Hagen-Poiseuille equation) and vulnerability to dysfunction (larger vessels tend to be more susceptible to cavitation and embolism spread). ||Grapevine is notable for producing exceptionally large vessels among woody plants, with maximum vessel diameters commonly exceeding 200 μm and sometimes reaching 400 μm in vigorous shoots, enabling the high transpiration rates that support rapid growth but creating inherent vulnerability to hydraulic failure. ||Vessel_Diameter_Disposition varies among cultivars and rootstocks, with genotypes producing larger vessels showing higher conductance under adequate water supply but potentially greater vulnerability to drought-induced conductivity loss. ||Vessel diameter is also plastic, with environmental factors including water availability during wood formation, temperature, and vigor affecting vessel dimensions, such that drought conditions during xylogenesis typically produce narrower, more numerous vessels than well-watered conditions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tyree MT, Zimmermann MH (2002) Xylem Structure and the Ascent of Sap, 2nd Edition, Springer-Verlag, Berlin|| Lovisolo C, Schubert A (1998) Effects of water stress on vessel size and xylem hydraulic conductivity in Vitis vinifera L., Journal of Experimental Botany 49:693-700|| Hochberg U et al. (2017) Grapevine petioles are more sensitive to drought induced embolism than stems: evidence from in vivo MRI and microCT observations of hydraulic vulnerability segmentation, Plant Cell and Environment 40:1831-1842"
  },
  "Intrinsic_WUE_Disposition": {
    "definition": "An Intrinsic_WUE_Disposition is a Water_Use_Efficiency_Disposition that inheres in a Vitis vinifera plant and is realized through the ratio of net photosynthetic rate (A) to stomatal conductance (gs), representing the leaf-level efficiency of carbon fixation relative to stomatal aperture independent of atmospheric evaporative demand.", 
    "alternative_term": "photosynthetic water use efficiency | A/gs ratio | stomatal-normalized carbon gain |+ Intrinsische-WUE-Disposition | Photosynthetische-Wassereffizienz | A/gs-Verhältnis",
    "example_of_usage": "Detailed physiological characterization of Intrinsic_WUE_Disposition at the University of the Balearic Islands analyzed the components underlying A/gs variation across 18 cultivars using gas exchange, chlorophyll fluorescence, and carbon isotope analysis. ||Simultaneous measurement of A, gs, and Ci enabled calculation of intrinsic WUE (A/gs) and partitioning of photosynthetic limitations into stomatal, mesophyll, and biochemical components. ||Intrinsic_WUE_Disposition ranged from 52 μmol mol⁻¹ ('Syrah', lowest) to 98 μmol mol⁻¹ ('Grenache', highest) under moderate water stress (-1.0 MPa predawn water potential). ||Analysis of component limitations revealed distinct mechanisms underlying high A/gs. 'Grenache' achieved high Intrinsic_WUE_Disposition primarily through sensitive stomatal closure (gs = 85 mmol m⁻² s⁻¹) while maintaining moderate A (7.2 μmol m⁻² s⁻¹) through high mesophyll conductance (gm = 125 mmol m⁻² s⁻¹) compensating for reduced CO₂ supply. 'Tempranillo' showed similarly high A/gs (92 μmol mol⁻¹) but achieved through different mechanism, with moderate gs (120 mmol m⁻² s⁻¹) and exceptionally high gm (185 mmol m⁻² s⁻¹) enabling high A (11.0 μmol m⁻² s⁻¹). ||Carbon isotope analysis confirmed that Δ¹³C correlated strongly with measured A/gs (r = -0.85), with low-Δ¹³C cultivars showing consistently high Intrinsic_WUE_Disposition across measurement dates. ||These findings demonstrate that equivalent Intrinsic_WUE_Disposition can arise through distinct physiological mechanisms with different implications for productivity and stress tolerance.",
    "editor_note": "Intrinsic_WUE_Disposition is_a Water_Use_Efficiency_Disposition. ||Intrinsic WUE (A/gs) removes the effect of atmospheric demand (VPD) that influences transpiration, isolating the physiological efficiency of the leaf. ||High A/gs can result from stomatal limitation (low gs) and/or enhanced CO₂ utilization (high gm, high carboxylation). Δ¹³C provides integrated assessment of intrinsic WUE suitable for screening. ||Mesophyll conductance (gm) is an important but often overlooked determinant of intrinsic WUE. ||Cultivars may achieve similar A/gs through different mechanistic pathways.  This disposition represents the physiologically intrinsic component of water use efficiency, removing the confounding effect of vapor pressure deficit (VPD) that influences transpiration rate at any given stomatal aperture. ||Intrinsic WUE (A/gs, expressed in μmol CO₂ mol⁻¹ H₂O) reflects the coordination between photosynthetic capacity and stomatal regulation, with high values indicating that carbon assimilation is maintained effectively relative to stomatal opening. ||Genotypic variation in Intrinsic_WUE_Disposition arises from differences in mesophyll conductance (gm, the conductance for CO₂ diffusion from substomatal cavity to chloroplasts), Rubisco carboxylation efficiency, and the sensitivity of photosynthesis versus stomata to environmental factors. ||Cultivars with high intrinsic WUE achieve relatively high photosynthetic rates at lower stomatal conductance, either through enhanced mesophyll conductance enabling efficient CO₂ delivery to chloroplasts or through high carboxylation capacity enabling rapid CO₂ fixation at lower intercellular CO₂ concentrations. ||Carbon isotope discrimination (Δ¹³C) provides an integrated measure of intrinsic WUE over time, as ¹³C discrimination during photosynthesis is inversely related to the ratio of intercellular to ambient CO₂ concentration (Ci/Ca), which in turn reflects the balance between stomatal supply and photosynthetic demand for CO₂.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Flexas J et al. (2010) Mesophyll conductance to CO2: current knowledge and future prospects, Plant Cell and Environment 33:1123-1146|| Tomás M et al. (2014) Variability of mesophyll conductance in grapevine cultivars under water stress conditions in relation to leaf anatomy and water use efficiency, Australian Journal of Grape and Wine Research 20:272-280|| Farquhar GD et al. (1989) Carbon isotope discrimination and photosynthesis, Annual Review of Plant Physiology and Plant Molecular Biology 40:503-537"
  },
  "Instantaneous_WUE_Disposition": {
    "definition": "An Instantaneous_WUE_Disposition is a Water_Use_Efficiency_Disposition that inheres in a Vitis vinifera plant and is realized through the ratio of net photosynthetic rate (A) to transpiration rate (E), representing the actual carbon gain achieved per unit water lost under prevailing environmental conditions at the moment of measurement.", 
    "alternative_term": "actual water use efficiency | A/E ratio | transpiration-based carbon efficiency |+ Momentane-WUE-Disposition | Aktuelle-Wassereffizienz | A/E-Verhältnis",
    "example_of_usage": "Diurnal investigation of Instantaneous_WUE_Disposition at UC Davis compared A/E dynamics across 12 cultivars under contrasting atmospheric conditions (cool marine day with peak VPD 2.0 kPa versus hot interior day with VPD 4.5 kPa). ||Gas exchange measurements were conducted at 2-hour intervals from 06:00 to 18:00, enabling assessment of diurnal A/E patterns and cultivar × environment interactions. ||Instantaneous_WUE_Disposition showed strong diurnal and environmental variation. ||On the cool day, 'Chardonnay' achieved peak A/E of 4.8 μmol mmol⁻¹ at 08:00 (low VPD), declining to 2.2 μmol mmol⁻¹ by 14:00 (moderate VPD), with daily mean of 3.1 μmol mmol⁻¹. ||On the hot day, 'Chardonnay' peak A/E was only 3.5 μmol mmol⁻¹ at 08:00, declining to 1.2 μmol mmol⁻¹ by 14:00 (high VPD), with daily mean of 2.0 μmol mmol⁻¹. ||Cultivar differences in Instantaneous_WUE_Disposition were environment-dependent. 'Grenache' showed smaller diurnal and environmental variation (cool day mean 3.4, hot day mean 2.8 μmol mmol⁻¹) due to stomatal closure maintaining relatively constant Ci/Ca ratio across conditions. 'Syrah' showed larger variation (cool 2.9, hot 1.6 μmol mmol⁻¹) as sustained stomatal opening exposed A/E to full VPD effects. ||However, daily integrated carbon gain was higher in 'Syrah' (22 versus 18 mol CO₂ m⁻² d⁻¹ on the hot day) despite lower instantaneous efficiency, illustrating the trade-off between efficiency and productivity in Instantaneous_WUE_Disposition.",
    "editor_note": "Instantaneous_WUE_Disposition is_a Water_Use_Efficiency_Disposition. ||Instantaneous WUE (A/E) represents actual efficiency under prevailing conditions, incorporating VPD effects that influence transpiration rate. ||A/E varies diurnally and seasonally with environmental conditions. ||High A/E does not guarantee high productivity, as severe stomatal closure reduces both water loss and carbon gain. ||The relationship between instantaneous efficiency and cumulative productivity depends on integration over time. ||A/E is relevant for irrigation scheduling decisions where water application is timed to periods of high efficiency.  This disposition represents the operationally relevant water use efficiency experienced by the plant, incorporating both physiological factors (stomatal conductance, photosynthetic capacity) and environmental factors (vapor pressure deficit, temperature, light intensity) that determine the actual rates of CO₂ uptake and water loss. ||Instantaneous WUE (A/E, expressed in μmol CO₂ mmol⁻¹ H₂O) varies throughout the day and across environments as VPD fluctuates, typically declining from morning (low VPD, high A/E) to midday (high VPD, low A/E) even when stomatal aperture remains constant. ||Genotypic variation in Instantaneous_WUE_Disposition reflects both intrinsic physiological differences (as captured by A/gs) and differences in the response to varying VPD, with some cultivars maintaining higher A/E under high evaporative demand than others at equivalent intrinsic efficiency. ||The relationship between instantaneous WUE and productivity is complex, as very high A/E may result from severely restricted gas exchange limiting both water loss and carbon gain, while moderate A/E with sustained gas exchange may accumulate more total carbon despite lower efficiency per unit water.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Medrano H et al. (2015) From leaf to whole-plant water use efficiency (WUE) in complex canopies: limitations of leaf WUE as a selection target, Crop Journal 3:220-228|| Schultz HR, Matthews MA (1993) Growth, osmotic adjustment, and cell-wall mechanics of expanding grape leaves during water deficits, Crop Science 33:287-294|| Chaves MM et al. (2010) Grapevine under deficit irrigation: hints from physiological and molecular data, Annals of Botany 105:661-676"
  },
  "Drought_Recovery_Disposition": {
    "definition": "A Drought_Recovery_Disposition is a Drought_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through physiological mechanisms that enable rapid restoration of normal function following relief of water stress, encompassing rehydration of tissues, repair of drought-induced damage, and resumption of growth and productive processes.", 
    "alternative_term": "post-drought restoration | stress recovery capacity | rewatering response |+ Trockenheitserholungs-Disposition | Post-Stress-Wiederherstellung | Wiederbewässerungs-Antwort",
    "example_of_usage": "Systematic evaluation of Drought_Recovery_Disposition at INRAE Bordeaux imposed standardized drought stress (predawn water potential of -1.0 MPa for 14 days) followed by rewatering on 20 cultivars, with recovery tracked over 21 days through measurements of water potential, stomatal conductance, photosynthesis, stem hydraulic conductivity, and shoot growth. ||Recovery was quantified as percentage of pre-stress function restored at each timepoint. ||Drought_Recovery_Disposition varied substantially among cultivars. 'Grenache' (isohydric) showed rapid, complete recovery with predawn water potential restored within 24 hours, stomatal conductance reaching 90% of pre-stress levels by day 3, and photosynthesis fully recovered by day 5, with no persistent hydraulic damage (PLC < 5% throughout). 'Syrah' (anisohydric) displayed slower, less complete recovery with water potential restored by 48 hours, but stomatal conductance reaching only 75% by day 7 and photosynthesis 80% by day 14, associated with 25% PLC requiring gradual embolism repair. 'Merlot' showed intermediate recovery but with persistent effects, achieving 85% stomatal recovery by day 7 but maintaining elevated ABA levels suggesting continued stress memory. ||Growth resumption analysis revealed that shoot elongation recommenced within 5 days in 'Grenache' versus 12 days in 'Syrah', with cumulative 21-day recovery growth 40% higher in 'Grenache'. ||These findings demonstrate that Drought_Recovery_Disposition reflects the integration of multiple recovery processes with different kinetics and potential for incomplete restoration.",
    "editor_note": "Drought_Recovery_Disposition is_a Drought_Tolerance_Disposition. ||Recovery encompasses multiple processes at different timescales, from rapid stomatal reopening to slow hydraulic repair. ||Child classes include Rehydration_Capacity_Disposition (tissue water restoration) and Growth_Resumption_Disposition (developmental recovery). ||Recovery completeness depends on drought severity and duration as well as genotype. ||Isohydric cultivars typically show faster, more complete recovery due to less hydraulic damage during stress. ||Incomplete recovery can have persistent effects on current and subsequent season productivity.  This disposition represents the restorative component of drought adaptation, determining how quickly and completely vines return to pre-stress function after water availability improves through rainfall, irrigation, or reduced evaporative demand. ||Drought recovery involves multiple processes operating at different timescales, from rapid stomatal reopening (minutes to hours), through tissue rehydration and turgor restoration (hours to days), repair of cavitation damage and cellular injury (days to weeks), and growth resumption and reserve replenishment (weeks to months). ||The completeness and speed of recovery depend on drought severity and duration (more severe stress causing more damage requiring more recovery time), cultivar physiology (stomatal behavior, hydraulic properties, cellular protection mechanisms), and environmental conditions during recovery (temperature, light, water availability). ||Drought_Recovery_Disposition is economically important because incomplete recovery can reduce productivity in the current season (delayed canopy development, reduced fruit quality) and subsequent seasons (depleted reserves, persistent hydraulic damage), making recovery capacity a key component of sustainable viticulture in drought-prone regions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Flexas J et al. (2006) Drought-inhibition of photosynthesis in C3 plants: stomatal and non-stomatal limitations revisited, Annals of Botany 98:871-892|| Galmes J et al. (2007) Water relations and stomatal characteristics of Mediterranean plants with different growth forms and leaf habits: responses to water stress and recovery, Plant and Soil 290:139-155|| Pou A et al. (2012) Anisohydric behaviour in grapevines results in better performance under moderate water stress and recovery than isohydric behaviour, Plant and Soil 359:335-349"
  },
  "Rehydration_Capacity_Disposition": {
    "definition": "A Rehydration_Capacity_Disposition is a Drought_Recovery_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to rapidly restore tissue water content and turgor pressure following relief of water stress, re-establishing the cellular hydration necessary for normal metabolic function and growth.", 
    "alternative_term": "tissue water restoration | post-stress rehydration | water status recovery |+ Rehydrierungs-Kapazität-Disposition | Gewebe-Wasserwiederherstellung | Post-Stress-Rehydrierung",
    "example_of_usage": "Kinetic analysis of Rehydration_Capacity_Disposition at Stellenbosch University tracked tissue water status recovery at high temporal resolution (hourly measurements for 72 hours post-rewatering) across 15 cultivars following standardized drought stress. ||Measurements included predawn and midday leaf water potential, leaf relative water content (RWC), stem water content, and root hydraulic conductance. ||Rehydration_Capacity_Disposition showed marked cultivar variation. 'Chenin Blanc' exhibited rapid rehydration with predawn water potential rising from -0.9 MPa to -0.25 MPa within 8 hours of rewatering, leaf RWC increasing from 72% to 92% by 12 hours, and complete water status restoration by 24 hours. ||Root hydraulic conductance recovered to 95% of pre-stress values by 24 hours, indicating minimal root damage during stress. 'Pinotage' showed slower Rehydration_Capacity_Disposition with predawn potential reaching only -0.45 MPa at 24 hours, RWC at 84%, and incomplete restoration even at 72 hours (predawn -0.32 MPa versus pre-stress -0.18 MPa). ||Root conductance in 'Pinotage' remained depressed at 65% of pre-stress, suggesting persistent root damage or dysfunction. ||Analysis of rehydration kinetics revealed that initial recovery rate (0-8 hours) was primarily determined by root hydraulic conductance (r = 0.78), while asymptotic recovery level depended on xylem embolism status (r = -0.72 with PLC). 'Syrah' showed an interesting pattern of rapid initial rehydration (high root conductance) but incomplete final recovery (significant xylem embolism), demonstrating that Rehydration_Capacity_Disposition has distinct kinetic components.",
    "editor_note": "Rehydration_Capacity_Disposition is_a Drought_Recovery_Disposition. ||Rehydration is the hydraulic foundation of drought recovery, restoring tissue water content and turgor. ||Recovery rate depends on root function and xylem conductance, while recovery completeness reflects damage extent. ||Rapid rehydration enables fast restoration of stomatal function and photosynthesis. ||Incomplete rehydration indicates persistent hydraulic damage. ||Water potential recovery (easily measured) may precede full RWC recovery due to osmotic adjustment effects.  This disposition represents the hydraulic component of drought recovery, determining how quickly water status is restored when soil water becomes available. ||Rehydration involves water uptake through roots, transport through the xylem to shoots and leaves, and equilibration of tissue water content with xylem water potential. ||The speed and completeness of rehydration depend on root system function (water uptake capacity, root-soil contact integrity), xylem hydraulic conductance (potentially compromised by drought-induced embolism), and tissue properties (cell wall elasticity affecting turgor restoration, osmotic adjustment requiring solute dilution or export). ||Cultivars differ in Rehydration_Capacity_Disposition based on root system properties, hydraulic architecture, and the extent of drought-induced damage requiring repair. ||Rapid rehydration enables quick restoration of stomatal function, photosynthesis, and growth, minimizing the productivity penalty of drought episodes, while slow or incomplete rehydration prolongs recovery and may indicate persistent damage to root or vascular systems.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Galmes J et al. (2007) Water relations and stomatal characteristics of Mediterranean plants with different growth forms and leaf habits: responses to water stress and recovery, Plant and Soil 290:139-155|| Lovisolo C et al. (2008) Whole-plant hydraulic conductance and root-to-shoot flow of abscisic acid are independently affected by water stress in grapevines, Functional Plant Biology 35:922-930|| Pou A et al. (2012) Anisohydric behaviour in grapevines results in better performance under moderate water stress and recovery than isohydric behaviour, Plant and Soil 359:335-349"
  },
  "Growth_Resumption_Disposition": {
    "definition": "A Growth_Resumption_Disposition is a Drought_Recovery_Disposition that inheres in a Vitis vinifera plant and is realized through the capacity to rapidly reinitiate shoot elongation, leaf expansion, and developmental processes following relief of water stress, restoring the growth trajectory interrupted by drought.", 
    "alternative_term": "post-drought growth restart | developmental recovery | growth reactivation |+ Wachstumswiederaufnahme-Disposition | Post-Stress-Wachstumsstart | Entwicklungs-Wiederherstellung",
    "example_of_usage": "Detailed tracking of Growth_Resumption_Disposition at Cornell University monitored shoot elongation, leaf emergence, and lateral shoot development following relief of a 21-day drought stress across 18 cultivars. ||Daily measurements of primary shoot length, leaf number, and lateral bud activation were recorded for 28 days post-rewatering, enabling characterization of growth resumption kinetics. ||Growth_Resumption_Disposition varied substantially among cultivars. 'Cayuga White' (cold-hardy hybrid) showed rapid resumption with shoot elongation detectable within 4 days of rewatering, reaching elongation rate of 2.8 cm day⁻¹ by day 10 (exceeding pre-stress rate of 2.4 cm day⁻¹), and new leaf emergence beginning day 6. 'Cabernet Franc' displayed delayed Growth_Resumption_Disposition with elongation not detectable until day 9, reaching only 1.5 cm day⁻¹ by day 14 (60% of pre-stress), and new leaf emergence delayed until day 12. ||Analysis of growth components revealed that resumption timing correlated strongly with pre-stress carbohydrate reserves in shoot and root tissues (r = 0.72), as stressed vines with depleted starch showed delayed regrowth. ||Hormonal analysis showed that rapid-resuming 'Cayuga White' achieved pre-stress cytokinin/ABA ratios by day 5, while slow-resuming 'Cabernet Franc' maintained elevated ABA until day 12. ||Meristem viability assessment revealed that severe-stress treatments (predawn -1.2 MPa) killed 15% of 'Cabernet Franc' shoot apical meristems versus 0% in 'Cayuga White', indicating that Growth_Resumption_Disposition involves both meristem stress tolerance and metabolic recovery capacity.",
    "editor_note": "Growth_Resumption_Disposition is_a Drought_Recovery_Disposition. ||Growth resumption requires restoration of meristematic activity, carbohydrate supply, and growth-promoting hormonal balance. ||Resumption timing reflects both stress damage extent and recovery capacity. ||Carbohydrate reserves and meristem viability are key determinants. ||Delayed growth resumption reduces seasonal productivity and may compromise fruit development. ||Growth resumption can be measured by shoot elongation rate, leaf emergence, and lateral activation.  This disposition represents the developmental component of drought recovery, determining how quickly productive growth resumes after the immediate physiological crisis of dehydration is resolved. ||Growth resumption requires not only restored water status but also reactivation of meristematic activity, remobilization of carbohydrate reserves, resumption of cell division and expansion, and restoration of hormonal balances favoring growth over stress responses. ||The timing and vigor of growth resumption depend on the extent of meristem damage during stress (severe dehydration can injure or kill shoot apical and lateral meristems), carbohydrate reserve status (stressed vines may have depleted reserves limiting growth fuel), and the speed of transitioning from stress-protective to growth-promoting hormonal states (particularly declining ABA and increasing cytokinins and gibberellins). ||Growth_Resumption_Disposition is economically important because delayed regrowth reduces canopy development, shortens the effective growing season, and may compromise fruit development and ripening, particularly when drought occurs during critical phenological stages.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Flexas J et al. (2006) Drought-inhibition of photosynthesis in C3 plants: stomatal and non-stomatal limitations revisited, Annals of Botany 98:871-892|| Chaves MM et al. (2003) Understanding plant responses to drought—from genes to the whole plant, Functional Plant Biology 30:239-264|| Patakas A et al. (2002) Leaf age effects on solute accumulation in water-stressed grapevines, Journal of Plant Physiology 159:969-976"
  },
  "Salt_Tolerance_Disposition": {
    "definition": "A Salt_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that enable maintenance of growth, cellular function, and productivity under elevated soil salinity conditions that would otherwise cause ion toxicity, osmotic stress, and nutritional imbalances.", 
    "alternative_term": "salinity tolerance | salt stress resistance | halotolerance |+ Salztoleranz-Disposition | Salinität-Toleranz | Salzstress-Resistenz",
    "example_of_usage": "Comprehensive evaluation of Salt_Tolerance_Disposition at CSIRO Adelaide assessed growth, ion accumulation, and physiological responses across 20 rootstocks irrigated with saline water (ECw 0, 2, 4, 6 dS/m) over two growing seasons. ||Measurements included shoot growth, leaf chloride and sodium concentrations, leaf necrosis severity, chlorophyll fluorescence, and yield components. ||Salt_Tolerance_Disposition varied dramatically among rootstocks. '140 Ruggeri' (V. berlandieri × V. rupestris) exhibited exceptional tolerance, maintaining 85% of control growth at ECw 4 dS/m, restricting leaf chloride to 15 mmol/kg DW and sodium to 8 mmol/kg DW (versus external concentrations of 40 and 25 mM respectively), and showing no leaf necrosis. 'K51-40' (V. champinii selection) showed similar tolerance through effective ion exclusion. ||In contrast, 'Schwarzmann' (V. riparia × V. rupestris) displayed high salt sensitivity with growth reduced to 35% of control at ECw 4 dS/m, leaf chloride accumulating to 450 mmol/kg DW and sodium to 85 mmol/kg DW, and severe marginal necrosis affecting 60% of leaf area. ||Analysis of tolerance mechanisms revealed that ion exclusion capacity (particularly chloride exclusion) was the primary determinant of Salt_Tolerance_Disposition (r = -0.89 between leaf Cl⁻ and relative growth), with osmotic adjustment contributing secondarily. ||These findings demonstrate that rootstock selection based on Salt_Tolerance_Disposition enables productive viticulture on sites with moderate salinity that would be unsuitable with sensitive rootstocks.",
    "editor_note": "Salt_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||Salt tolerance in grapevine is primarily determined by rootstock genotype in grafted vines. ||The major tolerance mechanism is ion exclusion, particularly of chloride, addressed through child class Ion_Exclusion_Disposition. ||Grapevine is more sensitive to chloride than sodium toxicity, distinguishing it from many other crops. ||Salt tolerance involves both osmotic and ionic components, with ion toxicity typically dominating at moderate salinity levels encountered in viticulture. ||Rootstocks with V. berlandieri, V. rupestris, and V. champinii parentage generally show superior salt tolerance.  This disposition represents the capacity to tolerate salt stress, increasingly important as vineyard expansion into marginal lands, irrigation with saline water, and climate-driven salinization affect viticultural regions worldwide. ||Salt stress in grapevine causes injury through multiple pathways including osmotic effects (reduced water uptake due to low soil water potential), ion toxicity (accumulation of sodium and chloride to damaging concentrations in leaves), and nutritional disruption (interference with uptake of essential nutrients, particularly potassium and calcium). ||Grapevine is classified as moderately salt-sensitive, with yield reductions typically beginning at soil electrical conductivity (ECe) of 1.5-2.5 dS/m and severe damage above 4 dS/m, though substantial genotypic variation exists. ||Salt tolerance mechanisms encompass ion exclusion (preventing toxic ion uptake and translocation to shoots), ion compartmentalization (sequestering accumulated ions in vacuoles or less sensitive tissues), osmotic adjustment (accumulating compatible solutes to maintain water uptake), and tissue tolerance (cellular mechanisms enabling function despite elevated ion concentrations). ||In grafted grapevines, Salt_Tolerance_Disposition is primarily determined by rootstock genotype, making rootstock selection the primary management tool for saline sites.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Walker RR et al. (2002) Rootstock effects on salt tolerance of irrigated field-grown grapevines, Australian Journal of Grape and Wine Research 8:146-155|| Munns R, Tester M (2008) Mechanisms of salinity tolerance, Annual Review of Plant Biology 59:651-681|| Fisarakis I et al. (2001) The effect of salinity on the growth, yield and quality of Vitis vinifera L. cv. Sultanina, Journal of Horticultural Science and Biotechnology 76:750-756"
  },
  "Ion_Exclusion_Disposition": {
    "definition": "An Ion_Exclusion_Disposition is a Salt_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that prevent or limit the uptake of toxic ions (primarily chloride and sodium) from saline soil and their translocation to sensitive shoot tissues, maintaining low ion concentrations in leaves despite elevated external salinity.", 
    "alternative_term": "salt exclusion | ion restriction | toxic ion avoidance |+ Ionenausschluss-Disposition | Salzausschluss | Toxische-Ionen-Vermeidung",
    "example_of_usage": "Systematic characterization of Ion_Exclusion_Disposition at INRA Montpellier employed detailed ion profiling across the soil-root-shoot pathway in 15 rootstocks under controlled salinity (50 mM NaCl). ||Root, stem xylem sap, petiole, and leaf lamina concentrations of chloride, sodium, potassium, and calcium were measured to locate exclusion barriers and quantify exclusion efficiency. ||Ion_Exclusion_Disposition showed strong rootstock variation with distinct exclusion patterns. '140 Ruggeri' demonstrated exceptional exclusion at multiple sites, with root chloride concentration of 85 mM (versus 50 mM external), xylem sap chloride of only 2.5 mM (indicating strong xylem loading restriction), and leaf lamina chloride of 18 mmol/kg DW. ||The exclusion factor (external/leaf concentration ratio) was 48 for chloride. '1103 Paulsen' showed similarly strong chloride exclusion (exclusion factor 42) but weaker sodium exclusion (factor 15), resulting in moderate sodium accumulation (45 mmol/kg DW) despite low chloride. 'Riparia Gloire' exhibited poor Ion_Exclusion_Disposition with minimal restriction at any site, showing xylem sap chloride of 28 mM and leaf chloride of 380 mmol/kg DW (exclusion factor only 2.3). ||Correlation analysis confirmed that chloride exclusion was the dominant determinant of overall salt tolerance (r = 0.92 with growth maintenance), while sodium exclusion contributed independently but less strongly (r = 0.65). ||These findings demonstrate that Ion_Exclusion_Disposition involves coordinated restriction at multiple pathway sites, with chloride exclusion particularly critical for grapevine.",
    "editor_note": "Ion_Exclusion_Disposition is_a Salt_Tolerance_Disposition. ||Ion exclusion is the primary salt tolerance mechanism in grapevine, as the species lacks strong tissue tolerance. ||Child classes address Chloride_Exclusion_Disposition and Sodium_Exclusion_Disposition, with chloride exclusion generally more important for grapevine. ||Exclusion operates at multiple sites including root uptake, xylem loading, and xylem retrieval. ||Exclusion factor (external/internal concentration ratio) quantifies exclusion efficiency. ||Effective excluders can maintain low leaf ion concentrations across wide external salinity ranges.  This disposition represents the primary mechanism of salt tolerance in grapevine, as the species lacks strong tissue tolerance to high internal ion concentrations and depends on exclusion to avoid toxicity. ||Ion exclusion operates at multiple sites in the soil-plant pathway including the root epidermis and cortex (initial uptake restriction), the endodermis (regulated loading into the xylem), the xylem parenchyma along the transpiration stream (retrieval of ions from xylem sap), and the leaf base (restriction of entry into leaf lamina). ||Effective Ion_Exclusion_Disposition maintains leaf chloride below approximately 25-50 mmol/kg DW and sodium below 25-35 mmol/kg DW, thresholds above which toxicity symptoms typically appear. ||Exclusion capacity varies substantially among rootstock genotypes, with excluders maintaining low shoot ion concentrations across a wide range of external salinity while non-excluders show proportional accumulation with external supply. ||Ion_Exclusion_Disposition is energetically costly, requiring active transport against concentration gradients, but this cost is far less than the productivity loss from ion toxicity, making exclusion the favored strategy for grapevine salt tolerance.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Munns R, Tester M (2008) Mechanisms of salinity tolerance, Annual Review of Plant Biology 59:651-681|| Walker RR et al. (2004) Rootstock effects on salt tolerance of irrigated grapevines in the Sunraysia region, Australian Journal of Grape and Wine Research 10:34-45|| Storey R et al. (2003) Transport of sodium from roots to shoots in grapevine rootstocks, Plant, Cell and Environment 26:1943-1956"
  },
  "Chloride_Exclusion_Disposition": {
    "definition": "A Chloride_Exclusion_Disposition is an Ion_Exclusion_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that specifically prevent or limit the uptake of chloride ions from saline soil and their translocation to shoot tissues, maintaining leaf chloride concentrations below toxic thresholds.", 
    "alternative_term": "chloride restriction | Cl⁻ exclusion | chloride avoidance |+ Chloridausschluss-Disposition | Chlorid-Restriktion | Cl⁻-Ausschluss",
    "example_of_usage": "Mechanistic investigation of Chloride_Exclusion_Disposition at the University of Adelaide combined ion flux measurements, gene expression analysis, and grafting experiments to characterize chloride exclusion across 12 rootstocks. ²²Cl⁻ tracer studies quantified unidirectional root chloride uptake and xylem loading rates, while qRT-PCR assessed expression of candidate chloride transporter genes (VvCLC-c, VvSLAH, VvNPF). ||Chloride_Exclusion_Disposition showed strong genotypic variation with distinct mechanistic bases. '140 Ruggeri' exhibited strong exclusion through reduced xylem loading (only 8% of absorbed chloride translocated to shoot) combined with moderate uptake restriction. ||Gene expression analysis revealed that '140 Ruggeri' roots showed 4-fold lower expression of VvSLAH3 (a xylem-loading anion channel) under salinity compared to salt-sensitive 'Schwarzmann'. ||Reciprocal grafting experiments confirmed that Chloride_Exclusion_Disposition was rootstock-determined, with 'Shiraz' scions accumulating 22 mmol Cl⁻/kg DW on '140 Ruggeri' roots versus 385 mmol/kg on 'Schwarzmann' roots under identical salinity. ||Root chloride concentration analysis revealed that excluding rootstocks accumulated chloride in root cortex vacuoles (45 mM in root versus 18 mmol/kg in leaf), suggesting that root sequestration contributes to Chloride_Exclusion_Disposition alongside xylem loading restriction. ||These findings demonstrate that Chloride_Exclusion_Disposition involves coordinated reduction of xylem loading and enhanced root compartmentalization, with transporter gene expression differences underlying genotypic variation.",
    "editor_note": "Chloride_Exclusion_Disposition is_a Ion_Exclusion_Disposition. ||Chloride exclusion is the dominant determinant of grapevine salt tolerance, as grapevine is more chloride-sensitive than sodium-sensitive. ||Child classes include Root_Chloride_Exclusion_Disposition (uptake restriction) and Xylem_Loading_Restriction_Disposition (translocation control). ||Xylem loading restriction appears more important than uptake restriction for rootstock differences. ||Key genes include anion channels (SLAH, CLC families) and transporters. ||Excluder rootstocks may compartmentalize chloride in root vacuoles as an additional tolerance mechanism.  This disposition represents the most critical component of grapevine salt tolerance, as grapevine is considerably more sensitive to chloride toxicity than to sodium toxicity, distinguishing it from many other crop species. ||Chloride toxicity in grapevine manifests as leaf marginal and tip necrosis, premature leaf abscission, reduced photosynthesis, and ultimately vine decline, with symptoms typically appearing when leaf chloride exceeds 25-50 mmol/kg DW depending on cultivar and environmental conditions. ||Chloride exclusion involves both restriction of chloride uptake at root level and control of chloride loading into the xylem, with the latter appearing particularly important for grapevine rootstock differences. ||The molecular basis involves regulation of chloride channels (CLC family) and transporters in root cells, with effective excluders showing reduced expression or activity of xylem-loading transporters and potentially enhanced vacuolar sequestration in root tissues. ||Chloride_Exclusion_Disposition varies dramatically among rootstocks, with excluders maintaining leaf chloride below 30 mmol/kg DW at external concentrations that cause sensitive rootstocks to accumulate over 400 mmol/kg DW.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tregeagle JM et al. (2010) Chloride and sodium accumulation in grapevine rootstocks, Australian Journal of Grape and Wine Research 16:14-26|| Henderson SW et al. (2014) Shoot chloride exclusion and salt tolerance in grapevine is associated with differential ion transporter expression in roots, BMC Plant Biology 14:273|| Gong H et al. (2011) Mechanisms of chloride transport in grapevines, Functional Plant Biology 38:1-9"
  },
  "Root_Chloride_Exclusion_Disposition": {
    "definition": "A Root_Chloride_Exclusion_Disposition is a Chloride_Exclusion_Disposition that inheres in Vitis root tissues and is realized through mechanisms at the root surface and cortex that restrict the initial uptake of chloride ions from the soil solution, reducing the chloride load presented to subsequent exclusion barriers.", 
    "alternative_term": "root uptake restriction | root chloride barrier | cortical chloride exclusion |+ Wurzel-Chloridausschluss-Disposition | Wurzelaufnahme-Restriktion | Kortikale-Chlorid-Barriere",
    "example_of_usage": "Detailed analysis of Root_Chloride_Exclusion_Disposition at CSIRO Adelaide employed short-term ³⁶Cl⁻ uptake assays with excised roots to characterize chloride influx kinetics across 10 rootstocks, separating root uptake from subsequent translocation processes. ||Concentration-dependent uptake was measured over the range 0.5-50 mM Cl⁻ to determine Vmax (maximum uptake rate) and Km (affinity) parameters. ||Root_Chloride_Exclusion_Disposition showed moderate variation among rootstocks. ||Chloride uptake followed Michaelis-Menten kinetics in all rootstocks, indicating transporter-mediated entry. '140 Ruggeri' showed relatively low uptake capacity (Vmax = 2.8 μmol g⁻¹ root FW h⁻¹, Km = 12 mM), while 'Schwarzmann' displayed higher uptake (Vmax = 5.2 μmol g⁻¹ h⁻¹, Km = 8 mM), representing approximately 2-fold difference in Root_Chloride_Exclusion_Disposition. ||Interestingly, this 2-fold difference in root uptake translated to only partial explanation of the 20-fold difference in leaf chloride accumulation between these rootstocks, indicating that xylem loading restriction contributes more substantially to whole-plant exclusion. ||Apoplastic bypass contribution was assessed using PTS dye (apoplastic tracer), revealing that 15-25% of chloride entry occurred via apoplast in all rootstocks, explaining why root symplastic exclusion cannot achieve complete protection. ||Gene expression analysis showed that low-uptake '140 Ruggeri' had reduced expression of VvNPF2.4 (a nitrate/chloride transporter) in root epidermis compared to 'Schwarzmann', suggesting molecular basis for Root_Chloride_Exclusion_Disposition differences.",
    "editor_note": "Root_Chloride_Exclusion_Disposition is_a Chloride_Exclusion_Disposition. ||Root uptake restriction provides the first barrier against chloride entry but is incomplete due to apoplastic bypass. ||Uptake kinetics (Vmax, Km) quantify transporter-mediated entry. ||Root uptake differences explain only a portion of whole-plant exclusion variation, indicating that xylem loading restriction is equally or more important. ||Candidate transporters include NPF family members and anion channels. ||Apoplastic entry through Casparian strip gaps limits the effectiveness of symplastic exclusion mechanisms.  This disposition represents the first line of defense against chloride entry into the plant, operating at the soil-root interface where chloride must cross the epidermis and cortex to reach the stele. ||Chloride uptake into root cells occurs through both passive channels (when electrochemical gradients favor entry) and active transporters, with the relative contribution depending on external chloride concentration and membrane potential. ||Root_Chloride_Exclusion_Disposition involves reduced density or activity of plasma membrane chloride channels in root epidermal and cortical cells, potentially combined with enhanced efflux transporter activity returning chloride to the soil solution. ||However, because chloride can also enter roots via the apoplastic pathway (through cell walls and intercellular spaces) until blocked by the Casparian strip at the endodermis, root surface exclusion provides incomplete protection when apoplastic bypass occurs through Casparian strip discontinuities or damaged root regions. ||Root_Chloride_Exclusion_Disposition thus represents a contributing rather than sufficient mechanism for whole-plant chloride exclusion, with xylem loading restriction providing a critical second barrier.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Teakle NL, Tyerman SD (2010) Mechanisms of Cl⁻ transport contributing to salt tolerance, Plant Cell and Environment 33:566-589|| White PJ, Broadley MR (2001) Chloride in soils and its uptake and movement within the plant: a review, Annals of Botany 88:967-988|| Gong H et al. (2011) Mechanisms of chloride transport in grapevines, Functional Plant Biology 38:1-9"
  },
  "Xylem_Loading_Restriction_Disposition": {
    "definition": "A Xylem_Loading_Restriction_Disposition is a Chloride_Exclusion_Disposition that inheres in Vitis root stele tissues and is realized through mechanisms that limit the transfer of chloride ions from root symplast into the xylem vessels, preventing chloride translocation to shoots even when root cortical chloride concentrations are elevated.", 
    "alternative_term": "xylem chloride loading control | stelar chloride retention | root-to-shoot chloride restriction |+ Xylembeladungs-Restriktions-Disposition | Steläre-Chlorid-Retention | Wurzel-Spross-Chlorid-Kontrolle",
    "example_of_usage": "Direct assessment of Xylem_Loading_Restriction_Disposition at the Australian Centre for Plant Functional Genomics employed xylem sap collection and analysis combined with transporter gene expression profiling across 8 rootstocks under salinity (50 mM NaCl for 21 days). ||Xylem sap was collected by root pressurization, and chloride concentration was measured alongside root cortex chloride to calculate the loading ratio (xylem/cortex concentration). ||Xylem_Loading_Restriction_Disposition showed striking genotypic variation. '140 Ruggeri' demonstrated exceptional loading restriction with xylem sap chloride of only 3.2 mM despite root cortex concentration of 65 mM, yielding a loading ratio of 0.05 (only 5% of cortical chloride reaching xylem). 'Schwarzmann' showed minimal restriction with xylem sap chloride of 42 mM and cortex of 58 mM, yielding loading ratio of 0.72. ||Gene expression analysis revealed that '140 Ruggeri' roots showed 6-fold lower VvSLAH3 expression and 4-fold lower VvSLAH1 expression under salinity compared to 'Schwarzmann', directly implicating these anion channels in Xylem_Loading_Restriction_Disposition. ||Electrophysiological studies on isolated xylem parenchyma protoplasts confirmed lower chloride channel activity in '140 Ruggeri' cells (current density -15 pA/pF versus -52 pA/pF in 'Schwarzmann' at -120 mV). ||These findings establish that Xylem_Loading_Restriction_Disposition is the dominant mechanism underlying rootstock chloride exclusion differences, mediated by differential SLAH channel expression.",
    "editor_note": "Xylem_Loading_Restriction_Disposition is_a Chloride_Exclusion_Disposition. ||Xylem loading restriction is the primary site of genotypic variation in grapevine chloride exclusion. ||Loading ratio (xylem sap/root cortex concentration) quantifies restriction effectiveness. ||SLAH family anion channels are key molecular determinants, with excluder rootstocks showing reduced SLAH expression under salinity. ||Xylem loading is an active process requiring energy but protecting shoot tissues is energetically favorable compared to toxicity costs. ||Loading restriction can maintain low xylem chloride even when root cortical chloride is elevated.  This disposition represents the critical second barrier in chloride exclusion, operating at the root stele where chloride accumulated in cortical cells must cross xylem parenchyma membranes to enter the transpiration stream. ||Xylem loading is an active process requiring energy expenditure to move chloride against the concentration gradient from relatively low xylem sap concentrations into the high-volume transpiration flow. ||The molecular machinery for xylem chloride loading includes SLAH (Slow Anion Channel-Associated Homolog) family anion channels and potentially NPF (Nitrate transporter/Peptide transporter Family) members that facilitate chloride release into xylem vessels. ||Effective Xylem_Loading_Restriction_Disposition involves reduced expression, activity, or plasma membrane localization of these xylem-loading transporters in stelar parenchyma cells under salinity conditions. ||Xylem_Loading_Restriction_Disposition appears to be the primary site of genotypic variation in grapevine chloride exclusion, with excluding rootstocks showing dramatically lower xylem sap chloride concentrations than non-excluders at equivalent root cortical concentrations, indicating that root uptake differences alone cannot explain exclusion phenotypes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Henderson SW et al. (2014) Shoot chloride exclusion and salt tolerance in grapevine is associated with differential ion transporter expression in roots, BMC Plant Biology 14:273|| Gilliham M, Tester M (2005) The regulation of anion loading to the maize root xylem, Plant Physiology 137:819-828|| Teakle NL, Tyerman SD (2010) Mechanisms of Cl⁻ transport contributing to salt tolerance, Plant Cell and Environment 33:566-589"
  },
  "Sodium_Exclusion_Disposition": {
    "definition": "A Sodium_Exclusion_Disposition is an Ion_Exclusion_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that prevent or limit the uptake of sodium ions from saline soil and their translocation to shoot tissues, maintaining leaf sodium concentrations below toxic thresholds.", 
    "alternative_term": "sodium restriction | Na⁺ exclusion | sodium avoidance |+ Natriumausschluss-Disposition | Natrium-Restriktion | Na⁺-Ausschluss",
    "example_of_usage": "Comprehensive characterization of Sodium_Exclusion_Disposition at CSIRO Adelaide profiled sodium concentrations across the root-shoot pathway in 15 rootstocks under 50 mM NaCl salinity, with parallel assessment of potassium status to evaluate Na⁺/K⁺ homeostasis. ||Tissue sodium and potassium were measured in roots, stems, petioles, and leaf laminae, and the selectivity coefficient SK,Na (K/Na ratio in plant divided by K/Na ratio in soil solution) was calculated as an integrated exclusion metric. ||Sodium_Exclusion_Disposition showed substantial rootstock variation. '140 Ruggeri' exhibited strong sodium exclusion with leaf sodium of 12 mmol/kg DW, K⁺/Na⁺ ratio of 28, and SK,Na of 85. '1103 Paulsen' showed moderate Sodium_Exclusion_Disposition with leaf sodium of 45 mmol/kg DW, K⁺/Na⁺ ratio of 8, and SK,Na of 24—notably, this rootstock excludes chloride effectively but is less effective for sodium. 'Schwarzmann' displayed poor sodium exclusion with leaf sodium of 95 mmol/kg DW, K⁺/Na⁺ ratio of 3, and SK,Na of 9. ||Xylem sap analysis revealed that sodium exclusion occurred at both root uptake and xylem retrieval sites, with '140 Ruggeri' showing low xylem sodium (2.8 mM) at root level and efficient retrieval reducing sodium 40% between basal and distal stem positions. ||Correlation analysis showed that Sodium_Exclusion_Disposition contributed significantly to salt tolerance (r = 0.65 with growth maintenance) but less than chloride exclusion (r = 0.89), confirming the relative importance of these mechanisms.",
    "editor_note": "Sodium_Exclusion_Disposition is_a Ion_Exclusion_Disposition. ||Sodium exclusion is important but generally secondary to chloride exclusion for grapevine salt tolerance. ||Child classes include Root_Sodium_Exclusion_Disposition (uptake restriction) and Sodium_Retrieval_Disposition (xylem retrieval). ||K⁺/Na⁺ ratio and selectivity coefficient (SK,Na) are key metrics. ||HKT transporters are central to sodium transport and exclusion. ||Some rootstocks show differential chloride versus sodium exclusion capacity, relevant for waters with varying NaCl versus other chloride salt composition.  This disposition represents the sodium-specific component of salt tolerance, important though generally secondary to chloride exclusion in grapevine. ||Sodium toxicity in grapevine manifests as disruption of potassium-dependent enzyme function (sodium competes with potassium at binding sites), interference with protein synthesis, and metabolic dysfunction, with symptoms including marginal leaf necrosis, reduced photosynthesis, and growth inhibition typically appearing when leaf sodium exceeds 25-50 mmol/kg DW. ||Sodium exclusion involves restriction of sodium uptake at the root level and prevention of sodium loading into the xylem, mechanistically paralleling chloride exclusion but involving distinct transporter systems. ||Additionally, sodium that enters the xylem can be retrieved along the transpiration pathway by xylem parenchyma cells, providing a third exclusion barrier. ||The molecular machinery for sodium transport and exclusion includes HKT (High-affinity Potassium Transporter) family members that mediate both root sodium uptake and xylem retrieval, with HKT1 subfamily members particularly important for retrieval. ||Sodium_Exclusion_Disposition varies among rootstocks, though typically with less dramatic variation than chloride exclusion.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Munns R, Tester M (2008) Mechanisms of salinity tolerance, Annual Review of Plant Biology 59:651-681|| Storey R et al. (2003) Transport of sodium from roots to shoots in grapevine rootstocks, Plant, Cell and Environment 26:1943-1956|| Walker RR et al. (2004) Rootstock effects on salt tolerance of irrigated grapevines in the Sunraysia region, Australian Journal of Grape and Wine Research 10:34-45"
  },
  "Root_Sodium_Exclusion_Disposition": {
    "definition": "A Root_Sodium_Exclusion_Disposition is a Sodium_Exclusion_Disposition that inheres in Vitis root tissues and is realized through mechanisms at the root surface and cortex that restrict the initial uptake of sodium ions from the soil solution and limit sodium accumulation in root symplast, reducing the sodium load available for xylem loading.", 
    "alternative_term": "root sodium uptake restriction | root sodium barrier | cortical sodium exclusion |+ Wurzel-Natriumausschluss-Disposition | Wurzel-Natrium-Barriere | Kortikaler-Natrium-Ausschluss",
    "example_of_usage": "Investigation of Root_Sodium_Exclusion_Disposition at the University of Adelaide employed ²²Na⁺ tracer studies and membrane transport assays to characterize sodium influx mechanisms across 8 rootstocks. ||Short-term (20 min) ²²Na⁺ uptake was measured at 50 mM Na⁺ to assess initial influx rates, with pharmacological dissection using channel blockers (Gd³⁺ for NSCC, tetraethylammonium for K⁺ channels) to identify entry pathways. ||Root_Sodium_Exclusion_Disposition varied 3-fold among rootstocks. '140 Ruggeri' showed the lowest sodium influx (1.8 μmol g⁻¹ root FW h⁻¹), with 65% of uptake blocked by Gd³⁺ indicating NSCC-mediated entry. 'Schwarzmann' displayed highest influx (5.4 μmol g⁻¹ h⁻¹) with similar pharmacological profile (70% Gd³⁺-sensitive). ||The remaining influx was largely apoplastic, as confirmed by parallel studies with the apoplastic tracer PTS. ||SOS1 expression analysis revealed that '140 Ruggeri' showed 3.5-fold higher root SOS1 transcript levels under salinity compared to 'Schwarzmann', suggesting enhanced sodium efflux capacity contributes to its Root_Sodium_Exclusion_Disposition. ||Whole-plant ²²Na⁺ partitioning showed that low-influx '140 Ruggeri' retained 78% of absorbed sodium in roots (suggesting effective root sequestration or efflux) while high-influx 'Schwarzmann' translocated 55% to shoots. ||These findings indicate that Root_Sodium_Exclusion_Disposition involves both reduced NSCC-mediated influx and enhanced SOS1-mediated efflux, with root retention capacity providing additional protection.",
    "editor_note": "Root_Sodium_Exclusion_Disposition is_a Sodium_Exclusion_Disposition. ||Root sodium uptake occurs primarily through non-selective cation channels (NSCCs), with some apoplastic contribution. ||SOS1 Na⁺/H⁺ antiporter mediates active sodium efflux back to soil. ||Root sodium exclusion provides the first barrier but is typically incomplete. ||Casparian strip integrity affects apoplastic bypass. ||Root sodium retention (vacuolar sequestration) can complement exclusion by reducing translocation even when uptake occurs.  This disposition represents the first barrier against sodium entry, operating at the soil-root interface where sodium must cross root cell membranes to enter the symplastic pathway to the shoot. ||Sodium can enter root cells through multiple pathways including non-selective cation channels (NSCC), which are the primary entry route under salinity, and potentially through HKT2 family transporters that can mediate sodium uptake when potassium is limiting. ||Root_Sodium_Exclusion_Disposition involves reduced activity or expression of sodium-permeable channels, enhanced plasma membrane H⁺-ATPase activity maintaining the driving force for sodium efflux, and active sodium extrusion via SOS1 (Salt Overly Sensitive 1) Na⁺/H⁺ antiporters that pump sodium back to the soil solution. ||Additionally, because sodium can enter via apoplastic flow, root_Sodium_Exclusion_Disposition is enhanced by Casparian strip integrity and suberization that blocks apoplastic bypass. ||Root sodium exclusion reduces the sodium load that must be handled by subsequent exclusion mechanisms, but complete exclusion at root level is typically not achievable, making xylem loading control and retrieval important complementary mechanisms.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tester M, Davenport R (2003) Na⁺ tolerance and Na⁺ transport in higher plants, Annals of Botany 91:503-527|| Munns R, Tester M (2008) Mechanisms of salinity tolerance, Annual Review of Plant Biology 59:651-681|| Shi H et al. (2002) The Arabidopsis thaliana salt tolerance gene SOS1 encodes a putative Na⁺/H⁺ antiporter, Proceedings of the National Academy of Sciences 97:6896-6901"
  },
  "Sodium_Retrieval_Disposition": {
    "definition": "A Sodium_Retrieval_Disposition is a Sodium_Exclusion_Disposition that inheres in Vitis xylem parenchyma cells along the root-to-shoot pathway and is realized through active removal of sodium ions from the xylem sap, reducing sodium translocation to leaves by reclaiming sodium into surrounding parenchyma cells before it reaches sensitive photosynthetic tissues.", 
    "alternative_term": "xylem sodium unloading | sodium reclamation | HKT1-mediated retrieval |+ Natrium-Rückholungs-Disposition | Xylem-Natrium-Entladung | HKT1-vermittelte-Rückholung",
    "example_of_usage": "Direct assessment of Sodium_Retrieval_Disposition at the Australian Centre for Plant Functional Genomics tracked sodium concentration changes along the transpiration pathway in 10 rootstocks under 50 mM NaCl salinity. ||Xylem sap was collected by Scholander pressure chamber from root (basal stem), mid-stem, and upper stem positions, with sodium measured at each location. ||Additionally, VvHKT1||1 gene expression was profiled in xylem-associated tissues. ||Sodium_Retrieval_Disposition showed significant rootstock variation. '140 Ruggeri' demonstrated strong retrieval with xylem sap sodium declining from 3.8 mM at root level to 2.4 mM at mid-stem to 1.5 mM at upper stem, representing 60% reduction along the pathway. 'K51-40' showed similar retrieval (58% reduction). '1103 Paulsen' exhibited moderate Sodium_Retrieval_Disposition (35% reduction from 8.2 to 5.3 mM). 'Schwarzmann' showed minimal retrieval (12% reduction from 42 to 37 mM), with high initial loading overwhelming limited retrieval capacity. ||VvHKT1||1 expression analysis revealed that retrieval-effective '140 Ruggeri' showed 5-fold higher HKT1||1 transcript levels in stem xylem parenchyma compared to 'Schwarzmann'. ||Immunolocalization confirmed HKT1||1 protein in xylem parenchyma cells surrounding vessels in high-retrieval genotypes. ||These findings establish that Sodium_Retrieval_Disposition provides a significant additional exclusion barrier mediated by HKT1 transporters, with genotypic variation in HKT1||1 expression underlying differential retrieval capacity.",
    "editor_note": "Sodium_Retrieval_Disposition is_a Sodium_Exclusion_Disposition. ||Sodium retrieval operates after xylem loading, removing sodium from transpiration stream via HKT1 transporters in xylem parenchyma. ||Retrieval can substantially reduce shoot sodium even when root exclusion is incomplete. ||Effectiveness is quantified by % reduction in xylem sodium along root-to-shoot pathway. ||VvHKT1||1 expression correlates with retrieval capacity. ||Retrieved sodium may be stored in parenchyma vacuoles or recirculated via phloem. ||Retrieval provides \"last line of defense\" protecting upper canopy.  This disposition represents a unique exclusion mechanism operating after xylem loading, providing a third barrier that can reduce shoot sodium accumulation even when root uptake and xylem loading restriction are imperfect. ||Sodium retrieval is mediated primarily by HKT1 (High-affinity K⁺ Transporter subfamily 1) proteins expressed in xylem parenchyma cells of roots and shoots, which function as sodium uniporters removing Na⁺ from the xylem stream. ||Retrieved sodium can be stored in xylem parenchyma vacuoles, redistributed to root tissues for efflux or sequestration, or in some cases loaded into phloem for recirculation. ||Effective Sodium_Retrieval_Disposition results in progressive decline in xylem sap sodium concentration from root to shoot, with sodium content in upper stems and leaves substantially lower than would be predicted from root xylem loading alone. ||The retrieval mechanism is particularly important in species like grapevine where complete root-level exclusion is not achieved, providing an additional opportunity to protect the most sensitive upper canopy tissues.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Munns R et al. (2012) Wheat grain yield on saline soils is improved by an ancestral Na⁺ transporter gene, Nature Biotechnology 30:360-364|| Storey R et al. (2003) Transport of sodium from roots to shoots in grapevine rootstocks, Plant, Cell and Environment 26:1943-1956|| Davenport RJ et al. (2007) The Na⁺ transporter AtHKT1||1 controls retrieval of Na⁺ from the xylem in Arabidopsis, Plant Cell and Environment 30:497-507"
  },
  "Ion_Compartmentalization_Disposition": {
    "definition": "An Ion_Compartmentalization_Disposition is a Salt_Tolerance_Disposition that inheres in a Vitis plant and is realized through cellular and whole-plant mechanisms that sequester accumulated toxic ions (sodium and chloride) in locations where they cause minimal metabolic damage, enabling tolerance of tissue ion concentrations that would otherwise be injurious.", 
    "alternative_term": "ion sequestration | toxic ion compartmentation | tissue ion tolerance |+ Ionenkompartimentierungs-Disposition | Ionen-Sequestrierung | Toxische-Ionen-Kompartmentierung",
    "example_of_usage": "Investigation of Ion_Compartmentalization_Disposition at the University of Adelaide employed X-ray microanalysis and tissue dissection to characterize subcellular and whole-plant ion distribution in 12 rootstocks following 28 days at 50 mM NaCl. ||Frozen-hydrated leaf sections were analyzed by energy-dispersive X-ray spectroscopy to determine vacuolar versus cytoplasmic ion concentrations, while systematic sampling of leaves by position quantified whole-plant ion distribution patterns. ||Ion_Compartmentalization_Disposition varied substantially among rootstocks. '1103 Paulsen' (which showed moderate exclusion capacity) demonstrated strong compartmentalization, with leaf mesophyll cells showing vacuolar Na⁺ concentration of 285 mM versus cytoplasmic concentration of only 28 mM (10-fold compartmentalization ratio), and vacuolar Cl⁻ of 195 mM versus cytoplasmic 32 mM. ||Whole-plant analysis revealed preferential accumulation in oldest leaves (leaf position 1-3 from base averaging 125 mmol Na⁺/kg DW) versus youngest fully expanded leaves (position 8-10 averaging 35 mmol/kg). 'Ramsey' showed similar compartmentalization patterns despite different absolute concentrations. ||In contrast, 'Schwarzmann' (poor excluder) showed weak Ion_Compartmentalization_Disposition with vacuolar/cytoplasmic Na⁺ ratio of only 3.5 and more uniform distribution across leaf positions (oldest 380, youngest 285 mmol/kg). ||The strong compartmentalization of '1103 Paulsen' enabled maintenance of cytoplasmic K⁺/Na⁺ ratio above 5 (critical for enzyme function) despite whole-leaf K⁺/Na⁺ ratio of only 2.5, demonstrating how compartmentalization protects metabolic function when exclusion is incomplete.",
    "editor_note": "Ion_Compartmentalization_Disposition is_a Salt_Tolerance_Disposition. ||Compartmentalization provides tissue tolerance when exclusion is insufficient, protecting sensitive metabolic compartments. ||Child classes include Vacuolar_Sequestration_Disposition (intracellular level) and Older_Tissue_Accumulation_Disposition (whole-plant level). ||Compartmentalization maintains cytoplasmic K⁺/Na⁺ ratio above critical threshold (~1-5) even when whole-tissue ratio is unfavorable. ||Compartmentalization and exclusion operate complementarily, with both contributing to overall salt tolerance.  This disposition represents a tissue tolerance strategy complementing ion exclusion, operating when exclusion mechanisms are overwhelmed or insufficient and ions accumulate in plant tissues. ||Effective compartmentalization protects metabolically sensitive compartments (particularly the cytoplasm where enzymes function and protein synthesis occurs) by directing ions to less sensitive locations including the vacuole (intracellular compartmentalization) and older, expendable tissues (whole-plant compartmentalization). ||Vacuolar sequestration removes ions from the cytoplasm while simultaneously contributing to osmotic adjustment, as vacuolar solutes lower cell water potential enabling continued water uptake from saline soil. ||Whole-plant compartmentalization preferentially accumulates ions in older leaves that are approaching senescence, sacrificing these tissues to protect young, photosynthetically active leaves critical for current and future productivity. ||Ion_Compartmentalization_Disposition varies among genotypes in both the capacity for vacuolar sequestration (determined by tonoplast transporter expression and activity) and the efficiency of directing ions to older tissues (involving coordination of xylem unloading and phloem redistribution), providing genetic variation for breeding salt-tolerant cultivars when exclusion capacity is limited.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Munns R, Tester M (2008) Mechanisms of salinity tolerance, Annual Review of Plant Biology 59:651-681|| Flowers TJ, Colmer TD (2008) Salinity tolerance in halophytes, New Phytologist 179:945-963|| Shabala S, Mackay A (2011) Ion transport in halophytes, Advances in Botanical Research 57:151-199"
  },
  "Vacuolar_Sequestration_Disposition": {
    "definition": "A Vacuolar_Sequestration_Disposition is an Ion_Compartmentalization_Disposition that inheres in Vitis cells and is realized through active transport of sodium and chloride ions from the cytoplasm into the vacuole, maintaining low cytoplasmic ion concentrations compatible with enzyme function while using accumulated vacuolar ions for osmotic adjustment.", 
    "alternative_term": "vacuolar ion storage | tonoplast sequestration | intracellular ion compartmentation |+ Vakuoläre-Sequestrierungs-Disposition | Tonoplast-Sequestrierung | Intrazelluläre-Ionen-Kompartimentierung",
    "example_of_usage": "Molecular and physiological characterization of Vacuolar_Sequestration_Disposition at CSIRO Adelaide combined tonoplast vesicle transport assays with gene expression analysis across 10 rootstocks under salt stress (50 mM NaCl, 21 days). ||Tonoplast vesicles isolated from root and leaf tissues were assayed for NHX-mediated ²²Na⁺/H⁺ exchange and CLC-mediated ³⁶Cl⁻ transport, while qRT-PCR quantified expression of VvNHX1, VvNHX2, VvCLCc, and VvCLCg. ||Vacuolar_Sequestration_Disposition showed significant rootstock variation. '1103 Paulsen' exhibited strong sequestration capacity with leaf tonoplast Na⁺/H⁺ exchange rate of 18.5 nmol mg⁻¹ protein min⁻¹ (3-fold higher than salt-sensitive 'Schwarzmann' at 6.2 nmol mg⁻¹ min⁻¹) and correspondingly high VvNHX1 expression (5.2-fold induction under salt versus 1.8-fold in 'Schwarzmann'). ||Chloride sequestration paralleled sodium patterns, with '1103 Paulsen' showing Cl⁻ transport of 12.4 nmol mg⁻¹ min⁻¹ versus 4.8 in 'Schwarzmann'. ||X-ray microanalysis confirmed functional significance, with high-sequestration '1103 Paulsen' maintaining cytoplasmic Na⁺ below 35 mM despite vacuolar accumulation to 290 mM, while low-sequestration 'Schwarzmann' showed cytoplasmic Na⁺ of 95 mM with vacuolar 180 mM. ||Critically, the cytoplasmic K⁺/Na⁺ ratio in '1103 Paulsen' remained at 6.5 (adequate for enzyme function) compared to only 1.8 in 'Schwarzmann' (below critical threshold). ||These findings demonstrate that Vacuolar_Sequestration_Disposition directly protects cytoplasmic metabolism through NHX and CLC transporter activity.",
    "editor_note": "Vacuolar_Sequestration_Disposition is_a Ion_Compartmentalization_Disposition. ||Vacuolar sequestration protects cytoplasm while contributing to osmotic adjustment. ||NHX antiporters (Na⁺/H⁺) mediate sodium sequestration|| CLC channels/antiporters mediate chloride sequestration. ||V-ATPase and V-PPase provide energization through proton gradient. ||Sequestration capacity correlates with transporter expression levels. ||Maintaining compartmentalization requires ongoing energy expenditure. ||Cytoplasmic K⁺/Na⁺ ratio is the key functional outcome, with ratios > 1-5 required for enzyme function.  This disposition represents intracellular compartmentalization, the most immediate mechanism for protecting cytoplasmic metabolism from ion toxicity. ||The vacuole, occupying 80-90% of mature cell volume, provides a large capacity sink for ion sequestration, and vacuolar ion accumulation simultaneously contributes to osmotic adjustment by lowering vacuolar water potential. ||Sodium sequestration is mediated primarily by NHX (Na⁺/H⁺ antiporter) family transporters on the tonoplast (vacuolar membrane), which use the proton gradient generated by V-ATPase and V-PPase to drive sodium into the vacuole against its concentration gradient. ||Chloride sequestration involves CLC (Chloride Channel) family proteins, particularly those functioning as Cl⁻/H⁺ antiporters on the tonoplast. ||Effective Vacuolar_Sequestration_Disposition requires coordinated activity of these transporters with the proton pumps that energize them, and maintaining this compartmentalization is an ongoing energy cost as ions tend to leak back to the cytoplasm. ||Genotypic variation in sequestration capacity reflects differences in transporter expression levels, kinetic properties, and regulation under salt stress.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Apse MP et al. (1999) Salt tolerance conferred by overexpression of a vacuolar Na⁺/H⁺ antiport in Arabidopsis, Science 285:1256-1258|| Bassil E, Blumwald E (2014) The ins and outs of intracellular ion homeostasis: NHX-type cation/H⁺ transporters, Current Opinion in Plant Biology 22:1-6|| Teakle NL, Tyerman SD (2010) Mechanisms of Cl⁻ transport contributing to salt tolerance, Plant Cell and Environment 33:566-589"
  },
  "Older_Tissue_Accumulation_Disposition": {
    "definition": "An Older_Tissue_Accumulation_Disposition is an Ion_Compartmentalization_Disposition that inheres in a Vitis plant and is realized through whole-plant transport mechanisms that preferentially direct sodium and chloride ions to older, senescing leaves while protecting young, metabolically active leaves from toxic ion accumulation.", 
    "alternative_term": "basipetal ion accumulation | sacrificial leaf accumulation | old leaf ion dumping |+ Altgewebe-Akkumulations-Disposition | Basipetale-Ionen-Akkumulation | Opferblatt-Strategie",
    "example_of_usage": "Systematic characterization of Older_Tissue_Accumulation_Disposition at Bordeaux Sciences Agro tracked ion distribution across leaf positions in 15 rootstock-scion combinations during 6 weeks of salt stress (ECw 4 dS/m). ||Leaves were harvested at weekly intervals from positions 2-4 (oldest), 6-8 (mid), and 10-12 (youngest) on marked shoots, with chloride and sodium analyzed for each position and timepoint. ||Older_Tissue_Accumulation_Disposition varied among rootstocks independent of total exclusion capacity. '1103 Paulsen' (moderate excluder) showed strong positional gradient with week-6 chloride concentrations of 185 mmol/kg in oldest leaves, 78 mmol/kg in mid leaves, and 32 mmol/kg in youngest leaves (5.8-fold old/young ratio). '140 Ruggeri' (strong excluder) maintained low concentrations throughout but still showed 3.2-fold positional gradient (28, 15, 9 mmol/kg). 'Schwarzmann' (weak excluder) accumulated high concentrations with minimal gradient (410, 385, 320 mmol/kg, only 1.3-fold ratio), indicating poor Older_Tissue_Accumulation_Disposition. ||Remarkably, '1103 Paulsen' maintained youngest leaf chloride below toxic threshold (50 mmol/kg) for the entire 6-week period despite oldest leaves exceeding 150 mmol/kg by week 3, demonstrating effective protection of critical tissues. ||Leaf abscission analysis revealed that '1103 Paulsen' lost 25% of oldest leaves by week 6 with no loss of younger leaves, representing successful operation of the sacrificial strategy. ||The weak Older_Tissue_Accumulation_Disposition of 'Schwarzmann' resulted in toxic concentrations reaching youngest leaves by week 4, causing shoot tip necrosis and growth cessation despite similar total ion uptake to '1103 Paulsen'.",
    "editor_note": "Older_Tissue_Accumulation_Disposition is_a Ion_Compartmentalization_Disposition. ||Older tissue accumulation is a whole-plant compartmentalization strategy protecting critical young tissues. ||Quantified by the old leaf/young leaf concentration ratio (effective values > 3). ||Mechanism involves differential xylem unloading and possibly phloem retranslocation. ||Older leaves can be sacrificed (abscised) when ion load becomes excessive. ||This strategy extends functional duration under salt stress even when total exclusion is limited. ||The disposition is partially independent of exclusion capacity, representing a distinct tolerance component.  This disposition represents whole-plant level compartmentalization, sacrificing expendable older tissues to maintain the function of irreplaceable younger tissues critical for current photosynthesis and future growth. ||Older leaves are more tolerant of ion accumulation because they have already completed their major contribution to plant carbon gain and can be abscised if damage becomes severe, while young expanding leaves and the shoot apex must be protected to maintain vine productivity. ||The mechanism involves differential xylem unloading (older leaves receiving proportionally more of the transpiration stream ions), possible phloem redistribution (retranslocation from young to old tissues), and potentially lower exclusion capacity in older leaf traces. ||Effective Older_Tissue_Accumulation_Disposition creates steep ion concentration gradients along the shoot, with basal (older) leaves showing concentrations 3-10 fold higher than apical (younger) leaves. ||This strategy extends the period before toxic concentrations accumulate in critical young tissues, effectively buying time during salt exposure and enabling continued growth even when some older leaves are lost to salt injury.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Munns R (2002) Comparative physiology of salt and water stress, Plant Cell and Environment 25:239-250|| Tester M, Davenport R (2003) Na⁺ tolerance and Na⁺ transport in higher plants, Annals of Botany 91:503-527|| Wolf O et al. (1991) Growth and cation composition of leaves and stems of Vitis vinifera in a saline environment, Journal of Plant Physiology 137:656-662"
  },
  "Osmotic_Stress_Tolerance_Disposition": {
    "definition": "An Osmotic_Stress_Tolerance_Disposition is a Salt_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that enable maintenance of water uptake, turgor pressure, and cellular function despite the low soil water potential created by dissolved salts, addressing the water-deficit component of salt stress independent of specific ion toxicity.", 
    "alternative_term": "salt-induced osmotic tolerance | osmotic adjustment under salinity | water deficit tolerance under salt |+ Osmotische-Stresstoleranz-Disposition | Salzinduzierte-Osmotoleranz | Osmotische-Anpassung-unter-Salinität",
    "example_of_usage": "Detailed investigation of Osmotic_Stress_Tolerance_Disposition at INRAE Montpellier employed pressure-volume analysis and compatible solute profiling across 12 rootstocks under iso-osmotic salt (NaCl) versus non-ionic osmoticum (PEG-6000) treatments at -0.5 MPa osmotic potential. ||This experimental design separated osmotic from ionic stress effects, enabling direct assessment of Osmotic_Stress_Tolerance_Disposition. ||Pressure-volume parameters including osmotic potential at full turgor (Ψπ100), turgor loss point (Ψtlp), and bulk modulus of elasticity (ε) were determined, alongside tissue concentrations of proline, soluble sugars, and organic acids. ||Osmotic_Stress_Tolerance_Disposition showed substantial variation among rootstocks. '110 Richter' exhibited strong osmotic tolerance with Ψπ100 declining from -1.2 MPa (control) to -1.95 MPa under salt (0.75 MPa adjustment), maintaining positive turgor (0.35 MPa) at leaf water potential of -1.6 MPa. ||Compatible solute analysis revealed proline accumulation to 42 μmol/g FW (8-fold increase) and total soluble sugars increasing 2.5-fold, together accounting for 45% of osmotic adjustment, with vacuolar Na⁺ and Cl⁻ contributing the remainder. 'Riparia Gloire' showed weak Osmotic_Stress_Tolerance_Disposition with Ψπ100 declining only to -1.45 MPa (0.25 MPa adjustment), reaching turgor loss at leaf water potential of -1.1 MPa, and proline accumulation of only 12 μmol/g FW. ||Importantly, responses to NaCl and PEG were highly correlated across genotypes (r = 0.88 for osmotic adjustment), indicating that Osmotic_Stress_Tolerance_Disposition reflects inherent osmotic adjustment capacity rather than salt-specific adaptation. ||Strong Osmotic_Stress_Tolerance_Disposition maintained stomatal conductance at 65% of control under salinity versus only 30% in osmotic-sensitive genotypes, directly supporting continued carbon assimilation.",
    "editor_note": "Osmotic_Stress_Tolerance_Disposition is_a Salt_Tolerance_Disposition. ||Osmotic stress is the water-deficit component of salinity, immediate and universal regardless of ion toxicity. ||Osmotic tolerance involves compatible solute accumulation and potentially use of sequestered ions for adjustment. ||Mechanisms parallel drought osmotic adjustment (see Osmotic_Adjustment_Disposition under Drought_Tolerance). ||Genotypes with strong drought tolerance often show strong salt osmotic tolerance. ||Osmotic and ionic components of salt stress are additive, with osmotic dominating at low salinity and ionic at high salinity.  This disposition represents tolerance to the osmotic effect of salinity, which is immediate (occurring as soon as roots encounter saline solution) and affects all plants regardless of ion exclusion capacity. ||The osmotic component of salt stress is functionally equivalent to drought stress in its effects on plant water relations, reducing soil water availability and creating the need for plants to lower their own water potential to maintain the gradient driving water uptake. ||Osmotic_Stress_Tolerance_Disposition involves active osmotic adjustment through accumulation of compatible solutes (proline, glycine betaine, sugars, organic acids) and inorganic ions (K⁺) that lower cytoplasmic and vacuolar osmotic potential, enabling water uptake from low-potential soil while maintaining turgor for growth and stomatal function. ||Sequestered Na⁺ and Cl⁻ can contribute to osmotic adjustment if effectively compartmentalized in vacuoles, providing a metabolic benefit from what would otherwise be purely detrimental ion accumulation. ||Genotypes with strong Osmotic_Stress_Tolerance_Disposition maintain higher water content, turgor, and stomatal conductance under salinity than sensitive genotypes at equivalent external osmotic potential.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Munns R, Tester M (2008) Mechanisms of salinity tolerance, Annual Review of Plant Biology 59:651-681|| Hasegawa PM et al. (2000) Plant cellular and molecular responses to high salinity, Annual Review of Plant Physiology and Plant Molecular Biology 51:463-499|| Cramer GR (2002) Sodium-calcium interactions under salinity stress, in Salinity: Environment-Plants-Molecules, Läuchli A, Lüttge U (eds), Kluwer Academic Publishers"
  },
  "Salt_Induced_ABA_Response_Disposition": {
    "definition": "A Salt_Induced_ABA_Response_Disposition is a Salt_Tolerance_Disposition that inheres in a Vitis plant and is realized through the capacity to rapidly synthesize and respond to abscisic acid (ABA) following salt stress perception, coordinating multiple protective responses including stomatal closure, ion transporter regulation, compatible solute accumulation, and stress-responsive gene expression.", 
    "alternative_term": "salt-ABA signaling | salinity-induced ABA accumulation | ABA-mediated salt response |+ Salzinduzierte-ABA-Antwort-Disposition | Salinität-ABA-Signalisierung | ABA-vermittelte-Salzantwort",
    "example_of_usage": "Time-course analysis of Salt_Induced_ABA_Response_Disposition at UC Davis characterized ABA dynamics and downstream responses across 10 rootstocks following acute salt application (100 mM NaCl). ||Xylem sap and leaf ABA were measured at 0, 2, 6, 12, 24, and 72 hours post-treatment, with parallel assessment of stomatal conductance, NCED gene expression, and stress-responsive gene activation (VvP5CS, VvLEA, VvNHX1). ||Salt_Induced_ABA_Response_Disposition showed striking genotypic variation in kinetics and magnitude. '140 Ruggeri' exhibited rapid, strong ABA response with xylem sap ABA increasing from 45 ng/L (control) to 380 ng/L at 6 hours and 620 ng/L at 24 hours, driven by 8-fold VvNCED3 induction detectable within 2 hours. ||This rapid ABA accumulation triggered stomatal closure to 25% of control by 12 hours, VvP5CS induction (6-fold by 24 hours), and VvNHX1 upregulation (3.5-fold by 24 hours) enhancing vacuolar sequestration. 'K51-40' showed similarly rapid response with comparable protective outcomes. 'Schwarzmann' displayed delayed, weaker Salt_Induced_ABA_Response_Disposition with xylem ABA reaching only 185 ng/L at 24 hours, VvNCED3 induction delayed until 6 hours and peaking at only 3-fold, stomatal closure to 60% of control (incomplete), and minimal VvP5CS induction (1.8-fold). ||Correlation analysis revealed that ABA response magnitude at 24 hours predicted ion exclusion efficiency (r = 0.72), proline accumulation (r = 0.78), and overall salt tolerance (r = 0.68), demonstrating the central coordinating role of Salt_Induced_ABA_Response_Disposition. ||However, constitutively elevated ABA (observed in one genotype) was associated with growth penalty under non-stress conditions, indicating that optimal Salt_Induced_ABA_Response_Disposition involves inducibility rather than constitutive elevation.",
    "editor_note": "Salt_Induced_ABA_Response_Disposition is_a Salt_Tolerance_Disposition. ||ABA is the central hormone coordinating salt stress responses across multiple processes. ||NCED genes control ABA biosynthesis, with root expression critical for xylem-transported ABA signal. ||ABA regulates stomata, ion transporters, compatible solute genes, and protective proteins. ||Response kinetics (speed) and magnitude both contribute to effective protection. ||ABA signaling overlaps with drought response (see isohydric behavior), with salt-tolerant genotypes often showing strong ABA responsiveness. ||Optimal response is inducible rather than constitutive to avoid growth penalties.  This disposition represents the hormonal signaling component of salt tolerance, with ABA serving as a central coordinator integrating diverse stress responses across tissues and timescales. ||Salt stress triggers ABA biosynthesis primarily in roots through upregulation of NCED (9-cis-epoxycarotenoid dioxygenase) genes, with ABA subsequently transported to shoots via the transpiration stream where it triggers stomatal closure reducing water loss and ion delivery to leaves. ||Beyond stomatal effects, ABA regulates expression of ion transporters (enhancing HKT1-mediated sodium retrieval, modulating NHX activity), activates compatible solute biosynthetic genes (P5CS for proline), induces protective proteins (LEA proteins, dehydrins), and triggers aquaporin regulation adjusting hydraulic conductance. ||The magnitude, speed, and sensitivity of the ABA response vary among genotypes, with rapid, strong ABA accumulation enabling faster protective responses but potentially excessive stomatal closure limiting carbon gain. ||Salt_Induced_ABA_Response_Disposition thus involves optimization of ABA signaling for effective protection without excessive growth limitation.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Zhu JK (2002) Salt and drought stress signal transduction in plants, Annual Review of Plant Biology 53:247-273|| Cramer GR et al. (2011) Effects of abiotic stress on plants: a systems biology perspective, BMC Plant Biology 11:163|| Ferrero M et al. (2020) A meta-analysis reveals the interactive role of ABA signaling in plant responses to stress, Frontiers in Plant Science 11:420"
  },
  "Lime_Tolerance_Disposition": {
    "definition": "A Lime_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that enable maintenance of adequate iron nutrition, normal chlorophyll synthesis, and healthy growth on calcareous (lime-rich) soils where high pH and bicarbonate concentrations would otherwise induce iron deficiency chlorosis.", 
    "alternative_term": "calcareous soil tolerance | limestone tolerance | chlorosis resistance |+ Kalktoleranz-Disposition | Kalkstein-Toleranz | Chlorose-Resistenz",
    "example_of_usage": "Comprehensive evaluation of Lime_Tolerance_Disposition at INRAE Bordeaux assessed growth, leaf chlorophyll content, and iron nutrition across 25 rootstocks grown in calcareous soil with 40% total CaCO₃ and 18% active lime over three growing seasons. ||Measurements included SPAD chlorophyll index, leaf iron concentration (total and \"active\" Fe²⁺), visual chlorosis severity (0-5 scale), and shoot dry weight. ||Lime_Tolerance_Disposition varied dramatically among rootstocks. '41B' (V. vinifera × V. berlandieri) exhibited exceptional tolerance with SPAD values of 38 (healthy green), leaf total Fe of 125 μg/g DW with 45% active Fe, chlorosis score of 0.5, and 95% shoot growth relative to reference soil. 'Fercal' (BC1 × 333EM) showed similar tolerance (SPAD 36, 92% growth). ||In contrast, '3309C' (V. riparia × V. rupestris) displayed severe lime sensitivity with SPAD of 18 (pronounced yellowing), total Fe of 180 μg/g DW but only 15% active Fe (indicating Fe inactivation), chlorosis score of 4.2, and growth reduced to 35% of reference. 'SO4' showed intermediate tolerance (SPAD 28, 65% growth). ||The paradox of high total but low active iron in sensitive rootstocks reflects the \"iron chlorosis paradox\" where Fe accumulates in inactive Fe³⁺ form in chlorotic leaves. ||Active lime tolerance thresholds (IPC values) were established as 40% for '41B', 40% for 'Fercal', 17% for '3309C', and 25% for 'SO4', providing practical guidance for rootstock selection based on soil analysis.",
    "editor_note": "Lime_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||Lime tolerance is primarily determined by rootstock genotype in grafted vines, making rootstock selection essential for calcareous sites. ||The primary problem is iron deficiency chlorosis despite often adequate total soil iron. ||Child classes address mechanisms including Iron_Acquisition_Efficiency_Disposition, Bicarbonate_Tolerance_Disposition, and High_pH_Adaptation_Disposition. ||V. berlandieri and V. vinifera × V. berlandieri hybrids show superior lime tolerance, reflecting adaptation to limestone soils of origin. ||IPC (Index de Pouvoir Chlorosant) or active lime tolerance % provides practical rootstock selection criteria.  This disposition represents the capacity to tolerate active lime (calcium carbonate) in soil, critically important for viticulture as many of the world's finest wine regions are located on limestone-derived soils, including Burgundy, Champagne, Chablis, parts of Bordeaux, and much of the Mediterranean basin. ||Lime-induced chlorosis results from impaired iron availability and utilization under high soil pH (> 7.5) and elevated bicarbonate (HCO₃⁻) concentrations, causing interveinal yellowing of young leaves, reduced photosynthesis, stunted growth, and in severe cases vine decline and death. ||The primary mechanisms of lime tolerance involve enhanced iron acquisition from calcareous soil (through rhizosphere acidification, increased ferric reductase activity, and efficient iron chelate uptake), tolerance of bicarbonate effects on root iron metabolism, and adaptation to consistently high rhizosphere pH. ||In grafted grapevines, Lime_Tolerance_Disposition is primarily determined by rootstock genotype, making rootstock selection the essential management tool for calcareous sites. ||Rootstock lime tolerance is commonly quantified by the \"Index de Pouvoir Chlorosant\" (IPC) or \"Active Lime Tolerance\" threshold, representing the maximum soil active lime content (% CaCO₃ extractable in ammonium oxalate) compatible with healthy growth.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bavaresco L et al. (2003) Grapevine iron nutrition and chlorosis, Plant and Soil 249:263-270|| Mengel K (1994) Iron availability in plant tissues—iron chlorosis on calcareous soils, Plant and Soil 165:275-283|| Tagliavini M, Rombolà AD (2001) Iron deficiency and chlorosis in orchard and vineyard ecosystems, European Journal of Agronomy 15:71-92"
  },
  "Rhizosphere_Acidification_Disposition": {
    "definition": "A Rhizosphere_Acidification_Disposition is an Iron_Acquisition_Efficiency_Disposition that inheres in Vitis root epidermal and cortical cells and is realized through enhanced capacity to extrude protons (H⁺) into the rhizosphere, lowering local soil pH to increase ferric iron solubility in the immediate root vicinity.", 
    "alternative_term": "proton extrusion capacity | root acidification | H⁺-ATPase activity |+ Rhizosphären-Ansäuerungs-Disposition | Protonen-Extrusion | Wurzel-Ansäuerung",
    "example_of_usage": "Detailed investigation of Rhizosphere_Acidification_Disposition at INRAE Montpellier employed pH-sensitive agar visualization, rhizosphere pH microelectrode measurements, and H⁺-ATPase activity assays across 12 rootstocks under iron-sufficient and iron-deficient conditions. ||Roots were embedded in pH indicator agar (bromocresol purple) to visualize acidification patterns, while selective microelectrodes measured pH at 50 μm from the root surface at defined positions along the root axis. ||Rhizosphere_Acidification_Disposition showed striking genotypic variation. '41B' exhibited strong, extensive acidification with yellow zones (pH < 5.5) extending 3-4 mm from root surfaces under Fe deficiency, microelectrode pH measurements of 5.8 at the root surface versus bulk pH 7.8 (2.0 unit depression), and proton efflux rates of 3.2 μmol H⁺ g⁻¹ root FW h⁻¹ representing 4.5-fold induction over Fe-sufficient controls. ||Acidification was localized primarily in the subapical zone (2-10 mm from root tip) where active iron uptake occurs. '140 Ruggeri' showed even stronger acidification (3.8 μmol H⁺ g⁻¹ h⁻¹, pH depression to 5.5), while 'Fercal' achieved intermediate but effective levels (2.4 μmol g⁻¹ h⁻¹). '3309C' displayed weak Rhizosphere_Acidification_Disposition with limited yellow zones, surface pH of only 7.2 (0.6 unit depression), and efflux of 0.9 μmol g⁻¹ h⁻¹ with only 1.8-fold induction. ||H⁺-ATPase gene expression (VvHA1) analysis confirmed that high-acidifying '41B' showed 6-fold transcript accumulation under Fe deficiency versus 2-fold in '3309C', indicating transcriptional regulation underlies genotypic differences.",
    "editor_note": "Rhizosphere_Acidification_Disposition is_a Iron_Acquisition_Efficiency_Disposition. ||Acidification is the first step in Strategy I, increasing local Fe³⁺ solubility. ||Mediated by plasma membrane H⁺-ATPases, activity localized to subapical root zones. ||Acidification capacity is iron-regulated, with strong induction under Fe deficiency in tolerant genotypes. pH reduction of 1-2 units can increase Fe solubility 100-1000 fold. ||Calcareous soil buffering capacity can limit effectiveness of acidification alone. ||VvHA genes encode the responsible H⁺-ATPases.  This disposition represents the first component of Strategy I iron acquisition, addressing the fundamental problem that Fe³⁺ solubility decreases approximately 1000-fold for each unit increase in pH above pH 4, making iron effectively unavailable at the pH 7.5-8.5 typical of calcareous soils. ||Rhizosphere acidification is mediated primarily by plasma membrane H⁺-ATPases that actively pump protons from the cytoplasm to the apoplast and soil solution, with the activity of these proton pumps increasing under iron deficiency. ||Effective acidification can reduce rhizosphere pH by 1-2 units relative to bulk soil, dramatically increasing local Fe³⁺ solubility and providing substrate for the subsequent ferric reductase reaction. ||Rhizosphere_Acidification_Disposition varies among rootstock genotypes in both the basal proton extrusion rate and the degree of upregulation under iron deficiency, with lime-tolerant genotypes typically showing 3-5 fold induction of acidification capacity under low Fe availability compared to 1.5-2 fold in sensitive genotypes. ||However, acidification capacity alone does not guarantee lime tolerance, as the high buffering capacity of calcareous soils can neutralize protons faster than roots can supply them, requiring integration with other acquisition mechanisms.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dell'Orto M et al. (2000) Fe-deficiency responses in Parietaria diffusa: a calcicole plant, Journal of Plant Nutrition 23:1719-1732|| Römheld V, Marschner H (1986) Evidence for a specific uptake system for iron phytosiderophores in roots of grasses, Plant Physiology 80:175-180|| Santi S, Schmidt W (2008) Laser microdissection-assisted analysis of the functional fate of iron deficiency-induced root hairs in cucumber, Journal of Experimental Botany 59:697-704"
  },
  "Iron_Reductase_Activity_Disposition": {
    "definition": "An Iron_Reductase_Activity_Disposition is an Iron_Acquisition_Efficiency_Disposition that inheres in Vitis root epidermal cells and is realized through high activity of plasma membrane-bound ferric chelate reductase enzymes (FRO family) that reduce solubilized Fe³⁺-chelates to Fe²⁺, the form required for uptake by IRT1 iron transporters.", 
    "alternative_term": "ferric chelate reductase | FCR activity | FRO enzyme capacity |+ Eisenreduktase-Aktivitäts-Disposition | Ferri-Chelat-Reduktase | FRO-Enzym-Kapazität",
    "example_of_usage": "Kinetic characterization of Iron_Reductase_Activity_Disposition at the University of Milan measured ferric chelate reductase (FCR) activity across 18 rootstocks using the standard Fe(III)-EDTA/BPDS assay under varying conditions of iron status (Fe-sufficient, Fe-deficient) and bicarbonate (0, 5, 10 mM NaHCO₃). ||Root segments were incubated with Fe(III)-EDTA substrate and the Fe²⁺ product was trapped and quantified by bathophenanthroline disulfonate (BPDS) formation. ||Iron_Reductase_Activity_Disposition showed remarkable genotypic variation. '41B' exhibited exceptional reductase capacity with activity increasing from 28 nmol Fe²⁺ g⁻¹ FW h⁻¹ under Fe sufficiency to 185 nmol g⁻¹ h⁻¹ under deficiency (6.6-fold induction), with activity localized to the root hair zone and subapical regions as demonstrated by histochemical staining. 'Fercal' showed similar strong induction (7.2-fold, reaching 210 nmol g⁻¹ h⁻¹). '110 Richter' displayed moderate Iron_Reductase_Activity_Disposition (125 nmol g⁻¹ h⁻¹, 4-fold induction). '3309C' exhibited weak activity with only 45 nmol g⁻¹ h⁻¹ under deficiency (2.1-fold induction) and reached maximum at lower substrate concentration, suggesting lower enzyme abundance. ||Bicarbonate sensitivity differed among rootstocks: '41B' retained 65% of reductase activity at 10 mM HCO₃⁻ while '3309C' was inhibited to 30%. ||Gene expression analysis showed that VvFRO2 transcript levels under Fe deficiency were 8-fold higher in '41B' than '3309C', correlating with activity differences (r = 0.91 between expression and activity across genotypes). ||These findings establish Iron_Reductase_Activity_Disposition as a key discriminating trait for lime tolerance.",
    "editor_note": "Iron_Reductase_Activity_Disposition is_a Iron_Acquisition_Efficiency_Disposition. ||Ferric reductase provides the obligatory reduction of Fe³⁺ to Fe²⁺ for uptake. ||Activity is highly iron-regulated, with tolerant genotypes showing stronger induction. ||VvFRO genes encode the ferric reductase enzymes. ||Bicarbonate directly inhibits reductase activity, with tolerant genotypes showing less sensitivity. ||Reductase activity often correlates better with field lime tolerance than acidification alone. ||Activity is localized to root hair zone and subapical epidermis.  This disposition represents the second and often rate-limiting component of Strategy I iron acquisition, providing the essential reduction step linking Fe³⁺ solubilization (by acidification) to Fe²⁺ uptake (by IRT transporters). ||Ferric reductase activity is obligatory because IRT1 transporters accept only Fe²⁺, while iron in calcareous soils and most organic chelates exists as Fe³⁺. ||The ferric reductase operates at the root cell plasma membrane, accepting electrons from cytoplasmic NADPH and transferring them across the membrane to reduce extracellular Fe³⁺-chelate complexes, releasing Fe²⁺ for immediate uptake by co-localized IRT1 transporters. ||Iron_Reductase_Activity_Disposition varies substantially among rootstock genotypes in both constitutive activity levels and the magnitude of upregulation under iron deficiency, with lime-tolerant genotypes typically showing 4-8 fold induction of reductase activity under Fe deficiency compared to 1.5-3 fold in sensitive genotypes. ||The enzyme is sensitive to bicarbonate inhibition, contributing to the chlorosis-inducing effect of high soil HCO₃⁻, with tolerant genotypes showing less bicarbonate sensitivity.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Brancadoro L et al. (1995) Mechanisms of Fe-efficiency in roots of Vitis spp. in response to iron deficiency stress, Plant and Soil 171:229-234|| Robinson NJ et al. (1999) A ferric-chelate reductase for iron uptake from soils, Nature 397:694-697|| Ksouri R et al. (2006) Genotypic variability within Tunisian grapevine varieties (Vitis vinifera L.) facing bicarbonate-induced iron deficiency, Plant Physiology and Biochemistry 44:315-322"
  },
  "Iron_Chelate_Uptake_Disposition": {
    "definition": "An Iron_Chelate_Uptake_Disposition is an Iron_Acquisition_Efficiency_Disposition that inheres in Vitis root epidermal cells and is realized through efficient uptake of ferrous iron (Fe²⁺) produced by ferric reductase activity, transporting iron across the plasma membrane into root cells via IRT1 (Iron-Regulated Transporter 1) and related transporters.", 
    "alternative_term": "IRT1-mediated uptake | ferrous iron transport | Fe²⁺ uptake capacity |+ Eisen-Chelat-Aufnahme-Disposition | IRT1-vermittelte-Aufnahme | Fe²⁺-Transport-Kapazität",
    "example_of_usage": "Investigation of Iron_Chelate_Uptake_Disposition at the University of Reims combined ⁵⁹Fe uptake kinetics with VvIRT1 gene expression analysis across 10 rootstocks under iron-sufficient and iron-deficient conditions. ||Short-term (30 min) ⁵⁹Fe²⁺ uptake was measured at Fe concentrations from 0.1 to 50 μM to determine Vmax and Km parameters, while qRT-PCR quantified VvIRT1 transcript abundance. ||Iron_Chelate_Uptake_Disposition showed significant genotypic variation, though less dramatic than reductase activity differences. ||Under Fe deficiency, '41B' exhibited high uptake capacity with Vmax of 52 nmol Fe g⁻¹ FW h⁻¹ and Km of 3.2 μM, accompanied by 35-fold induction of VvIRT1 expression relative to Fe-sufficient controls. 'Fercal' showed similar uptake parameters (Vmax 48, Km 2.8 μM) with 40-fold IRT1 induction. '3309C' displayed lower Iron_Chelate_Uptake_Disposition with Vmax of 28 nmol g⁻¹ h⁻¹ and higher Km of 5.5 μM (indicating lower affinity), with only 12-fold IRT1 induction. ||The uptake/reductase activity ratio (indicating coupling efficiency) varied from 0.28 in '41B' (efficient coupling) to 0.62 in '3309C' (less efficient, with more reductase activity than uptake capacity can utilize), suggesting that '3309C' loses a portion of generated Fe²⁺ to reoxidation before uptake. ||Importantly, differences in Iron_Chelate_Uptake_Disposition were smaller (2-fold range) than reductase differences (4-fold range), confirming that reductase activity is typically rate-limiting. ||However, under bicarbonate stress where Fe²⁺ reoxidation is accelerated, high uptake capacity and tight reductase-transporter coupling become more critical.",
    "editor_note": "Iron_Chelate_Uptake_Disposition is_a Iron_Acquisition_Efficiency_Disposition. ||IRT1 mediates Fe²⁺ uptake, completing the Strategy I pathway. ||Expression is highly iron-regulated (10-50 fold induction under deficiency). ||Uptake is typically not rate-limiting (reductase is), but coupling efficiency matters under field conditions where Fe²⁺ reoxidation competes with uptake. ||IRT1 also transports Mn²⁺, Zn²⁺, and potentially toxic Cd²⁺. ||VvIRT1 encodes the main iron transporter. ||Kinetic parameters (Vmax, Km) characterize uptake capacity and affinity.  This disposition represents the third component of Strategy I iron acquisition, completing the soil-to-cell pathway by importing the Fe²⁺ generated by reductase activity. ||Efficient uptake requires both adequate transporter expression (determined by iron regulatory networks) and functional coupling with reductase activity so that Fe²⁺ produced at the membrane surface is captured before reoxidation to Fe³⁺ in the alkaline rhizosphere. ||IRT1 belongs to the ZIP (Zinc/Iron-regulated transporter Protein) family and is highly induced under iron deficiency, with transcript and protein levels increasing 10-50 fold in deficient roots. ||Iron_Chelate_Uptake_Disposition varies among genotypes in both IRT1 expression levels and the efficiency of coupling between reduction and uptake. ||While uptake capacity rarely limits iron acquisition under laboratory conditions (reductase activity is typically rate-limiting), field performance may depend on uptake efficiency when reductase-generated Fe²⁺ is rapidly reoxidized in high-pH, high-bicarbonate soil environments. ||Additionally, IRT1 transports other divalent cations (Mn²⁺, Zn²⁺, Cd²⁺), and selectivity for iron versus competing metals may differ among genotypes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Eide D et al. (1996) A novel iron-regulated metal transporter from plants identified by functional expression in yeast, Proceedings of the National Academy of Sciences 93:5624-5628|| Vert G et al. (2002) IRT1, an Arabidopsis transporter essential for iron uptake from the soil and for plant growth, Plant Cell 14:1223-1233|| Korshunova YO et al. (1999) The IRT1 protein from Arabidopsis thaliana is a metal transporter with a broad substrate range, Plant Molecular Biology 40:37-44"
  },
  "Bicarbonate_Tolerance_Disposition": {
    "definition": "A Bicarbonate_Tolerance_Disposition is a Lime_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that maintain iron acquisition and metabolism despite the inhibitory effects of bicarbonate ions (HCO₃⁻) on iron uptake processes and internal iron utilization.", 
    "alternative_term": "HCO₃⁻ tolerance | bicarbonate stress resistance | carbonate tolerance |+ Bikarbonat-Toleranz-Disposition | HCO₃⁻-Toleranz | Karbonat-Stressresistenz",
    "example_of_usage": "Mechanistic investigation of Bicarbonate_Tolerance_Disposition at INRAE Bordeaux employed hydroponic culture with factorial combinations of iron supply (1, 10 μM Fe-EDDHA) and bicarbonate (0, 5, 10, 15 mM NaHCO₃) across 14 rootstocks to separate bicarbonate-specific effects from general pH effects (pH maintained at 7.5 throughout). ||Measurements included leaf chlorophyll, total and active (Fe²⁺) iron, root ferric reductase activity, and xylem sap iron concentration. ||Bicarbonate_Tolerance_Disposition showed strong genotypic variation independent of overall lime tolerance capacity. '41B' exhibited exceptional Bicarbonate_Tolerance_Disposition, maintaining 85% of control SPAD values at 10 mM HCO₃⁻, with ferric reductase retaining 68% activity, xylem sap Fe concentration declining only 25% (from 48 to 36 μM), and leaf active Fe proportion remaining at 42% of total Fe. 'Fercal' showed similar bicarbonate resistance (80% SPAD retention, 65% reductase retention). '110 Richter', despite reasonable overall lime tolerance, displayed moderate Bicarbonate_Tolerance_Disposition (65% SPAD, 45% reductase at 10 mM HCO₃⁻). '3309C' showed extreme bicarbonate sensitivity with SPAD declining to 35% of control, reductase inhibited to 22%, xylem Fe reduced 60%, and leaf active Fe proportion collapsing to only 12% of total (severe Fe inactivation). ||Dose-response analysis established IC50 values (HCO₃⁻ concentration causing 50% parameter reduction) ranging from 14.5 mM for '41B' reductase to 4.2 mM for '3309C', quantifying the 3.5-fold difference in Bicarbonate_Tolerance_Disposition. ||These findings demonstrate that bicarbonate specifically affects both Fe acquisition and utilization, with tolerant rootstocks showing resistance at both levels.",
    "editor_note": "Bicarbonate_Tolerance_Disposition is_a Lime_Tolerance_Disposition. ||Bicarbonate exerts specific effects beyond pH on iron nutrition, including direct reductase inhibition, acidification neutralization, and Fe inactivation in leaves. ||The \"iron chlorosis paradox\" (high total Fe, low active Fe) reflects bicarbonate-induced inactivation. ||Bicarbonate tolerance is partially independent of overall lime tolerance, providing distinct selection criteria. ||IC50 values quantify bicarbonate sensitivity of specific processes. ||Active lime (extractable CaCO₃) correlates with soil solution bicarbonate, explaining IPC predictive value.  This disposition represents tolerance to the specific and potent chlorosis-inducing factor in calcareous soils—bicarbonate—which exerts effects beyond simply raising pH. ||Bicarbonate concentrations in calcareous soil solution can reach 5-15 mM and cause chlorosis even when external pH is artificially controlled, indicating direct biochemical effects on iron nutrition. ||Bicarbonate inhibits iron acquisition through multiple mechanisms including direct inhibition of ferric reductase activity (HCO₃⁻ affects enzyme kinetics), neutralization of rhizosphere acidification (consuming protons extruded by roots), inhibition of iron translocation from roots to shoots, and impairment of iron reduction and utilization within leaves leading to Fe³⁺ accumulation in inactive forms. ||Bicarbonate_Tolerance_Disposition encompasses resistance to all these effects, with tolerant genotypes maintaining higher iron acquisition and utilization efficiency at equivalent bicarbonate concentrations. ||The \"iron chlorosis paradox\"—high total iron but low active iron in chlorotic leaves—reflects bicarbonate-induced Fe inactivation, and genotypes with strong Bicarbonate_Tolerance_Disposition show higher proportions of metabolically active Fe²⁺ in their leaf tissues.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mengel K et al. (1984) Effect of bicarbonate on iron nutrition of chlorosis-susceptible plants, Journal of Plant Nutrition 7:1467-1489|| Nikolic M, Römheld V (2002) Does high bicarbonate supply to roots change availability of iron in the leaf apoplast?, Plant and Soil 241:67-74|| Kosegarten H et al. (1999) Effect of bicarbonate on iron acquisition of sunflower and bean, Journal of Plant Nutrition 22:1147-1159"
  },
  "High_pH_Adaptation_Disposition": {
    "definition": "A High_pH_Adaptation_Disposition is a Lime_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological mechanisms that enable normal metabolic function and nutrient acquisition across roots exposed to consistently elevated soil pH (7.5-8.5) typical of calcareous environments, beyond the specific challenges of iron acquisition.", 
    "alternative_term": "alkaline soil adaptation | high pH tolerance | calcareous environment adaptation |+ Hoch-pH-Anpassungs-Disposition | Alkaliboden-Adaptation | Kalkumgebungs-Anpassung",
    "example_of_usage": "Comprehensive assessment of High_pH_Adaptation_Disposition at the University of Udine evaluated rootstock performance at pH levels from 5.5 to 8.5 (0.5 unit increments) with iron supplied as Fe-EDDHA (stable across pH range) to separate pH effects from iron availability effects. ||Measurements included root and shoot growth, root morphology (length, branching, root hair development), nutrient uptake efficiency (N, P, K, Mn, Zn, Cu), and cytoplasmic pH maintenance (using pH-sensitive fluorescent probes). ||High_pH_Adaptation_Disposition showed genotypic variation partially independent of iron acquisition efficiency. 'Fercal' demonstrated strong High_pH_Adaptation_Disposition with shoot growth at pH 8.5 reaching 92% of optimal pH (5.5-6.5) performance when Fe was non-limiting, normal root branching and hair development, and maintenance of root cortical cytoplasmic pH at 7.1-7.3 across external pH range (effective homeostasis). ||Manganese and zinc uptake efficiency decreased only 20-25% at pH 8.5. '41B' showed similarly strong adaptation (88% growth retention, stable cytoplasmic pH). 'SO4' displayed moderate High_pH_Adaptation_Disposition (72% growth at pH 8.5), with reduced root hair development and 40% decline in Mn uptake at high pH indicating some pH sensitivity beyond Fe effects. '3309C' exhibited poor adaptation with growth declining to 55% at pH 8.5 even with adequate Fe, impaired root hair formation, cytoplasmic pH stress (rising to 7.6, indicating homeostasis failure), and 55% reduction in Mn uptake. ||These findings demonstrate that High_pH_Adaptation_Disposition contributes to calcareous soil performance beyond iron acquisition capacity.",
    "editor_note": "High_pH_Adaptation_Disposition is_a Lime_Tolerance_Disposition. ||High pH affects multiple aspects of plant function beyond iron availability including other micronutrients, membrane transport, and cellular pH homeostasis. ||Assessing pH adaptation requires supplying iron in pH-stable form to separate effects. ||Cytoplasmic pH homeostasis (maintaining pH 7.0-7.5 despite external alkalinity) is a key component. ||Mn, Zn, Cu availability all decline at high pH, contributing to growth limitation. ||High pH adaptation is partially independent of iron acquisition efficiency, representing an additional tolerance component.  This disposition represents broad adaptation to alkaline conditions, addressing the multiple nutritional and physiological challenges of high-pH soils that extend beyond iron availability. ||High soil pH affects availability of multiple nutrients (reducing availability of Fe, Mn, Zn, Cu, B|| potentially increasing Mo to toxic levels), alters root membrane function and transport processes, affects rhizosphere microbial communities, and can directly impact root cell metabolism through effects on cytoplasmic pH regulation. ||While iron deficiency is typically the most limiting factor on calcareous soils, adaptation to other high-pH effects contributes to overall lime tolerance. ||High_pH_Adaptation_Disposition encompasses maintenance of cytoplasmic pH homeostasis despite alkaline external environment, adaptation of nutrient transporters to function at high apoplastic pH, adjustment of organic acid metabolism, and tolerance of altered micronutrient availability profiles. ||Genotypes with strong High_pH_Adaptation_Disposition show normal growth and function at pH 8.0-8.5 when iron is supplied in available form, while sensitive genotypes may show reduced performance even with adequate iron, indicating pH effects beyond Fe acquisition.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mengel K (1994) Iron availability in plant tissues—iron chlorosis on calcareous soils, Plant and Soil 165:275-283|| Marschner H (1995) Mineral Nutrition of Higher Plants, 2nd Edition, Academic Press, London|| Tang C et al. (2009) Mechanisms of plant adaptation to alkaline soil, Australian Journal of Experimental Agriculture 49:866-874"
  },
  "Waterlogging_Tolerance_Disposition": {
    "definition": "A Waterlogging_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis plant and is realized through physiological, anatomical, and metabolic mechanisms that enable survival and continued function under soil flooding conditions where oxygen availability to roots is severely restricted, causing hypoxia or anoxia that would otherwise lead to root death, impaired water and nutrient uptake, and vine decline.", 
    "alternative_term": "flooding tolerance | hypoxia tolerance | excess water tolerance |+ Staunässe-Toleranz-Disposition | Überflutungs-Toleranz | Hypoxie-Toleranz",
    "example_of_usage": "Comprehensive evaluation of Waterlogging_Tolerance_Disposition at the University of Florida compared survival, growth, and physiological responses across 15 rootstocks subjected to complete soil waterlogging for 30 days during the growing season. ||Measurements included survival rate, shoot growth, leaf gas exchange, root morphology (adventitious root formation, aerenchyma presence), and root ATP concentration as indicator of energy status. ||Waterlogging_Tolerance_Disposition varied dramatically among rootstocks. 'Riparia Gloire' (V. riparia) exhibited exceptional tolerance with 100% survival, shoot growth continuing at 65% of control rate, stomatal conductance maintained at 55% of control through formation of adventitious roots (12.5 new roots per plant in aerated surface zone), visible aerenchyma in 45% of root cross-sectional area, and root ATP maintained at 48% of control levels. '1103 Paulsen' (V. berlandieri × V. rupestris) showed good tolerance (95% survival, 50% growth rate, 35% aerenchyma). ||In contrast, '140 Ruggeri' (V. berlandieri × V. rupestris, but from drier ecotype) displayed poor Waterlogging_Tolerance_Disposition with only 55% survival, growth cessation by day 10, minimal adventitious rooting (2.3 roots/plant), negligible aerenchyma (8% of cross-section), and root ATP collapsing to 12% of control. 'Schwarzmann' showed intermediate tolerance (80% survival, 40% growth). ||Notably, waterlogging tolerance showed weak correlation with drought tolerance (r = 0.25), indicating these represent distinct adaptive syndromes. ||These findings demonstrate that Waterlogging_Tolerance_Disposition involves coordinated anatomical and metabolic adaptations that vary substantially among rootstock genotypes.",
    "editor_note": "Waterlogging_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||Waterlogging tolerance is primarily determined by rootstock genotype. ||The core problem is root oxygen deprivation, not excess water per se. ||Child classes address specific mechanisms including Adventitious_Root_Formation_Disposition, Aerenchyma_Formation_Disposition, and Anaerobic_Metabolism_Disposition. ||V. riparia and V. rupestris (riparian origins) generally show superior tolerance. ||Waterlogging tolerance is largely independent of drought tolerance, reflecting different adaptive origins.  This disposition represents the capacity to tolerate excess soil water, important for viticulture in regions with heavy clay soils, high water tables, or periodic flooding, and increasingly relevant as climate change intensifies precipitation events in many wine regions. ||Waterlogging stress results primarily from oxygen deprivation as soil pore spaces fill with water, limiting oxygen diffusion to roots (10,000× slower in water than air), and secondarily from accumulation of toxic reduced compounds (Fe²⁺, Mn²⁺, H₂S) in anaerobic soil and potentially from pathogen pressure in wet conditions. ||Root hypoxia impairs aerobic respiration, forcing reliance on inefficient fermentative pathways, depleting carbohydrate reserves, and disrupting ATP-dependent processes including ion uptake and phytohormone synthesis. ||Waterlogging_Tolerance_Disposition encompasses anatomical adaptations (adventitious root formation providing roots in aerated surface zones, aerenchyma development creating internal oxygen transport pathways), metabolic adaptations (efficient anaerobic metabolism, tolerance of fermentation end-products), and hormonal responses (ethylene-mediated adaptive responses). ||In grafted grapevines, rootstock genotype is the primary determinant of waterlogging tolerance, with species from riparian habitats (V. riparia, V. rupestris) generally showing superior tolerance compared to those from well-drained hillside environments.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kozlowski TT (1997) Responses of woody plants to flooding and salinity, Tree Physiology Monograph 1:1-29|| Dat JF et al. (2004) Sensing and signalling during plant flooding, Plant Physiology and Biochemistry 42:273-282|| Striegler RK et al. (1993) Influence of rootstock on the response of grapevines to flooding stress, American Journal of Enology and Viticulture 44:313-319"
  },
  "Adventitious_Root_Formation_Disposition": {
    "definition": "An Adventitious_Root_Formation_Disposition is a Waterlogging_Tolerance_Disposition that inheres in a Vitis plant and is realized through the capacity to rapidly initiate and develop new roots from stem tissues above the waterlogged zone, providing functional root surface in aerated soil or water layers when original roots are compromised by hypoxia.", 
    "alternative_term": "flood-induced rooting | hypoxia-induced adventitious roots | stem root formation |+ Adventivwurzel-Bildungs-Disposition | Überflutungs-induzierte-Bewurzelung | Sprossachsen-Wurzelbildung",
    "example_of_usage": "Detailed characterization of Adventitious_Root_Formation_Disposition at Cornell University tracked adventitious root development across 12 rootstocks during 21 days of waterlogging in transparent root observation chambers. ||Daily counts of emerging adventitious roots, root elongation rates, and anatomical analysis of developed roots were conducted. ||Ethylene production and auxin (IAA) concentration in stem bases were measured to assess hormonal triggers. ||Adventitious_Root_Formation_Disposition showed striking genotypic variation. 'Riparia Gloire' exhibited rapid, prolific adventitious rooting with first visible root emergence at day 3, peak initiation rate of 2.8 roots per day (days 5-8), total of 18.5 adventitious roots by day 21, and root elongation rate of 3.2 cm/day. ||Ethylene production in 'Riparia Gloire' stem bases increased 8-fold within 24 hours of waterlogging, with IAA accumulation in the rooting zone reaching 285 ng/g FW (3.5× control). '3309C' (V. riparia × V. rupestris) showed similarly strong response (15.2 roots, 2.6 cm/day elongation). '110 Richter' displayed moderate Adventitious_Root_Formation_Disposition (8.5 roots, first emergence day 6, 1.8 cm/day elongation) with weaker hormonal response (5-fold ethylene, 2× IAA). '140 Ruggeri' exhibited poor adventitious rooting (3.2 roots, emergence delayed to day 10, 0.9 cm/day) associated with only 3-fold ethylene increase and minimal IAA redistribution. ||Functional assessment revealed that adventitious roots of 'Riparia Gloire' supplied 72% of total vine water uptake by day 21, compensating for original root dysfunction, while '140 Ruggeri' adventitious roots contributed only 18%. ||These findings demonstrate that Adventitious_Root_Formation_Disposition involves both hormonal responsiveness and developmental capacity for rapid root initiation.",
    "editor_note": "Adventitious_Root_Formation_Disposition is_a Waterlogging_Tolerance_Disposition. ||Adventitious rooting is triggered by ethylene accumulation (trapped in waterlogged tissues) and auxin redistribution. ||Root primordia may be pre-formed or initiated de novo. ||Speed of initiation (days to emergence) and total root number both contribute to flooding survival. ||Adventitious roots often show enhanced aerenchyma compared to original roots. ||V. riparia shows particularly strong adventitious rooting, consistent with riparian habitat adaptation.  This disposition represents a key escape mechanism from waterlogging stress, enabling plants to establish a new functional root system in oxygen-rich zones while original roots may be dying or dysfunctional in anaerobic soil. ||Adventitious roots form from pre-existing root primordia in stem tissues or from de novo initiation at the cambium, with the process triggered by the hormonal changes associated with root hypoxia—particularly the accumulation of ethylene (trapped in waterlogged tissues due to slow diffusion in water) and changes in auxin transport and distribution. ||Adventitious roots that develop into aerated water or saturated surface soil layers are physiologically functional, capable of water and nutrient uptake, and often show enhanced aerenchyma formation facilitating oxygen transport to submerged portions. ||Adventitious_Root_Formation_Disposition varies among genotypes in the speed of initiation (days from waterlogging onset to visible root emergence), the number and vigor of adventitious roots produced, and the functional capacity of these roots to replace original root function. ||Genotypes with strong adventitious rooting can maintain vine function through extended waterlogging that would kill genotypes lacking this capacity.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Steffens B, Rasmussen A (2016) The physiology of adventitious roots, Plant Physiology 170:603-617|| Visser EJW et al. (1996) Ethylene accumulation in waterlogged Rumex plants promotes formation of adventitious roots, Journal of Experimental Botany 47:403-410|| Vidoz ML et al. (2010) Hormonal interplay during adventitious root formation in flooded tomato plants, Plant Journal 63:551-562"
  },
  "Aerenchyma_Formation_Disposition": {
    "definition": "An Aerenchyma_Formation_Disposition is a Waterlogging_Tolerance_Disposition that inheres in Vitis root and stem tissues and is realized through the formation of aerenchyma—interconnected air-filled spaces within the cortex that create a low-resistance pathway for oxygen diffusion from aerial plant parts to submerged roots, alleviating hypoxia in waterlogged tissues.", 
    "alternative_term": "cortical air space formation | internal aeration | lysigenous aerenchyma development |+ Aerenchym-Bildungs-Disposition | Kortikale-Luftraum-Bildung | Interne-Belüftung",
    "example_of_usage": "Anatomical investigation of Aerenchyma_Formation_Disposition at INRAE Bordeaux employed microscopic analysis of root cross-sections across 10 rootstocks at 0, 7, 14, and 21 days of waterlogging. ||Aerenchyma was quantified as percentage of cortex cross-sectional area occupied by air spaces, with parallel measurement of root oxygen concentration using microelectrodes and ethylene evolution (trigger signal). ||Aerenchyma_Formation_Disposition varied substantially among rootstocks. 'Riparia Gloire' showed rapid, extensive aerenchyma formation, increasing from 5% (constitutive) at day 0 to 25% at day 7 and 48% at day 21, with lysigenous origin confirmed by TUNEL staining for programmed cell death. ||Root internal oxygen concentration 15 cm from the waterline was maintained at 8.2% (versus atmospheric 21%) in 'Riparia Gloire' versus anoxic (< 0.5%) in low-aerenchyma genotypes. '3309C' displayed similar Aerenchyma_Formation_Disposition (45% by day 21, internal O₂ 7.5%). 'SO4' showed intermediate aerenchyma (32% maximum, internal O₂ 4.8%). '140 Ruggeri' exhibited poor Aerenchyma_Formation_Disposition with only 12% aerenchyma by day 21 and internal O₂ collapsing to 1.2%. ||Ethylene sensitivity differed among genotypes, with 'Riparia Gloire' root cortex showing aerenchyma initiation at ethylene concentration of 0.5 μL/L while '140 Ruggeri' required 2.5 μL/L for equivalent response. ||Interestingly, adventitious roots showed 1.5× higher aerenchyma percentage than original roots across all genotypes, suggesting adventitious roots are pre-adapted for oxygen-limited environments. ||Correlation between aerenchyma percentage at day 14 and waterlogging survival was strong (r = 0.89), confirming the functional importance of Aerenchyma_Formation_Disposition.",
    "editor_note": "Aerenchyma_Formation_Disposition is_a Waterlogging_Tolerance_Disposition. ||Aerenchyma provides internal oxygen transport pathway from shoots to submerged roots. ||Formation is typically inducible (triggered by hypoxia/ethylene) rather than constitutive in grapevine. ||Lysigenous aerenchyma involves programmed cell death|| schizogenous involves cell separation. ||Effective aerenchyma can occupy 20-50% of cortical cross-section. ||Oxygen transport distance depends on aerenchyma continuity and cross-sectional area. ||Adventitious roots often show enhanced aerenchyma compared to original roots.  This disposition represents the primary anatomical adaptation enabling internal oxygen transport when external oxygen supply through soil is blocked by water. ||Aerenchyma forms either constitutively (present in well-drained conditions, typical of wetland-adapted species) or inducibly (developing in response to waterlogging, typical of facultatively tolerant species including most Vitis). ||In grapevine, aerenchyma is predominantly inducible, forming through lysigenous development (programmed cell death creating air spaces) or schizogenous development (cell separation without death) in root cortical tissues. ||The extent of aerenchyma formation determines the oxygen transport capacity, with effective aerenchyma potentially occupying 20-50% of root cross-sectional area and enabling oxygen diffusion over distances of 20-30 cm in submerged roots. ||Aerenchyma_Formation_Disposition varies among genotypes in the speed of induction following waterlogging onset, the maximum aerenchyma volume achieved, the extent of interconnection between air spaces (critical for effective transport), and whether aerenchyma forms in adventitious roots as well as original roots.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Evans DE (2004) Aerenchyma formation, New Phytologist 161:35-49|| Colmer TD (2003) Long-distance transport of gases in plants: a perspective on internal aeration and radial oxygen loss from roots, Plant Cell and Environment 26:17-36|| Jackson MB, Armstrong W (1999) Formation of aerenchyma and the processes of plant ventilation in relation to soil flooding and submergence, Plant Biology 1:274-287"
  },
  "Anaerobic_Metabolism_Disposition": {
    "definition": "An Anaerobic_Metabolism_Disposition is a Waterlogging_Tolerance_Disposition that inheres in Vitis root tissues and is realized through metabolic adaptations that enable continued ATP production and cellular function when oxygen availability is insufficient for aerobic respiration, utilizing fermentative pathways and tolerating their byproducts.", 
    "alternative_term": "fermentative metabolism | hypoxic metabolism | anaerobic respiration capacity |+ Anaerober-Stoffwechsel-Disposition | Fermentativer-Metabolismus | Hypoxie-Stoffwechsel",
    "example_of_usage": "Biochemical characterization of Anaerobic_Metabolism_Disposition at UC Davis examined fermentative enzyme activities, end-product accumulation, and energy status across 12 rootstocks subjected to strict root anoxia (N₂-flushed nutrient solution) for 72 hours. ||Activities of alcohol dehydrogenase (ADH) and pyruvate decarboxylase (PDC), tissue concentrations of ethanol, lactate, and ATP, and cytoplasmic pH (by ³¹P-NMR) were measured at 0, 24, 48, and 72 hours. ||Anaerobic_Metabolism_Disposition showed significant genotypic variation in multiple parameters. 'Riparia Gloire' exhibited strong anaerobic capacity with ADH activity increasing 8.5-fold within 24 hours (to 4.2 μmol min⁻¹ g⁻¹ FW), PDC activity increasing 6-fold, ethanol accumulating to moderate levels (12 mM at 72h, then declining suggesting export/volatilization), lactate remaining low (2.5 mM), and cytoplasmic pH stable at 7.1 (no acidification). ||Root ATP in 'Riparia Gloire' declined to 35% of aerobic control but stabilized at this level, indicating sustained energy production. '3309C' showed similar metabolic adaptation (8-fold ADH induction, stable pH, 38% ATP maintenance). '140 Ruggeri' displayed poor Anaerobic_Metabolism_Disposition with only 3-fold ADH induction, high lactate accumulation (8.5 mM) indicating metabolic imbalance, cytoplasmic acidification (pH declining to 6.5 by 72h), and ATP collapsing to 8% of control. ||Upon re-aeration, 'Riparia Gloire' cleared accumulated ethanol within 6 hours and restored ATP to 85% of control by 24 hours, while '140 Ruggeri' showed persistent metabolic dysfunction (ATP recovery to only 45%) suggesting irreversible damage. ||These findings establish that Anaerobic_Metabolism_Disposition involves both efficient fermentative enzyme induction and metabolic regulation preventing self-toxicity.",
    "editor_note": "Anaerobic_Metabolism_Disposition is_a Waterlogging_Tolerance_Disposition. ||Fermentative metabolism provides ATP when oxygen is limiting but is inherently inefficient (2-3 vs 36-38 ATP/glucose). ||ADH and PDC are key fermentative enzymes, with inducibility varying among genotypes. ||Ethanol pathway preferred over lactate to avoid cytoplasmic acidification. ||Carbohydrate reserve depletion is a major constraint under extended anoxia. ||Recovery upon re-aeration depends on capacity to clear accumulated end-products and restore aerobic metabolism.  This disposition represents the biochemical component of waterlogging tolerance, determining how effectively roots can maintain energy production and metabolic function under oxygen deprivation when anatomical adaptations (aerenchyma, adventitious roots) are insufficient to fully alleviate hypoxia. ||Anaerobic metabolism in plant roots involves glycolysis coupled to ethanolic fermentation (via pyruvate decarboxylase and alcohol dehydrogenase) or lactic acid fermentation, yielding only 2-3 ATP per glucose compared to 36-38 from aerobic respiration. ||Survival under hypoxia requires efficient glycolytic flux to maintain ATP supply despite low yield, tolerance of fermentation end-products (ethanol, acetaldehyde) that can reach toxic concentrations, avoidance of cytoplasmic acidification from lactate accumulation, and conservation of carbohydrate reserves that are rapidly depleted by inefficient fermentative metabolism. ||Anaerobic_Metabolism_Disposition varies among genotypes in the inducibility and activity of fermentative enzymes (ADH, PDC), the balance between ethanol and lactate production (ethanol pathway generally less acidifying), the capacity to export or metabolize accumulated fermentation products upon re-aeration, and the efficiency of ATP utilization enabling function at reduced energy supply.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Drew MC (1997) Oxygen deficiency and root metabolism: injury and acclimation under hypoxia and anoxia, Annual Review of Plant Physiology and Plant Molecular Biology 48:223-250|| Gibbs J, Greenway H (2003) Mechanisms of anoxia tolerance in plants. I. Growth, survival and anaerobic catabolism, Functional Plant Biology 30:1-47|| Ismond KP et al. (2003) Enhanced low oxygen survival in Arabidopsis through increased metabolic flux in the fermentative pathway, Plant Physiology 132:1292-1302"
  },
  "UV_Tolerance_Disposition": {
    "definition": "A UV_Tolerance_Disposition is an Abiotic_Stress_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through physiological mechanisms that protect tissues from damage caused by ultraviolet radiation (UV-A, 315-400 nm|| UV-B, 280-315 nm) through a combination of UV screening, damage repair, and antioxidant defense.", 
    "alternative_term": "ultraviolet radiation tolerance | solar UV protection | UV-B resistance |+ UV-Toleranz-Disposition | Ultraviolett-Toleranz | Solare-UV-Resistenz",
    "example_of_usage": "Systematic evaluation of UV_Tolerance_Disposition at the University of Burgundy employed supplemental UV-B exposure (ambient + 8 kJ m⁻² d⁻¹ biologically effective UV-B for 21 days) across 20 cultivars, assessing damage indicators (DNA lesion frequency, lipid peroxidation, PSII efficiency) and protection mechanisms (epidermal UV absorbance, flavonoid content, DNA repair rate). ||UV_Tolerance_Disposition showed substantial cultivar variation. 'Malbec' (high-altitude Argentinian adaptation) exhibited strong tolerance with epidermal UV-B transmittance of only 8% (effective screening), leaf flavonoid content of 2.8 mg/g FW (quercetin glycosides dominant), DNA lesion frequency 65% lower than sensitive cultivars, and PSII efficiency (Fv/Fm) declining only 5% under UV treatment. 'Chasselas' (temperate Swiss origin) showed poor UV_Tolerance_Disposition with epidermal transmittance of 22%, flavonoid content of 1.1 mg/g, high DNA lesion accumulation, and 18% PSII decline. 'Gewürztraminer' displayed intermediate characteristics. ||Interestingly, 'Pinot Noir' showed moderate screening capacity but exceptional DNA repair, with cyclobutane pyrimidine dimer (CPD) removal rate of 78% within 4 hours of UV cessation (photoreactivation pathway) versus 45% in 'Chasselas'. ||Berry UV tolerance partially paralleled leaf tolerance but with distinct patterns—'Malbec' berries showed exceptional anthocyanin stability under UV while 'Pinot Noir' anthocyanins were more UV-labile despite adequate leaf protection. ||These findings demonstrate that UV_Tolerance_Disposition involves multiple mechanisms that vary independently among cultivars.",
    "editor_note": "UV_Tolerance_Disposition is_a Abiotic_Stress_Tolerance_Disposition. ||UV tolerance involves screening (preventing damage), repair (fixing damage), and tolerance (functioning despite damage). ||Child classes address Flavonoid_Accumulation_Disposition (screening) and DNA_Repair_Disposition (repair). ||UV exposure is increasing at many vineyard sites due to climate patterns and altitude shifts. ||Cultivars from high-altitude or low-latitude origins often show enhanced UV protection. ||UV effects on berry composition (flavonoids, aroma precursors) have quality implications beyond stress tolerance.  This disposition represents the capacity to tolerate UV exposure, important for viticulture as vineyards are often located in high-UV environments including high-altitude sites, Mediterranean climates with clear skies, and Southern Hemisphere locations with reduced ozone protection. ||UV radiation causes multiple types of damage including direct DNA lesions (cyclobutane pyrimidine dimers, 6-4 photoproducts), protein damage, lipid peroxidation through reactive oxygen species generation, and photosystem damage affecting photosynthetic function. ||UV exposure also triggers signaling pathways affecting gene expression, hormone levels, and secondary metabolism, with some UV effects being adaptive (inducing protective responses) rather than purely damaging. ||UV_Tolerance_Disposition encompasses UV screening capacity (accumulation of UV-absorbing compounds in the epidermis preventing penetration to sensitive underlying tissues), efficient DNA repair mechanisms (photoreactivation and nucleotide excision repair), enhanced antioxidant capacity (neutralizing UV-generated ROS), and tolerance of unavoidable damage at the cellular level. ||Grapevine shows substantial genotypic variation in UV tolerance, with cultivars adapted to high-altitude or low-latitude origins generally showing enhanced protection compared to those from more temperate regions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Frohnmeyer H, Staiger D (2003) Ultraviolet-B radiation-mediated stress responses in plants, Trends in Plant Science 8:135-141|| Jansen MAK et al. (1998) Higher plants and UV-B radiation: balancing damage, repair and acclimation, Trends in Plant Science 3:131-135|| Berli FJ et al. (2010) UV-B impairs growth and gas exchange in grapevines grown in high altitude, Physiologia Plantarum 138:146-155"
  },
  "Flavonoid_Accumulation_Disposition": {
    "definition": "A Flavonoid_Accumulation_Disposition is a UV_Tolerance_Disposition that inheres in a Vitis vinifera plant and is realized through enhanced capacity to synthesize and accumulate UV-absorbing flavonoid compounds in epidermal tissues, creating a chemical sunscreen that prevents UV penetration to underlying sensitive mesophyll cells, chloroplasts, and nuclei.", 
    "alternative_term": "UV-screening compound accumulation | phenylpropanoid UV protection | epidermal flavonoid synthesis |+ Flavonoid-Akkumulations-Disposition | UV-Schutzverbindungs-Akkumulation | Epidermale-Flavonoid-Synthese",
    "example_of_usage": "Detailed investigation of Flavonoid_Accumulation_Disposition at Stellenbosch University characterized flavonoid profiles and UV-screening capacity across 15 cultivars grown under ambient and supplemental UV-B (12 kJ m⁻² d⁻¹) for 28 days. ||Epidermal flavonoids were extracted and quantified by HPLC, UV transmittance was measured spectrophotometrically on epidermal peels, and expression of phenylpropanoid pathway genes (VvPAL, VvCHS, VvFLS1) was assessed by qRT-PCR. ||Flavonoid_Accumulation_Disposition showed substantial cultivar variation in both constitutive levels and UV inducibility. 'Malbec' exhibited exceptional flavonoid accumulation with constitutive epidermal flavonol content of 1.85 mg/g FW increasing to 3.42 mg/g under UV supplementation (1.85× induction), dominated by quercetin-3-glucoside (45%) and quercetin-3-glucuronide (28%). ||UV-B transmittance through 'Malbec' epidermis was only 6% at 310 nm, providing effective screening. ||VvFLS1 expression increased 12-fold under UV in 'Malbec'. 'Sauvignon Blanc' showed strong Flavonoid_Accumulation_Disposition (2.95 mg/g under UV, 8% transmittance) with distinct flavonol profile (kaempferol-dominant). 'Chasselas' displayed weak accumulation (1.25 mg/g under UV, only 1.4× induction, 18% transmittance) with correspondingly low VvFLS1 induction (3.5-fold). ||Correlation analysis revealed that UV-B transmittance was strongly predicted by total flavonol content (r = -0.92) and that flavonol accumulation correlated with photosynthetic protection under UV stress (r = 0.85 with Fv/Fm maintenance). ||Anthocyanins provided additional UV protection in red cultivar berries, with 'Malbec' berry skin anthocyanins absorbing 40% of incident UV-B.",
    "editor_note": "Flavonoid_Accumulation_Disposition is_a UV_Tolerance_Disposition. ||Flavonoids (particularly flavonols) are the primary UV-screening compounds in leaves. ||Accumulation occurs predominantly in epidermal vacuoles, creating a UV-absorbing layer. ||Both constitutive and UV-inducible accumulation contribute to protection. ||UVR8 photoreceptor mediates UV-induced pathway activation. ||Flavonol profiles (quercetin vs kaempferol dominance) vary among cultivars. ||Anthocyanins provide additional UV protection in pigmented tissues.  This disposition represents the primary protective mechanism against UV damage in plants, with flavonoids absorbing strongly in the UV-B and UV-A wavelengths while transmitting visible light required for photosynthesis. ||Key UV-protective flavonoids in grapevine include flavonols (quercetin, kaempferol, and their glycosides), which absorb maximally at 250-270 nm and 350-380 nm, and hydroxycinnamic acids (caffeic, ferulic, coumaric acids and derivatives), which absorb at 290-330 nm. ||These compounds accumulate predominantly in the vacuoles of epidermal cells, creating a UV-absorbing layer protecting underlying tissues. ||Flavonoid_Accumulation_Disposition encompasses both constitutive flavonoid levels (providing baseline protection) and UV-inducible accumulation (enhanced synthesis in response to UV exposure), with the phenylpropanoid pathway enzymes (PAL, CHS, CHI, F3H, FLS) upregulated by UV-B through the UVR8 photoreceptor signaling pathway. ||Genotypic variation in Flavonoid_Accumulation_Disposition reflects differences in constitutive pathway flux, UV-responsiveness of pathway genes, and potentially the specific flavonoid profile affecting UV absorption spectrum and cellular localization.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Agati G, Tattini M (2010) Multiple functional roles of flavonoids in photoprotection, New Phytologist 186:786-793|| Jenkins GI (2009) Signal transduction in responses to UV-B radiation, Annual Review of Plant Biology 60:407-431|| Kolb CA et al. (2001) UV-A screening in epidermis of grapevine leaves, Australian Journal of Plant Physiology 28:515-522"
  },
  "DNA_Repair_Disposition": {
    "definition": "A DNA_Repair_Disposition is a UV_Tolerance_Disposition that inheres in Vitis vinifera cells and is realized through efficient enzymatic mechanisms that detect and repair UV-induced DNA damage, particularly cyclobutane pyrimidine dimers (CPDs) and 6-4 photoproducts that if unrepaired cause mutations, replication blocks, and cell death.", 
    "alternative_term": "UV damage repair | photolyase activity | nucleotide excision repair capacity |+ DNA-Reparatur-Disposition | UV-Schadens-Reparatur | Photolyase-Aktivität",
    "example_of_usage": "Molecular assessment of DNA_Repair_Disposition at INRAE Montpellier quantified CPD accumulation and repair kinetics across 12 cultivars following acute UV-B exposure (15 kJ m⁻² over 2 hours) and subsequent recovery under photoreactivating light (white light) or dark conditions. ||CPD levels were measured by immunoassay at 0, 1, 2, 4, 8, and 24 hours post-UV, enabling calculation of repair rates. ||Photolyase gene expression (VvPHR1, VvUVR3) and protein levels were assessed in parallel. ||DNA_Repair_Disposition showed striking cultivar variation. 'Pinot Noir' exhibited exceptional repair capacity with CPD levels declining 78% within 4 hours under photoreactivating light (half-life 1.8 hours), associated with high constitutive VvPHR1 expression (3× mean across cultivars) and rapid UV-induced upregulation (4.5-fold within 2 hours). ||Dark repair in 'Pinot Noir' was also efficient, removing 45% of CPDs within 8 hours through NER pathway. 'Malbec' showed good repair (68% removal at 4 hours) complementing its strong screening capacity. 'Chasselas' displayed poor DNA_Repair_Disposition with only 35% CPD removal at 4 hours under photoreactivating light (half-life 4.8 hours) and minimal dark repair (18% at 8 hours), associated with low VvPHR1 expression and weak induction. ||Functional consequences were confirmed by measuring cell survival after UV exposure—'Pinot Noir' leaf discs showed 85% cell viability versus 52% for 'Chasselas' at 24 hours post-UV. ||Interestingly, repair capacity showed weak correlation with flavonoid accumulation (r = 0.32), indicating these represent independent components of UV tolerance and explaining why 'Pinot Noir' tolerates UV well despite only moderate screening capacity.",
    "editor_note": "DNA_Repair_Disposition is_a UV_Tolerance_Disposition. ||Photoreactivation (photolyase-mediated) is the most efficient repair pathway for UV-induced CPDs and 6-4 photoproducts. ||Requires blue/UV-A light for photolyase activation. ||NER provides dark repair backup but is slower. ||Repair capacity is genetically variable and partially independent of screening capacity. ||VvPHR1 and VvUVR3 encode key photolyases in grapevine. ||Strong repair capacity complements screening in providing comprehensive UV protection.  This disposition represents the damage repair component of UV tolerance, essential for maintaining genome integrity when UV screening is insufficient to prevent all DNA damage. ||Plants possess multiple DNA repair pathways including photoreactivation (light-dependent direct repair by photolyases, the most efficient pathway for UV damage), nucleotide excision repair (NER, a dark repair pathway removing and replacing damaged segments), and base excision repair (for oxidative damage). ||Photoreactivation is particularly important for UV tolerance, with CPD photolyase and 6-4 photolyase using blue/UV-A light energy to directly reverse the respective lesion types, enabling rapid and error-free repair. ||DNA_Repair_Disposition varies among genotypes in constitutive repair enzyme levels, UV-inducibility of repair pathways, and the efficiency of damage detection and processing. ||Strong repair capacity enables plants to tolerate UV exposure levels that would cause cumulative genetic damage in repair-deficient genotypes, complementing screening and antioxidant protection to provide comprehensive UV defense.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Britt AB (1996) DNA damage and repair in plants, Annual Review of Plant Physiology and Plant Molecular Biology 47:75-100|| Kimura S, Sakaguchi K (2006) DNA repair in plants, Chemical Reviews 106:753-766|| Waterworth WM et al. (2011) Repairing breaks in the plant genome: the importance of keeping it together, New Phytologist 192:805-822"
  },
  "Growth_And_Development_Disposition": {
    "definition": "A Growth_And_Development_Disposition is a Grapevine_Disposition that inheres in a Vitis vinifera plant and is realized through the inherent patterns, rates, and characteristics of vegetative and reproductive growth that determine vine architecture, canopy development, and the temporal progression through developmental stages from dormancy through harvest.", 
    "alternative_term": "vegetative growth disposition | developmental program | growth characteristics |+ Wachstums-und-Entwicklungs-Disposition | Vegetatives-Wachstumsprogramm | Entwicklungs-Charakteristik",
    "example_of_usage": "Comprehensive characterization of Growth_And_Development_Disposition at UC Davis compared growth parameters across 50 cultivars grown under standardized conditions (own-rooted, 2.4 × 1.5 m spacing, drip irrigation at 80% ETc) over four growing seasons. ||Measurements included shoot elongation rate, final shoot length, pruning weight, leaf area development, internode characteristics, and canopy architecture metrics. ||Growth_And_Development_Disposition showed substantial cultivar variation across multiple parameters. ||High-vigor cultivars like 'Barbera' and 'Carignane' produced mean pruning weights of 2.8-3.2 kg/vine, shoot lengths exceeding 250 cm, and dense canopies requiring multiple hedging passes. ||Moderate-vigor cultivars including 'Cabernet Sauvignon' and 'Merlot' showed pruning weights of 1.5-2.0 kg/vine and shoot lengths of 150-200 cm, balancing vegetative and reproductive development effectively. ||Low-vigor cultivars such as 'Pinot Noir' and 'Gewürztraminer' produced pruning weights of 0.8-1.2 kg/vine with shoots of 100-140 cm, often requiring vigor-enhancing rootstocks to achieve adequate canopy development. ||The stability of Growth_And_Development_Disposition rankings across years (r = 0.92 between years for pruning weight) confirmed strong genetic determination. ||Importantly, cultivars also differed in growth habit (erect vs. trailing), lateral shoot production, and the distribution of growth over the season, demonstrating that Growth_And_Development_Disposition encompasses multiple partially independent growth characteristics beyond simple vigor classification.",
    "editor_note": "Growth_And_Development_Disposition is_a Grapevine_Disposition and represents a major category encompassing vegetative growth characteristics. ||Child classes include Vigor_Disposition (growth intensity), Growth_Habit_Disposition (spatial organization), Phenological_Timing_Disposition (developmental timing), and potentially others addressing specific growth aspects. ||Growth disposition is genetically determined but environmentally modulated. ||In grafted vines, rootstock significantly influences scion growth expression. ||Growth characteristics have major implications for training system selection and canopy management requirements.  This disposition represents the fundamental growth program of the grapevine genotype, encompassing vigor (the intensity of vegetative growth), growth habit (the spatial organization of shoots and canopy), developmental timing (phenological progression), and the balance between vegetative and reproductive development. ||Growth_And_Development_Disposition integrates genetic determinants of meristem activity, hormone signaling, carbon allocation priorities, and environmental responsiveness that together produce the characteristic growth phenotype of each cultivar. ||Understanding Growth_And_Development_Disposition is essential for vineyard design (training system selection, vine spacing), canopy management (shoot positioning, hedging, leaf removal requirements), and predicting cultivar performance across different environments. ||The disposition is modified by environmental factors (climate, soil, water availability), management practices (pruning severity, irrigation, fertilization), and in grafted vines by rootstock influence on scion vigor. ||However, the underlying genetic disposition establishes the baseline growth characteristics that management can modulate but not fundamentally transform—a high-vigor cultivar remains inherently vigorous even under restrictive conditions, while a low-vigor cultivar cannot be induced to match high-vigor growth even with optimal resources.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2015) The Science of Grapevines: Anatomy and Physiology, 2nd Edition, Academic Press|| Mullins MG et al. (1992) Biology of the Grapevine, Cambridge University Press|| Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide"
  },
  "Vigor_Disposition": {
    "definition": "A Vigor_Disposition is a Growth_And_Development_Disposition that inheres in a Vitis vinifera plant and is realized through the inherent capacity for vegetative growth, determining the rate and extent of shoot elongation, leaf area production, lateral branching, and overall biomass accumulation during the growing season.", 
    "alternative_term": "vegetative vigor | growth intensity | growth capacity |+ Wuchsstärke-Disposition | Vegetative-Wuchskraft | Wachstums-Intensität",
    "example_of_usage": "Systematic evaluation of Vigor_Disposition at INRAE Bordeaux characterized vegetative growth across 80 cultivars and 20 rootstocks in a factorial trial assessing both scion and rootstock contributions to vigor expression. ||Standardized measurements of pruning weight per meter of cordon, shoot length, shoot number per meter, and Ravaz index (yield/pruning weight ratio) were collected over five seasons. ||Vigor_Disposition showed wide variation among scion cultivars, with pruning weights ranging from 0.4 kg/m ('Gewürztraminer' on '3309C') to 2.8 kg/m ('Carignane' on '110R'). ||Rootstock effects were substantial, with the same scion showing up to 2-fold variation in pruning weight depending on rootstock—'Cabernet Sauvignon' produced 0.9 kg/m on '101-14 Mgt' (devigorating) versus 1.8 kg/m on '110 Richter' (vigorating). ||However, scion genotype explained 65% of vigor variation while rootstock explained 25% and scion × rootstock interaction 10%, confirming that Vigor_Disposition is primarily a scion characteristic modulated by rootstock. ||Classification of cultivars by Vigor_Disposition revealed that vigor correlated with geographic origin—Mediterranean cultivars ('Carignan', 'Grenache', 'Mourvèdre') showed higher vigor than continental European cultivars ('Pinot Noir', 'Riesling', 'Gewürztraminer'), potentially reflecting adaptation to longer growing seasons and higher evaporative demand. ||Vigor_Disposition was partially independent of yield potential (r = 0.45), indicating that some high-vigor cultivars channel growth into vegetative rather than reproductive structures.",
    "editor_note": "Vigor_Disposition is_a Growth_And_Development_Disposition. ||Vigor represents growth intensity/capacity, the most fundamental growth characteristic. ||Pruning weight is the standard integrative measure of vigor expression. ||Child classes include Shoot_Vigor_Disposition and potentially Root_Vigor_Disposition. ||Vigor is primarily scion-determined but significantly modulated by rootstock (25% of variance). ||High vigor creates canopy management challenges|| low vigor may limit fruit ripening capacity. ||Vigor interacts with but is partially independent of yield potential.  This disposition represents the fundamental growth intensity of the genotype, reflecting the integrated activity of shoot apical meristems, cambial growth, and the mobilization and allocation of resources (carbon, nutrients, water) toward vegetative structures. ||Vigor is expressed through multiple measurable parameters including shoot elongation rate (cm/day during active growth), final shoot length, internode length, leaf size, lateral shoot production, trunk diameter increment, and total pruning weight (the most commonly used integrative measure). ||High vigor indicates strong inherent growth capacity producing abundant vegetative biomass, while low vigor indicates restrained growth with limited biomass production. ||Vigor_Disposition has profound viticultural implications, as it determines training system suitability (high-vigor cultivars requiring extensive canopy division or large canopy systems), planting density (low-vigor cultivars tolerating closer spacing), canopy management intensity (high vigor requiring more hedging, shoot thinning, and leaf removal), and the vine's capacity to ripen fruit while supporting adequate leaf area. ||The vigor expressed in any season represents the interaction between Vigor_Disposition (genetic potential) and environmental/management factors, but genotypic vigor rankings remain relatively stable across conditions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Howell GS (2001) Sustainable grape productivity and the growth-yield relationship: a review, American Journal of Enology and Viticulture 52:165-174|| Dry PR et al. (2010) Canopy management for fruitfulness, Australian Journal of Grape and Wine Research 16:47-52|| Keller M et al. (2004) Warm spring temperatures induce persistent season-long changes in shoot development in grapevines, Annals of Botany 93:739-746"
  },
  "Shoot_Vigor_Disposition": {
    "definition": "A Shoot_Vigor_Disposition is a Vigor_Disposition that inheres in Vitis vinifera shoots and is realized through the rate and extent of primary shoot growth from budburst through growth cessation, determining shoot length, internode dimensions, leaf size, and lateral shoot production.", 
    "alternative_term": "primary shoot growth | shoot growth capacity | aerial vigor |+ Triebwuchsstärke-Disposition | Primärtrieb-Wachstum | Oberirdische-Wuchskraft",
    "example_of_usage": "Detailed phenotyping of Shoot_Vigor_Disposition at Geisenheim University tracked shoot development across 45 cultivars at weekly intervals throughout the growing season, enabling characterization of growth rate dynamics, final dimensions, and growth component analysis. ||Measurements included primary shoot length, internode number and length, main leaf area, lateral shoot number and total lateral length, and the timing of growth cessation. ||Shoot_Vigor_Disposition showed wide cultivar variation with distinct growth patterns. ||High-vigor 'Silvaner' showed rapid early growth (peak rate 7.2 cm/day in week 6), extended growth duration (cessation week 16), and final shoot length of 285 cm with mean internode length of 9.8 cm and total lateral length of 180 cm per primary shoot. ||Moderate-vigor 'Riesling' displayed lower peak growth rate (4.8 cm/day), intermediate duration (cessation week 14), and final length of 165 cm with internode length of 7.2 cm and laterals of 85 cm. ||Low-vigor 'Gewürztraminer' showed modest peak growth (3.2 cm/day), early cessation (week 12), and final length of 95 cm with compact internodes (5.5 cm) and limited laterals (35 cm). ||Growth pattern analysis revealed that high-vigor cultivars differed from low-vigor primarily in growth duration rather than peak growth rate (r = 0.85 for duration vs. final length, r = 0.52 for peak rate vs. final length), indicating that Shoot_Vigor_Disposition reflects the period of sustained meristem activity rather than simply faster instantaneous growth. ||These findings enabled classification of cultivars into High, Moderate, and Low Shoot_Vigor_Disposition categories with distinct management implications.",
    "editor_note": "Shoot_Vigor_Disposition is_a Vigor_Disposition representing the above-ground vigor component. ||Shoot vigor reflects integrated meristem activity over the growing season. ||Child classes include High_Vigor_Disposition, Moderate_Vigor_Disposition, and Low_Vigor_Disposition as categorical descriptors. ||Key determinants are growth duration (weeks of active elongation) and peak growth rate. ||Lateral shoot production is an important component affecting canopy density. ||Shoot vigor determines training system requirements and canopy management intensity.  This disposition represents the above-ground expression of vigor, driven by shoot apical meristem activity, cell division and elongation rates, and the supply of resources (carbohydrates, water, nutrients) from roots and reserves to actively growing shoots. ||Shoot vigor is quantified through multiple parameters including shoot elongation rate (typically 2-8 cm/day during rapid growth phase, varying by genotype and conditions), final shoot length at growth cessation, mean internode length, individual leaf area, and the number and length of lateral (axillary) shoots produced. ||High Shoot_Vigor_Disposition results in long shoots with extended internodes, large leaves, and prolific lateral production, while low shoot vigor produces compact shoots with shorter internodes, smaller leaves, and limited laterals. ||Shoot vigor has direct implications for canopy density and fruit zone microclimate—high shoot vigor creates dense, shaded canopies requiring intensive management to maintain fruit quality, while low vigor may produce insufficient canopy for optimal fruit maturation. ||The disposition is expressed through three categorical subclasses (High, Moderate, Low) that capture the practical range of variation among cultivars and guide training system selection and management approaches.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lebon E et al. (2006) Shoot development in grapevine (Vitis vinifera L.) is affected by the modular branching pattern of the stem and intra- and inter-shoot trophic competition, Annals of Botany 98:1045-1056|| Schultz HR, Matthews MA (1988) Vegetative growth distribution during water deficits in Vitis vinifera L., Australian Journal of Plant Physiology 15:641-656|| Louarn G et al. (2007) A method to assess light interception efficiency of a grapevine canopy based on shoot architecture and leaf area distribution, Australian Journal of Grape and Wine Research 13:29-38"
  },
  "High_Vigor_Disposition": {
    "definition": "A High_Vigor_Disposition is a Shoot_Vigor_Disposition that inheres in Vitis vinifera shoots and is realized through strong, sustained vegetative growth producing long shoots (typically > 200 cm), extended internodes (> 8 cm mean length), large leaves (> 200 cm² individual area), and prolific lateral shoot development, resulting in dense canopies that require intensive management to maintain fruit quality.", 
    "alternative_term": "vigorous growth | strong vegetative growth | excessive vigor |+ Hohe-Wuchsstärke-Disposition | Starkes-Vegetatives-Wachstum | Überschüssige-Wuchskraft",
    "example_of_usage": "Characterization of High_Vigor_Disposition at AWRI Adelaide documented growth parameters in cultivars classified as high-vigor based on industry experience and research trials. ||Reference cultivars 'Carignan', 'Barbera', 'Silvaner', and 'Malbec' were grown under standardized conditions (own-rooted, 2.5 × 2.0 m spacing, moderate irrigation) with detailed growth measurements over three seasons. ||High_Vigor_Disposition cultivars showed consistent characteristics distinguishing them from moderate and low-vigor types. 'Carignan' exhibited archetypal High_Vigor_Disposition with mean shoot length of 265 cm (range 230-310 cm across seasons), internode length of 9.5 cm, individual leaf area of 245 cm², lateral shoot production of 12.5 laterals per primary shoot with total lateral length of 195 cm, and pruning weight of 2.65 kg/vine. ||Growth cessation occurred in week 17-18 (late February in Southern Hemisphere), 4-5 weeks after veraison, indicating continued vegetative growth during fruit ripening. 'Barbera' showed similar high vigor (255 cm shoots, 2.85 kg/vine pruning weight) with particularly strong lateral development. ||The Ravaz index (yield/pruning weight) for High_Vigor_Disposition cultivars averaged 3.2 (below the optimal 5-10 range), indicating vegetative dominance over reproductive development. ||Canopy management trials confirmed that High_Vigor_Disposition cultivars required 3-4 hedging passes per season to maintain fruit zone light exposure above 30% of ambient, compared to 1-2 passes for moderate-vigor types. ||Training system comparison showed that High_Vigor_Disposition cultivars performed best on divided canopy systems (GDC, Scott Henry) that accommodate total canopy leaf area of 22-28 m² per vine while maintaining adequate fruit zone microclimate.",
    "editor_note": "High_Vigor_Disposition is_a Shoot_Vigor_Disposition representing the upper vigor category. ||Typical characteristics include shoots > 200 cm, internodes > 8 cm, pruning weight > 2.0 kg/vine (site-dependent), extended growth duration past veraison, and Ravaz index < 5. ||Examples include 'Carignan', 'Barbera', 'Silvaner', 'Malbec', 'Carménère'. ||Management implications include need for divided canopy or large single-canopy systems, wide spacing, intensive hedging and shoot thinning, and careful water/nutrient management. ||High vigor is advantageous on limiting sites but problematic on fertile, well-watered sites.  This disposition represents the upper range of grapevine vigor, characteristic of cultivars with high inherent growth capacity that, under favorable conditions, produce abundant vegetative biomass potentially at the expense of reproductive development and fruit quality. ||High-vigor cultivars typically show extended growth duration (active shoot elongation continuing past veraison), delayed growth cessation, and strong regrowth response to hedging, creating ongoing canopy management challenges. ||The viticultural implications of High_Vigor_Disposition are substantial—such cultivars require large canopy training systems (e.g., sprawl, GDC, Scott Henry) or divided canopy systems to accommodate growth, wide vine spacing to prevent excessive competition, careful irrigation and fertilization management to avoid stimulating already excessive growth, and intensive canopy management including multiple hedging passes, shoot thinning, and leaf removal to maintain fruit zone light exposure and air circulation. ||High-vigor cultivars are typically well-suited to sites with growth-limiting factors (low fertility, limited water, cool climate) that naturally constrain vigor expression, but may produce problematic canopies on fertile, well-watered sites.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE (1985) Principles of grapevine canopy microclimate manipulation with implications for yield and quality: a review, American Journal of Enology and Viticulture 36:230-239|| Reynolds AG, Vanden Heuvel JE (2009) Influence of grapevine training systems on vine growth and fruit composition: a review, American Journal of Enology and Viticulture 60:251-268|| Dry PR (2000) Canopy management for fruitfulness, Australian Journal of Grape and Wine Research 6:109-115"
  },
  "Moderate_Vigor_Disposition": {
    "definition": "A Moderate_Vigor_Disposition is a Shoot_Vigor_Disposition that inheres in Vitis vinifera shoots and is realized through balanced vegetative growth producing shoots of intermediate length (typically 140-200 cm), moderate internodes (6-8 cm mean length), medium-sized leaves (150-200 cm² individual area), and manageable lateral shoot development, resulting in canopies that achieve favorable balance between vegetative and reproductive growth with standard management practices.", 
    "alternative_term": "medium vigor | balanced growth | intermediate vigor |+ Mittlere-Wuchsstärke-Disposition | Ausgewogenes-Wachstum | Mittlere-Wuchskraft",
    "example_of_usage": "Documentation of Moderate_Vigor_Disposition at the University of Bordeaux examined growth characteristics of cultivars classified as moderate-vigor in international viticulture. ||Reference cultivars 'Cabernet Sauvignon', 'Merlot', 'Chardonnay', and 'Sauvignon Blanc' were compared under standardized conditions across three Bordeaux appellations with varying soil types. ||Moderate_Vigor_Disposition cultivars showed consistent intermediate growth characteristics. 'Cabernet Sauvignon' exhibited typical Moderate_Vigor_Disposition with mean shoot length of 175 cm (range 155-195 cm across sites), internode length of 7.2 cm, individual leaf area of 175 cm², lateral production of 7.5 laterals per shoot with total lateral length of 85 cm, and pruning weight of 1.45 kg/vine. ||Growth cessation occurred in weeks 13-14 (late July/early August), coinciding with veraison and enabling timely shift to reproductive development. 'Merlot' showed similar moderate vigor (168 cm shoots, 1.55 kg/vine) with slightly more lateral development. 'Chardonnay' displayed Moderate_Vigor_Disposition with more upright growth habit (185 cm shoots, 6.8 cm internodes, 1.38 kg/vine). ||The Ravaz index for Moderate_Vigor_Disposition cultivars averaged 6.8 (within optimal 5-10 range), indicating appropriate vegetative-reproductive balance. ||Canopy management requirements were moderate—1-2 hedging passes maintained fruit zone conditions with VSP training, and standard shoot thinning (removing double shoots and weak shoots) achieved target shoot density of 14-18 shoots per meter of cordon. ||Training system flexibility was confirmed, with 'Cabernet Sauvignon' performing well on VSP, bilateral cordon, Guyot, and modified sprawl systems with appropriate vine spacing adjustments.",
    "editor_note": "Moderate_Vigor_Disposition is_a Shoot_Vigor_Disposition representing the middle vigor category. ||Typical characteristics include shoots 140-200 cm, internodes 6-8 cm, pruning weight 1.0-2.0 kg/vine (site-dependent), growth cessation around veraison, and Ravaz index 5-10. ||Examples include 'Cabernet Sauvignon', 'Merlot', 'Chardonnay', 'Sauvignon Blanc', 'Syrah'. ||Management is straightforward with standard training systems (VSP, bilateral cordon) and moderate canopy management intensity. ||Moderate vigor offers site and management flexibility, representing the practical ideal for many viticultural contexts.  This disposition represents the middle range of grapevine vigor, characteristic of cultivars that produce adequate canopy for optimal fruit maturation without excessive vegetative growth that would compromise fruit quality or require intensive canopy management. ||Moderate-vigor cultivars typically show timely growth cessation (around veraison or shortly after), allowing carbon allocation to shift toward fruit ripening rather than continued vegetative growth. ||The viticultural implications of Moderate_Vigor_Disposition are generally favorable—such cultivars are adaptable to standard training systems (VSP, bilateral cordon, cane pruning), tolerate a range of vine spacings, respond predictably to moderate irrigation and fertilization, and achieve optimal Ravaz indices (5-10) representing balanced vine performance. ||Moderate-vigor cultivars include many of the world's premium wine grape varieties, reflecting both historical selection for manageable growth characteristics and the quality advantages of balanced vines. ||These cultivars offer flexibility in site selection and management approach, performing well across a range of conditions without requiring the specialized approaches demanded by high or low vigor extremes.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kliewer WM, Dokoozlian NK (2005) Leaf area/crop weight ratios of grapevines: influence on fruit composition and wine quality, American Journal of Enology and Viticulture 56:170-181|| Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Jackson DI, Lombard PB (1993) Environmental and management practices affecting grape composition and wine quality—a review, American Journal of Enology and Viticulture 44:409-430"
  },
  "Low_Vigor_Disposition": {
    "definition": "A Low_Vigor_Disposition is a Shoot_Vigor_Disposition that inheres in Vitis vinifera shoots and is realized through restrained vegetative growth producing short shoots (typically < 140 cm), compact internodes (< 6 cm mean length), smaller leaves (< 150 cm² individual area), and limited lateral shoot development, resulting in open canopies that may require vigor-enhancing management or rootstock selection to achieve adequate leaf area for optimal fruit maturation.", 
    "alternative_term": "low growth | weak vigor | restrained vegetative growth |+ Niedrige-Wuchsstärke-Disposition | Schwaches-Wachstum | Geringe-Wuchskraft",
    "example_of_usage": "Evaluation of Low_Vigor_Disposition at the University of Burgundy characterized growth parameters in cultivars recognized for limited vegetative development. ||Reference cultivars 'Pinot Noir', 'Gewürztraminer', 'Aligoté', and 'Gamay' were grown under standardized conditions with detailed growth monitoring. ||Low_Vigor_Disposition cultivars showed consistent characteristics distinguishing them from moderate and high-vigor types. 'Pinot Noir' exhibited archetypal Low_Vigor_Disposition with mean shoot length of 115 cm (range 95-135 cm across clones), internode length of 5.4 cm, individual leaf area of 125 cm², lateral production of only 4.2 laterals per shoot with total lateral length of 32 cm, and pruning weight of 0.85 kg/vine on own roots. ||Growth cessation occurred in weeks 10-11 (mid-July), 4-5 weeks before veraison, indicating very short active growth period. 'Gewürztraminer' showed even lower vigor (98 cm shoots, 0.72 kg/vine pruning weight, growth cessation week 9), representing an extreme of Low_Vigor_Disposition among commercial cultivars. ||The Ravaz index for Low_Vigor_Disposition cultivars averaged 9.5-12.0, above the optimal range and indicating that fruit load may stress limited vine capacity. ||Rootstock trials demonstrated that Low_Vigor_Disposition cultivars benefited substantially from vigor-enhancing rootstocks—'Pinot Noir' pruning weight increased from 0.85 kg/vine on own roots to 1.45 kg/vine on '110 Richter' and 1.65 kg/vine on 'SO4', shifting Ravaz index into the optimal range. ||Spacing trials confirmed that Low_Vigor_Disposition cultivars tolerated close within-row spacing (0.9-1.0 m) without competition effects, enabling high vineyard leaf area indices despite limited per-vine growth.",
    "editor_note": "Low_Vigor_Disposition is_a Shoot_Vigor_Disposition representing the lower vigor category. ||Typical characteristics include shoots < 140 cm, internodes < 6 cm, pruning weight < 1.0 kg/vine (site-dependent), early growth cessation well before veraison, and Ravaz index > 10 if not corrected. ||Examples include 'Pinot Noir', 'Gewürztraminer', 'Aligoté', 'Gamay', 'Muscadet'. ||Management implications include need for vigor-enhancing rootstocks on most sites, close vine spacing, simple training systems, and attention to adequate leaf area for fruit ripening. ||Low vigor creates favorable fruit zone microclimate but risks inadequate canopy for optimal fruit maturation.  This disposition represents the lower range of grapevine vigor, characteristic of cultivars with inherently limited growth capacity that produce minimal vegetative biomass even under favorable growing conditions. ||Low-vigor cultivars typically show early growth cessation (well before veraison), short periods of active shoot elongation, and limited response to vigor-enhancing inputs, reflecting fundamental genetic constraints on growth capacity. ||The viticultural implications of Low_Vigor_Disposition are context-dependent—such cultivars may achieve excellent vegetative-reproductive balance on fertile sites or with vigorous rootstocks, but risk inadequate canopy development on limiting sites, potentially compromising fruit ripening through insufficient leaf area. ||Low-vigor cultivars are typically suited to close vine spacing (maximizing vineyard leaf area despite limited per-vine growth), simpler training systems (VSP, single Guyot), fertile soils, and vigor-enhancing rootstocks. ||The open canopies of low-vigor cultivars offer advantages for fruit zone microclimate (excellent light exposure, air circulation, reduced disease pressure) but may require irrigation management to avoid excessive water stress in the absence of shading.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Howell GS (2001) Sustainable grape productivity and the growth-yield relationship: a review, American Journal of Enology and Viticulture 52:165-174|| Kliewer WM, Dokoozlian NK (2005) Leaf area/crop weight ratios of grapevines: influence on fruit composition and wine quality, American Journal of Enology and Viticulture 56:170-181|| Vasconcelos MC et al. (2009) The flowering process of Vitis vinifera: a review, American Journal of Enology and Viticulture 60:411-434"
  },
  "Root_Vigor_Disposition": {
    "definition": "A Root_Vigor_Disposition is a Vigor_Disposition that inheres in the root system of a Vitis plant and is realized through the inherent capacity for root growth, determining the rate of root extension, the total root system size, root density and distribution patterns, and the overall below-ground biomass production.", 
    "alternative_term": "below-ground vigor | root growth capacity | root system development |+ Wurzelwuchsstärke-Disposition | Unterirdische-Wuchskraft | Wurzelsystem-Entwicklung",
    "example_of_usage": "Comprehensive characterization of Root_Vigor_Disposition at INRAE Bordeaux employed rhizotron observation, soil coring, and complete root excavation across 18 rootstock genotypes grown ungrafted for 5 years in deep soil (> 3 m). ||Measurements included total root length by minirhizotron imaging, root length density at depth intervals, maximum rooting depth, root dry weight, and fine root (< 2 mm diameter) to coarse root ratio. ||Root_Vigor_Disposition showed dramatic variation among rootstocks. '110 Richter' (V. berlandieri × V. rupestris) exhibited high Root_Vigor_Disposition with total root length of 2,850 m per vine, root dry weight of 4.2 kg, root length density of 2.8 cm/cm³ in the 0-50 cm zone, maximum rooting depth of 2.6 m, and fine root fraction of 68%. 'SO4' (V. berlandieri × V. riparia) showed similarly extensive root development (2,650 m total length, 3.8 kg dry weight) but with shallower distribution (maximum depth 1.8 m). ||In contrast, '101-14 Mgt' (V. riparia × V. rupestris) displayed limited Root_Vigor_Disposition with total length of 1,250 m, dry weight of 1.8 kg, and maximum depth of 1.4 m. '3309C' (V. riparia × V. rupestris) showed intermediate characteristics (1,650 m, 2.4 kg). ||Root vigor was moderately correlated with conferred scion vigor (r = 0.72 when grafted with 'Cabernet Sauvignon'), confirming that Root_Vigor_Disposition contributes to but does not fully determine above-ground vigor expression. ||Interestingly, the fine root fraction showed inverse relationship with total root mass (r = -0.58), with smaller root systems investing proportionally more in absorptive capacity.",
    "editor_note": "Root_Vigor_Disposition is_a Vigor_Disposition representing the below-ground vigor component. ||Root vigor is determined by rootstock genotype in grafted vines. ||Child classes include Extensive_Root_System_Disposition and Limited_Root_System_Disposition. ||Root vigor correlates with but does not fully determine scion vigor (~70% of variance). ||Root characteristics include total length/mass, depth distribution, and fine/coarse root ratio. ||Root vigor interacts with soil conditions (depth, texture, fertility) to determine functional root system size.  This disposition represents the underground component of vine vigor, reflecting the integrated activity of root apical meristems, lateral root initiation, and the allocation of resources toward root development. ||Root vigor is expressed through parameters including total root length, root dry weight, root length density (cm root per cm³ soil), rooting depth, and the ratio of fine absorptive roots to coarse structural roots. ||Root_Vigor_Disposition has fundamental implications for vine function, as the root system determines water and nutrient acquisition capacity, anchorage stability, carbohydrate storage reserves, and through root-derived signals (hormones, hydraulic signals) influences shoot growth and function. ||In grafted grapevines, Root_Vigor_Disposition is determined by rootstock genotype and represents a primary mechanism by which rootstocks influence scion performance. ||Rootstocks vary substantially in root system characteristics, from compact, limited root systems to extensive, vigorous systems that explore large soil volumes. ||The relationship between Root_Vigor_Disposition and Shoot_Vigor_Disposition is generally positive but not perfectly correlated, as root-to-shoot signaling and resource allocation patterns modify how below-ground growth capacity translates to above-ground vigor expression.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart DR et al. (2006) Grapevine rooting patterns: a comprehensive analysis and review, American Journal of Enology and Viticulture 57:89-104|| Swanepoel JJ, Southey JM (1989) The influence of rootstock on the rooting pattern of the grapevine, South African Journal of Enology and Viticulture 10:23-28|| Morlat R, Jacquet A (2003) Grapevine root system and soil characteristics in a vineyard maintained long-term with or without interrow sward, American Journal of Enology and Viticulture 54:1-7"
  },
  "Extensive_Root_System_Disposition": {
    "definition": "An Extensive_Root_System_Disposition is a Root_Vigor_Disposition that inheres in a Vitis rootstock and is realized through vigorous root growth producing a large, well-distributed root system with high total root length, deep penetration, and thorough exploration of the available soil volume, providing substantial capacity for water and nutrient acquisition.", 
    "alternative_term": "vigorous root system | large root system | extensive rooting |+ Ausgedehntes-Wurzelsystem-Disposition | Kräftiges-Wurzelsystem | Extensive-Bewurzelung",
    "example_of_usage": "Detailed documentation of Extensive_Root_System_Disposition at Stellenbosch University characterized root systems of rootstocks classified as extensive based on industry experience and research trials. ||Reference rootstocks '110 Richter', '140 Ruggeri', '1103 Paulsen', and 'SO4' were excavated at 8 years of age from deep granite-derived soils, with complete root recovery and morphological analysis. ||Extensive_Root_System_Disposition rootstocks showed consistent characteristics. '110 Richter' exhibited archetypal extensive root development with total excavated root length of 3,150 m, root dry weight of 4.8 kg, maximum rooting depth of 2.9 m with 35% of root length below 1 m depth, and horizontal spread of 2.4 m radius from the trunk. ||Root architecture showed strong vertical orientation with primary framework roots descending steeply before branching. '140 Ruggeri' displayed even more extensive characteristics (3,420 m, 5.2 kg, 3.4 m depth) reflecting its V. berlandieri × V. rupestris parentage combining deep-rooting tendencies of both parents. '1103 Paulsen' showed extensive but shallower distribution (2,880 m, 4.1 kg, 2.2 m depth, 45% in upper 50 cm). ||Functional assessment revealed that Extensive_Root_System_Disposition rootstocks maintained higher scion water potential during drought (Ψpd -0.35 MPa versus -0.65 MPa for limited root systems at equivalent surface soil moisture), demonstrating the stress-buffering advantage of extensive root development. ||Total soil volume explored by extensive root systems (estimated from spread and depth) reached 15-25 m³ per vine, compared to 5-10 m³ for limited systems.",
    "editor_note": "Extensive_Root_System_Disposition is_a Root_Vigor_Disposition representing high root vigor. ||Typical characteristics include total root length > 2,000 m, dry weight > 3 kg, rooting depth > 2 m (soil permitting), root length density > 2 cm/cm³. ||Examples include '110 Richter', '140 Ruggeri', '1103 Paulsen', 'SO4', 'Ramsey'. ||Advantages include drought tolerance, nutrient acquisition, stress buffering. ||V. berlandieri and V. rupestris parentage typically confers extensive rooting. ||Extensive root systems may confer excessive scion vigor on favorable sites.  This disposition represents the upper range of root vigor, characteristic of rootstocks that develop dominant below-ground structures capable of supporting vigorous scion growth and buffering against environmental stresses through access to large resource pools. ||Extensive root systems typically show total root lengths exceeding 2,000 m per mature vine, maximum rooting depths of 2-4 m (soil permitting), root length densities above 2 cm/cm³ in the primary rooting zone, and root dry weights of 3-5 kg. ||Such root systems are advantageous for drought tolerance (accessing deep soil water), nutrient acquisition (exploring large soil volumes), vine stability (extensive anchoring), and reserve storage (large root mass for carbohydrate accumulation). ||However, Extensive_Root_System_Disposition may confer excessive vigor to scions on fertile, well-watered sites, creating canopy management challenges. ||Rootstocks with extensive root systems are typically recommended for deep soils, sites with periodic water limitation, and situations requiring vigor enhancement of weak-growing scions.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Southey JM, Archer E (1988) The effect of rootstock cultivar on grapevine root distribution and density, in The Grapevine Root and its Environment, Department of Agriculture and Water Supply Technical Communication 215, Pretoria|| Smart DR et al. (2006) Grapevine rooting patterns: a comprehensive analysis and review, American Journal of Enology and Viticulture 57:89-104|| Paranychianakis NV et al. (2017) The effect of soil type and irrigation regime on vine performance and root system development, Australian Journal of Grape and Wine Research 23:426-436"
  },
  "Limited_Root_System_Disposition": {
    "definition": "A Limited_Root_System_Disposition is a Root_Vigor_Disposition that inheres in a Vitis rootstock and is realized through restrained root growth producing a compact, less extensive root system with moderate total root length, shallower penetration, and concentrated rather than expansive soil exploration, resulting in reduced capacity for water and nutrient acquisition compared to extensive root systems.", 
    "alternative_term": "compact root system | small root system | restricted rooting |+ Begrenztes-Wurzelsystem-Disposition | Kompaktes-Wurzelsystem | Eingeschränkte-Bewurzelung",
    "example_of_usage": "Characterization of Limited_Root_System_Disposition at the University of California Davis documented root systems of rootstocks recognized for compact root development. ||Reference rootstocks '101-14 Mgt', '3309C', 'Riparia Gloire', and '420A' were excavated at 8 years from deep alluvial soils, with complete root recovery and morphological analysis. ||Limited_Root_System_Disposition rootstocks showed consistent distinguishing characteristics. '101-14 Mgt' (V. riparia × V. rupestris) exhibited archetypal limited root development with total root length of 1,180 m, root dry weight of 1.6 kg, maximum rooting depth of 1.3 m with only 12% of root length below 1 m, and horizontal spread of 1.4 m radius. ||Root architecture showed horizontal orientation with shallow primary roots and limited vertical penetration. 'Riparia Gloire' displayed even more limited characteristics (950 m, 1.2 kg, 1.1 m depth) reflecting the shallow-rooting nature of V. riparia. '3309C' showed intermediate limited development (1,420 m, 2.1 kg, 1.6 m depth). ||Fine root fraction was notably higher in Limited_Root_System_Disposition rootstocks (72-78% versus 62-68% for extensive systems), indicating compensatory investment in absorptive capacity within constrained total root mass. ||Vigor assessment confirmed that Limited_Root_System_Disposition rootstocks reduced scion pruning weight by 25-40% compared to extensive rootstocks when grafted with identical scion ('Cabernet Sauvignon') under equivalent conditions, demonstrating the functional vigor-limiting effect of compact root systems. ||However, drought sensitivity was increased, with limited root system vines reaching stress thresholds (Ψpd < -0.5 MPa) 12-18 days earlier than extensive root system vines during dry-down experiments.",
    "editor_note": "Limited_Root_System_Disposition is_a Root_Vigor_Disposition representing low root vigor. ||Typical characteristics include total root length < 1,500 m, dry weight < 2.5 kg, rooting depth < 2 m, root length density < 2 cm/cm³. ||Examples include '101-14 Mgt', '3309C', 'Riparia Gloire', '420A'. ||V. riparia parentage typically confers limited rooting. ||Advantages include vigor control and suitability for fertile sites and high-density planting. ||Disadvantages include increased drought sensitivity and reduced stress buffering. ||Higher fine root fraction partially compensates for reduced total root mass.  This disposition represents the lower range of root vigor, characteristic of rootstocks that develop relatively modest below-ground structures, naturally constraining scion vigor through limited resource supply capacity. ||Limited root systems typically show total root lengths below 1,500 m per mature vine, maximum rooting depths of 1-2 m, root length densities below 2 cm/cm³, and root dry weights of 1.5-2.5 kg. ||Such root systems are advantageous for vigor control (naturally limiting scion growth on fertile sites), dense planting (reduced root competition zone), and situations requiring scion vigor reduction. ||However, Limited_Root_System_Disposition may increase drought sensitivity (smaller water reservoir), reduce nutrient buffering capacity, and limit vine recovery from stress or damage due to smaller reserve storage. ||Rootstocks with limited root systems are typically recommended for fertile soils, well-watered sites, vigorous scions requiring control, and high-density plantings where per-vine root volume is intentionally restricted.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Swanepoel JJ, Southey JM (1989) The influence of rootstock on the rooting pattern of the grapevine, South African Journal of Enology and Viticulture 10:23-28|| Tandonnet JP et al. (2010) Long term effects of rootstock on vine performance and wine quality for Vitis vinifera cv. Cabernet Sauvignon, Australian Journal of Grape and Wine Research 16:298-306|| Tramontini S et al. (2013) Rootstock control of scion response to water stress in grapevine, Environmental and Experimental Botany 93:20-26"
  },
  "Vigor_Conferred_To_Scion_Disposition": {
    "definition": "A Vigor_Conferred_To_Scion_Disposition is a Vigor_Disposition that inheres in a Vitis rootstock and is realized through the rootstock's influence on the vegetative growth of the grafted scion, modifying scion shoot elongation, leaf area production, and overall biomass accumulation relative to what the scion would produce on its own roots or on a neutral rootstock.", 
    "alternative_term": "rootstock vigor effect | rootstock-conferred vigor | grafting vigor influence |+ Unterlage-Wuchskraft-Übertragung-Disposition | Unterlagen-Vigor-Effekt | Pfropfungs-Wuchskraft-Einfluss",
    "example_of_usage": "Systematic quantification of Vigor_Conferred_To_Scion_Disposition at INRAE Bordeaux employed a factorial trial with 12 rootstocks grafted to a common scion ('Cabernet Sauvignon') grown under standardized conditions over 8 years, enabling isolation of rootstock effects on scion vigor. ||Measurements included scion pruning weight, shoot length, shoot number, trunk cross-sectional area, and leaf area per vine. ||Vigor_Conferred_To_Scion_Disposition showed wide variation among rootstocks. 'SO4' conferred highest vigor with scion pruning weight of 2.35 kg/vine (indexed as 145% relative to grand mean), shoot length of 195 cm, and trunk area of 12.8 cm². '110 Richter' and '140 Ruggeri' showed similarly high vigor conferral (138% and 142% respectively). 'Gravesac' conferred moderate vigor (102%). '101-14 Mgt' conferred substantially reduced vigor with pruning weight of 1.12 kg/vine (69% of mean), shoot length of 125 cm, and trunk area of 7.2 cm². '3309C' and 'Riparia Gloire' showed similar vigor-reducing effects (75% and 62% respectively). ||The effect was consistent across years (r > 0.90 for rootstock rankings between years) and when tested with alternative scions ('Merlot', 'Sauvignon Blanc'), confirming that Vigor_Conferred_To_Scion_Disposition is a stable rootstock characteristic. ||Correlation analysis revealed that vigor conferral was positively associated with root system size (r = 0.72), root hydraulic conductance (r = 0.68), and xylem cytokinin concentration (r = 0.58), indicating multiple contributing mechanisms. ||The range of vigor modulation (62-145% of mean) demonstrates that rootstock selection can nearly double or halve scion vigor expression.",
    "editor_note": "Vigor_Conferred_To_Scion_Disposition is_a Vigor_Disposition representing rootstock influence on scion vigor. ||Effect ranges from ~60% to ~150% of neutral reference, enabling substantial vigor modulation through rootstock selection. ||Child classes include Vigor_Reducing_Rootstock_Disposition and Vigor_Enhancing_Rootstock_Disposition. ||Vigor conferral is partially but not fully explained by root system size (~70% correlation). ||Additional mechanisms include hydraulic conductance, cytokinin export, and nutrient supply efficiency. ||Vigor conferral is a stable rootstock characteristic consistent across scions and years.  This disposition represents the rootstock's functional effect on scion vigor, integrating root system characteristics (size, distribution, efficiency) with physiological signaling (hormones, hydraulic conductance, nutrient supply) that together determine how the rootstock modulates scion growth expression. ||The vigor conferred to scion can range from substantial reduction (vigor-reducing rootstocks decreasing scion pruning weight by 30-50% relative to own-rooted vines) to substantial enhancement (vigor-enhancing rootstocks increasing pruning weight by 50-100%). ||This effect is relatively consistent across different scions—a vigor-reducing rootstock will reduce growth of both inherently vigorous and weak scions, though the absolute magnitude of reduction may differ. ||Vigor_Conferred_To_Scion_Disposition is only partially explained by Root_Vigor_Disposition (r ≈ 0.7), indicating that rootstock-scion signaling mechanisms contribute independently to vigor modulation. ||Mechanisms include regulation of cytokinin export from roots (promoting shoot growth), hydraulic conductance affecting water supply to shoots, and efficiency of nutrient uptake and translocation. ||Understanding Vigor_Conferred_To_Scion_Disposition enables strategic rootstock selection to achieve desired vine balance—pairing vigor-reducing rootstocks with vigorous scions or fertile sites, and vigor-enhancing rootstocks with weak scions or limiting sites.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ollat N et al. (2003) Grapevine rootstock effects on scion growth and mineral nutrition, Acta Horticulturae 617:47-54|| Tandonnet JP et al. (2010) Long term effects of rootstock on vine performance and wine quality for Vitis vinifera cv. Cabernet Sauvignon, Australian Journal of Grape and Wine Research 16:298-306|| Cookson SJ et al. (2013) Graft union formation in grapevine induces transcriptional changes related to cell wall modification, wounding, hormone signalling, and secondary metabolism, Journal of Experimental Botany 64:2997-3008"
  },
  "Vigor_Reducing_Rootstock_Disposition": {
    "definition": "A Vigor_Reducing_Rootstock_Disposition is a Vigor_Conferred_To_Scion_Disposition that inheres in a Vitis rootstock and is realized through mechanisms that limit scion vegetative growth, reducing shoot elongation, leaf area production, and pruning weight relative to own-rooted vines or vines grafted to vigor-neutral rootstocks.", 
    "alternative_term": "devigorating rootstock | low-vigor rootstock | vigor-limiting rootstock |+ Wuchskraft-Reduzierendes-Unterlagen-Disposition | Schwächer-Wachsende-Unterlage | Wuchskraft-Limitierende-Unterlage",
    "example_of_usage": "Characterization of Vigor_Reducing_Rootstock_Disposition at Geisenheim University documented the vigor-limiting effects of rootstocks recognized for scion growth reduction. ||A trial with 15 rootstocks grafted to 'Riesling' over 10 years quantified vigor parameters and identified mechanisms of vigor reduction. ||Rootstocks classified as vigor-reducing showed consistent characteristics. '101-14 Mgt' exhibited archetypal Vigor_Reducing_Rootstock_Disposition with scion pruning weight of 0.68 kg/vine (65% of trial mean), shoot length of 118 cm (72% of mean), and trunk cross-sectional area increment of 1.2 cm²/year (58% of mean). ||Root system excavation revealed total root length of 1,180 m and maximum depth of 1.4 m, indicating limited Root_Vigor_Disposition as a primary mechanism. '3309C' showed similar vigor reduction (72% pruning weight, 75% shoot length) with intermediate root system size (1,520 m). 'Riparia Gloire' displayed the strongest vigor reduction (58% pruning weight) associated with minimal root development (980 m total length). ||Physiological analysis revealed that Vigor_Reducing_Rootstock_Disposition rootstocks showed 35% lower xylem sap cytokinin concentration and 28% lower root hydraulic conductance compared to vigor-enhancing types, implicating both hormonal and hydraulic mechanisms. ||Ravaz index analysis confirmed improved vine balance on vigor-reducing rootstocks (Ravaz 8.5-10.0 versus 5.5-7.0 on vigor-enhancing), indicating that growth reduction shifted allocation toward reproduction. ||However, drought sensitivity was elevated, with vigor-reducing rootstock vines showing stress symptoms 15 days earlier during controlled dry-down.",
    "editor_note": "Vigor_Reducing_Rootstock_Disposition is_a Vigor_Conferred_To_Scion_Disposition representing vigor-limiting rootstocks. ||Typical vigor reduction is 25-45% of pruning weight versus mean. ||Examples include '101-14 Mgt', '3309C', 'Riparia Gloire', '420A', '161-49C'. ||V. riparia parentage is characteristic. ||Mechanisms include limited root system, reduced hydraulic conductance, lower cytokinin export. ||Advantages include vigor control and improved vine balance. ||Trade-offs include increased drought sensitivity and potentially reduced longevity. ||Strategic use with vigorous scions or fertile sites.  This disposition represents rootstock genotypes that naturally constrain scion vigor, typically reducing pruning weight by 25-45% compared to mean rootstock performance, achieved through limited root system size, reduced hydraulic conductance, lower cytokinin export, or some combination of these factors. ||Vigor-reducing rootstocks are strategically valuable for managing inherently vigorous scions, controlling excess growth on fertile or well-watered sites, achieving balanced canopies without intensive management intervention, and enabling closer vine spacing in high-density planting systems. ||The vigor reduction effect is generally proportional across scions—a vigor-reducing rootstock will reduce growth of any scion, though inherently low-vigor scions may become excessively weak requiring management compensation. ||Vigor-reducing rootstocks are typically characterized by V. riparia parentage, which contributes compact root systems and lower root-to-shoot signaling intensity. ||The trade-off for vigor reduction is often increased sensitivity to drought and other stresses due to limited root system buffering capacity, and potentially reduced vine longevity due to smaller carbohydrate reserves.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M et al. (2012) Interactive effects of rootstock and deficit irrigation on grapevine physiology and fruit quality, American Journal of Enology and Viticulture 63:303-312|| Ollat N et al. (2003) Grapevine rootstock effects on scion growth and mineral nutrition, Acta Horticulturae 617:47-54|| Harbertson JF, Keller M (2012) Rootstock effects on deficit-irrigated red winegrapes, American Journal of Enology and Viticulture 63:80-89"
  },
  "Vigor_Enhancing_Rootstock_Disposition": {
    "definition": "A Vigor_Enhancing_Rootstock_Disposition is a Vigor_Conferred_To_Scion_Disposition that inheres in a Vitis rootstock and is realized through mechanisms that promote scion vegetative growth, increasing shoot elongation, leaf area production, and pruning weight relative to own-rooted vines or vines grafted to vigor-neutral rootstocks.", 
    "alternative_term": "invigorating rootstock | high-vigor rootstock | vigor-promoting rootstock |+ Wuchskraft-Förderndes-Unterlagen-Disposition | Stärker-Wachsende-Unterlage | Wuchskraft-Steigernde-Unterlage",
    "example_of_usage": "Documentation of Vigor_Enhancing_Rootstock_Disposition at the Australian Wine Research Institute characterized the vigor-promoting effects of rootstocks recognized for scion growth enhancement. ||A trial with 18 rootstocks grafted to 'Shiraz' over 12 years quantified vigor parameters and identified mechanisms of vigor enhancement. ||Rootstocks classified as vigor-enhancing showed consistent characteristics. '110 Richter' exhibited strong Vigor_Enhancing_Rootstock_Disposition with scion pruning weight of 2.45 kg/vine (142% of trial mean), shoot length of 215 cm (138% of mean), and trunk cross-sectional area of 14.2 cm² (155% of mean). ||Root system excavation revealed total root length of 2,950 m with maximum depth of 2.8 m, indicating extensive Root_Vigor_Disposition as a primary mechanism. 'SO4' showed similar vigor enhancement (148% pruning weight) with somewhat shallower but dense root system (2,680 m, 1.9 m depth). '140 Ruggeri' displayed the strongest vigor enhancement (156% pruning weight) associated with the most extensive root development (3,280 m, 3.2 m depth). ||Physiological analysis revealed that Vigor_Enhancing_Rootstock_Disposition rootstocks showed 55% higher xylem sap cytokinin concentration and 45% higher root hydraulic conductance compared to vigor-reducing types. ||Canopy management requirements were substantially increased—vigor-enhancing rootstock vines required 3-4 hedging passes per season versus 1-2 for vigor-reducing, and fruit zone leaf layer number averaged 3.2 versus 1.8. ||However, drought resilience was substantially enhanced, with vigor-enhancing rootstock vines maintaining favorable water status 22 days longer during dry-down due to access to deeper soil water reserves.",
    "editor_note": "Vigor_Enhancing_Rootstock_Disposition is_a Vigor_Conferred_To_Scion_Disposition representing vigor-promoting rootstocks. ||Typical vigor enhancement is 30-60% above mean pruning weight. ||Examples include '110 Richter', '140 Ruggeri', '1103 Paulsen', 'SO4', 'Ramsey', '99 Richter'. ||V. berlandieri and V. rupestris parentage is characteristic. ||Mechanisms include extensive root system, high hydraulic conductance, enhanced cytokinin export. ||Advantages include support for weak scions, drought resilience, and performance on limiting sites. ||Trade-offs include canopy management challenges and potential quality reduction from excessive vigor. ||Strategic use with low-vigor scions or limiting sites.  This disposition represents rootstock genotypes that amplify scion vigor, typically increasing pruning weight by 30-60% compared to mean rootstock performance, achieved through extensive root systems, high hydraulic conductance, enhanced cytokinin export, and efficient nutrient acquisition. ||Vigor-enhancing rootstocks are strategically valuable for supporting inherently weak scions, overcoming growth limitations on poor or shallow soils, achieving adequate canopy development in challenging environments, and maximizing vine establishment vigor. ||The vigor enhancement effect is generally proportional across scions—a vigor-enhancing rootstock will increase growth of any scion, though inherently high-vigor scions may become excessively vigorous requiring intensive management. ||Vigor-enhancing rootstocks are typically characterized by V. berlandieri and V. rupestris parentage, which contribute extensive root systems and robust root-to-shoot signaling. ||The benefits of vigor enhancement may be offset by canopy management challenges on favorable sites, delayed fruit maturity due to vegetative competition, and potentially reduced fruit quality from excessive shading in dense canopies.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Walker RR et al. (2002) Rootstock effects on salt tolerance of irrigated field-grown grapevines, Australian Journal of Grape and Wine Research 8:146-155|| Tandonnet JP et al. (2010) Long term effects of rootstock on vine performance and wine quality for Vitis vinifera cv. Cabernet Sauvignon, Australian Journal of Grape and Wine Research 16:298-306|| Zhang L et al. (2016) The effect of rootstock on berry composition and aroma profile of Shiraz, American Journal of Enology and Viticulture 67:311-320"
  },
  "Growth_Habit_Disposition": {
    "definition": "A Growth_Habit_Disposition is a Growth_And_Development_Disposition that inheres in a Vitis vinifera plant and is realized through the characteristic spatial organization, architecture, and form of vegetative growth, determining how shoots are oriented in space, how the canopy develops its three-dimensional structure, and how the vine naturally occupies and fills its allotted growing space.", 
    "alternative_term": "vine architecture | canopy form | growth form |+ Wuchsform-Disposition | Rebarchitektur | Wuchshabitus",
    "example_of_usage": "Comprehensive characterization of Growth_Habit_Disposition at INRAE Montpellier assessed canopy architecture across 60 cultivars grown on a standardized trellis allowing free shoot expression (wide T-trellis with catch wires but no forced positioning). ||Measurements included shoot angle from vertical at multiple positions (base, mid, tip), percentage of shoots achieving vertical positioning without intervention, natural canopy width and density distribution, and the proportion of shoot length requiring positioning to achieve VSP geometry. ||Growth_Habit_Disposition showed wide cultivar variation. ||Strongly upright cultivars like 'Cabernet Sauvignon' and 'Merlot' showed mean shoot angles of 12-18° from vertical, with 85-92% of shoots naturally achieving VSP-compatible orientation and minimal positioning requirement (< 15% of shoot length needing adjustment). ||Intermediate cultivars including 'Chardonnay' and 'Sauvignon Blanc' displayed angles of 25-35°, with 55-70% natural VSP achievement. ||Trailing cultivars such as 'Gewürztraminer', 'Riesling', and 'Pinot Gris' showed angles of 45-70° from vertical, with only 20-35% natural VSP achievement and extensive positioning requirement (> 50% of shoot length). ||The disposition was stable across years (r = 0.94 for cultivar rankings) and only weakly correlated with vigor (r = 0.28), confirming that Growth_Habit_Disposition represents an independent architectural characteristic. ||Canopy light interception modeling demonstrated that cultivars with Growth_Habit_Disposition matched to training system achieved 15-25% higher light interception efficiency than mismatched combinations.",
    "editor_note": "Growth_Habit_Disposition is_a Growth_And_Development_Disposition representing spatial/architectural characteristics. ||Growth habit is distinct from vigor (intensity) though they interact in canopy expression. ||Primary child class is Shoot_Orientation_Disposition addressing the angle/direction of shoot growth. ||Growth habit determines training system suitability and canopy management requirements. ||The disposition is genetically stable but expression depends on vigor and training constraints. ||Matching growth habit to training system optimizes canopy light interception and management efficiency.  This disposition represents the architectural program of the genotype, distinct from but interacting with vigor (growth intensity) to determine the overall canopy phenotype. ||Growth habit encompasses shoot orientation (the angle at which shoots grow relative to vertical), branching pattern (apical dominance versus lateral proliferation), internode characteristics affecting compactness, tendril development and climbing behavior, and the natural tendency toward particular canopy forms. ||Understanding Growth_Habit_Disposition is essential for training system selection, as cultivars with strongly upright growth are well-suited to vertical shoot positioning (VSP) systems, while trailing cultivars may perform better on sprawl or divided canopy systems that accommodate their natural growth direction. ||Growth habit also affects canopy management requirements—upright cultivars may need minimal shoot positioning while trailing types require intensive positioning or acceptance of non-vertical canopy architecture. ||The disposition is genetically determined and relatively stable across environments, though the degree to which inherent growth habit is expressed depends on vigor level (low-vigor vines may not fully express trailing tendency due to limited shoot length) and training system constraints.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Carbonneau A (1995) La surface foliaire exposée potentielle—guide pour sa mesure, Progrès Agricole et Viticole 112:204-212|| Reynolds AG, Vanden Heuvel JE (2009) Influence of grapevine training systems on vine growth and fruit composition: a review, American Journal of Enology and Viticulture 60:251-268"
  },
  "Shoot_Orientation_Disposition": {
    "definition": "A Shoot_Orientation_Disposition is a Growth_Habit_Disposition that inheres in Vitis vinifera shoots and is realized through the inherent angle and direction of shoot growth relative to vertical, determining whether shoots naturally grow upward (positively gravitropic), horizontally, or downward (negatively gravitropic/trailing), and thus how the vine canopy develops in three-dimensional space.", 
    "alternative_term": "shoot angle | gravitropic response | shoot growth direction |+ Triebausrichtungs-Disposition | Triebwinkel | Gravitropische-Reaktion",
    "example_of_usage": "Systematic phenotyping of Shoot_Orientation_Disposition at Geisenheim University measured shoot angles across 80 cultivars at weekly intervals throughout the growing season to characterize orientation dynamics. ||Shoots were allowed free growth on a minimal support system (single wire at 1.2 m), with angle from vertical measured at 30, 50, and 70 cm from shoot base using a digital inclinometer. ||Shoot_Orientation_Disposition showed substantial and consistent cultivar variation. ||Strongly upright 'Cabernet Sauvignon' maintained mean angle of 15° at 50 cm throughout the season, with shoot tips ascending to 8° even as shoots exceeded 150 cm, demonstrating persistent negative gravitropism. 'Pinot Noir' showed semi-upright characteristics (28° at 50 cm) with moderate tip ascent. 'Riesling' displayed horizontal to trailing orientation with 52° at 50 cm, increasing to 68° at 70 cm as shoot weight overcame gravitropic response. ||Strongly trailing 'Gewürztraminer' reached 72° at 50 cm with tips often below horizontal (> 90°, true trailing). ||Developmental analysis revealed that shoot orientation was established early (by 40 cm length) and remained stable thereafter, indicating that Shoot_Orientation_Disposition reflects inherent properties rather than progressive mechanical effects. ||Internode flexibility measurements showed that trailing cultivars had 35% lower internode stiffness than upright types, contributing to their pendulous growth. ||The practical significance was confirmed by shoot positioning labor requirements—trailing cultivars required 3.5× more positioning labor than upright cultivars to achieve equivalent VSP canopy geometry.",
    "editor_note": "Shoot_Orientation_Disposition is_a Growth_Habit_Disposition addressing the angle of shoot growth from vertical. ||Orientation reflects the balance between gravitropic response and mechanical/architectural factors. ||Child classes include Upright_Growth_Disposition (< 20°), Semi_Upright_Growth_Disposition (20-40°), Horizontal_Growth_Disposition (40-60°), and Trailing_Growth_Disposition (> 60°). ||Orientation is established early in shoot development and remains stable. ||Internode stiffness contributes to orientation differences. ||Training system compatibility depends strongly on shoot orientation.  This disposition represents the gravitropic response program of the genotype, reflecting the balance between negative gravitropism (driving upward growth toward light) and the mechanical effects of shoot weight, internode flexibility, and growth rate that may overcome gravitropic orientation. ||Shoot orientation is determined by the shoot's angle from vertical, measured at standardized positions along the shoot (typically at 50 cm from the base for comparable assessment). ||Cultivars range from strongly upright (< 20° from vertical) through semi-upright, horizontal, to trailing (> 60° from vertical, often approaching or exceeding horizontal). ||Shoot_Orientation_Disposition has major implications for training system compatibility—upright cultivars naturally conform to VSP and similar vertical systems, while trailing cultivars resist vertical positioning and may perform better on sprawl, lyre, or pendulum systems that work with rather than against their natural orientation. ||The disposition also affects light distribution within canopies, fruit zone exposure, and the labor requirements for shoot positioning operations.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE (1988) Shoot spacing and canopy light microclimate, American Journal of Enology and Viticulture 39:325-333|| Intrieri C, Poni S (1995) Integrated evolution of trellis training systems and machines to improve grape quality and vintage quality of mechanized Italian vineyards, American Journal of Enology and Viticulture 46:116-127|| Louarn G et al. (2008) Characterization of the light interception efficiency of grapevine, Annals of Botany 101:385-399"
  },
  "Upright_Growth_Disposition": {
    "definition": "An Upright_Growth_Disposition is a Shoot_Orientation_Disposition that inheres in Vitis vinifera shoots and is realized through strong negative gravitropism producing shoots that grow predominantly vertically, maintaining angles of less than 20° from vertical throughout their length, with shoot tips ascending even as shoots elongate and gain weight.", 
    "alternative_term": "erect growth | vertical shoot growth | strongly upright habit |+ Aufrechte-Wuchs-Disposition | Vertikaler-Triebwuchs | Stark-Aufrechter-Habitus",
    "example_of_usage": "Documentation of Upright_Growth_Disposition at UC Davis characterized shoot architecture in cultivars recognized for strongly vertical growth habit. ||Reference cultivars 'Cabernet Sauvignon', 'Merlot', 'Petit Verdot', and 'Tannat' were grown on minimal trellis systems allowing free shoot expression, with detailed angular and mechanical measurements. ||Upright_Growth_Disposition cultivars showed consistent distinguishing characteristics. 'Cabernet Sauvignon' exhibited archetypal upright growth with mean shoot angle of 12° from vertical at 50 cm shoot length, maintaining 15° even at 100 cm length with shoots weighing 85 g, and shoot tips ascending to 8° demonstrating persistent gravitropic correction. ||Internode flexural stiffness averaged 2.8 N·mm² (highest quartile among cultivars tested). 'Petit Verdot' showed even stronger upright tendency (10° at 50 cm, stiffness 3.2 N·mm²). 'Merlot' displayed typical Upright_Growth_Disposition (14° at 50 cm) with moderate stiffness (2.4 N·mm²). ||In VSP training trials, Upright_Growth_Disposition cultivars required positioning labor of only 12-18 hours/ha/season (1-2 positioning passes), compared to 45-65 hours/ha for trailing cultivars. ||Canopy geometry analysis showed that upright cultivars achieved target VSP parameters (< 1.5 leaf layers, > 40% cluster exposure) with minimal intervention, while maintaining fruit zone height consistency (coefficient of variation 8% versus 22% for trailing types). ||Natural shoot spacing was more uniform in upright cultivars (CV 15% versus 28%), contributing to even canopy light distribution.",
    "editor_note": "Upright_Growth_Disposition is_a Shoot_Orientation_Disposition representing vertical shoot growth (< 20° from vertical). ||Characterized by strong negative gravitropism and stiff internodes. ||Examples include 'Cabernet Sauvignon', 'Merlot', 'Petit Verdot', 'Tannat', 'Cabernet Franc'. ||Advantages include VSP compatibility, reduced positioning labor, uniform canopy geometry, and mechanical harvest suitability. ||The disposition creates naturally organized canopies with good light penetration. ||High internode stiffness is a contributing mechanical factor.  This disposition represents the upper extreme of shoot orientation, characteristic of cultivars with robust gravitropic response that maintains vertical shoot positioning with minimal or no mechanical support or positioning intervention. ||Upright-growing cultivars naturally conform to vertical shoot positioning (VSP) training systems, reducing or eliminating the labor requirement for shoot positioning while achieving optimal canopy geometry for light interception and fruit zone exposure. ||The mechanical basis of Upright_Growth_Disposition involves stiff internodes (high lignification and/or cell wall properties), strong gravitropic sensing and response, and sometimes shorter internodes that reduce the mechanical moment tending to bend shoots. ||Upright growth creates naturally well-organized canopies with good light penetration, predictable fruit zone location, and compatibility with mechanical harvesting. ||The disposition is advantageous for VSP systems, pergola, and other vertically-oriented training systems, but may be less suitable for sprawl or GDC systems that benefit from lateral shoot spread.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Reynolds AG, Vanden Heuvel JE (2009) Influence of grapevine training systems on vine growth and fruit composition: a review, American Journal of Enology and Viticulture 60:251-268|| Dry PR (2000) Canopy management for fruitfulness, Australian Journal of Grape and Wine Research 6:109-115"
  },
  "Semi_Upright_Growth_Disposition": {
    "definition": "A Semi_Upright_Growth_Disposition is a Shoot_Orientation_Disposition that inheres in Vitis vinifera shoots and is realized through moderate negative gravitropism producing shoots that grow at intermediate angles of 20-40° from vertical, with shoot tips showing some ascending tendency but without the strong vertical orientation of upright cultivars.", 
    "alternative_term": "moderately upright | intermediate-erect growth | semi-vertical habit |+ Halbaufrechte-Wuchs-Disposition | Mäßig-Aufrechter-Wuchs | Mittlerer-Triebwinkel",
    "example_of_usage": "Characterization of Semi_Upright_Growth_Disposition at the University of Bordeaux documented shoot architecture in cultivars with intermediate-upright growth habit. ||Reference cultivars 'Pinot Noir', 'Syrah', 'Grenache', and 'Tempranillo' were assessed on standard VSP trellis with measurement of shoot angles before and after positioning operations. ||Semi_Upright_Growth_Disposition cultivars showed consistent intermediate characteristics. 'Pinot Noir' exhibited typical semi-upright growth with mean shoot angle of 28° from vertical at 50 cm before positioning, requiring two tuck/position passes to achieve VSP geometry, and maintaining positioned angle of 12° through the season. ||Natural (unpositioned) shoot tip orientation was 35° from vertical, indicating moderate but incomplete gravitropic correction. 'Syrah' showed similar Semi_Upright_Growth_Disposition (32° at 50 cm) with slightly greater positioning requirement. 'Grenache' displayed the upper range of semi-upright (38° at 50 cm), transitioning toward horizontal growth habit. ||Internode stiffness averaged 2.0 N·mm² in semi-upright cultivars (intermediate between upright at 2.8 and trailing at 1.6 N·mm²). ||Positioning labor requirement was 28-38 hours/ha/season (2-3 passes), intermediate between upright (12-18 hours) and trailing (45-65 hours). ||Training system trials confirmed that Semi_Upright_Growth_Disposition cultivars performed well on both VSP (with positioning) and Smart-Dyson ballerina systems that accommodate their natural intermediate orientation. ||The flexibility was reflected in global planting patterns, with semi-upright cultivars like 'Pinot Noir' and 'Syrah' successfully grown on diverse training systems across wine regions.",
    "editor_note": "Semi_Upright_Growth_Disposition is_a Shoot_Orientation_Disposition representing intermediate-upright growth (20-40° from vertical). ||Characterized by moderate gravitropism and intermediate internode stiffness. ||Examples include 'Pinot Noir', 'Syrah', 'Grenache', 'Tempranillo', 'Sangiovese'. ||Compatible with VSP (with positioning) and various other systems. ||Moderate positioning labor requirement (2-3 passes). ||Provides training system flexibility. ||Represents the most common growth habit category among commercial cultivars.  This disposition represents the intermediate-upright range of shoot orientation, characteristic of cultivars that grow predominantly upward but with sufficient deviation from vertical to require some positioning intervention for optimal VSP canopy geometry. ||Semi-upright cultivars are compatible with VSP training systems but benefit from catch wire positioning or tucking to achieve fully vertical canopy presentation, representing moderate labor requirement between strongly upright (minimal positioning) and horizontal/trailing types (intensive positioning). ||The mechanical and physiological basis involves intermediate internode stiffness and gravitropic response strength, producing shoots that initially grow upward but gradually deviate from vertical as they elongate and gain weight. ||Semi_Upright_Growth_Disposition provides flexibility in training system selection, as these cultivars can be successfully managed in VSP with positioning, in sprawl systems accepting their natural spread, or in divided canopy systems benefiting from their intermediate orientation.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Carbonneau A (1995) La surface foliaire exposée potentielle—guide pour sa mesure, Progrès Agricole et Viticole 112:204-212|| Smart RE (1988) Shoot spacing and canopy light microclimate, American Journal of Enology and Viticulture 39:325-333|| Jackson DI, Lombard PB (1993) Environmental and management practices affecting grape composition and wine quality—a review, American Journal of Enology and Viticulture 44:409-430"
  },
  "Horizontal_Growth_Disposition": {
    "definition": "A Horizontal_Growth_Disposition is a Shoot_Orientation_Disposition that inheres in Vitis vinifera shoots and is realized through weak negative gravitropism producing shoots that grow at angles of 40-60° from vertical, approaching or reaching horizontal orientation, particularly in the mid and distal portions of the shoot as length and weight increase.", 
    "alternative_term": "spreading growth | horizontal shoot habit | arching growth |+ Horizontale-Wuchs-Disposition | Waagerechter-Triebwuchs | Bogiger-Habitus",
    "example_of_usage": "Investigation of Horizontal_Growth_Disposition at Stellenbosch University characterized shoot architecture in cultivars recognized for spreading, horizontal growth habit. ||Reference cultivars 'Chenin Blanc', 'Colombard', 'Sémillon', and 'Muscadelle' were grown on multiple training systems with detailed angular measurements and positioning response assessment. ||Horizontal_Growth_Disposition cultivars showed consistent characteristics. 'Chenin Blanc' exhibited typical horizontal growth with mean shoot angle of 48° from vertical at 50 cm, increasing to 62° at 80 cm as shoot weight accumulated, with shoot tips often reaching true horizontal (90°) or slightly below. ||Gravitropic correction was minimal—tips deviated only 8° upward from mid-shoot trajectory compared to 25° in upright cultivars. 'Sémillon' showed similar Horizontal_Growth_Disposition (52° at 50 cm, 68° at 80 cm). ||Internode stiffness averaged 1.8 N·mm² (lower quartile). ||VSP positioning trials revealed that Horizontal_Growth_Disposition cultivars required 48-58 hours/ha/season positioning labor (3-4 passes), and showed 35% position loss (shoots falling from catch wires) compared to < 10% for upright types. ||Training system comparison demonstrated that 'Chenin Blanc' achieved superior canopy metrics on sprawl (leaf layer number 1.4, cluster exposure 52%) compared to VSP with intensive positioning (leaf layers 2.1, exposure 38%), suggesting that working with rather than against Horizontal_Growth_Disposition improves canopy function. ||Traditional pergola training in South African Chenin Blanc vineyards effectively utilizes the horizontal growth habit, achieving excellent fruit zone exposure beneath the horizontal canopy.",
    "editor_note": "Horizontal_Growth_Disposition is_a Shoot_Orientation_Disposition representing spreading/horizontal growth (40-60° from vertical). ||Characterized by weak gravitropism, lower internode stiffness, and increasing angle with shoot length. ||Examples include 'Chenin Blanc', 'Colombard', 'Sémillon', 'Muscadelle', 'Müller-Thurgau'. ||Poor VSP compatibility with high positioning requirement and position loss. ||Better suited to sprawl, GDC, pergola systems. ||Position loss (shoots falling from catch wires) is characteristic.  This disposition represents the intermediate-trailing range of shoot orientation, characteristic of cultivars that lack the gravitropic strength to maintain vertical growth against shoot weight, resulting in shoots that arc outward and eventually grow nearly horizontally without positioning intervention. ||Horizontal-growing cultivars present challenges for VSP training systems, requiring intensive positioning labor to achieve vertical canopy geometry, and often showing poor position retention (shoots falling back toward horizontal after positioning). ||These cultivars may be better suited to training systems that accommodate or utilize horizontal shoot orientation, including sprawl, GDC (Geneva Double Curtain), Scott Henry, and traditional pergola systems common in their regions of origin. ||The mechanical basis of Horizontal_Growth_Disposition includes lower internode stiffness and weaker gravitropic response, allowing shoot weight to overcome the upward growth tendency early in development.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Archer E, Strauss HC (1985) Effect of plant density on root distribution of three-year-old grafted 99 Richter grapevines, South African Journal of Enology and Viticulture 6:25-30|| Reynolds AG et al. (1994) Influence of cluster exposure on fruit composition and wine quality of Seyval blanc, Vitis 33:137-143"
  },
  "Trailing_Growth_Disposition": {
    "definition": "A Trailing_Growth_Disposition is a Shoot_Orientation_Disposition that inheres in Vitis vinifera shoots and is realized through minimal or absent negative gravitropism producing shoots that grow at angles exceeding 60° from vertical, with mature shoots often approaching or exceeding horizontal (> 90°, true trailing/pendulous), creating canopies that naturally cascade downward without support.", 
    "alternative_term": "pendulous growth | drooping habit | cascading growth |+ Hängende-Wuchs-Disposition | Überhängender-Triebwuchs | Pendelnder-Habitus",
    "example_of_usage": "Detailed documentation of Trailing_Growth_Disposition at Geisenheim University characterized shoot architecture in cultivars recognized for pendulous, trailing growth habit. ||Reference cultivars 'Gewürztraminer', 'Riesling', 'Pinot Gris', and 'Muscat Ottonel' were grown on multiple training systems with comprehensive angular and mechanical measurements. ||Trailing_Growth_Disposition cultivars showed consistent extreme characteristics. 'Gewürztraminer' exhibited archetypal trailing growth with mean shoot angle of 72° from vertical at 50 cm, reaching 95° (below horizontal) at 80 cm, with shoot tips pointing downward in a true pendulous orientation. ||Gravitropic correction was absent—tips continued the downward trajectory established by mid-shoot. 'Riesling' showed strong Trailing_Growth_Disposition (65° at 50 cm, 85° at 80 cm) with characteristic arching profile. ||Internode stiffness was lowest among growth habit categories, averaging 1.5 N·mm² in trailing cultivars, and internode length was 15% longer than upright cultivars at equivalent vigor. ||VSP positioning trials confirmed incompatibility—'Gewürztraminer' required 65+ hours/ha positioning labor with 55% position loss, making VSP management economically impractical. ||Alternative training system trials demonstrated that Trailing_Growth_Disposition cultivars excelled on Scott Henry (lower curtain shoots achieving 45° below horizontal with excellent exposure), pendulum/curtain systems, and traditional Mosel steep-slope training where downward shoot growth is managed by single-stake support. ||Light interception efficiency for 'Riesling' was 22% higher on appropriately designed curtain systems compared to VSP with intensive positioning, demonstrating that matching Trailing_Growth_Disposition to training system optimizes canopy function.",
    "editor_note": "Trailing_Growth_Disposition is_a Shoot_Orientation_Disposition representing pendulous/trailing growth (> 60° from vertical, often exceeding horizontal). ||Characterized by absent gravitropism, very low internode stiffness, and often longer internodes. ||Examples include 'Gewürztraminer', 'Riesling', 'Pinot Gris', 'Pinot Blanc', 'Muscat Ottonel', 'Grüner Veltliner'. ||Incompatible with VSP|| suited to Scott Henry lower tier, pendulum/curtain, and pergola systems. ||Many Alsatian and German cultivars show this trait. ||Traditional training in regions of origin often accommodates trailing habit.  This disposition represents the extreme of non-upright growth, characteristic of cultivars that show negligible gravitropic correction as shoots elongate, resulting in pendulous, curtain-like canopy architecture when grown on high-wire or pergola systems. ||Trailing cultivars are poorly suited to VSP training, requiring either extremely intensive positioning labor with poor retention, or acceptance of alternative canopy forms. ||These cultivars are naturally compatible with systems designed for downward-growing shoots, including Scott Henry (lower wire shoots), pendulum/curtain systems, and traditional high pergola training. ||The mechanical basis of Trailing_Growth_Disposition includes very low internode stiffness (flexible shoots that bend easily under their own weight), weak gravitropic sensing or response, and often longer internodes that increase the mechanical moment causing shoot bending. ||Some trailing cultivars originated in viticultural traditions using pergola or arbor training where trailing growth was advantageous or at least not problematic.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Reynolds AG, Vanden Heuvel JE (2009) Influence of grapevine training systems on vine growth and fruit composition: a review, American Journal of Enology and Viticulture 60:251-268|| Intrieri C, Poni S (1995) Integrated evolution of trellis training systems and machines to improve grape quality and vintage quality of mechanized Italian vineyards, American Journal of Enology and Viticulture 46:116-127"
  },
  "Branching_Pattern_Disposition": {
    "definition": "A Branching_Pattern_Disposition is a Growth_Habit_Disposition that inheres in a Vitis vinifera plant and is realized through the characteristic pattern of lateral shoot (axillary shoot) development from primary shoot nodes, determining the degree to which vines produce branched versus unbranched shoot structures during the growing season.", 
    "alternative_term": "lateral branching habit | axillary shoot development | shoot architecture pattern |+ Verzweigungsmuster-Disposition | Geiztrieb-Entwicklung | Triebarchitektur-Muster",
    "example_of_usage": "Comprehensive characterization of Branching_Pattern_Disposition at INRAE Bordeaux quantified lateral shoot development across 55 cultivars grown under standardized conditions (VSP, moderate vigor, no lateral removal) throughout the growing season. ||Measurements included number of lateral shoots per primary shoot, total lateral length, lateral shoot positions (basal, mid, distal nodes), and the ratio of lateral to primary shoot biomass. ||Additionally, auxin concentration in shoot apices and cytokinin sensitivity of lateral buds were assessed to investigate mechanistic basis. ||Branching_Pattern_Disposition showed substantial cultivar variation. 'Carignan' exhibited prolific branching with 14.5 lateral shoots per primary shoot, total lateral length of 245 cm (exceeding primary shoot length of 210 cm), and lateral/primary biomass ratio of 1.15, indicating that more resources were allocated to lateral than primary growth. 'Merlot' showed strong apical dominance with only 4.2 lateral shoots per primary, total lateral length of 48 cm, and biomass ratio of 0.22. 'Cabernet Sauvignon' displayed intermediate branching (7.8 laterals, 95 cm total length, ratio 0.45). ||Mechanistic analysis revealed that apex auxin concentration was 35% higher in strong apical dominance cultivars, while lateral bud cytokinin sensitivity (measured by bud outgrowth response to exogenous cytokinin) was 2.5-fold higher in prolific branching types. ||The practical significance was confirmed by canopy management labor requirements—prolific branching cultivars required 85 hours/ha for lateral management versus 25 hours/ha for strong apical dominance types.",
    "editor_note": "Branching_Pattern_Disposition is_a Growth_Habit_Disposition addressing lateral shoot development patterns. ||Branching reflects the balance between apical dominance (suppression) and lateral bud release (outgrowth). ||Child classes include Strong_Apical_Dominance_Disposition, Weak_Apical_Dominance_Disposition, and Lateral_Shoot_Proliferation_Disposition. ||Auxin-cytokinin balance underlies branching pattern differences. ||Branching interacts with vigor—limited resources constrain lateral expression regardless of hormonal predisposition. ||Branching pattern determines lateral management requirements and canopy density.  This disposition represents the balance between apical dominance (hormonal suppression of lateral bud outgrowth by the dominant shoot apex) and the tendency for lateral bud release (outgrowth of axillary buds into lateral shoots), together determining canopy architecture complexity and density. ||Branching pattern profoundly affects canopy management requirements, as cultivars with prolific lateral production develop dense, multi-layered canopies requiring intensive shoot thinning and lateral removal, while cultivars with strong apical dominance produce simpler canopy structures with reduced management intervention. ||The disposition reflects genotypic differences in auxin production by shoot apices, cytokinin sensitivity of lateral buds, and the hormonal communication between apex and lateral buds that regulates correlative inhibition. ||Branching_Pattern_Disposition interacts with vigor—high-vigor cultivars express their branching tendency more fully than low-vigor cultivars where limited resources constrain lateral development regardless of hormonal predisposition. ||Understanding branching pattern enables prediction of canopy management needs and guides decisions about shoot thinning, lateral removal, hedging timing, and training system complexity appropriate for each cultivar.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lebon E et al. (2006) Shoot development in grapevine (Vitis vinifera L.) is affected by the modular branching pattern of the stem and intra- and inter-shoot trophic competition, Annals of Botany 98:1045-1056|| Cline MG (1991) Apical dominance, Botanical Review 57:318-358|| Bennett T, Leyser O (2006) Something on the side: axillary meristems and plant development, Plant Molecular Biology 60:843-854"
  },
  "Strong_Apical_Dominance_Disposition": {
    "definition": "A Strong_Apical_Dominance_Disposition is a Branching_Pattern_Disposition that inheres in a Vitis vinifera plant and is realized through robust hormonal suppression of lateral bud outgrowth by the primary shoot apex, resulting in minimal lateral shoot production, simple unbranched shoot architecture, and naturally open canopy structure without intensive lateral management.", 
    "alternative_term": "high apical control | suppressed lateral growth | unbranched shoot habit |+ Starke-Apikaldominanz-Disposition | Hohe-Apikalkontrolle | Unterdrückte-Geiztrieb-Bildung",
    "example_of_usage": "Documentation of Strong_Apical_Dominance_Disposition at UC Davis characterized lateral suppression in cultivars recognized for minimal branching. ||Reference cultivars 'Merlot', 'Zinfandel', 'Petite Sirah', and 'Mourvèdre' were grown on VSP without lateral removal to assess natural branching expression. ||Detailed measurements included lateral number by node position, lateral length distribution, and the response of lateral development to apex removal (decapitation). ||Strong_Apical_Dominance_Disposition cultivars showed consistent characteristics. 'Merlot' exhibited archetypal strong apical dominance with mean of 3.8 lateral shoots per primary shoot of 165 cm length, concentrated at basal nodes 1-4 (85% of laterals), with total lateral length of only 42 cm (lateral/primary length ratio 0.25). ||Lateral shoots were short (mean 11 cm) and ceased growth early, reflecting persistent apical suppression. 'Petite Sirah' showed even stronger dominance (2.9 laterals, 28 cm total length). ||Decapitation experiments confirmed strong apical control—removal of 'Merlot' apex at 80 cm triggered outgrowth of 8.5 additional lateral buds within 14 days, demonstrating that buds were competent but hormonally suppressed. ||Apex auxin concentration in Strong_Apical_Dominance_Disposition cultivars averaged 285 ng/g FW (45% above cultivar mean), correlating with suppression strength (r = 0.78 between auxin and inverse lateral number). ||Canopy density measurements confirmed that Strong_Apical_Dominance_Disposition cultivars achieved 1.2-1.5 leaf layers without lateral removal, compared to 2.5-3.5 in prolific branching types, demonstrating the practical advantage for fruit zone light exposure.",
    "editor_note": "Strong_Apical_Dominance_Disposition is_a Branching_Pattern_Disposition representing minimal lateral development (< 5 laterals per primary shoot). ||Characterized by high apex auxin, efficient correlative inhibition, and lateral restriction to basal nodes. ||Examples include 'Merlot', 'Zinfandel', 'Petite Sirah', 'Mourvèdre'. ||Advantages include reduced lateral management labor and naturally open canopies. ||Laterals released by apex removal (hedging) confirm hormonal suppression mechanism. ||Strong dominance may limit canopy recovery after damage.  This disposition represents the upper extreme of correlative inhibition strength, characteristic of cultivars where auxin export from the shoot apex effectively prevents lateral bud activation across most or all nodes of the primary shoot. ||Cultivars with Strong_Apical_Dominance_Disposition typically produce fewer than 5 lateral shoots per primary shoot under normal growing conditions, with lateral development often restricted to basal nodes (where apical influence is weakest) or occurring only after hedging removes the dominant apex. ||The viticultural advantages of strong apical dominance include reduced labor requirements for lateral shoot management, naturally lower canopy density with better light penetration, and simplified canopy architecture facilitating mechanical operations. ||However, the disposition can be disadvantageous when lateral growth is desired—for example, to fill canopy gaps after frost damage or to increase leaf area on low-vigor vines. ||Strong_Apical_Dominance_Disposition is associated with higher auxin concentrations in shoot apices and more efficient polar auxin transport maintaining apical suppression of lateral buds.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Cline MG (1991) Apical dominance, Botanical Review 57:318-358|| Lebon E et al. (2006) Shoot development in grapevine (Vitis vinifera L.) is affected by the modular branching pattern of the stem and intra- and inter-shoot trophic competition, Annals of Botany 98:1045-1056|| Tanaka M et al. (2006) Auxin controls local cytokinin biosynthesis in the nodal stem in apical dominance, Plant Journal 45:1028-1036"
  },
  "Weak_Apical_Dominance_Disposition": {
    "definition": "A Weak_Apical_Dominance_Disposition is a Branching_Pattern_Disposition that inheres in a Vitis vinifera plant and is realized through limited hormonal suppression of lateral bud outgrowth, resulting in moderate lateral shoot production from primary shoot nodes even while the apex remains intact and actively growing.", 
    "alternative_term": "moderate apical control | intermediate branching | partial lateral suppression |+ Schwache-Apikaldominanz-Disposition | Mäßige-Apikalkontrolle | Intermediäre-Verzweigung",
    "example_of_usage": "Characterization of Weak_Apical_Dominance_Disposition at the University of Bordeaux documented intermediate lateral development in cultivars with moderate branching tendency. ||Reference cultivars 'Cabernet Sauvignon', 'Cabernet Franc', 'Sauvignon Blanc', and 'Pinot Noir' were assessed under standardized conditions without lateral management. ||Weak_Apical_Dominance_Disposition cultivars showed consistent intermediate characteristics. 'Cabernet Sauvignon' exhibited typical weak apical dominance with mean of 7.8 lateral shoots per primary shoot of 175 cm, distributed across basal (40%), mid-shoot (45%), and distal (15%) nodes, with total lateral length of 95 cm (ratio 0.54). ||Lateral shoots averaged 12 cm length with some exceeding 25 cm, indicating incomplete but not absent suppression. 'Pinot Noir' showed similar patterns (6.5 laterals, 78 cm total) with notable node-position effect—laterals at nodes 8-12 were significantly longer than at basal or distal positions, suggesting a zone of reduced apical influence at intermediate distance from apex. ||Apex auxin concentration in Weak_Apical_Dominance_Disposition cultivars averaged 195 ng/g FW (near cultivar mean), intermediate between strong dominance (285 ng/g) and proliferation types (145 ng/g). ||Management trials confirmed that Weak_Apical_Dominance_Disposition cultivars benefited from targeted lateral management—removal of laterals at fruiting zone nodes improved cluster exposure without requiring the intensive whole-shoot lateral removal needed for proliferation types. ||Labor requirement averaged 45 hours/ha, intermediate between strong dominance (25 hours) and proliferation types (85 hours).",
    "editor_note": "Weak_Apical_Dominance_Disposition is_a Branching_Pattern_Disposition representing moderate lateral development (6-10 laterals per primary shoot). ||Characterized by intermediate apex auxin and partial correlative inhibition. ||Examples include 'Cabernet Sauvignon', 'Cabernet Franc', 'Sauvignon Blanc', 'Pinot Noir', 'Chardonnay'. ||Laterals develop at basal and mid-shoot positions while apex remains active. ||Moderate management flexibility—laterals can be retained or removed as needed. ||Represents the most common branching pattern among commercial cultivars.  This disposition represents intermediate correlative inhibition, characteristic of cultivars where the auxin signal from the shoot apex is insufficient to fully suppress lateral bud activation, particularly at nodes distant from the apex or under favorable growing conditions. ||Cultivars with Weak_Apical_Dominance_Disposition typically produce 6-10 lateral shoots per primary shoot, with laterals developing at both basal and mid-shoot positions while the apex continues primary growth. ||The viticultural implications are intermediate—more lateral management is required than for strong apical dominance types, but the naturally moderate branching does not create the extremely dense canopies characteristic of lateral proliferation types. ||Weak_Apical_Dominance_Disposition provides flexibility, as lateral development can be allowed to increase leaf area where desired or removed where canopy density is excessive. ||The disposition is associated with lower apex auxin concentrations and/or reduced auxin transport efficiency, allowing cytokinin-driven bud activation to proceed at a moderate level.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lebon E et al. (2006) Shoot development in grapevine (Vitis vinifera L.) is affected by the modular branching pattern of the stem and intra- and inter-shoot trophic competition, Annals of Botany 98:1045-1056|| Bennett T, Leyser O (2006) Something on the side: axillary meristems and plant development, Plant Molecular Biology 60:843-854|| Dry PR (2000) Canopy management for fruitfulness, Australian Journal of Grape and Wine Research 6:109-115"
  },
  "Lateral_Shoot_Proliferation_Disposition": {
    "definition": "A Lateral_Shoot_Proliferation_Disposition is a Branching_Pattern_Disposition that inheres in a Vitis vinifera plant and is realized through minimal apical dominance and high intrinsic lateral bud activity, producing abundant lateral shoots from most or all nodes of the primary shoot, creating highly branched, complex shoot architecture and dense, multi-layered canopies without management intervention.", 
    "alternative_term": "prolific branching | excessive lateral growth | vigorous lateral production |+ Geiztrieb-Proliferations-Disposition | Übermäßige-Verzweigung | Starke-Geiztrieb-Bildung",
    "example_of_usage": "Investigation of Lateral_Shoot_Proliferation_Disposition at AWRI Adelaide documented extreme branching in cultivars recognized for prolific lateral development. ||Reference cultivars 'Carignan', 'Barbera', 'Colombard', and 'Silvaner' were grown without lateral management to characterize natural branching expression. ||Lateral_Shoot_Proliferation_Disposition cultivars showed consistent extreme characteristics. 'Carignan' exhibited archetypal proliferation with mean of 14.5 lateral shoots per primary shoot of 210 cm, occurring at 92% of nodes (essentially every node producing a lateral), with total lateral length of 245 cm exceeding primary length. ||Laterals developed vigorously with mean length of 17 cm and maximum exceeding 40 cm, and secondary laterals (laterals arising from primary laterals) were common (2.8 per primary shoot). ||The lateral/primary biomass ratio reached 1.15, indicating that lateral growth dominated resource allocation. 'Barbera' showed similar proliferation (12.8 laterals, 215 cm total length) with particularly vigorous secondary lateral development. ||Apex auxin concentration in Lateral_Shoot_Proliferation_Disposition cultivars averaged only 145 ng/g FW (50% below strong dominance types), while lateral bud cytokinin sensitivity was 2.8-fold higher, explaining the escape from correlative inhibition. ||Canopy density reached 3.8 leaf layers in unmanaged proliferating cultivars, severely compromising fruit zone light (< 5% ambient) and requiring intensive management intervention. ||Labor requirements for lateral management reached 85-95 hours/ha (4-5 removal passes) to achieve acceptable canopy density, representing a major management cost for these cultivars.",
    "editor_note": "Lateral_Shoot_Proliferation_Disposition is_a Branching_Pattern_Disposition representing extreme lateral development (> 10 laterals per primary shoot, often at every node). ||Characterized by low apex auxin, high bud cytokinin sensitivity, and ineffective correlative inhibition. ||Examples include 'Carignan', 'Barbera', 'Colombard', 'Silvaner', 'Trebbiano'. ||Secondary laterals common. ||Creates severe canopy management challenges with dense, multi-layered canopies. ||Requires intensive lateral removal (4-5 passes) or hedging approaches. ||Total lateral length may exceed primary shoot length.  This disposition represents the extreme of lateral development, characteristic of cultivars where correlative inhibition is largely ineffective, allowing lateral buds to activate freely regardless of apex activity. ||Cultivars with Lateral_Shoot_Proliferation_Disposition typically produce more than 10 lateral shoots per primary shoot, often with laterals at every node, and total lateral length may exceed primary shoot length as lateral growth captures a large proportion of vine resources. ||The viticultural challenges of lateral proliferation are substantial—without intensive management, canopies become excessively dense with 3+ leaf layers, severe fruit zone shading, poor air circulation promoting disease, and competition between lateral growth and fruit development. ||Management of proliferating cultivars requires multiple lateral removal passes or acceptance of hedging approaches that remove lateral-bearing shoot portions. ||The disposition is associated with low apex auxin production and/or high cytokinin sensitivity of lateral buds, resulting in constitutive bud activation that occurs regardless of apical suppression signals.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Lebon E et al. (2006) Shoot development in grapevine (Vitis vinifera L.) is affected by the modular branching pattern of the stem and intra- and inter-shoot trophic competition, Annals of Botany 98:1045-1056|| Intrieri C, Poni S (1995) Integrated evolution of trellis training systems and machines to improve grape quality and vintage quality of mechanized Italian vineyards, American Journal of Enology and Viticulture 46:116-127"
  },
  "Internode_Length_Disposition": {
    "definition": "An Internode_Length_Disposition is a Growth_Habit_Disposition that inheres in Vitis vinifera shoots and is realized through the characteristic distance between successive nodes on primary shoots, determining shoot compactness, the spatial distribution of leaves and clusters along the shoot, and contributing to canopy density and fruit zone architecture.", 
    "alternative_term": "node spacing | shoot compactness | internode dimensions |+ Internodienlängen-Disposition | Knotenabstand | Triebkompaktheit",
    "example_of_usage": "Systematic phenotyping of Internode_Length_Disposition at Geisenheim University measured internode dimensions across 70 cultivars at multiple timepoints to characterize developmental patterns and final dimensions. ||Internodes 5-15 on primary shoots were measured at full extension, avoiding variable basal internodes and incompletely expanded distal internodes. ||Additionally, internode cell number and cell length were assessed anatomically to investigate developmental basis. ||Internode_Length_Disposition showed substantial cultivar variation with distinct developmental patterns. 'Silvaner' exhibited long internode characteristics with mean internode length of 10.2 cm, ranging from 8.5-12.5 cm across the measured zone, producing shoots with widely-spaced leaves and open architecture. ||Cell number per internode averaged 485 with mean cell length of 210 μm. 'Gewürztraminer' showed even longer internodes (11.5 cm) associated with its trailing growth habit. 'Pinot Noir' displayed short internode characteristics with mean length of 5.8 cm (range 4.8-6.8 cm), creating compact shoots with closely-spaced leaves. ||Cell number was similar (465 cells) but cell length was shorter (125 μm), indicating that cell expansion rather than cell division primarily determines internode length differences. 'Chardonnay' and 'Cabernet Sauvignon' showed intermediate lengths (7.2-7.8 cm). ||The functional significance was confirmed by canopy light measurements—long-internode 'Silvaner' achieved 45% fruit zone light penetration at equivalent shoot density where short-internode 'Pinot Noir' achieved only 28%, demonstrating that Internode_Length_Disposition substantially affects canopy microclimate.",
    "editor_note": "Internode_Length_Disposition is_a Growth_Habit_Disposition addressing the spacing between nodes. ||Internode length affects canopy density, cluster spacing, and shoot mechanical properties. ||Child classes include Long_Internode_Disposition and Short_Internode_Disposition. ||Cell expansion (length) rather than cell division (number) primarily underlies internode length variation. ||Long internodes are associated with trailing growth habit and lower shoot stiffness. ||Environmental factors (temperature, light, gibberellins) modulate expression, but genotypic ranking is stable.  This disposition represents the cell elongation and division patterns in the subapical meristem region that establish internode dimensions, reflecting genotypic differences in gibberellin sensitivity, cell expansion capacity, and the duration of the internode elongation phase. ||Internode length profoundly affects canopy structure—cultivars with long internodes produce open, extended shoots with widely-spaced leaves, while short-internode cultivars create compact shoots with closely-spaced, overlapping leaves. ||The disposition also affects cluster distribution and exposure, as clusters develop at nodes and internode length determines cluster spacing along the shoot. ||Long internodes are associated with lower shoot stiffness (contributing to trailing growth habit) and less dense canopies, while short internodes create stiffer shoots (contributing to upright habit) and potentially denser canopies at equivalent shoot numbers. ||Internode_Length_Disposition is quantified as mean internode length measured on primary shoots at standardized developmental stage, typically at full shoot extension when internode elongation is complete.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (1992) An empirical model for the simulation of leaf appearance and leaf area development of primary shoots of several grapevine (Vitis vinifera L.) canopy systems, Scientia Horticulturae 52:179-200|| Keller M et al. (2004) Warm spring temperatures induce persistent season-long changes in shoot development in grapevines, Annals of Botany 93:739-746|| Louarn G et al. (2007) A method to assess light interception efficiency of a grapevine canopy based on shoot architecture and leaf area distribution, Australian Journal of Grape and Wine Research 13:29-38"
  },
  "Long_Internode_Disposition": {
    "definition": "A Long_Internode_Disposition is an Internode_Length_Disposition that inheres in Vitis vinifera shoots and is realized through extended cell elongation producing internodes exceeding 9 cm mean length, resulting in open, extended shoot architecture with widely-spaced leaves and clusters, and typically contributing to trailing growth habit through reduced shoot stiffness.", 
    "alternative_term": "extended internode | wide node spacing | open shoot architecture |+ Lange-Internodien-Disposition | Weiter-Knotenabstand | Offene-Triebarchitektur",
    "example_of_usage": "Documentation of Long_Internode_Disposition at INRAE Montpellier characterized shoot architecture in cultivars with extended internode development. ||Reference cultivars 'Silvaner', 'Gewürztraminer', 'Riesling', and 'Müller-Thurgau' were assessed for internode dimensions, associated canopy properties, and mechanical characteristics. ||Long_Internode_Disposition cultivars showed consistent characteristics. 'Silvaner' exhibited archetypal long internodes with mean length of 10.2 cm (nodes 5-15), standard deviation of 1.8 cm, and individual internodes reaching 14 cm in the mid-shoot region. ||Shoot length to node number ratio was 11.8 cm/node (compared to 7.2 for short-internode types). 'Gewürztraminer' showed the longest internodes (11.5 cm mean) among commercial cultivars assessed. ||Canopy density analysis revealed that Long_Internode_Disposition cultivars achieved 1.4 leaf layers at 18 shoots/m cordon, compared to 2.1 leaf layers for short-internode cultivars at equivalent shoot density, demonstrating the canopy-opening effect of extended internodes. ||Cluster spacing averaged 12.5 cm in long-internode cultivars versus 7.2 cm in short-internode types, potentially affecting within-canopy Botrytis spread (cluster-to-cluster contact reduced). ||Shoot stiffness measurements confirmed the mechanical association—flexural rigidity averaged 1.6 N·mm² in Long_Internode_Disposition cultivars versus 2.6 N·mm² in short-internode types, explaining the tendency toward trailing growth. ||Cell anatomy revealed that long internodes resulted primarily from increased cell length (215 μm versus 130 μm) rather than cell number, indicating that cell expansion capacity is the primary determinant of Long_Internode_Disposition.",
    "editor_note": "Long_Internode_Disposition is_a Internode_Length_Disposition representing extended internode length (> 9 cm mean). ||Characterized by high cell elongation, lower shoot stiffness, and association with trailing growth habit. ||Examples include 'Silvaner', 'Gewürztraminer', 'Riesling', 'Müller-Thurgau', 'Pinot Gris'. ||Advantages include naturally open canopy, good light penetration, wide cluster spacing. ||Associated with high gibberellin sensitivity. ||Many German/Alsatian cultivars show this trait, potentially reflecting adaptation to humid climates where open canopies reduce disease.  This disposition represents the upper range of internode dimensions, characteristic of cultivars with high gibberellin sensitivity or prolonged cell expansion phase that produces elongated internodes. ||Long-internode cultivars develop shoots where individual leaves are distinctly separated, light penetrates readily between leaf positions, and clusters are widely spaced along the fruiting zone. ||The mechanical consequence of long internodes is reduced shoot stiffness (each segment is longer relative to its diameter, increasing the bending moment), contributing to the association between long internodes and trailing or horizontal growth habit. ||Viticultural implications include naturally lower canopy density at equivalent shoot numbers (potentially advantageous for fruit exposure), wider cluster spacing (potentially affecting cluster-to-cluster disease spread), and more flexible shoots that may be easier to bend for training but harder to maintain in vertical position. ||Long_Internode_Disposition often co-occurs with Trailing_Growth_Disposition, as both reflect the same underlying shoot mechanical properties, though the correlation is not absolute.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (1992) An empirical model for the simulation of leaf appearance and leaf area development of primary shoots of several grapevine (Vitis vinifera L.) canopy systems, Scientia Horticulturae 52:179-200|| Keller M (2015) The Science of Grapevines: Anatomy and Physiology, 2nd Edition, Academic Press|| Louarn G et al. (2008) Characterization of the light interception efficiency of grapevine, Annals of Botany 101:385-399"
  },
  "Short_Internode_Disposition": {
    "definition": "A Short_Internode_Disposition is an Internode_Length_Disposition that inheres in Vitis vinifera shoots and is realized through limited cell elongation producing internodes of less than 7 cm mean length, resulting in compact shoot architecture with closely-spaced leaves, potentially overlapping leaf blades, and closely-positioned clusters.", 
    "alternative_term": "compact internode | close node spacing | dense shoot architecture |+ Kurze-Internodien-Disposition | Enger-Knotenabstand | Kompakte-Triebarchitektur",
    "example_of_usage": "Characterization of Short_Internode_Disposition at Cornell University documented shoot architecture in cultivars with compact internode development. ||Reference cultivars 'Pinot Noir', 'Gamay', 'Concord', and 'Niagara' were assessed for internode dimensions, canopy properties, and associated management implications. ||Short_Internode_Disposition cultivars showed consistent characteristics. 'Pinot Noir' exhibited archetypal short internodes with mean length of 5.8 cm (nodes 5-15), standard deviation of 0.9 cm (notably lower variability than long-internode types), and maximum internode length of only 7.5 cm. ||Shoot length to node number ratio was 6.8 cm/node. 'Gamay' showed similarly short internodes (6.0 cm mean) with compact canopy architecture. ||Canopy density analysis revealed that Short_Internode_Disposition cultivars developed 2.3 leaf layers at 18 shoots/m cordon, compared to 1.4 leaf layers for long-internode cultivars at equivalent shoot density, demonstrating the canopy-filling effect of compact internodes. ||Cluster spacing averaged 6.8 cm (compared to 12.5 cm in long-internode types), with clusters frequently touching within the fruiting zone, potentially facilitating Botrytis spread. ||Management trials confirmed that Short_Internode_Disposition cultivars required 35% more leaf removal labor to achieve equivalent fruit zone exposure compared to long-internode types at the same shoot density. ||Shoot stiffness was correspondingly higher (2.7 N·mm² versus 1.6 N·mm² for long-internode types), correlating with the upright to semi-upright growth habit typical of short-internode cultivars. ||Cell anatomy showed shorter cell length (125 μm versus 215 μm) as the primary basis for Short_Internode_Disposition.",
    "editor_note": "Short_Internode_Disposition is_a Internode_Length_Disposition representing compact internode length (< 7 cm mean). ||Characterized by limited cell elongation, higher shoot stiffness, and association with upright growth habit. ||Examples include 'Pinot Noir', 'Gamay', 'Concord', 'Niagara'. ||Creates denser canopies requiring more intensive management. ||Close cluster spacing may increase disease transmission risk. ||Associated with lower gibberellin sensitivity. ||Higher shoot stiffness contributes to upright positioning.  This disposition represents the lower range of internode dimensions, characteristic of cultivars with lower gibberellin sensitivity or abbreviated cell expansion phase that produces shortened internodes. ||Short-internode cultivars develop shoots where leaves are closely spaced and may overlap substantially, creating denser canopy conditions at equivalent shoot numbers compared to long-internode types. ||The mechanical consequence of short internodes is increased shoot stiffness (each segment is shorter relative to its diameter, reducing bending tendency), contributing to the association between short internodes and upright growth habit. ||Viticultural implications include naturally higher canopy density requiring more intensive management for adequate light penetration, closer cluster spacing (potentially increasing cluster-to-cluster disease transmission), and stiffer shoots that maintain vertical positioning more readily but may be more difficult to bend for training. ||Short_Internode_Disposition often co-occurs with Upright_Growth_Disposition, reflecting the relationship between internode compactness and shoot mechanical properties.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (1992) An empirical model for the simulation of leaf appearance and leaf area development of primary shoots of several grapevine (Vitis vinifera L.) canopy systems, Scientia Horticulturae 52:179-200|| Smart RE, Robinson M (1991) Sunlight into Wine: A Handbook for Winegrape Canopy Management, Winetitles, Adelaide|| Keller M (2015) The Science of Grapevines: Anatomy and Physiology, 2nd Edition, Academic Press"
  },
  "Leaf_Development_Disposition": {
    "definition": "A Leaf_Development_Disposition is a Growth_And_Development_Disposition that inheres in a Vitis vinifera plant and is realized through the characteristic patterns of leaf initiation, expansion, morphogenesis, and maturation that determine leaf size, shape, internal structure, and functional properties.", 
    "alternative_term": "foliar development | leaf morphogenesis | leaf characteristics |+ Blattentwicklungs-Disposition | Foliare-Entwicklung | Blattmorphogenese",
    "example_of_usage": "Comprehensive characterization of Leaf_Development_Disposition at INRAE Vassal ampelographic collection assessed leaf parameters across 250 cultivars using standardized OIV protocols for mature leaves (node positions 8-12 on primary shoots). ||Measurements included individual leaf area (by image analysis), leaf blade dimensions (length, width), depth and angle of petiolar and lateral sinuses, number and shape of lobes, leaf thickness (fresh weight per unit area), and chlorophyll content (SPAD). ||Leaf_Development_Disposition showed remarkable variation reflecting the diversity within V. vinifera. ||Individual leaf area ranged from 85 cm² ('Petit Manseng') to 385 cm² ('Sultanina'), a 4.5-fold range. ||Leaf dissection varied from nearly entire margins with shallow sinuses ('Sultanina', 'Cinsaut') through moderately 5-lobed ('Cabernet Sauvignon', 'Merlot') to deeply 7-lobed with overlapping sinuses ('Nebbiolo', 'Mourvèdre'). ||Leaf thickness (specific leaf mass) ranged from 28 g/m² ('Pinot Noir', thin) to 52 g/m² ('Grenache', thick). ||Correlation analysis revealed that Leaf_Development_Disposition components were partially independent—leaf size showed only moderate correlation with thickness (r = 0.35) and weak correlation with dissection (r = 0.18), indicating separate genetic control. ||Principal component analysis of leaf characters explained 65% of cultivar variation in the first two components, confirming the discriminatory power of Leaf_Development_Disposition for ampelographic classification. ||Functional analysis demonstrated that leaf size correlated with individual leaf photosynthetic capacity (r = 0.72) but that area-normalized photosynthetic rate was actually higher in smaller, thicker leaves, illustrating the complex relationships between leaf morphology and function.",
    "editor_note": "Leaf_Development_Disposition is_a Growth_And_Development_Disposition representing the developmental program for leaf characteristics. ||Leaf morphology is fundamental for both ampelography (cultivar identification) and vine physiology (canopy function). ||Child classes address specific characteristics including Leaf_Size_Disposition, Leaf_Dissection_Disposition, and Leaf_Thickness_Disposition. ||OIV descriptors provide standardized phenotyping framework. ||Leaf characteristics show both genetic determination (cultivar rankings stable) and environmental plasticity (absolute values vary with conditions).  This disposition represents the developmental program governing leaf organogenesis, from primordium initiation at the shoot apical meristem through cell division, expansion, and differentiation phases that establish final leaf form and function. ||Leaf characteristics are of fundamental importance both for vine physiology (leaves are the primary organs for photosynthesis, transpiration, and gas exchange) and for ampelography (leaf morphology provides key characters for cultivar identification and classification). ||Leaf_Development_Disposition encompasses multiple partially independent characteristics including leaf size (the area of individual leaves), leaf shape and dissection (the outline and degree of lobing), and leaf thickness (mesophyll development and specific leaf mass), each with distinct genetic control and functional implications. ||Leaf characteristics vary substantially among cultivars, providing the morphological basis for traditional ampelographic description systems (OIV descriptors), while also determining canopy function through effects on light interception, photosynthetic capacity, transpiration rate, and microclimate modification. ||Environmental factors modulate leaf expression (light intensity, water status, and temperature affect final leaf dimensions and structure), but genotypic rankings for leaf characteristics are relatively stable, confirming strong genetic determination of Leaf_Development_Disposition.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Galet P (1979) A Practical Ampelography: Grapevine Identification, Cornell University Press|| Organisation Internationale de la Vigne et du Vin (2009) OIV Descriptor List for Grape Varieties and Vitis Species, 2nd Edition|| Chitwood DH et al. (2014) A quantitative genetic basis for leaf morphology in a set of precisely defined tomato introgression lines, Plant Cell 26:2953-2969"
  },
  "Leaf_Size_Disposition": {
    "definition": "A Leaf_Size_Disposition is a Leaf_Development_Disposition that inheres in Vitis vinifera leaves and is realized through the characteristic final area of individual mature leaves, determined by the duration and rate of cell division and expansion during leaf development.", 
    "alternative_term": "individual leaf area | leaf blade size | foliar dimensions |+ Blattgrößen-Disposition | Einzelblattfläche | Blattspreiten-Größe",
    "example_of_usage": "Systematic assessment of Leaf_Size_Disposition at UC Davis compared individual leaf areas across 65 cultivars grown under standardized conditions (VSP, moderate irrigation, uniform vigor). ||Mature leaves from nodes 9-11 were harvested at full expansion, imaged, and area determined by digital analysis. ||Parallel measurements of leaf cell number and cell size (epidermal imprints) were conducted to investigate developmental basis. ||Leaf_Size_Disposition showed wide cultivar variation with distinct developmental patterns. 'Sultanina' (Thompson Seedless) exhibited large leaves with mean individual area of 365 cm² (range 320-410 cm² across seasons), representing approximately 4.2 million cells per leaf with mean cell area of 8,700 μm². 'Cabernet Sauvignon' showed intermediate Leaf_Size_Disposition (195 cm², 2.8 million cells, cell area 7,000 μm²). 'Petit Manseng' displayed small leaves (92 cm², 1.6 million cells, cell area 5,750 μm²), representing the lower range among commercial cultivars. ||Analysis of developmental components revealed that leaf size variation resulted from both cell number differences (2.6-fold range) and cell size differences (1.5-fold range), with cell number contributing approximately 65% of size variation. ||The functional significance was confirmed by canopy analysis—at equivalent shoot density (15 shoots/m), large-leaved 'Sultanina' achieved total leaf area of 4.8 m²/m cordon compared to 2.4 m²/m for small-leaved 'Petit Manseng', demonstrating the 2-fold impact of Leaf_Size_Disposition on canopy area. ||However, light distribution modeling showed that small-leaved canopies achieved more uniform light penetration, with interior leaf illumination 35% higher in 'Petit Manseng' than equivalent-area 'Sultanina' canopies.",
    "editor_note": "Leaf_Size_Disposition is_a Leaf_Development_Disposition addressing individual mature leaf area. ||Leaf size ranges from < 100 cm² to > 350 cm² among cultivars (4-fold range). ||Child classes include Large_Leaf_Disposition (> 200 cm²) and Small_Leaf_Disposition (< 150 cm²). ||Cell number variation (65%) contributes more than cell size (35%) to leaf area differences. ||Leaf size affects canopy area accumulation, light distribution, and boundary layer properties. ||OIV descriptor 065 (leaf blade size) provides standardized phenotyping.  This disposition represents one of the most readily observable and functionally significant leaf characteristics, with individual leaf area varying more than 4-fold among cultivars from less than 100 cm² in small-leaved types to over 350 cm² in large-leaved cultivars. ||Leaf size is established during the approximately 30-40 day period of leaf expansion following emergence, with final size reflecting the genetically-determined number of cell divisions, cell expansion capacity, and responsiveness to environmental conditions during development. ||Leaf_Size_Disposition profoundly affects canopy function—large-leaved cultivars achieve equivalent total canopy leaf area with fewer leaves (lower shoot node number or shoot density), while small-leaved cultivars require more leaves to achieve equivalent area. ||Individual leaf size also affects boundary layer thickness and heat dissipation, transpirational cooling efficiency, and the distribution of light within the canopy (large leaves creating more self-shading). ||The disposition interacts with shoot vigor and node number to determine total canopy leaf area, with high-vigor cultivars with large leaves potentially producing excessive canopy area requiring management intervention.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405|| Palliotti A et al. (2014) Changes in vineyard establishment and canopy management urged by earlier climate-related grape ripening: a review, Scientia Horticulturae 178:43-54|| Organisation Internationale de la Vigne et du Vin (2009) OIV Descriptor List for Grape Varieties and Vitis Species, 2nd Edition"
  },
  "Large_Leaf_Disposition": {
    "definition": "A Large_Leaf_Disposition is a Leaf_Size_Disposition that inheres in Vitis vinifera leaves and is realized through extended cell division and expansion phases producing individual mature leaf areas exceeding 200 cm², creating substantial foliar surfaces that rapidly accumulate canopy leaf area but may contribute to excessive shading in dense canopies.", 
    "alternative_term": "large-leaved cultivar | expansive foliage | high leaf area |+ Großblättrige-Disposition | Großblättrige-Sorte | Hohe-Einzelblattfläche",
    "example_of_usage": "Documentation of Large_Leaf_Disposition at the USDA Grape Germplasm Repository characterized leaf development in cultivars recognized for large foliage. ||Reference cultivars 'Sultanina', 'Emperor', 'Italia', and 'Cardinal' were assessed under standardized conditions with detailed measurements of leaf area, expansion dynamics, and canopy consequences. ||Large_Leaf_Disposition cultivars showed consistent characteristics. 'Sultanina' exhibited archetypal large leaves with mature leaf area of 365 cm² (mean of nodes 9-11), blade length of 22.5 cm and width of 24.8 cm, achieving 90% of final area by 35 days after emergence. ||The expansion rate peaked at 15.2 cm²/day during the rapid growth phase (days 12-22). 'Italia' showed even larger leaves (385 cm², the largest among commercial cultivars assessed) with correspondingly extended expansion period (38 days to 90% area). 'Emperor' displayed typical Large_Leaf_Disposition (325 cm²) with notably thick lamina (see Leaf_Thickness_Disposition). ||Canopy development analysis revealed that Large_Leaf_Disposition cultivars at 15 shoots/m achieved total leaf area index (LAI) of 4.2 m²/m² ground by mid-season, exceeding the optimal range (2.5-3.5 m²/m²) for fruit zone light exposure. ||Fruit zone light penetration in unmanaged Large_Leaf_Disposition canopies averaged only 8% of ambient, compared to 25% in small-leaved cultivars at equivalent shoot density, demonstrating the shading consequence. ||Management trials confirmed that Large_Leaf_Disposition cultivars required either 25% lower shoot density or 40% more leaf removal labor to achieve equivalent canopy light environment compared to moderate-leaved cultivars.",
    "editor_note": "Large_Leaf_Disposition is_a Leaf_Size_Disposition representing individual leaf area > 200 cm². ||Characterized by extended cell division phase, high cell number, and large cell size. ||Examples include 'Sultanina', 'Italia', 'Emperor', 'Cardinal', 'Muscat of Alexandria'. ||Table grape and raisin cultivars commonly show this trait. ||Creates canopy management challenges through rapid area accumulation and increased shading. ||Advantageous in low-vigor situations|| problematic in high-vigor situations. ||OIV descriptor 065 codes 7-9.  This disposition represents the upper range of leaf size, characteristic of cultivars that invest heavily in individual leaf development, producing fewer but larger leaves to achieve total canopy area. ||Large-leaved cultivars develop prominent, visually striking foliage that reaches full expansion over approximately 35-40 days following emergence, with high cell number and large cell size combining to produce extended leaf blades. ||The viticultural implications of Large_Leaf_Disposition include rapid canopy development (fewer leaves required to achieve target leaf area), potentially excessive canopy density at standard shoot densities (requiring shoot thinning or leaf removal), increased self-shading within individual leaves and between leaf layers, larger boundary layer affecting heat dissipation and gas exchange, and distinct visual character affecting vineyard aesthetics. ||Large leaves may be advantageous in low-vigor situations where maximizing leaf area from limited shoot growth is desirable, but can create management challenges in high-vigor situations by contributing to excessive canopy density. ||Many table grape and raisin cultivars exhibit Large_Leaf_Disposition, potentially reflecting selection for vegetative vigor in production systems focused on fruit quantity.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Galet P (1979) A Practical Ampelography: Grapevine Identification, Cornell University Press|| Palliotti A et al. (2014) Changes in vineyard establishment and canopy management urged by earlier climate-related grape ripening: a review, Scientia Horticulturae 178:43-54|| Organisation Internationale de la Vigne et du Vin (2009) OIV Descriptor List for Grape Varieties and Vitis Species, 2nd Edition"
  },
  "Small_Leaf_Disposition": {
    "definition": "A Small_Leaf_Disposition is a Leaf_Size_Disposition that inheres in Vitis vinifera leaves and is realized through abbreviated cell division and limited expansion producing individual mature leaf areas below 150 cm², creating compact foliage that accumulates canopy leaf area more gradually but provides more uniform light distribution within the canopy.", 
    "alternative_term": "small-leaved cultivar | compact foliage | low individual leaf area |+ Kleinblättrige-Disposition | Kleinblättrige-Sorte | Niedrige-Einzelblattfläche",
    "example_of_usage": "Characterization of Small_Leaf_Disposition at the University of Bordeaux documented leaf development in cultivars recognized for compact foliage. ||Reference cultivars 'Petit Manseng', 'Petit Verdot', 'Pinot Noir', and 'Riesling' were assessed under standardized conditions with detailed morphometric and functional analysis. ||Small_Leaf_Disposition cultivars showed consistent characteristics. 'Petit Manseng' exhibited archetypal small leaves with mature leaf area of 92 cm² (mean of nodes 9-11), blade length of 10.8 cm and width of 11.2 cm, achieving 90% of final area by only 26 days after emergence. ||The name \"Petit\" directly references the characteristically small foliage. 'Petit Verdot' showed similarly small leaves (105 cm²) with compact, deeply-dissected morphology. 'Pinot Noir' displayed typical Small_Leaf_Disposition (125 cm²) with moderately thick lamina partially compensating for reduced area. 'Riesling' showed small-to-moderate size (138 cm²). ||Canopy analysis revealed that Small_Leaf_Disposition cultivars at 15 shoots/m achieved LAI of only 2.2 m²/m² by mid-season, below optimal range and potentially limiting photosynthetic capacity. ||However, canopy light distribution was substantially more uniform, with interior leaf illumination averaging 45% of ambient compared to 18% in large-leaved canopies at equivalent LAI. ||Area-normalized photosynthetic rates were actually 15% higher in Small_Leaf_Disposition cultivars, partially compensating for lower total area. ||The correlation between Small_Leaf_Disposition and premium wine cultivars was notable—8 of the 10 highest-ranked Bordeaux varieties showed leaf areas below 160 cm², suggesting that moderate leaf size contributes to the canopy characteristics associated with wine quality.",
    "editor_note": "Small_Leaf_Disposition is_a Leaf_Size_Disposition representing individual leaf area < 150 cm². ||Characterized by abbreviated cell division phase and limited cell expansion. ||Examples include 'Petit Manseng', 'Petit Verdot', 'Pinot Noir', 'Riesling', 'Gamay'. ||Common among premium wine grape cultivars. ||Advantages include more uniform canopy light distribution, reduced shading, and potentially higher area-normalized photosynthesis. ||May require higher shoot density or vigor-enhancing management to achieve adequate canopy area. ||OIV descriptor 065 codes 1-3.  This disposition represents the lower range of leaf size, characteristic of cultivars that produce numerous smaller leaves rather than fewer large leaves to achieve total canopy area. ||Small-leaved cultivars develop modest individual leaves that reach full expansion over approximately 25-30 days, with lower cell number and smaller cell size combining to produce compact leaf blades. ||The viticultural implications of Small_Leaf_Disposition include gradual canopy development (more leaves required to achieve target leaf area), naturally lower canopy density at standard shoot densities (potentially advantageous for fruit exposure), reduced self-shading within the canopy, thinner boundary layer improving gas exchange efficiency, and distinct visual character with finer-textured foliage. ||Small leaves may be disadvantageous in low-vigor situations where limited shoot growth produces insufficient canopy area, but can be advantageous in high-vigor situations by moderating canopy density. ||Small_Leaf_Disposition is often associated with premium wine grape cultivars, potentially reflecting selection for moderate canopies suited to quality-focused production systems, and with cultivars from cooler climates where compact canopy architecture may reduce disease pressure.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Galet P (1979) A Practical Ampelography: Grapevine Identification, Cornell University Press|| Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405|| Organisation Internationale de la Vigne et du Vin (2009) OIV Descriptor List for Grape Varieties and Vitis Species, 2nd Edition"
  },
  "Leaf_Dissection_Disposition": {
    "definition": "A Leaf_Dissection_Disposition is a Leaf_Development_Disposition that inheres in Vitis vinifera leaves and is realized through the characteristic pattern and depth of leaf blade incision, determining the number, shape, and definition of leaf lobes and the depth and form of the sinuses between them.", 
    "alternative_term": "leaf lobing | leaf shape | sinus depth |+ Blattschnitt-Disposition | Blattlappung | Blattzähnung",
    "example_of_usage": "Detailed ampelographic documentation of Leaf_Dissection_Disposition at INRAE Vassal characterized leaf shape parameters across 180 cultivars using standardized OIV descriptors and digital morphometric analysis. ||Measurements included lobe number, petiolar sinus depth and overlap, lateral sinus depth, lobe shape, and the calculation of dissection index (perimeter²/area, higher values indicating greater dissection). ||Leaf_Dissection_Disposition showed remarkable cultivar variation representing the full range of grapevine leaf forms. 'Sultanina' exhibited minimal dissection with nearly entire leaf outline, very shallow lateral sinuses (depth < 15% of blade length), widely open U-shaped petiolar sinus, and low dissection index of 15.2. 'Cabernet Sauvignon' displayed moderate 5-lobed dissection with defined lateral sinuses (depth 25-30% of blade length), moderately open petiolar sinus with parallel sides, and intermediate dissection index of 22.8. 'Nebbiolo' showed strong 7-lobed dissection with deep lateral sinuses (depth 40-45%), overlapping petiolar sinus with lyre shape, and high dissection index of 35.4. 'Mourvèdre' exhibited extreme dissection with very deep lateral sinuses creating distinct narrow lobes, strongly overlapping petiolar sinus, and dissection index reaching 42.1. ||The functional significance of dissection was confirmed by boundary layer measurements—highly dissected 'Nebbiolo' leaves showed 25% higher boundary layer conductance than entire-leaved 'Sultanina' at equivalent leaf area, potentially enhancing gas exchange efficiency. ||Dissection also affected light transmission through the canopy, with highly dissected leaves allowing 18% more direct light penetration through gaps between lobes.",
    "editor_note": "Leaf_Dissection_Disposition is_a Leaf_Development_Disposition addressing leaf shape and lobing pattern. ||Dissection is a primary ampelographic character with high discriminatory value for cultivar identification. ||Key descriptors include lobe number (3, 5, 7), petiolar sinus depth and shape, and lateral sinus depth. ||Dissection index (perimeter²/area) provides quantitative measure. ||Functional implications include boundary layer conductance and canopy light penetration. ||OIV descriptors 068 (shape of blade), 079-083 (sinus characters) provide standardized phenotyping.  This disposition represents one of the most important ampelographic characters, as leaf shape and dissection pattern are highly distinctive among cultivars and relatively stable across environments, providing reliable identification criteria. ||Leaf dissection results from differential growth patterns during early leaf development, where regions destined to become sinuses show reduced cell division and expansion compared to lobe regions, creating the characteristic incised leaf outline. ||The degree of dissection ranges from nearly entire (unlobed, with shallow sinuses) through 3-lobed, 5-lobed, to deeply 7-lobed with narrow, deeply-incised sinuses that may overlap at the petiolar sinus. ||Key descriptive characters include the number of lobes (3, 5, or 7), the depth of the petiolar sinus (very open to overlapping), the shape of the petiolar sinus (U-shaped, V-shaped, lyre-shaped), and the depth and shape of lateral sinuses. ||Leaf_Dissection_Disposition has functional implications beyond ampelography—deeply dissected leaves have higher perimeter-to-area ratios enhancing boundary layer conductance, more complex three-dimensional structure potentially improving light penetration within the canopy, and distinct aerodynamic properties affecting flutter and self-shading.",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Galet P (1979) A Practical Ampelography: Grapevine Identification, Cornell University Press|| Chitwood DH et al. (2014) A quantitative genetic basis for leaf morphology in a set of precisely defined tomato introgression lines, Plant Cell 26:2953-2969|| Organisation Internationale de la Vigne et du Vin (2009) OIV Descriptor List for Grape Varieties and Vitis Species, 2nd Edition"
  },
  "Leaf_Thickness_Disposition": {
    "definition": "A Leaf_Thickness_Disposition is a Leaf_Development_Disposition that inheres in Vitis vinifera leaves and is realized through the characteristic development of mesophyll tissue determining leaf thickness, specific leaf mass (mass per unit area), and the internal structural framework affecting photosynthetic capacity and stress tolerance.", 
    "alternative_term": "specific leaf mass | leaf mass per area | mesophyll development |+ Blattdicken-Disposition | Spezifische-Blattmasse | Mesophyll-Entwicklung",
    "example_of_usage": "Physiological characterization of Leaf_Thickness_Disposition at the University of Burgundy measured leaf structural parameters and associated functional properties across 45 cultivars. ||Measurements included leaf thickness (micrometer), specific leaf mass (SLM, g fresh weight per m²), leaf dry matter content, mesophyll anatomy (palisade and spongy layer thickness), and functional correlates (area-based photosynthetic rate, water content, leaf thermal properties). ||Leaf_Thickness_Disposition showed substantial cultivar variation with clear functional associations. 'Grenache' exhibited thick leaves with SLM of 52 g/m², leaf thickness of 385 μm, well-developed two-layer palisade mesophyll (145 μm total), and dense spongy mesophyll with small intercellular spaces. ||Area-based photosynthetic capacity (Amax) reached 18.5 μmol CO₂ m⁻² s⁻¹, among the highest measured. 'Mourvèdre' showed similarly thick leaves (SLM 48 g/m²) with high photosynthetic capacity. 'Pinot Noir' displayed thin leaves with SLM of 32 g/m², thickness of 265 μm, single-layer palisade (75 μm), and loose spongy mesophyll with large air spaces. ||Amax was lower at 12.8 μmol m⁻² s⁻¹, though mass-based photosynthetic rate was actually similar. 'Riesling' showed intermediate thickness (SLM 38 g/m²). ||Correlation analysis confirmed that Leaf_Thickness_Disposition was associated with geographic origin—Mediterranean cultivars averaged SLM of 46 g/m² versus 36 g/m² for Northern European cultivars (P < 0.001). ||Drought tolerance trials revealed that thick-leaved cultivars maintained higher relative water content (85% versus 72% at Ψleaf = -1.5 MPa) and recovered more rapidly after stress, demonstrating the functional significance of Leaf_Thickness_Disposition for water relations.",
    "editor_note": "Leaf_Thickness_Disposition is_a Leaf_Development_Disposition addressing mesophyll development and leaf density. ||Specific leaf mass (g/m²) is the standard quantitative measure. ||Thick leaves (SLM > 45 g/m²) show higher area-based photosynthetic capacity and drought tolerance. ||Thin leaves (SLM < 35 g/m²) have lower construction cost and potentially faster expansion. ||Mediterranean-origin cultivars typically show thicker leaves than Northern European cultivars. ||Palisade mesophyll development is the primary determinant of thickness variation. ||Environmental factors (light, water) modulate expression but genotypic ranking is stable.  This disposition represents the investment of resources into leaf internal structure versus surface expansion, reflecting the balance between palisade mesophyll development (columnar photosynthetic cells), spongy mesophyll development (air space and gas exchange), and epidermal/structural tissue that together establish leaf thickness and density. ||Leaf thickness varies approximately 2-fold among cultivars, from thin leaves (specific leaf mass < 35 g/m²) with limited mesophyll development to thick leaves (> 45 g/m²) with multiple palisade layers and dense spongy mesophyll. ||Leaf_Thickness_Disposition has important functional implications—thicker leaves typically show higher photosynthetic capacity per unit area (more chloroplasts and Rubisco), greater water storage and drought tolerance, higher heat capacity moderating temperature fluctuations, and greater structural durability reducing physical damage. ||However, thick leaves also have higher construction cost and potentially slower expansion rates. ||The disposition reflects adaptation to environmental conditions, with thick leaves characteristic of cultivars from hot, dry Mediterranean environments (high light, water limitation) and thin leaves more common in cultivars from cooler, humid regions (lower light, adequate water).",
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought, Plant Cell and Environment 26:1393-1405|| Tomás M et al. (2014) Variability of mesophyll conductance in grapevine cultivars under water stress conditions in relation to leaf anatomy and water use efficiency, Australian Journal of Grape and Wine Research 20:272-280|| Flexas J et al. (2008) Mesophyll conductance to CO2: current knowledge and future prospects, Plant Cell and Environment 31:602-621"
  },
  "Tendril_Development_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to develop tendrils as modified shoots homologous to inflorescences, characterized by the phyllotactic pattern of tendril placement along the shoot axis and the morphological vigor of tendril formation.",
    "alternative_term": "tendril formation capacity | tendril production trait |+ Rankenbildungsvermögen | Rankenentwicklungsdisposition",
    "example_of_usage": "Vitis vinifera displays the characteristic 2:1 phyllotaxy with tendrils present at two consecutive nodes followed by one node without tendril, while some cultivars like 'Sultanina' show modified patterns with occasional 3:1 arrangements. ||Tendril dry weight allocation ranges from 2-8% of total shoot biomass depending on cultivar and trellis system.",
    "editor_note": "Tendril_Development_Disposition serves as the parent class for tendril-related traits. ||Tendrils in Vitis are developmentally homologous to inflorescences, sharing the same meristematic origin, with the uncommitted primordia (anlagen) differentiating into either structure based on gibberellin signaling. ||The VvTFL1A gene plays a key role in maintaining tendril identity versus inflorescence conversion.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mullins MG, Bouquet A, Williams LE (1992) Biology of the Grapevine, Cambridge University Press pp.: 52-58|| Carmona MJ et al. (2008) A molecular genetic perspective of reproductive development in grapevine. Journal of Experimental Botany 59:2579-2596|| Calonje M et al. (2004) Floral meristem identity genes are expressed during tendril development in grapevine. Plant Physiology 135:1تم491-1501"
  },
  "Strong_Tendril_Disposition": {
    "definition": "A tendril development disposition that is the inherited capacity of a Vitis vinifera plant to produce tendrils with high biomass, rapid elongation rate, strong coiling response, and persistent attachment strength, enabling effective climbing and canopy support.",
    "alternative_term": "vigorous tendril formation | strong climbing capacity | high tendril vigor |+ starke Rankenbildung | kräftige Rankenentwicklung | hohe Rankenkraft",
    "example_of_usage": "Cabernet Sauvignon exhibits strong tendril disposition with tendril elongation rates of 8-12 cm/day during active growth, coiling response initiated within 30-60 minutes of contact, and attachment tensile strength exceeding 15 N. ||Wild Vitis species such as V. riparia show even stronger tendril development with attachment forces up to 25 N, reflecting their natural climbing habit in forest margins.",
    "editor_note": "Strong tendril disposition correlates with vigorous vegetative growth patterns and is particularly pronounced in cultivars derived from wild Vitis species. ||The coiling mechanism involves differential cell elongation on the contact versus non-contact side mediated by auxin redistribution and jasmonat signaling. ||Strong tendrils may require more frequent shoot positioning in VSP systems but provide better natural support in minimal-pruning systems.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 42-45|| Bowling AJ, Bhattacharya S (2022) Tendril coiling in Vitis: biomechanics and molecular mechanisms. American Journal of Botany 109:234-248"
  },
  "Weak_Tendril_Disposition": {
    "definition": "A tendril development disposition that is the inherited capacity of a Vitis vinifera plant to produce tendrils with reduced biomass, slower elongation rate, delayed or diminished coiling response, and lower attachment strength, resulting in limited natural climbing ability.",
    "alternative_term": "reduced tendril formation | weak climbing capacity | low tendril vigor |+ schwache Rankenbildung | reduzierte Rankenentwicklung | geringe Rankenkraft",
    "example_of_usage": "Pinot Noir displays relatively weak tendril disposition with tendril elongation rates of 4-6 cm/day, delayed coiling response (2-4 hours post-contact), and attachment tensile strength of 5-10 N. ||Table grape cultivars selected for ease of harvest such as 'Thompson Seedless' often exhibit weak tendril traits, facilitating bunch removal. ||Some dwarfing rootstocks reduce scion tendril vigor by 20-35% compared to vigorous rootstocks.",
    "editor_note": "Weak tendril disposition may be advantageous in highly managed vineyard systems where tendrils can interfere with mechanical harvesting or require additional labor for removal. ||The trait shows moderate heritability (h² ≈ 0.45) and correlates weakly with overall plant vigor (r = 0.38), indicating partial genetic independence. ||Reduced tendril strength in some cultivars may reflect selection pressure during domestication for ease of training.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "This OD, Martinez-Zapater JM (2016) Genetic and genomic approaches for adaptation of grapevine to climate change. In: Gerós H et al. (eds) Grapevine in a Changing Environment, Wiley pp.: 157-178|| Dry PR et al. (2010) Canopy management for fruitfulness. Australian Journal of Grape and Wine Research 16:25-35"
  },
  "Lignification_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to deposit lignin polymers in secondary cell walls of shoot tissues, transforming green herbaceous shoots into woody canes through progressive sclerenchyma development and vascular tissue maturation.",
    "alternative_term": "shoot lignification capacity | cane woodiness trait | shoot hardening disposition |+ Verholzungsvermögen | Lignifizierungsdisposition | Triebausreifung",
    "example_of_usage": "Lignification typically initiates at basal internodes when shoots reach 40-60 cm length, progressing acropetally at rates of 1-2 nodes per week under optimal conditions. ||Cabernet Sauvignon achieves 85-95% cane lignification by leaf fall in temperate climates, while Grenache in warm Mediterranean conditions may reach only 70-80% due to extended vegetative growth. ||Lignin content in mature canes ranges from 18-24% of dry weight depending on cultivar.",
    "editor_note": "Lignification_Disposition serves as the parent class for shoot maturation traits critical to winter survival and carbohydrate reserve storage. ||The process involves coordinated expression of phenylpropanoid pathway genes including PAL, C4H, 4CL, and CAD. ||Lignification is promoted by moderate water stress, reduced nitrogen availability, and shorter photoperiods, while excessive vigor delays the process.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 68-75|| Bouquet A, Danglot Y (1996) Inheritance of several traits in grapevine. Vitis 35:89-94"
  },
  "Early_Lignification_Disposition": {
    "definition": "A lignification disposition that is the inherited capacity of a Vitis vinifera plant to initiate and complete shoot lignification earlier in the growing season relative to other cultivars, characterized by rapid color change from green to brown, accelerated periderm formation, and early cessation of shoot elongation.",
    "alternative_term": "early cane maturation | precocious lignification | early shoot hardening |+ frühe Verholzung | frühe Triebausreifung | vorzeitige Lignifizierung",
    "example_of_usage": "Pinot Noir exhibits early lignification disposition with visible browning of basal internodes by mid-July in Burgundy (approximately 60 days post-budbreak), completing 90% lignification 3-4 weeks before Grenache under identical conditions. ||Riesling shows early lignification completing by late August in German wine regions, contributing to its exceptional cold hardiness reaching -22°C LT50. ||Early-lignifying cultivars typically allocate 25-35% more starch reserves to perennial tissues before leaf fall.",
    "editor_note": "Early lignification correlates strongly with cold hardiness (r = 0.78) and is a key selection criterion for cultivars in continental climates. ||The trait shows moderate to high heritability (h² = 0.55-0.70) and is influenced by the VvMYB5a and VvMYB5b transcription factors regulating phenylpropanoid biosynthesis. ||Rootstock influence on scion lignification timing is moderate, with vigor-reducing rootstocks promoting earlier maturation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines. Journal of Crop Improvement 10:201-235|| Schnabel BJ, Wample RL (1987) Dormancy and cold hardiness in Vitis vinifera L. cv. White Riesling as influenced by photoperiod and temperature. American Journal of Enology and Viticulture 38:265-272"
  },
  "Complete_Cane_Maturation_Disposition": {
    "definition": "A lignification disposition that is the inherited capacity of a Vitis vinifera plant to achieve thorough lignification along the entire length of current-season shoots, including distal internodes, resulting in fully mature canes with continuous periderm coverage and maximal cold hardiness potential.",
    "alternative_term": "full shoot maturation | complete cane ripening | thorough lignification |+ vollständige Triebausreifung | komplette Holzreife | durchgehende Verholzung",
    "example_of_usage": "Chasselas demonstrates complete cane maturation disposition with 95-100% of internode length lignified by October in Swiss vineyards, including apical internodes within 5 cm of the shoot tip. ||In contrast, Carignan frequently shows incomplete maturation with 15-25% of distal shoot length remaining green at leaf fall in southern France. ||Complete maturation correlates with survival of 18-22 nodes per cane during winter, versus only 10-14 nodes in incompletely matured cultivars experiencing -15°C minimum temperatures.",
    "editor_note": "Complete cane maturation is essential for spur-pruned training systems requiring viable buds at distal positions. ||The trait depends on timely cessation of vegetative growth, adequate carbohydrate supply, and appropriate environmental signals. ||Excessive nitrogen fertilization, late-season irrigation, and crop overcropping reduce maturation completeness. ||Assessment typically uses the percentage of brown versus green internode tissue at natural leaf fall.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Galet P (2000) General Viticulture, Oenoplurimedia, Chaintre pp.: 185-192|| Howell GS (2001) Sustainable grape productivity and the growth-yield relationship: a review. American Journal of Enology and Viticulture 52:165-174"
  },
  "Periderm_Development_Disposition": {
    "definition": "A lignification disposition that is the inherited capacity of a Vitis vinifera plant to form a continuous protective periderm layer around maturing shoots through phellogen activity, producing cork cells (phellem) externally and phelloderm internally, providing barrier functions against desiccation and pathogen entry.",
    "alternative_term": "cork layer formation | bark development capacity | periderm maturation |+ Peridermbildung | Korkschichtentwicklung | Borkenbildungsvermögen",
    "example_of_usage": "Syrah exhibits robust periderm development disposition with cork layer thickness reaching 180-220 µm by dormancy and complete circumferential coverage by node 8-10. ||Müller-Thurgau shows thinner periderm development (100-140 µm) with occasional gaps at lenticels increasing susceptibility to desiccation injury. ||Periderm suberin content varies from 35-55% of cork cell wall dry weight, with higher values in cultivars adapted to continental climates. ||The phellogen initiates 15-25 days after lignification begins at each internode.",
    "editor_note": "Periderm development is distinct from but coordinated with xylem lignification. ||The phellogen (cork cambium) arises from dedifferentiation of cortical parenchyma cells. ||Periderm quality affects winter desiccation tolerance, Eutypa infection risk at pruning wounds, and grafting success through callus-periderm interactions. ||VvMYB93 regulates suberin biosynthesis genes during periderm formation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Evert RF (2006) Esau's Plant Anatomy: Meristems, Cells, and Tissues of the Plant Body, 3rd Ed, Wiley pp.: 427-445|| Pollard M et al. (2008) Building lipid barriers: biosynthesis of cutin and suberin. Trends in Plant Science 13:236-246"
  },
  "Senescence_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to undergo programmed developmental decline of leaves and other annual tissues at season end, involving chlorophyll degradation, macromolecule catabolism, nutrient remobilization to perennial organs, and eventual abscission.",
    "alternative_term": "autumn senescence capacity | leaf aging disposition | seasonal decline trait |+ Seneszenzverhalten | Blattaltungsdisposition | herbstliche Abbauprozesse",
    "example_of_usage": "Leaf senescence in grapevine initiates 2-4 weeks post-harvest in most cultivars, with chlorophyll content declining from 350-450 µg/cm² to below 50 µg/cm² over 25-40 days. ||Tempranillo exhibits early senescence disposition with 50% chlorophyll loss by late September in Rioja, while Mourvèdre retains green leaves until mid-November in Provence. ||The senescence-associated gene VvNAC26 shows 8-15 fold upregulation during leaf yellowing.",
    "editor_note": "Senescence_Disposition serves as the parent class for autumn decline processes. ||Unlike stress-induced premature senescence, developmental senescence is a genetically programmed process optimized by natural selection for nutrient recovery and cold hardiness preparation. ||The process involves orderly dismantling of chloroplasts, protein degradation via autophagy, and phloem loading of remobilized nutrients.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lim PO, Kim HJ, Nam HG (2007) Leaf senescence. Annual Review of Plant Biology 58:115-136|| Ferrara G et al. (2015) Grapevine leaf senescence: a review. Vitis 54:125-133"
  },
  "Leaf_Senescence_Timing_Disposition": {
    "definition": "A senescence disposition that is the inherited capacity of a Vitis vinifera plant to initiate and progress through leaf senescence at a characteristic time relative to harvest and environmental cues, determining the duration of post-harvest photosynthetic activity and nutrient recovery period.",
    "alternative_term": "autumn coloration timing | leaf drop timing | senescence onset trait |+ Blattalterungszeitpunkt | Seneszenz-Timing | Herbstlaubfärbungszeitpunkt",
    "example_of_usage": "Gewürztraminer exhibits early leaf senescence timing with visible yellowing 10-14 days post-harvest in Alsace, completing abscission by mid-October. ||Cinsault maintains photosynthetically active leaves for 45-60 days post-harvest in Mediterranean climates, enabling 15-25% greater starch reserve accumulation compared to early-senescing cultivars. ||The interval between 10% and 90% leaf yellowing spans 18-28 days in most V. vinifera cultivars, with tight clustering (18-22 days) indicating synchronized senescence.",
    "editor_note": "Leaf senescence timing represents a trade-off between extended photosynthesis for reserve accumulation versus early nutrient remobilization and cold acclimation initiation. ||Early-ripening cultivars typically show later relative senescence (more days post-harvest) than late-ripening cultivars. ||Photoperiod and temperature interact to trigger senescence, with short days and cool nights accelerating the process independently.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Parker AK et al. (2011) General phenological model to characterise the timing of flowering and veraison of Vitis vinifera L. Australian Journal of Grape and Wine Research 17:206-216|| Bennett J et al. (2005) Leaf senescence and fruit ripening: influence of post-harvest factors. Australian and New Zealand Grapegrower and Winemaker 497:22-26"
  },
  "Nutrient_Remobilization_Disposition": {
    "definition": "A senescence disposition that is the inherited capacity of a Vitis vinifera plant to efficiently catabolize macromolecules in senescing leaves and redistribute the resulting nutrients (particularly nitrogen, phosphorus, and potassium) to perennial storage tissues in roots, trunk, and cordons for use in the following season.",
    "alternative_term": "nutrient recycling efficiency | autumn nutrient recovery | reserve translocation capacity |+ Nährstoffrückverlagerung | Reservestoffverlagerung | herbstliche Nährstoffremobilisierung",
    "example_of_usage": "Efficient cultivars such as Sangiovese remobilize 65-75% of leaf nitrogen to perennial tissues, reducing leaf N from 2.8% to 0.9% dry weight during senescence. ||Merlot shows moderate remobilization efficiency (55-65% N recovery), while Petit Verdot exhibits lower efficiency (45-55%). ||Phosphorus remobilization reaches 70-85% in most cultivars, with K remobilization more variable (40-70%) due to its high phloem mobility but competition with fruit demand. ||Root starch content increases 40-80% between harvest and dormancy in well-managed vines.",
    "editor_note": "Nutrient remobilization efficiency affects vine sustainability, fertilizer requirements, and spring growth vigor. ||The process depends on adequate post-harvest leaf area duration, functional phloem connections, and sink strength of perennial tissues. ||Premature defoliation from disease or frost severely reduces remobilization. ||Nitrogen remobilization involves protein degradation to amino acids (particularly glutamine and asparagine) transported via phloem.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Zapata C et al. (2004) Partitioning and mobilization of starch and N reserves in grapevine. American Journal of Enology and Viticulture 55:83-88|| Schreiner RP et al. (2006) N, P, and K supply to Pinot noir grapevines: growth, yield, and fruit composition. American Journal of Enology and Viticulture 57:286-293"
  },
  "Reproductive_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to undergo sexual reproduction through the coordinated development of flowers, pollination, fertilization, and fruit set, encompassing all traits related to inflorescence formation, gametophyte development, and the transition from flower to berry.",
    "alternative_term": "reproductive capacity | sexual reproduction trait | generative disposition |+ Reproduktionsvermögen | generative Disposition | Fortpflanzungsfähigkeit",
    "example_of_usage": "Reproductive success in grapevine varies from 15-50% fruit set depending on cultivar, with Chardonnay achieving 35-45% berry set under optimal conditions while Merlot typically reaches only 20-30%. ||The transition from vegetative to reproductive growth involves 2-3 season lead time, with inflorescence primordia initiating in latent buds during the previous growing season. ||Reproductive allocation (berry dry weight / total above-ground dry weight) ranges from 25-45% in commercially managed vineyards.",
    "editor_note": "Reproductive_Disposition serves as the top-level parent class for all traits related to grapevine sexual reproduction. ||The category encompasses flowering biology, fruit set mechanisms, seedlessness traits, fruitfulness, and cluster architecture. ||Grapevine reproductive biology is complicated by the two-year developmental cycle where inflorescence primordia form in year N-1 but flowers open in year N.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Carmona MJ et al. (2008) A molecular genetic perspective of reproductive development in grapevine. Journal of Experimental Botany 59:2579-2596|| Mullins MG, Bouquet A, Williams LE (1992) Biology of the Grapevine, Cambridge University Press pp.: 80-117"
  },
  "Flowering_Disposition": {
    "definition": "A reproductive disposition that is the inherited capacity of a Vitis vinifera plant to develop functional inflorescences and individual flowers, encompassing traits related to flower organogenesis, calyptra formation, anthesis timing, and the coordination of male and female reproductive structures within flowers.",
    "alternative_term": "flowering capacity | bloom trait | anthesis disposition |+ Blühvermögen | Blühdisposition | Blühfähigkeit",
    "example_of_usage": "Grapevine flowering (anthesis) occurs over 5-15 days per vine, with Sauvignon Blanc completing flowering in 6-8 days under warm conditions (daily mean >18°C) while Cabernet Franc may require 12-15 days during cool springs. ||Individual flower opening involves calyptra abscission triggered by turgor pressure, typically occurring between 06:00-10:00 hours. ||A single inflorescence contains 100-500 individual flowers depending on cultivar, with Grenache averaging 350-450 flowers and Pinot Noir 150-250 flowers per cluster.",
    "editor_note": "Flowering_Disposition encompasses both the structural aspects of flower development and the temporal dynamics of anthesis. ||The grapevine flower is small (2-3 mm diameter), hypogynous, and pentamerous with a distinctive calyptra (fused petals) rather than separate petals. ||Flowering duration and synchrony significantly impact fruit set success and cluster uniformity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 95-115|| Vasconcelos MC et al. (2009) The flowering process of Vitis vinifera: a review. American Journal of Enology and Viticulture 60:411-434"
  },
  "Flower_Type_Disposition": {
    "definition": "A flowering disposition that is the inherited capacity of a Vitis vinifera plant to develop flowers of a specific sexual morphology, determined by the functional presence or absence of male (androecium) and female (gynoecium) reproductive organs within individual flowers.",
    "alternative_term": "flower sex type | floral morphology trait | sexual type disposition |+ Blütentyp | Blütengeschlecht | Blütenmorphologie-Disposition",
    "example_of_usage": "Wild Vitis species are predominantly dioecious with separate male and female vines, while domesticated V. vinifera cultivars are 99% hermaphroditic due to selection during domestication. ||The sex-determining region on chromosome 2 spans approximately 150 kb and includes the VviFSEX gene. ||Flower sex ratios in wild V. vinifera ssp. sylvestris populations show approximately 50% male, 40% female, and 10% hermaphrodite individuals.",
    "editor_note": "Flower_Type_Disposition serves as the parent class for specific sex morphologies. ||Grapevine flower sex determination involves a two-locus genetic model with male-sterility and female-sterility factors. ||Hermaphroditism arose through a mutation suppressing female-sterility in male flowers. ||Some cultivars show partial reversion to ancestral forms under stress conditions.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Picq S et al. (2014) A small XY chromosomal region explains sex determination in wild dioecious V. vinifera and the reversal to hermaphroditism in domesticated grapevines. BMC Plant Biology 14:229|| This P et al. (2006) Historical origins and genetic diversity of wine grapes. Trends in Genetics 22:511-519"
  },
  "Hermaphrodite_Flower_Disposition": {
    "definition": "Hermaphrodite_Flower_Disposition is a flower type disposition, that is the inherited capacity of a Vitis vinifera plant to develop perfect (bisexual) flowers containing both functional stamens producing viable pollen and a functional pistil with receptive stigma, enabling self-pollination and cross-pollination within a single flower.",
    "alternative_term": "perfect flower trait | bisexual flower disposition | complete flower capacity |+ Zwitterblütigkeit | Hermaphroditismus | zwittrige Blütenanlage",
    "example_of_usage": "All major wine grape cultivars including Cabernet Sauvignon, Chardonnay, Riesling, and Tempranillo possess hermaphrodite flower disposition with upright stamens (5 per flower) surrounding a central pistil. ||Pollen viability in hermaphrodite cultivars ranges from 70-95%, with Pinot Noir averaging 85-90% and Gewürztraminer showing lower viability at 70-80%. ||Self-pollination accounts for 30-70% of fertilization events in hermaphrodite cultivars depending on vineyard configuration, with the remainder from cross-pollination by adjacent vines.",
    "editor_note": "Hermaphrodite flower disposition is the predominant condition in cultivated V. vinifera, arising from domestication selection for reliable fruit set without requiring male pollinizer vines. ||The trait is controlled by the Sex locus on chromosome 2, with the hermaphrodite allele (H) dominant to both male (M) and female (F) alleles. ||Functional hermaphroditism requires coordinated development of both organ types and synchronous maturation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 98-105|| Oberle GD (1938) A genetic study of variations in floral morphology and function in cultivated forms of Vitis. New York Agricultural Experiment Station Technical Bulletin 250:1-63"
  },
  "Female_Flower_Disposition": {
    "definition": "A flower type disposition that is the inherited capacity of a Vitis vinifera plant to develop pistillate (functionally female) flowers containing a fully developed pistil with receptive stigma but only reflexed, non-functional stamens producing sterile or absent pollen, requiring cross-pollination from hermaphrodite or male vines for fruit set.",
    "alternative_term": "pistillate flower trait | female vine disposition | functionally female flower |+ Weiblichkeit | weibliche Blütenanlage | pistillate Blühdisposition",
    "example_of_usage": "Female flower disposition characterizes wild V. vinifera ssp. sylvestris populations (approximately 40% of individuals) and rare cultivated varieties. ||Stamens in female flowers are reflexed (bent downward and away from the pistil) and produce shriveled, non-viable pollen or no pollen at all. ||Female vines require pollinizer rows within 15-30 m for adequate fruit set, with pollen transfer primarily by wind. ||Some table grape cultivars including Almeria (Ohanez) and certain Muscats possess female flowers, requiring interplanting with hermaphrodite pollinizers at ratios of 1:8 to 1:10.",
    "editor_note": "Female flower disposition results from homozygosity for the female allele (ff) at the Sex locus. ||The reflexed stamen phenotype results from failure of filament elongation during flower development. ||Female-flowered cultivars were more common in historical viticulture before the advantages of hermaphroditism were understood, and persist in some traditional growing regions and wild populations.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Antcliff AJ (1980) Inheritance of sex in Vitis. Annales de l'Amélioration des Plantes 30:113-122|| Negi SS, Olmo HP (1971) Conversion and determination of sex in Vitis vinifera L. Vitis 9:265-279"
  },
  "Male_Flower_Disposition": {
    "definition": "A flower type disposition that is the inherited capacity of a Vitis vinifera plant to develop staminate (functionally male) flowers containing fully developed stamens producing abundant viable pollen but possessing only a vestigial, non-functional pistil incapable of fruit development, serving exclusively as a pollen source.",
    "alternative_term": "staminate flower trait | male vine disposition | functionally male flower |+ Männlichkeit | männliche Blütenanlage | staminate Blühdisposition",
    "example_of_usage": "Male flower disposition characterizes approximately 50% of wild V. vinifera ssp. sylvestris individuals and some Vitis species used as rootstocks. ||Male flowers produce 2-3 times more pollen per flower than hermaphrodite flowers (15,000-25,000 vs 8,000-12,000 pollen grains), but the pistil remains rudimentary with an undeveloped ovary. ||V. rupestris and some V. riparia selections used in rootstock breeding possess male flowers. ||In breeding programs, male parents contribute genetic diversity without fruit production, requiring controlled pollination to generate progeny.",
    "editor_note": "Male flower disposition results from the presence of the male allele (M) with female-sterility function at the Sex locus. ||Male-flowered vines are excluded from commercial fruit production but remain important in rootstock breeding and as genetic resources. ||The vestigial pistil in male flowers arrests development at the ovary primordium stage, lacking ovule differentiation. ||Some interspecific hybrids show unstable sex expression with partial pistil development.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fechter I et al. (2012) Candidate genes within a 143 kb region of the flower sex locus in Vitis. Molecular Genetics and Genomics 287:247-259|| Gallardo A et al. (2009) Pollen development and fertility in Vitis vinifera L. cv. Macabeo: a comparison between male-sterile and fertile flowers. American Journal of Enology and Viticulture 60:353-361"
  },
  "Inflorescence_Development_Disposition": {
    "definition": "A flowering disposition that is the inherited capacity of a Vitis vinifera plant to form compound inflorescences (panicles) from uncommitted primordia (anlagen) in latent buds, encompassing the initiation, differentiation, and elaboration of the branched flower-bearing structure over a two-year developmental cycle.",
    "alternative_term": "inflorescence formation capacity | panicle development trait | cluster primordium development |+ Infloreszenzentwicklung | Gescheinbildung | Blütenstandsentwicklung",
    "example_of_usage": "Inflorescence primordia become microscopically visible in latent buds 4-6 weeks after budbreak of the current season, reaching 0.3-0.5 mm in length by dormancy. ||Chardonnay typically initiates 2.1-2.4 inflorescence primordia per bud at nodes 4-10, while Sultana averages only 1.2-1.5 primordia. ||Final inflorescence size depends on primordium elaboration during spring of year N+1, with branch number increasing from 8-12 at dormancy to 15-25 at bloom through continued meristem activity.",
    "editor_note": "Inflorescence_Development_Disposition serves as the parent class for traits related to the formation of the grape cluster framework. ||The grapevine inflorescence is developmentally homologous to the tendril, with both arising from the same uncommitted primordium (anlage). ||The VvTFL1A, VvFT, and VvSOC1 genes regulate the balance between vegetative and reproductive development. ||Gibberellin promotes tendril fate while cytokinin promotes inflorescence fate.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Carmona MJ et al. (2008) A molecular genetic perspective of reproductive development in grapevine. Journal of Experimental Botany 59:2579-2596|| Srinivasan C, Mullins MG (1981) Physiology of flowering in the grapevine: a review. American Journal of Enology and Viticulture 32:47-63"
  },
  "Inflorescence_Initiation_Disposition": {
    "definition": "An inflorescence development disposition that is the inherited capacity of a Vitis vinifera plant to convert uncommitted primordia (anlagen) in latent buds into inflorescence meristems rather than tendril meristems, determining the potential for reproductive versus vegetative development in the following season.",
    "alternative_term": "cluster initiation capacity | reproductive primordium formation | inflorescence induction trait |+ Infloreszenzinduktion | Gescheinanlage | Blütenstandsinitiation",
    "example_of_usage": "Inflorescence initiation occurs primarily at nodes 3-12 from the shoot base, with peak initiation frequency at nodes 5-8 in most cultivars. ||Pinot Noir shows high initiation disposition with 85-95% of anlagen converting to inflorescence primordia at optimal nodes, while Cardinal converts only 40-60%. ||Temperature during the initiation window (4-8 weeks post-budbreak) critically affects conversion rate, with 25-30°C promoting initiation and temperatures below 20°C or above 35°C reducing it. ||Light exposure to developing buds increases initiation by 20-40% compared to shaded buds.",
    "editor_note": "Inflorescence initiation represents the first commitment step in the two-year reproductive cycle. ||The process is regulated by the ratio of gibberellins to cytokinins, with high cytokinin favoring inflorescence fate. ||Environmental factors including temperature, light, and carbohydrate availability during the critical 4-8 week window after budbreak determine initiation success. ||The VvTFL1A gene acts as a repressor of inflorescence identity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Buttrose MS (1974) Climatic factors and fruitfulness in grapevines. Horticultural Abstracts 44:319-326|| Sánchez LA, Dokoozlian NK (2005) Bud microclimate and fruitfulness in Vitis vinifera L. American Journal of Enology and Viticulture 56:319-329"
  },
  "Inflorescence_Number_Disposition": {
    "definition": "An inflorescence development disposition that is the inherited capacity of a Vitis vinifera plant to develop a characteristic number of inflorescences per shoot, determined by the frequency of inflorescence initiation across bud positions and the survival of initiated primordia through dormancy and spring development.",
    "alternative_term": "cluster number per shoot | inflorescence frequency trait | bunch number disposition |+ Gescheinzahl | Infloreszenzanzahl pro Trieb | Traubenzahl-Disposition",
    "example_of_usage": "Inflorescence number per shoot ranges from 1.0-3.5 across V. vinifera cultivars under standard management. ||Müller-Thurgau consistently produces 2.5-3.0 inflorescences per shoot, while Cabernet Sauvignon averages 1.5-2.0. ||Highly fruitful cultivars such as Trebbiano Toscano may exceed 3.0 inflorescences per shoot at basal nodes. ||The coefficient of variation for inflorescence number within a cultivar typically ranges from 15-30%, reflecting environmental and positional effects. ||Crop estimation models use historical inflorescence number data with 85-92% prediction accuracy.",
    "editor_note": "Inflorescence number disposition interacts with bud fruitfulness but represents specifically the realized count of developed inflorescences rather than the presence of primordia. ||Not all initiated primordia develop into visible inflorescences due to abortion during late dormancy or early spring. ||The trait shows moderate heritability (h² = 0.45-0.60) and significant genotype × environment interaction.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dry PR (2000) Canopy management for fruitfulness. Australian Journal of Grape and Wine Research 6:109-115|| Clingeleffer PR (2001) Crop development, crop estimation and crop control to secure quality and production of major wine grape varieties: a national approach. Final Report to Grape and Wine Research and Development Corporation, CSIRO Plant Industry"
  },
  "Pollen_Disposition": {
    "definition": "A flowering disposition that is the inherited capacity of a Vitis vinifera plant to produce, mature, and release pollen grains (male gametophytes) with characteristic properties affecting fertilization success, encompassing pollen quantity, structural integrity, physiological viability, and functional performance during pollination.",
    "alternative_term": "pollen production trait | male gametophyte disposition | pollen quality capacity |+ Pollendisposition | Pollenqualität | Pollenbildungsvermögen",
    "example_of_usage": "A single grapevine flower produces 8,000-25,000 pollen grains depending on cultivar and flower sex type, with hermaphrodite flowers of Cabernet Sauvignon releasing 10,000-15,000 grains per flower. ||Pollen diameter ranges from 22-32 µm across cultivars, with tricolporate aperture morphology characteristic of Vitaceae. ||Pollen release occurs primarily between 06:00-12:00 hours during anthesis, coinciding with calyptra abscission. ||Atmospheric pollen concentrations in vineyards during peak bloom reach 200-800 grains/m³.",
    "editor_note": "Pollen_Disposition serves as the parent class for traits affecting male reproductive function. ||Grapevine pollen is binucleate at release, with generative cell division occurring during pollen tube growth. ||The exine structure shows species-specific sculpturing patterns useful for taxonomic identification. ||Pollen traits significantly affect fruit set, seed number, and berry development through both quantity and quality effects on fertilization.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gallardo A et al. (2009) Pollen development and fertility in Vitis vinifera L. cv. Macabeo: a comparison between male-sterile and fertile flowers. American Journal of Enology and Viticulture 60:353-361|| Vasconcelos MC et al. (2009) The flowering process of Vitis vinifera: a review. American Journal of Enology and Viticulture 60:411-434"
  },
  "Pollen_Viability_Disposition": {
    "definition": "A pollen disposition that is the inherited capacity of a Vitis vinifera plant to produce pollen grains that maintain structural integrity, metabolic competence, and fertilization potential, as assessed by staining tests, in vitro germination, or fertilization success.",
    "alternative_term": "pollen fertility | pollen vitality trait | male fertility disposition |+ Pollenviabilität | Pollenfertilität | Pollenlebensfähigkeit",
    "example_of_usage": "Pollen viability assessed by acetocarmine or Alexander staining ranges from 50-95% across V. vinifera cultivars, with Riesling consistently showing high viability (88-95%) and Gewürztraminer exhibiting lower values (65-80%). ||Environmental stress during microsporogenesis (meiosis, approximately 6-8 weeks pre-bloom) reduces viability, with temperatures above 35°C causing 30-50% reduction. ||Viability declines rapidly after anther dehiscence, with 50% loss within 24-48 hours under ambient conditions. ||Cold storage at 4°C extends viability to 5-7 days, enabling controlled pollination in breeding programs.",
    "editor_note": "Pollen viability represents the proportion of pollen grains capable of successful fertilization under favorable conditions. ||Viability testing methods (vital staining, in vitro germination, fluorochromatic reaction) give correlated but not identical results due to different aspects of pollen competence assessed. ||Low viability contributes to poor fruit set and is exacerbated by nutritional deficiencies (boron, zinc) and fungicide applications during meiosis.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kelen M, Demirtas I (2003) Pollen viability, germination capability and pollen production level of some grape varieties (Vitis vinifera L.). Acta Physiologiae Plantarum 25:229-233|| Ebadi A et al. (1996) Effect of short-term temperature and shading on fruit-set, seed and berry development in model vines of V. vinifera cvs Chardonnay and Shiraz. Australian Journal of Grape and Wine Research 2:2-9"
  },
  "Pollen_Germination_Disposition": {
    "definition": "A pollen disposition that is the inherited capacity of a Vitis vinifera plant to produce pollen grains that successfully germinate on compatible stigmatic surfaces or in artificial media, forming a pollen tube initial through hydration, polarization, and cell wall extension at the aperture site.",
    "alternative_term": "pollen germinability | germination capacity trait | pollen activation disposition |+ Pollenkeimfähigkeit | Pollenkeimungsvermögen | Keimungsdisposition",
    "example_of_usage": "In vitro pollen germination on optimized agar media (15-20% sucrose, 100 ppm boric acid, 300 ppm calcium nitrate) reaches 60-85% in highly fertile cultivars such as Merlot and Syrah within 4-6 hours at 25°C. ||Chardonnay shows rapid germination initiation (50% germinated within 2 hours) while Sangiovese requires 4-5 hours to reach equivalent levels. ||In vivo germination on receptive stigmas occurs within 30-60 minutes of pollination, with germination percentages 10-20% higher than in vitro due to stigmatic exudate factors. ||Optimal temperature for germination ranges from 25-30°C, with rates declining sharply below 15°C.",
    "editor_note": "Pollen germination represents the first phase of post-pollination development, distinct from subsequent pollen tube growth. ||The process requires adequate stigma receptivity, appropriate temperature, and sufficient moisture. ||Germination percentage is partially independent of viability, as some structurally intact grains fail to germinate due to metabolic deficiencies. ||Boron is critical for germination, with deficiency reducing rates by 40-70%.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Staudt G (1999) Opening of flowers and time of anthesis in grapevines, Vitis vinifera L. Vitis 38:15-20|| Okamoto G, Imai S (1996) Effects of boric acid on pollen tube growth and fruit set in Vitis vinifera L. cv. Pione. Journal of the Japanese Society for Horticultural Science 65:283-289"
  },
  "Pollen_Tube_Growth_Disposition": {
    "definition": "A pollen disposition that is the inherited capacity of a Vitis vinifera plant to produce pollen grains capable of extending pollen tubes through the stigma and style to the ovary, maintaining directional growth, structural integrity, and metabolic activity sufficient to deliver sperm cells for fertilization.",
    "alternative_term": "pollen tube elongation capacity | tube growth rate trait | pollen tube extension disposition |+ Pollenschlauchwachstum | Pollenschlauchverlängerung | Wachstumsdisposition des Pollenschlauchs",
    "example_of_usage": "Pollen tube growth through the grapevine style requires 12-48 hours depending on cultivar and temperature, with tubes elongating at 15-40 µm/hour under optimal conditions. ||Cabernet Sauvignon pollen tubes reach the ovary within 18-24 hours at 25°C, while Muscat of Alexandria requires 36-48 hours due to longer style length. ||In vitro tube lengths after 24 hours range from 800-2,500 µm, with Pinot Noir achieving 2,000-2,500 µm and Grenache showing slower growth at 800-1,200 µm. ||Tube growth follows a chemotropic gradient guided by ovule-derived signals, with 75-90% of tubes successfully reaching ovules in compatible pollinations.",
    "editor_note": "Pollen tube growth is the rate-limiting step in fertilization timing, particularly under suboptimal temperatures. ||Growth requires continuous tip-localized pectin secretion and callose plug formation at intervals along the tube. ||Self-incompatibility in grapevine is generally weak, but pollen tube growth rates may differ between self and cross pollen. ||Temperature below 15°C severely restricts tube growth, contributing to poor fruit set in cool flowering seasons.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Staudt G (1982) Pollen germination and pollen tube growth in vivo in Vitis and the dependence on temperature. Vitis 21:205-216|| Galet P (2000) General Viticulture, Oenoplurimedia, Chaintre pp.: 128-135"
  },
  "Fruit_Set_Disposition": {
    "definition": "A reproductive disposition that is the inherited capacity of a Vitis vinifera plant to successfully convert pollinated flowers into developing berries through fertilization, initial cell division, and retention on the rachis, determining the proportion of flowers that become harvestable fruit.",
    "alternative_term": "berry set capacity | fruit retention trait | set percentage disposition |+ Fruchtansatz | Beerenansatz | Befruchtungserfolg",
    "example_of_usage": "Fruit set percentage in grapevine typically ranges from 15-50% of total flowers, with Chardonnay achieving 35-45% under favorable conditions and Merlot averaging 20-30%. ||A cluster with 300 flowers at bloom producing 90 berries represents 30% fruit set. ||Optimal fruit set requires temperatures of 20-25°C during flowering, adequate carbohydrate supply, and successful pollination of at least 2 ovules per flower. ||Fruit set below 20% often results in excessively loose clusters, while set above 50% may cause compact clusters prone to disease.",
    "editor_note": "Fruit_Set_Disposition serves as the parent class for traits affecting the flower-to-berry transition. ||The process involves multiple sequential steps including pollen germination, tube growth, fertilization, and hormone-triggered berry development. ||Unfertilized flowers abscise within 7-14 days post-bloom. ||Both genetic factors (cultivar) and environmental conditions (temperature, nutrition, water status) strongly influence fruit set success.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 115-135|| Vasconcelos MC et al. (2009) The flowering process of Vitis vinifera: a review. American Journal of Enology and Viticulture 60:411-434"
  },
  "High_Fruit_Set_Disposition": {
    "definition": "A fruit set disposition that is the inherited capacity of a Vitis vinifera plant to consistently achieve above-average conversion of flowers to berries (typically greater than 40%), resulting from efficient pollination, fertilization, and early berry retention under a range of environmental conditions.",
    "alternative_term": "high berry set | excellent fruit set capacity | superior set trait |+ hoher Fruchtansatz | hoher Beerenansatz | ausgezeichnete Befruchtung",
    "example_of_usage": "Chasselas exhibits high fruit set disposition with 45-55% conversion rates even under suboptimal flowering conditions, contributing to its reputation for consistent yields. ||Pinot Gris achieves 40-50% fruit set in cool climate regions where other cultivars struggle. ||Table grape cultivars selected for large clusters such as Italia and Red Globe show fruit set of 50-65% through breeding selection. ||High fruit set cultivars typically possess high pollen viability (>85%), rapid pollen tube growth, and strong sink strength in developing ovaries.",
    "editor_note": "High fruit set disposition may lead to excessively compact clusters in some cultivars, increasing susceptibility to Botrytis and other bunch rots. ||Management practices including early leaf removal, shoot positioning, and gibberellin application can moderate excessive set. ||The trait shows moderate heritability (h² = 0.40-0.55) and is partially independent of total flower number per cluster.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dry PR et al. (2010) Bunch architecture and susceptibility of berries to Botrytis cinerea in Vitis vinifera L. Australian Journal of Grape and Wine Research 16:257-264|| Dunn GM, Martin SR (2007) A functional association in Vitis vinifera L. cv. Cabernet Sauvignon between the extent of primary branching and the number of flowers formed per inflorescence. Australian Journal of Grape and Wine Research 13:95-100"
  },
  "Coulure_Susceptibility_Disposition": {
    "definition": "A fruit set disposition that is the inherited capacity of a Vitis vinifera plant to exhibit flower or young berry abscission (coulure) under unfavorable conditions, resulting in reduced fruit set and loose clusters due to failure of fertilization, embryo abortion, or disruption of early berry development.",
    "alternative_term": "shatter susceptibility | flower drop tendency | poor set disposition |+ Verrieselungsneigung | Durchrieselungsanfälligkeit | Blütenabwurf-Disposition",
    "example_of_usage": "Grenache is notoriously susceptible to coulure, with fruit set dropping to 10-20% in cool or rainy flowering seasons compared to 30-40% under optimal conditions. ||Malbec shows severe coulure susceptibility with yield losses of 40-70% in years with temperatures below 15°C during bloom. ||Muscat cultivars including Muscat of Alexandria and Muscat Ottonel exhibit high coulure susceptibility linked to functional pistil abnormalities. ||Coulure severity correlates with flower abscission rates exceeding 60% within two weeks post-bloom.",
    "editor_note": "Coulure_Susceptibility_Disposition serves as the parent class for weather-induced and nutritional subtypes. ||The trait reflects both inherent sensitivity of reproductive processes and inadequate buffering capacity against environmental stress. ||Cultivars with long flowering periods are often more susceptible due to extended exposure to unfavorable conditions. ||Selection against coulure susceptibility has been a major breeding objective for cool climate viticulture.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 125-130|| Galet P (2000) General Viticulture, Oenoplurimedia, Chaintre pp.: 136-145"
  },
  "Weather_Induced_Coulure_Disposition": {
    "definition": "A coulure susceptibility disposition that is the inherited capacity of a Vitis vinifera plant to exhibit flower or young berry abscission in response to adverse weather conditions during the flowering period, including low temperatures, excessive rainfall, high humidity, or persistent cloudiness that impair pollination and fertilization.",
    "alternative_term": "climate-induced shatter | temperature-sensitive coulure | weather-dependent poor set |+ witterungsbedingte Verrieselung | klimainduzierter Blütenabwurf | temperaturbedingte Durchrieselung",
    "example_of_usage": "Merlot exhibits pronounced weather-induced coulure disposition with fruit set declining from 35% at 25°C to only 12% when mean flowering temperature drops to 14°C. ||Gewürztraminer shows 50-60% flower loss during rainy bloom periods exceeding 5 consecutive days with precipitation. ||Cold-sensitive pollen tube growth (optimum 25-30°C) underlies weather-induced coulure, with elongation rates falling below the threshold for timely fertilization at temperatures under 15°C. ||Wind speeds exceeding 25 km/h during anthesis reduce fruit set by 15-25% through pollen dispersal and stigma desiccation.",
    "editor_note": "Weather-induced coulure results from direct effects on gametophyte function (pollen germination and tube growth) and indirect effects through reduced photosynthesis and carbohydrate supply to developing flowers. ||Rain during anthesis physically removes pollen from stigmas and dilutes stigmatic exudate. ||Cultivar differences in weather-induced coulure susceptibility correlate with pollen germination temperature optima and carpel development rate.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ebadi A et al. (1996) Effect of short-term temperature and shading on fruit-set, seed and berry development in model vines of V. vinifera cvs Chardonnay and Shiraz. Australian Journal of Grape and Wine Research 2:2-9|| Staudt G (1982) Pollen germination and pollen tube growth in vivo in Vitis and the dependence on temperature. Vitis 21:205-216"
  },
  "Nutritional_Coulure_Disposition": {
    "definition": "A coulure susceptibility disposition that is the inherited capacity of a Vitis vinifera plant to exhibit flower or young berry abscission in response to nutritional imbalances or deficiencies, particularly inadequate carbohydrate supply to developing flowers or insufficient micronutrient availability for reproductive processes.",
    "alternative_term": "nutrient-related shatter | carbohydrate-limited coulure | nutrition-dependent poor set |+ ernährungsbedingte Verrieselung | nährstoffinduzierter Blütenabwurf | Kohlenhydratmangel-Durchrieselung",
    "example_of_usage": "Excessive shoot vigor in Merlot diverts carbohydrates from clusters, causing nutritional coulure with fruit set below 15% when shoot growth rates exceed 4 cm/day during flowering. ||Boron deficiency induces severe nutritional coulure in susceptible cultivars such as Pinot Noir, reducing fruit set from 35% to 8-12% at leaf B concentrations below 25 ppm. ||Zinc deficiency causes coulure through impaired pollen development, with Chardonnay showing 40% reduction in fruit set at leaf Zn below 20 ppm. ||Shading of basal leaves during bloom reduces cluster carbohydrate supply, causing 20-35% additional flower abscission.",
    "editor_note": "Nutritional coulure results from source-sink competition between vegetative and reproductive growth, or from specific nutrient limitations affecting gametophyte development and function. ||Unlike weather-induced coulure, nutritional coulure can often be prevented through appropriate canopy management (shoot thinning, hedging) and targeted fertilization. ||Rootstock vigor significantly influences scion susceptibility to nutritional coulure through effects on vegetative-reproductive balance.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M et al. (2001) Reproductive growth of grapevines in response to nitrogen supply and rootstock. Australian Journal of Grape and Wine Research 7:12-18|| Christensen LP (1980) Timing of zinc foliar sprays. II. Effects on size, sweetness, and bunch rot of Thompson Seedless grapes. American Journal of Enology and Viticulture 31:256-260"
  },
  "Millerandage_Susceptibility_Disposition": {
    "definition": "A fruit set disposition that is the inherited capacity of a Vitis vinifera plant to develop clusters containing berries of highly variable size (millerandage or hen-and-chicks), resulting from incomplete fertilization producing seedless small berries (shot berries) alongside normally fertilized larger berries within the same cluster.",
    "alternative_term": "shot berry susceptibility | hen and chicks tendency | uneven berry size disposition |+ Kleinbeerigkeit | Millerandage-Anfälligkeit | Verrieselungsneigung mit Kleinbeeren",
    "example_of_usage": "Gewürztraminer exhibits severe millerandage susceptibility with shot berry proportions reaching 30-50% of berries per cluster in problematic years, while Cabernet Sauvignon typically shows only 5-15%. ||Shot berries in Chardonnay average 4-6 mm diameter and 0.3-0.5 g weight compared to 12-14 mm and 1.2-1.8 g for normally developed berries. ||Muscat cultivars show genetic predisposition to millerandage through high rates of ovule abortion even under favorable pollination conditions. ||Berry size coefficient of variation (CV) above 40% indicates severe millerandage compared to normal CV of 15-25%.",
    "editor_note": "Millerandage differs from coulure in that affected flowers are retained rather than abscised, but develop into small seedless or single-seeded berries. ||The condition results from partial fertilization (one ovule fertilized) or stimulative parthenocarpy without fertilization. ||Shot berries may have different sugar and acid composition than normal berries, potentially affecting wine quality. ||Some millerandage is considered desirable in certain wine styles due to higher skin-to-pulp ratio in small berries.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 130-135|| Friend AP, Trought MCT (2007) Delayed winter spur-pruning in New Zealand can alter yield components of Merlot grapevines. Australian Journal of Grape and Wine Research 13:157-164"
  },
  "Seedlessness_Disposition": {
    "definition": "A reproductive disposition that is the inherited capacity of a Vitis vinifera plant to produce berries lacking fully developed seeds, resulting from disruption of normal seed development through embryo abortion, endosperm failure, or fruit development without fertilization, yielding fruit with seed traces, rudimentary seeds, or no seeds.",
    "alternative_term": "seedless berry production | apyreny | seed abortion trait |+ Kernlosigkeit | Samenlosigkeit | Apyrenie",
    "example_of_usage": "Seedless table grapes represent over 80% of global table grape production, with Thompson Seedless (Sultanina) being the most widely planted seedless cultivar worldwide. ||Seedless berries contain seed traces ranging from barely perceptible (Thompson Seedless, 8-15 mg seed trace weight) to noticeable (Flame Seedless, 25-40 mg). ||The sdI locus on chromosome 18 controls stenospermocarpy in most commercial seedless cultivars. ||Berry weight in seedless cultivars ranges from 2-4 g without treatment to 6-10 g with gibberellin application.",
    "editor_note": "Seedlessness_Disposition serves as the parent class for different mechanisms producing seedless fruit. ||Three distinct pathways exist: stenospermocarpy (seed abortion after fertilization), parthenocarpy (fruit development without fertilization), and GA-induced seedlessness (hormone manipulation of seeded cultivars). ||Commercial seedlessness is almost exclusively stenospermocarpic. ||Seedlessness affects berry size, requiring compensatory treatments for acceptable fruit size.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ledbetter CA, Ramming DW (1989) Seedlessness in grapes. Horticultural Reviews 11:159-184|| Doligez A et al. (2002) Genetic mapping of grapevine (Vitis vinifera L.) applied to the detection of QTLs for seedlessness and berry weight. Theoretical and Applied Genetics 105:780-795"
  },
  "Stenospermocarpy_Disposition": {
    "definition": "A seedlessness disposition that is the inherited capacity of a Vitis vinifera plant to initiate normal fertilization and seed development but subsequently abort the embryo and endosperm at a genetically determined developmental stage, resulting in berries containing small, soft, incompletely developed seed traces.",
    "alternative_term": "seed trace development | abortive seed formation | post-fertilization seedlessness |+ Stenospermokarpie | Samenrudimentbildung | Embryoabortion",
    "example_of_usage": "Thompson Seedless exhibits stenospermocarpy with embryo abortion occurring 2-4 weeks post-fertilization, producing seed traces of 8-18 mg compared to 25-45 mg for fully developed seeds in seeded cultivars. ||Crimson Seedless shows later abortion timing with slightly larger seed traces (20-35 mg) that remain soft and edible. ||The stenospermocarpic trait is controlled by a major recessive gene (sdI) with quantitative modifiers affecting abortion timing and seed trace size. ||Pollen from stenospermocarpic cultivars is fully viable and produces normal seeded offspring when used to pollinate seeded maternal parents.",
    "editor_note": "Stenospermocarpy requires successful pollination and fertilization, distinguishing it from parthenocarpy. ||The abortion process involves programmed cell death in the nucellus and endosperm, triggered by hormonal signals around 15-40 days post-anthesis depending on genotype. ||Seed trace hardness varies among stenospermocarpic cultivars and is an important quality criterion for fresh consumption. ||Breeding for seedlessness uses embryo rescue techniques to recover progeny from stenospermocarpic crosses.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Stout AB (1936) Seedlessness in grapes. New York Agricultural Experiment Station Technical Bulletin 238:1-68|| Bouquet A, Danglot Y (1996) Inheritance of seedlessness in grapevine (Vitis vinifera L.). Vitis 35:35-42"
  },
  "Early_Seed_Abortion_Disposition": {
    "definition": "A stenospermocarpy disposition that is the inherited capacity of a Vitis vinifera plant to abort developing seeds at an early post-fertilization stage (typically 1-3 weeks after anthesis), resulting in very small, soft seed traces that are minimally perceptible during consumption.",
    "alternative_term": "early embryo abortion | small seed trace formation | early stenospermocarpy |+ frühe Samenabortion | frühe Embryoabtötung | kleine Samenrudimente",
    "example_of_usage": "Thompson Seedless exemplifies early seed abortion disposition with embryo collapse occurring 14-21 days post-anthesis, producing seed traces averaging 10-15 mg and 3-4 mm length. ||Perlette aborts even earlier (10-18 days post-anthesis) with seed traces of only 5-10 mg. ||Early aborting cultivars produce the smallest seed traces but often have inherently smaller berries, with Thompson Seedless averaging 2.5-3.5 g without gibberellin treatment compared to 4-5 g for later-aborting Crimson Seedless. ||Consumer acceptance studies show seed traces below 20 mg are imperceptible to 90% of tasters.",
    "editor_note": "Early seed abortion correlates with reduced berry size due to the loss of seed-derived hormones (auxin, gibberellin) that normally promote pericarp growth. ||The timing of abortion appears to be controlled by modifier genes in addition to the major sdI locus. ||Embryo rescue for breeding purposes is more challenging with early-aborting genotypes due to the smaller developmental window for viable embryo recovery.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ramming DW et al. (2000) Seedless grapes. In: Janick J (ed) Fruit Breeding Vol. II: Vine and Small Fruits, Wiley pp.: 197-239|| Perl A et al. (2000) Establishment of an Agrobacterium-mediated transformation system for grape (Vitis vinifera L.): the role of antioxidants during grape-Agrobacterium interactions. Nature Biotechnology 14:624-628"
  },
  "Late_Seed_Abortion_Disposition": {
    "definition": "A stenospermocarpy disposition that is the inherited capacity of a Vitis vinifera plant to abort developing seeds at a later post-fertilization stage (typically 3-6 weeks after anthesis), resulting in larger, sometimes partially lignified seed traces that may be noticeable during consumption.",
    "alternative_term": "late embryo abortion | large seed trace formation | late stenospermocarpy |+ späte Samenabortion | späte Embryoabtötung | große Samenrudimente",
    "example_of_usage": "Crimson Seedless exhibits late seed abortion disposition with embryo collapse occurring 28-42 days post-anthesis, producing seed traces of 25-40 mg and 5-7 mm length with partial lignification of the seed coat. ||Autumn Royal aborts at intermediate timing (21-35 days) with seed traces of 20-30 mg. ||Late abortion cultivars benefit from extended hormone signaling, producing larger berries (4-6 g without treatment) but requiring careful clone selection to minimize seed trace perceptibility. ||Seed trace hardness in late-aborting cultivars may reach 2-3 on the 1-5 lignification scale compared to 0.5-1 for early-aborting types.",
    "editor_note": "Late seed abortion produces larger seed traces due to extended endosperm and seed coat development before abortion occurs. ||The partially developed seed coat may undergo some lignification, creating harder traces that reduce consumer acceptance. ||Breeding programs select for minimal seed trace size within late-aborting backgrounds to combine larger berry size with acceptable seedlessness. ||Environmental factors including temperature can shift abortion timing by 5-10 days.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ledbetter CA, Burgos L (1994) Inheritance of stenospermocarpic seedlessness in Vitis vinifera L. Journal of Heredity 85:157-160|| Cabezas JA et al. (2006) A genetic analysis of seed and berry weight in grapevine. Genome 49:1572-1585"
  },
  "Parthenocarpy_Disposition": {
    "definition": "A seedlessness disposition that is the inherited capacity of a Vitis vinifera plant to develop fruit without fertilization or seed formation, resulting in berries that are entirely seedless from inception rather than containing aborted seed traces, typically producing small berries due to absence of seed-derived growth hormones.",
    "alternative_term": "virgin fruit development | seedless without fertilization | true parthenocarpy |+ Parthenokarpie | Jungfernfrüchtigkeit | befruchtungslose Fruchtbildung",
    "example_of_usage": "Black Corinth (Zante Currant) exhibits obligate parthenocarpy, producing tiny berries (0.3-0.8 g) entirely without seeds or seed traces regardless of pollination. ||Stimulative parthenocarpy in some cultivars is triggered by pollination without fertilization, with pollen tube growth providing sufficient hormonal stimulus for fruit development. ||Parthenocarpic berries in Black Corinth average 6-8 mm diameter compared to 12-18 mm for stenospermocarpic Thompson Seedless. ||The VvAGL11 gene shows altered expression patterns in parthenocarpic versus stenospermocarpic seedless grapes.",
    "editor_note": "Parthenocarpy is rare in commercial grape production due to the extremely small berry size resulting from complete absence of seed-derived hormones. ||Stimulative parthenocarpy (triggered by pollination but not fertilization) differs from true parthenocarpy (spontaneous fruit development). ||Gibberellin application can partially compensate for hormone deficiency but cannot achieve berry sizes comparable to stenospermocarpic cultivars. ||Black Corinth is primarily used for dried fruit (currants) where small berry size is acceptable.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pearson HM (1933) Parthenocarpy and seed abortion in Vitis vinifera. Proceedings of the American Society for Horticultural Science 29:169-175|| Costantini L et al. (2008) Berry and phenology-related traits in grapevine (Vitis vinifera L.): from quantitative trait loci to underlying genes. BMC Plant Biology 8:38"
  },
  "GA_Responsive_Seedlessness_Disposition": {
    "definition": "A seedlessness disposition that is the inherited capacity of a Vitis vinifera plant to produce functionally seedless berries following exogenous gibberellic acid (GA₃) application during bloom or early fruit development, through GA-induced inhibition of seed development in otherwise seeded cultivars.",
    "alternative_term": "gibberellin-induced seedlessness | hormone-induced apyreny | GA-induced seed suppression |+ GA-induzierte Kernlosigkeit | Gibberellin-responsives Apyrenie | hormonell induzierte Samenlosigkeit",
    "example_of_usage": "Delaware grape shows strong GA-responsive seedlessness disposition, with GA₃ application (25-50 ppm) at 50% capfall reducing seed development to trace levels while increasing berry size from 1.5 g to 2.5-3.0 g. ||Kyoho responds to GA treatment at bloom with 80-95% reduction in normal seed formation. ||Application timing is critical, with treatment 10-14 days pre-bloom for berry thinning and at full bloom for seedlessness induction being standard protocols in Japanese viticulture. ||GA responsiveness varies from complete seed suppression (Delaware) to partial reduction (Muscat Bailey A, 40-60% seed reduction).",
    "editor_note": "GA-responsive seedlessness differs mechanistically from genetic stenospermocapy, involving hormone-mediated suppression of ovule development or fertilization rather than post-fertilization embryo abortion. ||The trait is exploited commercially primarily in East Asian table grape production. ||GA treatment also affects cluster loosening, berry sizing, and skin texture. ||Cultivar-specific protocols are essential, as excessive GA concentration causes berry shatter and cluster deformation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Iwahori S et al. (1968) Gibberellin-induced parthenocarpy in grape. Plant Physiology 43:333-337|| Lu J et al. (1997) Effects of gibberellic acid on berry development and cluster morphology of several grape cultivars. Fruit Varieties Journal 51:219-227"
  },
  "Fruitfulness_Disposition": {
    "definition": "A reproductive disposition that is the inherited capacity of a Vitis vinifera plant to initiate and develop inflorescence primordia in latent buds that will produce fruit-bearing shoots in the following season, determining the potential yield through the number and distribution of clusters per vine.",
    "alternative_term": "fertility trait | reproductive potential | bud fertility disposition |+ Fruchtbarkeit | Ertragspotential | Fruchtbarkeitsdisposition",
    "example_of_usage": "Fruitfulness varies widely across V. vinifera cultivars, with Trebbiano Toscano averaging 2.5-3.2 clusters per shoot compared to 1.2-1.8 for Cabernet Sauvignon under similar management. ||The fruitfulness coefficient (clusters per shoot) shows cultivar-specific responses to environmental conditions, with a coefficient of variation of 15-35% across years. ||Total potential yield correlates strongly with bud fruitfulness (r = 0.75-0.85) when fruit set and berry weight are consistent. ||Fruitfulness assessment during dormancy through bud dissection enables crop forecasting with 80-90% accuracy.",
    "editor_note": "Fruitfulness_Disposition serves as the parent class for traits related to inflorescence primordia formation in buds. ||Fruitfulness is determined during the previous growing season (year N-1) when primordia differentiate in developing buds, making it responsive to environmental conditions 12-14 months before harvest. ||The trait is distinct from fruit set, which determines what proportion of flowers become berries after fruitfulness has established cluster number potential.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sánchez LA, Dokoozlian NK (2005) Bud microclimate and fruitfulness in Vitis vinifera L. American Journal of Enology and Viticulture 56:319-329|| Dry PR (2000) Canopy management for fruitfulness. Australian Journal of Grape and Wine Research 6:109-115"
  },
  "Bud_Fruitfulness_Disposition": {
    "definition": "A fruitfulness disposition that is the inherited capacity of a Vitis vinifera plant to form inflorescence primordia within compound buds at specific positions along the cane, with characteristic patterns of primordium number and development across node positions from base to apex.",
    "alternative_term": "bud fertility | node fruitfulness | positional fertility trait |+ Knospenfruchtbarkeit | Augenfertilität | positionelle Fruchtbarkeit",
    "example_of_usage": "Bud fruitfulness in Chardonnay increases from 0.8 clusters per bud at node 1-2 to 2.1 clusters at nodes 5-8, then decreases slightly to 1.8 at nodes 12-15. ||Riesling shows relatively uniform fruitfulness (1.4-1.8 clusters) across nodes 3-12, enabling flexible pruning strategies. ||Primary buds contain 1-3 inflorescence primordia in most cultivars, while secondary buds average 0.5-1.0 and tertiary buds rarely exceed 0.3 primordia. ||Microscopic dissection of dormant buds reveals primordium development stage, with fully differentiated primordia (stage 5-6) indicating high fruitfulness potential.",
    "editor_note": "Bud_Fruitfulness_Disposition serves as the parent class for position-specific fruitfulness patterns. ||The compound bud structure in grapevine contains primary, secondary, and tertiary buds, each with different fruitfulness potential. ||Environmental conditions during primordium initiation (temperature, light, carbohydrate availability) in year N-1 strongly influence bud fruitfulness realized in year N. ||Pruning strategy must consider cultivar-specific fruitfulness patterns to optimize yield and quality.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Buttrose MS (1974) Climatic factors and fruitfulness in grapevines. Horticultural Abstracts 44:319-326|| Dunn GM, Martin SR (2000) Do temperature conditions at budburst affect flower number in Vitis vinifera L. cv. Cabernet Sauvignon? Australian Journal of Grape and Wine Research 6:116-124"
  },
  "High_Basal_Fruitfulness_Disposition": {
    "definition": "A bud fruitfulness disposition that is the inherited capacity of a Vitis vinifera plant to develop high numbers of inflorescence primordia in buds at basal node positions (nodes 1-4 from the cane base), enabling productive short spur pruning and cordon-based training systems.",
    "alternative_term": "basal bud fertility | spur fruitfulness | proximal node fertility |+ basale Fruchtbarkeit | Zapfenfruchtbarkeit | stammnahe Knospenfertilität",
    "example_of_usage": "Grenache exhibits exceptional high basal fruitfulness disposition with 1.8-2.4 clusters per bud at nodes 1-3, enabling traditional gobelet training with 2-bud spurs. ||Tempranillo maintains 1.6-2.0 clusters at basal positions, well-suited for bilateral cordon systems. ||In contrast, Sultana shows poor basal fruitfulness (0.4-0.8 clusters at nodes 1-3), requiring cane pruning to access fruitful distal buds. ||High basal fruitfulness cultivars tolerate severe hedging and mechanical pruning without significant yield reduction, with spur-pruned Grenache producing 8-12 t/ha compared to 5-7 t/ha for spur-pruned Sultana.",
    "editor_note": "High basal fruitfulness is a key selection criterion for cultivars destined for mechanized viticulture and warm climate production where spur pruning simplifies management. ||The trait shows moderate heritability (h² = 0.45-0.60) and can be enhanced through canopy management promoting light exposure to basal buds during primordium initiation. ||Rootstock influence on basal fruitfulness is generally limited but may manifest through effects on shoot vigor and bud microclimate.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "May P (2004) Flowering and Fruitset in Grapevines, Lythrum Press, Adelaide pp.: 45-68|| Clingeleffer PR (1984) Production and growth of minimal pruned Sultana vines. Vitis 23:42-54"
  },
  "Distal_Fruitfulness_Disposition": {
    "definition": "A bud fruitfulness disposition that is the inherited capacity of a Vitis vinifera plant to develop high numbers of inflorescence primordia in buds at distal node positions (nodes 8-15 or beyond from the cane base), requiring cane pruning or long spur retention to achieve adequate crop levels.",
    "alternative_term": "apical bud fertility | cane fruitfulness | distal node fertility |+ distale Fruchtbarkeit | Bogenfruchtbarkeit | triebspitzige Knospenfertilität",
    "example_of_usage": "Thompson Seedless (Sultanina) exhibits pronounced distal fruitfulness disposition with peak fertility (2.0-2.8 clusters) at nodes 8-14 and minimal fruitfulness (0.3-0.6 clusters) at nodes 1-4, necessitating cane pruning for commercial production. ||Flame Seedless shows similar patterns with optimal fruitfulness at nodes 10-16. ||Guyot and other cane-pruned systems retain 8-15 node canes to capture distal fruitfulness, with typical cane-pruned Sultanina yields of 15-25 t/ha compared to only 4-8 t/ha under spur pruning. ||The fruitfulness gradient from base to apex may span a 4-6 fold difference in strongly distal cultivars.",
    "editor_note": "Distal fruitfulness patterns evolved in wild Vitis as an adaptation to climbing growth where basal portions are shaded. ||Domestication selection for spur-trainable cultivars has reduced but not eliminated distal fruitfulness patterns. ||Distal fruitfulness complicates mechanized pruning and requires skilled manual cane selection for optimal production. ||Some cultivars show bimodal fruitfulness with peaks at both basal and distal positions.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Antcliff AJ et al. (1972) The relationship between bud position and fruitfulness in Sultana. Vitis 11:140-151|| Huglin P, Schneider C (1998) Biologie et écologie de la vigne, 2nd Ed, Lavoisier pp.: 256-278"
  },
  "Lateral_Bud_Fruitfulness_Disposition": {
    "definition": "A bud fruitfulness disposition that is the inherited capacity of a Vitis vinifera plant to develop inflorescence primordia in lateral (axillary) buds that produce summer lateral shoots (Geiztriebe), providing secondary crop potential from current-season growth in addition to the primary crop from dormant buds.",
    "alternative_term": "lateral shoot fertility | summer lateral fruitfulness | axillary bud fertility |+ Geiztriebfruchtbarkeit | Seitentriebfertilität | Axillarknospen-Fruchtbarkeit",
    "example_of_usage": "Merlot exhibits high lateral bud fruitfulness disposition with 40-60% of summer lateral shoots bearing 1-2 small clusters, potentially contributing 10-20% of total yield as second crop in warm climates. ||Cabernet Sauvignon shows moderate lateral fruitfulness (25-40% of laterals fruiting) while Pinot Noir exhibits minimal lateral fruitfulness (<15% of laterals). ||Lateral clusters are smaller (50-120 g) than primary clusters (150-300 g) and ripen 2-4 weeks later, creating harvest timing complications. ||In regions with long growing seasons, lateral crop may reach 2-4 t/ha in fruitful cultivars.",
    "editor_note": "Lateral bud fruitfulness differs mechanistically from dormant bud fruitfulness, as lateral primordia differentiate during the current growing season without the dormancy period required for compound bud development. ||High lateral fruitfulness can complicate crop estimation and may reduce primary fruit quality through competition for resources. ||Lateral shoot removal (hedging, desuckering) is practiced in premium wine production to focus resources on primary clusters.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 88-94|| Intrieri C, Poni S (1995) Integrated evolution of trellis training systems and machines to improve grape quality and vintage quality of mechanized Italian vineyards. American Journal of Enology and Viticulture 46:116-127"
  },
  "Second_Crop_Potential_Disposition": {
    "definition": "A fruitfulness disposition that is the inherited capacity of a Vitis vinifera plant to produce a commercially significant secondary crop from lateral shoots, secondary buds following primary bud loss, or late-developing inflorescences, providing yield recovery potential or extended harvest in suitable climates.",
    "alternative_term": "secondary crop capacity | recovery crop potential | double cropping disposition |+ Zweitertragspotential | Nebenerntepotential | Sekundärertragsfähigkeit",
    "example_of_usage": "Kyoho in Japan and Flame Seedless in California demonstrate strong second crop potential disposition, with managed lateral crop contributing 15-30% of annual production. ||Following spring frost damage to primary buds, Chardonnay secondary buds produce 40-60% of normal yield, while Merlot secondary buds achieve only 25-40% recovery. ||In tropical viticulture (Brazil, Thailand), second crop potential enables double-cropping systems with two harvests annually, achieving combined yields of 25-40 t/ha. ||The interval between primary and secondary harvest ranges from 3-8 weeks depending on cultivar and climate.",
    "editor_note": "Second crop potential encompasses both intentional double-cropping systems exploiting lateral fruitfulness and recovery scenarios where secondary buds compensate for primary bud loss. ||Tropical viticulture deliberately manipulates vine dormancy to achieve multiple cropping cycles. ||Second crop quality typically differs from primary crop due to different ripening conditions, with applications in specific wine styles or table grape markets. ||Climate suitability (growing season length, heat accumulation) determines commercial viability of second crop utilization.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dry PR, Coombe BG (2004) Viticulture Volume 1: Resources, 2nd Ed, Winetitles pp.: 178-195|| Miele A, Mandelli F (2012) Grapevine canopy management in tropical viticulture. Acta Horticulturae 931:469-476"
  },
  "Cluster_Architecture_Disposition": {
    "definition": "A reproductive disposition that is the inherited capacity of a Vitis vinifera plant to develop grape clusters (bunches) with characteristic three-dimensional structure determined by rachis branching pattern, pedicel length, berry number, berry size, and the spatial arrangement of berries within the cluster framework.",
    "alternative_term": "bunch architecture trait | cluster morphology disposition | bunch structure capacity |+ Traubenarchitektur | Traubenstruktur | Gescheinmorphologie",
    "example_of_usage": "Cluster architecture varies dramatically across V. vinifera cultivars, from the extremely compact cylindrical clusters of Pinot Noir (compactness index 8-12 berries/cm rachis) to the loose conical clusters of Sauvignon Blanc (3-5 berries/cm). ||Architecture components include rachis length (8-25 cm), primary branch number (4-12), pedicel length (4-12 mm), and berry count (50-350 per cluster). ||The OIV descriptor 204 classifies cluster density on a 1-9 scale, with 1 being very loose and 9 being very compact. ||Cluster architecture heritability is moderate to high (h² = 0.55-0.75) for most component traits.",
    "editor_note": "Cluster_Architecture_Disposition serves as the parent class for traits determining bunch physical structure. ||Architecture profoundly affects disease susceptibility (particularly Botrytis), harvest method suitability, and wine quality through skin-contact dynamics. ||The trait complex results from the interaction of inflorescence development genes with berry growth patterns. ||Selection for loose cluster architecture has become a major breeding objective for disease resistance improvement.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tello J, Ibáñez J (2018) What do we know about grapevine bunch compactness? A state-of-the-art review. Australian Journal of Grape and Wine Research 24:6-23|| Shavrukov YN et al. (2004) Inflorescence and bunch architecture development in Vitis vinifera L. Australian Journal of Grape and Wine Research 10:116-124"
  },
  "Cluster_Compactness_Disposition": {
    "definition": "A cluster architecture disposition that is the inherited capacity of a Vitis vinifera plant to develop clusters with a characteristic degree of berry packing density, determined by the relationship between berry number, berry size, rachis length, and rachis branching pattern, affecting the spatial proximity of adjacent berries.",
    "alternative_term": "bunch density trait | cluster tightness | berry packing disposition |+ Traubendichte | Beerenpacking | Kompaktheits-Disposition",
    "example_of_usage": "Cluster compactness is quantified by multiple metrics including berries per centimeter of rachis (3-15 range), the CI-12 compactness index, and visual OIV 204 scoring. ||Pinot Noir exhibits high compactness (10-14 berries/cm, OIV 7-9) while Gewürztraminer shows moderate-high values (8-11 berries/cm, OIV 5-7). ||Compactness increases Botrytis incidence exponentially, with infection rates of 5-10% in loose clusters versus 30-60% in compact clusters under identical conditions. ||Berry deformation in highly compact clusters can reach 15-25% of berry diameter, affecting skin integrity.",
    "editor_note": "Cluster_Compactness_Disposition serves as the parent class for specific density categories. ||Compactness results from the interaction of multiple underlying traits and cannot be modified by single-gene manipulation. ||Management practices including gibberellin application, early leaf removal, and bloom-time irrigation stress can reduce compactness by 20-40% in susceptible cultivars. ||Compactness assessment timing is critical, as post-veraison berry softening increases apparent density.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tello J et al. (2015) A new image-based tool for the high throughput phenotyping of pollen viability: evaluation of inter- and intra-cultivar diversity in grapevine. Plant Methods 11:16|| Molitor D et al. (2012) Timing of cluster-zone leaf removal and its impact on canopy morphology, cluster structure and bunch rot susceptibility of grapes. Journal International des Sciences de la Vigne et du Vin 46:149-159"
  },
  "Compact_Cluster_Disposition": {
    "definition": "A cluster compactness disposition that is the inherited capacity of a Vitis vinifera plant to develop tightly packed clusters where berries are in close contact and often deformed by mutual pressure, with high berry density per unit rachis length (typically greater than 8 berries/cm) and limited air circulation within the cluster interior.",
    "alternative_term": "tight cluster trait | dense bunch disposition | high-density cluster |+ kompakte Traube | dichte Traube | eng gepackte Traubenstruktur",
    "example_of_usage": "Pinot Noir exemplifies compact cluster disposition with 10-15 berries/cm rachis, OIV 204 scores of 7-9, and characteristic spherical berry deformation creating polygonal cross-sections in cluster interiors. ||Riesling develops moderately compact clusters (8-11 berries/cm) that vary with clone selection, with loose clones achieving OIV scores of 5 versus compact clones at 7-8. ||Compact clusters in Pinot Noir show Botrytis infection rates 3-5× higher than loose-clustered cultivars under identical humidity conditions. ||Berry skin cracking at contact points occurs in 10-25% of berries in severely compact clusters during rapid post-veraison expansion.",
    "editor_note": "Compact cluster disposition results from the combination of high fruit set, large berry size relative to rachis framework, and short pedicels. ||The trait increases bunch rot susceptibility through impaired spray penetration, elevated interior humidity, and berry skin damage at contact points. ||Clone selection within compact cultivars can identify loose variants, with Pinot Noir clones ranging from OIV 5 to OIV 9. ||Pre-bloom gibberellin application reduces compactness through rachis elongation and berry thinning.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Vail ME, Marois JJ (1991) Grape cluster architecture and the susceptibility of berries to Botrytis cinerea. Phytopathology 81:188-191|| Hed B et al. (2009) Relationship between cluster compactness and bunch rot in Vignoles grapes. Plant Disease 93:1195-1201"
  },
  "Loose_Cluster_Disposition": {
    "definition": "A cluster compactness disposition that is the inherited capacity of a Vitis vinifera plant to develop clusters with moderate berry spacing where most berries remain separated without mutual contact or deformation, with intermediate berry density (typically 4-8 berries/cm rachis) and adequate air circulation for disease prevention.",
    "alternative_term": "open cluster trait | well-spaced bunch | moderate density cluster |+ lockere Traube | luftige Traube | locker gepackte Traubenstruktur",
    "example_of_usage": "Sauvignon Blanc exhibits loose cluster disposition with 4-6 berries/cm rachis, OIV 204 scores of 3-5, and clearly visible rachis branches between berry groups. ||Cabernet Sauvignon shows moderately loose architecture (5-7 berries/cm) with elongated conical cluster shape facilitating air movement. ||Loose clusters in Sauvignon Blanc demonstrate Botrytis incidence of 5-15% compared to 25-45% in compact Sémillon under identical conditions in Bordeaux. ||Spray coverage in loose clusters reaches 85-95% of berry surface versus only 50-70% in compact clusters, improving fungicide efficacy.",
    "editor_note": "Loose cluster disposition represents the optimal range for disease management while maintaining commercially acceptable cluster appearance and harvest efficiency. ||The trait results from moderate fruit set, proportionate berry size to rachis framework, or elongated pedicels. ||Many premium wine cultivars possess loose cluster architecture, contributing to their reputation for quality through reduced rot incidence and more uniform berry ripening from improved light and air penetration.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dry PR et al. (2010) Bunch architecture and susceptibility of berries to Botrytis cinerea in Vitis vinifera L. Australian Journal of Grape and Wine Research 16:257-264|| Herzog K et al. (2015) Initial steps for high-throughput phenotyping in vineyards. Vitis 54:1-5"
  },
  "Very_Loose_Cluster_Disposition": {
    "definition": "A cluster compactness disposition that is the inherited capacity of a Vitis vinifera plant to develop highly open clusters with widely spaced berries, extensive visible rachis structure, very low berry density (typically less than 4 berries/cm rachis), resulting from low fruit set, long pedicels, or extensive rachis branching.",
    "alternative_term": "very open cluster | straggly bunch | sparse cluster disposition |+ sehr lockere Traube | schüttere Traube | stark aufgelockerte Traubenstruktur",
    "example_of_usage": "Gewürztraminer in cool vintages with poor fruit set exhibits very loose cluster disposition with 2-4 berries/cm rachis and OIV 204 scores of 1-3, leaving extensive visible rachis framework. ||Coulure-affected Merlot clusters may show very loose architecture with only 30-50 berries per cluster versus the normal 80-150. ||Intentionally loosened clusters through gibberellin treatment in Flame Seedless achieve 2-3 berries/cm for optimal berry sizing. ||Very loose clusters virtually eliminate Botrytis risk but may increase sunburn exposure on previously shaded berries and complicate mechanical harvest through berry shatter.",
    "editor_note": "Very loose cluster disposition may result from genetic factors (low fruit set cultivars, long pedicel genotypes) or environmental/management effects (coulure, gibberellin application). ||While advantageous for disease control, extremely loose clusters reduce yield, complicate harvest, and may indicate underlying reproductive problems. ||Some breeding programs target loose but not excessively sparse cluster architecture as an optimum. ||The PIWI cultivars often exhibit loose cluster architecture inherited from disease-resistant wild Vitis species.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Töpfer R et al. (2011) New horizons for grapevine breeding. Fruit, Vegetable and Cereal Science and Biotechnology 5:79-100|| Tello J, Ibáñez J (2014) Evaluation of indexes for the quantitative and objective estimation of grapevine bunch compactness. Vitis 53:9-16"
  },
  "Cluster_Size_Disposition": {
    "definition": "A cluster architecture disposition that is the inherited capacity of a Vitis vinifera plant to develop clusters of characteristic weight and dimensions, determined by rachis length, branch number, berry count, and individual berry weight, affecting yield potential and optimal crop load management.",
    "alternative_term": "bunch size trait | cluster weight disposition | bunch dimension capacity |+ Traubengröße | Traubengewicht | Gescheingröße-Disposition",
    "example_of_usage": "Cluster size spans a 10-fold range across V. vinifera cultivars, from small-clustered Pinot Noir (80-150 g average) to large-clustered Trebbiano Toscano (400-800 g). ||Cluster weight comprises berry weight (60-75% of total) and rachis weight (2-5%), with berry number being the primary determinant of cluster size variation (r = 0.85). ||Size consistency within cultivar shows CV of 25-40% depending on vine uniformity and crop load. ||Cluster size interacts with cluster number to determine yield, with typical relationships of 20-30 clusters × 150 g = 3-4.5 kg/vine for premium wine production.",
    "editor_note": "Cluster_Size_Disposition serves as the parent class for large and small cluster categories. ||Size reflects both genetic potential and environmental expression, with significant plasticity in response to crop load, water status, and nutrition. ||Cluster thinning and shoot thinning modify effective cluster size at the vine level. ||Size assessment should specify developmental stage, as clusters gain 40-60% of final weight during the post-veraison ripening period.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Clingeleffer PR (2001) Crop development, crop estimation and crop control to secure quality and production of major wine grape varieties. Final Report to GWRDC, CSIRO Plant Industry|| Dunn GM, Martin SR (2007) A functional association in Vitis vinifera L. cv. Cabernet Sauvignon between the extent of primary branching and the number of flowers formed per inflorescence. Australian Journal of Grape and Wine Research 13:95-100"
  },
  "Large_Cluster_Disposition": {
    "definition": "A cluster size disposition that is the inherited capacity of a Vitis vinifera plant to develop clusters of above-average weight (typically greater than 300 g) and dimensions, with extensive rachis branching, high berry count, or large individual berry size contributing to elevated cluster mass.",
    "alternative_term": "big bunch trait | heavy cluster disposition | large bunch capacity |+ große Traube | schwere Traube | Großtraubigkeit",
    "example_of_usage": "Trebbiano Toscano exhibits large cluster disposition with average weights of 450-700 g, rachis lengths of 18-28 cm, and berry counts of 200-400 per cluster. ||Italia table grape produces clusters of 500-900 g optimized for retail presentation. ||Airén develops large cylindrical-conical clusters averaging 350-500 g, contributing to its position as the most widely planted white variety globally by area. ||Large clusters in Grenache (300-450 g) combined with high fruitfulness result in potential yields exceeding 15 t/ha without cluster thinning. ||Mechanical harvest efficiency increases with cluster size due to improved target detection.",
    "editor_note": "Large cluster disposition often correlates with high yield potential but may necessitate cluster thinning for quality wine production. ||The trait can complicate uniform ripening, as berries in cluster interiors receive less light and may lag in sugar accumulation. ||Large clusters are preferred for table grape and raisin production where total yield and impressive visual presentation are primary objectives. ||Rachis strength must scale with cluster weight to prevent bunch stem necrosis under heavy crop loads.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Creasy GL, Creasy LL (2009) Grapes, CABI Publishing pp.: 78-95|| Winkler AJ et al. (1974) General Viticulture, University of California Press pp.: 234-267"
  },
  "Small_Cluster_Disposition": {
    "definition": "A cluster size disposition that is the inherited capacity of a Vitis vinifera plant to develop clusters of below-average weight (typically less than 150 g) and compact dimensions, with limited rachis branching, moderate berry count, or small individual berry size resulting in reduced cluster mass.",
    "alternative_term": "small bunch trait | light cluster disposition | petite bunch capacity |+ kleine Traube | leichte Traube | Kleintraubigkeit",
    "example_of_usage": "Pinot Noir exhibits characteristic small cluster disposition with average weights of 80-140 g, rachis lengths of 8-12 cm, and berry counts of 60-120 per cluster. ||Gamay produces small cylindrical clusters (90-150 g) ideally suited for whole-cluster fermentation in Beaujolais. ||Nebbiolo develops small to medium clusters (100-180 g) with loose architecture, considered optimal for Barolo and Barbaresco production. ||Small clusters in premium wine cultivars typically show higher skin-to-pulp ratios, with Pinot Noir at 12-15% skin weight versus 8-10% for large-clustered cultivars.",
    "editor_note": "Small cluster disposition often associates with premium wine quality perception due to higher concentration of skin-derived compounds (anthocyanins, tannins, aromatics) per unit juice volume. ||The trait reduces yield potential, requiring higher cluster numbers per vine or acceptance of lower production levels. ||Small clusters facilitate whole-cluster fermentation techniques and may improve ripening uniformity. ||Clone selection within small-clustered cultivars can identify variants with modestly larger clusters while retaining quality attributes.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Matthews MA, Nuzzo V (2007) Berry size and yield paradigms on Vitis vinifera wine quality. Acta Horticulturae 754:423-436|| Roby G et al. (2004) Berry size and vine water deficits as factors in winegrape composition: anthocyanins and tannins. Australian Journal of Grape and Wine Research 10:100-107"
  },
  "Wing_Development_Disposition": {
    "definition": "A cluster architecture disposition that is the inherited capacity of a Vitis vinifera plant to develop prominent lateral branches (shoulders or wings) at the proximal end of the cluster, creating compound cluster shapes with one or more distinct secondary sub-clusters attached to the main rachis below the peduncle.",
    "alternative_term": "cluster shoulder development | bunch wing trait | lateral branch disposition |+ Schulterbildung | Flügelentwicklung | Traubenschulter-Disposition",
    "example_of_usage": "Cabernet Sauvignon exhibits strong wing development disposition with 1-2 prominent shoulders per cluster, creating the characteristic winged-conical cluster shape described in ampelographic references. ||Wing weight in Cabernet Sauvignon averages 20-35% of total cluster weight, with shoulder berry counts of 30-80. ||Merlot shows variable wing development (0-2 shoulders) depending on clone and vigor. ||Thompson Seedless typically lacks wings (simple conical shape), while Flame Seedless may develop small shoulders. ||Wing presence increases effective cluster surface area, potentially improving spray coverage and air circulation compared to cylindrical clusters of equivalent weight.",
    "editor_note": "Wing development results from enhanced growth of the first one or two basal branches of the inflorescence rachis, which elongate and bear berries comparably to the main cluster axis. ||The trait shows moderate heritability and clone-specific expression. ||Wings may detach during mechanical harvest, requiring separation equipment adjustments. ||Ampelographic description systems classify wing development on scales of absent/present/prominent, with further characterization of wing size relative to main cluster body.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "OIV (2009) OIV Descriptor List for Grape Varieties and Vitis Species, 2nd Ed, Organisation Internationale de la Vigne et du Vin|| Galet P (2000) Dictionnaire encyclopédique des cépages, Hachette pp.: 45-52"
  },
  "Phenological_Timing_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to progress through developmental stages (phenophases) at characteristic times relative to environmental cues, determining the temporal pattern of dormancy release, budbreak, flowering, veraison, ripening, and leaf senescence across the annual growth cycle.",
    "alternative_term": "phenological development trait | seasonal timing capacity | growth stage timing disposition |+ phänologische Entwicklung | jahreszeitliches Timing | Phänologie-Disposition",
    "example_of_usage": "Phenological timing varies by 4-8 weeks across V. vinifera cultivars under identical conditions, with Chasselas budbreak occurring 10-14 days before Cabernet Sauvignon in the same vineyard. ||The BBCH scale (Biologische Bundesanstalt, Bundessortenamt und CHemische Industrie) provides standardized phenological staging from BBCH 00 (dormancy) through BBCH 97 (leaf fall). ||Growing degree day (GDD) accumulation from budbreak to harvest ranges from 1100°C (Müller-Thurgau) to 1800°C (Mourvèdre) using base 10°C. ||Phenological models predict stage timing with accuracy of ±3-7 days when cultivar-specific parameters are calibrated.",
    "editor_note": "Phenological_Timing_Disposition serves as the top-level parent class for all traits related to developmental timing across the grapevine annual cycle. ||Phenological timing reflects the integration of genetic programming with environmental signals including temperature, photoperiod, and water availability. ||Climate change is advancing grapevine phenology by 2-3 days per decade in many regions, with implications for cultivar-region matching and wine style. ||The trait complex shows moderate to high heritability (h² = 0.50-0.75) for most component stages.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Coombe BG (1995) Growth stages of the grapevine: adoption of a system for identifying grapevine growth stages. Australian Journal of Grape and Wine Research 1:104-110|| Parker AK et al. (2011) General phenological model to characterise the timing of flowering and veraison of Vitis vinifera L. Australian Journal of Grape and Wine Research 17:206-216"
  },
  "Dormancy_Disposition": {
    "definition": "A phenological timing disposition that is the inherited capacity of a Vitis vinifera plant to enter, maintain, and exit the dormant state (endodormancy) characterized by arrested meristem activity, cold hardiness development, and metabolic quiescence during the winter period, with genotype-specific requirements for dormancy induction and release.",
    "alternative_term": "winter dormancy trait | endodormancy capacity | rest period disposition |+ Winterruhe | Dormanz | Vegetationsruhe-Disposition",
    "example_of_usage": "Grapevine dormancy initiates in response to shortening photoperiod (<13 hours) and declining temperatures (<15°C) during autumn, with bud endodormancy fully established by 4-8 weeks post-veraison in temperate climates. ||Dormancy depth peaks in mid-winter, with forcing requirement (days to budbreak at 25°C) reaching 30-60 days in December-January for northern hemisphere cultivars. ||Tropical cultivars such as those grown in Thailand and Brazil show reduced dormancy capacity, enabling continuous growth or managed double-cropping. ||Dormancy duration from onset to natural budbreak spans 120-180 days depending on latitude and cultivar.",
    "editor_note": "Dormancy_Disposition serves as the parent class for chilling requirement, dormancy release, and paradormancy traits. ||Endodormancy is physiologically distinct from ecodormancy (environmentally imposed) and paradormancy (correlatively imposed). ||The VvDAM and VvFT genes regulate dormancy induction and maintenance. ||Dormancy failure in warm climates causes erratic budbreak and reduced fruitfulness, necessitating chemical dormancy-breaking treatments (hydrogen cyanamide) or selection of low-chilling cultivars.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines. Journal of Crop Improvement 10:201-235|| Rubio S et al. (2019) Dormancy in grapevine buds: I. Physiological and genetic regulation. Acta Horticulturae 1248:29-36"
  },
  "Chilling_Requirement_Disposition": {
    "definition": "A dormancy disposition that is the inherited capacity of a Vitis vinifera plant to require accumulation of a genotype-specific quantity of cold exposure (chilling units) during endodormancy before buds become competent to resume growth, determining the minimum winter cold necessary for uniform and complete budbreak.",
    "alternative_term": "chilling hours requirement | cold accumulation need | vernalization requirement |+ Kältebedarf | Chilling-Anforderung | Kältesummen-Disposition",
    "example_of_usage": "Chilling requirements in V. vinifera range from 150-400 chilling hours (hours below 7.2°C) for low-chill cultivars to 800-1400 hours for high-chill cultivars adapted to continental climates. ||Pinot Noir requires approximately 700-1000 chilling hours for complete dormancy release, while Thompson Seedless satisfies chilling requirement with only 200-400 hours. ||The Utah Model quantifies chilling as weighted units based on temperature effectiveness (0-2.4°C optimal, negative contributions above 16°C). ||Insufficient chilling causes delayed, erratic, or incomplete budbreak with budbreak percentages dropping from 95% to 40-60% when chilling is 50% below cultivar requirement.",
    "editor_note": "Chilling_Requirement_Disposition serves as the parent class for high and low chilling categories. ||Multiple quantification models exist (chilling hours, Utah model, Dynamic model), with the Dynamic model showing best transferability across climates. ||Chilling requirement has a genetic basis but shows some environmental modification through prior-year temperature experience. ||Climate warming is reducing chilling accumulation in traditional wine regions by 10-30 hours per decade, threatening cultivar suitability in marginal areas.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dokoozlian NK (1999) Chilling temperature and duration interact on the budbreak of Perlette grapevine cuttings. HortScience 34:1054-1056|| Luedeling E et al. (2009) Sensitivity of grapevine phenology models to temperature: implications for climate change impacts across growing regions. Agricultural and Forest Meteorology 149:1115-1126"
  },
  "High_Chilling_Requirement_Disposition": {
    "definition": "A chilling requirement disposition that is the inherited capacity of a Vitis vinifera plant to require substantial cold accumulation (typically greater than 800 chilling hours or 60 chill portions) during dormancy for complete dormancy release, adapting the cultivar to continental or cool temperate climates with reliable winter cold.",
    "alternative_term": "high chill trait | cold-requiring cultivar | continental dormancy type |+ hoher Kältebedarf | hohe Chilling-Anforderung | kontinentaler Dormanz-Typ",
    "example_of_usage": "Riesling exhibits high chilling requirement disposition with optimal dormancy release requiring 900-1200 chilling hours, contributing to its successful cultivation in German, Austrian, and Alsatian climates. ||Cabernet Sauvignon requires 800-1000 chilling hours and shows incomplete budbreak (60-75%) when grown in subtropical regions without dormancy-breaking treatment. ||Pinot Noir populations from Burgundy demonstrate high chilling requirements (850-1100 hours) that present challenges in warm winter areas of Australia and California. ||High-chill cultivars moved to mild winter climates typically require hydrogen cyanamide application (1-2%) to achieve commercially acceptable budbreak uniformity.",
    "editor_note": "High chilling requirement evolved as an adaptation to continental climates, preventing premature budbreak during transient winter warm spells followed by damaging cold. ||The trait provides a safety mechanism against spring frost damage by delaying budbreak until winter is reliably concluded. ||High-chill cultivars planted in insufficient chilling zones show poor canopy development, reduced fruitfulness, and accelerated vine decline over multiple seasons. ||Climate change projections indicate many currently adequate chilling regions will become marginal for high-chill cultivars by 2050.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Moncur MW et al. (1989) Base temperatures for budbreak and leaf appearance of grapevines. American Journal of Enology and Viticulture 40:21-26|| Webb LB et al. (2007) Modelled impact of future climate change on the phenology of winegrapes in Australia. Australian Journal of Grape and Wine Research 13:165-175"
  },
  "Low_Chilling_Requirement_Disposition": {
    "definition": "A chilling requirement disposition that is the inherited capacity of a Vitis vinifera plant to achieve complete dormancy release with minimal cold accumulation (typically less than 400 chilling hours or 30 chill portions), enabling cultivation in subtropical, Mediterranean, or tropical climates with limited winter cold.",
    "alternative_term": "low chill trait | warm-climate cultivar | subtropical dormancy type |+ niedriger Kältebedarf | niedrige Chilling-Anforderung | subtropischer Dormanz-Typ",
    "example_of_usage": "Thompson Seedless (Sultanina) exhibits low chilling requirement disposition with dormancy release achieved after only 200-350 chilling hours, enabling its widespread cultivation in warm regions from California to India. ||Flame Seedless requires 250-400 chilling hours, suitable for desert viticulture in the Coachella Valley with winter temperatures rarely below 10°C. ||Tropical cultivars and hybrids selected for Brazilian and Thai viticulture may require fewer than 150 chilling hours or show near-continuous growth capacity. ||Low-chill cultivars in temperate climates risk premature budbreak during warm winter periods followed by frost damage.",
    "editor_note": "Low chilling requirement facilitates warm-climate viticulture but creates vulnerability to erratic budbreak when winter temperatures fluctuate. ||Many table grape cultivars have been selected for low chilling to enable production in warm markets near consumption centers. ||The trait shows quantitative inheritance with moderate heritability, enabling breeding for climate-specific chilling requirements. ||Chemical dormancy release using hydrogen cyanamide can partially substitute for insufficient natural chilling in low-chill cultivars experiencing unusually warm winters.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dokoozlian NK et al. (1995) Cultural practices and environmental influences on dormancy and dormancy release of grapevines. In: Rantz JM (ed) Proceedings of the International Symposium on Table Grape Production, ASEV pp.: 183-188|| Camargo UA et al. (2012) Grapevine breeding for tropical and subtropical regions. Acta Horticulturae 931:357-364"
  },
  "Dormancy_Release_Disposition": {
    "definition": "A dormancy disposition that is the inherited capacity of a Vitis vinifera plant to transition from endodormancy to ecodormancy once chilling requirements are satisfied, characterized by acquisition of growth competence in bud meristems and responsiveness to forcing temperatures for budbreak initiation.",
    "alternative_term": "dormancy exit capacity | rest completion | endodormancy termination trait |+ Dormanzlösung | Ruhebeendigung | Endodormanz-Aufhebung",
    "example_of_usage": "Dormancy release in Chardonnay occurs progressively during January-February in northern temperate zones, with forcing time at 25°C decreasing from 45-60 days in early December to 10-15 days by late February as chilling accumulates. ||Riesling demonstrates abrupt dormancy release once chilling threshold is met, with forcing time dropping from 50 to 12 days within a 2-week window. ||Biological markers of dormancy release include increased bud respiration rate (2-3× dormant levels), resumed cell division in meristems detectable by BrdU incorporation, and upregulation of VvFT expression. ||Field budbreak follows dormancy release by 2-6 weeks depending on spring temperature progression.",
    "editor_note": "Dormancy release is distinct from budbreak itself, representing the internal transition from endodormancy (inhibition from within the bud) to ecodormancy (inhibition from environmental conditions). ||Once dormancy is released, buds will grow whenever temperatures exceed the threshold (approximately 10°C base temperature). ||The timing of dormancy release relative to field temperatures determines frost risk, with early release in warm winter regions creating vulnerability to late cold events. ||Hormonal changes during release include declining ABA and increasing cytokinin levels in bud tissues.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lavee S, May P (1997) Dormancy of grapevine buds: facts and speculation. Australian Journal of Grape and Wine Research 3:31-46|| Pérez FJ et al. (2008) Hydrogen peroxide and glucanase activity during budbreak in grapevine. Vitis 47:17-22"
  },
  "Paradormancy_Disposition": {
    "definition": "A dormancy disposition that is the inherited capacity of a Vitis vinifera plant to maintain lateral and secondary buds in a quiescent state through correlative inhibition (apical dominance) exerted by actively growing shoot tips and primary buds, preventing lateral growth until the inhibitory signal is removed or overcome.",
    "alternative_term": "correlative inhibition trait | apical dominance disposition | lateral bud suppression capacity |+ Paradormanz | korrelative Hemmung | Apikaldominanz-Disposition",
    "example_of_usage": "Paradormancy in intact grapevine shoots maintains lateral buds quiescent during the growing season, with only 5-15% of lateral buds developing into summer laterals under normal conditions in most V. vinifera cultivars. ||Shoot tip removal (hedging) releases paradormancy, triggering lateral bud growth within 7-14 days through reduced auxin supply and increased cytokinin signaling. ||Merlot shows weaker paradormancy with 30-50% of lateral buds growing spontaneously, while Cabernet Sauvignon maintains stronger paradormancy (10-20% lateral growth). ||Primary bud damage from spring frost releases secondary bud paradormancy, with secondary shoots emerging within 10-21 days depending on temperature and cultivar.",
    "editor_note": "Paradormancy differs mechanistically from endodormancy, being imposed by signals from other plant organs rather than internal bud factors. ||The auxin-cytokinin balance hypothesis explains paradormancy through basipetal auxin transport from shoot tips suppressing lateral bud cytokinin response. ||Paradormancy strength affects canopy management requirements, with weak paradormancy increasing lateral shoot removal labor but potentially providing recovery capacity following frost or hail damage. ||The trait shows cultivar-specific expression modified by vine vigor and nitrogen status.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Cline MG (1991) Apical dominance. The Botanical Review 57:318-358|| Dry PR (2000) Canopy management for fruitfulness. Australian Journal of Grape and Wine Research 6:109-115"
  },
  "Budbreak_Timing_Disposition": {
    "definition": "A phenological timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate visible bud swelling and green tissue emergence (BBCH 07-09) at a characteristic time in spring, determined by the interaction of chilling fulfillment, heat accumulation requirements, and genotype-specific thermal sensitivity.",
    "alternative_term": "budburst timing | spring phenology trait | bud emergence timing |+ Austriebszeitpunkt | Knospentreiben | Austriebs-Disposition",
    "example_of_usage": "Budbreak timing spans a 4-6 week range across V. vinifera cultivars in any given location, with Chardonnay and Pinot Noir among the earliest (base 10°C GDD requirement of 50-80°C) and Mourvèdre and Carignan among the latest (GDD requirement of 120-160°C). ||In Bordeaux, Merlot reaches BBCH 09 (green tip visible) approximately 7-10 days before Cabernet Sauvignon in the same vineyard. ||Budbreak date shows year-to-year variation of ±10-18 days within cultivar depending on spring temperature patterns. ||The base temperature for bud development ranges from 7-12°C across cultivars, with lower base temperatures associated with earlier budbreak.",
    "editor_note": "Budbreak_Timing_Disposition serves as the parent class for early, mid-season, and late budbreak categories. ||The trait represents the first visible phenological event of the growing season and determines the starting point for GDD accumulation toward subsequent stages. ||Budbreak timing interacts critically with spring frost risk, as earlier cultivars face greater frost exposure probability. ||Thermal time models using cultivar-specific base temperatures predict budbreak with ±3-5 day accuracy when dormancy release timing is correctly estimated.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duchêne E, Schneider C (2005) Grapevine and climatic changes: a glance at the situation in Alsace. Agronomy for Sustainable Development 25:93-99|| Garcia de Cortázar-Atauri I et al. (2009) Performance of several models for predicting budburst date of grapevine (Vitis vinifera L.). International Journal of Biometeorology 53:317-326"
  },
  "Early_Budbreak_Disposition": {
    "definition": "A budbreak timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate budbreak earlier than average for the species under given environmental conditions, typically within the first tercile of cultivar budbreak dates, requiring lower heat accumulation following dormancy release.",
    "alternative_term": "early budburst | precocious budbreak | early spring phenology |+ früher Austrieb | frühes Knospentreiben | Frühaustrieb",
    "example_of_usage": "Chardonnay exhibits early budbreak disposition, reaching BBCH 09 approximately 7-14 days before the cultivar median in multi-variety trials, with heat sum requirement of only 50-70 GDD (base 10°C) post-dormancy release. ||Chasselas and Gewürztraminer show similarly early budbreak, emerging within the first 20% of V. vinifera cultivars across European phenology networks. ||Early budbreak in Pinot Noir at Burgundy reference sites (Clos de Vougeot) occurs at mean date of April 8 versus April 22 for late cultivars. ||Spring frost damage frequency in early cultivars exceeds late cultivars by 2-4× in continental climates with April frost probability above 30%.",
    "editor_note": "Early budbreak disposition confers advantages in short-season climates by maximizing the available growing period, but increases frost risk and may advance flowering into suboptimal pollination conditions. ||The trait results from lower thermal thresholds for meristem reactivation and/or reduced heat accumulation requirement following endodormancy release. ||Site selection (elevated, air-drained) partially mitigates frost risk for early cultivars. ||Climate warming is differentially advancing early cultivars, potentially disrupting traditional cultivar phenological sequences.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jones GV, Davis RE (2000) Climate influences on grapevine phenology, grape composition, and wine production and quality for Bordeaux, France. American Journal of Enology and Viticulture 51:249-261|| Leolini L et al. (2018) Late spring frost impacts on future grapevine distribution in Europe. Field Crops Research 222:197-208"
  },
  "Mid_Season_Budbreak_Disposition": {
    "definition": "A budbreak timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate budbreak at intermediate timing relative to the species range, typically within the second tercile of cultivar budbreak dates, balancing frost avoidance with adequate growing season length.",
    "alternative_term": "intermediate budbreak | average budburst timing | mid-spring phenology |+ mittlerer Austrieb | durchschnittliches Knospentreiben | Normalaustrieb",
    "example_of_usage": "Cabernet Sauvignon exhibits mid-season budbreak disposition, reaching BBCH 09 within ±5 days of the cultivar median in comparative trials, with heat sum requirement of 80-110 GDD (base 10°C). ||Merlot and Syrah show similar intermediate timing, providing balanced frost risk and season length across diverse growing regions. ||Mid-season cultivars in Napa Valley initiate budbreak during the second week of March, approximately 10 days after Chardonnay and 10 days before Mourvèdre. ||The coefficient of variation for budbreak date in mid-season cultivars (12-18%) is typically lower than for early cultivars (15-22%) due to more stable spring temperature conditions at later calendar dates.",
    "editor_note": "Mid-season budbreak disposition represents the adaptive optimum for many traditional wine regions, balancing frost avoidance with adequate heat accumulation for complete ripening. ||The category encompasses the majority of commercially important wine grape cultivars, reflecting centuries of empirical selection for regional climate matching. ||Mid-season cultivars offer flexibility in site selection and provide benchmark timing for vineyard planning and frost protection scheduling.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Parker AK et al. (2013) Classification of varieties for their timing of flowering and veraison using a modelling approach: a case study for the grapevine species Vitis vinifera L. Agricultural and Forest Meteorology 180:249-264|| Van Leeuwen C, Darriet P (2016) The impact of climate change on viticulture and wine quality. Journal of Wine Economics 11:150-167"
  },
  "Late_Budbreak_Disposition": {
    "definition": "A budbreak timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate budbreak later than average for the species under given environmental conditions, typically within the third tercile of cultivar budbreak dates, requiring higher heat accumulation following dormancy release and providing natural frost avoidance.",
    "alternative_term": "late budburst | delayed budbreak | late spring phenology |+ später Austrieb | spätes Knospentreiben | Spätaustrieb",
    "example_of_usage": "Mourvèdre exhibits late budbreak disposition, reaching BBCH 09 approximately 14-21 days after the cultivar median in multi-variety trials, with heat sum requirement of 130-170 GDD (base 10°C) post-dormancy release. ||Carignan and Grenache show similarly delayed budbreak, emerging within the last 20% of V. vinifera cultivars. ||Late budbreak in Mourvèdre at southern Rhône reference sites occurs at mean date of April 25 versus April 5 for early cultivars like Chardonnay. ||Spring frost damage in late cultivars occurs in fewer than 5% of years compared to 15-25% for early cultivars in the same continental vineyard sites.",
    "editor_note": "Late budbreak disposition provides natural frost protection but requires adequate growing season heat to achieve full ripeness, restricting late cultivars to warm climate regions or favorable mesoclimates. ||The trait results from higher thermal thresholds for meristem reactivation and/or greater heat accumulation requirement following dormancy release. ||Late budbreak may compress the interval to flowering, as both events converge toward optimal temperature ranges. ||Some late cultivars also show late ripening, but the correlation is imperfect (r = 0.6-0.7), with some late-breaking cultivars ripening at intermediate timing.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tomasi D et al. (2011) Grapevine phenology and climate change: relationships and trends in the Veneto region of Italy for 1964-2009. American Journal of Enology and Viticulture 62:329-339|| Webb LB et al. (2012) Observed trends in winegrape maturity in Australia. Global Change Biology 18:3055-3067"
  },
  "Flowering_Timing_Disposition": {
    "definition": "A phenological timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate and complete anthesis (BBCH 60-69) at a characteristic time relative to budbreak and environmental conditions, determining the calendar period of pollination and fruit set and influencing growing season partitioning between vegetative and reproductive development.",
    "alternative_term": "bloom timing | anthesis timing | flowering phenology trait |+ Blühzeitpunkt | Blühtermin | Anthese-Timing",
    "example_of_usage": "Flowering occurs 50-80 days after budbreak across V. vinifera cultivars, with the interval showing less variability (CV 8-12%) than budbreak timing itself (CV 12-22%) due to the stabilizing effect of accumulated thermal time. ||Chardonnay reaches 50% capfall (BBCH 65) after accumulating 350-400 GDD (base 10°C) from budbreak, while Grenache requires 450-550 GDD to the same stage. ||The flowering window per cultivar spans 8-15 days, with individual vine flowering duration of 5-10 days under favorable conditions. ||Optimal flowering temperatures of 20-25°C promote rapid, synchronized anthesis|| temperatures below 15°C extend flowering duration by 50-100% and reduce fruit set.",
    "editor_note": "Flowering_Timing_Disposition serves as the parent class for early and late flowering categories. ||The timing of flowering critically affects fruit set success through temperature effects on pollen germination and tube growth. ||Flowering timing also determines the interval available for berry development and ripening, with later flowering compressing the post-veraison period. ||Climate change is advancing flowering by 2-3 days per decade in many regions, potentially shifting bloom into warmer or cooler periods depending on latitude.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Zapata D et al. (2017) Predicting key phenological stages for 17 grapevine cultivars (Vitis vinifera L.). American Journal of Enology and Viticulture 68:60-72|| Caffarra A, Eccel E (2011) Projecting the impacts of climate change on the phenology of grapevine in a mountain area. Australian Journal of Grape and Wine Research 17:52-61"
  },
  "Early_Flowering_Disposition": {
    "definition": "A flowering timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate and complete flowering earlier than average for the species, typically within the first tercile of cultivar bloom dates, reaching anthesis with lower thermal time accumulation from budbreak.",
    "alternative_term": "early bloom | precocious flowering | early anthesis trait |+ frühe Blüte | Frühblüte | früher Blühtermin",
    "example_of_usage": "Chardonnay exhibits early flowering disposition, reaching 50% capfall approximately 5-10 days before the cultivar median in comparative trials, with budbreak-to-flowering thermal requirement of 320-380 GDD (base 10°C). ||Pinot Noir and Müller-Thurgau show similarly early flowering, completing anthesis within the first 25% of V. vinifera cultivars. ||Early flowering in Chardonnay at Burgundy reference sites occurs at mean date of June 5-10 versus June 18-25 for late-flowering cultivars. ||The budbreak-to-flowering interval in early flowering cultivars averages 55-65 days compared to 70-85 days for late flowering types under identical thermal conditions.",
    "editor_note": "Early flowering disposition may expose vines to suboptimal pollination conditions if bloom coincides with cool, wet spring weather, increasing coulure risk in some climates. ||However, early flowering extends the post-flowering period available for berry development and ripening, potentially improving fruit quality in short-season regions. ||Early flowering cultivars show tighter correlation between budbreak and flowering dates (r = 0.85-0.92) than late cultivars, suggesting more deterministic developmental programming.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duchêne E et al. (2010) A grapevine (Vitis vinifera L.) genetic map based on candidate genes. Theoretical and Applied Genetics 120:145-163|| Cola G et al. (2014) Description and testing of a weather-based model for predicting phenology, canopy development and source–sink balance in Vitis vinifera L. cv. Barbera. Agricultural and Forest Meteorology 184:117-136"
  },
  "Late_Flowering_Disposition": {
    "definition": "A flowering timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate and complete flowering later than average for the species, typically within the third tercile of cultivar bloom dates, requiring greater thermal time accumulation from budbreak to anthesis.",
    "alternative_term": "late bloom | delayed flowering | late anthesis trait |+ späte Blüte | Spätblüte | später Blühtermin",
    "example_of_usage": "Mourvèdre exhibits late flowering disposition, reaching 50% capfall approximately 10-18 days after the cultivar median in comparative trials, with budbreak-to-flowering thermal requirement of 480-580 GDD (base 10°C). ||Grenache and Carignan show similarly delayed flowering, completing anthesis within the last 25% of V. vinifera cultivars. ||Late flowering in Grenache at southern Rhône reference sites occurs at mean date of June 20-28 versus June 1-8 for early-flowering Chardonnay. ||The extended pre-flowering period in late cultivars correlates with more extensive inflorescence development, often resulting in larger flower numbers per cluster (300-500 versus 150-250 in early cultivars).",
    "editor_note": "Late flowering disposition typically positions bloom during warmer, more stable weather conditions, potentially improving fruit set reliability in Mediterranean climates. ||However, the compressed post-flowering period may challenge complete ripening in cool years or short-season regions, making late flowering cultivars better suited to warm climate viticulture. ||Late flowering shows weaker correlation with late ripening (r = 0.5-0.6) than might be expected, as post-flowering development rates vary independently among cultivars.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Parker AK et al. (2011) General phenological model to characterise the timing of flowering and veraison of Vitis vinifera L. Australian Journal of Grape and Wine Research 17:206-216|| Sadras VO, Moran MA (2012) Elevated temperature decouples anthocyanins and sugars in berries of Shiraz and Cabernet Franc. Australian Journal of Grape and Wine Research 18:115-122"
  },
  "Veraison_Timing_Disposition": {
    "definition": "A phenological timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate the onset of ripening (veraison, BBCH 81-85) at a characteristic time relative to flowering and environmental conditions, marking the transition from berry growth phase to sugar accumulation and color development through coordinated hormonal, metabolic, and gene expression changes.",
    "alternative_term": "veraison onset timing | ripening initiation trait | color change timing |+ Reifebeginn | Véraison-Zeitpunkt | Farbumschlagstermin",
    "example_of_usage": "Veraison occurs 40-70 days after flowering across V. vinifera cultivars, with Chasselas reaching 50% color change approximately 45-50 days post-bloom and Mourvèdre requiring 65-75 days. ||The flowering-to-veraison interval requires 700-1100 GDD (base 10°C) depending on cultivar, with thermal time models predicting veraison onset within ±4-7 days accuracy. ||Veraison date in Pinot Noir at Burgundy reference sites averages August 10-15, advancing by approximately 2 days per decade since 1980. ||The physiological transition spans 7-21 days per vine from first to last berry depending on cultivar and cluster architecture.",
    "editor_note": "Veraison_Timing_Disposition serves as the parent class for early veraison, uniform veraison, and extended veraison categories. ||Veraison represents the most dramatic developmental transition in grape berry development, involving abscisic acid accumulation, ethylene signaling, sugar transporter activation, and anthocyanin biosynthesis initiation in colored cultivars. ||The timing of veraison critically affects the length of the ripening period and final fruit composition, with earlier veraison generally providing longer maturation periods in temperate climates.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Coombe BG, McCarthy MG (2000) Dynamics of grape berry growth and physiology of ripening. Australian Journal of Grape and Wine Research 6:131-135|| Kuhn N et al. (2014) Berry ripening: recently heard through the grapevine. Journal of Experimental Botany 65:4543-4559"
  },
  "Early_Veraison_Disposition": {
    "definition": "A veraison timing disposition that is the inherited capacity of a Vitis vinifera plant to initiate ripening earlier than average for the species, typically within the first tercile of cultivar veraison dates, reaching the onset of color change and softening with lower thermal time accumulation from flowering.",
    "alternative_term": "early ripening onset | precocious veraison | early color change trait |+ früher Reifebeginn | frühe Véraison | Frühfärbung",
    "example_of_usage": "Chasselas exhibits early veraison disposition, reaching 50% color change approximately 45-50 days post-flowering with thermal requirement of 680-780 GDD (base 10°C) from bloom. ||Pinot Noir and Chardonnay show similarly early veraison, initiating ripening within the first 25% of V. vinifera cultivars in multi-variety trials. ||Early veraison in Chasselas at Swiss reference sites (Pully) occurs at mean date of July 25-30 versus August 20-28 for late cultivars. ||The extended post-veraison period in early cultivars (55-70 days versus 40-50 days for late cultivars in the same climate) allows gradual flavor development and tannin maturation under cooler autumn conditions.",
    "editor_note": "Early veraison disposition provides advantages in cool or short-season climates by maximizing the ripening period before autumn temperature decline and frost risk. ||The trait correlates moderately with early flowering (r = 0.65-0.75) but shows independent genetic control, enabling selection for early veraison without necessarily early budbreak vulnerability. ||Early veraison cultivars benefit from extended hang time for phenolic maturity while achieving sugar targets, though excessively early veraison in warm climates may accelerate ripening during peak summer heat, reducing aromatic complexity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Parker AK et al. (2011) General phenological model to characterise the timing of flowering and veraison of Vitis vinifera L. Australian Journal of Grape and Wine Research 17:206-216|| Duchêne E et al. (2012) Phenology and grape ripening in relation to climate change. Climate Research 53:145-156"
  },
  "Uniform_Veraison_Disposition": {
    "definition": "A veraison timing disposition that is the inherited capacity of a Vitis vinifera plant to undergo the ripening transition synchronously across berries within clusters and across clusters within vines, with minimal temporal dispersion between first and last berries reaching the color change and softening stage.",
    "alternative_term": "synchronous veraison | even ripening onset | uniform color change |+ gleichmäßige Véraison | synchroner Reifebeginn | einheitlicher Farbumschlag",
    "example_of_usage": "Cabernet Sauvignon exhibits uniform veraison disposition with 80% of berries completing color change within a 7-10 day window under favorable conditions, compared to 14-21 days for cultivars with extended veraison. ||Merlot shows high veraison uniformity with within-cluster coefficient of variation for sugar concentration at harvest of 8-12% compared to 15-25% in less uniform cultivars. ||Uniform veraison in Riesling enables single-pass harvest with consistent °Brix readings (±1.0°) across the vineyard block. ||Factors promoting uniformity include moderate crop load (Ravaz index 5-8), balanced canopy (1.0-1.5 m² leaf area per kg fruit), and even water status throughout the fruit zone.",
    "editor_note": "Uniform veraison disposition reflects both genetic predisposition and environmental/management expression. ||Uniform ripening simplifies harvest timing decisions, improves wine consistency, and enables mechanical harvest without excessive heterogeneity in fruit maturity. ||The trait correlates with loose cluster architecture (r = 0.55-0.65) through improved light penetration and reduced within-cluster microclimate variation. ||Clone selection within cultivars can identify more uniform variants, with commercial Chardonnay clones showing veraison duration ranges from 8 to 18 days.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 265-285|| Pagay V, Cheng L (2010) Variability in berry maturation of Concord and Cabernet franc in a cool climate. American Journal of Enology and Viticulture 61:61-67"
  },
  "Extended_Veraison_Disposition": {
    "definition": "A veraison timing disposition that is the inherited capacity of a Vitis vinifera plant to undergo the ripening transition asynchronously across berries, with substantial temporal dispersion between first and last berries reaching color change and softening, resulting in pronounced within-cluster and within-vine maturity heterogeneity.",
    "alternative_term": "asynchronous veraison | uneven ripening onset | protracted color change |+ verlängerte Véraison | ungleichmäßiger Reifebeginn | gestaffelter Farbumschlag",
    "example_of_usage": "Gewürztraminer exhibits extended veraison disposition with the ripening transition spanning 18-28 days from first to last berry within clusters, creating harvest timing dilemmas between under-ripe green berries and over-ripe pink berries. ||Zinfandel notoriously shows extended veraison with individual cluster sugar ranges of 18-28°Brix at any single harvest date, necessitating multiple harvest passes or acceptance of heterogeneous fruit. ||Extended veraison in Grenache contributes to the characteristic raisined berry proportion (5-15%) observed at harvest in warm vintages. ||The coefficient of variation for berry sugar concentration exceeds 20% at harvest in extended veraison cultivars compared to 8-12% in uniform types.",
    "editor_note": "Extended veraison disposition complicates harvest decisions and may reduce wine quality consistency through variable fruit maturity. ||The trait is exacerbated by compact cluster architecture (limited light to interior berries), high crop loads, and water stress during lag phase. ||Some winemakers exploit extended veraison for stylistic purposes, as the mixture of maturity levels contributes complexity in certain wine styles. ||Management interventions including cluster thinning, leaf removal, and irrigation management can reduce but not eliminate veraison dispersion in genetically predisposed cultivars.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kasimatis AN et al. (1975) Conversion of cane-pruned Zinfandel vineyards to bilateral cordon training and machine harvest. American Journal of Enology and Viticulture 26:157-160|| Friend AP et al. (2009) Delayed winter spur-pruning causes a shift in the source of fruit-zone leaf area in Vitis vinifera Merlot. Australian Journal of Grape and Wine Research 15:254-260"
  },
  "Ripening_Timing_Disposition": {
    "definition": "A phenological timing disposition that is the inherited capacity of a Vitis vinifera plant to reach harvest maturity at a characteristic time relative to veraison and cumulative environmental conditions, determining the calendar period when berries achieve target sugar, acid, and flavor compound concentrations for intended use.",
    "alternative_term": "harvest timing trait | maturation timing | ripeness timing disposition |+ Reifezeitpunkt | Erntereife-Timing | Reifetermin-Disposition",
    "example_of_usage": "Ripening timing spans an 8-10 week range across V. vinifera cultivars in any given region, from very early Chasselas (harvest late August in central Europe) to very late Mourvèdre (harvest late October). ||The veraison-to-harvest interval ranges from 35-45 days in very early cultivars to 65-80 days in very late cultivars under identical thermal conditions. ||Winkler's heat summation classification correlates ripening timing with regional suitability, with Region I (<1390 GDD) suited to early cultivars and Region V (>2220 GDD) accommodating late cultivars. ||Ripening timing shows high heritability (h² = 0.70-0.85) and moderate correlation with flowering timing (r = 0.55-0.70).",
    "editor_note": "Ripening_Timing_Disposition serves as the parent class for the five ripening period categories from very early to very late. ||The trait represents the integration of developmental rate from veraison through maturity, influenced by both genetic programming and environmental modulation. ||Ripening timing determines cultivar-climate matching, with mismatches causing either incomplete ripening (late cultivar in cool climate) or accelerated ripening with flavor compromise (early cultivar in hot climate). ||Traditional wine regions reflect centuries of empirical cultivar-climate matching for optimal ripening timing.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Winkler AJ et al. (1974) General Viticulture, University of California Press pp.: 61-75|| Jones GV et al. (2005) Climate change and global wine quality. Climatic Change 73:319-343"
  },
  "Very_Early_Ripening_Disposition": {
    "definition": "A ripening timing disposition that is the inherited capacity of a Vitis vinifera plant to reach harvest maturity very early in the season, typically within the first 10-15% of cultivar harvest dates for a region, requiring minimal heat accumulation from veraison to maturity and suited to cool climates or early-season fresh market windows.",
    "alternative_term": "very precocious ripening | ultra-early maturation | first-harvest trait |+ sehr frühe Reife | Frühreife | sehr früher Reifetermin",
    "example_of_usage": "Madeleine Angevine exhibits very early ripening disposition, reaching 20°Brix approximately 30-38 days post-veraison with total season heat requirement of 900-1050 GDD (base 10°C) from budbreak. ||Siegerrebe and Ortega ripen in early-mid August in German wine regions, 6-8 weeks before late cultivars in the same vineyard. ||Pearl of Csaba, a table grape, achieves market maturity in late July in Mediterranean climates, commanding premium early-season prices. ||Very early cultivars typically produce wines of 10-11.5% alcohol with fresh, aromatic profiles suited to light wine styles or sparkling base production.",
    "editor_note": "Very early ripening disposition enables viticulture in marginal cool climates (southern England, Belgium, northern Germany) where heat accumulation is insufficient for later cultivars. ||The trait may associate with lower total phenolic development due to compressed ripening period, though aromatic compound synthesis can be favored by cooler maturation temperatures. ||Very early cultivars face harvest timing pressure, as rapid sugar accumulation can outpace flavor development, requiring careful monitoring to avoid overripeness.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Skelton S (2014) Wine Growing in Great Britain, 2nd Ed, SP Skelton pp.: 89-112|| Fraga H et al. (2016) Future scenarios for viticultural zoning in Europe: ensemble projections and uncertainties. International Journal of Biometeorology 60:1599-1613"
  },
  "Early_Ripening_Disposition": {
    "definition": "A ripening timing disposition that is the inherited capacity of a Vitis vinifera plant to reach harvest maturity early in the season, typically within the second quartile of cultivar harvest dates for a region, requiring moderate heat accumulation and providing extended post-harvest vine recovery period before dormancy.",
    "alternative_term": "early maturation | precocious ripening | early harvest trait |+ frühe Reife | Frühreife-Disposition | früher Erntetermin",
    "example_of_usage": "Pinot Noir exhibits early ripening disposition, reaching 22-24°Brix approximately 40-50 days post-veraison with total season heat requirement of 1100-1300 GDD (base 10°C) from budbreak. ||Chardonnay and Gamay show similar early ripening, completing harvest in the first third of the regional vintage window. ||Early ripening in Pinot Noir at Burgundy reference sites occurs at mean date of September 15-25, approximately 3-4 weeks before Cabernet Sauvignon in Bordeaux. ||The extended post-harvest period (6-10 weeks before leaf fall) in early cultivars facilitates carbohydrate reserve accumulation for following-season fruitfulness.",
    "editor_note": "Early ripening disposition confers advantages in cool and moderate climates by ensuring complete maturation before autumn temperature decline and rain events that can compromise fruit quality. ||The trait correlates moderately with early budbreak (r = 0.50-0.65) and early flowering (r = 0.55-0.70), but genetic independence allows selection for late budbreak with early ripening to minimize frost risk while maximizing ripening reliability. ||Climate change is shifting early cultivars toward even earlier harvest, potentially advancing into warmer August conditions that may alter wine style.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Van Leeuwen C et al. (2008) Influence of climate, soil, and cultivar on terroir. American Journal of Enology and Viticulture 55:207-217|| Duchêne E, Schneider C (2005) Grapevine and climatic changes: a glance at the situation in Alsace. Agronomy for Sustainable Development 25:93-99"
  },
  "Mid_Season_Ripening_Disposition": {
    "definition": "A ripening timing disposition that is the inherited capacity of a Vitis vinifera plant to reach harvest maturity at intermediate timing relative to the species range, typically within the middle two quartiles of cultivar harvest dates for a region, requiring moderate to substantial heat accumulation and suited to temperate climates with reliable autumn conditions.",
    "alternative_term": "intermediate ripening | average maturation timing | mid-harvest trait |+ mittlere Reife | Normalreife | mittlerer Erntetermin",
    "example_of_usage": "Cabernet Sauvignon exhibits mid-season ripening disposition, reaching 23-25°Brix approximately 50-60 days post-veraison with total season heat requirement of 1400-1600 GDD (base 10°C) from budbreak. ||Merlot, Syrah, and Sangiovese show similar intermediate ripening, completing harvest during the middle third of the regional vintage window. ||Mid-season ripening in Cabernet Sauvignon at Bordeaux reference sites occurs at mean date of October 1-15, bracketed by earlier Merlot (September 20-30) and later Petit Verdot (October 15-25). ||The mid-season category encompasses the majority of classic wine grape cultivars, reflecting historical selection for reliable maturation in traditional European wine regions.",
    "editor_note": "Mid-season ripening disposition represents the adaptive center for temperate climate viticulture, balancing heat requirement against growing season length constraints. ||The category includes most internationally planted wine cultivars, which were selected over centuries for consistent ripening in their regions of origin. ||Mid-season cultivars show greatest flexibility in site selection, performing acceptably across a range of mesoclimates within suitable macroclimatic zones. ||Climate warming is shifting mid-season cultivars toward earlier harvest dates, with potential implications for wine style and regional typicity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Jones GV, Davis RE (2000) Climate influences on grapevine phenology, grape composition, and wine production and quality for Bordeaux, France. American Journal of Enology and Viticulture 51:249-261|| Gladstones J (1992) Viticulture and Environment, Winetitles pp.: 98-135"
  },
  "Late_Ripening_Disposition": {
    "definition": "A ripening timing disposition that is the inherited capacity of a Vitis vinifera plant to reach harvest maturity late in the season, typically within the fourth quartile of cultivar harvest dates for a region, requiring substantial heat accumulation and extended growing seasons for complete maturation.",
    "alternative_term": "late maturation | tardy ripening | late harvest trait |+ späte Reife | Spätreife-Disposition | später Erntetermin",
    "example_of_usage": "Cabernet Franc exhibits late ripening disposition, reaching 22-24°Brix approximately 55-65 days post-veraison with total season heat requirement of 1550-1750 GDD (base 10°C) from budbreak. ||Petit Verdot and Tannat show similar late ripening, completing harvest in the final third of the regional vintage window. ||Late ripening in Petit Verdot at Bordeaux reference sites occurs at mean date of October 15-28, 3-4 weeks after Merlot in the same appellation. ||In marginal vintages, late cultivars may fail to achieve full physiological ripeness, with residual green, herbaceous flavors indicating incomplete flavor maturation despite adequate sugar levels.",
    "editor_note": "Late ripening disposition restricts cultivar suitability to warm climates or favorable mesoclimates within moderate regions. ||The trait provides advantages in very warm climates by extending ripening into cooler autumn conditions, potentially preserving acidity and aromatic complexity that would be lost with earlier-ripening cultivars harvested during peak summer heat. ||Late cultivars face harvest timing risks from autumn rain, frost, and bird pressure, requiring careful site selection and vintage-specific management decisions.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Wolpert JA et al. (1994) Field performance of six Chardonnay clones in the Napa Valley. American Journal of Enology and Viticulture 45:393-400|| Robinson J, Harding J (2015) The Oxford Companion to Wine, 4th Ed, Oxford University Press pp.: 567-568"
  },
  "Very_Late_Ripening_Disposition": {
    "definition": "A ripening timing disposition that is the inherited capacity of a Vitis vinifera plant to reach harvest maturity very late in the season, typically within the final 10-15% of cultivar harvest dates for a region, requiring high heat accumulation and long growing seasons, restricting cultivation to warm or hot climates.",
    "alternative_term": "very tardy ripening | ultra-late maturation | final-harvest trait |+ sehr späte Reife | Spätreife | sehr später Erntetermin",
    "example_of_usage": "Mourvèdre exhibits very late ripening disposition, reaching 23-25°Brix approximately 65-80 days post-veraison with total season heat requirement of 1800-2100 GDD (base 10°C) from budbreak. ||Carignan and Graciano show similar very late ripening, completing harvest in late October to early November in Mediterranean climates. ||Very late ripening in Mourvèdre at Bandol (Provence) reference sites occurs at mean date of October 20-November 5, making it among the last cultivars harvested in French viticulture. ||Successful very late cultivar production requires Winkler Region III-V climates (>1670 GDD), limiting their range to Mediterranean, warm continental, and subtropical zones.",
    "editor_note": "Very late ripening disposition evolved as an adaptation to hot, dry Mediterranean climates where extended ripening periods under declining autumn temperatures optimize flavor development. ||The trait becomes problematic in cool or short-season climates where incomplete ripening produces unbalanced wines with green, vegetal characteristics. ||Climate change is expanding the viable range for very late cultivars into previously marginal regions, though the compressed post-harvest recovery period may affect vine health and following-season fruitfulness in newly suitable areas.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Huglin P, Schneider C (1998) Biologie et écologie de la vigne, 2nd Ed, Lavoisier pp.: 312-345|| Anderson K et al. (2017) Which Winegrape Varieties are Grown Where? A Global Empirical Picture, University of Adelaide Press pp.: 45-78"
  },
  "Phenological_Plasticity_Disposition": {
    "definition": "A phenological timing disposition that is the inherited capacity of a Vitis vinifera plant to modulate the timing of developmental stages in response to environmental variation, determining the degree to which phenological events shift under different temperature regimes, photoperiods, or other environmental signals.",
    "alternative_term": "developmental flexibility | phenological responsiveness | environmental timing sensitivity |+ phänologische Plastizität | Entwicklungsflexibilität | Umweltreaktivität",
    "example_of_usage": "Phenological plasticity varies substantially across V. vinifera cultivars, with high-plasticity cultivars such as Riesling showing 3-4 day advancement in veraison per 1°C increase in growing season temperature, while low-plasticity cultivars such as Ugni Blanc show only 1.5-2 day response to the same temperature change. ||Plasticity indices calculated from multi-site trials range from 0.5 (low responsiveness) to 2.5 (high responsiveness) days per degree-day deviation from normal. ||High plasticity enables cultivar adaptation across diverse climates but increases vintage variation, while low plasticity provides consistent timing but limits climatic range.",
    "editor_note": "Phenological_Plasticity_Disposition serves as the parent class for specific environmental response categories including temperature and photoperiod sensitivity. ||Plasticity represents the norm of reaction for phenological timing across environmental gradients, distinct from the mean timing under standard conditions. ||Understanding cultivar-specific plasticity is essential for predicting climate change impacts, as high-plasticity cultivars will show greater phenological shifts under warming scenarios. ||Plasticity may be adaptive (enabling environmental tracking) or maladaptive (causing phenological mismatches with optimal conditions).", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sadras VO, Moran MA (2013) Nonlinear effects of elevated temperature on grapevine phenology. Agricultural and Forest Meteorology 173:107-115|| Wolkovich EM et al. (2017) From Pinot to Xinomavro in the world's future wine-growing regions. Nature Climate Change 7:789-795"
  },
  "Temperature_Response_Disposition": {
    "definition": "A phenological plasticity disposition that is the inherited capacity of a Vitis vinifera plant to adjust developmental timing in response to temperature variation, with genotype-specific thermal sensitivity determining the magnitude of phenological shifts per unit change in ambient or accumulated temperature.",
    "alternative_term": "thermal sensitivity | heat response trait | temperature-driven plasticity |+ Temperaturreaktion | thermische Sensitivität | Wärmeempfindlichkeit",
    "example_of_usage": "Temperature response for budbreak-to-flowering interval ranges from 8-12 days earlier per 1°C warming in high-sensitivity cultivars (Riesling, Gewürztraminer) to 4-6 days in low-sensitivity cultivars (Grenache, Mourvèdre). ||Cabernet Sauvignon shows intermediate temperature response with veraison advancing 2.5 days per 1°C and harvest advancing 3.2 days per 1°C of seasonal warming. ||Non-linear temperature responses occur above threshold temperatures (approximately 35°C), where further warming may delay rather than advance phenology through heat stress effects. ||Temperature response coefficients derived from multi-year phenology records enable site-specific harvest date predictions with ±5-7 day accuracy.",
    "editor_note": "Temperature response disposition quantifies the thermal component of phenological plasticity, representing the primary driver of observed climate change impacts on grapevine phenology. ||High temperature response indicates strong coupling between vine development and ambient thermal conditions, enabling rapid adjustment to year-to-year variation but also magnifying long-term climate trends. ||Base temperature for development (typically 7-12°C) and optimal temperature range (25-30°C) show cultivar-specific variation that interacts with temperature response magnitude. ||Breeding for modified temperature response could enable climate change adaptation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Parker AK et al. (2011) General phenological model to characterise the timing of flowering and veraison of Vitis vinifera L. Australian Journal of Grape and Wine Research 17:206-216|| Webb LB et al. (2012) Observed trends in winegrape maturity in Australia. Global Change Biology 18:3055-3067"
  },
  "Photoperiod_Response_Disposition": {
    "definition": "A phenological plasticity disposition that is the inherited capacity of a Vitis vinifera plant to adjust developmental timing and growth patterns in response to day length (photoperiod), with genotype-specific sensitivity to the duration of light and dark periods affecting dormancy induction, growth cessation, and potentially other phenological transitions.",
    "alternative_term": "day length sensitivity | photoperiodic response | light duration plasticity |+ Photoperioden-Reaktion | Tageslängenempfindlichkeit | Lichtdauer-Response",
    "example_of_usage": "Photoperiod response in grapevine primarily affects dormancy induction and growth cessation rather than reproductive phenology, with short days (<13-14 hours) triggering periderm development and cold acclimation initiation in autumn. ||Cultivars originating from higher latitudes (Riesling, 49°N origin) show stronger photoperiod response for dormancy induction than cultivars from lower latitudes (Grenache, 42°N origin), initiating acclimation 2-3 weeks earlier under equivalent day length conditions. ||Photoperiod interacts with temperature for budbreak timing, with some cultivars showing delayed budbreak under artificially extended photoperiods. ||Tropical viticulture exploits weak photoperiod response in some cultivars to enable continuous growth cycles.",
    "editor_note": "Photoperiod response in grapevine is generally weaker than in many woody perennials, with temperature being the dominant driver of most phenological events. ||However, photoperiod sensitivity contributes to latitudinal adaptation patterns, with cultivars from northern origins showing stronger responses that prevent premature deacclimation during warm winter periods at high latitudes. ||The VvCO and VvFT genes mediate photoperiod signaling in grapevine, with expression patterns correlating with dormancy transitions. ||Understanding photoperiod response becomes increasingly important for predicting cultivar performance when transferred across latitudes.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A, Hoover E (1991) Photoperiod influences growth, bud dormancy, and cold acclimation in Vitis labruscana and V. riparia. Journal of the American Society for Horticultural Science 116:270-273|| Grant TNL et al. (2013) Biological processes of cold acclimation concomitant with dormancy release in grape (Vitis vinifera). Canadian Journal of Plant Science 93:1051-1068"
  },
  "Nutrient_Acquisition_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to absorb, transport, and assimilate mineral nutrients from the soil solution through root system activity, encompassing traits related to uptake efficiency, ion selectivity, and the ability to access nutrients under varying soil conditions and availability levels.",
    "alternative_term": "nutrient uptake capacity | mineral acquisition trait | nutrient foraging disposition |+ Nährstoffaufnahme | Mineralstoffakquisition | Nährstoffaneignungsvermögen",
    "example_of_usage": "Nutrient acquisition efficiency varies substantially among rootstocks, with 1103 Paulsen showing 40-60% higher phosphorus uptake than 101-14 Mgt under identical soil conditions. ||Total seasonal nutrient removal by grapevines ranges from 30-80 kg N/ha, 5-15 kg P/ha, and 40-100 kg K/ha depending on yield level and cultivar. ||Root system architecture strongly influences acquisition, with deep-rooted rootstocks accessing subsoil nutrients unavailable to shallow-rooted types. ||The rhizosphere pH modification capacity varies 0.5-1.5 pH units among genotypes, affecting micronutrient availability.",
    "editor_note": "Nutrient_Acquisition_Disposition serves as the top-level parent class for all traits related to mineral nutrition uptake. ||The category encompasses both macronutrient and micronutrient acquisition, as well as mycorrhizal associations that enhance nutrient access. ||Rootstock genotype exerts primary control over nutrient acquisition in grafted vines, though scion genotype influences demand patterns and sink strength. ||The trait complex is critical for sustainable viticulture, enabling reduced fertilizer inputs through selection of efficient genotypes.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 295-345|| Keller M et al. (2001) Rootstock effects on deficit-irrigated winegrapes in a dry climate: vigor, yield formation, and fruit ripening. American Journal of Enology and Viticulture 52:40-49"
  },
  "Macronutrient_Uptake_Disposition": {
    "definition": "A nutrient acquisition disposition that is the inherited capacity of a Vitis vinifera plant to absorb and accumulate the primary mineral nutrients required in large quantities (nitrogen, phosphorus, potassium, calcium, magnesium, and sulfur) through coordinated root transporter activity and root system exploration of the soil volume.",
    "alternative_term": "primary nutrient uptake | major element acquisition | macronutrient foraging capacity |+ Makronährstoffaufnahme | Hauptnährstoffakquisition | Makroelement-Aneignung",
    "example_of_usage": "Macronutrient uptake follows characteristic seasonal patterns, with nitrogen uptake peaking during rapid shoot growth (bloom to veraison) and potassium uptake continuing strongly through ripening for berry loading. ||Total vine macronutrient content at harvest in a mature vineyard (10 t/ha yield) approximates 100-150 kg N, 15-25 kg P, 120-180 kg K, 80-120 kg Ca, and 15-25 kg Mg per hectare in above-ground biomass. ||Rootstock influence on macronutrient uptake ranges from minimal (calcium) to substantial (potassium), with 140 Ruggeri conferring 30-50% higher K accumulation than SO4 on the same scion.",
    "editor_note": "Macronutrient_Uptake_Disposition serves as the parent class for individual macronutrient uptake traits. ||The category addresses nutrients required at concentrations above 0.1% of dry matter, distinguishing them from micronutrients required at trace levels. ||Macronutrient balance affects vine physiology, fruit composition, and wine quality, with deficiencies causing visible symptoms and yield reduction while excesses may impair fruit quality or vine health.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Conradie WJ (1981) Seasonal uptake of nutrients by Chenin blanc in sand culture: II. Phosphorus, potassium, calcium and magnesium. South African Journal of Enology and Viticulture 2:7-13|| Schreiner RP (2016) Nutrient uptake and distribution in young Pinot noir grapevines over two seasons. American Journal of Enology and Viticulture 67:436-448"
  },
  "Nitrogen_Uptake_Efficiency_Disposition": {
    "definition": "A macronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb nitrogen from the soil solution in various chemical forms (nitrate, ammonium, amino acids) through root transporter systems, with genotype-specific efficiency determining nitrogen acquisition per unit root length or root biomass under given soil nitrogen availability.",
    "alternative_term": "nitrogen acquisition efficiency | N uptake capacity | nitrogen foraging trait |+ Stickstoffaufnahme-Effizienz | N-Akquisitionseffizienz | Stickstoffaneignungsvermögen",
    "example_of_usage": "Nitrogen uptake efficiency varies 2-3 fold among rootstock genotypes, with Fercal showing high efficiency (45-60 mg N/m root length/day) compared to 101-14 Mgt (20-35 mg N/m/day) under identical nitrogen supply. ||Total seasonal nitrogen uptake ranges from 25-50 kg N/ha in low-vigor systems to 80-120 kg N/ha in high-vigor irrigated vineyards. ||Uptake timing shows two peaks in most cultivars, during rapid spring shoot growth and again post-harvest during root flush. ||VvNRT1 and VvNRT2 gene family members encode high-affinity and low-affinity nitrate transporters with rootstock-specific expression patterns.",
    "editor_note": "Nitrogen_Uptake_Efficiency_Disposition serves as the parent class for nitrate and ammonium uptake subcategories. ||Nitrogen is typically the most limiting macronutrient in vineyard soils and exerts the strongest influence on vine vigor and fruit composition. ||Excessive nitrogen uptake promotes vegetative growth at the expense of fruit quality, while deficiency reduces yield and photosynthetic capacity. ||Rootstock selection for appropriate nitrogen uptake efficiency enables vigor management without excessive fertilizer inputs.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tomasi N et al. (2015) New aspects of grapevine response to nitrogen nutrition. Plant Signaling and Behavior 10:e1032953|| Zerihun A, Treeby MT (2002) Biomass distribution and nitrate assimilation in response to N supply for Vitis vinifera L. cv. Cabernet Sauvignon on five Vitis rootstock genotypes. Australian Journal of Grape and Wine Research 8:157-162"
  },
  "Nitrate_Uptake_Disposition": {
    "definition": "A nitrogen uptake efficiency disposition that is the inherited capacity of a Vitis vinifera plant to absorb nitrate ions (NO₃⁻) from the soil solution through high-affinity and low-affinity nitrate transporter systems, representing the dominant nitrogen acquisition pathway in well-aerated vineyard soils.",
    "alternative_term": "nitrate acquisition | NO3 uptake capacity | nitrate transporter activity |+ Nitrataufnahme | NO₃⁻-Akquisition | Nitrattransporter-Aktivität",
    "example_of_usage": "Nitrate uptake accounts for 70-90% of total nitrogen acquisition in most vineyard soils due to rapid nitrification of ammonium under aerobic conditions. ||High-affinity nitrate transport (HATS, Km 10-100 µM) dominates at soil nitrate concentrations below 0.5 mM, while low-affinity transport (LATS, Km 1-5 mM) contributes at higher concentrations. ||Rootstock 110 Richter shows 40% higher nitrate uptake capacity than 3309C under low nitrogen availability (0.1 mM NO₃⁻), attributable to elevated VvNRT2.1 expression. ||Nitrate reductase activity in roots and leaves converts absorbed nitrate to ammonium for amino acid synthesis, with cultivar-specific partitioning between root and shoot reduction.",
    "editor_note": "Nitrate uptake dominates grapevine nitrogen acquisition except in waterlogged or highly acidic soils where nitrification is impaired. ||The dual transporter system (HATS and LATS) enables efficient uptake across the wide range of soil nitrate concentrations encountered in vineyards. ||Nitrate also serves as a signaling molecule influencing root architecture and gene expression beyond its nutritional role. ||Cover crop management and organic matter inputs modulate soil nitrate availability, interacting with genotypic uptake capacity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pii Y et al. (2014) The interaction between iron nutrition, plant species and soil type shapes the rhizosphere microbiome. Plant Physiology and Biochemistry 99:158-166|| Lecourt J et al. (2015) The nitrogen status of grapevine (Vitis vinifera) rootstocks affects root-shoot signaling. Functional Plant Biology 42:1038-1048"
  },
  "Ammonium_Uptake_Disposition": {
    "definition": "A nitrogen uptake efficiency disposition that is the inherited capacity of a Vitis vinifera plant to absorb ammonium ions (NH₄⁺) from the soil solution through ammonium transporter (AMT) family proteins, providing a direct nitrogen source requiring no reduction before amino acid synthesis.",
    "alternative_term": "ammonium acquisition | NH4 uptake capacity | ammonium transporter activity |+ Ammoniumaufnahme | NH₄⁺-Akquisition | Ammoniumtransporter-Aktivität",
    "example_of_usage": "Ammonium uptake typically accounts for 10-30% of total nitrogen acquisition in aerated vineyard soils, increasing to 40-60% under waterlogged or acidic conditions where nitrification is inhibited. ||Grapevine roots show preference for ammonium over nitrate when both forms are equally available, with ammonium uptake rates 20-40% higher at equivalent nitrogen concentrations. ||VvAMT1 and VvAMT2 genes encode ammonium transporters with differential expression in root tips versus mature root zones. ||Excessive ammonium uptake (NH₄⁺:NO₃⁻ ratio above 3:1) can induce toxicity symptoms including root browning and reduced growth, particularly under low potassium availability.",
    "editor_note": "Ammonium uptake provides energetic advantages over nitrate acquisition by eliminating the reduction step required for nitrate assimilation, potentially improving nitrogen use efficiency under energy-limited conditions. ||However, ammonium toxicity risk and the transient nature of soil ammonium pools limit its contribution in most vineyard systems. ||Rootstock genotypes differ in ammonium tolerance, with some showing growth inhibition at concentrations that others tolerate. ||Fertigation with ammonium-containing fertilizers can exploit genotypic differences in ammonium uptake capacity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lang CP et al. (2020) Different nitrogen sources affect grapevine root morphology and arbuscular mycorrhizal colonization. Vitis 59:79-85|| Gessler A et al. (1998) Field and laboratory experiments on net uptake of nitrate and ammonium by the roots of spruce (Picea abies) and beech (Fagus sylvatica) trees. New Phytologist 138:275-285"
  },
  "Phosphorus_Uptake_Efficiency_Disposition": {
    "definition": "A macronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb phosphate ions (H₂PO₄⁻, HPO₄²⁻) from the soil solution through phosphate transporter systems and mycorrhizal associations, with genotype-specific efficiency determining phosphorus acquisition under often limiting soil availability conditions.",
    "alternative_term": "phosphorus acquisition efficiency | P uptake capacity | phosphate foraging trait |+ Phosphoraufnahme-Effizienz | P-Akquisitionseffizienz | Phosphataneignungsvermögen",
    "example_of_usage": "Phosphorus uptake efficiency varies 3-4 fold among rootstocks, with 1103 Paulsen and 140 Ruggeri showing high efficiency (0.8-1.2 mg P/m root length/day) compared to 3309C and 101-14 Mgt (0.3-0.5 mg P/m/day). ||Arbuscular mycorrhizal colonization enhances P uptake by 30-80% through hyphal exploration of soil volumes inaccessible to roots. ||Total vine phosphorus content at harvest ranges from 12-25 kg P/ha, with approximately 40-50% removed in fruit. ||Phosphorus deficiency causes reduced shoot growth, anthocyanin accumulation in leaves, and poor fruit set, with symptoms appearing when petiole P falls below 0.12% dry weight at bloom.",
    "editor_note": "Phosphorus availability in vineyard soils is often limited by fixation to iron and aluminum oxides (acidic soils) or calcium compounds (calcareous soils), making uptake efficiency a critical adaptation. ||Rootstock selection for high P uptake efficiency can reduce fertilizer requirements and improve vine performance on low-P soils. ||Root architectural traits including fine root density and root hair development correlate with P uptake efficiency. ||VvPHT1 gene family members encode phosphate transporters with expression responsive to P availability.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schreiner RP (2005) Mycorrhizae and mineral acquisition in grapevines. In: Christensen LP, Smart DR (eds) Proceedings of the Soil Environment and Vine Mineral Nutrition Symposium, ASEV pp.: 49-60|| Grant RS, Matthews MA (1996) The influence of phosphorus availability and rootstock on root system characteristics, phosphorus uptake, phosphorus partitioning, and growth efficiency. American Journal of Enology and Viticulture 47:403-409"
  },
  "Potassium_Uptake_Efficiency_Disposition": {
    "definition": "A macronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb potassium ions (K⁺) from the soil solution through potassium channel and transporter proteins, with genotype-specific efficiency determining potassium acquisition to meet the high demand of this most abundant cation in grapevine tissues.",
    "alternative_term": "potassium acquisition efficiency | K uptake capacity | potassium foraging trait |+ Kaliumaufnahme-Effizienz | K-Akquisitionseffizienz | Kaliumaneignungsvermögen",
    "example_of_usage": "Potassium uptake efficiency shows pronounced rootstock effects, with 140 Ruggeri conferring 50-80% higher K accumulation than 101-14 Mgt on the same scion variety. ||Total seasonal K uptake ranges from 60-150 kg K/ha depending on yield and vine size, with approximately 50-70% removed in fruit at harvest. ||Potassium uptake continues strongly post-veraison during berry loading, when 40-60% of total fruit K accumulates. ||High-affinity K transport (VvHAK/KUP family) dominates at soil K below 0.2 mM, while voltage-gated channels (VvAKT1) contribute at higher concentrations.",
    "editor_note": "Potassium_Uptake_Efficiency_Disposition serves as the parent class for potassium accumulation traits. ||Potassium is required in the largest quantities of any cation, functioning in osmotic regulation, enzyme activation, phloem transport, and must/wine pH buffering. ||Excessive K uptake, particularly from high-K rootstocks, can elevate juice pH and reduce wine quality in red cultivars. ||Rootstock selection for moderate K uptake efficiency is often preferred over maximum uptake capacity to optimize fruit composition.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mpelasoka BS et al. (2003) A review of potassium nutrition in grapevines with special emphasis on berry accumulation. Australian Journal of Grape and Wine Research 9:154-168|| Kodur S (2011) Effects of juice pH and potassium on juice and wine quality, and regulation of potassium in grapevines through rootstocks. PhD Thesis, University of Adelaide"
  },
  "Potassium_Accumulation_Disposition": {
    "definition": "A potassium uptake efficiency disposition that is the inherited capacity of a Vitis vinifera plant to accumulate potassium in specific tissues, particularly berries, with genotype-specific partitioning patterns determining the distribution of absorbed K between vegetative structures and fruit and affecting must potassium concentration and pH.",
    "alternative_term": "K partitioning trait | berry potassium loading | potassium distribution disposition |+ Kaliumakkumulation | K-Verteilung | Kaliumeinlagerung",
    "example_of_usage": "Berry potassium concentration at harvest ranges from 1,500-4,000 mg/L juice across scion-rootstock combinations, with high-K rootstocks such as 140 Ruggeri and Ramsey conferring 30-50% higher fruit K than low-K rootstocks such as 101-14 Mgt and Riparia Gloire. ||Must pH correlates positively with K concentration (r = 0.65-0.80), with each 500 mg/L increase in K associated with approximately 0.15-0.20 pH units higher must pH. ||Potassium loading into berries occurs primarily via phloem transport during ripening, with VvK5.1 and VvKT2 channels mediating K influx into berry cells. ||Shiraz shows inherently high K accumulation disposition regardless of rootstock, while Cabernet Sauvignon shows greater rootstock-mediated variation.",
    "editor_note": "Potassium accumulation disposition has major implications for wine quality, as elevated juice K reduces titratable acidity through tartrate precipitation and increases pH, which can impair color stability, microbial stability, and sensory balance in red wines. ||Climate warming is exacerbating K accumulation through increased berry dehydration and concentration effects. ||Rootstock selection for low K accumulation is a primary management tool in warm climate viticulture where high pH is problematic. ||The trait shows complex genetic control with multiple QTLs identified in both rootstock and scion genomes.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Walker RR, Blackmore DH (2012) Potassium concentration and pH inter-relationships in grape juice and wine of Chardonnay and Shiraz from a range of rootstocks in different environments. Australian Journal of Grape and Wine Research 18:183-193|| Rogiers SY et al. (2006) Mineral sinks within ripening grape berries (Vitis vinifera L.). Vitis 45:115-123"
  },
  "Calcium_Uptake_Disposition": {
    "definition": "A macronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb calcium ions (Ca²⁺) from the soil solution through calcium channels and transporters, with uptake driven by transpiration stream transport and genotype-specific root membrane permeability.",
    "alternative_term": "calcium acquisition | Ca uptake capacity | calcium foraging trait |+ Calciumaufnahme | Ca-Akquisition | Calciumaneignungsvermögen",
    "example_of_usage": "Calcium uptake in grapevines ranges from 40-100 kg Ca/ha annually depending on soil availability and vine size, with relatively modest rootstock effects (15-30% variation) compared to potassium. ||Calcium moves primarily in the xylem with the transpiration stream, resulting in preferential accumulation in transpiring leaves (2-4% Ca dry weight) versus low-transpiring berries (0.02-0.05% juice). ||Petiole calcium concentration at bloom of 1.2-2.5% dry weight indicates adequate supply, with deficiency symptoms (marginal leaf necrosis) appearing below 0.8%. ||Calcicole rootstocks such as 41B and Fercal maintain Ca uptake efficiency on high-lime soils where calcifuge rootstocks show reduced absorption due to pH-impaired root function.",
    "editor_note": "Calcium uptake is less dependent on genotype than potassium uptake due to the predominantly passive nature of Ca transport in the transpiration stream. ||However, rootstock effects on root system health in calcareous soils indirectly affect Ca acquisition through overall root function. ||Calcium is immobile in phloem, making continuous uptake essential for developing tissues. ||Cell wall structural roles and signaling functions require adequate Ca supply throughout the growing season.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Conradie WJ (1981) Seasonal uptake of nutrients by Chenin blanc in sand culture: II. Phosphorus, potassium, calcium and magnesium. South African Journal of Enology and Viticulture 2:7-13|| White PJ, Broadley MR (2003) Calcium in plants. Annals of Botany 92:487-511"
  },
  "Magnesium_Uptake_Disposition": {
    "definition": "A macronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb magnesium ions (Mg²⁺) from the soil solution through magnesium transporter proteins, with genotype-specific uptake efficiency affecting chlorophyll synthesis, enzyme activation, and carbohydrate partitioning.",
    "alternative_term": "magnesium acquisition | Mg uptake capacity | magnesium foraging trait |+ Magnesiumaufnahme | Mg-Akquisition | Magnesiumaneignungsvermögen",
    "example_of_usage": "Magnesium uptake ranges from 10-30 kg Mg/ha annually, with rootstock effects of 20-40% variation under identical soil conditions. ||SO4 and 5BB Kober show high Mg uptake efficiency, while 41B and 140 Ruggeri demonstrate lower Mg acquisition. ||Magnesium deficiency symptoms (interveinal chlorosis of older leaves) appear when petiole Mg falls below 0.25% dry weight at veraison, with severe deficiency causing premature defoliation. ||Potassium-magnesium antagonism is pronounced in grapevines, with high K availability suppressing Mg uptake by 30-50% through competitive inhibition at root membrane transporters. ||Berry Mg concentration of 50-100 mg/L is typical, contributing to wine buffering capacity.",
    "editor_note": "Magnesium uptake shows intermediate rootstock influence, weaker than potassium but stronger than calcium. ||The K-Mg antagonism is particularly important in vineyard nutrition, as heavy K fertilization can induce Mg deficiency even on Mg-adequate soils. ||Rootstocks with high Mg uptake efficiency partially compensate for high K availability. ||Magnesium's role in chlorophyll structure (central atom of the porphyrin ring) makes adequate uptake essential for photosynthetic capacity and therefore sugar production.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Conradie WJ (1981) Seasonal uptake of nutrients by Chenin blanc in sand culture: II. Phosphorus, potassium, calcium and magnesium. South African Journal of Enology and Viticulture 2:7-13|| Etchebarne F et al. (2009) Leaf senescence in wine grape: effects of potassium deficiency. Functional Plant Biology 36:356-367"
  },
  "Micronutrient_Uptake_Disposition": {
    "definition": "A nutrient acquisition disposition that is the inherited capacity of a Vitis vinifera plant to absorb and accumulate essential trace elements (iron, zinc, manganese, boron, copper, molybdenum, chlorine, nickel) required in small quantities for specific enzymatic and structural functions, through specialized root transporter systems operating under typically low soil solution concentrations.",
    "alternative_term": "trace element uptake | minor element acquisition | micronutrient foraging capacity |+ Mikronährstoffaufnahme | Spurenelementakquisition | Mikroelement-Aneignung",
    "example_of_usage": "Micronutrient uptake requirements are orders of magnitude lower than macronutrients, with annual vine demand of 200-800 g Fe/ha, 100-400 g Zn/ha, 200-600 g Mn/ha, and 100-300 g B/ha for a mature vineyard. ||Rootstock effects on micronutrient uptake are pronounced for iron (3-5× variation) and zinc (2-3× variation) but modest for manganese and boron. ||Soil pH strongly modulates micronutrient availability, with Fe, Zn, Mn, and B becoming less available above pH 7.5, creating deficiency challenges on calcareous soils. ||Micronutrient deficiency symptoms appear at leaf concentrations below critical thresholds specific to each element and growth stage.",
    "editor_note": "Micronutrient_Uptake_Disposition serves as the parent class for individual trace element uptake traits. ||Despite low quantitative requirements, micronutrient deficiencies cause severe physiological disruption due to essential roles in enzyme function, electron transport, and structural components. ||Rootstock selection is the primary tool for managing micronutrient acquisition on problem soils, with genotypes showing wide variation in uptake efficiency. ||Chelate chemistry, soil pH management, and foliar application provide supplementary management options.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 325-345|| Robinson JB (1992) Grapevine nutrition. In: Coombe BG, Dry PR (eds) Viticulture Volume 2: Practices, Winetitles pp.: 178-208"
  },
  "Iron_Acquisition_Efficiency_Disposition": {
    "definition": "A micronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to acquire iron from the soil solution through Strategy I mechanisms (rhizosphere acidification, ferric reduction, ferrous uptake), with genotype-specific efficiency determining iron nutrition status across varying soil pH and carbonate conditions.",
    "alternative_term": "iron uptake efficiency | Fe acquisition capacity | iron foraging trait |+ Eisenaufnahme-Effizienz | Fe-Akquisitionseffizienz | Eisenaneignungsvermögen",
    "example_of_usage": "Iron acquisition efficiency varies 3-5 fold among rootstocks, with Fercal and 41B showing high efficiency (maintaining leaf Fe above 80 ppm on calcareous soils) compared to Riparia Gloire and 3309C (leaf Fe declining to 40-60 ppm). ||The Strategy I response involves coordinated expression of VvHA (H⁺-ATPase for acidification), VvFRO (ferric reductase), and VvIRT1 (iron-regulated transporter). ||Iron deficiency chlorosis develops when active leaf Fe falls below 50-60 ppm despite potentially adequate total Fe (the chlorosis paradox). ||Fe-efficient rootstocks reduce rhizosphere pH by 0.8-1.5 units compared to 0.2-0.4 units in Fe-inefficient types under bicarbonate stress.",
    "editor_note": "Iron acquisition efficiency is critical for vineyard performance on calcareous soils representing approximately 30% of global vineyard area. ||The trait encompasses both constitutive uptake capacity and inducible responses to Fe limitation. ||Unlike the Lime_Tolerance context focusing on chlorosis resistance, this disposition addresses the general Fe acquisition mechanism across soil types. ||Rootstock breeding has successfully combined high Fe efficiency with other desirable traits, with modern selections such as Fercal and 140 Ruggeri enabling viticulture on high-lime soils.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Brancadoro L et al. (1995) Mechanisms of Fe-efficiency in roots of Vitis spp. in response to iron deficiency stress. Plant and Soil 171:229-234|| Jiménez S et al. (2007) Phosphoenolpyruvate carboxylase (PEPC) and dark respiration in the Fe-deficient grapevine (Vitis vinifera L.) rootstock 140 Ruggeri. Journal of Plant Physiology 164:1527-1535"
  },
  "Zinc_Uptake_Disposition": {
    "definition": "A micronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb zinc ions (Zn²⁺) from the soil solution through ZIP family transporters, with genotype-specific efficiency affecting zinc-dependent enzyme function, auxin metabolism, and reproductive development.",
    "alternative_term": "zinc acquisition | Zn uptake capacity | zinc foraging trait |+ Zinkaufnahme | Zn-Akquisition | Zinkaneignungsvermögen",
    "example_of_usage": "Zinc uptake efficiency varies 2-3 fold among rootstocks, with 1103 Paulsen and 110 Richter showing high efficiency (maintaining petiole Zn above 30 ppm) compared to 101-14 Mgt and SO4 (petiole Zn 15-25 ppm) under identical low-Zn soil conditions. ||Zinc deficiency symptoms include shortened internodes (little leaf), mottled interveinal chlorosis, and poor fruit set with millerandage, appearing when petiole Zn falls below 15-20 ppm at bloom. ||VvZIP family members encode zinc transporters with root expression increasing 3-5 fold under Zn limitation. ||Zinc availability declines sharply above soil pH 7.0, with uptake reduced by 50-70% between pH 6.5 and 8.0 under equivalent total soil Zn.",
    "editor_note": "Zinc deficiency is among the most common micronutrient disorders in viticulture, affecting both vegetative growth and reproductive success. ||The characteristic little leaf symptom results from impaired auxin synthesis (Zn is required for tryptophan-dependent IAA biosynthesis). ||Zinc uptake efficiency is particularly important on high-pH soils and in high-phosphorus conditions that inhibit Zn absorption. ||Foliar Zn application before bloom effectively supplements root uptake for reproductive development.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Christensen LP (1980) Timing of zinc foliar sprays: II. Effects on size, sweetness, and bunch rot of Thompson Seedless grapes. American Journal of Enology and Viticulture 31:256-260|| Sinclair AH, Edwards AC (2008) Micronutrient deficiency problems in agricultural crops in Europe. In: Alloway BJ (ed) Micronutrient Deficiencies in Global Crop Production, Springer pp.: 225-244"
  },
  "Manganese_Uptake_Disposition": {
    "definition": "A micronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb manganese ions (Mn²⁺) from the soil solution through NRAMP family transporters, with genotype-specific efficiency affecting photosynthetic oxygen evolution, enzyme activation, and antioxidant capacity.",
    "alternative_term": "manganese acquisition | Mn uptake capacity | manganese foraging trait |+ Manganaufnahme | Mn-Akquisition | Mangananeignungsvermögen",
    "example_of_usage": "Manganese uptake shows moderate rootstock variation (1.5-2× range), with SO4 and 5BB Kober demonstrating higher Mn accumulation than 41B and 140 Ruggeri under equivalent soil conditions. ||Manganese deficiency symptoms (interveinal chlorosis of young leaves with green veins, distinct from Mg deficiency in older leaves) appear when petiole Mn falls below 20-25 ppm. ||Adequate petiole Mn ranges from 30-150 ppm, with toxicity symptoms (brown spotting, marginal necrosis) appearing above 500 ppm in acidic, waterlogged soils. ||The Mn²⁺/Mn⁴⁺ redox couple is highly pH-dependent, with Mn availability increasing 100-fold between pH 7.5 and 5.5, creating toxicity risk on acidic soils and deficiency on calcareous soils.",
    "editor_note": "Manganese uptake efficiency is less critical for rootstock selection than iron or zinc due to adequate Mn availability in most vineyard soils. ||However, Mn toxicity on acidic soils and Mn deficiency on high-pH soils create localized problems requiring attention. ||Manganese functions in the oxygen-evolving complex of photosystem II, making it essential for photosynthetic electron transport. ||The element also activates numerous enzymes and contributes to antioxidant defense through Mn-superoxide dismutase.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pearson RC, Goheen AC (1988) Compendium of Grape Diseases, APS Press pp.: 89-92|| Millaleo R et al. (2010) Manganese as essential and toxic element for plants: transport, accumulation and resistance mechanisms. Journal of Soil Science and Plant Nutrition 10:470-481"
  },
  "Boron_Uptake_Disposition": {
    "definition": "A micronutrient uptake disposition that is the inherited capacity of a Vitis vinifera plant to absorb boric acid (H₃BO₃) and borate ions from the soil solution through aquaporin-type channels (NIP subfamily) and borate transporters (BOR family), with genotype-specific efficiency affecting cell wall structure, pollen development, and sugar translocation.",
    "alternative_term": "boron acquisition | B uptake capacity | boron foraging trait |+ Boraufnahme | B-Akquisition | Boraneignungsvermögen",
    "example_of_usage": "Boron uptake efficiency varies 2-3 fold among rootstocks, with 1103 Paulsen and 140 Ruggeri showing high efficiency (maintaining petiole B above 35 ppm) compared to 3309C and Riparia Gloire (petiole B 20-30 ppm) on low-B soils. ||Boron deficiency severely impairs reproductive development, reducing pollen germination by 40-70% and fruit set by 30-60% when petiole B falls below 25 ppm at bloom. ||Symptoms include shortened internodes, distorted leaves, cluster necrosis (hen and chickens from failed pollination), and surface corking on berries. ||Boron mobility in phloem is limited, requiring continuous uptake for developing tissues. ||The narrow range between deficiency (<25 ppm) and toxicity (>80 ppm) makes B nutrition management challenging in some regions.",
    "editor_note": "Boron uptake disposition is critical for reproductive success due to the essential role of B in pollen tube growth and ovule development. ||The element cross-links cell wall pectin through borate-diol ester bonds, affecting wall structure and extensibility. ||Boron deficiency is widespread in sandy, leached soils and in regions with low-B irrigation water. ||Unlike most micronutrients, B uptake occurs primarily as undissociated boric acid at typical soil pH values, through aquaporin channels rather than ion transporters. ||Foliar B application before bloom effectively prevents deficiency-induced coulure and millerandage.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M et al. (2015) Boron nutrition of grapevines. Acta Horticulturae 1115:79-84|| Scott LE (1941) Effects of boron nutrition on grapevines. Botanical Gazette 102:726-736"
  },
  "Nutrient_Use_Efficiency_Disposition": {
    "definition": "A nutrient acquisition disposition that is the inherited capacity of a Vitis vinifera plant to produce biomass or yield per unit of nutrient absorbed, integrating uptake efficiency with internal utilization efficiency to determine overall productivity relative to nutrient input or availability.",
    "alternative_term": "nutrient efficiency trait | resource use efficiency | nutrient productivity disposition |+ Nährstoffnutzungseffizienz | Nährstoffverwertung | Ressourceneffizienz",
    "example_of_usage": "Nutrient use efficiency varies 2-3 fold among scion-rootstock combinations, with efficient combinations producing 150-200 kg fruit per kg N absorbed compared to 80-120 kg fruit/kg N in inefficient combinations. ||NUE comprises uptake efficiency (nutrient acquired per unit root) and utilization efficiency (biomass produced per unit nutrient in plant). ||High NUE genotypes maintain yield under reduced fertilizer inputs, with efficient Chardonnay clones producing equivalent yields at 60% of standard nitrogen rates. ||The NUE concept extends to all nutrients but is most commonly applied to nitrogen due to its dominant influence on vine growth and environmental concerns regarding N losses.",
    "editor_note": "Nutrient_Use_Efficiency_Disposition serves as the parent class for element-specific use efficiency traits. ||The concept originated in agronomic research addressing fertilizer efficiency and environmental sustainability. ||In viticulture, high NUE enables reduced input costs, lower environmental impact from nutrient runoff, and potentially improved fruit quality through moderate vigor. ||Both genetic (rootstock, scion) and management (irrigation, cover crops) factors influence NUE expression.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Moll RH et al. (1982) Analysis and interpretation of factors which contribute to efficiency of nitrogen utilization. Agronomy Journal 74:562-564|| Keller M et al. (2001) Reproductive growth of grapevines in response to nitrogen supply and rootstock. Australian Journal of Grape and Wine Research 7:12-18"
  },
  "Nitrogen_Use_Efficiency_Disposition": {
    "definition": "A nutrient use efficiency disposition that is the inherited capacity of a Vitis vinifera plant to produce biomass, yield, or quality outcomes per unit of nitrogen absorbed or available, determined by the combined efficiency of nitrogen uptake from soil, internal assimilation into organic compounds, remobilization between tissues, and allocation to productive versus vegetative growth.",
    "alternative_term": "nitrogen efficiency | N productivity | nitrogen utilization trait |+ Stickstoffnutzungseffizienz | N-Verwertungseffizienz | Stickstoffproduktivität",
    "example_of_usage": "Nitrogen use efficiency in grapevines ranges from 40-80 kg fruit per kg N in whole-vine content, with substantial rootstock and scion effects. ||Low-vigor rootstocks such as Riparia Gloire and 101-14 Mgt confer higher NUE (65-80 kg fruit/kg N) than high-vigor rootstocks such as 1103 Paulsen and 140 Ruggeri (45-60 kg fruit/kg N) by limiting vegetative N sinks. ||Internal NUE involves nitrogen remobilization from senescing leaves (recovering 60-75% of leaf N) and redistribution from storage pools in spring (contributing 30-50% of early-season N demand). ||High-NUE vines maintain adequate yield quality index (YAN above 150 mg N/L must) with 30-50% reduced N fertilizer application.",
    "editor_note": "Nitrogen use efficiency is the most studied nutrient efficiency parameter in viticulture due to nitrogen's dominant role in vine vigor, fruit composition, and environmental impact. ||The trait decomposes into uptake efficiency (N acquired per unit root investment) and utilization efficiency (fruit produced per unit N in vine). ||High NUE may conflict with wine quality objectives if must nitrogen (YAN) falls below fermentation requirements. ||Optimizing NUE requires balancing vegetative and reproductive N allocation rather than simply minimizing total N uptake.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Treeby MT et al. (2000) Irrigation management and rootstock effects on navel orange (Citrus sinensis L. Osbeck) fruit quality. Agricultural Water Management 46:1-17|| Verdenal T et al. (2021) Nitrogen management in the vineyard and its relationships with grape and wine quality. OENO One 55:1-32"
  },
  "Phosphorus_Use_Efficiency_Disposition": {
    "definition": "A nutrient use efficiency disposition that is the inherited capacity of a Vitis vinifera plant to produce biomass, yield, or quality outcomes per unit of phosphorus absorbed or available, determined by the combined efficiency of phosphorus uptake from soil, internal phosphate metabolism, and allocation to productive functions versus storage pools.",
    "alternative_term": "phosphorus efficiency | P productivity | phosphorus utilization trait |+ Phosphornutzungseffizienz | P-Verwertungseffizienz | Phosphorproduktivität",
    "example_of_usage": "Phosphorus use efficiency in grapevines ranges from 400-900 kg fruit per kg P in whole-vine content, reflecting the relatively low P requirement compared to nitrogen and potassium. ||High-PUE rootstocks including 1103 Paulsen and 110 Richter maintain adequate vine P status (petiole P above 0.15% at bloom) with 40-60% lower soil P availability than low-PUE rootstocks such as 3309C. ||Mycorrhizal colonization enhances PUE by 25-50% through improved P acquisition efficiency, with colonized vines showing higher P uptake per unit root length. ||Internal P recycling during senescence recovers 70-85% of leaf P for redistribution to perennial tissues, contributing to following-season P supply.",
    "editor_note": "Phosphorus use efficiency is particularly important in viticulture because P availability is often limited by soil fixation, and P fertilizer resources are finite globally. ||The trait encompasses both acquisition efficiency (including mycorrhizal contributions) and utilization efficiency (metabolic and allocation components). ||High-PUE genotypes show enhanced acid phosphatase activity, improved internal P recycling, and optimized P allocation between storage (vacuolar polyphosphate) and metabolically active pools. ||Root architectural traits including fine root proliferation and root hair density correlate with P acquisition efficiency.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schreiner RP (2005) Mycorrhizae and mineral acquisition in grapevines. In: Christensen LP, Smart DR (eds) Proceedings of the Soil Environment and Vine Mineral Nutrition Symposium, ASEV pp.: 49-60|| Grant RS, Matthews MA (1996) The influence of phosphorus availability and rootstock on root system characteristics, phosphorus uptake, phosphorus partitioning, and growth efficiency. American Journal of Enology and Viticulture 47:403-409"
  },
  "Mycorrhizal_Association_Disposition": {
    "definition": "A nutrient acquisition disposition that is the inherited capacity of a Vitis vinifera plant to form and maintain mutualistic symbiotic associations with arbuscular mycorrhizal fungi (AMF, phylum Glomeromycota), enabling enhanced nutrient and water acquisition through fungal hyphal networks in exchange for photosynthetically derived carbon compounds.",
    "alternative_term": "mycorrhizal symbiosis capacity | AMF association trait | fungal mutualism disposition |+ Mykorrhiza-Assoziation | AMF-Symbiose | Pilzsymbiose-Disposition",
    "example_of_usage": "Grapevines are obligate mycorrhizal hosts under natural conditions, with root colonization levels ranging from 20-80% depending on genotype, soil conditions, and management practices. ||Mycorrhizal association enhances P uptake by 30-80%, Zn uptake by 20-50%, and drought tolerance through improved water acquisition. ||The hyphal network extends the effective root zone by 10-100 fold, accessing soil volumes and pore spaces unavailable to roots alone. ||Vineyard AMF communities typically include Rhizophagus irregularis, Funneliformis mosseae, and Claroideoglomus species, with diversity correlating positively with vine nutrition and stress tolerance. ||Mycorrhizal benefits are greatest on low-P, low-input soils and diminish under high fertilizer regimes.",
    "editor_note": "Mycorrhizal_Association_Disposition serves as the parent class for colonization and dependency traits. ||The grapevine-AMF symbiosis is ancient and highly co-evolved, with vineyard soils maintaining AMF propagule banks that rapidly colonize establishing roots. ||Modern viticulture practices including fumigation, high P fertilization, and herbicide use can disrupt mycorrhizal function, reducing nutrient acquisition efficiency. ||Interest in mycorrhizal management is increasing as sustainable viticulture emphasizes reduced input agriculture and soil health.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schreiner RP (2007) Effects of native and nonnative arbuscular mycorrhizal fungi on growth and nutrient uptake of Pinot noir (Vitis vinifera L.) in two soils with contrasting levels of phosphorus. Applied Soil Ecology 36:205-215|| Trouvelot S et al. (2015) Arbuscular mycorrhiza symbiosis in viticulture: a review. Agronomy for Sustainable Development 35:1449-1467"
  },
  "Arbuscular_Mycorrhizal_Colonization_Disposition": {
    "definition": "A mycorrhizal association disposition that is the inherited capacity of a Vitis vinifera plant to support arbuscular mycorrhizal fungal colonization within root cortical cells, with genotype-specific colonization levels determined by root exudate signaling, cell wall permeability, and immune system modulation enabling fungal entry and arbuscule formation.",
    "alternative_term": "AMF colonization capacity | root colonization trait | mycorrhizal receptivity |+ AMF-Kolonisierungsvermögen | Mykorrhiza-Besiedlung | Wurzelkolonisations-Disposition",
    "example_of_usage": "Arbuscular mycorrhizal colonization intensity varies from 15-70% of root length colonized across grapevine genotypes under identical soil conditions, with rootstocks showing greater variation than scions. ||High-colonization rootstocks including 1103 Paulsen and SO4 support 50-70% root colonization, while low-colonization types such as 41B and 140 Ruggeri typically show 20-40% colonization. ||Colonization involves sequential stages of spore germination, hyphal branching toward roots (stimulated by strigolactone exudation), appressorium formation, cortical cell penetration, and arbuscule development within 10-21 days post-contact. ||Root colonization peaks during active root growth phases (spring and post-harvest) and declines during summer drought and winter dormancy.",
    "editor_note": "Arbuscular mycorrhizal colonization represents the structural foundation of the mycorrhizal symbiosis, with arbuscules serving as the primary nutrient exchange interface between fungus and plant. ||Colonization level does not always correlate with functional benefit, as colonization quality (arbuscule vitality, hyphal network extent) may be more important than percentage colonization. ||Genotypic differences in colonization reflect variation in strigolactone production, root cortex accessibility, and immune system responses to fungal entry. ||High colonization capacity is generally advantageous but may impose carbon costs under high soil fertility where mycorrhizal benefits are minimal.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schreiner RP (2003) Mycorrhizal colonization of grapevine rootstocks under field conditions. American Journal of Enology and Viticulture 54:143-149|| Nogales A et al. (2019) Response of mycorrhizal grapevine to Armillaria mellea inoculation: disease development and polyamines. Plant and Soil 440:371-385"
  },
  "Mycorrhizal_Dependency_Disposition": {
    "definition": "A mycorrhizal association disposition that is the inherited capacity of a Vitis vinifera plant to require mycorrhizal colonization for adequate growth and nutrient acquisition, with genotype-specific dependency levels determining the magnitude of growth reduction when mycorrhizal associations are absent or impaired.",
    "alternative_term": "AMF dependency | mycorrhizal responsiveness | obligate mycotrophy trait |+ Mykorrhiza-Abhängigkeit | AMF-Dependenz | Pilzsymbiose-Bedürftigkeit",
    "example_of_usage": "Mycorrhizal dependency in grapevines ranges from 30-70% growth reduction in non-mycorrhizal versus mycorrhizal plants under low-P conditions, with high-dependency genotypes showing near-complete growth failure without AMF colonization. ||Rootstock 3309C exhibits high mycorrhizal dependency with 60-70% biomass reduction in non-mycorrhizal treatments, while 1103 Paulsen shows lower dependency (30-40% reduction) due to inherently efficient root P uptake mechanisms. ||Dependency correlates inversely with root hair density (r = -0.65) and fine root proliferation capacity, as genotypes with extensive root surface area partially compensate for absent hyphal networks. ||Under high-P conditions, mycorrhizal dependency approaches zero as direct root uptake satisfies P demand, though benefits for micronutrient acquisition and drought tolerance may persist.",
    "editor_note": "Mycorrhizal dependency quantifies the degree to which a genotype relies on AMF symbiosis for normal function, distinct from colonization capacity which measures the ability to support fungal growth. ||High dependency indicates limited alternative nutrient acquisition strategies and greater vulnerability to mycorrhizal disruption from soil fumigation, high fertilizer inputs, or fungicide applications. ||Understanding rootstock-specific dependency informs management decisions regarding soil health practices, transplant inoculation, and fertilizer strategies. ||Dependency is context-dependent, varying with soil P availability, water status, and the specific AMF species present.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schreiner RP (2007) Effects of native and nonnative arbuscular mycorrhizal fungi on growth and nutrient uptake of Pinot noir (Vitis vinifera L.) in two soils with contrasting levels of phosphorus. Applied Soil Ecology 36:205-215|| Linderman RG, Davis EA (2001) Comparative response of selected grapevine rootstocks and cultivars to inoculation with different mycorrhizal fungi. American Journal of Enology and Viticulture 52:8-11"
  },
  "Water_Relations_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to acquire, transport, and regulate water movement through the soil-plant-atmosphere continuum, encompassing traits related to root water uptake, xylem hydraulic conductance, stomatal regulation, and the maintenance of favorable tissue water status under varying environmental conditions.",
    "alternative_term": "plant water relations trait | hydraulic capacity | water management disposition |+ Wasserhaushalt | Wasserbeziehungen | hydraulische Disposition",
    "example_of_usage": "Water relations parameters vary substantially among grapevine genotypes, with whole-vine hydraulic conductance ranging from 15-45 mmol H₂O/MPa/s across rootstock-scion combinations. ||Daily water flux through a mature vine reaches 20-50 L under high evaporative demand, requiring coordinated hydraulic capacity from roots through stems to leaves. ||Water potential gradients from soil (-0.1 to -1.5 MPa) through roots, stem, and leaves (midday values -0.8 to -1.8 MPa) drive transpirational flow along the resistance pathway. ||Rootstock genotype accounts for 40-60% of variation in scion water status under deficit irrigation, demonstrating strong genetic control of water relations.",
    "editor_note": "Water_Relations_Disposition serves as the top-level parent class for traits governing plant water economy. ||The category encompasses water acquisition (root uptake), long-distance transport (xylem conductance), and loss regulation (stomatal control, addressed separately under drought tolerance). ||Water relations traits critically determine vine productivity, fruit composition, and stress tolerance across the range of vineyard water environments from rain-fed to fully irrigated systems. ||The trait complex shows strong rootstock influence, making rootstock selection a primary tool for water relations management.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 197-245|| Lovisolo C et al. (2010) Grapevine adaptations to water stress: new perspectives about soil/plant interactions. Theoretical and Experimental Plant Physiology 22:1-15"
  },
  "Water_Uptake_Disposition": {
    "definition": "A water relations disposition that is the inherited capacity of a Vitis vinifera plant to absorb water from the soil solution through root system activity, determined by root surface area, root hydraulic conductivity, aquaporin expression, and the ability to maintain uptake across varying soil water potentials and temperatures.",
    "alternative_term": "root water absorption | water acquisition capacity | root uptake trait |+ Wasseraufnahme | Wurzelwasserabsorption | Wasserakquisitions-Disposition",
    "example_of_usage": "Water uptake capacity varies 2-3 fold among rootstocks, with deep-rooted types such as 110 Richter and 140 Ruggeri maintaining uptake from subsoil water sources inaccessible to shallow-rooted types like Riparia Gloire. ||Root water uptake follows a composite transport pathway involving apoplastic flow through cell walls and symplastic flow through membranes regulated by aquaporins. ||Maximum uptake rates of 0.5-1.5 mL H₂O/g root fresh weight/hour occur under high transpirational demand and adequate soil moisture. ||Uptake efficiency (water absorbed per unit root biomass) increases with fine root proportion, with rootstocks showing 20-60% fine root content differing correspondingly in uptake efficiency.",
    "editor_note": "Water_Uptake_Disposition serves as the parent class for root hydraulic conductivity and aquaporin activity traits. ||Water uptake represents the entry point of the soil-plant-atmosphere continuum, integrating soil water availability with root system architecture and membrane transport properties. ||Uptake limitation during soil drying triggers hydraulic and chemical (ABA) signals that coordinate stomatal closure with reduced water availability. ||Rootstock breeding for enhanced water uptake efficiency is a strategy for improving drought tolerance without sacrificing productivity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gambetta GA et al. (2012) Sugars and abscisic acid signaling orthologs are activated at the onset of ripening in grape. Planta 236:851-863|| Lovisolo C, Schubert A (1998) Effects of water stress on vessel size and xylem hydraulic conductivity in Vitis vinifera L. Journal of Experimental Botany 49:693-700"
  },
  "Root_Hydraulic_Conductivity_Disposition": {
    "definition": "A water uptake disposition that is the inherited capacity of a Vitis vinifera plant to conduct water through the root system with genotype-specific hydraulic efficiency, determined by root anatomical features (cortex structure, endodermal suberization, xylem vessel dimensions) and membrane water permeability.",
    "alternative_term": "root hydraulic conductance | root water permeability | Lp root trait |+ Wurzel-Leitfähigkeit | hydraulische Wurzelleitfähigkeit | Wurzelpermeabilität",
    "example_of_usage": "Root hydraulic conductivity (Lp) in grapevines ranges from 1.5-6.0 × 10⁻⁷ m/s/MPa across genotypes, with high-conductivity rootstocks such as 1103 Paulsen and SO4 showing 2-3× greater Lp than low-conductivity types such as 110 Richter and 140 Ruggeri. ||Root Lp shows strong diurnal variation, peaking in early morning (coinciding with maximum aquaporin expression) and declining 40-60% by midday under water stress. ||Temperature sensitivity of root Lp follows Arrhenius kinetics with Q₁₀ values of 2.0-2.5, explaining reduced water uptake at low soil temperatures. ||Suberization of the exodermis and endodermis increases hydraulic resistance, with older root zones showing 50-80% lower Lp than young root tips.",
    "editor_note": "Root hydraulic conductivity integrates anatomical and physiological determinants of root water transport capacity. ||High Lp enables rapid water uptake under transpirational demand but may increase vulnerability to drought through rapid soil water depletion. ||The trait shows plasticity in response to water availability, with drought-stressed roots increasing suberization and reducing Lp as a water-conserving adaptation. ||Rootstock-scion combinations with moderate root Lp often show superior performance under deficit irrigation by balancing uptake capacity with conservative water use.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Vandeleur RK et al. (2009) The role of plasma membrane intrinsic protein aquaporins in water transport through roots: diurnal and drought stress responses reveal different strategies between isohydric and anisohydric cultivars of grapevine. Plant Physiology 149:445-460|| Gambetta GA et al. (2012) Water uptake along the length of grapevine fine roots: developmental anatomy, tissue-specific aquaporin expression, and pathways of water transport. Plant Physiology 158:1492-1504"
  },
  "Aquaporin_Activity_Disposition": {
    "definition": "A water uptake disposition that is the inherited capacity of a Vitis vinifera plant to regulate transmembrane water flux through aquaporin water channel proteins (plasma membrane intrinsic proteins, PIPs|| tonoplast intrinsic proteins, TIPs), with genotype-specific expression levels and gating responses modulating root and leaf hydraulic conductance.",
    "alternative_term": "water channel activity | aquaporin expression trait | membrane water permeability |+ Aquaporin-Aktivität | Wasserkanalexpression | Membranwasserpermeabilität",
    "example_of_usage": "Aquaporin-mediated water flux accounts for 50-80% of root hydraulic conductivity in grapevines, with VvPIP1 and VvPIP2 subfamily members showing differential expression across tissues and environmental conditions. ||VvPIP2||1 expression in roots increases 3-5 fold during early morning, coinciding with peak transpirational demand, and declines 60-80% under drought stress through ABA-mediated transcriptional downregulation. ||Rootstock 110 Richter shows constitutively lower aquaporin expression (40-60% of SO4 levels), contributing to its conservative water use strategy. ||Aquaporin gating through phosphorylation and cytosolic pH changes enables rapid (minutes) adjustment of hydraulic conductance independent of transcriptional regulation.",
    "editor_note": "Aquaporin activity represents the primary regulatory node for membrane water transport, enabling fine-tuned adjustment of hydraulic conductance in response to environmental signals. ||The trait underlies genotypic differences in water use strategy, with isohydric cultivars showing strong aquaporin downregulation under stress versus anisohydric types maintaining expression. ||VvPIP and VvTIP gene families contain 10-15 members with tissue-specific expression patterns, enabling differential regulation of root uptake, xylem loading, and leaf cell hydration. ||Aquaporins also transport CO₂, affecting mesophyll conductance and photosynthetic efficiency.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Vandeleur RK et al. (2009) The role of plasma membrane intrinsic protein aquaporins in water transport through roots: diurnal and drought stress responses reveal different strategies between isohydric and anisohydric cultivars of grapevine. Plant Physiology 149:445-460|| Shelden MC et al. (2009) Expression and functional characterisation of plasma membrane intrinsic protein aquaporins in grapevine. Functional Plant Biology 36:1065-1075"
  },
  "Water_Transport_Disposition": {
    "definition": "A water relations disposition that is the inherited capacity of a Vitis vinifera plant to conduct water through the xylem vascular system from roots to transpiring leaves, determined by xylem vessel anatomy (diameter, length, pit membrane properties), hydraulic pathway architecture, and the maintenance of xylem functionality under tension.",
    "alternative_term": "xylem water transport | long-distance water movement | vascular hydraulic capacity |+ Wassertransport | Xylemleitfähigkeit | vaskuläre Transportkapazität",
    "example_of_usage": "Whole-shoot hydraulic conductance in grapevines ranges from 8-25 mmol H₂O/m²/s/MPa across genotypes, with high-conductance cultivars such as Grenache and Syrah showing 2× the transport capacity of conservative types like Chardonnay. ||The transpiration stream moves through a series of hydraulic resistances, with roots contributing 30-50%, stems 20-40%, and leaves 20-40% of total resistance depending on growth stage and environmental conditions. ||Maximum sap flow velocities of 0.5-2.0 m/hour occur at midday under high vapor pressure deficit, with daily total transport of 20-50 L in mature vines. ||Xylem transport capacity must exceed maximum transpirational demand by a safety margin to prevent hydraulic failure from cavitation.",
    "editor_note": "Water_Transport_Disposition serves as the parent class for xylem conductivity and hydraulic architecture traits. ||Long-distance water transport in the xylem occurs under negative pressure (tension), making the system vulnerable to cavitation and embolism under severe water stress. ||The balance between transport efficiency (large vessels, high conductance) and transport safety (small vessels, cavitation resistant) represents a fundamental hydraulic trade-off with genotype-specific resolution. ||Vine training and canopy management modify transport path length and resistance distribution.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought. Plant, Cell and Environment 26:1393-1405|| Tyree MT, Zimmermann MH (2002) Xylem Structure and the Ascent of Sap, 2nd Ed, Springer pp.: 175-220"
  },
  "Xylem_Conductivity_Disposition": {
    "definition": "A water transport disposition that is the inherited capacity of a Vitis vinifera plant to conduct water through xylem vessels with genotype-specific hydraulic efficiency, determined by vessel diameter, vessel density, vessel length, intervessel pit membrane properties, and the proportion of functional (non-embolized) conduits.",
    "alternative_term": "xylem hydraulic conductance | vascular conductivity | stem hydraulic efficiency |+ Xylem-Leitfähigkeit | Gefäßleitfähigkeit | vaskuläre Leitungseffizienz",
    "example_of_usage": "Xylem-specific hydraulic conductivity (Ks) in grapevine stems ranges from 3-12 kg/m/s/MPa across genotypes, with vessel diameter being the primary determinant (conductivity scales with the fourth power of radius per Hagen-Poiseuille law). ||Syrah and Grenache show wide vessels (mean diameter 80-120 µm) with high Ks (8-12 kg/m/s/MPa), while Pinot Noir and Riesling have narrower vessels (60-90 µm) with lower Ks (4-7 kg/m/s/MPa). ||Leaf-specific conductivity (KL, normalized to supplied leaf area) of 2-8 × 10⁻⁴ kg/m/s/MPa determines the water potential gradient required to sustain transpiration. ||Seasonal conductivity loss from winter embolism ranges from 20-60% in cold climates, with spring refilling restoring 70-90% of original conductivity through positive root pressure.",
    "editor_note": "Xylem conductivity reflects the anatomical investment in water transport infrastructure, with higher conductivity enabling greater stomatal opening and photosynthesis but potentially increasing cavitation vulnerability. ||The Hagen-Poiseuille relationship means that small increases in mean vessel diameter yield disproportionate conductivity gains, creating selection pressure for large vessels constrained by cavitation risk. ||Petiole and shoot conductivity measurements provide accessible proxies for whole-vine hydraulic status. ||Ring-porous versus diffuse-porous anatomy affects seasonal conductivity patterns.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lovisolo C, Schubert A (1998) Effects of water stress on vessel size and xylem hydraulic conductivity in Vitis vinifera L. Journal of Experimental Botany 49:693-700|| Brodersen CR et al. (2010) The dynamics of embolism repair in xylem: in vivo visualizations using high-resolution computed tomography. Plant Physiology 154:1088-1095"
  },
  "Transpiration_Disposition": {
    "definition": "A water relations disposition that is the inherited capacity of a Vitis vinifera plant to lose water vapor from leaf surfaces to the atmosphere through stomatal and cuticular pathways, with genotype-specific rates determined by stomatal density, aperture regulation, cuticular permeability, and canopy architecture influencing boundary layer conductance.",
    "alternative_term": "water loss capacity | evapotranspiration trait | transpirational flux disposition |+ Transpiration | Wasserverlust | Verdunstungs-Disposition",
    "example_of_usage": "Whole-vine transpiration rates in grapevines range from 15-60 L/day depending on genotype, canopy size, and atmospheric demand, with stomatal transpiration accounting for 90-98% of total water loss under well-watered conditions. ||Leaf-level transpiration rates of 3-12 mmol H₂O/m²/s occur under midday conditions, with high-transpiring cultivars such as Syrah and Grenache at the upper range and conservative types like Chardonnay and Riesling at the lower range. ||Canopy transpiration follows a diurnal pattern peaking at solar noon and declining through the afternoon as stomata respond to increasing vapor pressure deficit. ||Transpiration per unit leaf area declines 40-70% under moderate water stress (predawn water potential -0.4 to -0.8 MPa) through stomatal closure.",
    "editor_note": "Transpiration_Disposition serves as the parent class for stomatal conductance and cuticular transpiration traits. ||Transpiration is the dominant component of vineyard evapotranspiration (60-85% of ET), with the remainder from soil evaporation. ||The process drives nutrient transport, enables evaporative cooling, and creates the water potential gradient for xylem sap ascent. ||Transpiration management through irrigation, canopy manipulation, and cultivar selection is central to vineyard water balance in both rain-fed and irrigated systems.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 215-235|| Williams LE, Ayars JE (2005) Grapevine water use and the crop coefficient are linear functions of the shaded area measured beneath the canopy. Agricultural and Forest Meteorology 132:201-211"
  },
  "Stomatal_Conductance_Disposition": {
    "definition": "A transpiration disposition that is the inherited capacity of a Vitis vinifera plant to regulate gas exchange through stomatal pores with genotype-specific conductance levels and response patterns, determined by stomatal density, maximum aperture size, guard cell sensitivity to environmental and hormonal signals, and the coordination of stomatal behavior across the leaf surface.",
    "alternative_term": "stomatal aperture regulation | gs trait | stomatal opening capacity |+ Stomata-Leitfähigkeit | stomatäre Leitfähigkeit | Spaltöffnungsregulation",
    "example_of_usage": "Maximum stomatal conductance (gs) in well-watered grapevines ranges from 150-450 mmol H₂O/m²/s across cultivars, with Grenache and Semillon at the high end (350-450 mmol/m²/s) and Chardonnay and Pinot Noir at the low end (150-250 mmol/m²/s). ||Stomatal density varies from 150-350 stomata/mm² on abaxial leaf surfaces (amphistomatous leaves show 10-30% of adaxial density). ||Guard cell response to ABA shows genotypic variation, with sensitive cultivars reducing gs by 50% at leaf ABA concentrations of 500-800 ng/g FW while insensitive types require 1200-1800 ng/g FW for equivalent closure. ||Stomatal patchiness (heterogeneous aperture across the leaf) increases under stress, causing gs measurements to underestimate average conductance by 10-30%.",
    "editor_note": "Stomatal_Conductance_Disposition serves as the parent class for high and low conductance categories. ||Stomatal conductance represents the primary control point for the trade-off between carbon gain (photosynthesis) and water loss (transpiration). ||The trait integrates genetic programming with environmental responsiveness, showing both constitutive differences among genotypes and plastic responses to light, humidity, CO₂, and water status. ||Coordination between stomatal and hydraulic conductance determines the operating point for leaf water potential.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Rogiers SY et al. (2009) Does night-time transpiration contribute to anisohydric behaviour in a Vitis vinifera cultivar? Journal of Experimental Botany 60:3751-3763|| Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought. Plant, Cell and Environment 26:1393-1405"
  },
  "High_Stomatal_Conductance_Disposition": {
    "definition": "A stomatal conductance disposition that is the inherited capacity of a Vitis vinifera plant to maintain high rates of stomatal gas exchange (typically gs greater than 300 mmol H₂O/m²/s under well-watered conditions), enabling high photosynthetic rates but requiring substantial water supply and often associated with anisohydric water use behavior.",
    "alternative_term": "high gs trait | open stomata disposition | high transpiration capacity |+ hohe Stomata-Leitfähigkeit | hohe stomatäre Öffnung | starke Transpirationskapazität",
    "example_of_usage": "Grenache exhibits high stomatal conductance disposition with maximum gs of 380-450 mmol/m²/s under well-watered conditions, supporting photosynthetic rates of 14-18 µmol CO₂/m²/s. ||Semillon and Shiraz show similarly high conductance (350-420 mmol/m²/s), maintaining open stomata even as soil moisture declines. ||High-gs cultivars typically show anisohydric behavior, with midday leaf water potential declining to -1.4 to -1.8 MPa under moderate stress while maintaining gs above 150 mmol/m²/s. ||The correlation between maximum gs and drought sensitivity is moderate (r = 0.55-0.70), as high conductance capacity may be combined with responsive closure mechanisms in some genotypes.",
    "editor_note": "High stomatal conductance disposition maximizes carbon gain under favorable water conditions but increases vulnerability to hydraulic failure when water supply becomes limiting. ||The trait is advantageous in irrigated viticulture where water is managed to match high transpirational demand, enabling rapid canopy development and high yield potential. ||In rain-fed systems, high-gs cultivars may experience severe stress during dry periods. ||Selection for high gs is generally associated with selection for productivity in well-watered environments.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Soar CJ et al. (2006) Grape vine varieties Shiraz and Grenache differ in their stomatal response to VPD: apparent links with ABA physiology and gene expression in leaf tissue. Australian Journal of Grape and Wine Research 12:2-12|| Prieto JA et al. (2010) Stomatal behavior of different grapevine cultivars in response to soil water status and air water vapor pressure deficit. Journal International des Sciences de la Vigne et du Vin 44:9-20"
  },
  "Low_Stomatal_Conductance_Disposition": {
    "definition": "A stomatal conductance disposition that is the inherited capacity of a Vitis vinifera plant to maintain relatively low rates of stomatal gas exchange (typically gs less than 250 mmol H₂O/m²/s under well-watered conditions), conferring water conservation at the cost of reduced maximum photosynthetic rate, often associated with isohydric water use behavior.",
    "alternative_term": "low gs trait | conservative stomata disposition | restricted transpiration capacity |+ niedrige Stomata-Leitfähigkeit | niedrige stomatäre Öffnung | eingeschränkte Transpirationskapazität",
    "example_of_usage": "Chardonnay exhibits low stomatal conductance disposition with maximum gs of 150-220 mmol/m²/s under well-watered conditions, supporting moderate photosynthetic rates of 10-13 µmol CO₂/m²/s. ||Pinot Noir and Riesling show similarly conservative conductance (180-250 mmol/m²/s), with rapid stomatal closure as water deficit develops. ||Low-gs cultivars typically show isohydric behavior, maintaining midday leaf water potential above -1.2 to -1.4 MPa through stomatal restriction even as soil dries. ||Water savings of 20-40% compared to high-gs cultivars occur under equivalent atmospheric demand, with proportionally reduced carbon assimilation of 15-30%.",
    "editor_note": "Low stomatal conductance disposition represents a conservative water use strategy prioritizing hydraulic safety over maximum productivity. ||The trait provides advantages in rain-fed viticulture and water-limited environments by reducing the rate of soil water depletion and maintaining favorable plant water status. ||However, the carbon cost of stomatal restriction may reduce yield potential under well-watered conditions. ||Some premium wine regions favor low-gs cultivars for their association with moderate vigor and concentrated fruit composition.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Schultz HR (2003) Differences in hydraulic architecture account for near-isohydric and anisohydric behaviour of two field-grown Vitis vinifera L. cultivars during drought. Plant, Cell and Environment 26:1393-1405|| Chaves MM et al. (2010) Grapevine under deficit irrigation: hints from physiological and molecular data. Annals of Botany 105:661-676"
  },
  "Cuticular_Transpiration_Disposition": {
    "definition": "A transpiration disposition that is the inherited capacity of a Vitis vinifera plant to lose water vapor through the cuticle and associated epicuticular waxes when stomata are closed, with genotype-specific residual conductance determined by cuticle thickness, wax composition, and the presence of cuticular cracks or imperfections.",
    "alternative_term": "residual transpiration | minimum conductance | cuticular water loss trait |+ kutikuläre Transpiration | Residualtranspiration | Mindestwasserverlust",
    "example_of_usage": "Cuticular transpiration in grapevine leaves accounts for 2-10% of total water loss under well-watered conditions but becomes the dominant pathway during prolonged stomatal closure, with minimum conductance (gmin) ranging from 3-15 mmol H₂O/m²/s across genotypes. ||Cultivars with thick cuticles and dense epicuticular wax such as Carignane and Monastrell show low gmin (3-6 mmol/m²/s), while thin-cuticled types like Pinot Noir show higher residual conductance (10-15 mmol/m²/s). ||Cuticular conductance increases with leaf age (senescent leaves showing 2-3× higher gmin than mature leaves) and following physical damage or pathogen infection. ||Berry cuticular conductance of 0.5-3.0 mmol/m²/s contributes to post-veraison berry water loss and concentration.",
    "editor_note": "Cuticular transpiration represents the irreducible water loss that occurs even when stomata are fully closed, becoming critical during severe drought when stomatal closure is complete. ||Low cuticular conductance extends survival time during prolonged water deficit by slowing desiccation. ||The trait is determined by cuticle development during leaf expansion and shows limited plasticity in mature leaves. ||Berry cuticular properties affect fruit quality through water loss and concentration effects, particularly in late-harvest scenarios.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 65-72|| Blanke MM, Leyhe A (1987) Stomatal activity of the grape berry cv. Riesling, Müller-Thurgau and Ehrenfelser. Journal of Plant Physiology 127:451-460"
  },
  "Water_Use_Efficiency_Disposition": {
    "definition": "A water relations disposition that is the inherited capacity of a Vitis vinifera plant to produce biomass or yield per unit of water transpired, integrating stomatal regulation of the CO₂/H₂O exchange ratio with mesophyll conductance, photosynthetic capacity, and respiratory losses to determine overall carbon gain relative to water expenditure.",
    "alternative_term": "WUE trait | transpiration efficiency | water productivity disposition |+ Wassernutzungseffizienz | WUE | Wasserproduktivität",
    "example_of_usage": "Water use efficiency in grapevines ranges from 3-8 g dry matter per kg H₂O transpired (whole-plant WUE) or 2-6 µmol CO₂/mmol H₂O at the leaf level (instantaneous WUE), with substantial genotypic variation. ||Intrinsic WUE (A/gs, the ratio of photosynthesis to stomatal conductance) ranges from 40-90 µmol CO₂/mol H₂O across cultivars, with Tempranillo and Cabernet Sauvignon showing high values (70-90) and Grenache showing lower values (45-60). ||WUE increases under moderate water stress as stomatal closure restricts transpiration proportionally more than photosynthesis (non-stomatal limitation). ||Seasonal WUE of 4-8 kg fruit/m³ water applied is typical for deficit-irrigated wine grapes versus 2-4 kg/m³ for fully irrigated table grapes.",
    "editor_note": "Water_Use_Efficiency_Disposition serves as the parent class for carbon isotope discrimination and transpiration efficiency traits. ||This trait also appears under Drought_Tolerance_Disposition where the focus is stress-adaptive mechanisms|| here the emphasis is on general water economy under all conditions. ||WUE represents a key target for sustainable viticulture, as improving water productivity reduces irrigation requirements and environmental impact. ||The trait shows complex inheritance and genotype × environment interaction, complicating selection efforts.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Medrano H et al. (2015) Improving water use efficiency of vineyards in semi-arid regions: a review. Agronomy for Sustainable Development 35:499-517|| Tomás M et al. (2014) Variability of water use efficiency in grapevines. Environmental and Experimental Botany 103:148-157"
  },
  "Carbon_Isotope_Discrimination_Disposition": {
    "definition": "A water use efficiency disposition that is the inherited capacity of a Vitis vinifera plant to discriminate against the heavier stable carbon isotope (¹³C) relative to the lighter isotope (¹²C) during photosynthetic CO₂ fixation, providing an integrated measure of the ratio of intercellular to atmospheric CO₂ concentration (Ci/Ca) and thus a time-integrated proxy for intrinsic water use efficiency.",
    "alternative_term": "delta 13C trait | carbon isotope ratio | Δ¹³C disposition |+ Kohlenstoff-Isotopendiskriminierung | δ¹³C-Signatur | C-Isotopenverhältnis",
    "example_of_usage": "Carbon isotope discrimination (Δ¹³C) in grapevine leaf dry matter ranges from 18-24‰ across cultivars and water regimes, with higher discrimination indicating lower water use efficiency. ||Well-watered vines with high stomatal conductance show Δ¹³C of 22-24‰, while water-stressed vines with restricted stomata show 18-21‰. ||Cultivar differences of 1-3‰ in Δ¹³C persist across environments, with Grenache showing consistently higher discrimination (lower WUE) than Tempranillo. ||Berry sugar Δ¹³C of 20-26‰ integrates vine water status over the ripening period and correlates with seasonal water deficit (r = -0.65 to -0.80). δ¹³C values in wine range from -22 to -28‰ (expressed relative to PDB standard), enabling retrospective assessment of vineyard water status.",
    "editor_note": "Carbon isotope discrimination provides a powerful tool for phenotyping water use efficiency because the isotopic signature integrates gas exchange over the period of tissue formation, avoiding the instantaneous measurement challenges of leaf-level WUE. ||Lower discrimination (more negative δ¹³C, less positive Δ¹³C) indicates higher WUE through reduced Ci/Ca ratio resulting from stomatal limitation. ||The trait is used in breeding programs to screen for WUE, in production to assess irrigation adequacy, and in wine authentication to verify origin and vintage conditions.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gaudillère JP et al. (2002) Carbon isotope composition of sugars in grapevine, an integrated indicator of vineyard water status. Journal of Experimental Botany 53:757-763|| Santesteban LG et al. (2015) Discrimination ability of leaf and stem water potential at different times of the day through a meta-analysis in grapevine (Vitis vinifera L.). Agricultural Water Management 158:52-59"
  },
  "Transpiration_Efficiency_Disposition": {
    "definition": "A water use efficiency disposition that is the inherited capacity of a Vitis vinifera plant to produce biomass per unit of water transpired over extended time periods (days to seasons), integrating instantaneous gas exchange efficiency with respiratory carbon losses, non-productive water use, and the temporal dynamics of growth and transpiration across variable environmental conditions.",
    "alternative_term": "biomass water productivity | seasonal WUE | transpiration-based efficiency |+ Transpirations-Effizienz | saisonale Wassernutzungseffizienz | Biomasseproduktivität pro Transpiration",
    "example_of_usage": "Transpiration efficiency in grapevines ranges from 3-7 g above-ground dry matter per kg H₂O transpired over the growing season, with high-efficiency cultivars such as Tempranillo and Mourvèdre at 5-7 g/kg and lower-efficiency types like Grenache at 3-5 g/kg. ||Rootstock effects on scion transpiration efficiency reach 15-30%, with 110 Richter and 140 Ruggeri conferring higher efficiency than SO4 and 1103 Paulsen through moderate stomatal conductance and conservative water use. ||Deficit irrigation improves transpiration efficiency by 20-50% compared to full irrigation, as moderate stress reduces transpiration proportionally more than biomass production. ||Night-time transpiration (5-15% of daily total) represents a water loss with no carbon gain, reducing whole-plant transpiration efficiency.",
    "editor_note": "Transpiration efficiency captures the net outcome of water-for-carbon exchange over agronomically relevant time scales, integrating the multiple processes affecting WUE into a single production metric. ||The trait differs from instantaneous WUE by including respiratory losses and non-stomatal water loss. ||High transpiration efficiency is achieved through combinations of moderate stomatal conductance, high mesophyll conductance, efficient Rubisco carboxylation, and low respiratory costs. ||Partitioning of biomass between vegetative growth and fruit affects the agronomic relevance of transpiration efficiency for yield outcomes.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tomás M et al. (2012) Variability of mesophyll conductance in grapevine cultivars under water stress conditions in relation to leaf anatomy and water use efficiency. Australian Journal of Grape and Wine Research 18:164-172|| Escalona JM et al. (2012) Responses of leaf night transpiration to drought stress in Vitis vinifera L. Agricultural Water Management 118:50-58"
  },
  "Compatibility_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to form successful biological unions with other grapevine genotypes through grafting or to produce viable offspring through interspecific hybridization, encompassing traits related to graft union formation, long-term graft functionality, and cross-compatibility with related Vitis species.",
    "alternative_term": "union compatibility trait | grafting success capacity | biological integration disposition |+ Kompatibilität | Verträglichkeit | Vereinigungsfähigkeit",
    "example_of_usage": "Compatibility determines the success of grafted vine production, with graft take rates ranging from 60-98% depending on scion-rootstock combinations under commercial bench grafting conditions. ||Compatible combinations such as Cabernet Sauvignon on SO4 achieve 90-95% take rates with strong vascular connections, while marginally compatible combinations may show 70-80% initial success with subsequent decline. ||Interspecific compatibility enables rootstock breeding, with V. vinifera × V. rupestris and V. berlandieri × V. riparia crosses showing high fertility (>80% viable seed) versus difficult crosses such as V. vinifera × V. rotundifolia (<5% viable seed). ||Long-term compatibility affects vineyard longevity, with some scion-rootstock combinations maintaining productivity for 50-100 years while incompatible unions decline within 10-20 years.",
    "editor_note": "Compatibility_Disposition serves as the top-level parent class for traits related to graft union success and interspecific hybridization. ||The category addresses both the immediate success of graft union formation and the long-term physiological functionality of the grafted vine. ||Compatibility is fundamental to commercial viticulture, as phylloxera pressure requires grafting onto resistant rootstocks throughout most wine regions. ||Understanding compatibility mechanisms enables informed rootstock selection and improved nursery practices.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ollat N et al. (2016) Grapevine roots and soil environment. In: Gerós H et al. (eds) Grapevine in a Changing Environment, Wiley pp.: 175-202|| Goldschmidt EE (2014) Plant grafting: new mechanisms, evolutionary implications. Frontiers in Plant Science 5:727"
  },
  "Graft_Compatibility_Disposition": {
    "definition": "A compatibility disposition that is the inherited capacity of a Vitis vinifera scion to form and maintain a functional graft union with rootstock genotypes, determined by the ability to establish cellular continuity, vascular connections, and physiological integration across the graft interface without adverse incompatibility reactions.",
    "alternative_term": "grafting compatibility | scion-rootstock compatibility | graft success trait |+ Pfropfkompatibilität | Veredlungsverträglichkeit | Pfropfaffinität",
    "example_of_usage": "Graft compatibility in commercial viticulture is generally high among V. vinifera scions and standard rootstocks, with take rates of 85-98% for most combinations under optimal nursery conditions. ||Compatibility is assessed by callus bridge formation (visible within 14-21 days), vascular differentiation (28-42 days), and mechanical strength of the union (3-6 months). ||Compatible unions show continuous cambial activity, aligned vascular elements, and absence of necrotic tissue at the interface. ||Incompatibility symptoms include poor callus development, discontinuous cambium, excessive starch accumulation above the union, and delayed or absent vascular connections, with affected vines showing reduced vigor, leaf discoloration, and premature decline.",
    "editor_note": "Graft_Compatibility_Disposition serves as the parent class for graft union formation and graft incompatibility traits. ||Compatibility operates at multiple levels including cellular (callus intermingling), vascular (xylem and phloem connection), and physiological (hormone and metabolite exchange). ||Most V. vinifera cultivars show broad compatibility with standard rootstocks, though specific combinations may exhibit marginal or delayed incompatibility. ||Temperature, humidity, and grafting technique significantly influence compatibility expression.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pina A, Errea P (2005) A review of new advances in mechanism of graft compatibility-incompatibility. Scientia Horticulturae 106:1-11|| Cookson SJ et al. (2013) Graft union formation in grapevine induces transcriptional changes related to cell wall modification, wounding, hormone signalling, and secondary metabolism. Journal of Experimental Botany 64:2997-3008"
  },
  "Graft_Union_Formation_Disposition": {
    "definition": "A graft compatibility disposition that is the inherited capacity of a Vitis vinifera scion and rootstock combination to establish the initial graft union through coordinated wound response, callus proliferation, cellular adhesion, and de novo vascular differentiation connecting the previously separate vascular systems of the graft partners.",
    "alternative_term": "union establishment | graft healing capacity | initial compatibility trait |+ Veredlungsstellen-Bildung | Pfropfvereinigung | Kallusbrückenbildung",
    "example_of_usage": "Graft union formation in grapevine omega grafts proceeds through defined stages over 21-35 days under optimal conditions (25-28°C, 85-95% RH). ||Callus initiation occurs within 3-7 days, with callus cells from scion and rootstock intermingling by day 10-14 to form a callus bridge. ||Vascular differentiation begins at day 14-21, with first continuous xylem vessels detectable by day 21-28 and phloem connections by day 28-35. ||Mechanical union strength increases from near zero at grafting to 50-100 N pull-apart force by 6 weeks, reaching 200-400 N by 12 weeks in compatible unions. ||Bench graft callusing success rates of 90-98% are achieved in climate-controlled callusing rooms versus 70-85% under field conditions.",
    "editor_note": "Graft_Union_Formation_Disposition serves as the parent class for callus formation and vascular connection traits. ||Union formation represents the critical establishment phase where compatibility or incompatibility first manifests. ||The process requires coordinated wound responses from both graft partners, with auxin and cytokinin signaling driving callus proliferation and vascular redifferentiation. ||Successful union formation does not guarantee long-term compatibility, as delayed incompatibility may emerge years after initial graft take.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pina A et al. (2012) Differential induction of phenylalanine ammonia-lyase gene expression in response to in vitro callus unions of Prunus spp. Journal of Plant Physiology 169:1724-1730|| Melnyk CW et al. (2015) A developmental framework for graft formation and vascular reconnection in Arabidopsis thaliana. Current Biology 25:1306-1318"
  },
  "Callus_Formation_Disposition": {
    "definition": "A graft union formation disposition that is the inherited capacity of a Vitis vinifera graft partner to produce callus tissue (parenchymatous wound tissue) at cut surfaces in response to grafting injury, with genotype-specific rates of callus initiation, proliferation, and the capacity for callus cells to intermingle with partner callus across the graft interface.",
    "alternative_term": "callus proliferation capacity | wound healing response | callusing ability |+ Kallusbildung | Wundgewebeproliferation | Kallusierungsvermögen",
    "example_of_usage": "Callus formation capacity varies among grapevine genotypes, with vigorous rootstocks such as 1103 Paulsen and SO4 showing rapid callus initiation (visible within 3-5 days at 25°C) and abundant proliferation (2-4 mm callus thickness by day 14), while less vigorous types like Riparia Gloire show slower response (5-7 days to visible callus, 1-2 mm by day 14). ||Scion callusing ability also varies, with Cabernet Sauvignon and Merlot showing strong callus response versus Pinot Noir with moderate callusing. ||Callus cells dedifferentiate from cambium, phloem parenchyma, and ray cells adjacent to the cut surface, with cell division rates of 1-2 divisions per day under optimal conditions. ||Callus quality (firm, white, uniform) correlates with subsequent vascular connection success (r = 0.70-0.85).",
    "editor_note": "Callus formation represents the first visible step in graft union establishment, creating the cellular matrix within which vascular reconnection will occur. ||Adequate callus volume is necessary but not sufficient for compatibility, as callus cells must also show appropriate adhesion and competence for vascular redifferentiation. ||Callusing conditions (temperature, humidity, oxygen) strongly influence callus quantity and quality. ||Excessive callusing can impair union quality by displacing graft partners or creating excessive tissue mass without functional connections.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Cookson SJ, Ollat N (2013) Grafting with rootstocks induces extensive transcriptional re-programming in the shoot apical meristem of grapevine. BMC Plant Biology 13:147|| Zarrouk O et al. (2010) Grapevine rootstocks differentially influence the rate of ripening and modulate auxin-related genes in Cabernet Sauvignon berries. Australian Journal of Grape and Wine Research 16:355-363"
  },
  "Vascular_Connection_Disposition": {
    "definition": "A graft union formation disposition that is the inherited capacity of a Vitis vinifera graft combination to establish functional xylem and phloem connections across the graft interface through redifferentiation of callus cells into vascular elements, enabling water and nutrient transport from rootstock to scion and photosynthate transport from scion to rootstock.",
    "alternative_term": "vascular differentiation capacity | xylem-phloem reconnection | vascular bridge formation |+ Gefäßverbindung | vaskuläre Konnektivität | Leitbündelanschluss",
    "example_of_usage": "Vascular connection establishment in grapevine grafts requires 21-42 days under optimal conditions, with xylem continuity typically preceding phloem connection by 7-14 days. ||Compatible unions show 80-95% of the graft interface occupied by functional vascular tissue by 8-12 weeks, with vessel diameter at the union reaching 60-80% of normal internode vessel size. ||Hydraulic conductance across mature compatible unions reaches 70-90% of ungrafted stem conductance. ||Incompatible combinations may show only 30-50% vascular coverage with discontinuous elements, reduced vessel diameter (40-60% of normal), and hydraulic conductance below 50% of ungrafted values. ||Phloem connectivity assessed by carboxyfluorescein transport shows bidirectional movement within 35-45 days in compatible unions.",
    "editor_note": "Vascular connection represents the critical functional outcome of graft union formation, as inadequate vascular continuity limits water, nutrient, and photosynthate exchange regardless of callus development success. ||The process requires redifferentiation of callus cells along auxin gradients, with polar auxin transport establishing the directional pattern of vascular elements. ||Xylem connections form through transdifferentiation of callus cells into tracheary elements, while phloem connections require sieve element differentiation and companion cell association. ||Union anatomy assessment by sectioning provides definitive compatibility evaluation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Melnyk CW (2017) Plant grafting: insights into tissue regeneration. Regeneration 4:3-14|| Gambetta GA et al. (2017) Grapevine rootstocks and their role in managing salinity in Australian viticulture. Australian Journal of Grape and Wine Research 23:137-149"
  },
  "Graft_Incompatibility_Disposition": {
    "definition": "A graft compatibility disposition that is the inherited capacity of certain Vitis vinifera scion-rootstock combinations to exhibit impaired graft union function despite initial callus contact, resulting from adverse cellular, biochemical, or physiological interactions at the graft interface that prevent normal union development or cause progressive functional decline.",
    "alternative_term": "graft rejection | union dysfunction | incompatibility trait |+ Pfropfinkompatibilität | Veredlungsunverträglichkeit | Abstoßungsreaktion",
    "example_of_usage": "Graft incompatibility in grapevine ranges from immediate failure (0-20% graft take) in severe cases to delayed decline emerging 5-15 years after grafting in marginal combinations. ||Incompatibility symptoms include necrotic tissue at the graft interface, discontinuous cambial zones, bark involution, excessive starch accumulation in scion tissue above the union, reduced hydraulic conductance (30-60% of compatible unions), and vine decline with premature senescence. ||The combination of V. vinifera with V. rotundifolia (Muscadinia) shows severe incompatibility with <30% initial survival and universal long-term failure. ||Within V. vinifera × standard rootstock combinations, incompatibility is rare but reported for specific clonal combinations, with incidence of 2-8% showing measurable impairment.",
    "editor_note": "Graft_Incompatibility_Disposition serves as the parent class for translocated and localized incompatibility mechanisms. ||Incompatibility represents failure of the complex biological processes required for successful grafting, potentially involving any stage from initial cell recognition through long-term vascular function. ||The phenomenon is less prevalent in grapevine than in Prunus and other genera but remains a consideration in rootstock selection and nursery quality control. ||Climate stress may exacerbate marginal incompatibility that would remain subclinical under favorable conditions.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pina A, Errea P (2005) A review of new advances in mechanism of graft compatibility-incompatibility. Scientia Horticulturae 106:1-11|| Mudge K et al. (2009) A history of grafting. Horticultural Reviews 35:437-493"
  },
  "Translocated_Incompatibility_Disposition": {
    "definition": "A graft incompatibility disposition that is the inherited capacity of certain Vitis vinifera graft combinations to exhibit incompatibility symptoms caused by adverse substances (toxins, phenolics, hormones) produced by one graft partner and transported to the other, causing systemic physiological disruption beyond the immediate graft zone.",
    "alternative_term": "systemic incompatibility | biochemical incompatibility | translocatable factor incompatibility |+ translokatierte Inkompatibilität | systemische Unverträglichkeit | transportierte Inkompatibilität",
    "example_of_usage": "Translocated incompatibility in grapevine is implicated when incompatibility symptoms appear in tissues distant from the graft union, including scion leaf chlorosis, abnormal root development, or generalized growth reduction that cannot be explained by localized union dysfunction. ||Phenolic compounds including catechins, cyanogenic glycosides, and prunasin (in Prunus) serve as translocated incompatibility factors in other genera, with analogous compounds suspected but not definitively identified in Vitis. ||Reciprocal grafting experiments distinguish translocated from localized incompatibility, as translocated factors cause symptoms regardless of which partner serves as scion versus rootstock. ||Symptoms may appear within the first growing season or develop progressively over 2-5 years as factor accumulation exceeds tolerance thresholds.",
    "editor_note": "Translocated incompatibility is less well documented in grapevine than in stone fruits, where specific cyanogenic compounds have been identified as incompatibility factors. ||The mechanism involves phloem or xylem transport of inhibitory substances from one partner to sensitive tissues of the other, causing toxicity at sites distant from the graft zone. ||Distinguishing translocated from localized incompatibility has practical implications, as translocated incompatibility cannot be remedied by improved grafting technique while localized incompatibility may respond to modified practices.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Goldschmidt EE (2014) Plant grafting: new mechanisms, evolutionary implications. Frontiers in Plant Science 5:727|| Errea P (1998) Implications of phenolic compounds in graft incompatibility in fruit tree species. Scientia Horticulturae 74:195-205"
  },
  "Localized_Incompatibility_Disposition": {
    "definition": "A graft incompatibility disposition that is the inherited capacity of certain Vitis vinifera graft combinations to exhibit incompatibility symptoms restricted to the immediate graft zone, resulting from impaired cellular recognition, adhesion failure, aberrant vascular differentiation, or localized necrotic reactions at the interface without systemic toxic effects.",
    "alternative_term": "interface incompatibility | structural incompatibility | union zone dysfunction |+ lokalisierte Inkompatibilität | Schnittstellenunverträglichkeit | Vereinigungszonen-Störung",
    "example_of_usage": "Localized incompatibility in grapevine manifests as anatomical abnormalities confined to the graft union, including incomplete callus fusion, discontinuous cambium (present in only 40-70% of interface circumference versus >90% in compatible unions), vascular element misalignment, necrotic pockets within the callus bridge, and bark discontinuity visible as a persistent graft line. ||Mechanically, localized incompatibility causes union weakness with break strength below 150 N versus 300-500 N in compatible unions of similar age, predisposing vines to wind breakage at the graft zone. ||Hydraulic consequences include reduced conductance across the union (40-70% of ungrafted values) without systemic scion dysfunction. ||Localized incompatibility may improve with bridge grafting or inarching techniques that bypass the defective union.",
    "editor_note": "Localized incompatibility results from failure of the cellular and developmental processes required for union formation rather than from toxic factor translocation. ||The mechanism may involve cell recognition failures (preventing callus intermingling), physical barriers (callose or lignin deposition at interface), or developmental asynchrony (mismatched cambial activity timing). ||Localized incompatibility is more amenable to management through improved grafting technique, callusing conditions, and timing optimization than translocated incompatibility.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pina A et al. (2012) Differential induction of phenylalanine ammonia-lyase gene expression in response to in vitro callus unions of Prunus spp. Journal of Plant Physiology 169:1724-1730|| Cookson SJ et al. (2014) Heterografting with nonself rootstocks induces genes involved in stress responses at the graft interface when compared with autografted controls. Journal of Experimental Botany 65:2473-2481"
  },
  "Delayed_Incompatibility_Disposition": {
    "definition": "A graft incompatibility disposition that is the inherited capacity of certain Vitis vinifera scion-rootstock combinations to exhibit incompatibility symptoms that emerge years to decades after initial successful graft establishment, resulting from progressive vascular dysfunction, cumulative metabolic imbalances, or gradual failure of the graft union under production stress.",
    "alternative_term": "late-onset incompatibility | progressive union failure | chronic incompatibility trait |+ verzögerte Inkompatibilität | Spätinkompatibilität | progressive Veredlungsunverträglichkeit",
    "example_of_usage": "Delayed incompatibility in grapevine typically manifests 5-15 years after grafting, with vines showing initial normal growth followed by progressive vigor decline, premature autumn leaf coloration, reduced yield, and eventually vine death. ||Anatomical examination of delayed-incompatible unions reveals progressive necrotic zone expansion, discontinuous cambial bands, excessive starch accumulation in scion bark, and constricted vascular elements at the interface. ||The combination of Syrah on certain 110 Richter clones has shown delayed incompatibility in some California vineyards, with 15-30% of vines declining between years 8-15 despite initial take rates above 90%. ||Hydraulic conductance across delayed-incompatible unions declines progressively from 70-80% of normal at year 3 to 30-50% by year 10.",
    "editor_note": "Delayed incompatibility represents a particularly challenging phenomenon because affected vines may perform normally for years before decline begins, complicating diagnosis and economic planning. ||The progressive nature suggests cumulative damage from subclinical dysfunction rather than acute rejection. ||Environmental stresses (drought, crop load, disease) may accelerate symptom expression in marginally compatible combinations. ||Distinguishing delayed incompatibility from other decline syndromes (trunk diseases, viral infections) requires careful union examination and exclusion of alternative causes.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Goldschmidt EE (2014) Plant grafting: new mechanisms, evolutionary implications. Frontiers in Plant Science 5:727|| Stamp JA (2001) The contribution of imperfections in nursery stock to the decline of young vines in California. Phytopathologia Mediterranea 40:S369-S375"
  },
  "Interspecific_Hybridization_Disposition": {
    "definition": "A compatibility disposition that is the inherited capacity of a Vitis vinifera plant to successfully cross with other Vitis species to produce viable, fertile offspring, determined by reproductive barrier strength, genomic compatibility, and the developmental viability of hybrid embryos and resulting plants.",
    "alternative_term": "interspecies crossing ability | species hybridization capacity | cross-breeding compatibility |+ interspezifische Hybridisierung | Artkreuzungsfähigkeit | Kreuzungskompatibilität",
    "example_of_usage": "Interspecific hybridization capacity varies widely across Vitis species combinations, with V. vinifera showing high crossability with V. rupestris, V. riparia, and V. berlandieri (70-95% seed set, 60-85% germination) enabling rootstock breeding, while crosses with V. rotundifolia (Muscadinia subgenus) show severe barriers (<5% viable seed). ||First-generation (F1) hybrids between V. vinifera and American species typically show intermediate traits for disease resistance and wine quality, with subsequent backcrossing required to recover V. vinifera quality while retaining resistance. ||Modern PIWI (Pilzwiderstandsfähige) cultivars such as Regent, Solaris, and Cabernet Blanc derive from multiple generations of interspecific hybridization and backcrossing, combining Rpv and Ren resistance loci with acceptable wine quality.",
    "editor_note": "Interspecific_Hybridization_Disposition serves as the parent class for cross-compatibility and hybrid vigor traits. ||Hybridization has been fundamental to viticulture since the phylloxera crisis, providing both rootstock solutions and disease-resistant scion cultivars. ||The genus Vitis shows generally low reproductive barriers within the Vitis subgenus, facilitating breeding programs. ||Embryo rescue techniques enable recovery of hybrids from difficult crosses with low natural seed viability. ||Understanding hybridization barriers informs breeding strategy and genetic resource utilization.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Töpfer R et al. (2011) New horizons for grapevine breeding. Fruit, Vegetable and Cereal Science and Biotechnology 5:79-100|| This P et al. (2006) Historical origins and genetic diversity of wine grapes. Trends in Genetics 22:511-519"
  },
  "Cross_Compatibility_Disposition": {
    "definition": "An interspecific hybridization disposition that is the inherited capacity of a Vitis vinifera plant to produce viable seeds when crossed with specific other Vitis species or genotypes, determined by pollen-pistil interactions, fertilization success, and embryo development through seed maturation without lethal incompatibility.",
    "alternative_term": "crossing success | sexual compatibility | fertilization compatibility trait |+ Kreuzungskompatibilität | Befruchtungsverträglichkeit | sexuelle Kompatibilität",
    "example_of_usage": "Cross-compatibility between V. vinifera and other Vitis species ranges from highly compatible to essentially incompatible depending on the species pair. ||V. vinifera × V. rupestris crosses show high compatibility with 80-95% fruit set and 70-90% seed germination, enabling creation of rootstocks such as 3309C and 101-14 Mgt. ||V. vinifera × V. labrusca shows moderate compatibility (50-70% fruit set) with offspring exhibiting variable wine quality (foxy character inheritance). ||V. vinifera × V. rotundifolia crosses face severe post-zygotic barriers, with embryo abortion occurring 20-40 days post-fertilization in 90-98% of ovules, requiring embryo rescue for hybrid recovery. ||Pollen tube growth in incompatible crosses may proceed normally to fertilization, with barriers operating primarily at embryo development stages.",
    "editor_note": "Cross-compatibility encompasses both pre-zygotic barriers (pollen germination, tube growth, fertilization) and post-zygotic barriers (embryo development, seed viability, seedling survival). ||Most Vitis species within the Vitis subgenus show adequate cross-compatibility for breeding, with the Muscadinia subgenus (V. rotundifolia) representing the major crossing barrier. ||Reciprocal cross differences occur in some combinations, with success depending on which species serves as maternal versus paternal parent. ||Marker-assisted selection enables efficient introgression of resistance loci while minimizing unfavorable hybrid characteristics.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bouquet A (1980) Vitis × Muscadinia hybridization: a new way in grape breeding for disease resistance in France. Proceedings of the 3rd International Symposium on Grape Breeding pp.: 42-61|| Patel GI, Olmo HP (1955) Cytogenetics of Vitis: I. The hybrid V. vinifera × V. rotundifolia. American Journal of Botany 42:141-159"
  },
  "Hybrid_Vigor_Disposition": {
    "definition": "An interspecific hybridization disposition that is the inherited capacity of Vitis interspecific hybrids to exhibit heterosis (superior performance compared to parental species) for growth vigor, stress tolerance, or yield potential, resulting from heterozygosity, complementation of deleterious alleles, and epistatic interactions between divergent parental genomes.",
    "alternative_term": "heterosis | hybrid superiority | vigor enhancement trait |+ Heterosis | Hybridvitalität | Bastardwüchsigkeit",
    "example_of_usage": "Hybrid vigor in Vitis is prominently displayed in rootstock breeding, where F1 hybrids between American species often exceed parental performance for root development and stress tolerance. ||The V. berlandieri × V. riparia cross producing rootstocks such as SO4 and 5BB Kober shows heterosis for root system size (20-40% larger than either parent) and phylloxera tolerance. ||V. berlandieri × V. rupestris hybrids (110 Richter, 140 Ruggeri) exhibit heterosis for drought tolerance and lime resistance exceeding parental species. ||Scion hybrid vigor is observed in some PIWI cultivars, with Regent showing 15-25% greater yield potential than V. vinifera parents while maintaining acceptable wine quality. ||Heterosis magnitude varies by trait, with vegetative vigor showing 10-40% superiority in favorable combinations while fruit quality traits may show intermediate or negative heterosis.",
    "editor_note": "Hybrid vigor provides the genetic basis for rootstock superiority, as most commercial rootstocks are interspecific hybrids exploiting heterosis for vigor and stress tolerance. ||The phenomenon results from multiple genetic mechanisms including dominance (masking of deleterious recessive alleles), overdominance (heterozygote advantage at individual loci), and epistasis (favorable interactions between loci from different species). ||Heterosis typically declines in subsequent generations (F2, backcross) as heterozygosity decreases, favoring F1 hybrids for rootstock use. ||Understanding hybrid vigor mechanisms informs breeding strategy for both rootstock and scion improvement.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Ollat N et al. (2016) Grapevine roots and soil environment. In: Gerós H et al. (eds) Grapevine in a Changing Environment, Wiley pp.: 175-202|| Cousins P (2005) Evolution, genetics, and breeding: viticultural applications of the origins of our rootstocks. In: Christensen LP, Smart DR (eds) Proceedings of the Soil Environment and Vine Mineral Nutrition Symposium, ASEV pp.: 1-7"
  },
  "Quality_Potential_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to accumulate and balance the chemical constituents that determine grape and wine quality, encompassing traits related to sugar concentration, organic acid metabolism, phenolic compound synthesis, aromatic precursor accumulation, and color stability in the resulting wine.",
    "alternative_term": "fruit quality trait | quality component capacity | oenological potential disposition |+ Qualitätspotential | Traubenqualität | önologisches Potential",
    "example_of_usage": "Quality potential varies enormously across V. vinifera cultivars, with premium wine varieties such as Pinot Noir and Riesling prized for balanced sugar-acid ratios (20-24°Brix with 6-9 g/L titratable acidity), complex aromatic profiles, and age-worthy phenolic structures, while bulk wine cultivars such as Airén may achieve high yields but produce simpler wines. ||Quality parameters include sugar concentration (18-28°Brix), titratable acidity (4-10 g/L tartaric equivalents), pH (3.0-4.0), total phenolics (200-4000 mg/L gallic acid equivalents), anthocyanins in red cultivars (200-2000 mg/L), and varietal aroma compounds (terpenes 0.5-6 mg/L in aromatic cultivars). ||Terroir expression reflects genotype × environment interaction for quality traits, with identical cultivars producing distinct quality profiles across sites.",
    "editor_note": "Quality_Potential_Disposition serves as the top-level parent class for all traits contributing to grape and wine quality. ||Quality is inherently multidimensional, with different parameters prioritized for different wine styles and markets. ||The trait complex shows strong genotype × environment × management interaction, making quality expression highly context-dependent. ||Rootstock effects on scion quality potential are significant but secondary to scion genotype effects for most quality parameters.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 343-425|| Jackson RS (2020) Wine Science: Principles and Applications, 5th Ed, Academic Press pp.: 287-376"
  },
  "Sugar_Accumulation_Disposition": {
    "definition": "A quality potential disposition that is the inherited capacity of a Vitis vinifera plant to transport and accumulate hexose sugars (glucose and fructose) in ripening berries, determined by source leaf photosynthetic capacity, phloem loading and transport efficiency, berry sink strength, and the expression of sugar transporter and invertase genes controlling berry sugar import and storage.",
    "alternative_term": "sugar loading capacity | Brix accumulation trait | berry sweetening disposition |+ Zuckerakkumulation | Zuckereinlagerung | Beerenreife-Disposition",
    "example_of_usage": "Sugar accumulation in grape berries follows a sigmoidal pattern beginning at veraison, with accumulation rates of 0.1-0.3°Brix per day during active ripening. ||Final sugar concentrations range from 16-18°Brix in cool climate table grapes to 24-28°Brix in warm climate wine grapes harvested for high-alcohol wines. ||Cultivar differences in sugar accumulation capacity span 3-6°Brix at equivalent thermal time from veraison, with Grenache and Zinfandel showing high accumulation (24-28°Brix typical) and Riesling showing moderate accumulation (20-23°Brix at flavor maturity). ||Sugar composition shifts from glucose-dominant early in ripening (G/F ratio 2-3) to near-equal at maturity (G/F ratio 0.95-1.05), with cultivar-specific variation in final ratio.",
    "editor_note": "Sugar_Accumulation_Disposition serves as the parent class for specific sugar accumulation capacity categories. ||Sugar concentration is the primary determinant of potential alcohol in wine and significantly affects wine body, sweetness perception, and microbial stability. ||The trait integrates whole-vine carbon economy with berry-level transport and storage mechanisms. ||Climate warming is advancing sugar ripeness relative to flavor and phenolic maturity in many regions, creating challenges for balanced wine production.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Coombe BG, McCarthy MG (2000) Dynamics of grape berry growth and physiology of ripening. Australian Journal of Grape and Wine Research 6:131-135|| Dai ZW et al. (2013) Ecophysiological, genetic, and molecular causes of variation in grape berry weight and composition: a review. American Journal of Enology and Viticulture 64:1-24"
  },
  "High_Sugar_Accumulation_Disposition": {
    "definition": "A sugar accumulation disposition that is the inherited capacity of a Vitis vinifera plant to achieve elevated berry sugar concentrations (typically exceeding 24°Brix) at harvest maturity, resulting from high source-sink ratio, efficient phloem transport, strong berry sink activity, and/or extended ripening period under favorable thermal conditions.",
    "alternative_term": "high Brix capacity | elevated sugar trait | high potential alcohol disposition |+ hohe Zuckerakkumulation | hohe Mostgewichte | starke Zuckereinlagerung",
    "example_of_usage": "Grenache exhibits high sugar accumulation disposition, routinely achieving 26-30°Brix in Mediterranean climates with potential alcohol of 15-17% v/v if fermented dry. ||Zinfandel shows similarly high accumulation (25-28°Brix) with characteristic raisinification of exposed berries further concentrating sugars. ||Muscat of Alexandria reaches 24-28°Brix in warm climates, supporting production of sweet fortified wines. ||High-sugar cultivars typically show large leaf area to fruit weight ratios (1.2-1.8 m²/kg), efficient VvHT (hexose transporter) expression in berry flesh, and sustained photosynthetic activity through late ripening. ||Sugar accumulation rates in high-capacity cultivars reach 0.25-0.35°Brix/day during peak ripening versus 0.15-0.20°Brix/day in moderate accumulators.",
    "editor_note": "High sugar accumulation disposition was historically valued for producing full-bodied wines and ensuring complete fermentation, but contemporary trends toward moderate alcohol wines have shifted preferences in some markets. ||The trait may create challenges when sugar ripeness outpaces phenolic and flavor maturity, a phenomenon increasingly common under climate warming. ||Management strategies including early harvest, crop load adjustment, and shading can moderate excessive sugar accumulation in genetically predisposed cultivars.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sadras VO, Moran MA (2012) Elevated temperature decouples anthocyanins and sugars in berries of Shiraz and Cabernet Franc. Australian Journal of Grape and Wine Research 18:115-122|| Palliotti A et al. (2014) Changes in vineyard establishment and canopy management urged by earlier climate-related grape ripening: a review. Scientia Horticulturae 178:43-54"
  },
  "Moderate_Sugar_Accumulation_Disposition": {
    "definition": "A sugar accumulation disposition that is the inherited capacity of a Vitis vinifera plant to achieve intermediate berry sugar concentrations (typically 20-24°Brix) at harvest maturity, enabling production of balanced wines with moderate alcohol levels while achieving adequate flavor and phenolic development.",
    "alternative_term": "balanced sugar capacity | moderate Brix trait | medium sugar accumulation |+ moderate Zuckerakkumulation | ausgeglichene Mostgewichte | mittlere Zuckereinlagerung",
    "example_of_usage": "Riesling exhibits moderate sugar accumulation disposition, typically reaching 20-23°Brix at optimal flavor maturity in cool climate regions, producing wines of 11-13% alcohol with pronounced varietal character. ||Pinot Noir in Burgundy achieves 21-24°Brix at harvest, balancing sugar with the 5-7 g/L acidity required for age-worthy red wine. ||Sauvignon Blanc in Marlborough ripens to 21-23°Brix while retaining the high acidity and thiol precursor content defining regional style. ||Moderate-sugar cultivars often show self-limiting sugar accumulation, with photosynthetic rate declining or sugar transport saturating before extreme concentrations are reached. ||The moderate accumulation trait facilitates harvest timing flexibility, as sugar progression slows above 22-23°Brix in these genotypes.",
    "editor_note": "Moderate sugar accumulation disposition aligns with contemporary consumer preferences for wines with lower alcohol and fresher flavor profiles. ||The trait provides winemakers with a larger harvest window, as the relationship between sugar and quality parameters remains favorable over a longer period. ||Climate change adaptation strategies increasingly emphasize cultivars with moderate sugar accumulation to maintain balanced wine styles without extreme management intervention.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Van Leeuwen C, Darriet P (2016) The impact of climate change on viticulture and wine quality. Journal of Wine Economics 11:150-167|| Duchêne E et al. (2012) Deciphering the ability of different grapevine genotypes to accumulate sugar in berries. Australian Journal of Grape and Wine Research 18:319-328"
  },
  "Hexose_Transporter_Activity_Disposition": {
    "definition": "A sugar accumulation disposition that is the inherited capacity of a Vitis vinifera plant to regulate hexose sugar import into ripening berries through the expression and activity of plasma membrane hexose transporter proteins (VvHT family), determining the rate and final extent of sugar accumulation by controlling the entry of glucose and fructose from phloem-unloaded apoplast into berry flesh parenchyma cells.",
    "alternative_term": "sugar transporter expression | VvHT activity trait | hexose import capacity |+ Hexose-Transporter-Aktivität | Zuckertransporter-Expression | VvHT-Aktivität",
    "example_of_usage": "Hexose transporter activity in grape berries increases 5-15 fold between veraison and maturity, with VvHT1 (high-affinity) and VvHT6 (low-affinity) being the predominant isoforms in ripening fruit. ||High-sugar cultivars such as Grenache show 2-3 fold higher VvHT transcript abundance than moderate-sugar cultivars such as Riesling at equivalent developmental stages. ||VvHT1 exhibits Km values of 0.1-0.3 mM for glucose, enabling efficient uptake at low apoplastic concentrations early in ripening, while VvHT6 (Km 2-5 mM) becomes increasingly important as sugar concentrations rise. ||Transporter activity is localized primarily in berry flesh cells, with highest expression in the peripheral mesocarp zone where most sugar storage occurs. ||Water deficit increases VvHT expression by 30-60%, contributing to sugar concentration under drought stress.",
    "editor_note": "Hexose transporter activity represents a key regulatory point for sugar accumulation, controlling the final step of sugar import into storage cells after phloem unloading. ||The trait shows genetic variation among cultivars and responds dynamically to developmental and environmental signals. ||Understanding transporter regulation has implications for both breeding (selection for modified accumulation) and management (stress effects on sugar loading). ||The shift from symplastic to apoplastic phloem unloading at veraison makes transporter activity essential for post-veraison sugar accumulation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Afoufa-Bastien D et al. (2010) The Vitis vinifera sugar transporter gene family: phylogenetic overview and macroarray expression profiling. BMC Plant Biology 10:245|| Hayes MA et al. (2007) Involvement of abscisic acid in the coordinated regulation of a stress-inducible hexose transporter (VvHT5) and a cell wall invertase in grapevine in response to biotrophic fungal infection. Plant Physiology 145:537-546"
  },
  "Acid_Metabolism_Disposition": {
    "definition": "A quality potential disposition that is the inherited capacity of a Vitis vinifera plant to synthesize, accumulate, and metabolize organic acids in grape berries, primarily tartaric and malic acid, determining the total acidity, pH, and acid balance that fundamentally influence wine freshness, microbial stability, color expression, and aging potential.",
    "alternative_term": "organic acid trait | berry acidity capacity | acid balance disposition |+ Säuremetabolismus | Säurehaushalt | organische Säuren-Disposition",
    "example_of_usage": "Organic acid composition in grape berries comprises primarily tartaric acid (2-10 g/L) and malic acid (1-8 g/L), with minor contributions from citric, succinic, and other acids. ||Total titratable acidity (TA) at harvest ranges from 4-12 g/L tartaric equivalents across cultivars and climates, with corresponding pH values of 2.9-4.0. ||Acid metabolism follows distinct patterns for each major acid, with tartaric acid synthesized primarily pre-veraison and remaining metabolically stable, while malic acid accumulates early then declines through respiratory degradation during ripening. ||The tartrate-to-malate ratio shifts from 1:2 at veraison to 2:1 or higher at harvest maturity in warm climates, while remaining near 1:1 in cool climates.",
    "editor_note": "Acid_Metabolism_Disposition serves as the parent class for specific organic acid accumulation and retention traits. ||Acidity is fundamental to wine quality, providing freshness, balancing sweetness, stabilizing color through pH effects on anthocyanin equilibria, and inhibiting microbial spoilage. ||The divergent metabolic fates of tartaric (stable) and malic (respirable) acids create the characteristic acid profile shifts during ripening. ||Climate, through temperature effects on malic acid respiration, exerts profound influence on final acid balance.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 369-385|| Sweetman C et al. (2014) Regulation of malate metabolism in grape berry and other developing fruits. Phytochemistry 99:1-16"
  },
  "Tartaric_Acid_Accumulation_Disposition": {
    "definition": "An acid metabolism disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate tartaric acid in grape berries through the ascorbic acid pathway, with genotype-specific concentrations determined by biosynthetic enzyme activity during early berry development and the absence of significant catabolic pathways in Vitis.",
    "alternative_term": "tartrate synthesis capacity | tartaric acid trait | L-tartrate accumulation |+ Weinsäureakkumulation | Tartratbildung | Weinsäure-Disposition",
    "example_of_usage": "Tartaric acid accumulation occurs primarily during the green berry stage (pre-veraison), with synthesis essentially complete by veraison and concentrations of 5-15 g/L fresh weight in immature berries declining through dilution to 4-10 g/L at harvest. ||Cultivar differences in final tartrate concentration span 2-fold, with Riesling and Chenin Blanc showing high tartrate (7-10 g/L) and Grenache and Carignan showing lower values (4-6 g/L). ||The biosynthetic pathway proceeds from L-ascorbic acid through L-idonic acid to L-tartaric acid, with L-idonate dehydrogenase (VvLIdnDH) being a key regulatory enzyme. ||Unlike malic acid, tartaric acid is not metabolized during ripening, making it the stable backbone of grape and wine acidity.",
    "editor_note": "Tartaric acid is nearly unique to grapes among major fruit crops, providing the distinctive acid character of wine. ||The metabolic stability of tartrate (no respiratory degradation) makes it the reliable acidity component independent of ripening temperature, while malic acid varies with climate. ||Tartrate concentration at harvest depends primarily on synthesis rate during early development and subsequent dilution by berry expansion. ||Potassium bitartrate precipitation during winemaking can reduce effective tartrate contribution to wine acidity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "DeBolt S et al. (2006) L-Tartaric acid synthesis from vitamin C in higher plants. Proceedings of the National Academy of Sciences 103:5608-5613|| Ford CM (2012) The biochemistry of organic acids in the grape. In: Gerós H et al. (eds) The Biochemistry of the Grape Berry, Bentham Science pp.: 67-88"
  },
  "Malic_Acid_Accumulation_Disposition": {
    "definition": "An acid metabolism disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate malic acid in grape berries through phosphoenolpyruvate carboxylase (PEPC) activity and the citric acid cycle, with genotype-specific peak concentrations reached at or shortly after veraison before respiratory degradation during ripening.",
    "alternative_term": "malate synthesis capacity | malic acid trait | L-malate accumulation |+ Äpfelsäureakkumulation | Malatbildung | Äpfelsäure-Disposition",
    "example_of_usage": "Malic acid accumulation peaks at or shortly after veraison with concentrations of 15-25 g/L fresh weight in developing berries, subsequently declining to 1-8 g/L at harvest depending on cultivar and ripening temperature. ||High-malate cultivars such as Barbera and Colombard maintain 5-8 g/L malate at harvest even in warm climates, while low-malate types such as Chasselas and Palomino decline to 1-3 g/L. ||PEPC activity in green berries fixes respiratory CO₂ into oxaloacetate, which is reduced to malate by malate dehydrogenase (MDH) for vacuolar storage. ||Pre-veraison malate accumulation provides respiratory substrate for post-veraison berry metabolism and contributes to osmotic sugar accumulation through malate-sugar exchange across the tonoplast.",
    "editor_note": "Malic acid accumulation establishes the reservoir that will be subsequently depleted during ripening, with the balance between accumulation capacity and degradation rate determining final malate concentration. ||The trait shows moderate heritability (h² = 0.45-0.60) and significant genotype × environment interaction. ||High malate accumulation provides potential for maintaining acidity in warm climates if combined with low degradation rate, a breeding target for climate change adaptation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sweetman C et al. (2014) Regulation of malate metabolism in grape berry and other developing fruits. Phytochemistry 99:1-16|| Ruffner HP (1982) Metabolism of tartaric and malic acids in Vitis: a review, Part B. Vitis 21:346-358"
  },
  "Malic_Acid_Degradation_Disposition": {
    "definition": "An acid metabolism disposition that is the inherited capacity of a Vitis vinifera plant to catabolize malic acid in ripening grape berries through mitochondrial respiration and gluconeogenesis, with genotype-specific degradation rates determined by malic enzyme activity, mitochondrial density, and respiratory demand during the post-veraison period.",
    "alternative_term": "malate respiration capacity | malic acid breakdown | malate catabolism trait |+ Äpfelsäureabbau | Malatrespiration | Äpfelsäure-Degradation",
    "example_of_usage": "Malic acid degradation during ripening follows first-order kinetics with rate constants (k) ranging from 0.02-0.08 per day across cultivars, resulting in 50-90% malate loss between veraison and harvest over 40-60 days. ||Temperature exerts profound influence, with degradation rates doubling for each 10°C increase (Q₁₀ of 1.8-2.2) above the base temperature of approximately 10°C. ||Grenache shows rapid malate degradation (k = 0.06-0.08/day, 80-90% loss) while Riesling shows slow degradation (k = 0.02-0.03/day, 50-65% loss) under equivalent temperature conditions. ||The cytosolic NADP-malic enzyme (VvNADP-ME) decarboxylates malate to pyruvate, which enters mitochondrial respiration or gluconeogenic conversion to sugars (contributing 5-15% of berry sugar at maturity).",
    "editor_note": "Malic acid degradation is the primary mechanism by which climate affects grape acidity, as warm ripening temperatures accelerate respiration and gluconeogenesis of stored malate. ||The trait creates the characteristic acid profile differences between cool climate wines (high malate retention, fresh acidity) and warm climate wines (low malate, softer acidity). ||Breeding for reduced malate degradation rate is a strategy for maintaining acidity under warming conditions. ||Night temperature is particularly important, as high night temperatures sustain respiration that cool nights would suppress.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sweetman C et al. (2009) Transcriptome analysis at four developmental stages of grape berry (Vitis vinifera cv. Shiraz) provides insights into regulated and coordinated gene expression. BMC Genomics 10:648|| Lakso AN, Kliewer WM (1975) The influence of temperature on malic acid metabolism in grape berries. Plant Physiology 56:370-372"
  },
  "Acidity_Retention_Disposition": {
    "definition": "An acid metabolism disposition that is the inherited capacity of a Vitis vinifera plant to maintain total titratable acidity and low pH in berries through harvest maturity, determined by the combined effects of tartaric acid concentration, malic acid degradation rate, potassium accumulation (affecting pH), and berry water relations affecting acid concentration.",
    "alternative_term": "acid preservation capacity | acidity maintenance | TA retention trait |+ Säureretention | Säureerhalt | Azidität-Bewahrung",
    "example_of_usage": "Acidity retention at harvest varies from 4-5 g/L TA (pH 3.6-4.0) in warm climate, low-retention cultivars to 9-12 g/L TA (pH 2.9-3.2) in cool climate, high-retention types. ||Cultivar effects on retention are substantial, with Barbera maintaining 7-9 g/L TA in warm Italian climates while Chasselas in the same region shows only 4-5 g/L. ||Retention reflects the net balance of stable tartrate concentration, residual malate after degradation, and dilution or concentration effects from berry water status. ||Potassium accumulation independently affects pH (higher K raises pH at equivalent TA) through titration of organic acids to their potassium salts. ||The TA/pH relationship varies among cultivars, with high-retention types showing lower pH at equivalent TA due to higher tartrate/malate ratios.",
    "editor_note": "Acidity_Retention_Disposition serves as the parent class for high and low retention categories. ||Retention integrates multiple underlying processes affecting final acidity, making it a complex trait with moderate heritability but strong environmental modulation. ||The distinction between TA (total titratable acid, measuring acid quantity) and pH (measuring hydrogen ion activity) is important, as potassium effects can decouple these parameters. ||Wine style requirements vary in acidity targets, with sparkling wines requiring high retention and some red styles tolerating lower acidity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 378-385|| Volschenk H et al. (2006) Malic acid in wine: origin, function and metabolism during vinification. South African Journal of Enology and Viticulture 27:123-136"
  },
  "High_Acidity_Retention_Disposition": {
    "definition": "An acidity retention disposition that is the inherited capacity of a Vitis vinifera plant to maintain elevated titratable acidity (typically greater than 7 g/L) and low pH (below 3.3) at harvest maturity, through combinations of high tartrate concentration, slow malic acid degradation, moderate potassium accumulation, and/or genetic buffering against temperature-induced acid loss.",
    "alternative_term": "high acid retention | acid-preserving trait | low pH disposition |+ hohe Säureretention | Säureerhalt | hohe Azidität-Bewahrung",
    "example_of_usage": "Riesling exhibits high acidity retention disposition, maintaining 7-10 g/L TA and pH 3.0-3.2 at flavor maturity in German wine regions, with the combination of high tartrate (7-9 g/L) and slow malate degradation (k = 0.02-0.03/day) preserving acidity. ||Barbera retains 7-9 g/L TA even in warm Piedmont climates through exceptionally slow malate degradation despite moderate tartrate levels, enabling production of high-acid red wines. ||Chenin Blanc in the Loire Valley maintains 8-11 g/L TA with pH 3.0-3.3, supporting both dry and sweet wine styles requiring prominent acidity. ||High-retention cultivars typically show 20-40% higher residual malate at equivalent thermal time from veraison compared to low-retention types.",
    "editor_note": "High acidity retention disposition is essential for cool climate viticulture where crisp acidity defines wine style, and increasingly valuable for warm climate adaptation where maintaining freshness is challenging. ||The trait enables extended hang time for flavor development without excessive acid loss, expanding the harvest window. ||High-retention cultivars provide base material for sparkling wine production requiring TA above 8-9 g/L. ||Selection for high retention is complicated by the multiple contributing mechanisms and genotype × environment interaction.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Duchêne E et al. (2014) Genetic variability of descriptors for grapevine berry acidity in Riesling, Gewürztraminer and their progeny. Australian Journal of Grape and Wine Research 20:91-99|| Martinez de Toda F, Balda P (2015) Quantifying the effect of temperature on decoupling anthocyanins and sugars of the grape (Vitis vinifera L. cv. Maturana Tinta de Navarrete). Vitis 54:117-120"
  },
  "Low_Acidity_Retention_Disposition": {
    "definition": "An acidity retention disposition that is the inherited capacity of a Vitis vinifera plant to exhibit reduced titratable acidity (typically below 5 g/L) and elevated pH (above 3.6) at harvest maturity, through combinations of lower tartrate concentration, rapid malic acid degradation, high potassium accumulation, and/or sensitivity to temperature-induced acid loss.",
    "alternative_term": "low acid retention | acid-depleting trait | high pH disposition |+ niedrige Säureretention | geringer Säureerhalt | niedrige Azidität-Bewahrung",
    "example_of_usage": "Grenache exhibits low acidity retention disposition, declining to 4-5 g/L TA and pH 3.6-3.9 under warm Mediterranean conditions through rapid malate degradation (k = 0.06-0.08/day) combined with moderate tartrate (5-6 g/L). ||Chasselas shows low retention with harvest acidity of 4-6 g/L TA even in Swiss climates, attributed to moderate tartrate and rapid malate loss. ||Palomino (Sherry grape) reaches pH 3.8-4.2 with TA 3-4 g/L in Jerez, suited to the oxidative winemaking style requiring low acidity. ||Low-retention cultivars often show 2-3 fold higher malic enzyme activity than high-retention types, accelerating respiratory malate loss.",
    "editor_note": "Low acidity retention disposition suits wine styles where softness and roundness are preferred over crisp freshness, including certain Mediterranean reds and fortified wine bases. ||The trait becomes problematic when pH rises above 3.8-4.0, increasing microbial spoilage risk and reducing color stability in red wines through anthocyanin equilibrium shifts. ||Acidification during winemaking can partially compensate but may affect wine character. ||Climate warming is shifting some traditionally balanced cultivars toward low-retention phenotypes, requiring management adaptation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M et al. (2010) Interactive effects of deficit irrigation and crop load on Cabernet Sauvignon in an arid climate. American Journal of Enology and Viticulture 61:221-233|| Mpelasoka BS et al. (2003) A review of potassium nutrition in grapevines with special emphasis on berry accumulation. Australian Journal of Grape and Wine Research 9:154-168"
  },
  "Phenolic_Compound_Disposition": {
    "definition": "A quality potential disposition that is the inherited capacity of a Vitis vinifera plant to synthesize, accumulate, and modify phenolic compounds in grape berries, encompassing flavonoid pathways (anthocyanins, tannins, flavonols) and non-flavonoid pathways (hydroxycinnamic acids, stilbenes) that determine wine color, astringency, bitterness, antioxidant capacity, and aging potential.",
    "alternative_term": "phenolic synthesis capacity | polyphenol trait | phenolic accumulation disposition |+ Phenolstoffwechsel | Polyphenol-Disposition | phenolische Verbindungen",
    "example_of_usage": "Total phenolic content in grape berries ranges from 200-500 mg/100g fresh weight in white cultivars to 800-2500 mg/100g in red cultivars, with anthocyanins (100-1500 mg/100g skins), proanthocyanidins (100-800 mg/100g skins and seeds), and flavonols (10-100 mg/100g) as major flavonoid classes. ||Cultivar differences in phenolic profiles are substantial, with Tannat producing 2-3× higher total phenolics than Pinot Noir under equivalent conditions. ||The phenylpropanoid pathway converts phenylalanine to p-coumaroyl-CoA, which enters branching pathways toward flavonoids (via chalcone synthase) or stilbenes (via stilbene synthase). ||Phenolic extractability into wine ranges from 20-60% depending on compound class, berry maturity, and winemaking technique.",
    "editor_note": "Phenolic_Compound_Disposition serves as the parent class for specific phenolic compound categories. ||Phenolics are the primary determinants of red wine color and structure, while also contributing to white wine complexity and stability. ||The trait complex shows strong genotype effects overlaid with substantial environmental and management modulation. ||Climate, water status, light exposure, and ripeness stage all influence phenolic accumulation and composition, creating the foundation for terroir expression in wine phenolic profiles.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kennedy JA (2008) Grape and wine phenolics: observations and recent findings. Ciencia e Investigación Agraria 35:107-120|| Teixeira A et al. (2013) Berry phenolics of grapevine under challenging environments. International Journal of Molecular Sciences 14:18711-18739"
  },
  "Anthocyanin_Accumulation_Disposition": {
    "definition": "A phenolic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate anthocyanin pigments in grape berry skins through the flavonoid pathway, with genotype-specific total concentration, anthocyanin profile (relative proportions of individual anthocyanins), and modification patterns (glycosylation, acylation) determining red wine color intensity, hue, and stability.",
    "alternative_term": "anthocyanin synthesis capacity | grape color trait | pigment accumulation disposition |+ Anthocyanakkumulation | Farbstoffbildung | Anthocyan-Disposition",
    "example_of_usage": "Anthocyanin concentration in red grape skins ranges from 200-400 mg/100g in lightly colored cultivars such as Pinot Noir to 1500-2500 mg/100g in deeply colored types such as Tannat and Alicante Bouschet. ||Five anthocyanidin aglycones occur in V. vinifera, differing in B-ring hydroxylation and methoxylation pattern, with 3-O-glucoside and 3-O-acylglucoside conjugates predominating. ||Anthocyanin biosynthesis begins at veraison with coordinated upregulation of VvUFGT (UDP-glucose:flavonoid 3-O-glucosyltransferase), VvMYBA1/A2 transcription factors, and structural genes. ||Accumulation peaks 2-4 weeks post-veraison, with concentration subsequently declining through degradation and dilution, losing 20-40% between peak and harvest in warm climates.",
    "editor_note": "Anthocyanin_Accumulation_Disposition serves as the parent class for specific anthocyanin type and concentration traits. ||Anthocyanins are the sole pigments responsible for red grape and wine color, with their chemistry fundamentally affecting color expression. ||The trait shows high heritability (h² = 0.70-0.85) for total concentration but also strong environmental modulation, particularly by temperature and light. ||The VvMYBA1/A2 locus is the major genetic determinant, with white-fruited cultivars carrying non-functional alleles.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Boss PK et al. (1996) Expression of anthocyanin biosynthesis pathway genes in red and white grapes. Plant Molecular Biology 32:565-569|| Castellarin SD, Di Gaspero G (2007) Transcriptional control of anthocyanin biosynthetic genes in extreme phenotypes for berry pigmentation of naturally occurring grapevines. BMC Plant Biology 7:46"
  },
  "Malvidin_Dominance_Disposition": {
    "definition": "An anthocyanin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate malvidin-based anthocyanins (malvidin-3-O-glucoside and its acylated derivatives) as the predominant pigment class, typically comprising 40-90% of total anthocyanins due to high flavonoid 3',5'-hydroxylase (F3'5'H) and O-methyltransferase (OMT) activity.",
    "alternative_term": "malvidin predominance | tri-substituted anthocyanin trait | malvidin-type pigmentation |+ Malvidin-Dominanz | Malvidinprävalenz | Malvidin-Vorherrschaft",
    "example_of_usage": "Malvidin-3-O-glucoside predominates in most V. vinifera cultivars, comprising 50-90% of total anthocyanins in Cabernet Sauvignon (60-75%), Merlot (55-70%), Syrah (45-60%), and Tempranillo (40-55%). ||Malvidin accumulation requires sequential activity of F3'5'H (converting dihydrokaempferol to dihydromyricetin), DFR, ANS, UFGT, and finally OMT (O-methyltransferase) for the two methoxy groups on the B-ring. ||The 3',5'-disubstituted, di-methoxylated structure of malvidin confers blue-shifted color (λmax 520-535 nm versus 506-513 nm for cyanidin) and enhanced stability against oxidation and pH-induced color loss. ||Wine color derived from malvidin-dominant grapes shows characteristic purple-red hues that evolve toward brick-red with aging through anthocyanin-tannin polymerization.",
    "editor_note": "Malvidin dominance is characteristic of V. vinifera and distinguishes it from most hybrid cultivars that show higher cyanidin proportions. ||The trait results from the coordinated expression of F3'5'H (directing flux toward delphinidin pathway) and OMT (methylating to petunidin and malvidin). ||Malvidin-based anthocyanins show greater color stability than cyanidin-based forms, contributing to the superior aging potential of V. vinifera wines. ||The relative proportion of malvidin versus other anthocyanins is used in authenticity testing to detect hybrid blending.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mattivi F et al. (2006) Metabolite profiling of grape: flavonols and anthocyanins. Journal of Agricultural and Food Chemistry 54:7692-7702|| Castellarin SD et al. (2006) Colour variation in red grapevines (Vitis vinifera L.): genomic organisation, expression of flavonoid 3'-hydroxylase, flavonoid 3',5'-hydroxylase genes and related metabolite profiling of red cyanidin-/blue delphinidin-based anthocyanins in berry skin. BMC Genomics 7:12"
  },
  "Cyanidin_Accumulation_Disposition": {
    "definition": "An anthocyanin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate cyanidin-based anthocyanins (cyanidin-3-O-glucoside and derivatives) as a significant proportion of total pigments, resulting from elevated flavonoid 3'-hydroxylase (F3'H) activity relative to F3'5'H and producing red-orange hue contributions to wine color.",
    "alternative_term": "cyanidin content trait | di-hydroxylated anthocyanin | cyanidin-type pigmentation |+ Cyanidin-Akkumulation | Cyanidingehalt | Cyanidin-Einlagerung",
    "example_of_usage": "Cyanidin-3-O-glucoside typically comprises 2-15% of total anthocyanins in most V. vinifera cultivars, but reaches elevated proportions (15-35%) in specific genotypes including Sangiovese, Nebbiolo, and Pinot Noir. ||The cyanidin pathway branches from dihydroquercetin via DFR and ANS without F3'5'H involvement, with F3'H converting dihydrokaempferol to dihydroquercetin. ||Cyanidin shows λmax of 506-513 nm, contributing orange-red hues distinct from the purple-blue of malvidin derivatives. ||The 3',4'-dihydroxylated B-ring of cyanidin lacks the methoxy groups that stabilize malvidin, resulting in faster color loss under oxidative conditions. ||Sangiovese wines owe their characteristic bright ruby-red color partly to elevated cyanidin proportions.",
    "editor_note": "Cyanidin accumulation represents the alternative branch of the anthocyanin pathway competing with malvidin synthesis for common precursors. ||The F3'H/F3'5'H expression ratio largely determines the cyanidin/malvidin balance, with cultivar-specific regulatory patterns established early in berry development. ||Elevated cyanidin is characteristic of some traditional Italian cultivars (Sangiovese, Nebbiolo) and contributes to their distinctive color profiles. ||The lower stability of cyanidin-based color may contribute to the faster color evolution observed in wines from these cultivars.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mattivi F et al. (2006) Metabolite profiling of grape: flavonols and anthocyanins. Journal of Agricultural and Food Chemistry 54:7692-7702|| Rinaldi A et al. (2020) Metabolic and RNA profiling elucidates proanthocyanidins accumulation in Aglianico grape. Food Chemistry 312:126045"
  },
  "Peonidin_Accumulation_Disposition": {
    "definition": "An anthocyanin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate peonidin-based anthocyanins (peonidin-3-O-glucoside and derivatives) through O-methylation of cyanidin, contributing red-magenta hues and representing an intermediate methylation state between cyanidin and malvidin in the anthocyanin profile.",
    "alternative_term": "peonidin content trait | mono-methoxylated anthocyanin | peonidin-type pigmentation |+ Peonidin-Akkumulation | Peonidingehalt | Peonidin-Einlagerung",
    "example_of_usage": "Peonidin-3-O-glucoside typically comprises 5-20% of total anthocyanins in V. vinifera cultivars, with elevated proportions (15-30%) in Primitivo (Zinfandel), Tempranillo, and Pinot Noir. ||Peonidin formation requires O-methyltransferase (VvOMT) activity on cyanidin, adding a single methoxy group at the 3' position of the B-ring. ||The mono-methoxylated structure produces λmax of 508-518 nm, intermediate between cyanidin (506-513 nm) and malvidin (520-535 nm). ||Peonidin shows intermediate stability between the highly labile cyanidin and the more stable malvidin, contributing to red-magenta hues in young wines. ||The peonidin/cyanidin ratio reflects OMT activity in the di-hydroxylated anthocyanin branch, analogous to the petunidin/delphinidin and malvidin/petunidin ratios in the tri-hydroxylated branch.",
    "editor_note": "Peonidin accumulation represents the methylated form of the cyanidin pathway, providing an intermediate color and stability profile. ||The trait depends on both F3'H activity (producing the cyanidin precursor) and OMT activity (methylating to peonidin). ||Cultivars with elevated peonidin often show elevated cyanidin as well, reflecting generally high F3'H pathway flux. ||The peonidin proportion is used alongside other anthocyanin ratios for cultivar identification and wine authentication.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fournier-Level A et al. (2011) Quantitative trait loci analysis of anthocyanin content in Vitis vinifera L. grape berries. Journal of Experimental Botany 62:1043-1051|| De Rosso M et al. (2012) Changes in grape polyphenols (V. vinifera L.) as a consequence of post-harvest withering by high-resolution mass spectrometry. Postharvest Biology and Technology 67:102-109"
  },
  "Acylated_Anthocyanin_Disposition": {
    "definition": "An anthocyanin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to modify anthocyanin-3-O-glucosides through acylation with hydroxycinnamic acids (p-coumaric, caffeic, acetic) at the 6-position of the glucose moiety, with genotype-specific acylation proportions affecting anthocyanin stability, color expression, and copigmentation behavior.",
    "alternative_term": "anthocyanin acylation trait | acyl-glucoside proportion | hydroxycinnamic acid conjugation |+ Acylierte Anthocyane | Anthocyan-Acylierung | Acylglucosid-Disposition",
    "example_of_usage": "Acylated anthocyanins comprise 10-65% of total anthocyanins across V. vinifera cultivars, with high-acylation types such as Syrah (50-65% acylated), Mourvèdre (45-60%), and Grenache (40-55%) contrasting with low-acylation cultivars such as Pinot Noir (5-15%) and Sangiovese (10-20%). ||The anthocyanin acyltransferase (VvAT) catalyzes transfer of acyl groups from hydroxycinnamoyl-CoA donors to the 6-O-position of the glucose. p-Coumaroyl derivatives predominate in most cultivars, with caffeic and acetic acid conjugates as minor forms. ||Acylation shifts λmax by 5-15 nm, increases molar extinction coefficient by 10-20%, and enhances color stability through intramolecular copigmentation (the acyl group stacking with the chromophore). ||Acylated anthocyanins show 30-50% slower degradation rates than non-acylated forms under equivalent storage conditions.",
    "editor_note": "Acylated anthocyanin proportion significantly affects wine color stability and intensity, with high-acylation cultivars retaining color better during aging. ||The trait shows high heritability (h² = 0.75-0.85) and relatively low environmental modulation compared to total anthocyanin concentration. ||Acylation pattern is used as a chemotaxonomic marker for cultivar identification and hybrid detection, as American Vitis species and their hybrids typically show different acylation patterns than pure V. vinifera. ||The intramolecular copigmentation provided by acylation partially substitutes for intermolecular copigmentation with other phenolics.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Rinaldo AR et al. (2015) A grapevine anthocyanin acyltransferase, transcriptionally regulated by VvMYBA, can produce most acylated anthocyanins present in grape skins. Plant Physiology 169:1897-1916|| García-Beneytez E et al. (2003) Analysis of grape and wine anthocyanins by HPLC-MS. Journal of Agricultural and Food Chemistry 51:5622-5629"
  },
  "Skin_Anthocyanin_Concentration_Disposition": {
    "definition": "An anthocyanin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to achieve specific total anthocyanin concentrations in grape berry skin tissue at harvest maturity, determined by biosynthetic rate, vacuolar storage capacity, degradation rate, and skin cell density, directly affecting potential wine color intensity.",
    "alternative_term": "skin color intensity | anthocyanin content trait | pigment concentration disposition |+ Beerenhaut-Anthocyankonzentration | Schalenanthocyangehalt | Farbstoffkonzentration",
    "example_of_usage": "Skin anthocyanin concentration at harvest ranges from 200-500 mg/100g fresh weight skins in lightly pigmented cultivars such as Pinot Noir and Grenache to 1200-2500 mg/100g in deeply colored types such as Tannat, Alicante Bouschet, and Petite Sirah. ||Cabernet Sauvignon and Merlot show intermediate concentrations of 600-1000 mg/100g under favorable conditions. ||Concentration is determined by both anthocyanin per cell (vacuolar loading) and cells per unit skin area (hypodermal cell layers, typically 2-6 layers containing anthocyanins). ||Wine color extraction of 30-60% of skin anthocyanins produces young wine concentrations of 200-1500 mg/L depending on cultivar and maceration technique. ||Skin anthocyanin concentration shows heritability of h² = 0.65-0.80 with substantial environmental modulation by temperature, light exposure, and water status.",
    "editor_note": "Skin anthocyanin concentration is the primary determinant of potential wine color intensity, integrating biosynthetic capacity with the anatomical and developmental factors affecting pigment density in skin tissue. ||The trait differs from total berry anthocyanin, as skin thickness and cell density vary independently of biosynthetic rate. ||Climate change is negatively affecting skin anthocyanin concentration in many regions through high temperature inhibition of biosynthesis and accelerated degradation. ||Selection for high concentration combined with temperature tolerance is a breeding priority for warm climate viticulture.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Roby G et al. (2004) Berry size and vine water deficits as factors in winegrape composition: anthocyanins and tannins. Australian Journal of Grape and Wine Research 10:100-107|| Sadras VO, Moran MA (2012) Elevated temperature decouples anthocyanins and sugars in berries of Shiraz and Cabernet Franc. Australian Journal of Grape and Wine Research 18:115-122"
  },
  "Tannin_Accumulation_Disposition": {
    "definition": "A phenolic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate proanthocyanidins (condensed tannins) in grape berry skins and seeds through the flavonoid pathway, with genotype-specific total concentration, polymer size distribution, and subunit composition determining wine astringency, bitterness, mouthfeel, color stability, and aging potential.",
    "alternative_term": "proanthocyanidin synthesis | condensed tannin trait | PA accumulation disposition |+ Tanninakkumulation | Proanthocyanidin-Bildung | Gerbstoff-Disposition",
    "example_of_usage": "Tannin concentration in grape berries ranges from 1-6 mg/berry across cultivars, with skins contributing 20-40% and seeds 60-80% of total berry tannin in most genotypes. ||Cultivar differences span 3-4 fold, with high-tannin types such as Tannat (4-6 mg/berry) and Nebbiolo (3-5 mg/berry) contrasting with low-tannin cultivars such as Gamay (1-2 mg/berry) and Pinot Noir (1.5-2.5 mg/berry). ||Proanthocyanidin biosynthesis involves leucoanthocyanidin reductase (VvLAR) producing catechin units and anthocyanidin reductase (VvANR) producing epicatechin units, with polymerization extending chains to 3-80+ subunits. ||Tannin accumulation in skins begins pre-veraison, peaks at veraison, then remains stable, while seed tannin accumulates earlier and declines post-veraison through oxidative polymerization.",
    "editor_note": "Tannin_Accumulation_Disposition serves as the parent class for specific tannin location, polymerization, and extractability traits. ||Tannins are essential for red wine structure, aging capacity, and color stabilization through anthocyanin-tannin polymerization. ||The trait shows moderate heritability (h² = 0.50-0.70) with significant environmental modulation by water status, light exposure, and temperature. ||Winemaking practices (maceration time, temperature, pressing) strongly affect tannin extraction from the genetically determined berry pool.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kennedy JA et al. (2001) Composition of grape skin proanthocyanidins at different stages of berry development. Journal of Agricultural and Food Chemistry 49:5348-5355|| Bogs J et al. (2005) Proanthocyanidin synthesis and expression of genes encoding leucoanthocyanidin reductase and anthocyanidin reductase in developing grape berries and grapevine leaves. Plant Physiology 139:652-663"
  },
  "Skin_Tannin_Disposition": {
    "definition": "A tannin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate proanthocyanidins specifically in the hypodermal cell layers of grape berry skins, with genotype-specific concentration, polymer length (typically longer than seed tannins), and subunit composition (higher proportion of epigallocatechin) contributing softer, less astringent tannin character.",
    "alternative_term": "skin proanthocyanidin | exocarp tannin trait | skin condensed tannin |+ Schalentannin | Beerenhaut-Proanthocyanidin | Exokarp-Gerbstoff",
    "example_of_usage": "Skin tannin concentration ranges from 0.3-2.0 mg/berry across cultivars, comprising 20-50% of total berry tannin depending on genotype and ripeness stage. ||High skin tannin cultivars such as Cabernet Sauvignon (1.2-2.0 mg/berry) and Tannat (1.5-2.5 mg/berry) contrast with lower skin tannin types like Merlot (0.8-1.2 mg/berry) and Pinot Noir (0.4-0.8 mg/berry). ||Skin proanthocyanidins show higher mean degree of polymerization (mDP 15-40) than seed tannins (mDP 3-12), contributing less astringent, more rounded mouthfeel. ||The prodelphindin content (epigallocatechin subunits) reaches 15-35% in skin tannins versus <5% in seeds, with trihydroxylated subunits conferring reduced astringency perception. ||Skin tannin extractability increases during ripening as cell walls soften, reaching 40-70% extraction during extended maceration.",
    "editor_note": "Skin tannin contributes the preferred \"soft\" tannin character in wine, with longer polymers and higher prodelphindin content creating less aggressive astringency than seed tannins. ||The trait shows independent genetic control from seed tannin, enabling selection for modified skin/seed tannin ratios. ||Skin tannins also provide sites for anthocyanin incorporation into polymeric pigments during winemaking and aging, contributing to color stability. ||Water deficit during ripening increases skin tannin concentration through both enhanced synthesis and berry size reduction effects.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Downey MO et al. (2003) Analysis of tannins in seeds and skins of Shiraz grapes throughout berry development. Australian Journal of Grape and Wine Research 9:15-27|| Bindon KA et al. (2014) Relationships between harvest time and wine composition in Vitis vinifera L. cv. Cabernet Sauvignon. 1. Grape and wine chemistry. Food Chemistry 146:253-263"
  },
  "Seed_Tannin_Disposition": {
    "definition": "A tannin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate proanthocyanidins in grape seed integuments (testa and tegmen), with genotype-specific concentration, shorter polymer length than skin tannins, and higher galloylation producing more astringent, bitter tannin character when extracted into wine.",
    "alternative_term": "seed proanthocyanidin | seed coat tannin trait | seed condensed tannin |+ Kerntannin | Samenproanthocyanidin | Samen-Gerbstoff",
    "example_of_usage": "Seed tannin concentration ranges from 1-5 mg/berry across cultivars, typically comprising 50-80% of total berry tannin content. ||High seed tannin cultivars such as Cabernet Sauvignon (3-5 mg/berry for 2-4 seeds) and Mourvèdre (2.5-4 mg/berry) contrast with seedless or low-seed cultivars. ||Individual seed tannin content of 0.8-1.5 mg/seed is relatively consistent across cultivars, making seed number the primary determinant of total seed tannin. ||Seed proanthocyanidins show lower mDP (3-12 subunits) than skin tannins, with 20-40% galloylation (gallic acid esterification at the 3-position) versus 3-8% in skins. ||Seed tannin biosynthesis peaks 4-6 weeks post-flowering, with subsequent oxidative browning and decreased extractability as seeds lignify post-veraison. ||Extraction into wine requires extended maceration (>14 days) and/or mechanical seed damage.",
    "editor_note": "Seed tannin represents the majority of berry tannin in most cultivars but requires careful extraction management to avoid excessive astringency and bitterness from the shorter, more galloylated polymers. ||The trait shows high heritability for concentration per seed, with total seed tannin determined primarily by seed number per berry. ||Seed maturity (brown color, reduced extractability) is used as a harvest indicator, with \"green\" seed tannins producing harsher wine character. ||Climate effects on seed tannin are less pronounced than for skin tannins, as seed development largely precedes the ripening period.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Kennedy JA et al. (2000) Grape seed proanthocyanidins and their structural units. Phytochemistry 55:77-85|| Cadot Y et al. (2006) Flavan-3-ol compositional changes in grape berries (Vitis vinifera L. cv Cabernet Franc) before veraison, using two complementary analytical approaches, HPLC reversed phase and histochemistry. Analytica Chimica Acta 563:159-170"
  },
  "Tannin_Polymerization_Disposition": {
    "definition": "A tannin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to produce proanthocyanidin polymers of characteristic chain length (mean degree of polymerization, mDP), with genotype-specific polymer size distributions affecting astringency intensity, astringency quality, and protein precipitation capacity of extracted tannins.",
    "alternative_term": "PA polymer length | tannin chain length trait | proanthocyanidin mDP disposition |+ Tanninpolymerisation | Polymerisationsgrad | Kettenlängen-Disposition",
    "example_of_usage": "Mean degree of polymerization (mDP) ranges from 5-50 subunits across tannin sources in grape berries, with skin tannins showing mDP 15-40 versus seed tannins mDP 3-12. ||Cultivar differences in skin tannin mDP range from 15-20 in shorter-polymer types such as Pinot Noir to 30-45 in longer-polymer cultivars such as Cabernet Sauvignon and Tannat. ||Polymerization occurs through oxidative coupling of flavan-3-ol units via 4→8 or 4→6 interflavan bonds, with chain extension continuing in vacuolar storage. ||Longer polymers (mDP >20) show reduced astringency per unit mass due to steric constraints on protein binding, producing \"softer\" mouthfeel despite higher total tannin. ||The polymer size distribution (polydispersity) affects astringency character, with narrow distributions producing more uniform sensory response.",
    "editor_note": "Tannin polymerization degree directly affects the sensory quality of wine tannins, with the relationship between polymer size and astringency following an inverted U-curve (maximum astringency at intermediate mDP 8-15). ||The trait shows moderate heritability with developmental and environmental modulation, as polymerization continues during berry maturation and can be affected by oxidative conditions. ||Understanding polymerization enables interpretation of total tannin concentration in relation to sensory outcomes, as high concentration with high mDP may produce less astringency than moderate concentration with intermediate mDP.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Vidal S et al. (2003) The mouth-feel properties of grape and apple proanthocyanidins in a wine-like medium. Journal of the Science of Food and Agriculture 83:564-573|| Kennedy JA, Jones GP (2001) Analysis of proanthocyanidin cleavage products following acid-catalysis in the presence of excess phloroglucinol. Journal of Agricultural and Food Chemistry 49:1740-1746"
  },
  "Tannin_Extractability_Disposition": {
    "definition": "A tannin accumulation disposition that is the inherited capacity of a Vitis vinifera plant to produce grape berry tannins with genotype-specific ease of extraction into wine during maceration, determined by cell wall composition, tannin-cell wall binding strength, and the developmental changes in extractability that occur during ripening.",
    "alternative_term": "tannin release capacity | PA extractability trait | tannin accessibility disposition |+ Tanninextrahierbarkeit | Gerbstoff-Freisetzung | Extraktions-Disposition",
    "example_of_usage": "Tannin extractability varies 2-3 fold among cultivars under equivalent maceration conditions, with high-extractability types such as Syrah and Mourvèdre releasing 50-70% of berry tannin versus low-extractability cultivars like Pinot Noir releasing 25-40%. ||Extractability increases during ripening as pectin degradation and cell wall loosening reduce tannin-polysaccharide binding, with skin tannin extractability rising from 20-30% at veraison to 50-70% at maturity. ||Seed tannin extractability conversely decreases during ripening from 60-80% at veraison to 15-30% at harvest as seed coat lignification and oxidative polymerization reduce permeability. ||The tannin-to-anthocyanin extraction ratio ranges from 1:1 to 3:1 depending on cultivar and maceration conditions, affecting wine balance between color and structure.",
    "editor_note": "Tannin extractability determines the relationship between berry tannin concentration and wine tannin content, with high-extractability cultivars producing more tannic wines from equivalent berry material. ||The trait shows genotype × ripeness × winemaking interaction, as extraction conditions (temperature, alcohol, maceration time) interact with inherent extractability. ||Understanding cultivar-specific extractability informs maceration management, enabling targeted extraction of skin versus seed tannins. ||Berry cell wall composition, particularly pectin and hemicellulose content, affects extractability through tannin binding and physical barrier effects.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Bindon KA et al. (2010) Interaction between grape-derived proanthocyanidins and cell wall material. 1. Effect on proanthocyanidin composition and molecular mass. Journal of Agricultural and Food Chemistry 58:2520-2528|| Hernández-Hierro JM et al. (2014) Comparative study of the relationship between skin cell wall composition and anthocyanin extractability in Vitis vinifera. Food Chemistry 158:506-513"
  },
  "Flavonol_Accumulation_Disposition": {
    "definition": "A phenolic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate flavonol compounds (quercetin, myricetin, kaempferol, isorhamnetin, laricitrin, syringetin glycosides) in grape berry skins through flavonol synthase (VvFLS) activity, with genotype-specific total concentration and profile affecting wine color through copigmentation, bitterness contribution, and antioxidant capacity.",
    "alternative_term": "flavonol synthesis capacity | flavonol glycoside trait | FLS activity disposition |+ Flavonolakkumulation | Flavonolbildung | Flavonol-Disposition",
    "example_of_usage": "Flavonol concentration in grape skins ranges from 2-100 mg/kg berries across cultivars and light exposure conditions, with quercetin-3-O-glucoside and quercetin-3-O-glucuronide typically predominating. ||High-flavonol cultivars such as Pinot Noir (40-100 mg/kg) and Cabernet Sauvignon (30-80 mg/kg) contrast with lower-flavonol types such as Grenache (15-40 mg/kg). ||Light exposure is the dominant environmental modifier, with sun-exposed clusters showing 3-10 fold higher flavonol concentration than shaded clusters through VvFLS1 induction. ||The flavonol profile mirrors the anthocyanin profile regarding B-ring hydroxylation, with quercetin (3',4'-diOH) and myricetin (3',4',5'-triOH) reflecting F3'H and F3'5'H activity respectively. ||Flavonols serve as UV-B protectants in berry skins and copigments enhancing anthocyanin color expression in wine.",
    "editor_note": "Flavonol accumulation shows the strongest light response among grape phenolics, making cluster exposure management a primary tool for modulating wine flavonol content. ||The copigmentation function of flavonols enhances and stabilizes red wine color by forming molecular stacks with anthocyanins, shifting the color equilibrium toward the colored flavylium form. ||Quercetin can form insoluble precipitates in wine under specific pH and temperature conditions, creating instability concerns in some contexts. ||The genetic basis involves VvFLS expression regulated by light-responsive VvMYB transcription factors.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Downey MO et al. (2004) The effect of bunch shading on berry development and flavonoid accumulation in Shiraz grapes. Australian Journal of Grape and Wine Research 10:55-73|| Martínez-Lüscher J et al. (2014) Sensitivity of grapevine phenology to water availability, temperature and CO₂ concentration. Frontiers in Environmental Science 2:48"
  },
  "Aromatic_Compound_Disposition": {
    "definition": "A quality potential disposition that is the inherited capacity of a Vitis vinifera plant to synthesize, accumulate, and store volatile and non-volatile aroma precursor compounds in grape berries, encompassing terpenoids, norisoprenoids, thiols, methoxypyrazines, and other metabolites that contribute to varietal aroma character in grapes and wines.",
    "alternative_term": "aroma synthesis capacity | volatile precursor trait | flavor compound disposition |+ Aromaverbindungen | Aromastoff-Disposition | Duftstoff-Akkumulation",
    "example_of_usage": "Aromatic compound profiles vary dramatically across V. vinifera cultivars, defining varietal identity through characteristic volatile signatures. ||Muscat cultivars accumulate 2-6 mg/L free monoterpenes (primarily linalool and geraniol), while non-aromatic cultivars contain <0.5 mg/L. ||Sauvignon Blanc accumulates volatile thiol precursors (cysteine and glutathione conjugates) reaching 500-2000 µg/L, releasing 3-mercaptohexanol and 4-mercapto-4-methylpentan-2-one during fermentation. ||Methoxypyrazine content distinguishes Cabernet Sauvignon and Sauvignon Blanc (5-40 ng/L IBMP) from non-herbaceous cultivars (<2 ng/L). ||The glycosidically bound aroma pool exceeds free volatiles by 3-10 fold in most cultivars, representing a reservoir released during winemaking and aging.",
    "editor_note": "Aromatic_Compound_Disposition serves as the parent class for specific aroma compound categories. ||Varietal aroma is among the most valued quality attributes, with aromatic cultivars commanding premium prices. ||The trait shows strong genetic control (h² = 0.70-0.90 for total monoterpenes) but also significant environmental modulation by temperature, light, and water status. ||Aroma compounds exist in both free (volatile) and bound (glycosylated, non-volatile) forms, with bound precursors released through acid hydrolysis, enzyme action, or fermentation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Lund ST, Bohlmann J (2006) The molecular basis for wine grape quality - a volatile subject. Science 311:804-805|| Robinson AL et al. (2014) Origins of grape and wine aroma. Part 1. Chemical components and viticultural impacts. American Journal of Enology and Viticulture 65:1-24"
  },
  "Monoterpene_Accumulation_Disposition": {
    "definition": "An aromatic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate monoterpenoid compounds (C10 isoprenoids) through the plastidial methylerythritol phosphate (MEP) pathway, with genotype-specific concentrations and profiles of linalool, geraniol, nerol, α-terpineol, and related compounds determining the intensity and character of floral-citrus aroma in Muscat and aromatic cultivars.",
    "alternative_term": "terpene synthesis capacity | monoterpenoid trait | floral aroma disposition |+ Monoterpenakkumulation | Terpenoidbildung | Monoterpen-Disposition",
    "example_of_usage": "Monoterpene accumulation distinguishes aromatic from non-aromatic V. vinifera cultivars, with total monoterpene concentrations spanning three orders of magnitude from <100 µg/L in neutral cultivars to >6000 µg/L in highly aromatic Muscats. ||The MEP pathway provides isopentenyl diphosphate (IPP) and dimethylallyl diphosphate (DMAPP) precursors, with VvDXS (1-deoxy-D-xylulose-5-phosphate synthase) being the primary rate-limiting enzyme. ||Terpene synthases (VvTPS) convert geranyl diphosphate (GPP) to specific monoterpenes, with VvTPS gene family expansion in aromatic cultivars. ||Muscat of Alexandria shows 3000-6000 µg/L total monoterpenes, Gewürztraminer 1500-3000 µg/L, Riesling 500-1500 µg/L, and Chardonnay <200 µg/L. ||Sensory threshold for linalool (15-25 µg/L) means that even low-accumulating cultivars may show subtle floral notes.",
    "editor_note": "Monoterpene_Accumulation_Disposition serves as the parent class for specific monoterpene compound traits. ||The Muscat aroma character that defines this compound class is one of the most ancient and recognizable wine flavor attributes. ||A major QTL on chromosome 5 containing VvDXS explains much of the variation between aromatic and non-aromatic cultivars, with a SNP causing reduced enzyme activity in non-aromatic types. ||Both free and glycosylated monoterpenes accumulate during ripening, with the bound fraction increasing proportionally through harvest.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Battilana J et al. (2009) The 1-deoxy-D-xylulose 5-phosphate synthase gene co-localizes with a major QTL affecting monoterpene content in grapevine. Theoretical and Applied Genetics 118:653-669|| Martin DM et al. (2010) Functional annotation, genome organization and phylogeny of the grapevine (Vitis vinifera) terpene synthase gene family based on genome assembly, FLcDNA cloning, and enzyme assays. BMC Plant Biology 10:226"
  },
  "Linalool_Accumulation_Disposition": {
    "definition": "A monoterpene accumulation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate linalool (3,7-dimethyl-1,6-octadien-3-ol) as a predominant monoterpene alcohol in grape berries, with genotype-specific concentrations determining the intensity of floral (lily-of-the-valley, lavender) aroma character and serving as the primary contributor to Muscat aroma.",
    "alternative_term": "linalool synthesis capacity | floral terpene trait | linalool content disposition |+ Linaloolakkumulation | Linaloolgehalt | Linalool-Disposition",
    "example_of_usage": "Linalool concentration in grape berries ranges from 10-50 µg/L in non-aromatic cultivars to 500-2500 µg/L in highly aromatic Muscats, with the sensory threshold of 15-25 µg/L explaining the characteristic floral notes in aromatic wines. ||Muscat Blanc à Petits Grains shows the highest linalool levels (1500-2500 µg/L free + bound), followed by Muscat of Alexandria (1000-2000 µg/L) and Gewürztraminer (400-1200 µg/L). ||VvTPS-lin (linalool synthase) converts GPP to linalool with high specificity, with gene expression increasing 10-50 fold during ripening in aromatic cultivars. ||The linalool/geraniol ratio varies among Muscat types, with Muscat Blanc showing linalool dominance (ratio 2-4) and some Muscats showing more balanced profiles (ratio 0.8-1.5). ||Linalool undergoes acid-catalyzed rearrangement to α-terpineol and limonene during winemaking and aging.",
    "editor_note": "Linalool is the signature compound of Muscat aroma and contributes floral character across aromatic wine styles. ||The compound exists in both (R)-(-)- and (S)-(+)-enantiomeric forms, with grapevine producing predominantly the (S)-(+)-linalool enantiomer (lavender character) versus the (R)-(-)- form (woody character) produced by some other plants. ||Linalool concentration peaks at or slightly before optimal harvest maturity, with potential decline through volatilization and oxidation if harvest is delayed. ||The glycosylated pool provides a reservoir for continued linalool release during wine aging.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mateo JJ, Jiménez M (2000) Monoterpenes in grape juice and wines. Journal of Chromatography A 881:557-567|| Fenoll J et al. (2009) Changes in the free and bound volatile monoterpene content of Vitis vinifera cv. Muscat of Alexandria throughout grape berry development. Food Chemistry 117:383-388"
  },
  "Geraniol_Accumulation_Disposition": {
    "definition": "A monoterpene accumulation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate geraniol (3,7-dimethyl-2,6-octadien-1-ol) as a significant monoterpene alcohol in grape berries, with genotype-specific concentrations contributing rose-like floral aroma and serving as a biosynthetic precursor for other monoterpenes including citronellol, nerol, and linalool through enzymatic interconversion.",
    "alternative_term": "geraniol synthesis capacity | rose terpene trait | geraniol content disposition |+ Geraniolakkumulation | Geraniolgehalt | Geraniol-Disposition",
    "example_of_usage": "Geraniol concentration in grape berries ranges from 5-30 µg/L in non-aromatic cultivars to 200-1200 µg/L in aromatic types, with sensory threshold of 20-40 µg/L for the characteristic rose-geranium aroma. ||Muscat of Alexandria and Muscat Ottonel show elevated geraniol (600-1200 µg/L), while Gewürztraminer typically shows moderate levels (200-500 µg/L) with lychee-rose character. ||VvTPS-ger (geraniol synthase) produces geraniol directly from GPP, while geraniol reductase can convert geraniol to citronellol (citrus character). ||Geraniol serves as the immediate precursor to nerol (geometric isomer) and can be converted to linalool through enzymatic or acid-catalyzed rearrangement. ||The geraniol/nerol ratio typically ranges from 3-6 in fresh grapes, with higher nerol proportions developing during wine aging. ||Geraniol oxidation products (rose oxide, citral) contribute additional complexity to aged aromatic wines.",
    "editor_note": "Geraniol occupies a central position in monoterpene metabolism, serving both as an aroma-active compound and as a precursor for structural diversity through enzymatic modification. ||The rose-like character of geraniol complements the lily/lavender notes of linalool, with the relative proportions contributing to cultivar-specific aromatic profiles. ||Geraniol shows somewhat greater stability than linalool during winemaking but undergoes oxidation and esterification reactions that modulate its sensory contribution during aging.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Luan F et al. (2005) Effects of different substrates on monoterpene production in Vitis vinifera cv. Gewürztraminer berry exocarp. Journal of Agricultural and Food Chemistry 53:4520-4525|| Ilc T et al. (2016) A grapevine cytochrome P450 generates the precursor of wine lactone, a key odorant in wine. New Phytologist 211:864-874"
  },
  "Terpene_Glycoside_Accumulation_Disposition": {
    "definition": "A monoterpene accumulation disposition that is the inherited capacity of a Vitis vinifera plant to conjugate free monoterpenes with sugar moieties (glucose, arabinose, rhamnose, apiose) through glycosyltransferase activity, creating a non-volatile, water-soluble bound aroma pool that serves as a reservoir for volatile release during winemaking, fermentation, and aging.",
    "alternative_term": "bound terpene capacity | glycosylated aroma trait | terpene glycoconjugate disposition |+ Terpenglykosid-Akkumulation | gebundene Terpene | Glykosid-Bindung",
    "example_of_usage": "Terpene glycosides typically exceed free monoterpenes by 3-10 fold in grape berries, with the bound/free ratio increasing during ripening from 2-3 at veraison to 5-15 at harvest maturity. ||Muscat of Alexandria contains 8-15 mg/L total bound monoterpenes versus 2-4 mg/L free forms, while Riesling shows 2-5 mg/L bound with <0.5 mg/L free. ||Glycoconjugates include monoglucosides, diglycosides (6-O-α-L-arabinofuranosyl-β-D-glucosides, 6-O-α-L-rhamnopyranosyl-β-D-glucosides), and triglycosides. ||VvGT (glycosyltransferase) gene family members catalyze sugar transfer, with VvGT7 and VvGT14 showing activity toward monoterpene substrates. ||Hydrolysis releases free terpenes through acid conditions (wine pH, bottle aging), yeast β-glucosidases during fermentation, or exogenous enzyme addition, with release rates varying by glycoside structure (monoglucosides > disaccharides > trisaccharides).",
    "editor_note": "Terpene glycoside accumulation creates the \"hidden\" aroma potential of grapes that is progressively revealed during winemaking and aging. ||The glycosidically bound pool is non-volatile and sensorially inactive until hydrolyzed, providing extended aroma release over time. ||Cultivar differences in glycosylation patterns affect both the magnitude of bound pool and the kinetics of release. ||The enzymatic specificity of yeast β-glucosidases means that different fermentation conditions and yeast strains produce different monoterpene release patterns from the same glycoside pool.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Williams PJ et al. (1982) Synthesis of monoterpene hydrocarbons from tritiated monoterpene alcohols in non-Muscat and Muscat grape berries and wine. Journal of Agricultural and Food Chemistry 30:1219-1223|| Günata Z et al. (1985) The aroma of grapes. I. Extraction and determination of free and glycosidically bound fractions of some grape aroma components. Journal of Chromatography A 331:83-90"
  },
  "Norisoprenoid_Accumulation_Disposition": {
    "definition": "An aromatic compound disposition that is the inherited capacity of a Vitis vinifera plant to generate and accumulate C13-norisoprenoid aroma compounds and their glycosidic precursors through oxidative cleavage of carotenoid pigments (C40) by carotenoid cleavage dioxygenases (CCDs), with genotype-specific concentrations of β-damascenone, β-ionone, TDN precursors, and related compounds contributing complex fruit, floral, honey, and kerosene notes.",
    "alternative_term": "norisoprenoid synthesis capacity | carotenoid-derived aroma trait | C13 aroma compound disposition |+ Norisoprenoid-Akkumulation | Carotinoid-Abbauprodukte | Norisoprenoid-Disposition",
    "example_of_usage": "Norisoprenoid precursor accumulation occurs in all V. vinifera cultivars but shows substantial genotypic variation, with precursor concentrations ranging from 50-500 µg/L depending on cultivar and ripeness stage. ||Carotenoid cleavage by VvCCD1 and VvCCD4 generates C13 fragments that undergo further modification to produce β-damascenone (rose, apple, honey|| threshold 0.05 µg/L), β-ionone (violet, raspberry|| threshold 0.09 µg/L), and TDN precursors (kerosene|| threshold 2-20 µg/L). ||Riesling shows high TDN precursor accumulation (100-300 µg/L), while Chardonnay and Semillon show elevated β-damascenone potential. ||Norisoprenoid precursors increase during ripening, particularly during the final 2-4 weeks before harvest, with sun exposure enhancing both carotenoid synthesis and subsequent degradation.",
    "editor_note": "Norisoprenoid_Accumulation_Disposition serves as the parent class for specific norisoprenoid precursor traits. ||Unlike monoterpenes that are synthesized de novo, norisoprenoids arise from carotenoid catabolism, linking color and aroma metabolism. ||The precursors are stored as glycosides and released through acid hydrolysis during wine aging, producing the characteristic \"bottle-aged\" aroma development. ||The low sensory thresholds of β-damascenone and TDN mean these compounds significantly impact wine aroma even at trace concentrations.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mathieu S et al. (2005) A carotenoid cleavage dioxygenase from Vitis vinifera L.: functional characterization and expression during grape berry development in relation to C13-norisoprenoid accumulation. Journal of Experimental Botany 56:2721-2731|| Mendes-Pinto MM (2009) Carotenoid breakdown products - the norisoprenoids - in wine aroma. Archives of Biochemistry and Biophysics 483:236-245"
  },
  "TDN_Precursor_Accumulation_Disposition": {
    "definition": "A norisoprenoid accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate glycosidic precursors of 1,1,6-trimethyl-1,2-dihydronaphthalene (TDN) in grape berries, with genotype-specific concentrations determining the potential for development of the characteristic kerosene/petrol aroma that defines aged Riesling and related wines.",
    "alternative_term": "TDN potential | petrol aroma precursor | kerosene note disposition |+ TDN-Vorläufer-Akkumulation | Petrolnote-Potential | Kerosin-Aroma-Disposition",
    "example_of_usage": "TDN precursor concentration varies dramatically among cultivars, with Riesling showing uniquely high accumulation (100-400 µg/L glycosidic precursors) compared to most other V. vinifera cultivars (<50 µg/L). ||TDN forms through acid-catalyzed rearrangement of carotenoid-derived precursors, primarily megastigma-4,6,8-triene glycosides, with release accelerating at wine pH during bottle aging. ||Free TDN in young Riesling wines typically ranges from 1-10 µg/L, increasing to 30-200 µg/L after 5-10 years of bottle aging. ||The sensory threshold of 2-20 µg/L (depending on wine matrix) means TDN transitions from subliminal in young wines to dominant in aged examples. ||High sun exposure and warm ripening temperatures increase TDN precursor accumulation by 50-200%, explaining higher petrol character in warm-climate Riesling. ||Other cultivars showing moderate TDN potential include Semillon, Chenin Blanc, and Silvaner.",
    "editor_note": "TDN represents the defining aged character of Riesling, with the kerosene/petrol aroma being considered either highly desirable (aged Riesling connoisseurs) or a fault (consumers preferring fruity young wines). ||The uniquely high TDN potential of Riesling reflects cultivar-specific carotenoid composition and degradation patterns not fully understood mechanistically. ||Viticultural management targeting moderate sun exposure and controlled water stress can modulate TDN precursor accumulation, enabling some producer control over this distinctive aroma development trajectory.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sacks GL et al. (2012) Origins of TDN in Riesling. In: Ebeler SB et al. (eds) Progress in Authentication of Food and Wine, ACS Symposium Series pp.: 255-271|| Marais J et al. (1992) Effect of sunlight and shade on norisoprenoid levels in maturing Weisser Riesling and Chenin blanc grapes and Weisser Riesling wines. South African Journal of Enology and Viticulture 13:23-32"
  },
  "Beta_Damascenone_Precursor_Disposition": {
    "definition": "A norisoprenoid accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate glycosidic precursors of β-damascenone (1-(2,6,6-trimethyl-1-cyclohexa-1,3-dienyl)but-2-en-1-one) in grape berries, with this potent odorant contributing rose, apple, honey, and tropical fruit notes across virtually all wine styles due to its extremely low sensory threshold.",
    "alternative_term": "damascenone potential | rose-apple aroma precursor | damascenone glycoside disposition |+ β-Damascenon-Vorläufer | Damascenon-Potential | Rosenketonnote",
    "example_of_usage": "β-Damascenone precursor concentration ranges from 100-800 µg/L across cultivars, with Chardonnay, Semillon, and Sauvignon Blanc showing higher accumulation (400-800 µg/L) than red cultivars such as Cabernet Sauvignon and Merlot (200-400 µg/L). ||The glycosidic precursors include multiple conjugate forms (glucose, 6-O-α-L-arabinofuranosyl-β-D-glucoside) requiring acid hydrolysis for release. ||Wine β-damascenone concentrations of 1-10 µg/L are typical, vastly exceeding the remarkably low sensory threshold of 0.05 µg/L (50 ng/L), making β-damascenone sensorially active in virtually all wines. β-Damascenone acts as an aroma enhancer, increasing perception of fruity notes and masking green/herbaceous character even when below its own detection threshold. ||Sun exposure during ripening increases β-damascenone precursor accumulation by 30-80%, with extended hang time also promoting accumulation.",
    "editor_note": "β-Damascenone may be the single most impactful aroma compound in wine due to its exceptionally low threshold and near-universal presence. ||The compound contributes directly to fruity/floral character and indirectly through enhancement/suppression interactions with other odorants. ||Unlike TDN which shows strong cultivar specificity, β-damascenone precursors accumulate across all V. vinifera cultivars, though at varying concentrations. ||The carotenoid precursors (primarily neoxanthin) undergo CCD-mediated cleavage followed by further enzymatic and chemical modifications to generate the damascenone skeleton.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Pineau B et al. (2007) Contribution of grape C13-norisoprenoid compounds to wine aroma in young Bordeaux red wines. Journal of Agricultural and Food Chemistry 55:6426-6433|| Sefton MA et al. (2011) Occurrence, sensory impact, formation, and fate of damascenone in grapes, wines, and other foods and beverages. Journal of Agricultural and Food Chemistry 59:9717-9746"
  },
  "Methoxypyrazine_Accumulation_Disposition": {
    "definition": "An aromatic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate alkyl-methoxypyrazine compounds (IBMP, IPMP, SBMP) in grape berries and vegetative tissues, with genotype-specific concentrations determining the intensity of green, herbaceous, bell pepper, and vegetal aroma character that defines certain Bordeaux varieties and contributes to wine style.",
    "alternative_term": "MP synthesis capacity | green aroma trait | herbaceous character disposition |+ Methoxypyrazin-Akkumulation | grüne Aromen | Pyrazin-Disposition",
    "example_of_usage": "Methoxypyrazine concentration varies over three orders of magnitude across V. vinifera cultivars, from <1 ng/L in non-herbaceous types to 30-80 ng/L in high-MP cultivars such as Cabernet Sauvignon, Sauvignon Blanc, and Carménère. ||IBMP (3-isobutyl-2-methoxypyrazine) predominates in most cultivars (70-95% of total MPs), with IPMP and SBMP as minor contributors. ||MP biosynthesis occurs in both berries and leaves, with accumulation peaking pre-veraison (reaching 50-150 ng/L) then declining 80-95% during ripening through photodegradation and dilution to harvest levels of 5-40 ng/L. ||The sensory threshold of IBMP (1-2 ng/L in red wine, 8-15 ng/L in white wine) means even trace concentrations significantly impact wine character. ||Cluster light exposure reduces MP concentration by 50-80% compared to shaded fruit.",
    "editor_note": "Methoxypyrazine_Accumulation_Disposition serves as the parent class for specific MP compound traits. ||The green/herbaceous character from MPs is valued at moderate levels in some wine styles (Sauvignon Blanc, cool-climate Cabernet) but considered a fault when excessive. ||Unlike most grape aroma compounds, MPs are stable through fermentation and aging, making viticultural management the primary tool for controlling wine MP levels. ||The O-methyltransferase (VvOMT3) catalyzing the final biosynthetic step shows cultivar-specific expression explaining genetic variation in MP accumulation capacity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dunlevy JD et al. (2010) The production of flavour and aroma compounds in grape berries. In: Roubelakis-Angelakis KA (ed) Grapevine Molecular Physiology and Biotechnology, 2nd Ed, Springer pp.: 293-340|| Roujou de Boubée D et al. (2000) Identification of an odoriferous compound responsible for the green bell pepper aroma in wines made from immature Cabernet Sauvignon berries. Journal of Agricultural and Food Chemistry 48:4830-4834"
  },
  "IBMP_Accumulation_Disposition": {
    "definition": "A methoxypyrazine accumulation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate 3-isobutyl-2-methoxypyrazine (IBMP) as the predominant methoxypyrazine in grape berries, with genotype-specific concentrations determining the intensity of characteristic green bell pepper aroma and representing the primary contributor to herbaceous character in Bordeaux varieties.",
    "alternative_term": "IBMP synthesis capacity | bell pepper aroma trait | isobutyl-methoxypyrazine disposition |+ IBMP-Akkumulation | Paprika-Aroma | Isobutyl-Methoxypyrazin",
    "example_of_usage": "IBMP concentration at harvest ranges from <1 ng/L in low-MP cultivars such as Pinot Noir and Merlot to 15-40 ng/L in high-MP types such as Cabernet Sauvignon (15-35 ng/L), Cabernet Franc (20-45 ng/L), Sauvignon Blanc (10-30 ng/L), and Carménère (30-80 ng/L). ||The sensory threshold of 1-2 ng/L in red wine and 8-15 ng/L in white wine means IBMP is supra-threshold in many wines from high-MP cultivars. ||IBMP biosynthesis involves condensation of leucine-derived isobutyl amine with glyoxylic acid followed by O-methylation by VvOMT3, with gene expression and IBMP accumulation peaking 2-4 weeks pre-veraison. ||Post-veraison decline of 90-98% through UV photodegradation (half-life 10-20 days in sun-exposed fruit) and metabolic degradation reduces IBMP to harvest levels. ||Shaded clusters retain 2-5× higher IBMP than exposed clusters at harvest.",
    "editor_note": "IBMP is the signature compound defining the green bell pepper note of Bordeaux varieties and represents the most thoroughly studied grape methoxypyrazine. ||The compound shows remarkable stability during winemaking and aging, with wine IBMP concentrations closely reflecting grape levels. ||Viticultural management (leaf removal, cluster exposure, delayed harvest, low vigor) provides the primary tools for IBMP reduction, as no winemaking intervention effectively removes IBMP from wine. ||Cool climate and vigorous vine conditions favor higher IBMP retention through reduced photodegradation and advanced harvest.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Dunlevy JD et al. (2013) The methyltransferase VvOMT3 is responsible for the formation of 3-isobutyl-2-methoxypyrazine (IBMP), a key flavour compound in grapevine. New Phytologist 197:1177-1186|| Koch A et al. (2010) Fruit ripening in Vitis vinifera: light intensity before and not during ripening determines the concentration of 2-methoxy-3-isobutylpyrazine in Cabernet Sauvignon berries. Physiologia Plantarum 140:74-84"
  },
  "IPMP_Accumulation_Disposition": {
    "definition": "A methoxypyrazine accumulation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate 3-isopropyl-2-methoxypyrazine (IPMP) as a minor methoxypyrazine in grape berries, with genotype-specific concentrations contributing green pea and earthy aroma notes that complement the bell pepper character of IBMP.",
    "alternative_term": "IPMP synthesis capacity | green pea aroma trait | isopropyl-methoxypyrazine disposition |+ IPMP-Akkumulation | Erbsen-Aroma | Isopropyl-Methoxypyrazin",
    "example_of_usage": "IPMP concentration at harvest typically ranges from 0.1-5 ng/L across cultivars, representing 5-20% of total methoxypyrazine content in most genotypes. ||Cabernet Sauvignon shows IPMP levels of 1-4 ng/L, Sauvignon Blanc 0.5-3 ng/L, and Carménère 2-6 ng/L at harvest. ||The sensory threshold of IPMP (0.3-2 ng/L) is lower than IBMP, making its earthy, green pea character perceptible at trace concentrations. ||IPMP biosynthesis parallels IBMP, utilizing valine-derived isopropyl amine rather than leucine-derived isobutyl amine, with subsequent methylation by VvOMT3. ||The IPMP/IBMP ratio varies among cultivars (0.05-0.20 typical) and increases during ripening as IBMP declines faster than IPMP through preferential photodegradation. ||IPMP contributes distinctive earthy, asparagus notes distinguishable from the bell pepper character of IBMP in sensory analysis.",
    "editor_note": "IPMP represents the second most abundant methoxypyrazine in grape berries, contributing complementary green character to the IBMP-dominated profile. ||The lower sensory threshold of IPMP relative to IBMP means small absolute concentrations can significantly impact wine aroma. ||The earthy/green pea character of IPMP is sometimes considered more undesirable than the bell pepper note of IBMP, influencing quality perception in affected wines. ||IPMP shows similar environmental modulation to IBMP, with cluster exposure reducing accumulation through photodegradation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Sala C et al. (2004) Contents of 3-alkyl-2-methoxypyrazines in musts and wines from Vitis vinifera variety Cabernet Sauvignon. Journal of Agricultural and Food Chemistry 52:5978-5983|| Hashizume K, Samuta T (1999) Grape maturity and light exposure affect berry methoxypyrazine concentration. American Journal of Enology and Viticulture 50:194-198"
  },
  "Thiol_Precursor_Accumulation_Disposition": {
    "definition": "An aromatic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate non-volatile cysteine and glutathione conjugates of volatile thiols in grape berries, with genotype-specific precursor concentrations determining the potential for release of powerful odorants (3-mercaptohexan-1-ol, 4-mercapto-4-methylpentan-2-one, 3-mercaptohexyl acetate) that define the tropical, citrus, and boxwood character of Sauvignon Blanc and related wines.",
    "alternative_term": "volatile thiol precursor | polyfunctional thiol capacity | thiol conjugate disposition |+ Thiol-Vorläufer-Akkumulation | Thiol-Konjugate | Schwefelverbindungen-Potential",
    "example_of_usage": "Thiol precursor concentration varies substantially across cultivars, with Sauvignon Blanc showing the highest accumulation (Cys-3MH 200-800 µg/L, Cys-4MMP 10-50 µg/L) compared to lower levels in Riesling, Gewürztraminer, and Colombard (50-200 µg/L Cys-3MH). ||Precursors exist as both cysteine conjugates (Cys-3MH, Cys-4MMP) and glutathione conjugates (Glut-3MH, Glut-4MMP), with the glutathione forms representing biosynthetic intermediates converted to cysteine conjugates in the berry. ||Yeast carbon-sulfur lyases during fermentation cleave 1-5% of precursors to release free volatile thiols, with wine concentrations of 200-5000 ng/L 3MH and 1-50 ng/L 4MMP in aromatic Sauvignon Blanc. ||The remarkably low sensory thresholds (60 ng/L for 3MH, 0.8 ng/L for 4MMP) mean these trace compounds dominate wine aroma.",
    "editor_note": "Thiol_Precursor_Accumulation_Disposition serves as the parent class for specific thiol precursor traits. ||Volatile thiols represent a relatively recently discovered aroma class (1990s-2000s) that revolutionized understanding of Sauvignon Blanc character. ||The compounds are non-volatile and odorless in grape juice, with aroma release requiring yeast enzymatic cleavage during fermentation. ||This fermentation-dependent release means that both grape precursor concentration and yeast strain selection affect wine thiol content. ||Oxidation rapidly destroys free thiols, making reductive winemaking essential for preserving thiol character.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tominaga T et al. (1998) A powerful aromatic volatile thiol, 2-furanmethanethiol, exhibiting roast coffee aroma in wines made from several Vitis vinifera grape varieties. Journal of Agricultural and Food Chemistry 46:1044-1048|| Roland A et al. (2011) Evolution of S-cysteine and glutathione conjugate contents during grape ripening. Journal of Agricultural and Food Chemistry 59:4958-4964"
  },
  "3MH_Precursor_Disposition": {
    "definition": "A thiol precursor accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate cysteine and glutathione conjugates of 3-mercaptohexan-1-ol (3MH) in grape berries, with genotype-specific concentrations determining the potential for grapefruit, passionfruit, and tropical fruit aroma release during fermentation.",
    "alternative_term": "3MH conjugate capacity | grapefruit thiol precursor | 3-mercaptohexanol potential |+ 3MH-Vorläufer | Grapefruit-Thiol | Passionsfrucht-Aroma",
    "example_of_usage": "3MH precursor concentration (Cys-3MH + Glut-3MH) ranges from 50-150 µg/L in low-precursor cultivars to 400-1200 µg/L in high-precursor Sauvignon Blanc from Marlborough. ||Cysteine-3MH typically comprises 60-80% of total 3MH precursors, with glutathione-3MH as the biosynthetic intermediate. ||Wine 3MH concentrations of 200-8000 ng/L result from 1-5% conversion of grape precursors during fermentation, vastly exceeding the sensory threshold of 60 ng/L. ||The released 3MH shows distinct grapefruit (zesty citrus) and passionfruit (tropical) character, with perception varying by enantiomeric ratio ((R)-3MH more citrus, (S)-3MH more passionfruit). 3MH can be acetylated to 3-mercaptohexyl acetate (3MHA) during fermentation, adding boxwood and tropical notes with a threshold of 4 ng/L. ||Precursor accumulation increases during ripening, with sun exposure promoting accumulation through glutathione conjugation mechanisms.",
    "editor_note": "3MH and its acetate 3MHA are the primary contributors to Sauvignon Blanc tropical character, with concentrations typically 10-100× above threshold in aromatic examples. ||The precursor concentration in grapes sets the ceiling for potential wine thiol content, but fermentation conditions (yeast strain, nutrition, temperature) strongly modulate conversion efficiency. ||The dual origin of 3MH (from both (E)-2-hexenal and hexanal via conjugation) provides metabolic flexibility in precursor synthesis. ||Water deficit and nitrogen status affect precursor accumulation through effects on glutathione metabolism.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Peyrot des Gachons C et al. (2002) Influence of water and nitrogen deficit on fruity and herbaceous aroma potential of Vitis vinifera L. cv. Sauvignon blanc in three terroirs. Journal of the Science of Food and Agriculture 82:1167-1174|| Capone DL et al. (2010) The cysteine conjugate of 3-mercaptohexan-1-ol in grape juice. Food Chemistry 119:1326-1330"
  },
  "4MMP_Precursor_Disposition": {
    "definition": "A thiol precursor accumulation disposition that is the inherited capacity of a Vitis vinifera plant to accumulate cysteine and glutathione conjugates of 4-mercapto-4-methylpentan-2-one (4MMP) in grape berries, with genotype-specific concentrations determining the potential for boxwood, blackcurrant bud, and broom aroma release during fermentation.",
    "alternative_term": "4MMP conjugate capacity | boxwood thiol precursor | 4-mercapto-4-methylpentan-2-one potential |+ 4MMP-Vorläufer | Buchsbaum-Thiol | Schwarze-Johannisbeere-Aroma",
    "example_of_usage": "4MMP precursor concentration (Cys-4MMP + Glut-4MMP) ranges from 5-20 µg/L in most cultivars to 30-80 µg/L in high-precursor Sauvignon Blanc clones. 4MMP precursors accumulate at 10-20× lower concentration than 3MH precursors, but the 75× lower sensory threshold (0.8 ng/L versus 60 ng/L for 3MH) means 4MMP significantly impacts wine aroma even at trace concentrations. ||Wine 4MMP concentrations of 5-50 ng/L are typical in aromatic Sauvignon Blanc, with the boxwood and blackcurrant bud character becoming dominant above 20 ng/L. 4MMP shows no acetylation (lacking the hydroxyl group of 3MH), maintaining its ketone form throughout wine aging. ||The precursor arises from conjugation of mesityl oxide with glutathione/cysteine, with biosynthesis pathway details less characterized than for 3MH. ||Precursor concentration shows strong clone and terroir effects within Sauvignon Blanc.",
    "editor_note": "4MMP contributes the distinctive boxwood/blackcurrant character that, together with the grapefruit notes of 3MH, defines Sauvignon Blanc typicity. ||The extremely low threshold means 4MMP significantly impacts aroma even in wines with modest precursor levels. ||The blackcurrant bud character can be perceived as either desirable (varietal typicity) or undesirable (cat urine association at high concentrations) depending on context and concentration. ||Some Sauvignon Blanc terroirs (Sancerre) show higher 4MMP/3MH ratios than others (Marlborough), contributing to regional style differences.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Tominaga T et al. (1998) Development of a method for analyzing the volatile thiols involved in the characteristic aroma of wines made from Vitis vinifera L. cv. Sauvignon blanc. Journal of Agricultural and Food Chemistry 46:1044-1048|| Helwi P et al. (2016) Vine nitrogen status and volatile thiols and their precursors from plot to transcriptome level. BMC Plant Biology 16:173"
  },
  "Rotundone_Accumulation_Disposition": {
    "definition": "An aromatic compound disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and accumulate the sesquiterpene rotundone ((3S,5R,8S)-3,4,5,6,7,8-hexahydro-3,8-dimethyl-5-(prop-1-en-2-yl)azulen-1(2H)-one) in grape berry skins, with genotype-specific concentrations determining the intensity of black pepper and spice aroma that characterizes Syrah and certain other red cultivars.",
    "alternative_term": "pepper sesquiterpene | black pepper aroma trait | spice compound disposition |+ Rotundon-Akkumulation | Pfefferaroma | Gewürznote",
    "example_of_usage": "Rotundone concentration varies dramatically across cultivars, with Syrah showing uniquely high accumulation (50-500 ng/L in berries, 10-200 ng/kg in wine) compared to most other V. vinifera cultivars (<10 ng/L). ||Additional cultivars with measurable rotundone include Durif/Petite Sirah (20-150 ng/L), Mourvèdre (10-80 ng/L), Vespolina (50-200 ng/L), and Grüner Veltliner (10-50 ng/L). ||The sensory threshold of 8-16 ng/L (with 20-25% of the population anosmic to rotundone) means the compound is supra-threshold in most Syrah wines but subliminal in low-accumulating cultivars. ||Rotundone biosynthesis occurs via the cytosolic mevalonate (MVA) pathway through sesquiterpene synthase activity, with VvTPS24 (α-guaiene synthase) producing the precursor that is subsequently oxidized to rotundone. ||Accumulation occurs primarily in berry skins during late ripening (4-6 weeks post-veraison), with cool temperatures (15-20°C) and moderate water deficit promoting higher concentration.",
    "editor_note": "Rotundone represents a breakthrough discovery (2008) explaining the distinctive black pepper/spice character of cool-climate Syrah. ||The compound shows remarkable cultivar specificity, with Syrah accumulating 10-100× higher concentrations than most other varieties. ||The high proportion of anosmia (inability to detect rotundone) in the population means pepper character is perceived differently by different tasters. ||Climate significantly modulates rotundone, with cool sites and vintages producing more peppery wines, explaining the traditional association of pepper with northern Rhône Syrah versus the fruitier character of warm-climate Shiraz.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Wood C et al. (2008) From wine to pepper: rotundone, an obscure sesquiterpene, is a potent spicy aroma compound. Journal of Agricultural and Food Chemistry 56:3738-3744|| Siebert TE et al. (2008) Development of a stable isotope dilution analysis for the quantification of the key odorant rotundone in grapes, juice, and wine. Journal of Agricultural and Food Chemistry 56:3745-3748"
  },
  "Color_Stability_Disposition": {
    "definition": "A quality potential disposition that is the inherited capacity of a Vitis vinifera plant to produce grapes yielding wines with stable red-purple color that resists fading during winemaking and aging, determined by anthocyanin concentration and profile, copigmentation capacity, and the formation of polymeric pigments through anthocyanin-tannin reactions that create color forms resistant to SO₂ bleaching and pH-induced equilibrium shifts.",
    "alternative_term": "color retention capacity | pigment stability trait | color durability disposition |+ Farbstabilität | Farbbeständigkeit | Pigmentstabilitäts-Disposition",
    "example_of_usage": "Color stability varies substantially across red V. vinifera cultivars, with stable-color types such as Tannat, Syrah, and Cabernet Sauvignon retaining 60-80% of initial color density after 2 years of bottle aging, while less stable cultivars such as Pinot Noir and Grenache may retain only 30-50%. ||Color stability depends on multiple factors including initial anthocyanin concentration (higher = more stable), acylation proportion (acylated forms more stable), copigmentation capacity (enhancing color expression), and polymeric pigment formation rate (creating SO₂-resistant color). ||The color density (A520 + A420) to anthocyanin concentration ratio increases during aging from 0.04-0.06 in young wines to 0.10-0.20 in aged wines as monomeric anthocyanins convert to polymeric forms. ||Wine pH strongly affects stability, with lower pH (3.2-3.4) favoring the colored flavylium form over colorless hemiketal and chalcone equilibrium species.",
    "editor_note": "Color_Stability_Disposition serves as the parent class for copigmentation and polymeric pigment formation traits. ||Color stability represents the practical outcome of multiple underlying chemical processes, integrating grape composition with wine chemistry evolution. ||The trait is critical for red wine quality, as color loss is perceived as a quality defect and limits aging potential. ||Climate change effects on grape anthocyanin accumulation (temperature inhibition) indirectly affect color stability through reduced initial pigment concentration.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Boulton R (2001) The copigmentation of anthocyanins and its role in the color of red wine: a critical review. American Journal of Enology and Viticulture 52:67-87|| He F et al. (2012) Anthocyanins and their variation in red wines. I. Monomeric anthocyanins and their color expression. Molecules 17:1571-1601"
  },
  "Copigmentation_Disposition": {
    "definition": "A color stability disposition that is the inherited capacity of a Vitis vinifera plant to produce grapes with sufficient anthocyanin and copigment (flavonol, hydroxycinnamic acid, tannin) concentrations and appropriate molecular ratios to support copigmentation reactions that enhance and stabilize red wine color through non-covalent molecular stacking between anthocyanins and colorless phenolic cofactors.",
    "alternative_term": "copigment capacity | color enhancement trait | molecular stacking disposition |+ Copigmentierung | Farbverstärkung | Copigment-Kapazität",
    "example_of_usage": "Copigmentation contributes 30-50% of young red wine color through hyperchromic (increased absorbance) and bathochromic (red-shifted wavelength) effects on anthocyanin chromophores. ||Effective copigmentation requires molar ratios of copigment to anthocyanin of 5-20:1, with flavonols (quercetin, myricetin) and hydroxycinnamic acids (caffeic, p-coumaric) serving as primary cofactors. ||Cultivars with high flavonol accumulation (Pinot Noir 40-100 mg/kg, Cabernet Sauvignon 30-80 mg/kg) show enhanced copigmentation compared to low-flavonol types (Grenache 15-40 mg/kg). ||Self-association of anthocyanins (intramolecular copigmentation in acylated forms, intermolecular stacking at high concentration) provides additional stabilization. ||Copigmentation effects are maximal in young wines and decline as anthocyanins are incorporated into polymeric pigments, with the copigmentation contribution decreasing from 40-50% at bottling to 10-20% after 2 years.",
    "editor_note": "Copigmentation represents the primary mechanism of color enhancement in young red wines, explaining why wine color intensity can exceed that predicted from anthocyanin concentration alone. ||The non-covalent nature of copigmentation complexes means they are in dynamic equilibrium, with complex stability affected by pH, temperature, and ethanol concentration. ||Copigmentation provides a \"bridge\" to polymeric pigment formation by maintaining anthocyanin in favorable conformations for subsequent covalent reactions. ||Viticultural practices affecting flavonol accumulation (cluster exposure) directly impact copigmentation capacity.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Boulton R (2001) The copigmentation of anthocyanins and its role in the color of red wine: a critical review. American Journal of Enology and Viticulture 52:67-87|| Hermosín Gutiérrez I et al. (2005) Influence of variety and aging on colour and anthocyanin composition of wines from Castilla-La Mancha. Food Chemistry 91:429-438"
  },
  "Polymeric_Pigment_Formation_Disposition": {
    "definition": "A color stability disposition that is the inherited capacity of a Vitis vinifera plant to produce grapes with anthocyanin and tannin compositions favoring the formation of covalently linked anthocyanin-tannin polymers during winemaking and aging, creating pigmented polymers that are resistant to SO₂ bleaching, less sensitive to pH-induced color loss, and provide the stable brick-red color of aged red wines.",
    "alternative_term": "pigmented tannin formation | anthocyanin-tannin polymerization | stable pigment capacity |+ Polymerpigment-Bildung | Anthocyan-Tannin-Polymerisation | stabile Farbpigmente",
    "example_of_usage": "Polymeric pigment formation proceeds through multiple reaction pathways including direct anthocyanin-tannin condensation (A-T and T-A adducts), acetaldehyde-mediated bridging (ethyl-linked polymers), and pyranoanthocyanin formation (vitisins, portisins). ||Cultivars with high initial anthocyanin and tannin concentrations such as Tannat and Cabernet Sauvignon show rapid polymeric pigment accumulation, reaching 40-60% of total wine color from polymeric forms within 12-18 months versus 20-35% in lower-phenolic cultivars such as Pinot Noir. ||The ratio of small polymeric pigments (SPP, trichloroacetic acid-soluble) to large polymeric pigments (LPP, trichloroacetic acid-precipitable) shifts from 3-5:1 in young wines to 1:1 or lower in aged wines as polymerization continues. ||Pyranoanthocyanins (vitisin A, vitisin B) contribute orange-red hues and exceptional stability, with concentrations reaching 5-20 mg/L in aged wines. ||The rate of polymeric pigment formation is enhanced by higher temperature, micro-oxygenation, and lower pH conditions during aging.",
    "editor_note": "Polymeric pigment formation represents the ultimate stabilization mechanism for red wine color, converting labile monomeric anthocyanins into stable covalent structures. ||The trait depends on grape composition (anthocyanin and tannin concentrations, tannin structure) and winemaking/aging conditions (oxygen exposure, acetaldehyde formation, time). ||Understanding cultivar-specific polymerization capacity enables prediction of wine aging trajectory and optimization of cellar practices. ||The color shift from purple-red (monomeric anthocyanins) to brick-red (polymeric pigments) during aging reflects the changing pigment composition rather than simple degradation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Somers TC (1971) The polymeric nature of wine pigments. Phytochemistry 10:2175-2186|| Harbertson JF et al. (2003) A survey of polymeric pigments and phenolics in red wines. American Journal of Enology and Viticulture 54:301-306"
  },
  "Longevity_And_Resilience_Disposition": {
    "definition": "A grapevine disposition that is the inherited capacity of a Vitis vinifera plant to maintain productive function over extended time periods (decades to centuries) and to recover from stress events, damage, or decline through regenerative growth, encompassing traits related to structural durability, disease resistance of perennial tissues, carbohydrate reserve management, and the capacity for renewal from latent buds.",
    "alternative_term": "vine durability trait | long-term productivity | persistence disposition |+ Langlebigkeit und Resilienz | Rebstockausdauer | Widerstandsfähigkeit",
    "example_of_usage": "Vine longevity varies substantially across cultivars and growing conditions, with well-managed vines of long-lived cultivars such as Zinfandel and Mourvèdre remaining productive for 80-150+ years, while shorter-lived types may decline within 25-40 years. ||Resilience encompasses recovery from frost damage (regrowth from basal buds), drought stress (osmotic adjustment, root regeneration), mechanical injury (wound compartmentalization, callus formation), and chronic stress from trunk diseases (survival with partial vascular dysfunction). ||Old vines (>40 years) often show reduced yield (30-60% of peak production) but enhanced fruit quality through deeper root systems, improved vine balance, and concentration effects from smaller berry size. ||The economic value of old vine vineyards reflects both the irreplaceable time investment and the perceived quality advantages.",
    "editor_note": "Longevity_And_Resilience_Disposition serves as the top-level parent class for traits governing vine persistence and recovery capacity. ||The category addresses the unique perennial nature of grapevines, which can remain productive far longer than most agricultural crops. ||Understanding longevity determinants has both economic implications (vineyard investment protection) and cultural significance (preservation of heritage vineyards). ||Climate change and emerging trunk disease pressures are increasing attention to resilience traits in cultivar and rootstock selection.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 145-195|| Gramaje D et al. (2018) Managing grapevine trunk diseases with respect to etiology and epidemiology: current strategies and future prospects. Plant Disease 102:12-39"
  },
  "Vine_Longevity_Disposition": {
    "definition": "A longevity and resilience disposition that is the inherited capacity of a Vitis vinifera plant to maintain structural integrity, vascular function, and reproductive capacity over extended time periods, with genotype-specific maximum productive lifespan determined by trunk disease resistance, wood durability, and the balance between accumulating damage and regenerative capacity.",
    "alternative_term": "productive lifespan | vine persistence trait | long-term viability disposition |+ Rebstock-Langlebigkeit | Lebensdauer | Produktionsdauer",
    "example_of_usage": "Vine longevity ranges from 25-40 years for short-lived cultivar-site combinations to over 150 years for exceptional old vine vineyards, with documented examples of productive vines exceeding 200 years in Australia (Barossa Shiraz), California (Zinfandel), and Europe (various cultivars). ||Longevity-promoting factors include inherent trunk disease resistance, appropriate rootstock selection (matching vigor to site), balanced crop load management, and absence of catastrophic stress events. ||Cultivars reputed for longevity include Zinfandel, Mourvèdre (Monastrell), Carignan, and Grenache, while Merlot and Sauvignon Blanc are often considered shorter-lived. ||Annual trunk diameter increment of 0.5-2.0 mm in mature vines gradually increases conductive capacity but also accumulates tyloses, wound tissue, and pathogen-damaged zones that eventually compromise function.",
    "editor_note": "Vine_Longevity_Disposition serves as the parent class for structural integrity, decline resistance, and growth resumption traits. ||Longevity is determined by the race between damage accumulation (trunk diseases, mechanical injury, environmental stress) and the vine's regenerative capacity. ||The concept of \"vine age\" as a quality factor is embedded in wine marketing (vieilles vignes), though the mechanisms linking age to quality likely involve root system development, yield reduction, and vine balance rather than age per se.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fontaine F et al. (2016) Grapevine trunk diseases: etiology and management. In: Maixner M, Eder J (eds) Phytoplasma, Methods in Molecular Biology, Springer pp.: 427-443|| Smart RE (2014) Old vines - can we define the term for Barossa wines? Wine and Viticulture Journal 29:38-42"
  },
  "Structural_Integrity_Disposition": {
    "definition": "A vine longevity disposition that is the inherited capacity of a Vitis vinifera plant to maintain the physical strength and functional integrity of woody perennial structures (trunk, cordons, spurs) over time, resisting mechanical failure, decay, and the progressive loss of conductive tissue that limits productive lifespan.",
    "alternative_term": "wood durability | structural soundness | mechanical integrity trait |+ Strukturelle Integrität | Holzbeständigkeit | mechanische Stabilität",
    "example_of_usage": "Structural integrity declines progressively with vine age as functional sapwood is converted to non-conductive heartwood, wound compartmentalization creates discontinuous vascular zones, and trunk disease fungi colonize dead tissue and spread into living wood. ||Cultivars with dense, durable wood such as Mourvèdre and Carignan show slower structural decline than softer-wooded types. ||Trunk cross-sectional area of functional xylem may decline from 80-90% in young vines to 30-50% in old vines through combined effects of heartwood formation and disease damage. ||Mechanical failure (trunk breakage, cordon collapse) becomes increasingly likely as the ratio of dead to living wood increases, with failure typically occurring during wind events or under heavy crop load. ||Wound management practices (pruning cut protection, disease prevention) significantly affect the rate of structural integrity loss.",
    "editor_note": "Structural integrity represents the physical foundation of vine longevity, with mechanical failure setting the ultimate limit on productive lifespan even when vascular function and regenerative capacity remain adequate. ||The trait integrates wood density, wound compartmentalization ability, and resistance to wood-decay fungi. ||Training system design affects structural demands, with high-cordon systems placing greater mechanical stress on supporting structures than low-trained systems.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Shigo AL (1984) Compartmentalization: a conceptual framework for understanding how trees grow and defend themselves. Annual Review of Phytopathology 22:189-214|| Pearce RB (1996) Antimicrobial defences in the wood of living trees. New Phytologist 132:203-233"
  },
  "Decline_Resistance_Disposition": {
    "definition": "A vine longevity disposition that is the inherited capacity of a Vitis vinifera plant to resist or tolerate the chronic progressive deterioration known as vine decline, maintaining productive function despite accumulating damage from trunk diseases (Esca complex, Botryosphaeria dieback, Eutypa dieback), vascular dysfunction, and age-related physiological changes.",
    "alternative_term": "decline tolerance | trunk disease resistance | chronic stress tolerance |+ Dekline-Resistenz | Verfallsresistenz | Abbautoleranz",
    "example_of_usage": "Decline resistance varies among cultivars, with Cabernet Sauvignon and Ugni Blanc showing relative tolerance (5-10% cumulative mortality over 20 years) while Sauvignon Blanc and Semillon are highly susceptible (15-30% mortality). ||Esca complex (caused by Phaeomoniella chlamydospora, Phaeoacremonium minimum, and Fomitiporia mediterranea) represents the primary decline syndrome in mature vineyards, with symptom expression varying from chronic (tiger-stripe leaf symptoms, progressive weakening) to apoplectic (sudden vine death). ||Decline-resistant genotypes show enhanced wound compartmentalization, production of antifungal stilbenes (resveratrol, ε-viniferin) in response to infection, and maintained hydraulic function despite partial vascular occlusion. ||Rootstock effects on scion decline resistance are significant, with 110 Richter and 140 Ruggeri conferring improved decline survival compared to SO4 in some studies.",
    "editor_note": "Decline resistance is increasingly critical as trunk disease pressure intensifies globally and effective chemical controls remain limited. ||The trait encompasses both resistance (limiting pathogen establishment and spread) and tolerance (maintaining function despite infection). ||Understanding cultivar-specific decline susceptibility enables targeted prophylactic management and informed replanting decisions. ||The economic impact of vine decline includes direct replacement costs and indirect losses from reduced vineyard uniformity and quality.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Gramaje D et al. (2018) Managing grapevine trunk diseases with respect to etiology and epidemiology: current strategies and future prospects. Plant Disease 102:12-39|| Murolo S, Romanazzi G (2014) Effects of grapevine cultivar, rootstock and clone on Esca disease. Australasian Plant Pathology 43:215-221"
  },
  "Cane_Maturation_Disposition": {
    "definition": "A longevity and resilience disposition that is the inherited capacity of a Vitis vinifera plant to complete the developmental transition of current-season shoots from green, herbaceous growth to lignified, cold-hardy canes capable of surviving winter dormancy and supporting following-season fruiting, encompassing periderm formation, reserve accumulation, and acquisition of freezing tolerance.",
    "alternative_term": "shoot maturation | cane ripening | wood maturation trait |+ Holzreife | Triebausreifung | Rutenreife",
    "example_of_usage": "Cane maturation progresses basipetally (from base to tip) during late summer and autumn, with fully matured canes showing brown periderm color, firm texture, and cold hardiness to -15 to -25°C depending on cultivar, while immature portions remain green, soft, and susceptible to freeze damage below -5°C. ||Maturation rate varies among cultivars, with early-maturing types such as Pinot Noir and Chardonnay completing lignification 3-4 weeks before late-maturing cultivars such as Carignan and Mourvèdre. ||Internode maturation percentage at first frost ranges from 95-100% in well-adapted cultivars to 60-80% in poorly matched cultivar-climate combinations or over-cropped vines. ||Carbohydrate reserve concentration in mature canes reaches 15-25% of dry weight (predominantly starch), providing energy for cold hardiness maintenance and spring growth resumption.",
    "editor_note": "Cane_Maturation_Disposition serves as the parent class for periderm formation and reserve accumulation traits. ||Cane maturation is critical for vineyard survival in cold climates, as immature wood is highly susceptible to winter injury. ||The process integrates multiple developmental and physiological changes occurring in parallel, including secondary wall lignification, periderm development, starch accumulation, and cold acclimation gene expression. ||Viticultural practices (crop load management, shoot positioning, water management) significantly affect maturation rate and completeness.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Fennell A (2004) Freezing tolerance and injury in grapevines. Journal of Crop Improvement 10:201-235|| Keller M, Tarara JM (2010) Warm spring temperatures induce persistent season-long changes in shoot development in grapevines. Annals of Botany 106:131-141"
  },
  "Periderm_Formation_Disposition": {
    "definition": "A cane maturation disposition that is the inherited capacity of a Vitis vinifera plant to develop a protective periderm (cork layer) on current-season shoots through phellogen (cork cambium) activity, replacing the epidermis with suberized phellem cells that provide desiccation resistance, pathogen exclusion, and the physical barrier necessary for winter survival.",
    "alternative_term": "cork development | shoot browning | periderm development trait |+ Peridermbildung | Korkentwicklung | Borkenbildung",
    "example_of_usage": "Periderm formation initiates at shoot nodes approximately 6-8 weeks after budbreak and progresses to internodes over the following weeks, with the characteristic color change from green to tan-brown indicating suberization completion. ||Cultivars differ in periderm development rate, with fast-forming types such as Cabernet Sauvignon showing 90-100% internode coverage by veraison while slow-forming cultivars such as Sultanina may reach only 50-70% coverage at the same developmental stage. ||Periderm thickness at maturity ranges from 150-300 µm depending on cultivar and growing conditions, with thicker periderm associated with improved cold hardiness and desiccation resistance. ||The VvMYB93 transcription factor regulates suberin biosynthesis genes (VvFAR, VvCYP86, VvGPAT) controlling periderm development. ||Incomplete periderm formation leaves shoots vulnerable to winter desiccation and freeze damage, with damage typically occurring in distal, immature portions.",
    "editor_note": "Periderm formation represents the visible indicator of cane maturation and provides essential protective functions for winter survival. ||The suberized cell layers restrict water loss (critical during winter desiccation stress), exclude pathogens, and provide insulation for underlying living tissues. ||Periderm quality and completeness directly correlate with winter hardiness assessment and cane selection for propagation. ||The trait shows strong environmental modulation, with water stress and moderate temperatures promoting periderm development while excessive vigor and late-season irrigation delay maturation.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Franke R, Schreiber L (2007) Suberin - a biopolyester forming apoplastic plant interfaces. Current Opinion in Plant Biology 10:252-259|| Pollard M et al. (2008) Building lipid barriers: biosynthesis of cutin and suberin. Trends in Plant Science 13:236-246"
  },
  "Reserve_Accumulation_Disposition": {
    "definition": "A cane maturation disposition that is the inherited capacity of a Vitis vinifera plant to synthesize and store carbohydrate reserves (primarily starch) and nitrogen reserves (amino acids, proteins) in perennial woody tissues during late season, providing the energy and nutrient pools required for winter cold hardiness maintenance, spring growth resumption, and early-season development before photosynthesis becomes self-supporting.",
    "alternative_term": "carbohydrate storage | reserve deposition | starch accumulation trait |+ Reservestoffeinlagerung | Kohlenhydratspeicherung | Stärkeakkumulation",
    "example_of_usage": "Reserve accumulation occurs primarily during the post-harvest period (4-8 weeks between harvest and leaf fall), with starch concentration in canes and trunks increasing from 8-12% to 18-28% of dry weight during this period in well-managed vines. ||Cultivars differ in reserve accumulation capacity, with Pinot Noir and Riesling showing typically higher reserve levels (22-28% starch) than vigorous cultivars such as Thompson Seedless (15-20%). ||Reserve distribution within the vine shows highest concentrations in roots (20-30%) and cane bases (18-25%), with declining levels toward shoot tips. ||Nitrogen reserves (arginine predominating, comprising 40-60% of root free amino acids) accumulate to 1.5-3.0% of root dry weight during autumn. ||Spring mobilization depletes 40-60% of reserves by bloom, with reserves not fully restored until mid-summer in heavy crop years. ||Insufficient reserves result in weak spring growth, poor fruit set, and increased susceptibility to stress.",
    "editor_note": "Reserve accumulation represents the physiological foundation for vine perenniality, bridging the dormant season and fueling the burst of spring growth before current-season photosynthesis becomes established. ||The trait integrates source capacity (post-harvest photosynthesis), sink activity (phloem loading into storage tissues), and the enzymatic machinery for starch synthesis (ADP-glucose pyrophosphorylase, starch synthase). ||Management practices affecting reserve status (harvest timing, post-harvest irrigation, defoliation) have carry-over effects on following-season performance.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Holzapfel BP et al. (2010) Accumulation and distribution of carbohydrate and nitrogen in grapevines under a Mediterranean climate. Australian Journal of Grape and Wine Research 16:53-63|| Zapata C et al. (2004) Effects of girdling on carbohydrate and nitrogen partitioning in grapevine. Journal of Experimental Botany 55:579-592"
  },
  "Recovery_Disposition": {
    "definition": "A longevity and resilience disposition that is the inherited capacity of a Vitis vinifera plant to restore productive function following severe damage, stress, or deliberate renovation interventions, through coordinated activation of latent meristems, mobilization of carbohydrate reserves, and reconstruction of functional canopy architecture within acceptable timeframes.",
    "alternative_term": "restoration capacity | damage recovery trait | rehabilitation disposition |+ Erholungsvermögen | Wiederherstellungsfähigkeit | Regenerations-Disposition",
    "example_of_usage": "Recovery capacity determines vineyard resilience to catastrophic events and the feasibility of renovation practices, with full productive recovery requiring 2-5 years depending on damage severity and cultivar. ||Recovery from severe winter injury (trunk kill to soil line) in own-rooted vineyards involves sucker selection and retraining over 3-4 years, while grafted vines may require trunk regrafting or replanting. ||Recovery from trunk disease damage through cordon or trunk renewal exploits the vine's capacity to regenerate from basal latent buds while maintaining the established root system. ||Fire-damaged vineyards show variable recovery depending on heat exposure intensity, with complete crown recovery possible within 2-3 seasons when root systems survive. ||Cultivars with abundant latent bud reserves and high reserve carbohydrate content show superior recovery compared to low-reserve types, with Grenache and Carignan noted for exceptional recovery capacity.",
    "editor_note": "Recovery_Disposition serves as the parent class for retraining capacity and crown regeneration traits. ||Recovery represents the practical application of the vine's regenerative potential to restore economic productivity following damage or as part of planned vineyard renovation. ||The trait integrates multiple underlying capacities including latent bud viability, reserve mobilization, and growth vigor. ||Understanding cultivar-specific recovery potential enables informed decisions about renovation versus replanting following damage events.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Keller M (2020) The Science of Grapevines: Anatomy and Physiology, 3rd Ed, Academic Press pp.: 165-195|| Wample RL, Bary A (1992) Harvest date as a factor in carbohydrate storage and cold hardiness of Cabernet Sauvignon grapevines. Journal of the American Society for Horticultural Science 117:32-36"
  },
  "Retraining_Capacity_Disposition": {
    "definition": "A recovery disposition that is the inherited capacity of a Vitis vinifera plant to be successfully retrained to a new canopy architecture following trunk renewal, training system conversion, or severe corrective pruning, through vigorous shoot growth from selected renewal positions and the establishment of new permanent structures within acceptable production recovery timeframes.",
    "alternative_term": "renovation potential | training flexibility | restructuring capacity |+ Umerzugsfähigkeit | Erziehungsumstellung | Neuformierungspotential",
    "example_of_usage": "Retraining capacity enables vineyard renovation strategies that extend productive lifespan without replanting, with successful retraining restoring 80-100% of pre-renovation yield within 3-4 years. ||Trunk renewal from basal suckers requires selection of vigorous, well-positioned shoots (typically 2-4 candidates) with subsequent training to the target architecture over 1-2 seasons. ||Training system conversion (e.g., head-trained to bilateral cordon) exploits retraining capacity to improve mechanization compatibility or canopy microclimate. ||Cultivar differences in retraining success relate to latent bud fertility (fruitfulness of renewal shoots), growth vigor (rate of structure establishment), and wood flexibility (ease of positioning during training). ||High-vigor cultivars such as Thompson Seedless and Barbera show rapid retraining (full production year 3), while low-vigor types such as Pinot Noir may require 4-5 years. ||Rootstock effects on scion retraining capacity are significant, with vigorous rootstocks accelerating structure establishment.",
    "editor_note": "Retraining capacity provides the foundation for vineyard renovation practices that preserve the value of established root systems and site adaptation while replacing damaged or inefficient above-ground structures. ||The trait is increasingly important as trunk disease pressure creates need for trunk renewal in otherwise healthy vineyards. ||Successful retraining requires both biological capacity (vigorous growth, fruitful buds) and appropriate timing/technique (dormant versus growing season renewal, wound management). ||Economic analysis of retraining versus replanting depends on cultivar-specific recovery trajectory.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Intrieri C, Poni S (1995) Integrated evolution of trellis training systems and machines to improve grape quality and vintage quality of mechanized Italian vineyards. American Journal of Enology and Viticulture 46:116-127|| Sivilotti P et al. (2016) Grapevine response to trunk renewal: yield recovery, carbohydrate partitioning and pruning weight. Scientia Horticulturae 207:165-172"
  },
  "Crown_Regeneration_Disposition": {
    "definition": "A recovery disposition that is the inherited capacity of a Vitis vinifera plant to regenerate a complete functional canopy (crown) from latent buds, adventitious meristems, or the root system following total or near-total loss of above-ground vegetative structures due to frost, fire, mechanical damage, or severe disease, re-establishing photosynthetic capacity and reproductive potential.",
    "alternative_term": "canopy regeneration | shoot system recovery | above-ground restoration |+ Kronenregeneration | Laubwandwiederherstellung | oberirdische Regeneration",
    "example_of_usage": "Crown regeneration enables vine survival of catastrophic events that destroy the entire above-ground structure, with regeneration source depending on damage extent and vine type. ||Severe spring frost (-8 to -12°C on green tissue) killing all primary shoots triggers regeneration from secondary and tertiary buds, restoring partial canopy within 3-6 weeks but typically reducing yield by 50-80% in the current season. ||Complete crown loss (trunk kill) initiates regeneration from basal latent buds (own-rooted vines) or necessitates regrafting (grafted vines), with full canopy restoration requiring 2-3 growing seasons. ||Fire-damaged vines show crown regeneration from surviving cambial tissue or basal buds if heat exposure duration was limited, with recovery success inversely related to trunk char depth. ||Cultivars with extensive latent bud populations persisting on old wood (Grenache, Mourvèdre, Carignan) show superior crown regeneration compared to types with limited latent bud longevity. ||The regenerated crown initially shows juvenile growth characteristics (high vigor, low fruitfulness) transitioning to mature production patterns over 2-4 seasons.",
    "editor_note": "Crown regeneration represents the ultimate survival mechanism enabling grapevine persistence through catastrophic above-ground destruction. ||The trait depends on maintenance of viable meristematic tissue (latent buds on surviving trunk/root crown, root cambium capable of adventitious bud formation) and adequate carbohydrate reserves to fuel initial regrowth before photosynthetic independence. ||Crown regeneration capacity has historically enabled vineyard recovery from fire, extreme frost, and war damage, preserving genetic resources and established plantings. ||Climate change increasing frost and fire risk elevates the importance of crown regeneration capacity in cultivar and site resilience assessment.", 
    "has_curation_status": "http://purl.obolibrary.org/obo/IAO_0000123",
    "external_mapping": [ "no_mapping_assigned" ],
    "definition_source": "Mullins MG et al. (1992) Biology of the Grapevine, Cambridge University Press pp.: 80-112|| Keller M, Mills LJ (2007) Effect of pruning on recovery and productivity of cold-injured Merlot grapevines. American Journal of Enology and Viticulture 58:351-357"
  }

});

